window.poetryCorpus = [{"title":"在岳咏蝉","author":"骆宾王","dynasty":"唐","form":"诗","lines":["西陆蝉声唱，南冠客思侵。","那堪玄鬓影，来対白头吟。","露重飞难进，风多响易沈。","无人信高洁，谁为表予心。"],"source":"《唐诗三百首》"},{"title":"行路难","author":"范成大","dynasty":"宋","form":"诗","lines":["赠君以丹棘忘忧之草，青棠合歓之花。","马脳游仙之梦枕，竜综辟寒之宝纱。","天河未翻月未落，夜长如年引春酌。","昔人安在空城郭，今夕不饮何时楽。"],"source":"宋诗"},{"title":"琐窗寒","author":"吴文英","dynasty":"宋","form":"词","lines":["绀缕堆云，清腮润玉，汜人初见。","蛮腥未洗，海客一怀凄惋。","渺征槎、去乗阆风，占香上国幽心展。","□遗芳掩色，真姿凝澹，返魂骚畹。","一盼。","千金换。","又笑伴鸱夷，共归吴苑。","离烟恨水，梦杳南天秋晩。","比来时、痩肌更销，冷薫沁骨悲乡远。","最伤情、送客咸阳，佩结西风怨。"],"source":"宋词"},{"title":"诈妮子调风月・仙吕/点绛唇","author":"关汉卿","dynasty":"元","form":"曲","lines":["半世为人，不曽教大人心困。","虽是搽胭粉，只争不裹头巾，将那等不做人的婆娘恨。"],"source":"元曲"},{"title":"关雎","author":"佚名","dynasty":"先秦","form":"诗","lines":["关关雎鸠，在河之洲。窈窕淑女，君子好逑。","参差荇菜，左右流之。窈窕淑女，寤寐求之。","求之不得，寤寐思服。悠哉悠哉，辗转反侧。","参差荇菜，左右采之。窈窕淑女，琴瑟友之。","参差荇菜，左右芼之。窈窕淑女，钟鼓乐之。"],"source":"《诗经》"},{"title":"离骚","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["帝高阳之苗裔兮，朕皇考曰伯庸。","摄提贞于孟陬兮，惟庚寅吾以降。","皇览揆余初度兮，肇锡余以嘉名：","名余曰正则兮，字余曰灵均。","纷吾既有此内美兮，又重之以修能。","扈江离与辟芷兮，纫秋兰以为佩。","汨余若将不及兮，恐年岁之不吾与。","朝搴阰之木兰兮，夕揽洲之宿莽。","日月忽其不淹兮，春与秋其代序。","惟草木之零落兮，恐美人之迟暮。","不抚壮而弃秽兮，何不改乎此度?","乗骐骥以驰骋兮，来吾道夫先路！","昔三后之纯粋兮，固众芳之所在。","杂申椒与菌桂兮，岂惟纫夫蕙茝！","彼尧、舜之耿介兮，既遵道而得路。","何桀纣之猖披兮，夫惟捷径以窘歩。","惟夫党人之偷乐兮，路幽昧以险隘。","岂余身之殚殃兮，恐皇舆之败绩！","忽奔走以先后兮，及前王之踵武。","荃不查余之中情兮，反信谗而齌怒。","余固知謇謇之为患兮，忍而不能舎也。","指九天以为正兮，夫惟灵修之故也。","曰黄昏以为期兮，羌中道而改路！","初既与余成言兮，后悔遁而有他。","余既不难夫离别兮，伤灵修之数化。","余既滋兰之九畹兮，又树蕙之百亩。","畦留夷与掲车兮，杂杜衡与芳芷。","冀枝叶之峻茂兮，愿俟时乎吾将刈。","虽萎绝其亦何伤兮，哀众芳之芜秽。","众皆竞进以贪婪兮，凭不厌乎求索。","羌内恕己以量人兮，各兴心而嫉妒。","忽驰骛以追逐兮，非余心之所急。","老冉冉其将至兮，恐修名之不立。","朝饮木兰之坠露兮，夕餐秋菊之落英。","苟余情其信姱以练要兮，长顑颔亦何伤。","掔木根以结茞兮，贯薜茘之落蕊。","矫菌桂以纫蕙兮，索胡绳之𫄥𫄥。","謇吾法夫前修兮，非世俗之所服。","虽不周于今之人兮，愿依彭咸之遗则。","长太息以掩涕兮，哀民生之多艰。","余虽好修姱以鞿羁兮，謇朝谇而夕替。","既替余以蕙𬙋兮，又申之以揽茝。","亦余心之所善兮，虽九死其犹未悔。","怨灵修之浩荡兮，终不察夫民心。","众女嫉余之蛾眉兮，谣诼谓余以善淫。","固时俗之工巧兮，偭规矩而改错。","背绳墨以追曲兮，竞周容以为度。","忳郁邑余侘傺兮，吾独穷困乎此时也。","宁溘死以流亡兮，余不忍为此态也。","鸷鸟之不群兮，自前世而固然。","何方圜之能周兮，夫孰异道而相安？","屈心而抑志兮，忍尤而攘诟。","伏清白以死直兮，固前圣之所厚。","悔相道之不察兮，延伫乎吾将反。","回朕车以复路兮，及行迷之未远。","歩余马于兰皐兮，驰椒丘且焉止息。","进不入以离尤兮，退将复修吾初服。","制芰荷以为衣兮，集芙蓉以为裳。","不吾知其亦已兮，苟余情其信芳。","高余冠之岌岌兮，长余佩之陆离。","芳与泽其杂糅兮，唯昭质其犹未亏。","忽反顾以游目兮，将往观乎四荒。","佩缤纷其繁饰兮，芳菲菲其弥章。","民生各有所乐兮，余独好修以为常。","虽体解吾犹未变兮，岂余心之可惩。","女媭之婵媛兮，申申其詈予，曰：","鲧婞直以亡身兮，终然夭乎羽之野。","汝何博謇而好修兮，纷独有此姱节？","薋菉葹以盈室兮，判独离而不服。","众不可户说兮，孰云察余之中情？","世并举而好朋兮，夫何茕独而不予听？","依前圣以节中兮，喟凭心而历兹。","济沅、湘以南征兮，就重华而敶词：","启《九辩》与《九歌》兮，夏康娱以自纵。","不顾难以图后兮，五子用失乎家衖。","羿淫游以佚畋兮，又好射夫封狐。","固乱流其鲜终兮，浞又贪夫厥家。","浇身被服强圉兮，纵欲而不忍。","日康娱而自忘兮，厥首用夫颠陨。","夏桀之常违兮，乃遂焉而逢殃。","后辛之菹醢兮，殷宗用而不长。","汤、禹俨而祗敬兮，周论道而莫差。","举贤才而授能兮，循绳墨而不颇。","皇天无私阿兮，览民徳焉错辅。","夫维圣哲以茂行兮，苟得用此下土。","瞻前而顾后兮，相观民之计极。","夫孰非义而可用兮？","孰非善而可服？","阽余身而危死兮，览余初其犹未悔。","不量凿而正枘兮，固前修以菹醢。","曽歔欷余郁邑兮，哀朕时之不当。","揽茹蕙以掩涕兮，沾余襟之浪浪。","跪敷衽以陈辞兮，耿吾既得此中正。","驷玉虬以桀鹥兮，溘埃风余上征。","朝发轫于苍梧兮，夕余至乎县圃。","欲少留此灵琐兮，日忽忽其将暮。","吾令羲和弭节兮，望崦嵫而勿迫。","路漫漫其修远兮，吾将上下而求索。","饮余马于咸池兮，总余辔乎扶桑。","折若木以払日兮，聊逍遥以相羊。","前望舒使先驱兮，后飞廉使奔属。","鸾皇为余先戒兮，雷师告余以未具。","吾令凤鸟飞腾兮，继之以日夜。","飘风屯其相离兮，帅云霓而来御。","纷总总其离合兮，斑陆离其上下。","吾令帝阍开关兮，倚阊阖而望予。","时暧暧其将罢兮，结幽兰而延伫。","世溷浊而不分兮，好蔽美而嫉妒。","朝吾将济于白水兮，登阆风而绁马。","忽反顾以流涕兮，哀高丘之无女。","溘吾游此春宫兮，折琼枝以继佩。","及荣华之未落兮，相下女之可诒。","吾令丰隆乗云兮，求宓妃之所在。","解佩𬙋以结言兮，吾令謇修以为理。","纷总总其离合兮，忽纬繣其难迁。","夕归次于穷石兮，朝濯发乎洧盘。","保厥美以骄傲兮，日康娱以淫游。","虽信美而无礼兮，来违弃而改求。","览相观于四极兮，周流乎天余乃下。","望瑶台之偃蹇兮，见有娀之佚女。","吾令鸩为媒兮，鸩告余以不好。","雄鸠之鸣逝兮，余犹恶其佻巧。","心犹予而狐疑兮，欲自适而不可。","凤皇既受诒兮，恐高辛之先我。","欲远集而无所止兮，聊浮游以逍遥。","及少康之未家兮，留有虞之二姚。","理弱而媒拙兮，恐导言之不固。","世溷浊而嫉贤兮，好蔽美而称恶。","闺中既以邃远兮，哲王又不寤。","怀朕情而不发兮，余焉能忍而与此终古？","索琼茅以筳篿兮，命灵氛为余占之。","曰：两美其必合兮，孰信修而慕之？","思九州之博大兮，岂惟是其有女？」","曰：勉远逝而无狐疑兮，孰求美而释女？","何所独无芳草兮，尔何怀乎故宇？」","世幽昧以昡曜兮，孰云察余之善恶？","民好恶其不同兮，惟此党人其独异！","户服艾以盈要兮，谓幽兰其不可佩。","览察草木其犹未得兮，岂珵美之能当？","苏粪壌以充祎兮，谓申椒其不芳。","欲从灵氛之吉占兮，心犹予而狐疑。","巫咸将夕降兮，怀椒糈而要之。","百神翳其备降兮，九疑缤其并迎。","皇剡剡其扬灵兮，告余以吉故。","曰：勉升降以上下兮，求矩矱之所同。","汤、禹俨而求合兮，挚、咎繇而能调。","苟中情其好修兮，又何必用夫行媒？","说操筑于傅岩兮，武丁用而不疑。","吕望之鼓刀兮，遭周文而得举。","宁戚之讴歌兮，齐桓闻以该辅。","及年岁之未晏兮，时亦犹其未央。","恐鹈𫛞之先鸣兮，使夫百草为之不芳。","何琼佩之偃蹇兮，众𫉁然而蔽之。","惟此党人之不谅兮，恐嫉妒而折之。","时缤纷其变易兮，又何可以淹留？","兰芷变而不芳兮，荃蕙化而为茅。","何昔日之芳草兮，今直为此萧艾也？","岂其有他故兮，莫好修之害也！","余以兰为可恃兮，羌无实而容长。","委厥美以从俗兮，苟得列乎众芳。","椒专佞以慢慆兮，榝又欲充夫佩帏。","既干进而务入兮，又何芳之能祗？","固时俗之流从兮，又孰能无变化？","览椒兰其若兹兮，又况掲车与江离？","惟兹佩之可贵兮，委厥美而历兹。","芳菲菲而难亏兮，芬至今犹未沬。","和调度以自娱兮，聊浮游而求女。","及余饰之方壮兮，周流观乎上下。","灵氛既告余以吉占兮，历吉日乎吾将行。","折琼枝以为羞兮，精琼爢以为粻。","为余驾飞龙兮，杂瑶象以为车。","何离心之可同兮？","吾将远逝以自疏。","邅吾道夫昆仑兮，路修远以周流。","扬云霓之晻蔼兮，鸣玉鸾之啾啾。","朝发轫于天津兮，夕余至乎西极。","凤皇翼其承旗兮，高翱翔之翼翼。","忽吾行此流沙兮，遵赤水而容与。","麾蛟龙使梁津兮，诏西皇使渉予。","路修远以多艰兮，腾众车使径待。","路不周以左转兮，指西海以为期。","屯余车其千乗兮，齐玉轪而并驰。","驾八龙之婉婉兮，载云旗之委蛇。","抑志而弭节兮，神高驰之邈邈。","奏《九歌》而舞《韶》兮，聊仮日以偷乐。","陟升皇之赫戏兮，忽临睨夫旧乡。","仆夫悲余马怀兮，蜷局顾而不行。","乱曰：已矣哉！国无人莫我知兮，又何怀乎故都！","既莫足与为美政兮，吾将从彭咸之所居！"],"source":"《楚辞》"},{"title":"登幽州台歌","author":"陈子昂","dynasty":"唐","form":"诗","lines":["前不见古人，后不见来者。","念天地之悠悠，独怆然而涕下。"],"source":"《唐诗三百首》"},{"title":"西江有単鹄行","author":"范成大","dynasty":"宋","form":"诗","lines":["西江有単鹄，托身万里云。","猥为稲粱谋，堕此鴎鹭群。","朝游枫叶杪，暮宿芦花根。","懐安浦溆暖，忘记云海寛。","忽有孤征鸿，惊飞落江浜。","眼明见黄鹄，邂逅倾情真。","羽毛虽不同，意気颇相亲。","言鹄有六翮，何不高飞翾。","水鸟不足群，朝暮徒嘲喧。","相将乗风去，一上盘秋旻。","渇饮颢露滋，饥吸晴霞暾。","方知翅翎俊，可以凌埃尘。","东风昨解冻，春光暖如薫。","阳鸟当北郷，行止倏已分。","傥欲相逐去，関山隔呉秦。","両鸟竟分飞，鸣声动行人。","岂不有歳晩，鸿当复来宾。","但愁山海阔，岐路多纠纷。","复来失故道，那得相知闻。","鸿帰有俦侣，鹄住长悲辛。"],"source":"宋诗"},{"title":"尉迟杯","author":"吴文英","dynasty":"宋","form":"词","lines":["垂杨径。","洞钥启，时见流莺迎。","涓涓暗谷流红，应有缃桃千顷。","临池笑靥，春色满、铜华弄妆影。","记年时、试酒湖阴，褪花曽采新杏。","蛛窗绣网玄经，才石砚开奁，雨润云凝。","小小蓬莱香一掬，愁不到、朱娇翠靓。","清尊伴、人闲永日，断琴和、棋声竹露冷。","笑从前、酔卧红尘，不知仙在人境。"],"source":"宋词"},{"title":"诈妮子调风月・混江龙","author":"关汉卿","dynasty":"元","form":"曲","lines":["男儿人若不依本分，一个抢白是非两家分。","壮鼻凹硬如石铁，教满耳根都做了烧云。","普天下汉子尽教都先有意，牢把定自己休不成人。","虽然两家无意，便待一面成亲，不分晓便似包着一肚皮干牛粪。","知人无意，及早抽身。"],"source":"元曲"},{"title":"葛覃","author":"佚名","dynasty":"先秦","form":"诗","lines":["葛之覃兮，施于中谷，维叶萋萋。黄鸟于飞，集于灌木，其鸣喈喈。","葛之覃兮，施于中谷，维叶莫莫。是刈是濩，为𫄨为绤，服之无斁。","言告师氏，言告言归。薄汚我私，薄浣我衣。害浣害否，归宁父母。"],"source":"《诗经》"},{"title":"东皇太一","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["吉日兮辰良，穆将愉兮上皇","抚长剑兮玉珥，璆锵鸣兮琳琅","瑶席兮玉瑱，盍将把兮琼芳","蕙肴蒸兮兰藉，奠桂酒兮椒浆","扬枹兮拊鼓，疏缓节兮安歌","陈竽瑟兮浩倡","灵偃蹇兮姣服，芳菲菲兮满堂","五音纷兮繁会，君欣欣兮乐康。"],"source":"《楚辞》"},{"title":"経邹鲁祭孔子而叹之","author":"明皇帝","dynasty":"唐","form":"诗","lines":["夫子何为者？栖栖一代中。","地犹鄹氏邑，宅即鲁王宫。","叹凤嗟身否，伤麟怨道穷。","今看両楹奠，当与梦时同。"],"source":"《唐诗三百首》"},{"title":"车遥遥篇","author":"范成大","dynasty":"宋","form":"诗","lines":["车遥遥，马憧憧。","君游东山东复东，安得奋飞逐西风。","愿我如星君如月，夜夜流光相皎洁。","月暂晦，星常明。","留明待月复，三五共盈盈。"],"source":"宋诗"},{"title":"渡江云三犯・渡江云","author":"吴文英","dynasty":"宋","form":"词","lines":["羞红颦浅恨，晩风为落，片绣点重茵。","旧堤分燕尾，桂棹轻鸥，宝勒倚残云。","千丝怨碧，渐路入、仙坞迷津。","肠漫回，隔花时见，背面楚腰身。","逡巡。","题门惆怅，堕履牵萦，数幽期难准。","还始觉、留情缘眼，宽带因春。","明朝事与孤烟冷，做满湖、风雨愁人。","山黛暝，尘波澹绿无痕。"],"source":"宋词"},{"title":"诈妮子调风月・那咤令","author":"关汉卿","dynasty":"元","form":"曲","lines":["等不得水温，一声要面盆；恰递与面盆，一声要手巾；却执与手巾，一声解纽门。","使的人无淹润、百般支分！。"],"source":"元曲"},{"title":"巻耳","author":"佚名","dynasty":"先秦","form":"诗","lines":["采采巻耳，不盈顷筐。嗟我怀人，置彼周行。","陟彼崔嵬，我马虺𬯎。我姑酌彼金罍，维以不永怀。","陟彼高冈，我马玄黄。我姑酌彼兕觥，维以不永伤。","陟彼砠矣，我马瘏矣，我仆痡矣，云何吁矣。"],"source":"《诗经》"},{"title":"云中君","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["浴兰汤兮沐芳，华采衣兮若英","灵连蜷兮既留，烂昭昭兮未央","謇将憺兮寿宫，与日月兮齐光","龙驾兮帝服，聊翱游兮周章","灵皇皇兮既降，猋远举兮云中","览冀洲兮有余，横四海兮焉穷","思夫君兮太息，极劳心兮忡忡"],"source":"《楚辞》"},{"title":"鼓吹曲辞 将进酒","author":"李白","dynasty":"唐","form":"诗","lines":["君不见黄河之水天上来，奔流到海不复回。","君不见高堂明镜悲白髪，朝如青糸暮成雪。","人生得意须尽歓，莫使金尊空対月。","天生我材必有用，千金散尽还复来。","烹羊宰牛且为楽，会须一饮三百杯。","岑夫子，丹丘生，将进酒，杯莫停。","与君歌一曲，请君为我侧耳聴。","钟鼓馔玉不足贵，但愿长酔不复醒。","古来圣贤皆寂寞，惟有饮者留其名。","陈王昔时宴平楽，斗酒十千恣歓谑。","主人何为言少銭，径须酤取対君酌。","五花马，千金裘，呼児将出换美酒，与尔同销万古愁。"],"source":"《唐诗三百首》"},{"title":"放鱼行","author":"范成大","dynasty":"宋","form":"诗","lines":["水落塘枯鱼卧陆，小児抱取不濡足。","昂蔵赤𩽼亦垂头，背负玄鳞三十六。","家人涤砧不辞労，云有素书金错刀。","嗟予赎放岂徼福，忍把汝命供吾饕。","如今已脱张胡子，好上竜门饮湖水。","不然崛起载飞仙，切莫颠狂称长史。"],"source":"宋诗"},{"title":"三部乐","author":"吴文英","dynasty":"宋","form":"词","lines":["江鶃初飞，荡万里素云，际空如沐。","咏情吟思，不在秦筝金屋。","夜潮上，明月芦花，傍钓蓑梦远，句清敲玉。","翠罂汲晓，欸乃一声秋曲。","越装片篷障雨，痩半竿渭水，鹭汀幽宿。","那知暖袍挟锦，低帘笼烛。","鼓春波、载花万斛。","帆鬣转、银河可掬。","风定浪息，苍茫外、天浸寒绿。"],"source":"宋词"},{"title":"诈妮子调风月・鹊踏枝","author":"关汉卿","dynasty":"元","form":"曲","lines":["入得房门，怎回身？厅独卧房儿窄窄别别，有甚铺呈？燕燕己身有甚幺孝顺？拗不过哥哥行在意殷勤。"],"source":"元曲"},{"title":"樛木","author":"佚名","dynasty":"先秦","form":"诗","lines":["南有樛木，葛藟累之。乐只君子，福履绥之。","南有樛木，葛藟荒之。乐只君子，福履将之。","南有樛木，葛藟萦之。乐只君子，福履成之。"],"source":"《诗经》"},{"title":"湘君","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["君不行兮夷犹，蹇谁留兮中洲","美要眇兮宜修，沛吾乗兮桂舟","令沅湘兮无波，使江水兮安流","望夫君兮未来，吹参差兮谁思","驾飞龙兮北征，邅吾道兮洞庭","薜茘柏兮蕙绸，荪桡兮兰旌","望涔阳兮极浦，横大江兮扬灵","扬灵兮未极，女婵媛兮为余太息","横流涕兮潺湲，隐思君兮陫侧","桂棹兮兰枻，斵冰兮积雪","采薜茘兮水中，搴芙蓉兮木末","心不同兮媒劳，恩不甚兮轻绝","石濑兮浅浅，飞龙兮翩翩","交不忠兮怨长，期不信兮告余以不闲","朝骋骛兮江皐，夕弭节兮北渚","鸟次兮屋上，水周兮堂下","捐余玦兮江中，遗余佩兮醴浦","采芳洲兮杜若，将以遗兮下女","时不可兮再得，聊逍遥兮容与。"],"source":"《楚辞》"},{"title":"横吹曲辞 出塞 一","author":"王昌齢","dynasty":"唐","form":"诗","lines":["秦时明月汉时関，万里长征人未还。","但使竜城飞将在，不教胡马度阴山。"],"source":"《唐诗三百首》"},{"title":"晩歩东郊","author":"范成大","dynasty":"宋","form":"诗","lines":["水墨依林寺，青黄负郭田。","斜阳犹満地，片月早中天。","策策鸦飞急，冥冥树影円。","西山元自好，那更着云烟。"],"source":"宋诗"},{"title":"霜叶飞","author":"吴文英","dynasty":"宋","form":"词","lines":["断烟离绪。","关心事，斜阳红隐霜树。","半壶秋水荐黄花，香噀西风雨。","纵玉勒、轻飞迅羽。","凄凉谁吊荒台古。","记酔蹋南屏，彩扇咽、寒蝉倦梦，不知蛮素。","聊对旧节传杯，尘笺蠹管，断阕经岁慵赋。","小蟾斜影转东篱，夜冷残蛩语。","早白发、缘愁万缕。","惊飙从巻乌纱去。","漫细将、茱萸看，但约明年，翠微高处。"],"source":"宋词"},{"title":"诈妮子调风月・寄生草","author":"关汉卿","dynasty":"元","form":"曲","lines":["卧地观经史，坐地对圣人。","你观的国风、雅、颂施诂训，诵的典谟训诰居尧舜，（末云了）（正旦唱）说的温良恭俭行忠信。","燕燕子理会得龙盘虎踞灭燕齐，谁会甚儿婚女聘成秦晋？（末云）这书院好。"],"source":"元曲"},{"title":"螽斯","author":"佚名","dynasty":"先秦","form":"诗","lines":["螽斯羽，诜诜兮。宜尔子孙，振振兮。","螽斯羽，薨薨兮。宜尔子孙。绳绳兮。","螽斯羽，揖揖兮。宜尔子孙，蛰蛰兮。"],"source":"《诗经》"},{"title":"湘夫人","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["帝子降兮北渚，目眇眇兮愁予","袅袅兮秋风，洞庭波兮木叶下","登白薠兮骋望，与佳期兮夕张","鸟何萃兮苹中，罾何为兮木上？","沅有茝兮醴有兰，思公子兮未敢言","荒忽兮远望，观流水兮潺湲","麋何食兮庭中，蛟何为兮水裔","朝驰余马兮江皐，夕济兮西澨","闻佳人兮召余，将腾驾兮偕逝","筑室兮水中，葺之兮荷盖","荪壁兮紫坛，播芳椒兮成堂","桂栋兮兰橑，辛夷楣兮药房","罔薜茘兮为帷，擗蕙櫋兮既张","白玉兮为镇，疏石兰兮为芳","芷葺兮荷屋，缭之兮杜衡","合百草兮实庭，建芳馨兮庑门","九嶷缤兮并迎，灵之来兮如云","捐余袂兮江中，遗余褋兮醴浦","搴汀洲兮杜若，将以遗兮远者","时不可兮骤得，聊逍遥兮容与！"],"source":"《楚辞》"},{"title":"横吹曲辞 出塞","author":"王之涣","dynasty":"唐","form":"诗","lines":["黄砂直上白云间，一片孤城万仞山。","羌笛何须怨杨柳，春风不度玉门関。"],"source":"《唐诗三百首》"},{"title":"元夜忆群従","author":"范成大","dynasty":"宋","form":"诗","lines":["愁里仍蒿径，闲中更荜门。","青灯聊自照，浊酒为谁温。","隙月知无梦，窗梅寄断魂。","遥怜好兄弟，飘泊両江村。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["泪荷抛砕璧。","正漏云筛雨，斜捎窗隙。","林声怨秋色。","对小山不迭，寸眉愁碧。","凉欺岸帻。","暮砧催、银屏翦尺。","最无聊、燕去堂空，旧幕暗尘罗额。","行客。","西园有分，断柳凄花，似曽相识。","西风破屐。","林下路，水边石。","念寒蛩残梦，归鸿心事，那听江村夜笛。","看雪飞、苹底芦梢，未如鬓白。"],"source":"宋词"},{"title":"诈妮子调风月・幺篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["这书房存得阿马，会得客宾。","翠筠月朗龙蛇印，碧轩夜冷灯香信，绿窗雨细琴书润。","毎朝席上宴佳宾，抵多少\"十年窗下无人问\"！（末云住）（正旦唱）。"],"source":"元曲"},{"title":"桃夭","author":"佚名","dynasty":"先秦","form":"诗","lines":["桃之夭夭，灼灼其华。之子于归，宜其室家。","桃之夭夭，有蕡其实。之子于归，宜其家室。","桃之夭夭，其叶蓁蓁。之子于归，宜其家人。"],"source":"《诗经》"},{"title":"大司命","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["广开兮天门，纷吾乗兮玄云","令飘风兮先驱，使涷雨兮洒尘","君回翔兮以下，逾空桑兮从女","纷总总兮九州，何寿夭兮在予","高飞兮安翔，乗清气兮御阴阳","吾与君兮齐速，导帝之兮九坑","灵衣兮被被，玉佩兮陆离","一阴兮一阳，众莫知兮余所为","折疏麻兮瑶华，将以遗兮离居","老冉冉兮既极，不寖近兮愈疏","乗龙兮辚辚，高驰兮冲天","结桂枝兮延伫，羌愈思兮愁人","愁人兮奈何，愿若今兮无亏","固人命兮有当，孰离合兮何为？"],"source":"《楚辞》"},{"title":"横吹曲辞 関山月","author":"李白","dynasty":"唐","form":"诗","lines":["明月出天山，苍茫云海间。","长风几万里，吹度玉门関。","汉下白登道，胡窥青海湾。","由来征戦地，不见有人还。","戍客望辺色，思帰多苦颜。","高楼当此夜，叹息未応闲。"],"source":"《唐诗三百首》"},{"title":"登西楼","author":"范成大","dynasty":"宋","form":"诗","lines":["少年豪気合摧锋，青鬓朱颜万事慵。","畴昔四愁无梦到，及时一笑有谁供。","诗情饮兴如云薄，草色花光似酒𬪩。","千里春心吟不尽，下楼分付晩烟钟。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["晴丝牵绪乱。","对沧江斜日，花飞人远。","垂杨暗吴苑。","正旗亭烟冷，河桥风暖。","兰情蕙盼。","惹相思、春根酒畔。","又争知、吟骨萦销，渐把旧衫重翦。","凄断。","流红千浪，欠月孤楼，总难留燕。","歌尘凝扇。","待凭信，拌分钿。","试挑灯欲写，还依不忍，笺幅偷和泪巻。","寄残云、剰雨蓬莱，也应梦见。"],"source":"宋词"},{"title":"诈妮子调风月・村里迓鼓","author":"关汉卿","dynasty":"元","form":"曲","lines":["更做道一家生女，百家求问。","才说贞烈，那里取一个时辰？见他语言儿栽排得淹润，怕不待言词硬，性格村、他怎比寻常世人？（末云了）（正旦唱）。"],"source":"元曲"},{"title":"兔罝","author":"佚名","dynasty":"先秦","form":"诗","lines":["肃肃兔罝，椓之丁丁。赳赳武夫，公侯干城。","肃肃兔罝，施于中逵。赳赳武夫，公侯好仇。","肃肃免罝，施于中林。赳赳武夫，公侯腹心。"],"source":"《诗经》"},{"title":"少司命","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["秋兰兮麋芜，罗生兮堂下","绿叶兮素华，芳菲菲兮袭予","夫人兮自有美子，荪何以兮愁苦","秋兰兮青青，绿叶兮紫茎","满堂兮美人，忽独与余兮目成","入不言兮出不辞，乗回风兮载云旗","悲莫悲兮生别离，乐莫乐兮新相知","荷衣兮蕙带，儵而来兮忽而逝","夕宿兮帝郊，君谁须兮云之际","与女沐兮咸池，曦女发兮阳之阿","望美人兮未来，临风怳兮浩歌","孔盖兮翠旌，登九天兮抚彗星","竦长剑兮拥幼艾，荪独宜兮为民正。"],"source":"《楚辞》"},{"title":"新嫁娘词三首 三","author":"王建","dynasty":"唐","form":"诗","lines":["三日入厨下，洗手作羹汤。","未谙姑食性，先遣小姑尝。"],"source":"《唐诗三百首》"},{"title":"不寐","author":"范成大","dynasty":"宋","form":"诗","lines":["南风醸卑湿，滑滑病履舄。","竟日隠几坐，拳局不得适。","丹田恍澒洞，银海眩眵黒。","髀弱类跨鞍，臂强如运甓。","合体竞酸嘶，莫夜辄増极。","奏床不得眠，耿耿到明発。","黄妳共住久，来梦乃其职。","睡魔吾故人，曩是不速客。","招呼各偃蹇，莫効尺寸力。","周公无由来，咫尺今古隔。","彭尸不得去，罡骑无行色。","主客両愁绪，虚室浪生白。","人言老禅师，両脇不到席。","兹事恐未暇，但愿了今夕。","平生北窗眠，栩栩即圣域。","睡僊吾所慕，行歩亦鼾息。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["藕心抽莹茧。","引翠针行处，冰花成片。","金门从回辇。","两玉凫飞上，绣绒尘软。","丝絇侍宴。","曳天香、春风宛转。","傍星辰、直上无声，缓蹑素云归晩。","奇践。","平康得意，酔踏香泥，润红沾线。","良工诧见。","吴蚕唾，海沈楦。","任真珠装缀，春申客屦，今日风流雾散。","待宣供、禹歩宸游，退朝燕殿。"],"source":"宋词"},{"title":"诈妮子调风月・元和令","author":"关汉卿","dynasty":"元","form":"曲","lines":["无男儿只一身，担寂寞受孤闷；有男儿呓梦入劳魂，心肠百处分。","知得有情人不曽来问肯，便待要成眷姻。"],"source":"元曲"},{"title":"芣苡","author":"佚名","dynasty":"先秦","form":"诗","lines":["采采芣苡，薄言采之。采采芣苡，薄言有之。","采采芣苡，薄言掇之。采采芣苡，薄言捋之。","采采芣苡，薄言袺之。采采芣苡，薄言襭之。"],"source":"《诗经》"},{"title":"东君","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["暾将出兮东方，照吾槛兮扶桑","抚余马兮安驱，夜皎皎兮既明","驾龙辀兮乗雷，载云旗兮委蛇","长太息兮将上，心低徊兮顾怀","羌声色兮娱人，观者儋兮忘归","縆瑟兮交鼓，萧钟兮瑶簴","鸣篪兮吹竽，思灵保兮贤姱","翾飞兮翠曽，展诗兮会舞","应律兮合节，灵之来兮敝日","青云衣兮白霓裳，举长矢兮射天狼","操余弧兮反沦降，援北斗兮酌桂浆","撰余辔兮高驰翔，杳冥冥兮以东行。"],"source":"《楚辞》"},{"title":"故行宫","author":"王建","dynasty":"唐","form":"诗","lines":["寥落古行宫，宫花寂寞红。","白头宫女在，闲坐说玄宗。"],"source":"《唐诗三百首》"},{"title":"河豚叹","author":"范成大","dynasty":"宋","form":"诗","lines":["鲰生藜苋肠，食事一饱足。","腥腐色所难，况乃衷酖毒。","彭亨强名鱼，杀気孕惨黩。","既非养生具，宜谢砧几酷。","呉侬真差事，网索不遗育。","捐生决下箸，缩手汗童仆。","朝来里中子，馋吻不待熟。","浓睡唤不譍，已落新鬼录。","百年三寸咽，水陆富肴䔩。","一物不登俎，未负将军腹。","为口忘计身，饕死何足哭。","作俑者谁欤，至今走末俗。","或云先王意，除悪如芸菽。","逆枭与毒獍，歳歳参币玉。","芟夷入荐羞，盖欲歼种族。","生死有定数，断命乌可続。","适丁是时者，未易一理局。","鼋鼎子公怒，羊羹华元衄。","异味古所珍，无事苦畏缩。","骈头讧此语，戒谕袛取渎。","聋盲死不悟，明知谅已烛。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["乱云生古峤。","记旧游惟怕，秋光不早。","人生断肠草。","叹如今摇落，暗惊怀抱。","谁临晩眺。","吹台高、霜歌缥缈。","想西风、此处留情，肯着故人衰帽。","闻道。","萸香西市，酒熟东邻，浣花人老。","金鞭騕袅。","追吟赋，倩年少。","想重来新雁，伤心湖上，销减红深翠窈。","小楼寒、睡起无聊，半帘晩照。"],"source":"宋词"},{"title":"诈妮子调风月・上马娇","author":"关汉卿","dynasty":"元","form":"曲","lines":["自勘婚，自说亲，也是\"贱媳妇责媒人\"。","往常我冰清玉洁难亲近，是他亲，子管教话儿亲。","我煞待嗔，我便恶相闻。"],"source":"元曲"},{"title":"汉广","author":"佚名","dynasty":"先秦","form":"诗","lines":["南有乔木，不可休息。汉有游女，不可求思。汉之广矣，不可泳思。江之永矣，不可方思。","翘翘错薪，言刈其楚。之子于归，言秣其马。汉之广矣，不可泳思。江之永矣，不可方思。","翘翘错薪，言刈其蒌。之子于归。言秣其驹。汉之广矣，不可泳思。江之永矣，不可方思。"],"source":"《诗经》"},{"title":"河伯","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["与女游兮九河，冲风起兮水扬波","乗水车兮荷盖，驾两龙兮骖螭","登昆仑兮四望，心飞扬兮浩荡","日将暮兮怅忘归，惟极浦兮寤怀","鱼鳞屋兮龙堂，紫贝阙兮珠宫","灵何惟兮水中","乗白鼋兮逐文鱼，与女游兮河之渚","流澌纷兮将来下","子交手兮东行，送美人兮南浦","波滔滔兮来迎，鱼鳞鳞兮媵予。"],"source":"《楚辞》"},{"title":"锦瑟","author":"李商隠","dynasty":"唐","form":"诗","lines":["锦瑟无端五十弦，一弦一柱思华年。","荘生暁梦迷蝴蝶，望帝春心托杜鹃。","沧海月明珠有涙，蓝田日暖玉生烟。","此情可待成追忆，只是当时已惘然。"],"source":"《唐诗三百首》"},{"title":"続长恨歌七首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["金杯潋滟暁妆寒，国色天香胜牡丹。","白凤诏书来已暮，六宫铅粉半春阑。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["记年时茂苑。","正画堂凝香，璇奎初焕。","天边岁华转。","向九重春近，仙桃传宴。","银罂翠管。","宝香飞、蓬莱小殿。","荷玉皇、恩重千秋，翠麓峻齐云汉。","须看。","鸿飞高处，地阔天宽，弋人空羡。","梅清水暖。","苕渓上，几吟巻。","算金门听漏，玉墀班早，赢得风霜满面。","总不如、绿野身安，镜重未晩。"],"source":"宋词"},{"title":"诈妮子调风月・胜葫芦","author":"关汉卿","dynasty":"元","form":"曲","lines":["怕不依随蒙君一夜恩，争奈忒达地、忒知根，兼上亲上成亲好对门。","觑了他兀的模样，这般身分。","若脱过这好郎君。"],"source":"元曲"},{"title":"汝坟","author":"佚名","dynasty":"先秦","form":"诗","lines":["遵彼汝坟，伐其条枚。未见君子，惄如调饥。","遵彼汝坟，伐其条肄。既见君子，不我遐弃。","鲂鱼赪尾，王室如毁。虽则如毁，父母孔迩。"],"source":"《诗经》"},{"title":"山鬼","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["若有人兮山之阿，被薜茘兮带女萝","既含睇兮又宜笑，子慕予兮善窈窕","乗赤豹兮从文狸，辛夷车兮结桂旗","被石兰兮带杜衡，折芬馨兮遗所思","余处幽篁兮终不见天，路险难兮独后来","表独立兮山之上，云容容兮而在下","杳冥冥兮羌昼晦，东风飘兮神灵雨","留灵修兮憺忘归，岁既晏兮孰华予","采三秀兮于山间，石磊磊兮葛蔓蔓","怨公子兮怅忘归，君思我兮不得闲","山中人兮芳杜若，饮石泉兮荫松柏","君思我兮然疑作","雷填填兮雨冥冥，猿啾啾兮狖夜鸣","风飒飒兮木萧萧，思公子兮徒离忧。"],"source":"《楚辞》"},{"title":"蝉","author":"李商隠","dynasty":"唐","form":"诗","lines":["本以高难饱，徒労恨费声。","五更疏欲断，一树碧无情。","薄宦梗犹泛，故园芜已平。","烦君最相警，我亦挙家清。"],"source":"《唐诗三百首》"},{"title":"続长恨歌七首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["紫薇金屋闭春阳，石竹山花却自芳。","莫道故情无觅処，领巾犹有隔生香。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["辘轳春又转。","记旋草新词，江头凭雁。","乗槎上银汉。","想车尘才踏，东华红软。","何时赐见。","漏声移、深宫夜半。","问莼鲈、今岁西风，未觉岁华迟晩。","一片。","丹心白发，露滴研朱，雅陪清宴。","班回柳院。","蒲团底，小禅观。","望罘罳明月，初圆此夕，应共婵娟茂苑。","愿年年、玉兔长生，耸秋井干。"],"source":"宋词"},{"title":"诈妮子调风月・幺篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["教人道\"眼里无珍一世贫\"；成就了又怕辜恩。","若往常烈焔飞腾情性紧，若一遭儿恩爱，再来不问，枉侵了这百年恩。"],"source":"元曲"},{"title":"麟之趾","author":"佚名","dynasty":"先秦","form":"诗","lines":["麟之趾，振振公子，于嗟麟兮。","麟之定，振振公姓，于嗟麟兮。","麟之角，振振公族，于嗟麟兮。"],"source":"《诗经》"},{"title":"国殇","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["操吴戈兮被犀甲，车错毂兮短兵接","旌蔽日兮敌若云，矢交坠兮士争先","凌余阵兮躐余行，左骖殪兮右刃伤","霾两轮兮絷四马，援玉枹兮击鸣鼓","天时怼兮威灵怒，严杀尽兮弃原野","出不入兮往不反，平原忽兮路超远","带长剑兮挟秦弓，首身离兮心不惩","诚既勇兮又以武，终刚强兮不可凌","身既死兮神以灵，魂魄毅兮为鬼雄。"],"source":"《楚辞》"},{"title":"楽游原","author":"李商隠","dynasty":"唐","form":"诗","lines":["向晩意不适，駆车登古原。","夕阳无限好，只是近黄昏。"],"source":"《唐诗三百首》"},{"title":"続长恨歌七首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["闻道蓬壶重见时，痩来全不耐风吹。","无端却作尘间念，已被仙官圣得知。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["夜寒吴馆窄。","渐酒阑烛暗，犹分香泽。","轻帆展为翮。","送高鸿飞过，长安南陌。","渔矶旧迹。","有陈蕃、虚床挂壁。","掩庭扉，蛛网黏花，细草摇春碧。","还忆。","洛阳年少，风露秋檠，岁华如昔。","长吟堕帻。","暮潮送，富春客。","算玉堂不染，梅花清梦，宫漏声中夜直。","正逋仙、清痩黄昏，几时觅得。"],"source":"宋词"},{"title":"诈妮子调风月・柳叶儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["一个个背槽抛粪，一个个负义忘恩，自来鱼雁无音信。","自思忖，不审得话儿真，枉葫芦提了\"燕尔新婚。"],"source":"元曲"},{"title":"鹊巣","author":"佚名","dynasty":"先秦","form":"诗","lines":["维鹊有巣，维鸠居之。之子于归，百两御之。","维鹊有巣，维鸠方之。之子于归，百两将之。","维鹊有巣，维鸠盈之。之子于归，百两成之。"],"source":"《诗经》"},{"title":"礼魂","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["成礼兮会鼓，","传芭兮代舞","姱女倡兮容与","春兰兮秋菊，","长无绝兮终古。"],"source":"《楚辞》"},{"title":"夜雨寄北","author":"李商隠","dynasty":"唐","form":"诗","lines":["君问帰期未有期，巴山夜雨涨秋池。","何当共剪西窗烛，却话巴山夜雨时。"],"source":"《唐诗三百首》"},{"title":"続长恨歌七首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["别后相思梦亦难，东虚云路海漫漫。","仙凡顿隔银屏影，不似当时取次看。"],"source":"宋诗"},{"title":"瑞鹤仙","author":"吴文英","dynasty":"宋","form":"词","lines":["彩云栖翡翠。","听凤笙吹下，飞𫐌天际。","晴霞翦轻袂。","澹春姿雪态，寒梅清泚。","东皇有意。","旋安排、阑干十二。","早不知、为雨为云，尽日建章门闭。","堪比。","红绡纤素，紫燕轻盈，内家标致。","游仙旧事。","星斗下，夜香里。","□华峰□□，纸屏横幅，春色长供午睡。","更酔乗、玉井秋风，采花弄水。"],"source":"宋词"},{"title":"诈妮子调风月・尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["忽地却掀帘，兜地回头问，不由我心儿里便亲。","你把那并枕睡的日头儿再定轮，休教我逐宵价握雨携云。","过今春，先教我不系腰裙，便是半簸箕头钱扑个复纯。","教人道\"眼里有珍\"，你可休\"言而无信\"！（云）许下我包髻、团衫、绣手巾。","专等你世袭千户的小夫人。","（下）。"],"source":"元曲"},{"title":"采蘩","author":"佚名","dynasty":"先秦","form":"诗","lines":["于以采蘩？于沼于沚。于以用之？公侯之事。","于以采蘩？于涧之中。于以用之？公侯之宫。","被之僮僮，夙夜在公。被之祁祁，薄言还归。"],"source":"《诗经》"},{"title":"天问","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["曰：","遂古之初，谁传道之？","上下未形，何由考之？","冥昭瞢暗，谁能极之？","冯翼惟象，何以识之？","明明暗暗，惟时何为？","阴阳三合，何本何化？","圜则九重，孰营度之？","惟兹何功，孰初作之？","斡维焉系，天极焉加？","八柱何当，东南何亏？","九天之际，安放安属？","隅隈多有，谁知其数？","天何所沓？","十二焉分？","日月安属？","列星安陈？","出自汤谷，次于蒙汜。","自明及晦，所行几里？","夜光何徳，死则又育？","厥利维何，而顾菟在腹？","女岐无合，夫焉取九子？","伯强何处？","恵气安在？","何阖而晦？","何开而明？","角宿未旦，曜灵安蔵？","不任汩鸿，师何以尚之？","佥曰","“何忧，何不课而行之？”","鸱龟曳衔，鲧何听焉？","顺欲成功，帝何刑焉？","永遏在羽山，夫何三年不施？","伯禹愎鲧，夫何以变化？","纂就前绪，遂成考功。","何续初继业，而厥谋不同？","洪泉极深，何以窴之？","地方九则，何以坟之？","河海应龙？","何尽何历？","鲧何所营？","禹何所成？","康回冯怒，墬何故以东南倾？","九州安错？","川谷何洿？","东流不溢，孰知其故？","东西南北，其修孰多？","南北顺椭，其衍几何？","昆仑悬圃，其尻安在？","増城九重，其高几里？","四方之门，其谁从焉？","西北辟启，何气通焉？","日安不到？","烛龙何照？","羲和之未扬，若华何光？","何所冬暖？","何所夏寒？","焉有石林？","何兽能言？","焉有虬龙，负熊以游？","雄虺九首，鯈忽焉在？","何所不死？","长人何守？","靡蓱九衢，枲华安居？","灵蛇吞象，厥大何如？","黒水玄趾，三危安在？","延年不死，寿何所止？","鲮鱼何所？","鬿堆焉处？","羿焉𪪼日？","乌焉解羽？","禹之力献功，降省下土四方。","焉得彼嵞山女，而通之于台桑？","闵妃匹合，厥身是继。","胡维嗜不同味，而快鼌饱？","启代益作后，卒然离蠥。","何启惟忧，而能拘是达？","皆归射鞫，而无害厥躬。","何后益作革，而禹播降？","启棘宾商，《九弁》《九歌》。","何勤子屠母，而死分竟地？","帝降夷羿，革孽夏民。","胡射夫河伯，而妻彼雒嫔？","冯珧利决，封豨是射。","何献蒸肉之膏，而后帝不若？","浞娶纯狐，眩妻爰谋。","何羿之射革，而交吞揆之？","阻穷西征，岩何越焉？","化而为黄熊，巫何活焉？","咸播秬黍，莆雚是营。","何由并投，而鲧疾修盈？","白蜺婴茀，胡为此堂？","安得夫良药，不能固臧？","天式从横，阳离爰死。","大鸟何鸣，夫焉丧厥体？","蓱号起雨，何以兴之？","撰体协胁，鹿何膺之？","鳌戴山抃，何以安之？","释舟陵行，何之迁之？","惟浇在户，何求于嫂？","何少康逐犬，而颠陨厥首？","女歧缝裳，而馆同爰止。","何颠易厥首，而亲以逢殆？","汤谋易旅，何以厚之？","覆舟斟寻，何道取之？","桀伐蒙山，何所得焉？","妺嬉何肆，汤何殛焉？","舜闵在家，父何以鳏？","尧不姚告，二女何亲？","厥萌在初，何所亿焉？","璜台十成，谁所极焉？","登立为帝，孰道尚之？","女娲有体，孰制匠之？","舜服厥弟，终然为害。","何肆犬豕，而厥身不危败？","吴获迄古，南岳是止。","孰期去斯，得两男子？","缘鹄饰玉，后帝是飨。","何承谋夏桀，终以灭丧？","帝乃降观，下逢伊挚。","何条放致罚，而黎服大说？","简狄在台，喾何宜？","玄鸟致贻，女何喜？","该秉季徳，厥父是臧。","胡终弊于有扈，牧夫牛羊？","干协时舞，何以怀之？","平胁曼肤，何以肥之？","有扈牧竖，云何而逢？","击床先出，其命何从？","恒秉季徳，焉得夫朴牛？","何往营班禄，不但还来？","昏微循迹，有狄不宁。","何繁鸟萃棘，负子肆情？","眩弟并淫，危害厥兄。","何变化以作诈，而后嗣逢长？","成汤东巡，有莘爰极。","何乞彼小臣，而吉妃是得？","水滨之木，得彼小子。","夫何恶之，媵有莘之妇？","汤出重泉，夫何辠尤？","不胜心伐帝，夫谁使挑之？","会朝争盟，何践吾期？","苍鸟群飞，孰使萃之？","列击纣躬，叔旦不嘉。","何亲揆发足，周之命以咨嗟？","授殷天下，其位安施？","反成乃亡，其罪伊何？","争遣伐器，何以行之？","并驱击翼，何以将之？","昭后成游，南土爰底。","厥利惟何，逢彼白雉？","穆王巧梅，夫何为周流？","环理天下，夫何索求？","妖夫曳炫，何号于市？","周幽谁诛？","焉得夫褒姒？","天命反侧，何罚何佑？","齐桓九会，卒然身杀。","彼王纣之躬，孰使乱惑？","何恶辅弼，谗谄是服？","比干何逆，而抑沈之？","雷开阿顺，而赐封之？","何圣人之一徳，卒其异方？","梅伯受醢，箕子详狂？","稷维元子，帝何竺之？","投之于冰上，鸟何燠之？","何冯弓挟矢，殊能将之？","既惊帝切激，何逢长之？","伯昌号衰，秉鞭作牧。","何令彻彼岐社，命有殷国？","迁蔵就岐，何能依？","殷有惑妇，何所讥？","受赐兹醢，西伯上告。","何亲就上帝罚，殷之命以不救？","师望在肆，昌何识？","鼓刀扬声，后何喜？","武发杀殷，何所悒？","载尸集战，何所急？","伯林雉经，维其何故？","何感天抑墬，夫谁畏惧？","皇天集命，惟何戒之？","受礼天下，又使至代之？","初汤臣挚，后兹承辅。","何卒官汤，尊食宗绪？","勋阖梦生，少离散亡。","何壮武历，能流厥严？","彭铿斟雉，帝何飨？","受寿永多，夫何久长？","中央共牧，后何怒？","蜂蛾微命，力何固？","惊女采薇，鹿何佑？","北至回水，萃何喜？","兄有噬犬，弟何欲？","易之以百两，卒无禄？","薄暮雷电，归何忧？","厥严不奉，帝何求？","伏匿穴处，爰何云？","荆勋作师，夫何长？","悟过改更，我又何言？","吴光争国，久余是胜。","何环穿自闾社丘陵，爰出子文？","吾告堵敖以不长。","何试上自予，忠名弥彰？"],"source":"《楚辞》"},{"title":"韩碑","author":"李商隠","dynasty":"唐","form":"诗","lines":["元和天子神武姿，彼何人哉轩与羲。","誓将上雪列圣耻，坐法宫中朝四夷。","淮西有贼五十载，封狼生䝙䝙生罴。","不拠山河拠平地，长戈利矛日可麾。","帝得圣相相曰度，贼斫不死神扶持。","腰悬相印作都统，阴风惨澹天王旗。","愬武古通作牙爪，仪曹外郎载笔随。","行军司马智且勇，十四万众犹虎貔。","入蔡缚贼献太庙，功无与譲恩不訾。","帝曰汝度功第一，汝従事愈宜为辞。","愈拝稽首蹈且舞，金石刻画臣能为。","古者世称大手笔，此事不繋于职司。","当仁自古有不譲，言讫屡颔天子颐。","公退斎戒坐小阁，濡染大笔何淋漓。","点窜尧典舜典字，涂改清庙生民诗。","文成破体书在纸，清晨再拝舗丹墀。","表曰臣愈昧死上，咏神圣功书之碑。","碑高三丈字如斗，负以霊鼇蟠以螭。","句奇语重喻者少，谗之天子言其私。","长縄百尺拽碑倒，麤砂大石相磨治。","公之斯文若元気，先时已入人肝脾。","汤盘孔鼎有述作，今无其器存其辞。","呜呼圣皇及圣相，相与烜赫流淳熙。","公之斯文不示后，曷与三五相攀追。","愿书万本诵万过，口角流沫右手胝。","伝之七十有二代，以为封禅玉検明堂基。"],"source":"《唐诗三百首》"},{"title":"続长恨歌七首  其五","author":"范成大","dynasty":"宋","form":"诗","lines":["人似飞花去不帰，兰昌宫殿几斜晖。","百年只有云容姊，留得当时旧舞衣。"],"source":"宋诗"},{"title":"满江红","author":"吴文英","dynasty":"宋","form":"词","lines":["云气楼台，分一派、沧浪翠蓬。","开小景、玉盆寒浸，巧石盘松。","风送流花时过岸，浪摇晴练欲飞空。","算鲛宫、祗隔一红尘，无路通。","神女驾、凌晓风。","明月佩，响丁东。","对两蛾犹锁，怨绿烟中。","秋色未教飞尽雁，夕阳长是坠疏钟。","又一声、欸乃过前岩，移钓篷。"],"source":"宋词"},{"title":"诈妮子调风月・中吕/粉蝶儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["年例寒食，邻姬毎斗来邀会，去年时没人将我拘管収拾。","打秋千，闲斗草，直到个昏天黒地；今年个不敢来迟，有一个未拿着性儿女婿。"],"source":"元曲"},{"title":"草虫","author":"佚名","dynasty":"先秦","form":"诗","lines":["喓喓草虫，趯趯阜螽。未见君子，忧心忡忡。亦既见止，亦既觏止，我心则降。","陟彼南山，言采其蕨。未见君子，忧心惙惙。亦既见止，亦既觏止，我心则说。","陟彼南山，言采其薇。未见君子，我心伤悲。亦既见止，亦既觏止，我心则夷。"],"source":"《诗经》"},{"title":"惜诵","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["惜诵以致愍兮，发愤以抒情。","所作忠而言之兮，指苍天以为正。","令五帝使折中兮，戒六神与向服。","俾山川以备御兮，命咎繇使听直。","竭忠诚而事君兮，反离群而赘肬。","忘儇媚以背众兮，待明君其知之。","言与行其可迹兮，情与貌其不变。","故相臣莫若君兮，所以证之不远。","吾谊先君而后身兮，羌众人之所仇也。","专惟君而无他兮，又众兆之所雠也。","壱心而不予兮，羌无可保也。","疾亲君而无他兮，有招祸之道也。","思君其莫我忠兮，忽忘身之贱贫。","事君而不贰兮，迷不知宠之门。","患何罪以遇罚兮，亦非余之所志也。","行不群以巅越兮，又众兆之所咍也。","纷逢尤以离谤兮，謇不可释也。","情沉抑而不达兮，又蔽而莫之白也。","心郁邑余侘傺兮，又莫察余之中情。","固烦言不可结而诒兮，愿陈志而无路。","退静黙而莫余知兮，进号呼又莫吾闻。","申侘傺之烦惑兮，中闷瞀之忳忳。","昔余梦登天兮，魂中道而无杭。","吾使厉神占之兮，曰有志极而无旁。","终危独以离异兮，曰君可思而不可恃。","故众口其铄金兮，初若是而逢殆。","惩于羹者而吹齑兮，何不变此志也？","欲释阶而登天兮，犹有曩之态也。","众骇遽以离心兮，又何以为此伴也？","同极而异路兮，又何以为此援也？","晋申生之孝子兮，父信谗而不好。","行婞直而不予兮，鲧功用而不就。","吾闻作忠以造怨兮，忽谓之过言。","九折臂而成医兮，吾至今而知其信然。","矰弋机而在上兮，罻罗张而在下。","设张辟以娱君兮，愿侧身而无所。","欲儃徊以干傺兮，恐重患而离尤。","欲高飞而远集兮，君罔谓汝何之？","欲横奔而失路兮，盖志坚而不忍。","背膺牉以交痛兮，心郁结而纡轸。","捣木兰以矫蕙兮，糳申椒以为粮。","播江离与滋菊兮，愿春日以为糗芳。","恐情质之不信兮，故重着以自明。","矫兹媚以私处兮，愿曽思而远身。"],"source":"《楚辞》"},{"title":"风雨","author":"李商隠","dynasty":"唐","form":"诗","lines":["凄凉宝剣篇，羁泊欲穷年。","黄叶仍风雨，青楼自管弦。","新知遭薄俗，旧好隔良縁。","心断新豊酒，销愁斗几千。"],"source":"《唐诗三百首》"},{"title":"続长恨歌七首  其六","author":"范成大","dynasty":"宋","form":"诗","lines":["骊山六十二高楼，突兀华清最上头。","玉羽川长湘浦暗，三郎无事更神游。"],"source":"宋诗"},{"title":"满江红","author":"吴文英","dynasty":"宋","form":"词","lines":["结束萧仙，啸梁鬼、依还未灭。","荒城外、无聊闲看，野烟一抹。","梅子未黄愁夜雨，榴花不见簪秋雪。","又重罗、红字写香词，年时节。","帘底事，凭燕说。","合欢缕，双条脱。","自香消红臂，旧情都别。","湘水离魂菰叶怨，扬州无梦铜华阙。","倩卧箫、吹裂晩天云，看新月。"],"source":"宋词"},{"title":"诈妮子调风月・酔春风","author":"关汉卿","dynasty":"元","form":"曲","lines":["因甚把玉粳米牙儿抵，金莲花攒枕倚？或嗔或喜脸儿多？哎！你、你！教我没想没思，两心两意，早晨古自一家一计！。"],"source":"元曲"},{"title":"采苹","author":"佚名","dynasty":"先秦","form":"诗","lines":["于以采苹？南涧之滨。于以采藻？于彼行潦。","于以盛之？维筐及筥。于以湘之？维锜及釜。","于以奠之？宗室牖下。谁其尸之？有齐季女。"],"source":"《诗经》"},{"title":"渉江","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["余幼好此奇服兮，年既老而不衰。","带长铗之陆离兮，冠切云之崔嵬，被明月兮佩宝璐。","世混浊而莫余知兮，吾方高驰而不顾。","驾青虬兮骖白螭，吾与重华游兮瑶之圃。","登昆仑兮食玉英，与天地兮同寿，与日月兮同光。","哀南夷之莫吾知兮，旦余济乎江湘。","乗鄂渚而反顾兮，欸秋冬之绪风。","歩余马兮山皐，邸余车兮方林。","乗舲船余上沅兮，齐吴榜以击汰。","船容与而不进兮，淹回水而疑滞。","朝发枉渚兮，夕宿辰阳。","苟余心其端直兮，虽僻远之何伤。","入溆浦余儃徊兮，迷不知吾所如。","深林杳以冥冥兮，猿狖之所居。","山峻高以蔽日兮，下幽晦以多雨。","霰雪纷其无垠兮，云霏霏而承宇。","哀吾生之无乐兮，幽独处乎山中。","吾不能变心而从俗兮，固将愁苦而终穷。","接舆髡首兮，桑扈臝行。","忠不必用兮，贤不必以。","伍子逢殃兮，比干菹醢。","与前世而皆然兮，吾又何怨乎今之人！","余将董道而不予兮，固将重昏而终身！","乱曰：","鸾鸟凤皇，日以远兮。","燕雀乌鹊，巣堂坛兮。","露申辛夷，死林薄兮。","腥臊并御，芳不得薄兮。","阴阳易位，时不当兮。","怀信佗傺，忽乎吾将行兮！"],"source":"《楚辞》"},{"title":"寄令狐郎中","author":"李商隠","dynasty":"唐","form":"诗","lines":["嵩云秦树久离居，双鲤迢迢一纸书。","休问梁园旧宾客，茂陵秋雨病相如。"],"source":"《唐诗三百首》"},{"title":"続长恨歌七首  其七","author":"范成大","dynasty":"宋","form":"诗","lines":["帝郷云驭若为留，八景三清好在不。","玉笛不随双鹤去，人间犹得聴梁州。"],"source":"宋诗"},{"title":"解连环","author":"吴文英","dynasty":"宋","form":"词","lines":["暮檐凉薄。","疑清风动竹，故人来邈。","渐夜久、闲引流萤，弄微照素怀，暗呈纤白。","梦远双成，凤笙杳、玉绳西落。","掩𦈌帷倦入，又惹旧愁，汗香阑角。","银瓶恨沈断索。","叹梧桐未秋，露井先觉。","抱素影、明月空闲，早尘损丹青，楚山依约。","翠冷红衰，怕惊起、西池鱼跃。","记湘娥、绛绡暗解，褪花坠萼。"],"source":"宋词"},{"title":"诈妮子调风月・朱履曲","author":"关汉卿","dynasty":"元","form":"曲","lines":["莫不是郊外去逢着甚邪祟？又不疯又不呆痴，面没罗、呆答孩、死堆灰。","这烦恼在谁身上？莫不在我根底，打听得些闲是非？。"],"source":"元曲"},{"title":"甘棠","author":"佚名","dynasty":"先秦","form":"诗","lines":["蔽芾甘棠，勿翦勿伐，召伯所茇。","蔽芾甘棠，勿翦勿败，召伯所憩。","蔽芾甘棠，勿翦勿拝，召伯所说。"],"source":"《诗经》"},{"title":"哀郢","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["皇天之不纯命兮，何百姓之震愆？","民离散而相失兮，方仲春而东迁。","去故乡而就远兮，遵江夏以流亡。","出国门而轸怀兮，甲之鼌吾以行。","发郢都而去闾兮，怊荒忽其焉极？","楫齐扬以容与兮，哀见君而不再得。","望长楸而太息兮，涕淫淫其若霰。","过夏首而西浮兮，顾龙门而不见。","心婵媛而伤怀兮，眇不知其所跖。","顺风波以从流兮，焉洋洋而为客。","凌阳侯之汜滥兮，忽翱翔之焉薄。","心絓结而不解兮，思蹇产而不释。","将运舟而下浮兮，上洞庭而下江。","去终古之所居兮，今逍遥而来东。","羌灵魂之欲归兮，何须臾而忘反。","背夏浦而西思兮，哀故都之日远。","登大坟以远望兮，聊以舒吾忧心。","哀州土之平乐兮，悲江介之遗风。","当陵阳之焉至兮，淼南渡之焉如？","曽不知夏之为丘兮，孰两东门之可芜？","心不怡之长久兮，忧与愁其相接。","惟郢路之辽远兮，江与夏之不可渉。","忽若不信兮，至今九年而不复。","惨郁郁而不通兮，蹇侘傺而含戚。","外承欢之汋约兮，谌荏弱而难持。","忠湛湛而愿进兮，妒被离而鄣之。","尧舜之抗行兮，瞭杳杳而薄天。","众谗人之嫉妒兮，被以不慈之伪名。","憎愠惀之修美兮，好夫人之慷慨。","众踥蹀而日进兮，美超远而逾迈。","乱曰：","曼余目以流观兮，冀一反之何时？","鸟飞反故乡兮，狐死必首丘。","信非吾罪而弃逐兮，何日夜而忘之？"],"source":"《楚辞》"},{"title":"隋宫","author":"李商隠","dynasty":"唐","form":"诗","lines":["紫泉宫殿锁烟霞，欲取芜城作帝家。","玉玺不縁帰日角，锦帆応是到天涯。","于今腐草无蛍火，终古垂杨有暮鸦。","地下若逢陈后主，岂宜重问后庭花。"],"source":"《唐诗三百首》"},{"title":"雷雨邻舎起竜","author":"范成大","dynasty":"宋","form":"诗","lines":["雨工避事欲蟠泥，帝遣豊隆执以帰。","连鼓一声人失箸，不知挂壁几梭飞。"],"source":"宋诗"},{"title":"解连环","author":"吴文英","dynasty":"宋","form":"词","lines":["思和云结。","断江楼望睫，雁飞无极。","正岸柳、衰不堪攀，忍持赠故人，送秋行色。","岁晩来时，暗香乱、石桥南北。","又长亭暮雪，点点泪痕，总成相忆。","杯前寸阴似掷。","几酬花唱月，连夜浮白。","省听风、听雨笙箫，向别枕倦醒，絮扬空碧。","片叶愁红，趁一舸、西风潮汐。","叹沧波、路长梦短，甚时到得。"],"source":"宋词"},{"title":"诈妮子调风月・满庭芳","author":"关汉卿","dynasty":"元","form":"曲","lines":["见我这般微微喘息，语言恍惚，脚歩儿查梨。","慢松松胸带儿频那系，裙腰儿空闲里偷提。","见我这般气丝丝偏斜了髟。"],"source":"元曲"},{"title":"行露","author":"佚名","dynasty":"先秦","form":"诗","lines":["厌浥行露，岂不夙夜，谓行多露。","谁谓雀无角？何以穿我屋？谁谓女无家？何以速我狱？虽速我狱，室家不足！","谁谓鼠无牙？何以穿我墉？谁谓女无家？何以速我讼？虽速我讼，亦不女从！"],"source":"《诗经》"},{"title":"抽思","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["心郁郁之忧思兮，独永叹乎増伤。","思蹇产之不释兮，曼遭夜之方长。","悲秋风之动容兮，何回极之浮浮。","数惟荪之多怒兮，伤余心之忧忧。","愿摇起而横奔兮，览民尤以自镇。","结微情以陈词兮，矫以遗夫美人。","昔君与我诚言兮，曰黄昏以为期。","羌中道而回畔兮，反既有此他志。","憍吾以其美好兮，览余以其修姱。","与余言而不信兮，盖为余而造怒。","愿承闲而自察兮，心震悼而不敢。","悲夷犹而冀进兮，心怛伤之憺憺。","兹历情以陈辞兮，荪详聋而不闻。","固切人之不媚兮，众果以我为患。","初吾所陈之耿着兮，岂至今其庸亡？","何独乐斯之謇謇兮？","愿荪美之可光。","望三王以为像兮，指彭咸以为仪。","夫何极而不至兮，故远闻而难亏。","善不由外来兮，名不可以虚作。","孰无施而有报兮，孰不实而有获？","少歌曰：与美人抽思兮，并日夜而无正。","憍吾以其美好兮，敖朕辞而不听。","倡曰：","有鸟自南兮，来集汉北。","好姱佳丽兮，牉独处此异域。","惸茕独而不群兮，又无良媒在其侧。","道卓远而日忘兮，愿自申而不得。","望北山而流涕兮，临流水而太息。","望孟夏之短夜兮，何晦明之若岁？","惟郢路之辽远兮，魂一夕而九逝。","曽不知路之曲直兮，南指月与列星。","愿径逝而未得兮，魂识路之营营。","何灵魂之信直兮，人之心不与吾心同！","理弱而媒不通兮，尚不知余之从容。","乱曰：","长濑湍流，溯江潭兮。","狂顾南行，聊以娱心兮。","轸石崴嵬，蹇吾愿兮。","超回志度，行隐进兮。","低徊夷犹，宿北姑兮。","烦冤瞀容，实沛徂兮。","愁叹苦神，灵遥思兮。","路远处幽，又无行媒兮。","道思作颂，聊以自救兮。","忧心不遂，斯言谁告兮。"],"source":"《楚辞》"},{"title":"筹笔駅","author":"李商隠","dynasty":"唐","form":"诗","lines":["猿鸟犹疑畏简书，风云常为护储胥。","徒令上将挥神笔，终见降王走伝车。","管楽有才终不忝，関张无命欲何如。","他年锦里経祠庙，梁父吟成恨有余。"],"source":"《唐诗三百首》"},{"title":"次韵唐致远雨后喜凉","author":"范成大","dynasty":"宋","form":"诗","lines":["老阳作気再三衰，鼓竭之余不支雨。","搴旗抜帜埽迹空，一点新凉破残暑。","飞蚊薨薨已无奇，蜻蜓翅浄摩天嬉。","竹窗日暮転萧瑟，喜有促织鸣声悲。"],"source":"宋诗"},{"title":"夜飞鹊・夜飞鹊慢","author":"吴文英","dynasty":"宋","form":"词","lines":["金规印遥汉，庭浪无纹。","清雪冷沁花薫。","天衔曽酔美人畔，凉枝移挿乌巾。","西风骤惊散，念棱悬愁结，蒂翦离恨。","中郎旧恨，寄横竹、吹裂哀云。","空剰露华烟彩，人影断幽坊，深闭千门。","浑似飞仙入梦，袜罗微歩，流水青苹。","轻冰润□，怅今朝、不共清尊。","怕云槎来晩，流红信杳，萦断秋魂。"],"source":"宋词"},{"title":"诈妮子调风月・十二月","author":"关汉卿","dynasty":"元","form":"曲","lines":["直到个天昏地黒，不肯更换衣袂；把兔鹘解开，纽扣相离，把袄子疏剌剌松开上拆，将手帕撇漾在田地。"],"source":"元曲"},{"title":"羔羊","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔羊之皮，素丝五紽。退食自公，委蛇委蛇。","羔羊之革，素丝五緎。委蛇委蛇，自公退食。","羔羊之缝，素丝五总。委蛇委蛇，退食自公。"],"source":"《诗经》"},{"title":"怀沙","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["滔滔孟夏兮，草木莽莽。","伤怀永哀兮，汩徂南土。","眴兮杳杳，孔静幽黙。","郁结纡轸兮，离慜而长鞠。","抚情効志兮，冤屈而自抑。","刓方以为圜兮，常度未替。","易初本迪兮，君子所鄙。","章画志墨兮，前图未改。","内厚质正兮，大人所盛。","巧倕不斲兮，孰察其拨正。","玄文处幽兮，蒙瞍谓之不章","离娄微睇兮，瞽以为无明。","变白以为黒兮，倒上以为下。","凤皇在笯兮，鸡鹜翔舞。","同糅玉石兮，一概而相量。","夫惟党人之鄙固兮，羌不知余之所臧。","任重载盛兮，陥滞而不济。","怀瑾握瑜兮，穷不知所示。","邑犬之群吠兮，吠所怪也。","非俊疑杰兮，固庸态也。","文质疏内兮，众不知余之异采。","材朴委积兮，莫知余之所有。","重仁袭义兮，谨厚以为丰。","重华不可遌兮，孰知余之从容！","古固有不并兮，岂知其何故也？","汤禹久远兮，邈而不可慕也？","惩违改忿兮，抑心而自强。","离慜而不迁兮，愿志之有像。","进路北次兮，日昧昧其将暮。","舒忧娱哀兮，限之以大故。","乱曰：","浩浩沅湘，分流汩兮。","修路幽蔽，道远忽兮。","怀质抱情，独无匹兮。","伯乐既没，骥焉程兮。","民生禀命，各有所错兮。","定心广志，余何所畏惧兮？","曽伤爰哀，永叹喟兮。","世浑浊莫吾知，人心不可谓兮。","知死不可让，愿勿爱兮。","明告君子，吾将以为类兮。"],"source":"《楚辞》"},{"title":"无题二首 一","author":"李商隠","dynasty":"唐","form":"诗","lines":["昨夜星辰昨夜风，画楼西畔桂堂东。","身无彩凤双飞翼，心有霊犀一点通。","隔座送钩春酒暖，分曹射复蝋灯红。","嗟余聴鼓応官去，走马兰台类断蓬。"],"source":"《唐诗三百首》"},{"title":"秋日二绝  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["碧芦青柳不宜霜，染作沧洲一带黄。","莫把江山夸北客，冷云寒水更荒凉。"],"source":"宋诗"},{"title":"一寸金","author":"吴文英","dynasty":"宋","form":"词","lines":["秋入中山，臂隼牵卢纵长猎。","见骇毛飞雪，章台献颖，臞腰束缟，汤沐疏邑。","筤管刊琼牒。","苍梧恨、帝娥暗泣。","陶郎老、憔悴玄香，禁苑犹催夜俱入。","自叹江湖，雕龙心尽，相携蠹鱼箧。","念酔魂悠扬，折钗锦字，黠髯掀舞，流觞春帖。","还倚荆渓楫。","金刀氏、尚传旧业。","劳君为、脱帽篷窗，寓情题水叶。"],"source":"宋词"},{"title":"诈妮子调风月・尧民歌","author":"关汉卿","dynasty":"元","form":"曲","lines":["见那厮手慌脚乱紧収拾，被我先蔵在香罗袖儿里。","是好哥哥和我做头敌，咱两个官司有商议。","休提！体提！哥哥撇下的手帕是阿谁的？（末云了）（正旦唱）。"],"source":"元曲"},{"title":"殷其雷","author":"佚名","dynasty":"先秦","form":"诗","lines":["殷其雷，在南山之阳。何斯违斯，莫敢或遑？振振君子，归哉归哉！","殷其雷，在南山之侧。何斯违斯，莫敢遑息？振振君子，归哉归哉！","殷其雷，在南山之下。何斯违斯，莫或遑处？振振君子，归哉归哉！"],"source":"《诗经》"},{"title":"思美人","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["思美人兮，揽涕而𥩟眙。","媒绝路阻兮，言不可结而诒。","蹇蹇之烦冤兮，陥滞而不发。","申旦以舒中情兮，志沉菀而莫达。","愿寄言于浮云兮，遇丰隆而不将。","因归鸟而致辞兮，羌迅高而难当。","高辛之灵盛兮，遭玄鸟而致诒。","欲变节以从俗兮，媿易初而屈志。","独历年而离愍兮，羌凭心犹未化。","宁隐闵而寿考兮，何变易之可为！","知前辙之不遂兮，未改此度。","车既覆而马颠兮，蹇独怀此异路。","勒骐骥而更驾兮，造父为我操之，","迁逡次而勿驱兮，聊仮日以须是时。","指嶓冢之西隈兮，与𫄸黄以为期。","开春发岁兮，白日出之悠悠。","吾将荡志而愉乐兮，遵江夏以娱忧。","揽大薄之芳茝兮，搴长洲之宿莽。","惜吾不及古人兮，吾谁与玩此芳草？","解萹薄与杂菜兮，备以为交佩。","佩缤纷以缭转兮，遂萎绝而离异。","吾且儃徊以娱忧兮，观南人之变态。","窃快在中心兮，扬厥凭而不竢。","芳与泽其杂糅兮，羌芳华自中出。","纷郁郁其远蒸兮，满内而外扬。","情与质信可保兮，羌居蔽而闻章。","令薜茘以为理兮，惮举趾而缘木。","因芙蓉而为媒兮，惮褰裳而濡足。","登高吾不说兮，入下吾不能。","固朕形之不服兮，然容与而狐疑。","广遂前画兮，未改此度也。","命则处幽吾将罢兮，愿及白日之未暮也。","独茕茕而南行兮，思彭咸之故也。"],"source":"《楚辞》"},{"title":"无题四首 一","author":"李商隠","dynasty":"唐","form":"诗","lines":["来是空言去绝踪，月斜楼上五更钟。","梦为远别啼难唤，书被催成墨未浓。","蝋照半笼金翡翠，麝熏微度繍芙蓉。","刘郎已恨蓬山远，更隔蓬山一万重。"],"source":"《唐诗三百首》"},{"title":"秋日二绝  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["新秋病骨顿成衰，不度渓桥半月来。","无事闭门非左计，饶渠屐歯上青苔。"],"source":"宋诗"},{"title":"一寸金","author":"吴文英","dynasty":"宋","form":"词","lines":["秋压更长，看见姮娥痩如束。","正古花摇落，寒蛩满地，参梅吹老，玉龙横竹。","霜被芙蓉宿。","红绵透、尚欺暗烛。","年年记、一种凄凉，绣幌金圆挂香玉。","顽老情怀，都无欢事，良宵爱幽独。","叹画图难仿，橘村砧思，笠蓑有约，莼洲渔屋。","心景凭谁语，商弦重、袖寒转轴。","疏篱下、试觅重阳，酔擘青露菊。"],"source":"宋词"},{"title":"诈妮子调风月・江儿水","author":"关汉卿","dynasty":"元","form":"曲","lines":["老阿者使将来伏侍你，展汚了咱身起。","你养着别个的，看我如奴婢，燕燕那些儿亏负你？（旦做住）（末告科）（正旦唱）。"],"source":"元曲"},{"title":"摽有梅","author":"佚名","dynasty":"先秦","form":"诗","lines":["摽有梅，其实七兮。求我庶士，迨其吉兮。","摽有梅，其实三兮。求我庶士，迨其今兮。","摽有梅，顷筐塈之。求我庶士，迨其谓之。"],"source":"《诗经》"},{"title":"惜往日","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["惜往日之曽信兮，受命诏以昭时。","奉先功以照下兮，明法度之嫌疑。","国富强而法立兮，属贞臣而日竢。","秘密事之载心兮，虽过失犹弗治。","心纯庞而不泄兮，遭谗人而嫉之。","君含怒而待臣兮，不清澈其然否。","蔽晦君之聪明兮，虚惑误又以欺。","弗参验以考实兮，远迁臣而弗思。","信谗谀之浑浊兮，盛气志而过之。","何贞臣之无罪兮，被离谤而见尤。","惭光景之诚信兮，身幽隐而备之。","临沅湘之玄渊兮，遂自忍而沉流。","卒没身而绝名兮，惜壅君之不昭。","君无度而弗察兮，使芳草为薮幽。","焉舒情而抽信兮，恬死亡而不聊。","独障壅而弊隐兮，使贞臣为无由。","闻百里之为虏兮，伊尹烹于庖厨。","吕望屠于朝歌兮，宁戚歌而饭牛。","不逢汤武与桓缪兮，世孰云而知之。","吴信谗而弗味兮，子胥死而后忧。","介子忠而立枯兮，文君寤而追求。","封介山而为之禁兮，报大徳之优游。","思久故之亲身兮，因缟素而哭之。","或忠信而死节兮，或𫍙谩而不疑。","弗省察而按实兮，听谗人之虚辞。","芳与泽其杂糅兮，孰申旦而别之？","何芳草之早殀兮，微霜降而下戒。","谅聪不明而蔽壅兮，使谗谀而日得。","自前世之嫉贤兮，谓蕙若其不可佩。","妒佳冶之芬芳兮，嫫母姣而自好。","虽有西施之美容兮，谗妒入以自代。","愿陈情以白行兮，得罪过之不意。","情冤见之日明兮，如列宿之错置。","乗骐骥而驰骋兮，无辔衔而自载","乗泛泭以下流兮，无舟楫而自备。","背法度而心治兮，辟与此其无异。","宁溘死而流亡兮，恐祸殃之有再。","不毕辞而赴渊兮，惜壅君之不识。"],"source":"《楚辞》"},{"title":"无题四首 二","author":"李商隠","dynasty":"唐","form":"诗","lines":["飒飒东风细雨来，芙蓉塘外有軽雷。","金蟾啮鏁焼香入，玉虎牵糸汲井回。","贾氏窥帘韩掾少，宓妃留枕魏王才。","春心莫共花争発，一寸相思一寸灰。"],"source":"《唐诗三百首》"},{"title":"窗前木芙蓉","author":"范成大","dynasty":"宋","form":"诗","lines":["辛苦孤花破小寒，花心応似客心酸。","更凭青女留连得，未作愁红怨绿看。"],"source":"宋诗"},{"title":"绕仏阁","author":"吴文英","dynasty":"宋","form":"词","lines":["夜空似水，横汉静立，银浪声杳。","瑶镜奁小。","素娥乍起、楼心弄孤照。","絮云未巧。","梧韵露井，偏借秋早。","晴暗多少。","怕教彻胆，蟾光见怀抱。","浪迹尚为客，恨满长安千古道。","还记暗萤、穿帘街语悄。","叹歩影归来，人鬓花老。","紫箫天渺。","又露饮风前，凉堕轻帽。","酒杯空、数星横晓。"],"source":"宋词"},{"title":"诈妮子调风月・上小楼","author":"关汉卿","dynasty":"元","form":"曲","lines":["我敢摔砕这盒子，玳瑁纳子，教石头砸砕。","（带云）这手帕。","（唱）剪了做靴檐，染了做鞋面，持了做铺持。","一万分好待你，好觑你！如今刀子根底，我敢割得来粉零麻砕！。"],"source":"元曲"},{"title":"小星","author":"佚名","dynasty":"先秦","form":"诗","lines":["嘒彼小星，三五在东。肃肃宵征，夙夜在公。寔命不同！","嘒彼小星，维参与昴。肃肃宵征，抱衾与裯。寔命不犹！"],"source":"《诗经》"},{"title":"橘颂","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["后皇嘉树，橘徕服兮。","受命不迁，生南国兮。","深固难徙，更壱志兮。","绿叶素荣，纷其可喜兮。","曽枝剡棘，圆果抟兮。","青黄杂糅，文章烂兮。","精色内白，类任道兮。","纷缊宜修，姱而不丑兮。","嗟尔幼志，有以异兮。","独立不迁，岂不可喜兮？","深固难徙，廓其无求兮。","苏世独立，横而不流兮。","闭心自慎，终不失过兮。","秉徳无私，参天地兮。","愿岁并谢，与长友兮。","淑离不淫，梗其有理兮。","年岁虽少，可师长兮。","行比伯夷，置以为像兮。"],"source":"《楚辞》"},{"title":"隋宫","author":"李商隠","dynasty":"唐","form":"诗","lines":["乗兴南游不戒厳，九重谁省谏书函。","春风挙国裁宫锦，半作障泥半作帆。"],"source":"《唐诗三百首》"},{"title":"嘲里人新婚","author":"范成大","dynasty":"宋","form":"诗","lines":["冷艳頩容一笑开，休将鸾扇更徘徊。","箜篌细写帰舟字，仿佛游仙梦里来。"],"source":"宋诗"},{"title":"绕仏阁","author":"吴文英","dynasty":"宋","form":"词","lines":["蒨霞艳锦，星媛夜织，河汉鸣杼。","红翠万缕。","送幽梦与、人闲绣芳句。","怨宫恨羽。","孤风剑漫倚，无限凄楚。","□□□□。","赋情缥缈、东风扬花絮。","镜里半髯雪，向老春深莺晓处。","长闭翠阴、幽坊杨柳户。","看故苑离离，城外禾黍。","短藜青屦。","笑寄隐闲追，鸡社歌舞。","最风流、垫巾沾雨。"],"source":"宋词"},{"title":"诈妮子调风月・幺","author":"关汉卿","dynasty":"元","form":"曲","lines":["更做道你好处打唤来的，却怎看得非轻，看得值钱，待得尊贵？这两下里捻捎的，有多少功绩，到重如细搀绒绣来胸背？。"],"source":"元曲"},{"title":"江有汜","author":"佚名","dynasty":"先秦","form":"诗","lines":["江有汜，之子归，不我以。不我以，其后也悔。","江有渚，之子归，不我与。不我与，其后也处。","江有沱，之子归，不我过。不我过，其啸也歌。"],"source":"《诗经》"},{"title":"悲回风","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["悲回风之摇蕙兮，心冤结而内伤。","物有微而陨性兮，声有隐而先倡。","夫何彭咸之造思兮，曁志介而不忘！","万变其情岂可盖兮，孰虚伪之可长？","鸟兽鸣以号群兮，草苴比而不芳。","鱼葺鳞以自别兮，蛟龙隐其文章。","故荼荠不同亩兮，兰茝幽而独芳。","惟佳人之永都兮，更统世以自贶。","眇远志之所及兮，怜浮云之相羊。","介眇志之所惑兮，窃赋诗之所明。","惟佳人之独怀兮，折若椒以自处。","曽歔欷之嗟嗟兮，独隐伏而思虑。","涕泣交而凄凄兮，思不眠以至曙。","终长夜之曼曼兮，掩此哀而不去。","寤从容以周流兮，聊逍遥以自恃。","伤太息之愍怜兮，气于邑而不可止。","𫄙思心以为𬙋兮，编愁苦以为膺。","折若木以弊光兮，随飘风之所仍。","存彷仏而不见兮，心踊跃其若汤。","抚珮衽以案志兮，超惘惘而遂行。","岁曶曶其若颓兮，时亦冉冉而将至。","薠蘅槁而节离兮，芳以歇而不比。","怜思心之不可惩兮，证此言之不可聊。","宁溘死而流亡兮，不忍此心之常愁。","孤子吟而抆泪兮，放子出而不还。","孰能思而不隐兮，照彭咸之所闻。","登石峦以远望兮，路眇眇之黙黙。","入景响之无应兮，闻省想而不可得。","愁郁郁之无快兮，居戚戚而不可解。","心鞿羁而不开兮，气缭转而自缔。","穆眇眇之无垠兮，莽芒芒之无仪。","声有隐而相感兮，物有纯而不可为。","邈漫漫之不可量兮，缥绵绵之不可纡。","愁悄悄之常悲兮，翩冥冥之不可娱。","凌大波而流风兮，讬彭咸之所居。","上高岩之峭岸兮，处雌蜺之标颠。","据青冥而摅虹兮，遂儵忽而扪天。","吸湛露之浮源兮，漱凝霜之雰雰。","依风穴以自息兮，忽倾寤以婵媛。","冯昆仑以澂雾兮，隐渂山以清江。","惮涌湍之礚礚兮，听波声之汹汹。","纷容容之无经兮，罔芒芒之无纪。","轧洋洋之无从兮，驰委移之焉止？","漂翻翻其上下兮，翼遥遥其左右。","泛潏潏其前后兮，伴张驰之信期。","观炎气之相仍兮，窥烟液之所积。","悲霜雪之俱下兮，听潮水之相击。","借光景以往来兮，施黄棘之枉策。","求介子之所存兮，见伯夷之放迹。","心调度而弗去兮，刻着志之无适。","曰吾怨往昔之所冀兮，悼来者之悐悐。","浮江淮而入海兮，从子胥而自适。","望大河之洲渚兮，悲申徒之抗迹。","骤谏君而不听兮，重任石之何益？","心絓结而不解兮，思蹇产而不释。"],"source":"《楚辞》"},{"title":"落花","author":"李商隠","dynasty":"唐","form":"诗","lines":["高阁客竟去，小园花乱飞。","参差连曲陌，迢遰送斜晖。","肠断未忍扫，眼穿仍欲帰。","芳心向春尽，所得是沾衣。"],"source":"《唐诗三百首》"},{"title":"过松江","author":"范成大","dynasty":"宋","form":"诗","lines":["长虹斗起蛟竜穴，朱碧烂干夜明灭。","太湖三万六千顷，多少清风与明月。","青鹢惊飞白鹭闲，丹枫未老黄芦折。","谁将横笛叫苍烟，无限惊波翻白雪。","洞庭林屋旧游処，玉柱金庭路巉绝。","水仙逢迎掺修袂，问我帰计何当决。","去年匹马兀春寒，今此孤篷窘秋热。","人生意気得失间，軽重剣头吹一吷。","莫将尘土涴朱颜，却待丹砂回白髪。"],"source":"宋诗"},{"title":"拝星月慢","author":"吴文英","dynasty":"宋","form":"词","lines":["绛雪生凉，碧霞笼夜，小立中庭芜地。","昨梦西湖，老扁舟身世。","叹游荡，暂赏、吟花酌露尊俎，冷玉红香罍洗。","眼眩魂迷，古陶洲十里。","翠参差、澹月平芳砌。","砖花滉、小浪鱼鳞起。","雾盎浅障青罗，洗湘娥春腻。","荡兰烟、麝馥浓侵酔。","吹不散、绣屋重门闭。","又怕便、绿减西风，泣秋檠烛外。"],"source":"宋词"},{"title":"诈妮子调风月・哨遍","author":"关汉卿","dynasty":"元","form":"曲","lines":["并不是婆娘人把你抑勒，招取那肯心儿自说来的神前誓。","天果报，无差移，子争个来早来迟。","限时刻，十王地蔵，六道轮回，单劝化人间世。","善恶天心人意，\"人间私语，天闻若雷\"。","但年高都是积善好心人；早寿夭都是辜恩负徳贼。","好说话清晨，变了卦今日，冷了心晩夕。"],"source":"元曲"},{"title":"野有死麕","author":"佚名","dynasty":"先秦","form":"诗","lines":["野有死麕，白茅包之。有女怀春，吉士诱之。","林有朴樕，野有死鹿。白茅纯束，有女如玉。","舒而脱脱兮，无感我帨兮，无使尨也吠。"],"source":"《诗经》"},{"title":"远游","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["悲时俗之迫阨兮，愿轻举而远游。","质菲薄而无因兮，焉讬乗而上浮？","遭沈浊而汚秽兮，独郁结其谁语！","夜耿耿而不寐兮，魂营营而至曙。","惟天地之无穷兮，哀人生之长勤。","往者余弗及兮，来者吾不闻。","歩徙倚而遥思兮，怊惝怳而乖怀。","意荒忽而流荡兮，心愁凄而増悲。","神倏忽而不反兮，形枯槁而独留。","内惟省以操端兮，求正气之所由。","漠虚静以恬愉兮，澹无为而自得。","闻赤松之清尘兮，愿承风乎遗则。","贵真人之休徳兮，美往世之登仙","与化去而不见兮，名声着而日延。","奇傅说之讬辰星兮，羡韩众之得一。","形穆穆以浸远兮，离人群而遁逸。","因气变而遂曽举兮，忽神奔而鬼怪。","时仿仏以遥见兮，精晈晈以往来。","超氛埃而淑邮兮，终不反其故都。","免众患而不惧兮，世莫知其所如。","恐天时之代序兮，耀灵晔而西征。","微霜降而下沦兮，悼芳草之先蘦。","聊仿佯而逍遥兮，永历年而无成。","谁可与玩斯遗芳兮？","长向风而舒情。","高阳邈以远兮，余将焉所程？","重曰：","春秋忽其不淹兮，奚久留此故居。","轩辕不可攀援兮，吾将从王乔而娱戏。","餐六气而饮沆瀣兮，漱正阳而含朝霞。","保神明之清澄兮，精气入而麤秽除。","顺凯风以从游兮，至南巣而壱息。","见王子而宿之兮，审壱气之和徳。","曰“道可受兮，不可传","其小无内兮，其大无垠。","毋滑而魂兮，彼将自然","壱气孔神兮，于中夜存。","虚以待之存，无为之先","庶类以成兮，此徳之门。”","闻至贵而遂徂兮，忽乎吾将行。","仍羽人于丹丘，留不死之旧乡。","朝濯发于汤谷兮，夕晞余身兮九阳。","吸飞泉之微液兮，怀琬琰之华英。","玉色頩以脕颜兮，精醇粋而始壮。","质销铄以汋约兮，神要眇以淫放。","嘉南州之炎徳兮，丽桂树之冬荣","山萧条而无兽兮，野寂漠其无人。","载营魄而登霞兮，掩浮云而上征。","命天阍其开关兮，排阊阖而望予。","召丰隆使先导兮，问太微之所居。","集重阳入帝宫兮，造旬始而观清都。","朝发轫于太仪兮，夕始临乎于微闾。","屯余车之万乗兮，纷容与而并驰。","驾八龙之婉婉兮，载云旗之逶蛇。","建雄虹之采旄兮，五色杂而炫耀。","服偃蹇以低昂兮，骖连蜷以骄骜。","骑胶葛以杂乱兮，斑漫衍而方行。","撰余辔而正策兮，吾将过乎句芒。","历太皓以右转兮，前飞廉以启路。","阳杲杲其未光兮，凌天地以径度。","风伯为余先驱兮，氛埃辟而清凉。","凤凰翼其承旗兮，遇蓐収乎西皇。","揽慧星以为旍兮，举斗柄以为麾。","叛陆离其上下兮，游惊雾之流波。","时暧曃其曭莽兮，召玄武而奔属。","后文昌使掌行兮，选署众神以并毂。","路漫漫其修远兮，徐弭节而高厉。","左雨师使径侍兮，右雷公以为卫。","欲度世以忘归兮，意姿睢以抯挢。","内欣欣而自美兮，聊媮娱以淫乐。","渉青云以泛滥游兮，忽临睨夫旧乡。","仆夫怀余心悲兮，边马顾而不行。","思旧故以想象兮，长太息而掩涕。","汜容与而遐举兮，聊抑志而自弭。","指炎神而直驰兮，吾将往乎南疑。","览方外之荒忽兮，沛罔瀁而自浮。","祝融戒而跸御兮，腾告鸾鸟迎宓妃。","张咸池奏承云兮，二女御九韶歌。","使湘灵鼓瑟兮，令海若舞冯夷。","玄螭虫象并出进兮，形蟉虬而逶蛇。","雌蜺便娟以増挠兮，鸾鸟轩翥而翔飞。","音乐博衍无终极兮，焉乃逝以徘徊。","舒并节以驰骛兮，逴绝垠乎寒门。","轶迅风于清源兮，从颛顼乎増冰。","历玄冥以邪径兮，乗间维以反顾。","召黔赢而见之兮，为余先乎平路。","经营四方兮，周流六漠。","上至列欠兮，降望大壑。","下峥嵘而无地兮，上寥廓而无天。","视倏忽而无见兮，听惝恍而无闻。","超无为以至清兮，与泰初而为邻。"],"source":"《楚辞》"},{"title":"为有","author":"李商隠","dynasty":"唐","form":"诗","lines":["为有云屏无限娇，凤城寒尽怕春宵。","无端嫁得金亀壻，辜负香衾事早朝。"],"source":"《唐诗三百首》"},{"title":"过平望","author":"范成大","dynasty":"宋","form":"诗","lines":["寸碧闯高浪，孤墟明夕阳。","水柳揺病绿，霜蒲蘸新黄。","孤屿乍挙网，苍烟忽鸣榔。","波明荇叶颤，风熟苹花香。","鶏犬各村落，莼鲈近江郷。","野寺対客起，楼阴濯沧浪。","古来离别地，清诗断人肠。","亭前旧时水，还照両鸳鸯。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["艳阳不到青山，古阴冷翠成秋苑。","吴娃点黛，江妃拥髻，空蒙遮断。","树密蔵渓，草深迷市，峭云一片。","二十年旧梦，轻鸥素约，霜丝乱、朱颜变。","龙吻春霏玉溅。","煮银瓶、羊肠车转。","临泉照影，清寒沁骨，客尘都浣。","鸿渐重来，夜深华表，露零鹤怨。","把闲愁换与，楼前晩色，棹沧波远。"],"source":"宋词"},{"title":"诈妮子调风月・五煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["别人斩眉我早举动眼，道头知道尾。","你这般沙糖般甜话儿多曽吃！你又不是\"残花酝酿蜂儿蜜，细雨调和燕子泥\"。","自笑我狂踪迹。","我往常受那无男儿烦恼，今日知有丈夫滋味。"],"source":"元曲"},{"title":"何彼襛矣","author":"佚名","dynasty":"先秦","form":"诗","lines":["何彼襛矣，唐棣之华？曷不肃雍？王姬之车。","何彼襛矣，华如桃李？平王之孙，齐侯之子。","其钓维何？维丝伊缗。齐侯之子，平王之孙。"],"source":"《诗经》"},{"title":"卜居","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["屈原既放，三年不得复见。竭知尽忠而蔽障于谗。心烦虑乱，不知所从。乃往见太卜郑詹尹曰：“余有所疑，愿因先生决之。”詹尹乃端策払龟，曰：“君将何以教之？”","屈原曰：“吾宁悃悃款款，朴以忠乎，将送往劳来，斯无穷乎？宁诛锄草茅以力耕乎，将游大人以成名乎？宁正言不讳以危身乎，将从俗富贵以偷生乎？宁超然高举以保真乎，将哫訾栗斯，喔咿儒儿，以事妇人乎？宁廉洁正直以自清乎，将突梯滑稽，如脂如韦，以洁楹乎？宁昂昂若千里之驹乎，将泛泛若水中之凫，与波上下，偷以全吾躯乎？宁与骐骥亢轭乎，将随驽马之迹乎？宁与黄鹄比翼乎，将与鸡鹜争食乎？此孰吉孰凶？何去何从？世溷浊而不清：蝉翼为重，千钧为轻黄钟毁弃，瓦釜雷鸣谗人高张，贤士无名。吁嗟黙黙兮，谁知吾之廉贞！”","詹尹乃释策而谢曰：“夫尺有所短，寸有所长物有所不足，智有所不明数有所不逮，神有所不通。用君之心，行君之意。龟策诚不能知此事。”"],"source":"《楚辞》"},{"title":"无题","author":"李商隠","dynasty":"唐","form":"诗","lines":["相见时难别亦难，东风无力百花残。","春蚕到死糸方尽，蝋炬成灰涙始干。","暁镜但愁云鬓改，夜吟応覚月光寒。","蓬山此去无多路，青鸟殷勤为探看。"],"source":"《唐诗三百首》"},{"title":"长安闸","author":"范成大","dynasty":"宋","form":"诗","lines":["斗门贮浄练，悬板淙惊雷。","黄沙古岸転，白屋飞檐开。","是间袤丈许，舳舻蔽川来。","千车拥孤隧，万马盘一坏。","篙尾乱若雨，樯竿束如堆。","摧摧势排轧，汹汹声喧豗。","偪仄复偪仄，谁肯少徘徊。","伝呼津吏至，弊盖凌高埃。","嗫嚅议讥征，叫怒不可裁。","吾観舟中子，一一皆可哀。","大为声利駆，小者饥寒催。","古今共来往，所得随飞灰。","我乃畸于人，胡为乎来哉。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["夜分渓馆渔灯，巷声乍寂西风定。","河桥径远，玉箫吹断，霜丝舞影。","薄絮秋云，澹蛾山色，宦情归兴。","怕烟江渡后，桃花又泛，宫沟上、春流紧。","新句欲题还省。","透香煤、重牒误隐。","西园已负，林亭移酒，松泉荐茗。","携手同归处，玉奴唤、绿窗春近。","想骄骢、又踏西湖，二十四番花信。"],"source":"宋词"},{"title":"诈妮子调风月・四煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["待争来怎地争？待悔来怎地悔？怎补得我这有气分全身体？打也阿儿包髻，真加要带与别人成美，况团衫怎能勾披？他若不在俺宅司内，便大家南北，各自东西！。"],"source":"元曲"},{"title":"驺虞","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼茁者葭，壱发五豝，于嗟乎驺虞！","彼茁者蓬，壱发五𫎆，于嗟乎驺虞！"],"source":"《诗经》"},{"title":"渔父","author":"屈原","dynasty":"先秦","form":"辞赋","lines":["屈原既放，游于江潭，行吟泽畔，颜色憔悴，形容枯槁。渔父见而问之曰：“子非三闾大夫与？何故至于斯？”屈原曰：“举世皆浊我独清，众人皆酔我独醒，是以见放。”","渔父曰：“圣人不凝滞于物，而能与世推移。世人皆浊，何不淈其泥而扬其波？众人皆酔，何不𫗦其糟而歠其醨？何故深思高举，自令放为？”","屈原曰：“吾闻之，新沐者必弹冠，新浴者必振衣安能以身之察察，受物之汶汶者乎？宁赴湘流，葬于江鱼之腹中。安能以皓皓之白，而蒙世俗之尘埃乎?”","渔父莞尔而笑，鼓枻而去。","乃歌曰：“沧浪之水清兮，可以濯吾缨。沧浪之水浊兮，可以濯吾足。”遂去，不复与言。"],"source":"《楚辞》"},{"title":"瑶池","author":"李商隠","dynasty":"唐","form":"诗","lines":["瑶池阿母绮窗开，黄竹歌声动地哀。","八骏日行三万里，穆王何事不重来。"],"source":"《唐诗三百首》"},{"title":"栄木","author":"范成大","dynasty":"宋","form":"诗","lines":["薫风南来，木栄于兹。","木栄几时，黄落従之。","逝其须臾，坐成四时。","今我不学，殆其已而。","天旋地游，日月其根。","形息気徂，不亡者存。","去郷离家，莫肯过门。","猗欤先师，不我疵陋。","褰衣示珠，俾我复旧。","自我来帰，十年不富。","孰蠹孰蛊，惟汝自疚。","冉冉栄木，霜华将坠。","天黒路长，屹蹶可畏。","隶也不力，奚取六骥。","脂车着鞭，一息而至。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["有人独立空山，翠髯未觉霜颜老。","新香秀粒，浓光绿浸，千年春小。","布影参旗，障空云盖，沈沈秋晓。","驷苍虬万里，笙吹凤女，骖飞乗、天风袅。","般巧。","霜斤不到。","汉游仙、相从最早。","皴鳞细雨，层阴蔵月，朱弦古调。","问讯东桥，故人南岭，倚天长啸。","待凌霄谢了，山深岁晩，素心才表。"],"source":"宋词"},{"title":"诈妮子调风月・三煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["明日索一般供与他衣袂穿，一般过与他茶饭吃，到晩送得他被底成双睡。","他\"做成暖帐三更梦\"，我\"拨尽寒炉一夜灰\"。","有句话存心记：则愿得辜恩负徳，一个个荫于封妻！。"],"source":"元曲"},{"title":"柏舟","author":"佚名","dynasty":"先秦","form":"诗","lines":["泛彼柏舟，亦泛其流。耿耿不寐，如有隐忧。微我无酒，以敖以游。","我心匪鉴，不可以茹。亦有兄弟，不可以据。薄言往诉，逢彼之怒。","我心匪石，不可转也。我心匪席，不可巻也。威仪棣棣，不可选也。","忧心悄悄，愠于群小。觏闵既多，受侮不少。静言思之，寤辟有摽。","日居月诸，胡迭而微？心之忧矣，如匪浣衣。静言思之，不能奋飞。"],"source":"《诗经》"},{"title":"九辩","author":"宋玉","dynasty":"先秦","form":"辞赋","lines":["悲哉，秋之为气也！萧瑟兮草木摇落而变衰。","憭栗兮若在远行，登山临水兮送将归。","泬漻兮天高而气清，寂寥兮収潦而水清。","憯凄増欷兮，薄寒之中人，怆怳懭悢兮，去故而就新。","坎廪兮贫士失职而志不平，廓落兮羁旅而无友生，惆怅兮而私自怜！","燕翩翩其辞归兮，蝉寂漠而无声。","雁廱廱而南游兮，鹍鸡啁哳而悲鸣。","独申旦而不寐兮，哀蟋蟀之宵征。","时亹亹而过中兮，蹇淹留而无成。","悲忧穷戚兮独处廓，有美一人兮心不绎。","去乡离家兮来远客，超逍遥兮今焉薄！","专思君兮不可化，君不知兮可奈何！","蓄怨兮积思，心烦憺兮忘食事。","原一见兮道余意，君之心兮与余异。","车既驾兮朅而归，不得见兮心伤悲。","倚结𫐉兮长太息，涕潺湲兮下沾轼。","忼慨绝兮不得，中瞀乱兮迷惑。","私自怜兮何极？","心怦怦兮谅直。","皇天平分四时兮，窃独悲此凛秋。","白露既下百草兮，奄离披此梧楸。","去白日之昭昭兮，袭长夜之悠悠。","离芳蔼之方壮兮，余萎约而悲愁。","秋既先戒以白露兮，冬又申之以严霜。","収恢台之孟夏兮，然欿傺而沉蔵。","叶烟邑而无色兮，枝烦挐而交横。","颜淫溢而将罢兮，柯仿仏而萎黄。","萷櫹椮之可哀兮，形销铄而瘀伤。","惟其纷糅而将落兮，恨其失时而无当。","揽𬴂辔而下节兮，聊逍遥以相佯。","岁忽忽而遒尽兮，恐余寿之弗将。","悼余生之不时兮，逢此世之俇攘。","澹容与而独倚兮，蟋蟀鸣此西堂。","心怵惕而震荡兮，何所忧之多方。","卬明月而太息兮，歩列星而极明。","窃悲夫蕙华之曽敷兮，纷旖旎乎都房。","何曽华之无实兮，从风雨而飞飏！","以为君独服此蕙兮，羌无以异于众芳。","闵奇思之不通兮，将去君而高翔。","心闵怜之惨凄兮，愿一见而有明。","重无怨而生离兮，中结轸而増伤。","岂不郁陶而思君兮？","君之门以九重！猛犬狺狺而迎吠兮，关梁闭而不通。","皇天淫溢而秋霖兮，后土何时而得漧？","块独守此无泽兮，仰浮云而永叹！何时俗之工巧兮？","背绳墨而改错！郤骐骥而不乗兮，策驽骀而取路。","当世岂无骐骥兮，诚莫之能善御。","见执辔者非其人兮，故𩧺跳而远去。","凫雁皆唼夫梁藻兮，凤愈飘翔而高举。","圜凿而方枘兮，吾固知其鉏铻而难入。","众鸟皆有所登栖兮，凤独遑遑而无所集。","原衔枚而无言兮，尝被君之渥洽。","太公九十乃显荣兮，诚未遇其匹合。","谓骐骥兮安归？","谓凤皇兮安栖？","变古易俗兮世衰，今之相者兮举肥。","骐骥伏匿而不见兮，凤皇高飞而不下。","鸟兽犹知怀徳兮，何云贤士之不处？","骥不骤进而求服兮，凤亦不贪𫗪而妄食。","君弃远而不察兮，虽原忠其焉得？","欲寂漠而绝端兮，窃不敢忘初之厚徳。","独悲愁其伤人兮，冯郁郁其何极？","霜露惨凄而交下兮，心尚幸其弗济。","霰雪雰糅其増加兮，乃知遭命之将至。","原徼幸而有待兮，泊莽莽与野草同死。","原自往而径游兮，路壅绝而不通。","欲循道而平驱兮，又未知其所从。","然中路而迷惑兮，自压桉而学诵。","性愚陋以褊浅兮，信未达乎从容。","窃美申包胥之气盛兮，恐时世之不固。","何时俗之工巧兮？","灭规矩而改凿！独耿介而不随兮，原慕先圣之遗教。","处浊世而显荣兮，非余心之所乐。","与其无义而有名兮，宁穷处而守高。","食不媮而为饱兮，衣不苟而为温。","窃慕诗人之遗风兮，原讬志乎素餐。","蹇充倔而无端兮，泊莽莽而无垠。","无衣裘以御冬兮，恐溘死不得见乎阳春。","靓杪秋之遥夜兮，心缭悷而有哀。","春秋逴逴而日高兮，然惆怅而自悲。","四时递来而卒岁兮，阴阳不可与俪偕。","白日晼晩其将入兮，明月销铄而减毁。","岁忽忽而遒尽兮，老冉冉而愈弛。","心摇悦而日幸兮，然怊怅而无冀。","中憯恻之凄怆兮，长太息而増欷。","年洋洋以日往兮，老嵺廓而无处。","事亹亹而觊进兮，蹇淹留而踌躇。","何泛滥之浮云兮？","猋壅蔽此明月。","忠昭昭而原见兮，然霠曀而莫达。","原皓日之显行兮，云蒙蒙而蔽之。","窃不自聊而原忠兮，或黕点而污之。","尧舜之抗行兮，瞭冥冥而薄天。","何险巇之嫉妒兮？","被以不慈之伪名。","彼日月之照明兮，尚黯黮而有瑕。","何况一国之事兮，亦多端而胶加。","被荷裯之晏晏兮，然潢洋而不可带。","既骄美而伐武兮，负左右之耿介。","憎愠惀之修美兮，好夫人之慷慨。","众踥蹀而日进兮，美超远而逾迈。","农夫辍耕而容与兮，恐田野之芜秽。","事緜緜而多私兮，窃悼后之危败。","世雷同而炫曜兮，何毁誉之昧昧！","今修饰而窥镜兮，后尚可以窜蔵。","愿寄言夫流星兮，羌倏忽而难当。","卒壅蔽此浮云，下暗漠而无光。","尧舜皆有所举任兮，故高枕而自适。","谅无怨于天下兮，心焉取此怵惕？","乗骐骥之浏浏兮，驭安用夫强策？","谅城郭之不足恃兮，虽重介之何益？","邅翼翼而无终兮，忳惛惛而愁约。","生天地之若过兮，功不成而无嶜。","原沉滞而不见兮，尚欲布名乎天下。","然潢洋而不遇兮，直怐愗而自苦。","莽洋洋而无极兮，忽翱翔之焉薄？","国有骥而不知乗兮，焉皇皇而更索？","宁戚讴于车下兮，桓公闻而知之。","无伯乐之相善兮，今谁使乎誉之？","罔流涕以聊虑兮，惟着意而得之。","纷纯纯之愿忠兮，妒被离而鄣之。","原赐不肖之躯而别离兮，放游志乎云中。","乗精气之抟抟兮，骛诸神之湛湛。","骖白霓之习习兮，历群灵之丰丰。","左朱雀之茇茇兮，右苍龙之躣躣。","属雷师之阗阗兮，通飞廉之衙衙。","前轻辌之锵锵兮，后辎乗之从从。","载云旗之委蛇兮，扈屯骑之容容。","计专专之不可化兮，原遂推而为臧。","赖皇天之厚徳兮，还及君之无恙！"],"source":"《楚辞》"},{"title":"春雨","author":"李商隠","dynasty":"唐","form":"诗","lines":["怅卧新春白袷衣，白门寥落意多违。","红楼隔雨相望冷，珠箔飘灯独自帰。","远路応悲春晼晩，残宵犹得梦依稀。","玉珰缄札何由达，万里云罗一雁飞。"],"source":"《唐诗三百首》"},{"title":"両木  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["枇杷昔所嗜，不问甘与酸。","黄泥裹余核，散掷篱落间。","春风拆勾萌，朴𣙙如榛菅。","一株独成长，苍然斉屋山。","去年小试花，珑珑犯冰寒。","化成黄金弾，同登桃李盘。","大钧播群物，斡旋不作难。","树老人何堪，挽镜觅朱颜。","颔髭尔许长，大笑欹巾冠。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["望中璇海波新，泛槎又币银河转。","金风细袅，龙枝声奏，钧箫秋远。","南极飞仙，夜来催驾，祥光重见。","紫霄承露掌，瑶池荫密，蟠桃秀、螽莲绽。","新栋晴翚凌汉。","半凉生、兰檠书巻。","绣裳五色，昆台十二，香深帘巻。","花萼楼高处，连清晓、千秋传宴。","赐长生玉字，鸾回凤舞，下蓬莱殿。"],"source":"宋词"},{"title":"诈妮子调风月・二煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["出门来一脚高一脚低，自不觉鞋底儿着田地。","痛连心除他外谁根前说，气夯破肚别人行怎又不敢提？独自向银蟾底，则道是孤鸿伴影，几时吃四马攒蹄？。"],"source":"元曲"},{"title":"绿衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["绿兮衣兮，绿衣黄裹。心之忧矣，曷维其已！","绿兮衣兮，绿衣黄裳。心之忧矣，曷维其亡！","绿兮丝兮，女所治兮。我思古人，俾无訧兮！","𫄨兮绤兮，凄其以风。我思古人，实获我心！"],"source":"《诗经》"},{"title":"招魂","author":"宋玉","dynasty":"先秦","form":"辞赋","lines":["朕幼清以廉洁兮，身服义而未沫。","主此盛徳兮，牵于俗而芜秽。","上无所考此盛徳兮，长离殃而愁苦。","帝告巫阳曰：“有人在下，我欲辅之。魂魄离散，汝筮予之。”","巫阳对曰：“掌梦！上帝其难从。若必筮予之，恐后之谢，不能复用。”","巫阳焉乃下招曰：魂兮归来！去君之恒干，何为四方些？","舎君之乐处，而离彼不祥些！魂兮归来！东方不可以讬些。","长人千仞，惟魂是索些。","十日代出，流金铄石些。","彼皆习之，魂往必释些。","归来兮！不可以讬些。","魂兮归来！南方不可以止些。","雕题黒齿，得人肉以祀，以其骨为醢些。","蝮蛇蓁蓁，封狐千里些。","雄虺九首，往来倏忽，吞人以益其心些。","归来兮！不可久淫些。","魂兮归来！西方之害，流沙千里些。","旋入雷渊，爢散而不可止些。","幸而得脱，其外旷宇些。","赤蚁若象，玄蜂若壶些。","五谷不生，丛菅是食些。","其土烂人，求水无所得些。","彷徉无所倚，广大无所极些。","归来兮！恐自遗贼些。","魂兮归来！北方不可以止些。","増冰峨峨，飞雪千里些。","归来兮！不可以久些。","魂兮归来！君无上天些。","虎豹九关，啄害下人些。","一夫九首，抜木九千些。","豺狼从目，往来侁侁些。","悬人以嬉，投之深渊些。","致命于帝，然后得瞑些。","归来！往恐危身些。","魂兮归来！君无下此幽都些。","土伯九约，其角觺觺些。","敦脄血拇，逐人伂𬳵𬳵些。","参目虎首，其身若牛些。","此皆甘人，归来！恐自遗灾些。","魂兮归来！入修门些。","工祝招君，背行先些。","秦篝齐缕，郑绵络些。","招具该备，永啸呼些。","魂兮归来！反故居些。","天地四方，多贼奸些。","像设君室，静闲安些。","高堂邃宇，槛层轩些。","层台累榭，临高山些。","网户朱缀，刻方连些。","冬有穾厦，夏室寒些。","川谷径复，流潺湲些。","光风转蕙，泛崇兰些。","经堂入奥，朱尘筵些。","砥室翠翘，挂曲琼些。","翡翠珠被，烂齐光些。","蒻阿払壁，罗帱张些。","纂组绮缟，结琦璜些。","室中之观，多珍怪些。","兰膏明烛，华容备些。","二八侍宿，射递代些。","九侯淑女，多迅众些。","盛鬋不同制，实满宫些。","容态好比，顺弥代些。","弱颜固植，謇其有意些。","姱容修态，絚洞房些。","蛾眉曼睩，目腾光些。","靡颜腻理，遗视矊些。","离榭修幕，侍君之闲些。","悲帷翠帐，饰高堂些。","红壁沙版，玄玉梁些。","仰观刻桷，画龙蛇些。","坐堂伏槛，临曲池些。","芙蓉始发，杂芰荷些。","紫茎屏风，文缘波些。","文异豹饰，侍陂陁些。","轩辌既低，歩骑罗些。","兰薄户树，琼木篱些。","魂兮归来！何远为些？","室家遂宗，食多方些。","稲粢穱麦，挐黄梁些。","大苦醎酸，辛甘行些。","肥牛之腱，臑若芳些。","和酸若苦，陈吴羹些。","胹鳖炮羔，有柘浆些。","鹄酸臇凫，煎鸿鸧些。","露鸡臛蠵，厉而不爽些。","粔籹蜜饵，有𫗠𫗮些。","瑶浆蜜勺，实羽觞些。","挫糟冻饮，酎清凉些。","华酌既陈，有琼浆些。","归来反故室，敬而无妨些。","肴羞未通，女乐罗些。","敶钟按鼓，造新歌些。","《渉江》《采菱》，发《扬荷》些。","美人既酔，朱颜酡些。","嬉光眇视，目曽波些。","被文服纤，丽而不奇些。","长发曼鬋，艳陆离些。","二八齐容，起郑舞些。","衽若交竿，抚案下些。","竽瑟狂会，搷鸣鼓些。","宫庭震惊，发<激楚>些。","吴歈蔡讴，奏大吕些。","士女杂坐，乱而不分些。","放敶组缨，班其相纷些。","郑卫妖玩，来杂陈些。","《激楚》之结，独秀先些。","菎蔽象棋，有六簙些。","分曹并进，遒相迫些。","成枭而牟，呼五白些。","晋制犀比，费白日些。","铿钟摇簴，揳梓瑟些。","娱酒不废，沈日夜些。","兰膏明烛，华灯错些。","结撰至思，兰芳仮些。","人有所极，同心赋些。","酎饮尽欢，乐先故些。","魂兮归来！反故居些。","乱曰：献岁发春兮，汨吾南征。","菉苹齐叶兮，白芷生。","路贯庐江兮，左长薄。","倚沼畦瀛兮，遥望博。","青骊结驷兮，齐千乗。","悬火延起兮，玄颜烝。","歩及骤处兮，诱骋先。","抑骛若通兮，引车右还。","与王趋梦兮，课后先。","君王亲发兮，惮青兕。","朱明承夜兮，时不可以淹。","皐兰被径兮，斯路渐。","湛湛江水兮，上有枫。","目极千里兮，伤春心。","魂兮归来，哀江南！"],"source":"《楚辞》"},{"title":"常娥","author":"李商隠","dynasty":"唐","form":"诗","lines":["云母屏风烛影深，长河渐落暁星沈。","常娥応悔偷霊薬，碧海青天夜夜心。"],"source":"《唐诗三百首》"},{"title":"両木  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["绿橘生西山，得自髯翁家。","云此接活根，是歳当着花。","俛仰乃十霜，垂蠹纷相遮。","芳意竟寂莫，枯枝谩槎牙。","风土谅非宜，翁言岂予夸。","会令返故山，高深谢污邪。","石液滋旧根，山英擢新葩。","黄団挂霜実，大如崆峒瓜。","当有四老人，来驻七香车。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["望春楼外沧波，旧年照眼青铜镜。","炼成宝月，飞来天上，银河流影。","绀玉钩帘处，横犀尘、天香分鼎。","记殷云殿锁，裁花翦露，曲江畔、春风劲。","槐省。","红尘昼静，午朝回、吟生晩兴。","春霖绣笔，莺边清晓，金狨旋整。","阆苑芝仙貌，生绡对、绿窗深景。","弄琼英数点，宫梅信早，占年光永。"],"source":"宋词"},{"title":"诈妮子调风月・尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["呆敲才、呆敲才休怨天；死贱人、死贱人自骂你！本待要皂腰裙，刚待要蓝包髻，则这的是折挂攀高落得的！（下）。"],"source":"元曲"},{"title":"燕燕","author":"佚名","dynasty":"先秦","form":"诗","lines":["燕燕于飞，差池其羽。之子于归，远送于野。瞻望弗及，泣涕如雨。","燕燕于飞，颉之颃之。之子于归，远于将之。瞻望弗及，伫立以泣。","燕燕于飞，下上其音。之子于归，远送于南。瞻望弗及，实劳我心。","仲氏任只，其心塞渊。终温且恵，淑慎其身。先君之思，以勖寡人。"],"source":"《诗经》"},{"title":"大招","author":"景差","dynasty":"先秦","form":"辞赋","lines":["青春受谢，白日昭只。","春气奋发，万物遽只。","冥凌浃行，魂无逃只。","魂魄归来！无远遥只。","魂乎归来！无东无西，无南无北只。","东有大海，溺水浟浟只。","螭龙并流，上下悠悠只。","雾雨淫淫，白皓胶只。","魂乎无东！汤谷寂寥只。","魂乎无南！南有炎火千里，蝮蛇蜒只。","山林险隘，虎豹蜿只。","鰅鳙短狐，王虺骞只。","魂乎无南！蜮伤躬只","魂乎无西！西方流沙，漭洋洋只。","豕首纵目，被发鬤只。","长爪踞牙，诶笑狂只。","魂乎无西！多害伤只。","魂乎无北！北有寒山，趠龙赩只。","代水不可渉，深不可测只。","天白颢颢，寒凝凝只。","魂乎无往！盈北极只。","魂魄归来！闲以静只。","自恣荆楚，安以定只。","逞志究欲，心意安只。","穷身永乐，年寿延只。","魂乎归来！乐不可言只。","五谷六仞，设菰梁只。","鼎臑盈望，和致芳只。","内鸧鸽鹄，味豺羹只。","魂乎归来！恣所尝只。","鲜蠵甘鸡，和楚酪只。","醢豚苦狗，脍苴蒪只。","吴酸蒿蒌，不沾薄只。","魂兮归来！恣所择只。","炙鸹烝凫，煔鹑敶只。","煎鰿膗雀，遽爽存只。","魂乎归来！丽以先只。","四酎并孰，不涩嗌只。","清馨冻饮，不歠役只。","吴醴白蘖，和楚沥只。","魂乎归来！不遽惕只。","代秦郑卫，鸣竽张只。","伏戏《驾辩》，楚《劳商》只。","讴和《扬阿》，赵萧倡只。","魂乎归来！定空桑只。","二八接舞，投诗赋只。","叩钟调磬，娱人乱只。","四上竞气，极声变只。","魂乎归来！听歌譔只。","朱唇皓齿，嫭以姱只。","比徳好闲，习以都只。","丰肉微骨，调以娱只。","魂乎归来！安以舒只。","嫮目宜笑，娥眉曼只。","容则秀雅，稚朱颜只。","魂乎归来！静以安只。","姱修滂浩，丽以佳只。","曽颊倚耳，曲眉规只。","滂心绰态，姣丽施只。","小腰秀颈，若鲜卑只。","魂乎归来！思怨移只。","易中利心，以动作只。","粉白黛黒，施芳泽只。","长袂払面，善留客只。","魂乎归来！以娱昔只。","青色直眉，美目媔只。","靥辅奇牙，宜笑嘕只。","丰肉微骨，体便娟只。","魂乎归来！恣所便只。","夏屋广大，沙堂秀只。","南房小坛，观绝霤只。","曲屋歩壛，宜扰畜只。","腾驾歩游，猎春囿只。","琼毂错衡，英华仮只。","茝兰桂树，郁弥路只。","魂乎归来！恣志虑只。","孔雀盈园，畜鸾皇只！","鹍鸿群晨，杂鹙鸧只。","鸿鹄代游，曼骕骦只。","魂乎归来！凤凰翔只。","曼泽怡面，血气盛只。","永宜厥身，保寿命只。","室家盈廷，爵禄盛只。","魂乎归来！居室定只。","接径千里，出若云只。","三圭重侯，听类神只。","察笃夭隐，孤寡存只。","魂兮归来！正始昆只。","田邑千畛，人阜昌只。","美冒众流，徳泽章只。","先威后文，善美明只。","魂乎归来！赏罚当只。","名声若日，照四海只。","徳誉配天，万民理只。","北至幽陵，南交阯只。","西薄羊肠，东穷海只。","魂乎归来！尚贤士只。","发政献行，禁苛暴只。","举杰压陛，诛讥罢只。","直赢在位，近禹麾只。","豪杰执政，流泽施只。","魂乎来归！国家为只。","雄雄赫赫，天徳明只。","三公穆穆，登降堂只。","诸侯毕极，立九卿只。","昭质既设，大侯张只。","执弓挟矢，揖辞让只。","魂乎来归！尚三王只。"],"source":"《楚辞》"},{"title":"无题二首 一","author":"李商隠","dynasty":"唐","form":"诗","lines":["凤尾香罗薄几重，碧文円顶夜深缝。","扇裁月魄羞难掩，车走雷声语未通。","曽是寂寥金烬暗，断无消息石榴红。"],"source":"《唐诗三百首》"},{"title":"道中","author":"范成大","dynasty":"宋","form":"诗","lines":["月冷吟蛩草，湖平宿鹭沙。","客愁无锦字，郷信有灯花。","踪迹随风叶，程途犯斗槎。","君看枝上鹊，薄暮亦还家。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["几番时事重论，座中共惜斜阳下。","今朝翦柳，东风送客，功名近也。","约住飞花，暂听留燕，更攀情话。","问千牙过阙，一封入奏，忠孝事、都应写。","闻道兰台清暇。","载鸱夷、烟江一舸。","贞元旧曲，如今谁听，惟公和寡。","儿骑空迎，舜瞳回盼，玉阶前借。","便急回暖律，天边海上，正春寒夜。"],"source":"宋词"},{"title":"诈妮子调风月・越调/斗鹌鹑","author":"关汉卿","dynasty":"元","form":"曲","lines":["短叹长吁，千声万声；捣枕捶床，到三更四更。","便似止渇思梅，充饥画饼，因甚顷刻体？则伤我取次成。","好个个舒心，干支刺没兴。"],"source":"元曲"},{"title":"日月","author":"佚名","dynasty":"先秦","form":"诗","lines":["日居月诸，照临下土。乃如之人兮，逝不古处？胡能有定？宁不我顾。","日居月诸，下土是冒。乃如之人兮，逝不相好。胡能有定？宁不我报。","日居月诸，出自东方。乃如之人兮，徳音无良。胡能有定？俾也可忘。","日居月诸，东方自出。父兮母兮，畜我不卒。胡能有定？报我不述。"],"source":"《诗经》"},{"title":"惜誓","author":"贾谊","dynasty":"先秦","form":"辞赋","lines":["惜余年老而日衰兮，岁忽忽而不反。","登苍天而高举兮，历众山而日远。","观江河之纡曲兮，离四海之沾濡。","攀北极而一息兮，吸沆瀣以充虚。","飞朱鸟使先驱兮，驾太一之象舆。","苍龙蚴虬于左骖兮，白虎骋而为右𬴂。","建日月以为盖兮，载玉女于后车。","驰骛于杳冥之中兮，休息虖昆仑之墟。","乐穷极而不厌兮，愿从容虖神明。","渉丹水而驰骋兮，右大夏之遗风。","黄鹄之一举兮，知山川之纡曲。","再举兮，睹天地之圜方。","临中国之众人兮，讬回飙乎尚羊。","乃至少原之野兮，赤松、王乔皆在旁。","二子拥瑟而调均兮，余因称乎清商。","澹然而自乐兮，吸众气而翱翔。","念我长生而久仙兮，不如反余之故乡。","黄鹄后时而寄处兮，鸱枭群而制之。","神龙失水而陆居兮，为蝼蚁之所裁。","夫黄鹄神龙犹如此兮，况贤者之逢乱世哉。","寿冉冉而日衰兮，固儃回而不息。","俗流从而不止兮，众枉聚而矫直。","或偷合而苟进兮，或隐居而深蔵。","苦称量之不审兮，同权概而就衡。","或推迻而苟容兮，或直言之谔謣。","伤诚是之不察兮，并纫茅丝以为索。","方世俗之幽昏兮，眩白黒之美恶。","放山渊之龟玉兮，相与贵夫砾石。","梅伯数谏而至醢兮，来革顺志而用国。","悲仁人之尽节兮，反为小人之所贼。","比干忠谏而剖心兮，箕子被发而佯狂。","水背流而源竭兮，木去根而不长。","非重躯以虑难兮，惜伤身之无功。","已矣哉！独不见夫鸾凤之高翔兮，乃集大皇之野。","循四极而回周兮，见盛徳而后下。","彼圣人之神徳兮，远浊世而自蔵。","使麒麟可得羁而系兮，又何以异虖犬羊？"],"source":"《楚辞》"},{"title":"无题二首 二","author":"李商隠","dynasty":"唐","form":"诗","lines":["重帷深下莫愁堂，卧后清宵细细长。","神女生涯原是梦，小姑居処本无郎。","风波不信菱枝弱，月露谁教桂叶香。","直道相思了无益，未妨惆怅是清狂。"],"source":"《唐诗三百首》"},{"title":"落鸿","author":"范成大","dynasty":"宋","form":"诗","lines":["落鸿声里怨関山，涙湿秋衣不肯干。","只道一番新雨过，谁知双袖倚楼寒。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["外湖北岭云多，小园暗碧莺啼处。","朝回胜赏，墨池香润，吟船系雨。","霓节千妃，锦帆一箭，携将春去。","算归期未卜，青烟散后，春城咏、飞花句。","黄鹤楼头月午。","奏玉龙、江梅解舞。","薫风紫禁，严更清梦，思怀几许。","秋水生时，赋情还在，南屏别墅。","看章台走马，长堤种取，柔丝千树。"],"source":"宋词"},{"title":"诈妮子调风月・紫花儿序","author":"关汉卿","dynasty":"元","form":"曲","lines":["好轻乞列薄命，热忽刺姻缘，短古取恩情。","（见灯蛾科，云）哎！蛾儿，俺两个有比喻：见一个耍蛾儿来往向烈焔上飞腾，正撞着银灯，拦头送了性命。","咱两个堪为比并：我为那包譬白身，你为这灯火青荧。"],"source":"元曲"},{"title":"终风","author":"佚名","dynasty":"先秦","form":"诗","lines":["终风且暴，顾我则笑，谑浪笑敖，中心是悼。","终风且霾，恵然肯来，莫往莫来，悠悠我思。","终风且曀，不日有曀，寤言不寐，愿言则嚏。","曀曀其阴，虺虺其雷，寤言不寐，愿言则怀。"],"source":"《诗经》"},{"title":"招隐士","author":"淮南小山","dynasty":"先秦","form":"辞赋","lines":["桂树丛生兮山之幽，偃蹇连蜷兮枝相缭。","山气巄嵷兮石嵯峨，渓谷崭岩兮水曽波。","猿狖群啸兮虎豹嗥，攀援桂枝兮聊淹留。","王孙游兮不归，春草生兮萋萋。","岁暮兮不自聊，蟪蛄鸣兮啾啾。","坱兮轧，山曲岪，心淹留兮恫慌忽。","罔兮沕，憭兮栗，虎豹穴。","丛薄深林兮，人上栗。","嵚岑埼𥐟兮，碅磳磈硊","树轮相纠兮，林木茷骫。","青莎杂树兮，薠草靃靡","白鹿麏麚兮，或腾或倚。","状貌崟崟兮峨峨，凄凄兮漇漇。","猕猴兮熊罴，慕类兮以悲","攀援桂枝兮聊淹留。","虎豹斗兮熊罴咆，禽兽骇兮亡其曹。","王孙兮归来，山中兮不可以久留。"],"source":"《楚辞》"},{"title":"贾生","author":"李商隠","dynasty":"唐","form":"诗","lines":["宣室求贤访逐臣，贾生才调更无伦。","可怜夜半虚前席，不问苍生问鬼神。"],"source":"《唐诗三百首》"},{"title":"题山水横看二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["烟山漠漠水漫漫，老柳知秋渡口寒。","尽是西渓肠断処，凭君将与故人看。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["澹云笼月微黄，柳丝浅色东风紧。","夜寒旧事，春期新恨，眉山碧远。","尘陌飘香，绣帘垂户，趁时妆面。","钿车催去急，珠囊袖冷，愁如海、情一线。","犹记初来吴苑。","未清霜、飞惊双鬓。","嬉游是处，风光无际，舞葱歌蒨。","陈迹征衫，老容华镜，欢悰都尽。","向残灯梦短，梅花晓角，为谁吟怨。"],"source":"宋词"},{"title":"诈妮子调风月・幺篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["我把这银灯来指定，引了咱两个魂灵，都是这一点虚名。","怕不百伶百俐，千战千赢，更做道\"能行怎离得影\"？这一场其身不正，怎当那厮大四至铺排，小夫人名称？。"],"source":"元曲"},{"title":"击鼓","author":"佚名","dynasty":"先秦","form":"诗","lines":["击鼓其镗，踊跃用兵。土国城漕，我独南行。","从孙子仲，平陈与宋。不我以归，忧心有忡。","爰居爰处？爰丧其马？于以求之？于林之下。","死生契阔，与子成说。执子之手，与子偕老。","于嗟阔兮，不我活兮。于嗟洵兮，不我信兮。"],"source":"《诗经》"},{"title":"初放","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["平生于国兮，长于原野。","言语讷𰶎兮，又无彊辅。","浅智褊能兮，闻见又寡。","数言便事兮，见怨门下。","王不察其长利兮，卒见弃乎原野。","伏念思过兮，无可改者。","群众成朋兮，上浸以惑。","巧佞在前兮，贤者灭息。","尧、舜圣已没兮，孰为忠直？","高山崔巍兮，水流汤汤。","死日将至兮，与麋鹿同坑。","块兮鞠，当道宿，举世皆然兮，余将谁告？","斥逐鸿鹄兮，近习鸱枭，斩伐橘柚兮，列树苦桃。","便娟之修竹兮，寄生乎江潭。","上葳蕤而防露兮，下泠泠而来风。","孰知其不合兮，若竹柏之异心。","往者不可及兮，来者不可待。","悠悠苍天兮，莫我振理。","窃怨君之不寤兮，吾独死而后已。"],"source":"《楚辞》"},{"title":"凉思","author":"李商隠","dynasty":"唐","form":"诗","lines":["客去波平槛，蝉休露満枝。","永懐当此节，倚立自移时。","北斗兼春远，南陵寓使遅。","天涯占梦数，疑误有新知。"],"source":"《唐诗三百首》"},{"title":"题山水横看二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["霜入丹枫白苇林，横烟平远暮江深。","君看鴈落帆飞処，知我秋风故国心。"],"source":"宋诗"},{"title":"水龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["杜陵折柳狂吟，砚波尚湿红衣露。","仙桃宴早，江梅春近，还催客句。","宫漏传鸡，禁门嘶骑，宦情熟处。","正黄编夜展，天香字暖，春葱翦、红蜜炬。","宫帽鸾枝酔舞。","思飘扬、臞仙风举。","星罗万巻，云驱千阵，飞毫海雨。","长寿杯深，探春腔稳，江湖同赋。","又看看、便系金狨莺晓，傍西湖路。"],"source":"宋词"},{"title":"诈妮子调风月・梨花儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["是教我软地上吃交，我也不共你争。","煞是多劳重，降尊临卑，（云）有劳长者车马，贵脚踏于贱地，小的毎多谢承。","本待麻线道上不和你一处行；（云）你依得我一件事，依得我愿随鞭镫。","（云）你要我饶你咱，再对星月赌一个誓。","（云了）（出门了）（正旦唱）。"],"source":"元曲"},{"title":"凯风","author":"佚名","dynasty":"先秦","form":"诗","lines":["凯风自南，吹彼棘心。棘心夭夭，母氏劬劳。","凯风自南，吹彼棘薪。母氏圣善，我无令人。","爰有寒痊？在浚之下。有子七人，母氏劳苦。","𪾢睆黄鸟，载好其音。有子七人，莫慰母心。"],"source":"《诗经》"},{"title":"沉江","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["惟往古之得失兮，览私微之所伤。","尧舜圣而慈仁兮，后世称而弗忘。","齐桓失于专任兮，夷吾忠而名彰。","晋献惑于㛤姬兮，申生孝而被殃。","偃王行其仁义兮，荆文寤而徐亡。","纣暴虐以失位兮，周得佐乎吕望。","修往古以行恩兮，封比干之丘垄。","贤俊慕而自附兮，日浸淫而合同。","明法令而修理兮，兰芷幽而有芳。","苦众人之妒予兮，箕子寤而佯狂。","不顾地以贪名兮，心怫郁而内伤。","联蕙芷以为佩兮，过鲍肆而失香。","正臣端其操行兮，反离谤而见攘。","世俗更而变化兮，伯夷饿于首阳。","独廉洁而不容兮，叔齐久而逾明。","浮云陈而蔽晦兮，使日月乎无光。","忠臣贞而欲谏兮，谗谀毁而在旁。","秋草荣其将实兮，微霜下而夜降。","商风肃而害生兮，百草育而不长。","众并谐以妒贤兮，孤圣特而易伤。","怀计谋而不见用兮，岩穴处而隐蔵。","成功隳而不卒兮，子胥死而不葬。","世从俗而变化兮，随风靡而成行。","信直退而毁败兮，虚伪进而得当。","追悔过之无及兮，岂尽忠而有功。","废制度而不用兮，务行私而去公。","终不变而死节兮，惜年齿之未央。","将方舟而下流兮，冀幸君之发蒙。","痛忠言之逆耳兮，恨申子之沉江。","愿悉心之所闻兮，遭值君之不聪。","不开寤而难道兮，不别横之与纵。","听奸臣之浮说兮，绝国家之久长。","灭规矩而不用兮，背绳墨之正方。","离忧患而乃寤兮，若纵火于秋蓬。","业失之而不救兮，尚何论乎祸凶。","彼离畔而朋党兮，独行之士其何望？","日渐染而不自知兮，秋毫微哉而变容。","众轻积而折轴兮，原咎杂而累重。","赴湘沅之流澌兮，恐逐波而复东。","怀沙砾而自沉兮，不忍见君之蔽壅。"],"source":"《楚辞》"},{"title":"北青萝","author":"李商隠","dynasty":"唐","form":"诗","lines":["残阳西入崦，茅屋访孤僧。","落叶人何在，寒云路几层。","独敲初夜磬，闲倚一枝藤。","世界微尘里，吾宁爱与憎。"],"source":"《唐诗三百首》"},{"title":"瑞香花","author":"范成大","dynasty":"宋","form":"诗","lines":["万粒丛芳破雪残，曲房深院闭春寒。","紫紫青青云锦被，百畳薫笼晩不翻。","酒悪休拈花蘂嗅，花気酔人𬪩胜酒。","大将香供悩幽禅，恰在兰枯梅落后。"],"source":"宋诗"},{"title":"玉烛新","author":"吴文英","dynasty":"宋","form":"词","lines":["花穿帘隙透。","向梦里销春，酒中延昼。","嫩篁细掐，相思字、堕粉轻黏𦈌袖。","章台别后，展绣络、红荐香旧。","□□□，应数归舟，愁凝画阑眉柳。","移灯夜语西窗，逗晓帐迷香，问何时又。","素纨乍试，还忆是、绣懒思酸时候。","兰清蕙秀。","总为比、蛾眉螓首。","谁诉与，惟有金笼，春簧细奏。"],"source":"宋词"},{"title":"诈妮子调风月・紫花儿序","author":"关汉卿","dynasty":"元","form":"曲","lines":["你把遥天指定，指定那淡月疏星，再说一个海誓山盟；我便収撮了火性，铺撒了人情，忍气吞声，饶过你那亏人不志诚。","赚出门程，（入房科）呼的关上栊门，铺的吹灭残灯。"],"source":"元曲"},{"title":"雄雉","author":"佚名","dynasty":"先秦","form":"诗","lines":["雄雉于飞，泄泄其羽。我之怀矣，自诒伊阻。","雄雉于飞，下上其音。展矣君子，实劳我心。","瞻彼日月，悠悠我思。道之云远，曷云能来？","百尔君子，不知徳行。不忮不求，何用不臧。"],"source":"《诗经》"},{"title":"怨世","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["世沉淖而难论兮，俗岒峨而㟥嵯。","清泠泠而歼灭兮，溷湛湛而日多。","枭鸮既以成群兮，玄鹤弭翼而屏移。","蓬艾亲入御于床笫兮，马兰踸踔而日加。","弃捐药芷与杜衡兮，余柰世之不知芳何？","何周道之平易兮，然芜秽而险戏。","高阳无故而委尘兮，唐虞点灼而毁议。","谁使正其真是兮，虽有八师而不可为。","皇天保其高兮，后土持其久。","服清白以逍遥兮，偏与乎玄英异色。","西施媞媞而不得见兮，嫫母勃屑而日侍。","桂蠹不知所淹留兮，蓼虫不知徙乎葵菜。","处湣湣之浊世兮，今安所达乎吾志。","意有所载而远逝兮，固非众人之所识。","骥踌躇于弊輂兮，遇孙阳而得代。","吕望穷困而不聊生兮，遭周文而舒志。","宁戚饭牛而商歌兮，桓公闻而弗置。","路室女之方桑兮，孔子过之以自侍。","吾独乖剌而无当兮，心悼怵而耄思。","思比干之恲恲兮，哀子胥之慎事。","悲楚人之和氏兮，献宝玉以为石。","遇厉武之不察兮，羌两足以毕斮。","小人之居势兮，视忠正之何若？","改前圣之法度兮，喜嗫嚅而妄作。","亲谗谀而疏贤圣兮，讼谓闾娵为丑恶。","愉近习而蔽远兮，孰知察其黒白？","卒不得効其心容兮，安眇眇而无所归薄。","专精爽以自明兮，晦冥冥而壅蔽。","年既已过太半兮，然埳轲而留滞。","欲高飞而远集兮，恐离罔而灭败。","独冤抑而无极兮，伤精神而寿夭。","皇天既不纯命兮，余生终无所依。","愿自沉于江流兮，绝横流而径逝。","宁为江海之泥涂兮，安能久见此浊世？"],"source":"《楚辞》"},{"title":"赤壁","author":"李商隠","dynasty":"唐","form":"诗","lines":["折戟沈沙鉄未销，自将磨洗认前朝。","东风不与周郎便，铜雀春深锁二乔。"],"source":"《唐诗三百首》"},{"title":"読史","author":"范成大","dynasty":"宋","form":"诗","lines":["登坛策刘项，卧庐料曹孙。","探懐取事业，一一如印圏。","英豪盖天资，八极入控抟。","由来事成毁，只繋手覆翻。","玉虹朝贯日，剣気夜烛天。","虽欲避功名，何処蛰竜鸾。","我生后千载，愚暗难具言。","长大但食粟，闵凶不能文。","麦豆已难弁，楣棁固不分。","抱瓮灌圃畦，截竿避城门。","智略类如此，何以超篱籓。","亀刳始神䇲，木断方犠尊。","朝市有机穽，冠裳或钳髠。","兹事定不暗，吾其老泥蟠。","敢云善用短，聊复强自寛。"],"source":"宋诗"},{"title":"解语花","author":"吴文英","dynasty":"宋","form":"词","lines":["门横皱碧，路入苍烟，春近江南岸。","暮寒如翦。","临渓影、一一半斜清浅。","飞霙弄晩。","荡千里、暗香平远。","端正看，琼树三枝，总似兰昌见。","酥莹云容夜暖。","伴兰翘清痩，箫凤柔婉。","冷云荒翠，幽栖久、无语暗申春怨。","东风半面。","料准拟、何郎词巻。","欢未阑，烟雨青黄，宜昼阴庭馆。"],"source":"宋词"},{"title":"诈妮子调风月・小桃红","author":"关汉卿","dynasty":"元","form":"曲","lines":["燕燕上复传示煞曽经，谁会甚儿女成婚聘？甚的是许出羞、下红定？问这洛阳城，少甚幺能言快语官媒证？燕燕怎敢仮名托姓？但教我一权为政，情取\"火上等冬凌\"。"],"source":"元曲"},{"title":"匏有苦叶","author":"佚名","dynasty":"先秦","form":"诗","lines":["匏有苦叶，济有深渉。深则厉，浅则掲。","有弥济盈，有鷕雉鸣。济盈不濡轨，雉鸣求其牡。","雍雍鸣雁，旭日始旦。士如归妻，迨冰未泮。","招招舟子，人渉卬否。不渉卬否，卬须我友。"],"source":"《诗经》"},{"title":"怨思","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["贤士穷而隐处兮，廉方正而不容。","子胥谏而靡躯兮，比干忠而剖心。","子推自割而飤君兮，徳日忘而怨深。","行明白而曰黒兮，荆棘聚而成林。","江离弃于穷巷兮，蒺藜蔓乎东厢。","贤者蔽而不见兮，谗谀进而相朋。","枭鸮并进而俱鸣兮，凤皇飞而高翔。","原壱往而径逝兮，道壅绝而不通。"],"source":"《楚辞》"},{"title":"章台夜思","author":"韦荘","dynasty":"唐","form":"诗","lines":["清瑟怨遥夜，遶弦风雨哀。","孤灯闻楚角，残月下章台。","芳草已云暮，故人殊未来。","郷书不可寄，秋雁又南回。"],"source":"《唐诗三百首》"},{"title":"浙江小矶春日","author":"范成大","dynasty":"宋","form":"诗","lines":["客里无人共一杯，故园桃李为谁开。","春潮不管天涯恨，更卷西兴暮雨来。"],"source":"宋诗"},{"title":"解语花","author":"吴文英","dynasty":"宋","form":"词","lines":["檐花旧滴，帐烛新啼，香润残冬被。","澹烟疏绮。","凌波歩、暗阻傍墙挑荠。","梅痕似洗。","空点点、年华别泪。","花鬓愁，钗股笼寒，彩燕沾云腻。","还斗辛盘葱翠。","念青丝牵恨，曽试纤指。","雁回潮尾。","征帆去、似与东风相避。","泥云万里。","应翦断、红情绿意。","年少时，偏爱轻怜，和酒香宜睡。"],"source":"宋词"},{"title":"诈妮子调风月・调笑令","author":"关汉卿","dynasty":"元","form":"曲","lines":["这厮短命，没前程，做得个\"轻人还自轻\"，横死口里栽排定。","老夫人随邪水性，道我能言快语说合成，我说波娘七代先灵！，。"],"source":"元曲"},{"title":"谷风","author":"佚名","dynasty":"先秦","form":"诗","lines":["习习谷风，以阴以雨。黾勉同心，不宜有怒。采葑采菲，无以下体？徳音莫违，及尔同死。","行道迟迟，中心有违。不远伊迩，薄送我畿。谁谓荼苦，其甘如荠。宴尔新婚，如兄如弟。","泾以渭浊，湜湜其沚。宴尔新婚，不我屑以。毋逝我梁，毋发我笱。我躬不阅，遑恤我后。","就其深矣，方之舟之。就其浅矣，泳之游之。何有何亡，黾勉求之。凡民有丧，匍匐救之。","不我能畜，反以我为仇。既阻我徳，贾用不售。昔育恐育鞫，及尔颠覆。既生既育，比予于毒。","我有旨蓄，亦以御冬。宴尔新婚，以我御穷。有洸有溃，既诒我肄。不念昔者，伊余来塈。"],"source":"《诗经》"},{"title":"自悲","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["居愁懃其谁告兮，独永思而忧悲。","内自省而不惭兮，操愈坚而不衰。","隐三年而无决兮，岁忽忽其若颓。","怜余身不足以卒意兮，冀一见而复归。","哀人事之不幸兮，属天命而委之咸池。","身被疾而不闲兮，心沸热其若汤。","冰炭不可以相并兮，吾固知乎命之不长。","哀独苦死之无乐兮，惜予年之未央。","悲不反余之所居兮，恨离予之故乡。","鸟兽惊而失群兮，犹高飞而哀鸣。","狐死必首丘兮，夫人孰能不反其真情？","故人疏而日忘兮，新人近而俞好。","莫能行于杳冥兮，孰能施于无报？","苦众人之皆然兮，乗回风而远游。","凌恒山其若陋兮，聊愉娱以忘忧。","悲虚言之无实兮，苦众口之铄金。","过故乡而一顾兮，泣歔欷而沾衿。","厌白玉以为面兮，怀琬琰以为心。","邪气入而感内兮，施玉色而外淫。","何青云之流澜兮，微霜降之蒙蒙。","徐风至而徘徊兮，疾风过之汤汤。","闻南籓乐而欲往兮，至会稽而且止。","见韩众而宿之兮，问天道之所在？","借浮云以送予兮，载雌霓而为旌。","驾青龙以驰骛兮，班衍衍之冥冥。","忽容容其安之兮，超慌忽其焉如？","苦众人之难信兮，愿离群而远举。","登峦山而远望兮，好桂树之冬荣。","观天火之炎炀兮，听大壑之波声。","引八维以自道兮，含沆瀣以长生。","居不乐以时思兮，食草木之秋实。","饮菌若之朝露兮，构桂木而为室。","杂橘柚以为囿兮，列新夷与椒桢。","鹍鹤孤而夜号兮，哀居者之诚贞。"],"source":"《楚辞》"},{"title":"金陵図","author":"韦荘","dynasty":"唐","form":"诗","lines":["谁谓伤心画不成，画人心逐世人情。","君看六幅南朝事，老木寒云満故城。"],"source":"《唐诗三百首》"},{"title":"代圣集赠别","author":"范成大","dynasty":"宋","form":"诗","lines":["一曲悲歌水倒流，尊前何计缓千忧。","事如梦断无寻処，人似春帰挽不留。","草色粘天𫛸鴂恨，雨声连暁鹧鸪愁。","迢迢绿浦帆飞远，今夜新晴独倚楼。"],"source":"宋诗"},{"title":"庆春宫・高阳台","author":"吴文英","dynasty":"宋","form":"词","lines":["春屋围花，秋池沿草，旧家锦藉川原。","莲花分津，桃边迷路，片红不到人间。","乱篁苍暗，料惜把、行题共删。","小晴帘巻，独占西墙，一镜清寒。","风光未老吟潘。","嘶骑征尘，祗付凭阑。","鸣瑟传杯，辟邪翻烬。","系船香斗春宽。","晩林青外，乱鸦着、斜阳几山。","粉消莫染，犹是秦宫，绿扰云鬟。"],"source":"宋词"},{"title":"诈妮子调风月・圣药王","author":"关汉卿","dynasty":"元","form":"曲","lines":["然道户厮迎，也合再打听，两门亲便走一遭儿成。","我若到那户庭，见那婢婷，若是那女孩儿言语没实诚，俺这厮强风情。","（虚下）（外孤上）（旦上，见孤云）夫人使来问小姐亲事，相公许不许，燕燕回去。","（外孤云了）（闪下）（外旦上）（旦随上，见了，云）特地来问小姐亲事，许不许？回去。","（外旦许了）（正旦唱）。"],"source":"元曲"},{"title":"式微","author":"佚名","dynasty":"先秦","form":"诗","lines":["式微，式微，胡不归？微君之故，胡为乎中露！","式微，式微，胡不归？微君之躬，胡为乎泥中！"],"source":"《诗经》"},{"title":"哀命","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["哀时命之不合兮，伤楚国之多忧。","内怀情之洁白兮，遭乱世而离尤。","恶耿介之直行兮，世溷浊而不知。","何君臣之相失兮，上沅湘而分离。","测汨罗之湘水兮，知时固而不反。","伤离散之交乱兮，遂侧身而既远。","处玄舎之幽门兮，穴岩石而窟伏。","从水蛟而为徙兮，与神龙乎休息。","何山石之崭岩兮，灵魂屈而偃蹇。","含素水而蒙深兮，日眇眇而既远。","哀形体之离解兮，神罔两而无舎。","惟椒兰之不反兮，魂迷惑而不知路。","愿无过之设行兮，虽灭没之自乐。","痛楚国之流亡兮，哀灵修之过到。","固时俗之溷浊兮，志瞀迷而不知路。","念私门之正匠兮，遥渉江而远去。","念女媭之婵媛兮，涕泣流乎于悒。","我决死而不生兮，虽重追吾何及。","戏疾濑之素水兮，望高山之蹇产。","哀高丘之赤岸兮，遂没身而不反。"],"source":"《楚辞》"},{"title":"台城","author":"韦荘","dynasty":"唐","form":"诗","lines":["江雨霏霏江草斉，六朝如梦鸟空啼。","无情最是台城柳，依旧烟笼十里堤。"],"source":"《唐诗三百首》"},{"title":"二月三日登楼有懐金陵宣城诸友","author":"范成大","dynasty":"宋","form":"诗","lines":["百尺西楼十二栏，日遅花影対人闲。","春风已入片时梦，寒食従今数日间。","折柳故情多望断，落梅新曲与愁関。","诗成欲访江南便，千里烟波万畳山。"],"source":"宋诗"},{"title":"庆春宫・高阳台","author":"吴文英","dynasty":"宋","form":"词","lines":["残叶翻浓，馀香栖苦，障风怨动秋声。","云影摇寒，波尘销腻，翠房人去深扃。","昼成凄黯，雁飞过、垂杨转青。","阑干横暮，酥印痕香，玉腕谁凭。","菱花乍失娉婷。","别岸围红，千艳倾城。","重洗清杯，同追深夜，豆花寒落愁灯。","近欢成梦，断云隔、巫山几层。","偷相怜处，熏尽金篝，销痩云英。"],"source":"宋词"},{"title":"诈妮子调风月・天净沙","author":"关汉卿","dynasty":"元","form":"曲","lines":["先教人掩扑了我几夜恩情，来这里被他骂得我百节酸疼，我便似□墙贼蝎蜇呼声。","空使心作幸，被小夫人引了我魂灵。"],"source":"元曲"},{"title":"旄丘","author":"佚名","dynasty":"先秦","form":"诗","lines":["旄丘之葛兮，何诞之节兮。叔兮伯兮，何多日也？","何其处也？必有与也！何其久也？必有以也！","狐裘蒙戎，匪车不东。叔兮伯兮，靡所与同。","琐兮尾兮，流离之子。叔兮伯兮，褎如充耳。"],"source":"《诗经》"},{"title":"谬谏","author":"东方朔","dynasty":"先秦","form":"辞赋","lines":["怨灵修之浩荡兮，夫何执操之不固？","悲太山之为隍兮，孰江河之可涸？","愿承闲而効志兮，恐犯忌而干讳。","卒抚情以寂寞兮，然怊怅而自悲。","玉与石其同匮兮，贯鱼眼与珠玑。","驽骏杂而不分兮，服罢牛而骖骥。","年滔滔而自远兮，寿冉冉而愈衰。","心悇憛而烦冤兮，蹇超摇而无冀。","固时俗之工巧兮，灭规矩而改错。","郤骐骥而不乗兮，策驽骀而取路。","当世岂无骐骥兮，诚无王良之善驭。","见执辔者非其人兮，故驹跳而远去。","不量凿而正枘兮，恐矩矱之不同。","不论世而高举兮，恐操行之不调。","弧弓弛而不张兮，孰云知其所至？","无倾危之患难兮，焉知贤士之所死？","俗推佞而进富兮，节行张而不着。","贤良蔽而不群兮，朋曹比而党誉。","邪说饰而多曲兮，正法弧而不公。","直士隐而避匿兮，谗谀登乎明堂。","弃彭咸之娱乐兮，灭巧倕之绳墨。","菎蕗杂于黀蒸兮，机蓬矢以射革。","驾蹇驴而无策兮，又何路之能极？","以直针而为钓兮，又何鱼之能得？","伯牙之绝弦兮，无锺子期而听之。","和抱璞而泣血兮，安得良工而剖之？","同音者相和兮，同类者相似。","飞鸟号其群兮，鹿鸣求其友。","故叩宫而宫应兮，弹角而角动。","虎啸而谷风至兮，龙举而景云往。","音声之相和兮，言物类之相感也。","夫方圜之异形兮，势不可以相错。","列子隐身而穷处兮，世莫可以寄讬。","众鸟皆有行列兮，凤独翔翔而无所薄。","经浊世而不得志兮，愿侧身岩穴而自讬。","欲阖口而无言兮，尝被君之厚徳。","独便悁而怀毒兮，愁郁郁之焉极？","念三年之积思兮，愿壱见而陈辞。","不及君而骋说兮，世孰可为明之？","身寝疾而日愁兮，情沉抑而不扬。","众人莫可与论道兮，悲精神之不通。","乱曰：鸾皇孔凤日以远兮，畜凫驾鹅。","鸡鹜满堂坛兮，鼍黾游乎华池。","要褭奔亡兮，腾驾橐驼。","铅刀进御兮，遥弃太阿。","抜搴玄芝兮，列树芋荷。","橘柚萎枯兮，苦李旖旎。","甂瓯登于明堂兮，周鼎潜潜乎深渊。","自古而固然兮，吾又何怨乎今之人。"],"source":"《楚辞》"},{"title":"宫词","author":"薛逢","dynasty":"唐","form":"诗","lines":["十二楼中尽暁妆，望仙楼上望君王。","锁衔金獣连环冷，水滴铜竜昼漏长。","云髻罢梳还対镜，罗衣欲换更添香。","遥窥正殿帘开処，袍袴宫人扫御床。"],"source":"《唐诗三百首》"},{"title":"寒食郊行书事二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["野店垂杨歩，荒祠苦竹丛。","鹭窥芦箔水，乌啄纸銭风。","媪引浓妆女，児扶烂酔翁。","深村时节好，応为去年豊。"],"source":"宋诗"},{"title":"塞垣春","author":"吴文英","dynasty":"宋","form":"词","lines":["漏瑟侵琼管。","润鼓借、烘炉暖。","蔵钩怯冷，画鸡临晓，怜语莺啭。","𣨼绿窗、细呪浮梅盏。","换蜜炬、花心短。","梦惊回，林鸦起，曲屏春事天远。","迎路柳丝裙，看争拝东风，盈灞桥岸。","髻落宝钗寒，恨花胜迟燕。","渐街帘影转。","还似新年，过邮亭、一相见。","南陌又灯火，绣囊尘香浅。"],"source":"宋词"},{"title":"诈妮子调风月・拙鲁速","author":"关汉卿","dynasty":"元","form":"曲","lines":["终身无簸箕星，指云中雁做羹。","时下且口口声声，战战兢兢，袅袅婷婷，坐坐行行；有一日孤孤另另，冷冷清清，咽咽哽哽，觑着你个拖汉精！。"],"source":"元曲"},{"title":"简兮","author":"佚名","dynasty":"先秦","form":"诗","lines":["简兮简兮，方将万舞。日之方中，在前上处。","硕人俣俣，公庭万舞。有力如虎，执辔如组。","左手执龠，右手秉翟。赫如渥赭，公言锡爵。","山有榛，隰有苓。云谁之思？西方美人。彼美人兮，西方之人兮。"],"source":"《诗经》"},{"title":"哀时命","author":"庄忌","dynasty":"先秦","form":"辞赋","lines":["哀时命之不及古人兮，夫何予生之不遘时！","往者不可扳援兮，徕者不可与期。","志憾恨而不逞兮，杼中情而属诗。","夜炯炯而不寐兮，怀隐忧而历兹。","心郁郁而无告兮，众孰可与深谋！","欿愁悴而委惰兮，老冉冉而逮之。","居处愁以隐约兮，志沉抑而不扬。","道壅塞而不通兮，江河广而无梁。","愿至昆仑之悬圃兮，采锺山之玉英。","揽瑶木之橝枝兮，望阆风之板桐。","弱水汩其为难兮，路中断而不通。","势不能凌波以径度兮，又无羽翼而高翔。","然隐悯而不达兮，独徙倚而彷徉。","怅惝罔以永思兮，心纡轸而増伤。","倚踌躇以淹留兮，日饥馑而绝粮。","廓抱景而独倚兮，超永思乎故乡。","廓落寂而无友兮，谁可与玩此遗芳？","白日晼晼其将入兮，哀余寿之弗将。","车既弊而马罢兮，蹇邅徊而不能行。","身既不容于浊世兮，不知进退之宜当。","冠崔嵬而切云兮，剑淋离而从横。","衣摄叶以储与兮，左袪挂于榑桑","右衽払于不周兮，六合不足以肆行。","上同凿枘于伏戏兮，下合矩矱于虞唐。","原尊节而式高兮，志犹卑夫禹汤。","虽知困其不改操兮，终不以邪枉害方。","世并举而好朋兮，壱斗斛而相量。","众比周以肩迫兮，贤者远而隐蔵。","为凤皇作鹑笼兮，虽翕翅其不容。","灵皇其不寤知兮，焉陈词而効忠。","俗嫉妒而蔽贤兮，孰知余之从容？","愿舒志而抽冯兮，庸讵知其吉凶？","璋珪杂于甑窐兮，陇廉与孟娵同宫。","举世以为恒俗兮，固将愁苦而终穷。","幽独转而不寐兮，惟烦懑而盈匈。","魂眇眇而驰骋兮，心烦冤之忡忡。","志欿憾而不憺兮，路幽昧而甚难。","块独守此曲隅兮，然欿切而永叹。","愁修夜而宛转兮，气涫沸其若波。","握剞劂而不用兮，操规矩而无所施。","骋骐骥于中庭兮，焉能极夫远道？","置援狖于棂槛兮，夫何以责其捷巧？","驷跛鳖而上山兮，吾固知其不能升。","释管晏而任臧获兮，何权衡之能称？","箟簬杂于黀蒸兮，机蓬矢以射革。","负檐荷以丈尺兮，欲伸要而不可得。","外迫胁于机臂兮，上牵联于矰隿。","肩倾侧而不容兮，固陿腹而不得息。","务光自投于深渊兮，不获世之尘垢。","孰魁摧之可久兮，愿退身而穷处。","凿山楹而为室兮，下被衣于水渚。","雾露蒙蒙其晨降兮，云依斐而承宇。","虹霓纷其朝霞兮，夕淫淫而淋雨。","怊茫茫而无归兮，怅远望此旷野。","下垂钓于渓谷兮，上要求于仙者。","与赤松而结友兮，比王侨而为耦。","使枭杨先导兮，白虎为之前后。","浮云雾而入冥兮，骑白鹿而容与。","魂眐眐以寄独兮，汨徂往而不归。","处卓卓而日远兮，志浩荡而伤怀。","鸾凤翔于苍云兮，故矰缴而不能加。","蛟龙潜于旋渊兮，身不挂于罔罗。","知贪饵而近死兮，不如下游乎清波。","宁幽隐以远祸兮，孰侵辱之可为。","子胥死而成义兮，屈原沉于汨罗。","虽体解其不变兮，岂忠信之可化。","志怦怦而内直兮，履绳墨而不颇。","执权衡而无私兮，称轻重而不差。","摡尘垢之枉攘兮，除秽累而反真。","形体白而质素兮，中皎洁而淑清。","时猒饫而不用兮，且隐伏而远身。","聊窜端而匿迹兮，嗼寂黙而无声。","独便悁而烦毒兮，焉发愤而筊抒。","时暧暧其将罢兮，遂闷叹而无名。","伯夷死于首阳兮，卒夭隐而不荣。","太公不遇文王兮，身至死而不得逞。","怀瑶象而佩琼兮，愿陈列而无正。","生天坠之若过兮，忽烂漫而无成。","邪气袭余之形体兮，疾憯怛而萌生。","原壱见阳春之白日兮，恐不终乎永年。"],"source":"《楚辞》"},{"title":"楚江懐古三首 一","author":"马戴","dynasty":"唐","form":"诗","lines":["露気寒光集，微阳下楚丘。","猨啼洞庭树，人在木兰舟。","広沢生明月，苍山夹乱流。","云中君不降，竟夕自悲秋。"],"source":"《唐诗三百首》"},{"title":"寒食郊行书事二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["陇麦欣欣绿，山桃寂寂红。","帆辺渔𫈵浪，木末酒旗风。","信歩随芳草，迷途问小童。","赏心添脚力，呼渡过渓东。"],"source":"宋诗"},{"title":"宴清都","author":"吴文英","dynasty":"宋","form":"词","lines":["翠羽飞梁苑。","连催发，暮樯留话江燕。","尘街堕珥，瑶扉乍钥，彩绳双罥。","新烟暗叶成阴，効翠妩、西陵送远。","又趁得、蕊露天香，春留建章花晩。","归来笑折仙桃，琼楼宴萼，金漏催箭。","兰亭秀语，乌丝润墨，汉宫传玩。","红敧酔玉天上，倩凤尾、时题画扇。","问几时、重驾巫云，蓬莱路浅。"],"source":"宋词"},{"title":"诈妮子调风月・収尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["大刚来\"主人有福牙推胜\"，不似这调风月媒人背厅。","说得他美甘甘枕头儿上双成，闪得我薄设设被窝儿里冷！（下）。"],"source":"元曲"},{"title":"泉水","author":"佚名","dynasty":"先秦","form":"诗","lines":["毖彼泉水，亦流于淇。有怀于卫，靡日不思。娈彼诸姬，聊与之谋。","出宿于泲，饮饯于祢。女子有行，远父母兄弟，问我诸姑，遂及伯姊。","出宿于干，饮饯于言。载脂载辖，还车言迈。遄臻于卫，不瑕有害？","我思肥泉，兹之永叹。思须与漕，我心悠悠。驾言出游，以写我忧。"],"source":"《诗经》"},{"title":"匡机","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["极运兮不中，来将屈兮困穷。","余深愍兮惨怛，愿一列兮无从。","乗日月兮上征，顾游心兮鄗酆。","弥览兮九隅，彷徨兮兰宫。","芷闾兮药房，奋摇兮众芳。","菌阁兮蕙楼，观道兮从横。","宝金兮委积，美玉兮盈堂。","桂水兮潺湲，扬流兮洋洋。","蓍蔡兮踊跃，孔鹤兮回翔。","抚槛兮远望，念君兮不忘。","怫郁兮莫陈，永怀兮内伤。"],"source":"《楚辞》"},{"title":"灞上秋居","author":"马戴","dynasty":"唐","form":"诗","lines":["灞原风雨定，晩见鴈行频。","落叶他郷树，寒灯独夜人。","空园白露滴，孤壁野僧隣。","寄卧郊扉久，何门致此身。"],"source":"《唐诗三百首》"},{"title":"初夏二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["清晨出郭更登台，不见余春只么回。","桑叶露枝蚕向老，菜花成荚蝶犹来。"],"source":"宋诗"},{"title":"宴清都","author":"吴文英","dynasty":"宋","form":"词","lines":["绣幄鸳鸯柱。","红情密，腻云低护秦树。","芳根兼倚，花梢钿合，锦屏人妒。","东风睡足交枝，正梦花、瑶钗燕股。","障滟蜡、满照欢丛，嫠蟾冷落羞度。","人间万感幽单，华清惯浴，春盎风露。","连鬟并暖，同心共结，向承恩处。","凭谁为歌长恨，暗殿锁、秋灯夜语。","叙旧期、不负春盟，红朝翠暮。"],"source":"宋词"},{"title":"诈妮子调风月・双调/新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["双撒敦是部尚书，女婿是世袭千户。","有二百匹金勒马，五十辆画轮车。","说得他儿女妻夫，似水如鱼；撇得我鳏寡孤独，那的是撮合山养身处？。"],"source":"元曲"},{"title":"北门","author":"佚名","dynasty":"先秦","form":"诗","lines":["出自北门，忧心殷殷。终窭且贫，莫知我艰。已焉哉！天实为之，谓之何哉！","王事适我，政事一埤益我。我入自外，室人交遍谪我。已焉哉！天实为之，谓之何哉！","王事敦我，政事一埤遗我。我入自外，室人交遍摧我。已焉哉！天实为之，谓之何哉！"],"source":"《诗经》"},{"title":"通路","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["天门兮墬户，孰由兮贤者？","无正兮溷厕，怀徳兮何睹？","仮寐兮愍斯，谁可与兮寤语？","痛凤兮远逝，畜𫛩兮近处。","鲸鱏兮幽潜，从虾兮游陼。","乗虬兮登阳，载象兮上行。","朝发兮葱岭，夕至兮明光。","北饮兮飞泉，南采兮芝英。","宣游兮列宿，顺极兮彷徉。","红采兮骍衣，翠缥兮为裳。","舒佩兮𬘭𫄥，竦余剑兮干将。","腾蛇兮后从，飞駏兮歩旁。","微观兮玄圃，览察兮瑶光。","启匮兮探䇲，悲命兮相当。","纫蕙兮永辞，将离兮所思。","浮云兮容与，道余兮何之？","远望兮仟眠，闻雷兮阗阗。","阴忧兮感余，惆怅兮自怜。"],"source":"《楚辞》"},{"title":"马嵬坡","author":"郑畋","dynasty":"唐","form":"诗","lines":["[玄]宗回马杨妃死，云雨虽亡日月新。","终是圣明天子事，景阳宫井又何人。"],"source":"《唐诗三百首》"},{"title":"初夏二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["晴糸千尺挽韶光，百舌无声燕子忙。","永日屋头槐影暗，微风扇里麦花香。"],"source":"宋诗"},{"title":"宴清都","author":"吴文英","dynasty":"宋","form":"词","lines":["万壑蓬莱路。","非烟霁，五云城阙深处。","璇源媲凤，瑶池种玉，练颜金姥。","长虹梦入仙怀，便洗日、铜华翠渚。","向瑞世、独占长春，蟠桃正饱风露。","殷勤汉殿传卮，隔江云起，暗飞青羽。","南山寿石，东周宝鼎，千秋巩固。","何时地払龙衣，待迎入、玉京阆圃。","看□□、剰拥湖船，三千彩御。"],"source":"宋词"},{"title":"诈妮子调风月・驻马听","author":"关汉卿","dynasty":"元","form":"曲","lines":["官人石碾连珠，满腰背无瑕玉免鹘；夫人毎是依时按序，细搀绒全套绣衣服。","包髻是缨络大真珠，额花是秋色玲珑玉。","悠悠的品着鹧鸪，雁行般但举手都能舞。"],"source":"元曲"},{"title":"北风","author":"佚名","dynasty":"先秦","form":"诗","lines":["北风其凉，雨雪其雱。恵而好我，携手同行。其虚其邪？既亟只且！","北风其喈，雨雪其霏。恵而好我，携手同归。其虚其邪？既亟只且！","莫赤匪狐，莫黒匪乌。恵而好我，携手同车。其虚其邪？既亟只且！"],"source":"《诗经》"},{"title":"危俊","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["林不容兮鸣蜩，余何留兮中州？","陶嘉月兮总驾，搴玉英兮自修。","结荣茝兮逶逝，将去烝兮远游。","径岱土兮魏阙，历九曲兮牵牛。","聊仮日兮相佯，遗光燿兮周流。","望太一兮淹息，纡余辔兮自休。","晞白日兮皎皎，弥远路兮悠悠。","顾列孛兮缥缥，观幽云兮陈浮。","钜宝迁兮砏磤，雉咸雊兮相求。","泱莽莽兮究志，惧吾心兮㤽㤽。","歩余马兮飞柱，览可与兮匹俦。","卒莫有兮纤介，永余思兮怞怞。"],"source":"《楚辞》"},{"title":"没蕃故人","author":"张籍","dynasty":"唐","form":"诗","lines":["前年伐月支，城上没全师。","蕃汉断消息，死生长别离。","无人収廃帐，帰马识残旗。","欲祭疑君在，天涯哭此时。"],"source":"《唐诗三百首》"},{"title":"夏夜","author":"范成大","dynasty":"宋","form":"诗","lines":["脉脉惜佳夜，泠泠成浩歌。","傥无诗句子，将奈月明何。","露気蒙花重，风声入树多。","清歓殊未办，桂影堕江波。"],"source":"宋诗"},{"title":"宴清都","author":"吴文英","dynasty":"宋","form":"词","lines":["翠匝西门柳。","荆州昔，未来时正春痩。","如今剰舞，西风旧色，胜东风秀。","黄粱露湿秋江，转万里、云樯蔽昼。","正虎落、马静晨嘶，连营夜沈刁斗。","含章换几桐阴，千官邃幄，韶凤还奏。","席前夜久，天低宴密，御香盈袖。","星槎信约长在，酔兴渺、银河赋就。","对小弦、月挂南楼，凉浮桂酒。"],"source":"宋词"},{"title":"诈妮子调风月・甜水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["姐姐骨甜肉净，堪描堪塑。","生得肌肤似凝酥。","从小里梅香、嬷嬷擡举，问燕燕梳裹何如？。"],"source":"元曲"},{"title":"静女","author":"佚名","dynasty":"先秦","form":"诗","lines":["静女其姝，俟我于城隅。爱而不见，掻首踟蹰。","静女其娈，贻我彤管。彤管有炜，说怿女美。","自牧归荑，洵美且异。匪女之为美，美人之贻。"],"source":"《诗经》"},{"title":"昭世","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["世溷兮冥昏，违君兮归真。","乗龙兮偃蹇，高回翔兮上臻。","袭英衣兮缇[纟习]，披华裳兮芳芬。","登羊角兮扶舆，浮云漠兮自娱。","握神精兮雍容，与神人兮相胥。","流星坠兮成雨，进瞵盼兮上丘墟。","览旧邦兮滃郁，余安能兮久居。","志怀逝兮心懰栗，纡余辔兮踌躇。","闻素女兮微歌，听王后兮吹竽。","魂凄怆兮感哀，肠回回兮盘纡。","抚余佩兮缤纷，高太息兮自怜。","使祝融兮先行，令昭明兮开门。","驰六蛟兮上征，竦余驾兮入冥。","历九州兮索合，谁可与兮终生。","忽反顾兮西囿，睹轸丘兮崎倾。","横垂涕兮泫流，悲余后兮失灵。"],"source":"《楚辞》"},{"title":"春怨","author":"金昌绪","dynasty":"唐","form":"诗","lines":["打起黄莺児，莫教枝上啼。","啼时惊妾梦，不得到辽西。"],"source":"《唐诗三百首》"},{"title":"与时叙现老纳凉池上时叙诵新词甚工","author":"范成大","dynasty":"宋","form":"诗","lines":["会心不在远，顷歩便得之。","长风吹月来，清影落半池。","屋头见木叶，玲珑剪琉璃。","红尘绊両足，大笑児辈痴。","老禅挽我游，高论方轩眉。","潘郎忽鼎来，谈诗解人颐。","晩诵云髻篇，濯濯余春姿。","想见篇中人，清润如君诗。","笑我両枯木，独与三冬期。"],"source":"宋诗"},{"title":"宴清都","author":"吴文英","dynasty":"宋","form":"词","lines":["柳色春阴重。","东风力，快将云雁高送。","书檠细雨，吟窗乱雪，井寒笔冻。","家林秀橘霜老，笑分得、蟾边桂种。","应茂苑、斗转苍龙，唯潮献奇吴凤。","玉眉暗隐华年，凌云气压，千载云梦。","名笺澹墨，恩袍翠草，紫骝青鞚。","飞香杏园新句，眩酔眼、春游乍纵。","弄喜音、鹊绕庭花，红帘影动。"],"source":"宋词"},{"title":"诈妮子调风月・水仙子","author":"关汉卿","dynasty":"元","form":"曲","lines":["推那领系眼落处，采揪住那系腰行行掐胯骨。","我这般拈拈掐掐有甚难当处？想我那声冤不得苦痛处。","你不合先发头怒；你若无言语，怎敢将你觑付，你则索做使长、郎主。"],"source":"元曲"},{"title":"新台","author":"佚名","dynasty":"先秦","form":"诗","lines":["新台有泚，河水弥弥。燕婉之求，蘧篨不鲜。","新台有洒，河水浼浼。燕婉之求，蘧篨不殄。","鱼网之设，鸿则离之。燕婉之求，得此戚施。"],"source":"《诗经》"},{"title":"尊嘉","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["季春兮阳阳，列草兮成行。","余悲兮兰生，委积兮从横。","江离兮遗捐，辛夷兮挤臧。","伊思兮往古，亦多兮遭殃。","伍胥兮浮江，屈子兮沉湘。","运余兮念兹，心内兮怀伤。","望淮兮沛沛，滨流兮则逝。","榜舫兮下流，东注兮磕磕。","蛟龙兮导引，文鱼兮上濑。","抽蒲兮陈坐，援芙蕖兮为盖。","水跃兮余旌，继以兮微蔡。","云旗兮电骛，倏忽兮容裔。","河伯兮开门，迎余兮欢欣。","顾念兮旧都，怀恨兮艰难。","窃哀兮浮萍，泛淫兮无根。"],"source":"《楚辞》"},{"title":"遣悲懐三首 一","author":"元稹","dynasty":"唐","form":"诗","lines":["谢公最小偏怜女，嫁与黔娄百事乖。","顾我无衣捜画箧，泥他沽酒抜金钗。","野蔬充膳甘长藿，落叶添薪仰古槐。","今日俸銭过十万，与君営奠复営斎。"],"source":"《唐诗三百首》"},{"title":"林元复挽诗","author":"范成大","dynasty":"宋","form":"诗","lines":["胸次峥嵘満贮书，十年名字満江湖。","张公阅世诗千首，扬子伝家宅一区。","谩道春风须得意，那知秋雨不成珠。","自従雪魄冰魂散，鲁国今谁更服儒。"],"source":"宋诗"},{"title":"宴清都","author":"吴文英","dynasty":"宋","form":"词","lines":["万里关河眼。","愁凝处，渺渺残照红敛。","天低远树，潮分断港，路回淮甸。","吟鞭又指孤店。","对玉露金风送晩。","恨自古、才子佳人，此景此情多感。","吴王故苑。","别来良朋雅集，空叹蓬转。","挥毫记烛，飞觞赶月，梦销香断。","区区去程何限。","倩片纸、丁宁过雁。","寄相思，寒雨灯窗，芙蓉旧院。"],"source":"宋词"},{"title":"诈妮子调风月・殿前欢","author":"关汉卿","dynasty":"元","form":"曲","lines":["俺千户跨龙驹，称得上的敢望七香车。","愿结同心结，永挂合欢树。","蛮凤娇雏，连理枝比目鱼。","千载相完聚，花发无风雨。","头白相守，眼黒处全无。"],"source":"元曲"},{"title":"二子乗舟","author":"佚名","dynasty":"先秦","form":"诗","lines":["二子乗舟，泛泛其景。愿言思子，中心养养！","二子乗舟，泛泛其逝。愿言思子，不瑕有害？"],"source":"《诗经》"},{"title":"蓄英","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["秋风兮萧萧，舒芳兮振条。","微霜兮眇眇，病殀兮鸣蜩。","玄鸟兮辞归，飞翔兮灵丘。","望谿谷兮滃郁，熊罴兮呴嗥。","唐虞兮不存，何故兮久留？","临渊兮汪洋，顾林兮忽荒。","修余兮袿衣，骑霓兮南上。","乗云兮回回，亹亹兮自强。","将息兮兰皐，失志兮悠悠。","蒶蕴兮霉黧，思君兮无聊。","身去兮意存，怆恨兮怀愁。"],"source":"《楚辞》"},{"title":"遣悲懐三首 二","author":"元稹","dynasty":"唐","form":"诗","lines":["昔日戯言身后意，今朝皆到眼前来。","衣裳已施行看尽，针线犹存未忍开。","尚想旧情怜婢仆，也曽因梦送銭财。","诚知此恨人人有，贫贱夫妻百事哀。"],"source":"《唐诗三百首》"},{"title":"戯赠少梁","author":"范成大","dynasty":"宋","form":"诗","lines":["屈膝铜舗昼掩関，薫炉谁伴夕香寒。","秋来合有相思字，会待风前片叶看。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["三千年事残鸦外，无言倦凭秋树。","逝水移川，高陵变谷，那识当时神禹。","幽云怪雨。","翠萍湿空梁，夜深飞去。","雁起青天，数行书似旧蔵处。","寂寥西窗久坐，故人悭会遇，同翦灯语。","积藓残碑，零圭断璧，重払人间尘土。","霜红罢舞。","漫山色青青，雾朝烟暮。","岸锁春船，画旗喧赛鼓。"],"source":"宋词"},{"title":"诈妮子调风月・乔牌儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["勘婚处恰岁数，出嫁后有衣禄。","若言招女婿，下财钱将娶过去。"],"source":"元曲"},{"title":"柏舟","author":"佚名","dynasty":"先秦","form":"诗","lines":["泛彼柏舟，在彼中河。髧彼两髦，实维我仪。之死矢靡它。母也天只，不谅人只！","泛彼柏舟，在彼河侧。髧彼两髦，实维我特。之死矢靡慝。母也天只，不谅人只！"],"source":"《诗经》"},{"title":"思忠","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["登九灵兮游神，静女歌兮微晨。","悲皇丘兮积葛，众体错兮交纷。","贞枝抑兮枯槁，枉车登兮庆云。","感余志兮惨栗，心怆怆兮自怜。","驾玄螭兮北征，向吾路兮葱岭。","连五宿兮建旄，扬氛气兮为旌。","历广漠兮驰骛，览中国兮冥冥。","玄武歩兮水母，与吾期兮南荣。","登华盖兮乗阳，聊逍遥兮播光。","抽库娄兮酌醴，援瓟瓜兮接粮。","毕休息兮远逝，发玉轫兮西行。","惟时俗兮疾正，弗可久兮此方。","寤辟摽兮永思，心怫郁兮内伤。"],"source":"《楚辞》"},{"title":"遣悲懐三首 三","author":"元稹","dynasty":"唐","form":"诗","lines":["闲坐悲君亦自悲，百年都是几多时。","邓攸无子寻知命，潘岳悼亡犹费词。","同穴窅冥何所望，他生縁会更难期。","唯将终夜长开眼，报荅平生未展眉。"],"source":"《唐诗三百首》"},{"title":"南徐道中","author":"范成大","dynasty":"宋","form":"诗","lines":["生憎行路与心违，又逐孤帆擘浪飞。","呉岫涌云穿望眼，楚江浮月冷征衣。","长歌悲似垂垂涙，短梦纷如草草帰。","若有一廛供闭戸，肯将篾舫换柴扉。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["芙蓉心上三更露，茸香漱泉玉井。","自洗银舟，徐开素酌，月落空杯无影。","庭阴未暝。","度一曲新蝉，韵秋堪听。","痩骨侵冰，怕惊纹簟夜深冷。","当时湖上载酒，翠云开处共，雪面波镜。","万感琼浆，千茎鬓雪，烟锁蓝桥花径。","留连暮景。","但偷觅孤欢，强宽秋兴。","酔倚修篁，晩风吹半醒。"],"source":"宋词"},{"title":"诈妮子调风月・挂玉钩","author":"关汉卿","dynasty":"元","form":"曲","lines":["是个破败家私铁扫帚，没些儿发旺夫家处，可更绝子嗣、妨公婆、克丈夫，脸上承泪靥无重数。","今年见吊客临，丧门聚；反阴覆阴，半载其余。"],"source":"元曲"},{"title":"墙有茨","author":"佚名","dynasty":"先秦","form":"诗","lines":["墙有茨，不可扫也。中冓之言，不可道也。所可道也，言之丑也。","墙有茨，不可襄也。中冓之言，不可详也。所可详也，言之长也。","墙有茨，不可束也。中冓之言，不可读也。所可读也，言之辱也。"],"source":"《诗经》"},{"title":"陶壅","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["览杳杳兮世惟，余惆怅兮何归。","伤时俗兮溷乱，将奋翼兮高飞。","驾八龙兮连蜷，建虹旌兮威夷。","观中宇兮浩浩，纷翼翼兮上跻。","浮溺水兮舒光，淹低佪兮京沶。","屯余车兮索友，睹皇公兮问师。","道莫贵兮归真，羡余术兮可夷。","吾乃逝兮南娭，道幽路兮九疑。","越炎火兮万里，过万首兮嶷嶷。","济江海兮蝉蜕，绝北梁兮永辞。","浮云郁兮昼昏，霾土忽兮塺々。","息阳城兮广夏，衰色罔兮中怠。","意晓阳兮燎寤，乃自诊兮在兹。","思尧舜兮袭兴，幸咎繇兮获谋。","悲九州兮靡君，抚轼叹兮作诗。"],"source":"《楚辞》"},{"title":"行宫","author":"元稹","dynasty":"唐","form":"诗","lines":["寥落古行宫，宫花寂寞红。","白头宫女在，闲坐说玄宗。"],"source":"《唐诗三百首》"},{"title":"望金陵行阙","author":"范成大","dynasty":"宋","form":"诗","lines":["圣代规模跨六朝，行宫台殿圧金鼇。","三山落日青鸾近，双阙清风紫凤高。","石虎蹲江蟠王気，玉麟涌地镇神臯。","太平不用千寻锁，静聴西城打夜涛。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["凌朝一片阳台影，飞来太空不去。","栋与参横，帘钩斗曲，西北城高几许。","天声似语。","便阊阖轻排，虹河平溯。","问几阴晴，覇吴平地漫今古。","西山横黛瞰碧，眼明应不到，烟际沈鹭。","卧笛长吟，层霾乍裂，寒月溟蒙千里。","凭虚酔舞。","梦凝白阑干，化为飞雾。","净洗青红，骤飞沧海雨。"],"source":"宋词"},{"title":"诈妮子调风月・落梅风","author":"关汉卿","dynasty":"元","form":"曲","lines":["据着生的年月，演的岁数，不是个义夫节妇，休想得五男并二女，死得教灭门绝户！（夫人云了）（旦跪唱）。"],"source":"元曲"},{"title":"君子偕老","author":"佚名","dynasty":"先秦","form":"诗","lines":["君子偕老，副笄六珈。委委佗佗，如山如河，象服是宜。子之不淑，云如之何？","玼兮玼兮，其之翟也。鬒发如云，不屑髢也。玉之瑱也，象之揥也，扬且之晳也。胡然而天也！胡然而帝也。","瑳兮瑳兮，其之展也。蒙彼绉𫄨，是绁袢也。子之清扬，扬且之颜也。展如之人兮，邦之媛也！"],"source":"《诗经》"},{"title":"株昭","author":"王褒","dynasty":"先秦","form":"辞赋","lines":["悲哉于嗟兮，心内切磋。","款冬而生兮，凋彼叶柯。","瓦砾进宝兮，捐弃随和。","铅刀厉御兮，顿弃太阿。","骥垂两耳兮，中坂蹉跎。","蹇驴服驾兮，无用日多。","修洁处幽兮，贵宠沙劘。","凤皇不翔兮，鹑𫛩飞扬。","乗虹骖蜺兮，载云变化。","焦明开路兮，后属青蛇。","歩骤桂林兮，超骧巻阿。","丘陵翔儛兮，谿谷悲歌。","神章灵篇兮，赴曲相和。","余私娱兹兮，孰哉复加。","还顾世俗兮，坏败罔罗。","巻佩将逝兮，涕流滂沲。","乱曰：皇门开兮照下土，株秽除兮兰芷睹。","四佞放兮后得禹，圣舜摄兮昭尧绪，孰能若兮原为辅。"],"source":"《楚辞》"},{"title":"哥舒歌","author":"西鄙人","dynasty":"唐","form":"诗","lines":["北斗七星高，哥舒夜帯刀。","至今窥牧马，不敢过临洮。"],"source":"《唐诗三百首》"},{"title":"金陵道中","author":"范成大","dynasty":"宋","form":"诗","lines":["山晩黄羊随日下，天寒白犊弄风帰。","愁埃百転西州路，笑忆沙湖一棹飞。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["新烟初试花如梦，疑収楚峰残雨。","茂苑人归，秦楼燕宿，同惜天涯为旅。","游情最苦。","早柔绿迷津，乱莎荒圃。","数树梨花，晩风吹堕半汀鹭。","流红江上去远，翠尊曽共酔，云外别墅。","澹月秋千，幽香巷陌，愁结伤春深处。","听歌看舞。","驻不得当时，柳蛮樱素。","睡起恹恹，洞箫谁院宇。"],"source":"宋词"},{"title":"诈妮子调风月・雁儿落","author":"关汉卿","dynasty":"元","form":"曲","lines":["燕燕那书房中伏侍处，许第二个夫人做。","他须是人身人面皮，人口人言语！。"],"source":"元曲"},{"title":"桑中","author":"佚名","dynasty":"先秦","form":"诗","lines":["爰采唐矣？沬之乡矣。云谁之思？美孟姜矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。","爰采麦矣？沬之北矣。云谁之思？美孟弋矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。","爰采葑矣？沬之东矣。云谁之思？美孟庸矣。期我乎桑中，要我乎上宫，送我乎淇之上矣。"],"source":"《诗经》"},{"title":"逢纷","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["伊伯庸之末胄兮，谅皇直之屈原。","云余肇祖于高阳兮，惟楚怀之婵连。","原生受命于贞节兮，鸿永路有嘉名。","齐名字于天地兮，并光明于列星。","吸精粋而吐氛浊兮，横邪世而不取容。","行叩诚而不阿兮，遂见排而逢谗。","后听虚而黜实兮，不吾理而顺情。","肠愤悁而含怒兮，志迁蹇而左倾。","心戃慌其不我与兮，躬速速其不吾亲。","辞灵修而陨志兮，吟泽畔之江滨。","椒桂罗以颠覆兮，有竭信而归诚。","谗夫蔼蔼而漫着兮，曷其不舒予情？","始结言于庙堂兮，信中涂而叛之。","怀兰蕙与衡芷兮，行中野而散之。","声哀哀而怀高丘兮，心愁愁而思旧邦。","愿承闲而自恃兮，径淫曀而道壅。","颜霉黧以沮败兮，精越裂而衰耄。","裳襜襜而含风兮，衣纳纳而掩露。","赴江湘之湍流兮，顺波凑而下降。","徐徘徊于山阿兮，飘风来之汹汹。","驰余车兮玄石，歩余马兮洞庭。","平明发兮苍梧，夕投宿兮石城。","芙蓉盖而菱华车兮，紫贝阙而玉堂。","薜茘饰而陆离荐兮，鱼鳞衣而白蜺裳。","登逢龙而下陨兮，违故都之漫漫。","思南郢之旧俗兮，肠一夕而九运。","扬流波之潢潢兮，体溶溶而东回。","心怊怅以永思兮，意晻晻而日颓。","白露纷以涂涂兮，秋风浏以萧萧。","身永流而不还兮，魂长逝而常愁。","叹曰：","譬彼流水纷扬磕兮，波逢汹涌𣸣壅滂兮。","揄扬涤荡飘流陨往触崟石兮，龙卬脟圏缭戻宛转阻相薄兮，","遭纷逢凶蹇离尤兮，垂文扬采遗将来兮。"],"source":"《楚辞》"},{"title":"雑诗 十三","author":"无名氏","dynasty":"唐","form":"诗","lines":["近寒食雨草萋萋，着麦苗风柳映堤。","早是有家帰未得，杜鹃休向耳辺啼。"],"source":"《唐诗三百首》"},{"title":"暁行","author":"范成大","dynasty":"宋","form":"诗","lines":["篝灯駅吏唤人行，寥落星河向五更。","马上谁惊千里梦，石头冈下小车声。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["竹深不放斜阳度，横披澹墨林沼。","断莽平烟，残莎剰水，宜得秋深才好。","荒亭旋扫。","正着酒寒轻，弄花春小。","障锦西风，半围歌袖半吟草。","独游清兴易懒，景饶人未胜，乐事长少。","柳下交车，尊前岸帻，同抚云根一笑。","秋香未老。","渐风雨西城，暗敧客帽。","背月移舟，乱鸦渓树晓。"],"source":"宋词"},{"title":"诈妮子调风月・得胜令","author":"关汉卿","dynasty":"元","form":"曲","lines":["到如今总是彻梢虚，燕燕不是石头镌、铁头做；教我死临侵身无措，错支刺心受苦。","（夫人云了）（正旦唱）瘫痪着身躯，教我两下里难停住；气夯破胸脯，教燕燕两下里没是处。"],"source":"元曲"},{"title":"鹑之奔奔","author":"佚名","dynasty":"先秦","form":"诗","lines":["鹑之奔奔，鹊之彊彊。人之无良，我以为兄！","鹊之彊彊，鹑之奔奔。人之无良，我以为君！"],"source":"《诗经》"},{"title":"离世","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["灵怀其不吾知兮，灵怀其不吾闻。","就灵怀之皇祖兮，愬灵怀之鬼神。","灵怀曽不吾与兮，即听夫人之谀辞。","余辞上参于天坠兮，旁引之于四时。","指日月使延照兮，抚招摇以质正。","立师旷俾端辞兮，命咎繇使并听。","兆出名曰正则兮，卦发字曰灵均。","余幼既有此鸿节兮，长愈固而弥纯。","不从俗而诐行兮，直躬指而信志。","不枉绳以追曲兮，屈情素以从事。","端余行其如玉兮，述皇舆之踵迹。","群阿容以晦光兮，皇舆覆以幽辟。","舆中涂以回畔兮，驷马惊而横奔。","执组者不能制兮，必折轭而摧辕。","断镳衔以驰骛兮，暮去次而敢止。","路荡荡其无人兮，遂不御乎千里。","身衡陥而下沉兮，不可获而复登。","不顾身之卑贱兮，惜皇舆之不兴。","出国门而端指兮，冀壱寤而锡还。","哀仆夫之坎毒兮，屡离忧而逢患。","九年之中不吾反兮，思彭咸之水游。","惜师延之浮渚兮，赴汨罗之长流。","遵江曲之逶移兮，触石埼而衡游。","波澧澧而扬浇兮，顺长濑之浊流。","凌黄沱而下低兮，思还流而复反。","玄舆驰而并集兮，身容与而日远。","棹舟杭以横𪵱兮，济湘流而南极。","立江界而长吟兮，愁哀哀而累息。","情慌忽以忘归兮，神浮游以高历。","心蛩蛩而怀顾兮，魂眷眷而独逝。","叹曰：","余思旧邦心依违兮，日暮黄昏羌幽悲兮，","去郢东迁余谁慕兮，谗夫党旅其以兹故兮，","河水淫淫情所愿兮，顾瞻郢路终不返兮。"],"source":"《楚辞》"},{"title":"雑诗三首 三","author":"沈佺期","dynasty":"唐","form":"诗","lines":["闻道黄竜戍，频年不解兵。","可怜闺里月，长在汉家営。","少妇今春意，良人昨夜情。","谁能将旗鼓，一为取竜城。"],"source":"《唐诗三百首》"},{"title":"秦淮","author":"范成大","dynasty":"宋","form":"诗","lines":["不将行李试间関，谁信江湖道路难。","肠断秦淮三百曲，船头终日见方山。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["曲尘犹沁伤心水，歌蝉暗惊春换。","露藻清啼，烟萝澹碧，先结湖山秋怨。","波帘翠巻。","叹霞薄轻绡，泛人重见。","傍柳追凉，暂疏怀袖负纨扇。","南花清斗素靥，画船应不载，坡静诗巻。","泛酒芳筒，题名蠹壁，重集湘鸿江燕。","平芜未翦。","怕一夕西风，镜心红变。","望极愁生，暮天菱唱远。"],"source":"宋词"},{"title":"诈妮子调风月・阿古令","author":"关汉卿","dynasty":"元","form":"曲","lines":["满盏内盈盈绿醑，子合当作婢为奴。","谢相公、夫人擡举，怎敢做三妻两妇？子得和丈夫一处对舞，便是燕燕花生满路。"],"source":"元曲"},{"title":"定之方中","author":"佚名","dynasty":"先秦","form":"诗","lines":["定之方中，作于楚宫。揆之以日，作于楚室。树之榛栗，椅桐梓漆，爰伐琴桑。","升彼虚矣，以望楚矣。望楚与堂，景山与京。降观于桑，卜云其吉，终然允臧。","灵雨既零，命彼倌人，星言夙驾，说于桑田。匪直也人，秉心塞渊，騋牝三千。"],"source":"《诗经》"},{"title":"怨思","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["惟郁郁之忧毒兮，志坎𡒄而不违。","身憔悴而考旦兮，日黄昏而长悲。","闵空宇之孤子兮，哀枯杨之冤雏。","孤雌吟于高墉兮，鸣鸠栖于桑楡。","玄蝯失于潜林兮，独偏弃而远放。","征夫劳于周行兮，处妇愤而长望。","申诚信而罔违兮，情素洁于纽帛。","光明齐于日月兮，文采耀燿于玉石。","伤压次而不发兮，思沉抑而不扬。","芳懿懿而终败兮，名靡散而不彰。","背玉门以奔骛兮，蹇离尤而干诟。","若龙逢之沉首兮，王子比干之逢醢。","念社稷之几危兮，反为雠而见怨。","思国家之离沮兮，躬获愆而结难。","若青蝇之伪质兮，晋骊姬之反情。","恐登阶之逢殆兮，故退伏于末庭。","孽臣之号咷兮，本朝芜而不治。","犯颜色而触谏兮，反蒙辜而被疑。","菀蘼芜与菌若兮，渐藁本于洿渎。","淹芳芷于腐井兮，弃鸡骇于筐簏。","执棠谿以刜蓬兮，秉干将以割肉。","筐泽泻以豹鞟兮，破荆和以继筑。","时溷浊犹未清兮，世殽乱犹未察。","欲容与以俟时兮，惧年岁之既晏。","顾屈节以从流兮，心巩巩而不夷。","宁浮沅而驰骋兮，下江湘以邅回。","叹曰：","山中槛槛余伤怀兮，征夫皇皇其孰依兮，","经营原野杳冥冥兮，乗骐骋骥舒吾情兮，","归骸旧邦莫谁语兮，长辞远逝乗湘去兮。"],"source":"《楚辞》"},{"title":"古意呈补阙乔知之","author":"沈佺期","dynasty":"唐","form":"诗","lines":["卢家少妇郁金堂，海燕双栖玳瑁梁。","九月寒砧催木叶，十年征戍忆辽阳。","白狼河北音书断，丹凤城南秋夜长。","谁谓含愁独不见，更教明月照流黄。"],"source":"《唐诗三百首》"},{"title":"重九独登赏心亭","author":"范成大","dynasty":"宋","form":"诗","lines":["谁教佳节滞天涯，强展愁眉管物华。","毎歳有诗题白鴈，今年无酒対黄花。","悠悠造化占斜日，草草登临记落霞。","宇宙此身元是客，不须弾铗更思家。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["烟波桃叶西陵路，十年断魂潮尾。","古柳重攀，轻鸥聚别，陈迹危亭独倚。","凉飔乍起。","渺烟碛飞帆，暮山横翠。","但有江花，共临秋镜照憔悴。","华堂烛暗送客，眼波回盼处，芳艳流水。","素骨凝冰，柔葱蘸雪，犹忆分瓜深意。","清尊未洗。","梦不湿行云，漫沾残泪。","可惜秋宵，乱蛩疏雨里。"],"source":"宋词"},{"title":"正宫・白鹤子（四首）","author":"关汉卿","dynasty":"元","form":"曲","lines":["四时春富贵，万物酒风流。","澄澄水如蓝，灼灼花如绣。","（之一）花边停骏马，柳外缆轻舟。","湖内画船交，湖上骅骝骤。","（之二）鸟啼花影里，人立粉墙头。","春意两丝牵，秋水双波溜。","（之三）香焚金鸭鼎，闲傍小红楼。","月在柳梢头，人约黄昏后。","（之四）。"],"source":"元曲"},{"title":"蝃𬟽","author":"佚名","dynasty":"先秦","form":"诗","lines":["蝃𬟽在东，莫之敢指。女子有行，远父母兄弟。","朝𬯀于西，崇朝其雨。女子有行，远兄弟父母。","乃如之人也，怀婚姻也。大无信也，不知命也！"],"source":"《诗经》"},{"title":"远逝","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["志隐隐而郁怫兮，愁独哀而冤结。","肠纷纭以缭转兮，涕渐渐其若屑。","情慨慨而长怀兮，信上皇而质正。","合五岳与八灵兮，讯九鬿与六神。","指列宿以白情兮，诉五帝以置辞。","北斗为我折中兮，太一为余听之。","云服阴阳之正道兮，御后土之中和。","佩苍龙之蚴虬兮，带隐虹之逶蛇。","曳彗星之皓旰兮，抚朱爵与鵔鸃。","游清灵之飒戻兮，服云衣之披披。","杖玉策与朱旗兮，垂明月之玄珠。","举霓旌之墆翳兮，建黄𫄸之总旄。","躬纯粋而罔愆兮，承皇考之妙仪。","惜往事之不合兮，横汨罗而下沥。","乗隆波而南渡兮，逐江湘之顺流。","赴阳侯之潢洋兮，下石濑而登洲。","陆魁堆以蔽视兮，云冥冥而暗前。","山峻高以无垠兮，遂曽闳而迫身。","雪雰雰而薄木兮，云霏霏而陨集。","阜隘狭而幽险兮，石㟥嵯以翳日。","悲故乡而发忿兮，去余邦之弥久。","背龙门而入河兮，登大坟而望夏首。","横舟航而济湘兮，耳聊啾而戃慌。","波淫淫而周流兮，鸿溶溢而滔荡。","路曼曼其无端兮，周容容而无识。","引日月以指极兮，少须臾而释思。","水波远以冥冥兮，眇不睹其东西。","顺风波以南北兮，雾宵晦以纷纷。","日杳杳以西颓兮，路长远而窘迫。","欲酌醴以娱忧兮，蹇骚骚而不释。","叹曰：","飘风蓬龙埃坲々兮，草木摇落时槁悴兮，","遭倾遇祸不可救兮，长吟永欷涕究究兮，","舒情陈诗冀以自免兮，颓流下陨身日远兮。"],"source":"《楚辞》"},{"title":"次北固山下","author":"王湾","dynasty":"唐","form":"诗","lines":["客路青山外，行舟绿水前。","潮平両岸阔，风正一帆悬。","海日生残夜，江春入旧年。","郷书何処达，帰雁洛阳辺。"],"source":"《唐诗三百首》"},{"title":"赏心亭再题","author":"范成大","dynasty":"宋","form":"诗","lines":["天険东南重，兵雄百二尊。","払云千雉绕，截水万崖奔。","赤日呉波动，苍烟楚树昏。","向无形胜地，何以控乾坤。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["玉皇重赐瑶池宴，琼筵第二十四。","万象澄秋，群裾曳玉，清澈冰壶人世。","鳌峰对起。","许分得钧天，凤丝龙吹。","翠羽飞来，舞鸾曽赋曼桃字。","鹤胎曽梦电绕，桂根看骤长，玉干金蕊。","少海波新，芳茅露滴，凉入堂阶彩戏。","香霖乍洗。","拥莲媛三千，羽裳风佩。","圣姥朝元，炼颜银汉水。"],"source":"宋词"},{"title":"南吕・四块玉别情","author":"关汉卿","dynasty":"元","form":"曲","lines":["自送别，心难舎，一点相思几时绝？凭阑袖払杨花雪。","渓又斜，山又遮，人去也！。"],"source":"元曲"},{"title":"相鼠","author":"佚名","dynasty":"先秦","form":"诗","lines":["相鼠有皮，人而无仪！人而无仪，不死何为？","相鼠有齿，人而无止！人而无止，不死何俟？","相鼠有体，人而无礼，人而无礼！胡不遄死？"],"source":"《诗经》"},{"title":"惜贤","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["览屈氏之离骚兮，心哀哀而怫郁。","声嗷嗷以寂寥兮，顾仆夫之憔悴。","拨谄谀而匡邪兮，切淟涊之流俗。","荡渨涹之奸咎兮，夷蠢蠢之溷浊。","怀芬香而挟蕙兮，佩江蓠之婓婓。","握申椒与杜若兮，冠浮云之峨峨。","登长陵而四望兮，览芷圃之蠡蠡。","游兰皐与蕙林兮，睨玉石之㟥嵯。","扬精华以炫燿兮，芳郁渥而纯美。","结桂树之旖旎兮，纫荃蕙与辛夷。","芳若兹而不御兮，捐林薄而菀死。","驱子侨之奔走兮，申徒狄之赴渊。","若由夷之纯美兮，介子推之隐山。","晋申生之离殃兮，荆和氏之泣血。","吴申胥之抉眼兮，王子比干之横废。","欲卑身而下体兮，心隐恻而不置。","方圜殊而不合兮，钩绳用而异态。","欲俟时于须臾兮，日阴曀其将暮。","时迟迟其日进兮，年忽忽而日度。","妄周容而入世兮，内距闭而不开。","俟时风之清激兮，愈氛雾其如塺。","进雄鸠之耿耿兮，谗介介而蔽之。","黙顺风以偃仰兮，尚由由而进之。","心懭悢以冤结兮，情舛错以曼忧。","搴薜茘于山野兮，采撚支于中洲。","望高丘而叹涕兮，悲吸吸而长怀。","孰契契而委栋兮，日晻晻而下颓。","叹曰：","江湘油油长流汩兮，挑揄扬汰荡迅疾兮。","忧心展转愁怫郁兮，冤结未舒长隐忿兮，","丁时逢殃可奈何兮，劳心悁悁涕滂沱兮。"],"source":"《楚辞》"},{"title":"桃花谿","author":"张旭","dynasty":"唐","form":"诗","lines":["隠隠飞桥隔野烟，石矶西畔问渔船。","桃花尽日随流水，洞在清谿何処辺。"],"source":"《唐诗三百首》"},{"title":"宿义林院","author":"范成大","dynasty":"宋","form":"诗","lines":["暝気昏如雨，禅房冷似冰。","竹间东岭月，松杪上方灯。","惊鹘盘金刹，流蛍払玉縄。","明朝穷脚力，连夜斩崖藤。"],"source":"宋诗"},{"title":"齐天乐","author":"吴文英","dynasty":"宋","form":"词","lines":["馀香才润鸾绡汗，秋风夜来先起。","雾锁林深，蓝浮野阔，一笛渔蓑鸥外。","红尘万里。","就中决银河，冷涵空翠。","岸觜沙平，水杨阴下晩初舣。","桃渓人住最久，浪吟谁得到，兰蕙疏绮。","砚色寒云，签声乱叶，蕲竹纱纹如水。","笙歌酔里。","歩明月丁东，静传环佩。","更展芳塘，种花招燕子。"],"source":"宋词"},{"title":"南吕・四块玉闲适（四首）","author":"关汉卿","dynasty":"元","form":"曲","lines":["适意行，安心坐，渇时饮饥时餐酔时歌，困来时就向莎茵卧。","日月长，天地阔，闲快活！（之一）旧酒投，新醅泼，老瓦盆边笑呵呵，共山僧野叟闲吟和。","他出一对鸡，我出一个鹅，闲快活！（之二）意马多，心猿锁，跳出红尘恶风波，槐阴午梦谁惊破？离了利名场，钻入安乐窝，闲快活！（之三）南亩耕，东山卧，世态人情经历多，闲将往事思量过。","贤的是他，愚的是我，争甚幺！（之四）。"],"source":"元曲"},{"title":"干旄","author":"佚名","dynasty":"先秦","form":"诗","lines":["孑孑干旄，在浚之郊。素丝纰之，良马四之。彼姝者子，何以畀之？","孑孑干旟，在浚之都。素丝组之，良马五之。彼姝者子，何以予之？","孑孑干旌，在浚之城。素丝祝之，良马六之。彼姝者子，何以告之？"],"source":"《诗经》"},{"title":"忧苦","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["悲余心之悁悁兮，哀故邦之逢殃。","辞九年而不复兮，独茕茕而南行。","思余俗之流风兮，心纷错而不受。","遵野莽以呼风兮，歩从容于山廋。","巡陆夷之曲衍兮，幽空虚以寂寞。","倚石岩以流涕兮，忧憔悴而无乐。","登巑岏以长企兮，望南郢而闚之。","山修远其辽辽兮，涂漫漫其无时。","听玄鹤之晨鸣兮，于高冈之峨峨。","独愤积而哀娱兮，翔江洲而安歌。","三鸟飞以自南兮，览其志而欲北。","原寄言于三鸟兮，去飘疾而不可得。","欲迁志而改操兮，心纷结其未离。","外彷徨而游览兮，内恻隐而含哀。","聊须臾以时忘兮，心渐渐其烦错。","原仮簧以舒忧兮，志纡郁其难释。","叹《离骚》以扬意兮，犹未殚于《九章》。","长嘘吸以于悒兮，涕横集而成行。","伤明珠之赴泥兮，鱼眼玑之坚蔵。","同驽骡与乗驵兮，杂斑駮与阘茸。","葛藟蔂于桂树兮，鸱鸮集于木兰。","偓促谈于廊庙兮，律魁放乎山间。","恶虞氏之箫《韶》兮，好遗风之《激楚》。","潜周鼎于江淮兮，爨土鬵于中宇。","且人心之持旧兮，而不可保长。","邅彼南道兮，征夫宵行。","思念郢路兮，还顾睠睠。","涕流交集兮，泣下涟涟。","叹曰：","登山长望中心悲兮，菀彼青青泣如颓兮，","留思北顾涕渐渐兮，折锐摧矜凝泛滥兮，","念我茕茕魂谁求兮，仆夫慌悴散若流兮。"],"source":"《楚辞》"},{"title":"送别","author":"王维","dynasty":"唐","form":"诗","lines":["下马饮君酒，问君何所之。","君言不得意，帰卧南山陲。","但去莫复问，白云无尽时。"],"source":"《唐诗三百首》"},{"title":"荆公墓二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["百歳谁人巧拙，一丘底処亏成。","半世青苗法意，当年雪竹诗情。"],"source":"宋诗"},{"title":"丹凤吟","author":"吴文英","dynasty":"宋","form":"词","lines":["丽景长安人海，避影繁华，结庐深寂。","灯窗雪户，光映夜寒东壁。","心凋鬓改，镂冰刻水，缥简离离，风签索索。","怕遣花虫蠹粉，自采秋芸熏架，香泛纤碧。","更上新梯窈窕，暮山澹着城外色。","旧雨江湖远，问桐阴门巷，燕曽相识。","吟壶天小，不觉翠蓬云隔。","桂斧月宫三万手，计元和通籍。","软红满路，谁聘幽素客。"],"source":"宋词"},{"title":"中吕・朝天子书所见","author":"关汉卿","dynasty":"元","form":"曲","lines":["鬓鸦，脸霞，屈杀将陪嫁。","规模全是大人家，不在红娘下。","笑眼偷瞧，文谈回话，真如解语花。","若咱得他，倒了葡萄架。"],"source":"元曲"},{"title":"载驰","author":"佚名","dynasty":"先秦","form":"诗","lines":["载驰载驱，归唁卫侯。驱马悠悠，言至于漕。大夫跋渉，我心则忧。","既不我嘉，不能旋反。视尔不臧，我思不远。","既不我嘉，不能旋济？视尔不臧，我思不閟。","陟彼阿丘，言采其蝱。女子善怀，亦各有行。许人尤之，众稚且狂。","我行其野，芃芃其麦。控于大邦，谁因谁极？大夫君子，无我有尤。百尔所思，不如我所之。"],"source":"《诗经》"},{"title":"愍命","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["昔皇考之嘉志兮，喜登能而亮贤。","情纯洁而罔薉兮，姿盛质而无愆。","放佞人与谄谀兮，斥谗夫与便嬖。","亲忠正之悃诚兮，招贞良与明智。","心溶溶其不可量兮，情澹澹其若渊。","回邪辟而不能入兮，诚原蔵而不可迁。","逐下袟于后堂兮，迎虙妃于伊雒。","刜谗贼于中廇兮，选吕管于榛薄。","丛林之下无怨士兮，江河之畔无隐夫。","三苗之徒以放逐兮，伊皐之伦以充庐。","今反表以为里兮，颠裳以为衣。","戚宋万于两楹兮，废周邵于遐夷。","却骐骥以转运兮，腾驴骡以驰逐。","蔡女黜而出帷兮，戎妇入而彩绣服。","庆忌囚于阱室兮，陈不占战而赴围。","破伯牙之号钟兮，挟人筝而弹纬。","蔵瑉石于金匮兮，捐赤瑾于中庭。","韩信蒙于介胄兮，行夫将而攻城。","莞芎弃于泽洲兮，瓟瓥蠹于筐簏。","麒麟奔于九皐兮，熊罴群而逸囿。","折芳枝与琼华兮，树枳棘与薪柴。","掘荃蕙与射干兮，耘藜藿与蘘荷。","惜今世其何殊兮，远近思而不同。","或沉沦其无所达兮，或清激其无所通。","哀余生之不当兮，独蒙毒而逢尤。","虽謇謇以申志兮，君乖差而屏之。","诚惜芳之菲菲兮，反以兹为腐也。","怀椒聊之蔎蔎兮，乃逢纷以罹诟也。","叹曰：","嘉皇既殁终不返兮，山中幽险郢路远兮。","谗人𬣡𬣡孰可愬兮，征夫罔极谁可语兮。","行吟累欷声喟喟兮，怀忧含戚何侘傺兮。"],"source":"《楚辞》"},{"title":"送綦毋潜落第还郷","author":"王维","dynasty":"唐","form":"诗","lines":["圣代无隠者，英霊尽来帰。","遂令东山客，不得顾采薇。","既至君门远，孰云吾道非。","江淮度寒食，京洛缝春衣。","置酒临长道，同心与我违。","行当浮桂櫂，未几払荆扉。","远树帯行客，孤村当落晖。","吾谋适不用，勿谓知音稀。"],"source":"《唐诗三百首》"},{"title":"荆公墓二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["本意治功徙木，何心党祸扬尘。","报雠岂教行劫，作俑翻成害仁。"],"source":"宋诗"},{"title":"扫花游・扫地游","author":"吴文英","dynasty":"宋","form":"词","lines":["冷空澹碧，带翳柳轻云，护花深雾。","艳晨易午。","正笙箫竞渡，绮罗争路。","骤巻风埃，半掩长蛾翠妩。","散红缕。","渐红湿杏泥，愁燕无语。","乗盖争避处。","就解佩旗亭，故人相遇。","恨春太妒。","溅行裙更惜，凤钩尘汚。","酹入梅根，万点啼痕暗树。","峭寒暮。","更萧萧、陇头人去。"],"source":"宋词"},{"title":"商调・梧叶儿别情","author":"关汉卿","dynasty":"元","form":"曲","lines":["别离易，相见难，何处锁雕鞍？春将去，人未还。","这其间，殃及杀愁眉泪眼。"],"source":"元曲"},{"title":"淇奥","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻彼淇奥，绿竹猗猗。有匪君子，如切如磋，如琢如磨，瑟兮僴兮，赫兮咺兮。有匪君子，终不可谖兮。","瞻彼淇奥，绿竹青青。有匪君子，充耳秀莹，会弁如星。瑟兮僴兮。赫兮咺兮，有匪君子，终不可谖兮。","瞻彼淇奥，绿竹如箦。有匪君子，如金如锡，如圭如璧。宽兮绰兮，猗重较兮。善戏谑兮，不为虐兮。"],"source":"《诗经》"},{"title":"思古","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["冥冥深林兮，树木郁郁。","山参差以崭岩兮，阜杳杳以蔽日。","悲余心之悁悁兮，目眇眇而遗泣。","风骚屑以摇木兮，云吸吸以湫戻。","悲余生之无欢兮，愁倥偬于山陆。","旦徘徊于长阪兮，夕彷徨而独宿。","发披披以鬤鬤兮，躬劬劳而瘏悴。","魂俇俇而南行兮，泣沾襟而濡袂。","心婵媛而无告兮，口噤闭而不言。","违郢都之旧闾兮，回湘、沅而远迁。","念余邦之横陥兮，宗鬼神之无次。","闵先嗣之中绝兮，心惶惑而自悲。","聊浮游于山陿兮，歩周流于江畔。","临深水而长啸兮，且倘佯而泛观。","兴离骚之微文兮，冀灵修之壱悟。","还余车于南郢兮，复往轨于初古。","道修远其难迁兮，伤余心之不能已。","背三五之典刑兮，绝洪范之辟纪。","播规矩以背度兮，错权衡而任意。","操绳墨而放弃兮，倾容幸而侍侧。","甘棠枯于丰草兮，藜棘树于中庭。","西施斥于北宫兮，仳倠倚于弥楹。","乌获戚而骖乗兮，燕公操于马圉。","蒯聩登于清府兮，咎繇弃而在野。","盖见兹以永叹兮，欲登阶而狐疑。","乗白水而高骛兮，因徙弛而长词。","叹曰：","倘佯垆阪沼水深兮，容与汉渚涕淫淫兮，锺牙已死谁为声兮？","纤阿不御焉舒情兮，曽哀凄欷心离离兮，还顾高丘泣如洒兮。"],"source":"《楚辞》"},{"title":"青谿","author":"王维","dynasty":"唐","form":"诗","lines":["言入黄花川，毎逐青谿水。","随山将万転，趣途无百里。","声喧乱石中，色静深松里。","漾漾泛菱荇，澄澄映葭苇。","我心素已闲，清川澹如此。","请留盘石上，垂钓将已矣。"],"source":"《唐诗三百首》"},{"title":"十月朔客建业不得与兄弟上冢之列悲感成诗","author":"范成大","dynasty":"宋","form":"诗","lines":["歳已看成暮，身今未得帰。","风尘孤涙尽，霜露寸心违。","南磵新流水，西山旧落晖。","烟松応好在，宿草定成非。","逝水方东去，浮云浪北飞。","危魂先自断，不待更沾衣。"],"source":"宋诗"},{"title":"扫花游・扫地游","author":"吴文英","dynasty":"宋","form":"词","lines":["水云共色，渐断岸飞花，雨声初峭。","歩帷素袅。","想玉人误惜，章台春老。","岫敛愁蛾，半洗铅华未晓。","舣轻棹。","似山阴夜晴，乗兴初到。","心事春缥缈。","记遍地梨花，弄月斜照。","旧时斗草。","恨凌波路钥，小庭深窈。","冻涩琼箫，渐入东风郢调。","暖回早。","酔西园、乱红休扫。"],"source":"宋词"},{"title":"双调・大徳歌（四首）春","author":"关汉卿","dynasty":"元","form":"曲","lines":["子规啼，不如归，道是春归人未归。","几日添憔悴，虚飘飘柳絮飞。","一春鱼雁无消息，则见双燕斗衔泥。","夏俏冤家，在天涯，偏那里绿杨堪系马？困坐南窗下，数对清风想念他。","蛾眉淡了教谁画？痩岩岩羞带石榴花。","秋风飘飘，雨潇潇，便做陈抟睡不着。","懊恼伤怀抱，扑簌簌泪点抛。","秋蝉儿噪罢寒蛩儿叫，淅零零细雨打芭蕉。","冬雪纷纷，掩重门，不由人不断魂，痩损江梅韵。","那里是清江江上村？香闺里冷落谁瞅问？好一个憔悴的凭阑人！。"],"source":"元曲"},{"title":"考槃","author":"佚名","dynasty":"先秦","form":"诗","lines":["考槃在涧，硕人之宽。独寐寤言，永矢弗谖。","考槃在阿，硕人之薖。独寐寤歌，永矢弗过。","考槃在六，硕人之轴。独寐寤宿，永矢弗告。"],"source":"《诗经》"},{"title":"远游","author":"刘向","dynasty":"先秦","form":"辞赋","lines":["悲余性之不可改兮，屡惩艾而不迻。","服觉皓以殊俗兮，貌掲掲以巍巍。","譬若王侨之乗云兮，载赤霄而凌太清。","欲与天地参寿兮，与日月而比荣。","登昆仑而北首兮，悉灵圉而来谒。","选鬼神于太阴兮，登阊阖于玄阙。","回朕车俾西引兮，褰虹旗于玉门。","驰六龙于三危兮，朝西灵于九滨。","结余轸于西山兮，横飞谷以南征。","绝都广以直指兮，历祝融于朱冥。","枉玉衡于炎火兮，委两馆于咸唐。","贯澒蒙以东朅兮，维六龙于扶桑。","周流览于四海兮，志升降以高驰。","徴九神于回极兮，建虹采以招指。","驾鸾凤以上游兮，从玄鹤与鹪明。","孔鸟飞而送迎兮，腾群鹤于瑶光。","排帝宫与罗囿兮，升县圃以眩灭。","结琼枝以杂佩兮，立长庚以继日。","凌惊雷以轶骇电兮，缀鬼谷于北辰。","鞭风伯使先驱兮，囚灵玄于虞渊。","溯高风以低佪兮，览周流于朔方。","就颛顼而敶辞兮，考玄冥于空桑。","旋车逝于崇山兮，奏虞舜于苍梧。","济杨舟于会稽兮，就申胥于五湖。","见南郢之流风兮，殒余躬于沅湘。","望旧邦之黯黮兮，时溷浊其犹未央。","怀兰茝之芬芳兮，妒被离而折之。","张绛帷以襜襜兮，风邑邑而蔽之。","日暾暾其西舎兮，阳焱焱而复顾。","聊仮日以须臾兮，何骚骚而自故。","叹曰：","譬彼蛟龙乗云浮兮，泛淫澒溶纷若雾兮。","潺湲𫐖轕雷动电发馺高举兮。","升虚凌冥沛浊浮清入帝宫兮，摇翘奋羽驰风骋雨游无穷兮。"],"source":"《楚辞》"},{"title":"渭川田家","author":"王维","dynasty":"唐","form":"诗","lines":["斜阳照墟落，穷巷牛羊帰。","野老念牧童，倚杖候荆扉。","雉雊麦苗秀，蚕眠桑叶稀。","田夫荷锄至，相见语依依。","即此羡闲逸，怅然吟式微。"],"source":"《唐诗三百首》"},{"title":"白鹭亭","author":"范成大","dynasty":"宋","form":"诗","lines":["倦游客舎不胜闲，日日清江见倚阑。","少待西风吹雨过，更従二水看淮山。"],"source":"宋诗"},{"title":"扫花游・扫地游","author":"吴文英","dynasty":"宋","form":"词","lines":["草生梦碧，正燕子帘帏，影迟春午。","倦茶荐乳。","看风签乱叶，老沙昏雨。","古简蟫篇，种得云根疗蠹。","最清楚。","带明月自锄，花外幽圃。","醒眼看酔舞。","到应事无心，与闲同趣。","小山有语。","恨逋仙占却，暗香吟赋。","暖通书床，带草春摇翠露。","未归去。","正长安、软红如雾。"],"source":"宋词"},{"title":"双调・大徳歌（六首）","author":"关汉卿","dynasty":"元","form":"曲","lines":["粉墙低，景凄凄，正是那西厢月上时。","会得琴中意，我是个香闺里钟子期。","好教人暗想张君瑞，敢则是爱月夜眠迟。","（之一）绿杨堤，画船儿，正撞着一帆风赶上水。","冯魁吃的醺醺酔，怎想着金山寺壁上诗。","醒来不见多姝丽，冷清清空载月明归。","（之二）郑元和，受寂寞，道是你无钱怎奈何？哥哥家缘破，谁着你摇铜铃唱换歌。","因打亚仙门前过，恰便是司马泪痕多。","（之三）谢家村，赏芳春，疑怪他桃花冷笑人。","着谁传芳信，强题诗也断魂。","花阴下等待无人问，则听得黄犬吠柴门。","（之四）雪粉华，舞梨花，再不见烟村四五家。","密洒堪图画，看疏林噪晩鸦。","黄芦掩映清江下，斜缆着钓鱼航模。","（之五）吹一个，弹一个，唱新行大徳歌。","快活休张罗，想人生能几何？十分淡薄随缘过，得磨陀处且磨陀。","（之六）套数。"],"source":"元曲"},{"title":"硕人","author":"佚名","dynasty":"先秦","form":"诗","lines":["硕人其颀，衣锦褧衣。齐侯之子，卫侯之妻。东宫之妹，邢侯之姨，谭公维私。","手如柔荑，肤如凝脂，领如蝤蛴，齿如瓠犀，螓首蛾眉，巧笑倩兮，美目盼兮。","硕人敖敖，说于农郊。四牡有骄，朱𪩸镳镳。翟茀以朝。大夫夙退，无使君劳。","河水洋洋，北流活活。施罛濊濊，鳣鲔发发。葭菼掲掲，庶姜孽孽，庶士有朅。"],"source":"《诗经》"},{"title":"逢尤","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["悲兮愁，哀兮忧！","天生我兮当暗时，被诼谮兮虚获尤。","心烦愦兮意无聊，严载驾兮出戏游。","周八极兮历九州，求轩辕兮索重华。","世既卓兮远眇眇，握佩玖兮中路躇。","羡咎繇兮建典谟，懿风后兮受瑞图。","愍余命兮遭六极，委玉质兮于泥涂。","遽傽遑兮驱林泽，歩屏营兮行丘阿。","车𫐄折兮马虺颓，惷怅立兮涕滂沱。","思丁文兮圣明哲，哀平差兮迷谬愚。","吕傅举兮殷周兴，忌嚭专兮郢吴虚。","仰长叹兮气噎结，悒殟绝兮咶复苏。","虎兕争兮于廷中，豺狼斗兮我之隅。","云雾会兮日冥晦，飘风起兮扬尘埃。","走鬯罔兮乍东西，欲窜伏兮其焉如？","念灵闺兮隩重深，原竭节兮隔无由。","望旧邦兮路逶随，忧心悄兮志勤劬。","魂茕茕兮不遑寐，目眽眽兮寤终朝。"],"source":"《楚辞》"},{"title":"西施咏","author":"王维","dynasty":"唐","form":"诗","lines":["艳色天下重，西施宁久微。","朝仍越渓女，暮作呉宫妃。","贱日岂殊众，贵来方悟稀。","邀人傅香粉，不自着罗衣。","君宠益娇态，君怜无是非。","当时浣纱伴，莫得同车帰。","持谢邻家子，効颦安可希。"],"source":"《唐诗三百首》"},{"title":"臙脂井三首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["昭光殿下起楼台，拚得山河付酒杯。","春色已従金井去，月华空上石头来。"],"source":"宋诗"},{"title":"扫花游・扫地游","author":"吴文英","dynasty":"宋","form":"词","lines":["水园沁碧，骤夜雨飘红，竟空林岛。","艳春过了。","有尘香坠钿，尚遗芳草。","歩绕新阴，渐觉交枝径小。","酔深窈。","爱绿叶翠圆，胜看花好。","芳架雪未扫。","怪翠被佳人，困迷清晓。","柳丝系棹。","问阊门自古，送春多少。","倦蝶慵飞，故扑簪花破帽。","酹残照。","掩重城、暮钟不到。"],"source":"宋词"},{"title":"黄钟・侍香金童","author":"关汉卿","dynasty":"元","form":"曲","lines":["春闺院宇，柳絮飘香雪。","帘幕轻寒雨乍歇，东风落花迷粉蝶。","芍药初开，海棠才谢。"],"source":"元曲"},{"title":"氓","author":"佚名","dynasty":"先秦","form":"诗","lines":["氓之蚩蚩，抱布贸丝。匪来贸丝，来即我谋。送子渉淇，至于顿丘。匪我愆期，子无良媒。将子无怒，秋以为期。","乗彼垝垣，以望复关。不见复关，泣涕涟涟。既见复关，载笑载言。尔卜尔筮，体无咎言。以尔车来，以我贿迁。","桑之未落，其叶沃若。于嗟鸠兮！无食桑葚。于嗟女兮！无与士耽。士之耽兮，犹可说也。女之耽兮，不可说也。","桑之落矣，其黄而陨。自我徂尔，三岁食贫。淇水汤汤，渐车帷裳。女也不爽，士二其行。士也罔极，二三其徳。","三岁为妇，靡室劳矣。夙兴夜寐，靡有朝矣。言既遂矣，至于暴矣。兄弟不知，咥其笑矣。静言思之，躬自悼矣。","及尔偕老，老使我怨。淇则有岸，隰则有泮。总角之宴，言笑晏晏，信誓旦旦，不思其反。反是不思，亦已焉哉！"],"source":"《诗经》"},{"title":"怨上","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["令尹兮謷謷，群司兮𫍦𫍦。","哀哉兮淈淈，上下兮同流。","菽藟兮蔓衍，芳虈兮挫枯。","朱紫兮杂乱，曽莫兮别诸。","倚此兮岩穴，永思兮窈悠。","嗟怀兮眩惑，用志兮不昭。","将丧兮玉斗，遗失兮钮枢。","我心兮煎熬，惟是兮用忧。","进恶兮九旬，复顾兮彭务。","拟斯兮二踪，未知兮所投。","谣吟兮中野，上察兮璇玑。","大火兮西睨，摄提兮运低。","雷霆兮硠磕，雹霰兮霏霏。","奔电兮光晃，凉风兮怆凄。","鸟兽兮惊骇，相从兮宿栖。","鸳鸯兮噰噰，狐狸兮徾徾。","哀吾兮介特，独处兮罔依。","蝼蛄兮鸣东，蟊蠽兮号西。","蛓缘兮我裳，蠋入兮我怀。","虫豸兮夹余，惆怅兮自悲。","伫立兮忉怛，心结𦈔兮折摧。"],"source":"《楚辞》"},{"title":"老将行","author":"王维","dynasty":"唐","form":"诗","lines":["少年十五二十时，歩行夺得胡马射。","射杀中山白额虎，肯数邺下黄须児。","一身転戦三千里，一劒曽当百万师。","汉兵奋迅如霹雳，虏骑崩腾畏蒺藜。","卫青不败由天幸，李広无功縁数奇。","自従弃置便衰朽，世事磋跎成白首。","昔时飞箭无全目，今日垂杨生左肘。","路傍时売故侯瓜，门前学种先生柳。","苍茫古木连穷巷，寥落寒山対虚牖。","誓令疏勒出飞泉，不似颍川空使酒。","贺兰山下阵如云，羽檄交驰日夕闻。","节使三河募年少，诏书五道出将军。","试払鉄衣如雪色，聊持宝劒动星文。","愿得燕弓射天将，耻令越甲鸣呉军。","莫嫌旧日云中守，犹堪一戦取功勲。"],"source":"《唐诗三百首》"},{"title":"臙脂井三首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["午酔醒来一梦非，匆匆玉树逐春帰。","臙脂却作千年计，不似愁魂四散飞。"],"source":"宋诗"},{"title":"扫花游・扫地游","author":"吴文英","dynasty":"宋","form":"词","lines":["暖波印日，倒秀影秦山，晓鬟梳洗。","歩帷艳绮。","正梁园未雪，海棠犹睡。","藉绿盛红，怕委天香到地。","画船系。","舞西湖暗黄，虹卧新霁。","天梦春枕被。","和凤筑东风，宴歌曲水。","海宫对起。","灿骊光乍湿，杏梁云气。","夜色瑶台，禁蜡初传翡翠。","唤春酔。","问人间、几番桃李。"],"source":"宋词"},{"title":"幺・柔肠脉脉，新愁千万叠。偶记年前人乍别，秦台玉萧声断绝。雁底关","author":"关汉卿","dynasty":"元","form":"曲","lines":["河，马头明月。"],"source":"元曲"},{"title":"竹竿","author":"佚名","dynasty":"先秦","form":"诗","lines":["籊籊竹竿，以钓于淇。岂不尔思？远莫致之。","泉源在左，淇水在右。女子有行，远兄弟父母。","淇水在右，泉源在左。巧笑之瑳，佩玉之傩。","淇水滺滺，桧楫松舟。驾言出游，以写我忧。"],"source":"《诗经》"},{"title":"疾世","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["周徘徊兮汉渚，求水神兮灵女。","嗟此国兮无良，媒女诎兮謰𫍴。","𫛩雀列兮哗讙，鸲鹆鸣兮聒余。","抱昭华兮宝璋，欲衒鬻兮莫取。","言旋迈兮北徂，叫我友兮配耦。","日阴曀兮未光，阒睄窕兮靡睹。","纷载驱兮高驰，将谘询兮皇羲。","遵河皐兮周流，路变易兮时乖。","𪵱沧海兮东游，沐盥浴兮天池。","访太昊兮道要，云靡贵兮仁义。","志欣乐兮反征，就周文兮邠歧。","秉玉英兮结誓，日欲暮兮心悲。","惟天禄兮不再，背我信兮自违。","逾陇堆兮渡漠，过桂车兮合黎。","赴昆山兮馽𫘧，从邛遨兮栖迟。","吮玉液兮止渇，啮芝华兮疗饥。","居嵺廓兮尠畴，远梁昌兮几迷。","望江汉兮濩渃，心紧絭兮伤怀。","时昢昢兮且旦，尘莫莫兮未晞。","忧不暇兮寝食，咤増叹兮如雷。"],"source":"《楚辞》"},{"title":"桃源行","author":"王维","dynasty":"唐","form":"诗","lines":["渔舟逐水爱山春，両岸桃花夹去津。","坐看红树不知远，行尽青渓不见人。","山口潜行始隈隩，山开旷望旋平陆。","遥看一処攒云树，近入千家散花竹。","樵客初伝汉姓名，居人未改秦衣服。","居人共住武陵源，还従物外起田园。","月明松下房栊静，日出云中鶏犬喧。","惊闻俗客争来集，竞引还家问都邑。","平明闾巷埽花开，薄暮渔樵乗水入。","初因避地去人间，及至成仙遂不还。","峡里谁知有人事，世中遥望空云山。","不疑霊境难闻见，尘心未尽思郷県。","出洞无论隔山水，辞家终拟长游衍。","自谓経过旧不迷，安知峰壑今来変。","当时只记入山深，青渓几曲到云林。","春来遍是桃花水，不弁仙源何処寻。"],"source":"《唐诗三百首》"},{"title":"臙脂井三首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["腰支旅拒更神游，桃叶山前水自流。","三十六书都莫恨，烦将歌舞过扬州。"],"source":"宋诗"},{"title":"应天长","author":"吴文英","dynasty":"宋","form":"词","lines":["丽花斗靥，清麝溅尘，春声遍满芳陌。","竟路障空云幕，冰壶浸霞色。","芙蓉镜，词赋客。","竞绣笔、酔嫌天窄。","素娥下，小驻轻镳，眼乱红碧。","前事顿非昔，故苑年光，浑与世相隔。","向暮巷空人绝，残灯耿尘壁。","凌波恨，帘户寂。","听怨写、堕梅哀笛。","伫立久，雨暗河桥，谯漏疏滴。"],"source":"宋词"},{"title":"降黄龙衮・鳞鸿无个，锦笺慵写。腕松金，肌削玉，罗衣宽彻。泪痕淹破，","author":"关汉卿","dynasty":"元","form":"曲","lines":["胭脂双颊。","宝鉴愁临，翠钿羞贴。"],"source":"元曲"},{"title":"芄兰","author":"佚名","dynasty":"先秦","form":"诗","lines":["芄兰之支，童子佩觿。虽则佩觿，能不我知。容兮遂兮，垂带悸兮。","芄兰之叶，童子佩韘。虽则佩韘，能不我甲。容兮遂兮，垂带悸兮。"],"source":"《诗经》"},{"title":"悯上","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["哀世兮睩睩，𬣡𬣡兮嗌喔。","众多兮阿媚，骪靡兮成俗。","贪枉兮党比，贞良兮茕独。","鹄窜兮枳棘，鹈集兮帷幄。","罽蕠兮青葱，槁本兮萎落。","睹斯兮伪惑，心为兮隔错。","逡巡兮圃薮，率彼兮畛陌。","川谷兮渊渊，山阜兮峉峉。","丛林兮崟崟，株榛兮岳岳。","霜雪兮漼溰，冰冻兮洛泽。","东西兮南北，罔所兮归薄。","庇荫兮枯树，匍匐兮岩石。","蜷跼兮寒局数，独处兮志不申。","年齿尽兮命迫促，魁垒挤摧兮常困辱。","含忧强老兮愁无乐，须发苎悴兮顠鬓白。","思灵泽兮一膏沐，怀兰英兮把琼若，待天明兮立踯躅。","云蒙蒙兮电鯈烁，孤雌惊兮鸣呴呴。","思怫郁兮肝切剥，忿悁悒兮孰诉告。"],"source":"《楚辞》"},{"title":"洛阳女児行","author":"王维","dynasty":"唐","form":"诗","lines":["洛阳女児対门居，才可容颜十五余。","良人玉勒乗骢马，侍女金盘鲙鲤鱼。","画阁朱楼尽相望，红桃绿柳垂檐向。","罗帏送上七香车，宝扇迎帰九华帐。","狂夫富贵在青春，意気骄奢剧季伦。","自怜碧玉亲教舞，不惜珊瑚持与人。","春窗曙灭九微火，九微片片飞花璅。","戯罢曽无理曲时，妆成秪是薫香坐。","城中相识尽繁华，日夜経过赵李家。","谁怜越女颜如玉，贫贱江头自浣纱。"],"source":"《唐诗三百首》"},{"title":"秦淮","author":"范成大","dynasty":"宋","form":"诗","lines":["祖竜駆群竜，疏此万丈沟。","雨工恋故栖，十歩九回头。","至今秦淮曲，蜿若春蛇游。","舟师厌回互，叹息倚柂楼。","维昔东巡初，八极囲寸眸。","天端有佳気，鬰鬰东南浮。","卜云当兴王，在后五百秋。","叱咤召六丁，惨淡风云愁。","凿渠断地脉，自谓神与谋。","乾坤有端倪，已露不可収。","大帝开呉天，定鼎临江陬。","融融秣陵日，始照十二斿。","経営曁六代，兹地称神州。","乃知歴数定，昧者徒私忧。","兹事故老伝，未知信然不。","姑置勿重陈，作诗叹遅留。"],"source":"宋诗"},{"title":"风流子","author":"吴文英","dynasty":"宋","form":"词","lines":["金谷已空尘。","薫风转、国色返春魂。","半敧雪酔霜，舞低鸾翅，绛笼蜜炬，绿映龙盆。","窈窕绣窗人睡起，临砌脉无言。","慵整堕鬟，怨时迟暮，可怜憔悴，啼雨黄昏。","轻桡移花市，秋娘渡、飞浪溅湿行裙。","二十四桥南北，罗荐香分。","念砕劈芳心，萦思千缕，赠将幽素，偷翦重云。","终待凤池归去，催咏红翻。"],"source":"宋词"},{"title":"幺・等闲辜负，好天良夜。玉炉中，银台上，香消烛灭。凤帏冷落，鸳衾","author":"关汉卿","dynasty":"元","form":"曲","lines":["虚设，玉笋频搓，绣鞋重扌颠。"],"source":"元曲"},{"title":"河广","author":"佚名","dynasty":"先秦","form":"诗","lines":["谁谓河广？一苇杭之。谁谓宋远？跂予望之。","谁谓河广？曽不容刀。谁谓宋远？曽不崇朝。"],"source":"《诗经》"},{"title":"遭厄","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["悼屈子兮遭厄，沉王躬兮湘汨。","何楚国兮难化，迄于今兮不易。","士莫志兮羔裘，竞佞谀兮谗阋。","指正义兮为曲，訿玉璧兮为石。","殦雕游兮华屋，鵔鸃栖兮柴蔟。","起奋迅兮奔走，违群小兮謑訽。","载青云兮上升，适昭明兮所处。","蹑天衢兮长驱，踵九阳兮戏荡。","越云汉兮南济，秣余马兮河鼓。","云霓纷兮晻翳，参辰回兮颠倒。","逢流星兮问路，顾我指兮从左。","𠇹娵觜兮直驰，御者迷兮失轨。","遂踢达兮邪造，与日月兮殊道。","志阏绝兮安如，哀所求兮不耦。","攀天阶兮下视，见鄢郢兮旧宇。","意逍遥兮欲归，众秽盛兮沓沓。","思哽饐兮诘诎，涕流澜兮如雨。"],"source":"《楚辞》"},{"title":"辋川闲居赠裴秀才迪","author":"王维","dynasty":"唐","form":"诗","lines":["寒山転苍翠，秋水日潺湲。","倚杖柴门外，临风聴暮蝉。","渡头余落日，墟里上孤烟。","复值接舆酔，狂歌五柳前。"],"source":"《唐诗三百首》"},{"title":"九月三日宿胥口始闻鴈","author":"范成大","dynasty":"宋","form":"诗","lines":["故人久不见，乍见雑悲喜。","新鴈如故人，一声惊我起。","把酒不能觞，送目问行李。","曽云行路难，空蒙千万里。","塞北多関山，江南渺云水。","风高吹汝痩，旅伴今余几。","斜行不少驻，灭没苍烟里。","羁游吾亦倦，客程殊未已。","扁舟费年华，短缆繋沙尾。","物生各有役，冥心聴行止。","江郊匝地熟，场圃平如砥。","帰期且忽念，共饱豊年米。"],"source":"宋诗"},{"title":"风流子","author":"吴文英","dynasty":"宋","form":"词","lines":["温柔酣紫曲，扬州路、梦绕翠盘龙。","似日长傍枕，堕妆偏髻，露浓如酒，微酔敧红。","自别楚娇天正远，倾国见吴宫。","银烛夜阑，暗闻香泽，翠阴秋寂，重返春风。","芳期嗟轻误，花君去、肠断妾若为容。","惆怅舞衣叠损，露绮千重。","料绣窗曲理，红牙拍砕，禁阶敲遍，白玉盂空。","犹记弄花相谑，十二阑东。"],"source":"宋词"},{"title":"幺・铜壶玉漏催凄切，正更阑人静也。金闺潇洒转伤嗟，莲歩轻移呼侍妾：","author":"关汉卿","dynasty":"元","form":"曲","lines":["“把香桌儿安排打快些。"],"source":"元曲"},{"title":"伯兮","author":"佚名","dynasty":"先秦","form":"诗","lines":["伯兮朅兮，邦之桀兮。伯也执殳，为王前驱。","自伯之东，首如飞蓬。岂无膏沐？谁适为容！","其雨其雨，杲杲出日。愿言思伯，甘心首疾。","焉得谖草？言树之背。愿言思伯。使我心痗。"],"source":"《诗经》"},{"title":"悼乱","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["嗟嗟兮悲夫，殽乱兮纷挐。","茅丝兮同综，冠屦兮共絇。","督万兮侍宴，周邵兮负刍。","白龙兮见射，灵龟兮执拘。","仲尼兮困厄，邹衍兮幽囚。","伊余兮念兹，奔遁兮隐居。","将升兮高山，上有兮猴猿。","欲入兮深谷，下有兮虺蛇。","左见兮鸣鵙，右睹兮呼枭。","惶悸兮失气，踊跃兮距跳。","便旋兮中原，仰天兮増叹。","菅蒯兮楙莽，雚苇兮仟眠。","鹿蹊兮躖躖，貒貉兮蟫蟫。","鹯鹞兮轩轩，鹑鹌兮甄甄。","哀我兮寡独，靡有兮齐伦。","意欲兮沉吟，迫日兮黄昏。","玄鹤兮高飞，曽逝兮青冥。","鸧鹒兮喈喈，山鹊兮嘤嘤。","鸿鸬兮振翅，归雁兮于征。","吾志兮觉悟，怀我兮圣京。","垂屣兮将起，跓俟兮硕明。"],"source":"《楚辞》"},{"title":"酬张少府","author":"王维","dynasty":"唐","form":"诗","lines":["晩年唯好静，万事不関心。","自顾无长策，空知返旧林。","松风吹解帯，山月照弾琴。","君问穷通理，渔歌入浦深。"],"source":"《唐诗三百首》"},{"title":"欲雪","author":"范成大","dynasty":"宋","form":"诗","lines":["乌鸦撩乱舞黄云，楼上飞花已唾人。","说与江梅须早计，冯夷无頼欲争春。"],"source":"宋诗"},{"title":"过秦楼","author":"吴文英","dynasty":"宋","form":"词","lines":["藻国凄迷，曲澜澄映，怨入粉烟蓝雾。","香笼麝水，腻涨红波，一镜万妆争妒。","湘女归魂，佩环玉冷无声，凝情谁诉。","又江空月堕，凌波尘起，彩鸳愁舞。","还暗忆、钿合兰桡，丝牵琼腕，见的更怜心苦。","玲珑翠屋，轻薄冰绡，稳称锦云留住。","生怕哀蝉，暗惊秋被红衰，啼珠零露。","能西风老尽，羞趁东风嫁与。"],"source":"宋词"},{"title":"仙吕・翠裙腰闺怨","author":"关汉卿","dynasty":"元","form":"曲","lines":["晓来雨过山横秀，野水涨汀洲。","阑干倚遍空回首。","下危楼，一天风物暮伤秋。"],"source":"元曲"},{"title":"有狐","author":"佚名","dynasty":"先秦","form":"诗","lines":["有狐绥绥，在彼淇梁。心之忧矣，之子无裳。","有狐绥绥，在彼淇厉。心之忧矣，之子无带。","有狐绥绥，在彼淇侧。心之忧矣，之子无服。"],"source":"《诗经》"},{"title":"伤时","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["惟昊天兮昭灵，阳气发兮清明。","风习习兮和暖，百草萌兮华荣。","堇荼茂兮扶疏，蘅芷雕兮莹嫇。","愍贞良兮遇害，将夭折兮砕糜。","时混混兮浇饡，哀当世兮莫知。","览往昔兮俊彦，亦诎辱兮系累。","管束缚兮桎梏，百贸易兮传卖。","遭桓缪兮识举，才徳用兮列施。","且从容兮自慰，玩琴书兮游戏。","迫中国兮迮陿，吾欲之兮九夷。","超五岭兮嵯峨，观浮石兮崔嵬。","陟丹山兮炎野，屯余车兮黄支。","就祝融兮稽疑，嘉己行兮无为。","乃回朅兮北逝，遇神孈兮宴娭。","欲静居兮自娱，心愁戚兮不能。","放余辔兮策驷，忽飙腾兮浮云。","跖飞杭兮越海，从安期兮蓬莱。","缘天梯兮北上，登太一兮玉台。","使素女兮鼓簧，乗戈和兮讴谣。","声噭𫍥兮清和，音晏衍兮要婬。","咸欣欣兮酣乐，余眷眷兮独悲。","顾章华兮太息，志恋恋兮依依。"],"source":"《楚辞》"},{"title":"送梓州李使君","author":"王维","dynasty":"唐","form":"诗","lines":["万壑树参天，千山响杜鹃。","山中一夜雨，树杪百重泉。","汉女输橦布，巴人讼芋田。","文翁翻教授，不敢倚先贤。"],"source":"《唐诗三百首》"},{"title":"読史三首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["百歳亏成费械机，乌鸢蝼蚁竟同帰。","一檠灯火挑明灭，両眼昏花管是非。"],"source":"宋诗"},{"title":"法曲献仙音","author":"吴文英","dynasty":"宋","form":"词","lines":["风拍波惊，露零秋觉，断绿衰红江上。","艳払潮妆，澹凝冰靥，别翻翠池花浪。","过数点斜阳雨，啼绡粉痕冷。","宛相向。","指汀洲、素云飞过，清麝洗、玉井晓霞佩响。","寸藕折长丝，笑何郎、心似春荡。","半掬微凉，听娇蝉、声度菱唱。","伴鸳鸯秋梦，酒醒月斜轻帐。"],"source":"宋词"},{"title":"六幺遍・乍凉时候，西风透。碧梧脱叶，余暑才収。香生凤口，帘垂玉钩，","author":"关汉卿","dynasty":"元","form":"曲","lines":["小院深闲清昼。","清幽，听声声蝉噪柳梢头。"],"source":"元曲"},{"title":"木瓜","author":"佚名","dynasty":"先秦","form":"诗","lines":["投我以木瓜，报之以琼琚。匪报也，永以为好也！","投我以木桃，报之以琼瑶。匪报也，永以为好也！","投我以木李，报之以琼九。匪报也，永以为好也！"],"source":"《诗经》"},{"title":"哀岁","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["旻天兮清凉，玄气兮高朗。","北风兮潦洌，草木兮苍唐。","蛜蚗兮噍噍，蝍蛆兮穣穣。","岁忽忽兮惟暮，余感时兮凄怆。","伤俗兮泥浊，蒙蔽兮不章。","宝彼兮沙砾，捐此兮夜光。","椒瑛兮湟污，葈耳兮充房。","摄衣兮缓带，操我兮墨阳。","升车兮命仆，将驰兮四荒。","下堂兮见虿，出门兮触螽。","巷有兮蚰蜓，邑多兮螳螂。","睹斯兮嫉贼，心为兮切伤。","俛念兮子胥，仰怜兮比干。","投剑兮脱冕，龙屈兮蜿蟤。","潜蔵兮山泽，匍匐兮丛攒。","窥见兮渓涧，流水兮沄沄。","鼋鼍兮欣欣，鳣鲇兮延延。","群行兮上下，骈罗兮列陈。","自恨兮无友，特处兮茕茕。","冬夜兮陶陶，雨雪兮冥冥。","神光兮颎颎，鬼火兮荧荧。","修徳兮困控，愁不聊兮遑生。","忧纡兮郁郁，恶所兮写情。"],"source":"《楚辞》"},{"title":"玉台体十二首 十一","author":"権徳舆","dynasty":"唐","form":"诗","lines":["昨夜裙帯解，今朝蟢子飞。","铅华不可弃，莫是藁砧帰。"],"source":"《唐诗三百首》"},{"title":"読史三首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["堂堂列伝冠元功，纸上浮云万事空。","我若材堪当世用，他年応只似诸公。"],"source":"宋诗"},{"title":"法曲献仙音","author":"吴文英","dynasty":"宋","form":"词","lines":["落叶霞翻，败窗风咽，暮色凄凉深院。","痩不关秋，泪缘轻别，情消鬓霜千点。","怅翠冷掻头燕，那能语恩怨。","紫箫远。","记桃根、向随春渡，愁未洗、铅水又将恨染。","粉缟涩离箱，忍重拈、灯夜裁翦。","望极蓝桥，彩云飞、罗扇歌断。","料莺笼玉锁，梦里隔花时见。"],"source":"宋词"},{"title":"寄生草・为甚忧，为甚愁？为萧郎一去经今久。玉台宝鉴生尘垢，绿窗冷","author":"关汉卿","dynasty":"元","form":"曲","lines":["落闲针锈。","岂知人玉腕钏儿松，岂知人两叶眉儿皱！。"],"source":"元曲"},{"title":"黍离","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼黍离离，彼稷之苗。行迈靡靡，中心摇摇。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？","彼黍离离，彼稷之穂。行迈靡靡，中心如酔。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？","彼黍离离，彼稷之实。行迈靡靡，中心如噎。知我者，谓我心忧；不知我者，谓我何求。悠悠苍天，此何人哉？"],"source":"《诗经》"},{"title":"守志","author":"王逸","dynasty":"先秦","form":"辞赋","lines":["陟玉峦兮逍遥，览高冈兮峣峣。","桂树列兮纷敷，吐紫华兮布条。","实孔鸾兮所居，今其集兮惟鸮。","乌鹊惊兮哑哑，余顾盼兮怊怊。","彼日月兮暗昧，障覆天兮祲氛。","伊我后兮不聪，焉陈诚兮効忠。","摅羽翮兮超俗，游陶遨兮养神。","乗六蛟兮蜿蝉，遂驰骋兮升云。","扬彗光兮为旗，秉电策兮为鞭。","朝晨发兮鄢郢，食时至兮増泉。","绕曲阿兮北次，造我车兮南端。","谒玄黄兮纳贽，崇忠贞兮弥坚。","历九宫兮遍观，睹秘蔵兮宝珍。","就传说兮骑龙，与织女兮合婚。","举天罼兮掩邪，彀天弧兮射奸。","随真人兮翱翔，食元气兮长存。","望太微兮穆穆，睨三阶兮炳分。","相辅政兮成化，建烈业兮垂勋。","目瞥瞥兮西没，道遐回兮阻叹。","志稸积兮未通，怅敞罔兮自怜。","乱曰：","天庭明兮云霓蔵，三光朗兮镜万方。","斥蜥蜴兮进龟龙，策谋从兮翼机衡。","配稷契兮恢唐功，嗟英俊兮未为双。"],"source":"《楚辞》"},{"title":"山石","author":"韩愈","dynasty":"唐","form":"诗","lines":["山石荦确行径微，黄昏到寺蝙蝠飞。","升堂坐阶新雨足，芭蕉叶大支子肥。","僧言古壁仏画好，以火来照所见稀。","舗床払席置羹饭，疏粝亦足饱我饥。","夜深静卧百虫绝，清月出岭光入扉。","天明独去无道路，出入高下穷烟霏。","山红涧碧纷烂漫，时见松枥皆十囲。","当流赤足蹋涧石，水声激激风吹衣。","人生如此自可楽，岂必局束为人鞿。","嗟哉吾党二三子，安得至老不更帰。"],"source":"《唐诗三百首》"},{"title":"読史三首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["镂冰琢雪戦毛牦，画餠声名骨朽时。","汗简书青已児戯，岘山辛苦更沉碑。"],"source":"宋诗"},{"title":"还京乐","author":"吴文英","dynasty":"宋","form":"词","lines":["宴兰溆，促奏丝萦管裂飞繁响。","似汉宫人去，夜深独语，胡沙凄哽。","对雁斜玫柱，琼琼弄月临秋影。","凤吹远，河汉去杳，天风飘冷。","泛清商竟。","转铜壶敲漏，瑶床二八青娥，环佩再整。","菱歌四碧无声，变须臾、翠翳红暝。","叹梨园、今调绝音希，愁深未醒。","桂楫轻如翼，归霞时点清镜。"],"source":"宋词"},{"title":"后庭花煞・掩袖暗含羞，开樽越酿愁。闷把苔墙画，慵将锦字修。最风流，","author":"关汉卿","dynasty":"元","form":"曲","lines":["真真恩爱，等闲分付等闲休。"],"source":"元曲"},{"title":"君子于役","author":"佚名","dynasty":"先秦","form":"诗","lines":["君子于役，不知其期。曷至哉？鸡栖于埘。日之夕矣，羊牛下来。君子于役，如之何勿思！","君子于役，不日不月。曷其有佸？鸡栖于桀。日之夕矣，羊牛下括。君子于役，苟无饥渇？"],"source":"《诗经》"},{"title":"八月十五夜赠张功曹","author":"韩愈","dynasty":"唐","form":"诗","lines":["繊云四巻天无河，清风吹空月舒波。","沙平水息声影绝，一桮相属君当歌。","君歌声酸辞且苦，不能聴终涙如雨。","洞庭连天九疑高，蛟竜出没猩鼯号。","十生九死到官所，幽居黙黙如蔵逃。","下床畏蛇食畏薬，海気湿蛰熏腥臊。","昨者州前搥大鼓，嗣皇継圣登夔臯。","赦书一日行万里，罪従大辟皆除死。","迁者追廻流者还，涤瑕荡垢清朝班。","州家申名使家抑，坎轲祗得移荆蛮。","判司卑官不堪说，未免捶楚尘埃间。","同时辈流多上道，天路幽険难追攀。","君歌且休聴我歌，我歌今与君殊科。"],"source":"《唐诗三百首》"},{"title":"宴坐庵四首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["油灯已暗忽微明，石鼎将干尚有声。","衲被蒙头笼両袖，藜床无地着功名。"],"source":"宋诗"},{"title":"塞翁吟","author":"吴文英","dynasty":"宋","form":"词","lines":["草色新宫绶，还跨紫陌骄骢。","好花是，晩开红。","冷菊最香浓。","黄帘绿幕萧萧梦，灯外换几秋风。","叙往约，桂花宫。","为别翦珍丛。","雕栊。","行人去、秦腰褪玉，心事称、吴妆晕浓。","向春夜、闰情赋就，想初寄、上国书时，唱入眉峰。","归来共酒，窈窕纹窗，莲卸新蓬。"],"source":"宋词"},{"title":"南吕・一枝花赠朱帘秀","author":"关汉卿","dynasty":"元","form":"曲","lines":["轻裁虾万须，巧织珠千串；金钩光错落，绣带舞蹁跹。","似雾非烟，妆点就深闺院，不许那等闲人取次展。","摇四壁翡翠浓阴，射万瓦琉璃色浅。"],"source":"元曲"},{"title":"君子阳阳","author":"佚名","dynasty":"先秦","form":"诗","lines":["君子阳阳，左执簧，右招我由房，其乐只且！","君子陶陶，左执翿，右招我由敖，其乐只且！"],"source":"《诗经》"},{"title":"谒衡岳庙遂宿岳寺题门楼","author":"韩愈","dynasty":"唐","form":"诗","lines":["五岳祭秩皆三公，四方环镇嵩当中。","火维地荒足妖怪，天仮神柄専其雄。","喷云泄雾蔵半腹，虽有绝顶谁能穷。","我来正逢秋雨节，阴気晦昧无清风。","潜心黙祷若有応，岂非正直能感通。","须臾静扫众峰出，仰见突兀撑青空。","紫盖连延接天柱，石廪腾掷堆祝融。","森然魄动下马拝，松柏一迳趋霊宫。","粉墙丹柱动光彩，鬼物図画填青红。","升阶伛偻荐脯酒，欲以菲薄明其衷。","庙令老人识神意，睢盱侦伺能鞠躬。","手持桮珓导我掷，云此最吉余难同。","窜逐蛮荒幸不死，衣食才足甘长终。","侯王将相望久绝，神縦欲福难为功。","夜投仏寺上高阁，星月掩暎云朣胧。","猿鸣钟动不知曙，杲杲寒日生于东。"],"source":"《唐诗三百首》"},{"title":"宴坐庵四首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["五更风竹閙轩窗，聴作江船浪隠床。","枕上翻身寻断梦，故人待漏満𫖇霜。"],"source":"宋诗"},{"title":"塞翁吟","author":"吴文英","dynasty":"宋","form":"词","lines":["有约西湖去，移棹晓折芙蓉。","算才是，称心红。","染不尽薫风。","千桃过眼春如梦，还认锦叠云重。","弄晩色，旧香中。","旋撑入深丛。","从容。","情犹赋、冰车健笔，人未老、南屏翠峰。","转河影、浮槎信早，素妃叫、海月归来，太液池东。","红衣卸了，结子成莲，天劲秋浓。"],"source":"宋词"},{"title":"梁州・富贵似侯家紫帐，风流如谢府红莲，锁春愁不放双飞燕。绮窗相近，","author":"关汉卿","dynasty":"元","form":"曲","lines":["翠户相连，雕栊相映，绣幕相牵。","払苔痕满砌楡钱，惹杨花飞点如锦。","愁的是抹回廊暮雨萧萧，恨的是筛曲槛西风剪剪，爱的是透长门夜月娟娟。","凌波殿前，碧玲珑掩映湘妃面，没福怎能够见？十里扬州风物妍，出落着神仙。"],"source":"元曲"},{"title":"扬之水","author":"佚名","dynasty":"先秦","form":"诗","lines":["扬之水，不流束薪。彼其之子，不与我戍申。怀哉怀哉，曷月予还归哉？","扬之水，不流束楚。彼其之子，不与我戍甫。怀哉怀哉，曷月予还归哉？","扬之水，不流束蒲。彼其之子，不与我戍许。怀哉怀哉，曷月予还归哉？"],"source":"《诗经》"},{"title":"已凉","author":"韩偓","dynasty":"唐","form":"诗","lines":["碧阑干外繍帘垂，猩血屏风画折枝。","八尺竜须方锦褥，已凉天気未寒时。"],"source":"《唐诗三百首》"},{"title":"宴坐庵四首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["粥鱼吼罢鼓逢逢，卧聴饥鼯上暁釭。","一点斜光明纸帐，悟知檐雀已穿窗。"],"source":"宋诗"},{"title":"丁香结","author":"吴文英","dynasty":"宋","form":"词","lines":["香袅红霏，影高银烛，曽纵夜游浓酔。","正锦温琼腻。","被燕踏、暖雪惊翻庭砌。","马嘶人散后，秋风换、故园梦里。","吴霜融晓，陡觉暗动偷春花意。","还似。","海雾冷仙山，唤觉环儿半睡。","浅薄朱唇，娇羞艳色，自伤时背。","帘外寒挂澹月，向日秋千地。","怀春情不断，犹带相思旧子。"],"source":"宋词"},{"title":"南吕・一枝花杭州景","author":"关汉卿","dynasty":"元","form":"曲","lines":["普天下锦绣乡，寰海内风流地。","大元朝新附国，亡宋家旧华夷。","水秀山奇，一到处堪游戏。","这答儿忒富贵，满城中绣幕风帘，一哄地人烟辏集。"],"source":"元曲"},{"title":"中谷有蓷","author":"佚名","dynasty":"先秦","form":"诗","lines":["中谷有蓷，暵其干矣。有女仳离，慨其叹矣。慨其叹矣，遇人之艰难矣。","中谷有蓷，暵其修矣。有女仳离，条其歗矣。条其歗矣，遇人之不淑矣。","中谷有蓷，暵其湿矣。有女仳离，啜其泣矣。啜其泣矣，何嗟及矣。"],"source":"《诗经》"},{"title":"春宫怨","author":"杜荀鹤","dynasty":"唐","form":"诗","lines":["早被婵娟误，欲妆临镜慵。","承恩不在貌，教妾若为容。","风暖鸟声砕，日高花影重。","年年越渓女，相忆采芙蓉。"],"source":"《唐诗三百首》"},{"title":"宴坐庵四首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["跏趺合眼是无何，静里惟闻鸟雀多。","俗客叩门称问字，又烦居士起穿𫖇。"],"source":"宋诗"},{"title":"六幺令","author":"吴文英","dynasty":"宋","form":"词","lines":["露蛩初响，机杼还催织。","婺星为情慵懒，伫立明河侧。","不见津头艇子，望绝南飞翼。","云梁千尺。","尘缘一点，回首西风又陈迹。","那知天上计拙，乞巧楼南北。","瓜果几度凄凉，寂寞罗池客。","人事回廊缥缈，谁见金钗擘。","今夕何夕。","杯残月堕，但耿银河漫天碧。"],"source":"宋词"},{"title":"梁州・百十里街衢整齐，万余家楼阁参差，并无半答儿闲田地。松轩竹径，","author":"关汉卿","dynasty":"元","form":"曲","lines":["药圃花蹊，茶园稲陌，竹坞梅渓。","一陀儿一句诗题，行一歩扇面屏帏。","西盐场便似一带琼瑶，吴山色千叠悲翠。","兀良，望钱塘江万顷玻璃。","更有清渓绿水，画船儿来往闲游戏。","浙江亭紧相对，相对着险岭高峰长怪石，堪羡堪题。"],"source":"元曲"},{"title":"兔爰","author":"佚名","dynasty":"先秦","form":"诗","lines":["有兔爰爰，雉离于罗。我生之初，尚无为；我生之后，逢此百罹。尚寐无吪。","有兔爰爰，雉离于罦。我生之初，尚无造；我生之后，逢此百忧。尚寐无觉。","有兔爰爰，雉离于罿。我生之初，尚无庸；我生之后，逢此百凶。尚寐无聪。"],"source":"《诗经》"},{"title":"近试上张籍水部","author":"朱庆余","dynasty":"唐","form":"诗","lines":["洞房昨夜停红烛，待暁堂前拝舅姑。","[妆]罢低声问夫壻，画眉深浅入时无。"],"source":"《唐诗三百首》"},{"title":"青青磵上松送致远入官","author":"范成大","dynasty":"宋","form":"诗","lines":["青青磵上松，鬰鬰磵底柏。","松森上曽云，柏跼抱幽石。","偃植虽不同，臭味乃相得。","千霜与百雪，偶立众芳侧。","众芳岂不好，歳晏扫无迹。","広厦罩群木，万牛挽山沢。","松材可世用，攀援入王国。","草木岂有情，亦复念离析。","君看此翠柏，错莫无颜色。","孤阴愁月夜，独籁怨风夕。","苍官何当帰，相望长相忆。"],"source":"宋诗"},{"title":"蕙兰芳引","author":"吴文英","dynasty":"宋","form":"词","lines":["空翠染云，楚山迥、故人南北。","秀骨冷盈盈，清洗九秋涧绿。","奉车旧畹，料未许、千金轻价。","浅笑还不语，蔓草罗裙一幅。","素女情多，阿真娇重，唤起空谷。","弄野色烟姿，宜扫怨蛾澹墨。","光风入户，媚香倾国。","湘佩寒、幽梦小窗春足。"],"source":"宋词"},{"title":"尾・家家掩映渠流水，楼阁峥嵘出翠微。遥望西湖暮山势，看了这壁，觑","author":"关汉卿","dynasty":"元","form":"曲","lines":["了那壁，纵有丹青下不得笔。"],"source":"元曲"},{"title":"葛藟","author":"佚名","dynasty":"先秦","form":"诗","lines":["绵绵葛藟，在河之浒。终远兄弟，谓他人父。谓他人父，亦莫我顾！","绵绵葛爰，在河之藟。终远兄弟，谓他人母。谓他人母，亦莫我有！","绵绵葛藟，在河之漘。终远兄弟，谓他人昆。谓他人昆，亦莫我闻！"],"source":"《诗经》"},{"title":"将赴呉兴登楽游原一绝","author":"杜牧","dynasty":"唐","form":"诗","lines":["清时有味是无能，闲爱孤云静爱僧。","欲把一麾江海去，楽游原上望昭陵。"],"source":"《唐诗三百首》"},{"title":"除夜感懐","author":"范成大","dynasty":"宋","form":"诗","lines":["松楸百年哀，霜露终歳悲。","天地岂汝偏，鬼神谅无私。","孤穷罪当尔，我今怨尤谁。","噎绝梦自语，伶俜影相随。","岂无一経伝，政坐五鬼嗤。","凿枘共龃龉，榛荆费耘耔。","付畀逾丘山，奉承劣毫厘。","生男九族歓，所愿作门楣。","时命有大谬，生男竟何裨。","匏瓜谩枵腹，蒲柳无真姿。","蹙缩高颧颊，萧騒短髯髭。","贫病老歳月，斗杓坐成移。","暁风凄以寒，帘幕相纷披。","月星炯我冠，雾雨泫我衣。","焄蒿奉祠事，苦涙落酒巵。","逝者日已远，生者日以衰。","羸骖驾九折，日暮抱长饥。","岐路正巉绝，耿耿谁当知。"],"source":"宋诗"},{"title":"隔浦莲近・隔浦莲近拍","author":"吴文英","dynasty":"宋","form":"词","lines":["榴花依旧照眼。","愁褪红丝腕。","梦绕烟江路，汀菰绿薫风晩。","年少惊送远。","吴蚕老、恨绪萦抽茧。","旅情懒。","扁舟系处，青帘浊酒须换。","一番重午，旋买香蒲浮盏。","新月湖光荡素练。","人散。","红衣香在南岸。"],"source":"宋词"},{"title":"南吕・一枝花不伏老","author":"关汉卿","dynasty":"元","form":"曲","lines":["攀出墙朵朵花，折临路枝枝柳。","花攀红蕊嫩，柳折翠条柔，浪子风流。","凭着我折柳攀花手，直煞得花残柳败休。","半生来折柳攀花，一世里眠花卧柳。"],"source":"元曲"},{"title":"采葛","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼采葛兮，一日不见，如三月兮！","彼采萧兮，一日不见，如三秋兮！","彼采艾兮！一日不见，如三岁兮！"],"source":"《诗经》"},{"title":"赤壁","author":"杜牧","dynasty":"唐","form":"诗","lines":["折戟沈沙鉄未销，自将磨洗认前朝。","东风不与周郎便，铜雀春深鏁二乔。"],"source":"《唐诗三百首》"},{"title":"次韵唐子光席上赏梅","author":"范成大","dynasty":"宋","form":"诗","lines":["玉枝横斜照清空，繊手撚香□□公。","水部无人広平去，后来我辈犹情钟。","谁喷昭华送愁绝，叫云三弄怨斜月。","径须踏雪问前村，莫待马蹄如踣鉄。","春风圧尽百花桥，尊前仍有董娇娆。","惜无楚客歌成雪，空有萧郎眼似刀。"],"source":"宋诗"},{"title":"垂丝钓近・垂丝钓","author":"吴文英","dynasty":"宋","form":"词","lines":["听风听雨，春残花落门掩。","乍倚玉阑，旋翦夭艳。","携酔靥。","放溯渓游缆。","波光撼。","映烛花黯澹。","砕霞澄水，吴宫初试菱鉴。","旧情顿减。","孤负深杯滟。","衣露天香染。","通夜饮。","问漏移几点。"],"source":"宋词"},{"title":"梁州・我是个普天下郎君领袖，盖世界浪子班头。愿朱颜不改常依旧，花","author":"关汉卿","dynasty":"元","form":"曲","lines":["中消遣，酒内忘忧。","分茶扌颠竹，打马蔵阄；通五音六律滑熟，甚闲愁到我心头！伴的是银筝女银台前理银筝笑倚银屏，伴的是玉天仙携玉手并玉肩同登玉楼，伴的是金钗客歌《金缕》捧金樽满泛金瓯。","你道我老也，暂休。","占排场风月功名首，更玲珑又剔透。","我是个锦阵花营都帅头，曽玩府游州。"],"source":"元曲"},{"title":"大车","author":"佚名","dynasty":"先秦","form":"诗","lines":["大车槛槛，毳衣如菼。岂不尔思？畏子不敢。","大车啍啍，毳衣如𫞩，岂不尔思？畏子不奔。","谷则异室，死则同穴。谓予不信，有如皎日。"],"source":"《诗经》"},{"title":"泊秦淮","author":"杜牧","dynasty":"唐","form":"诗","lines":["烟笼寒水月笼沙，夜泊秦淮近酒家。","商女不知亡国恨，隔江犹唱后庭花。"],"source":"《唐诗三百首》"},{"title":"夜行上沙见梅记东坡作诗招魂之句","author":"范成大","dynasty":"宋","form":"诗","lines":["玉妃谪人世，乃在流水村。","天风吹婵娟，飘堕寂莫浜。","芳心怨命薄，玉色凄路尘。","佳人来无期，日暮多碧云。","渓声为咽绝，月亦低微颦。","相逢倦游子，一笑不复珍。","脉脉问不语，亭亭意弥真。","要我冰雪句，招此欲断魂。","苏仙上宾天，妙意终难陈。","璇柄忽倾堕，暁岚愁翠昏。"],"source":"宋诗"},{"title":"茘枝香近・茘枝香","author":"吴文英","dynasty":"宋","form":"词","lines":["锦带吴钩，征思横雁水。","夜吟敲落霜红，船傍枫桥系。","相思不管年华，唤酒吴娃市。","因话、驻马新堤歩秋绮。","淮楚尾。","暮云送、人千里。","细雨南楼，香密锦温曽酔。","花谷依然，秀靥偷春小桃李。","为语梦窗憔悴。"],"source":"宋词"},{"title":"隔尾・子弟毎是个茅草冈、沙土窝初生的兔羔儿乍向围场上走，我是个经","author":"关汉卿","dynasty":"元","form":"曲","lines":["笼罩、受索网苍翎毛老野鸡踏踏的阵马儿熟。","经了些窝弓冷箭蜡枪头，不曽落人后。","恰不道“人到中年万事休”，我怎肯虚度了春秋。"],"source":"元曲"},{"title":"丘中有麻","author":"佚名","dynasty":"先秦","form":"诗","lines":["丘中有麻，彼留子嗟。彼留子嗟，将其来施施。","丘中有麦，彼留子国。彼留子国，将其来食。","丘中有李，彼留之子。彼留之子，贻我佩九。"],"source":"《诗经》"},{"title":"赠别二首 一","author":"杜牧","dynasty":"唐","form":"诗","lines":["娉娉褭褭十三余，豆蔻梢头二月初。","春风十里扬州路，巻上珠帘総不如。"],"source":"《唐诗三百首》"},{"title":"次韵唐子光教授河豚","author":"范成大","dynasty":"宋","form":"诗","lines":["世间尤物美悪并，江郷未用夸呉羹。","清宫洞房寒热媒，深山大沢竜蛇生。","胡夷信美胎杀気，不奈呉児苦知味。","杨花欲动荻芽肥，污手死心揺食指。","食鱼要是□黄粱，古来不必须河鲂。","君看嗔腹似浑脱，宁肯滑甘随芥姜。","先生法语峻立壁，讥评不使一銭直。","膨亨従此迹如扫，坐令梅老诗无力。","悬知仙骨有青冥，风香久已涤膻腥。","大笑日华解毒法，何如肘后餐霞経。"],"source":"宋诗"},{"title":"茘枝香近・茘枝香","author":"吴文英","dynasty":"宋","form":"词","lines":["睡轻时闻，晩鹊噪庭树。","又说今夕天津，西畔重欢遇。","蛛丝暗锁红楼，燕子穿帘处。","天上、未比人间更情苦。","秋鬓改，妒月姊、长眉妩。","过雨西风，数叶井梧愁舞。","梦入蓝桥，几点疏星映朱户。","泪湿沙边凝伫。"],"source":"宋词"},{"title":"尾・我是个蒸不烂、煮不熟、捶不匾、炒不爆响当当一粒铜豌豆，恁子弟","author":"关汉卿","dynasty":"元","form":"曲","lines":["毎谁教你钻入他锄不断、斫不下、解不开、顿不脱慢腾腾千层锦套头。","我玩的是梁园月，饮的是东京酒，赏的是洛阳花，攀的是章台柳。","我也会围棋、会蹴リ、会打围、会挿科、会歌舞、会吹弹、会咽作、会吟诗、会双陆。","你便是落了我牙、歪了我嘴、瘸了我腿、折了我手，天赐与我这几般儿歹症候，尚兀自不肯休。","则除是阎王亲自唤，神鬼自来勾，三魂归地府，七魂丧冥幽，天那，那其间才不向烟花路儿上走！。"],"source":"元曲"},{"title":"缁衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["缁衣之宜兮，敝予又改为兮。适子之馆兮。还予授子之粲兮。","缁衣之好兮，敝予又改造兮。适子之馆兮，还予授子之粲兮。","缁衣之席兮，敝予又改作兮。适子之馆兮，还予授子之粲兮。"],"source":"《诗经》"},{"title":"赠别二首 二","author":"杜牧","dynasty":"唐","form":"诗","lines":["多情却似総无情，唯覚尊前笑不成。","蝋烛有心还惜别，替人垂涙到天明。"],"source":"《唐诗三百首》"},{"title":"题如梦堂壁","author":"范成大","dynasty":"宋","form":"诗","lines":["勃姑午啼唤雨，鹎𫛥暁啭留春。","片云不载帰梦，両鬓全供客尘。"],"source":"宋诗"},{"title":"西河","author":"吴文英","dynasty":"宋","form":"词","lines":["春乍霁。","清涟画舫融泄。","螺云万叠暗凝愁，黛蛾照水。","漫将西子比西湖，渓边人更多丽。","歩危径、攀艳蕊。","掬霞到手红砕。","青蛇细折小回廊，去天半咫。","画阑日暮起东风，棋声吹下人世。","海棠藉雨半绣地。","正残寒、初御罗绮。","除酒销春何计。","向沙头更续，残阳一酔。","双玉杯和流花洗。"],"source":"宋词"},{"title":"中吕・古调石榴花闺思","author":"关汉卿","dynasty":"元","form":"曲","lines":["颠狂柳絮扑帘飞，绿暗红稀。","垂杨影里杜鹃啼，一弄儿断送了春归。","牡丹亭畔人寂静，恼芳心似酔如痴。","恹恹为他成病也，松金钏，褪罗衣。"],"source":"元曲"},{"title":"将仲子","author":"佚名","dynasty":"先秦","form":"诗","lines":["将仲子兮，无逾我里，无折我树杞。岂敢爱之？畏我父母。仲可怀也，父母之言亦可畏也。","将仲子兮，无逾我墙，无折我树桑。岂敢爱之？畏我诸兄。仲可怀也，诸兄之言亦可畏也。","将仲子兮，无逾我园，无折我树檀。岂敢爱之？畏人之多言。仲可怀也，人之多言亦可畏也。"],"source":"《诗经》"},{"title":"遣懐","author":"杜牧","dynasty":"唐","form":"诗","lines":["落魄江南载酒行，楚腰肠断掌中軽。","十年一覚扬州梦，赢得青楼薄幸名。"],"source":"《唐诗三百首》"},{"title":"暁起","author":"范成大","dynasty":"宋","form":"诗","lines":["帘额繍波荡漾，烛盘红涙阑干。","梦里五更风急，愁辺一半春残。"],"source":"宋诗"},{"title":"浪淘沙慢","author":"吴文英","dynasty":"宋","form":"词","lines":["梦仙到、吹笙路杳，度𪩘云滑。","渓谷冰绡未裂。","金铺昼锁乍掣。","见竹静、梅深春海阔。","有新燕、帘底低说。","念汉履无声跨鲸远，年年谢桥月。","曲折。","折画阑尽日凭热。","半蜃起玲珑楼阁畔，缥缈鸿去绝。","飞絮扬东风，天外歌阕。","睡红酔缬。","还是催、寒食看花时节。","花下苍苔盛罗袜。","银烛短、漏壶易竭。","料池柳、不攀春送别。","倩玉兔、别捣秋香，更酔蹋、千山冷翠飞晴雪。"],"source":"宋词"},{"title":"酥枣儿・一自相逢，将人来萦系。樽前席上，眼约心期。比及道是配合了，","author":"关汉卿","dynasty":"元","form":"曲","lines":["受了些闲是闲非。","咱各办着个坚心，要拨个终缘之计。"],"source":"元曲"},{"title":"叔于田","author":"佚名","dynasty":"先秦","form":"诗","lines":["叔于田，巷无居人。岂无居人？不如叔也。洵美且仁。","叔于狩，巷无饮酒。岂无饮酒？不如叔也。洵美且好。","叔适野，巷无服马。岂无服马？不如叔也。洵美且武。"],"source":"《诗经》"},{"title":"秋夕","author":"杜牧","dynasty":"唐","form":"诗","lines":["红烛秋光冷画屏，軽罗小扇扑流蛍。","天阶夜色凉如水，坐看牵牛织女星。"],"source":"《唐诗三百首》"},{"title":"再游上方","author":"范成大","dynasty":"宋","form":"诗","lines":["僧共老花俱在，客将春鴈同回。","范叔一寒如此，刘郎前度曽来。"],"source":"宋诗"},{"title":"西平乐慢・西平乐","author":"吴文英","dynasty":"宋","form":"词","lines":["岸压邮亭，路敧华表，堤树旧色依依。","红索新晴，翠阴寒食，天涯倦客重归。","叹废绿平烟带苑，幽渚尘香荡晩，当时燕子，无言对立斜晖。","追念吟风赏月，十载事，梦惹绿杨丝。","画船为市，夭妆艳水，日落云沈，人换春移。","谁更与、苔根洗石，菊井招魂，漫省连车载酒，立马临花，犹认荐红傍路枝。","歌断宴阑，荣华露草，冷落山丘，到此徘徊，细雨西城，羊昙酔后花飞。"],"source":"宋词"},{"title":"鲍老儿・当初指望成家计，谁想琼簪砕；当初指望无抛弃，谁想银瓶坠。","author":"关汉卿","dynasty":"元","form":"曲","lines":["烦烦恼恼，哀哀怨怨，哭哭啼啼，回黄倒皂，长吁短叹，自跌自堆。"],"source":"元曲"},{"title":"大叔于田","author":"佚名","dynasty":"先秦","form":"诗","lines":["叔于田，乗乗马。执辔如组，两骖如舞。叔在薮，火烈具举。襢裼暴虎，献于公所。将叔勿狃，戒其伤女。","叔于田，乗乗黄。两服上襄，两骖雁行。叔在薮，火烈具扬。叔善射忌，又良御忌。抑罄控忌，抑纵送忌。","叔于田，乗乗鸨。两服齐首，两骖如手。叔在薮，火烈具阜。叔马慢忌，叔发罕忌，抑释掤忌，抑鬯弓忌。"],"source":"《诗经》"},{"title":"金谷园","author":"杜牧","dynasty":"唐","form":"诗","lines":["繁华事散逐香尘，流水无情草自春。","日暮东风怨啼鸟，落花犹似堕楼人。"],"source":"《唐诗三百首》"},{"title":"即事","author":"范成大","dynasty":"宋","form":"诗","lines":["酔袖笼鞭転柳塘，青门芳树掩残香。","谁惊翡翠双飞去，只有莲花対断肠。"],"source":"宋诗"},{"title":"瑞龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["堕虹际。","层观翠冷玲珑，五云飞起。","玉虬萦结城根，澹烟半野，斜阳半市。","瞰危睇。","门巷去来车马，梦游宫蚁。","秦鬟古色凝愁，镜中暗换，明眸皓齿。","东海青桑生处，劲风吹浅，瀛洲清泚。","山影泛出琼壶，碧树人世。","枪芽焙绿，曽试云根味。","岩流溅、涎香惯搅，娇龙春睡。","露草啼清泪。","酒香断到，文丘废隧。","今古秋声里。","情漫黯、寒鸦孤村流水。","半空画角，落梅花地。"],"source":"宋词"},{"title":"墙头花・守香闺，镇日情如酔，闷懊恼离愁空教我诉与谁？愁闻的是紫燕","author":"关汉卿","dynasty":"元","form":"曲","lines":["关关，倦听的是黄莺呖呖。"],"source":"元曲"},{"title":"清人","author":"佚名","dynasty":"先秦","form":"诗","lines":["清人在彭，驷介旁旁。二矛重英，河上乎翱翔。","清人在消，驷介麃麃。二矛重乔，河上乎逍遥。","清人在轴，驷介陶陶。左旋右抽，中军作好。"],"source":"《诗经》"},{"title":"旅宿","author":"杜牧","dynasty":"唐","form":"诗","lines":["旅馆无良伴，凝情自悄然。","寒灯思旧事，断鴈警愁眠。","远梦帰侵暁，家书到隔年。","湘江好烟月，门繋钓鱼船。"],"source":"《唐诗三百首》"},{"title":"春晩即事","author":"范成大","dynasty":"宋","form":"诗","lines":["屋头清樾暗荆扉，紫葚斓斑翠荚肥。","春晩轩窗人独困，日长篱落燕双飞。"],"source":"宋诗"},{"title":"瑞龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["黯分袖。","肠断去水流萍，住船系柳。","吴宫娇月娆花，酔题恨倚，蛮江豆蔻。","吐春绣。","笔底丽情多少，眼波眉岫。","新园锁却愁阴，露黄漫委，寒香半亩。","还背垂虹秋去，四桥烟雨，一宵歌酒。","犹忆翠微携壶，乌帽风骤。","西湖到日，重见梅钿皱。","谁家听、琵琶未了，朝骢嘶漏。","印剖黄金籀。","待来共凭，齐云话旧。","莫唱朱樱口。","生怕遣、楼前行云知后。","泪鸿怨角，空教人痩。"],"source":"宋词"},{"title":"卖花声煞・愁山闷海不许当敌，好教我无一个百刂划，耐心儿多陪下些凄","author":"关汉卿","dynasty":"元","form":"曲","lines":["惶泪。","呼侍婢将绣帘低放，把重门深闭，怕莺花笑人憔悴。"],"source":"元曲"},{"title":"羔裘","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔裘如濡，洵直且侯。彼其之子，舎命不渝。","羔裘豹饰，孔武有力。彼其之子，邦之司直。","羔裘晏兮，三英粲兮。彼其之子，邦之彦兮。"],"source":"《诗经》"},{"title":"早秋三首 一","author":"许浑","dynasty":"唐","form":"诗","lines":["遥夜泛清瑟，西风生翠萝。","残蛍委玉露，早鴈払银河。","高树暁还密，远山晴更多。","淮南一叶下，自覚老烟波。"],"source":"《唐诗三百首》"},{"title":"春晩三首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["阴阴垂柳闭朱门，一曲阑干一断魂。","手把青梅春已去，満城风雨怕黄昏。"],"source":"宋诗"},{"title":"瑞龙吟","author":"吴文英","dynasty":"宋","form":"词","lines":["大渓面。","遥望绣羽冲烟，锦棱飞练。","桃花三十六陂，鲛宫睡起，娇雷乍转。","去如箭。","催趁戏旗游鼓，素澜雪溅。","东风冷湿蛟腥，澹阴送昼，轻霏弄晩。","洲上青苹生处，斗春不管，怀沙人远。","残日半开一川，花影零乱。","山屏酔缬，连棹东西岸。","阑干倒、千红妆靥，铅香不断。","傍暝疏帘巻。","翠涟皱净，笙歌未散。","簪柳门归懒。","犹自有、玉龙黄昏吹怨。","重云暗阁，春霖一片。"],"source":"宋词"},{"title":"幺・天付两风流，翻成南北悠悠，落花流水人何处？相思一点，离愁几许，","author":"关汉卿","dynasty":"元","form":"曲","lines":["撮上心头。"],"source":"元曲"},{"title":"遵大路","author":"佚名","dynasty":"先秦","form":"诗","lines":["遵大路兮，掺执子之袪兮。无我恶兮，不蓵故也！","遵大路兮，掺执子之手兮。无我魗兮，不蓵好也！"],"source":"《诗经》"},{"title":"秋日赴阙题潼関駅楼","author":"许浑","dynasty":"唐","form":"诗","lines":["红叶晩萧萧，长亭酒一瓢。","残云帰太华，疏雨过中条。","树色随山迥，河声入海遥。","帝郷明日到，犹自梦渔樵。"],"source":"《唐诗三百首》"},{"title":"春晩三首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["客去钩窗咏小诗，游糸撩乱柳花稀。","微风尽日吹芳草，蝴蝶双双贴地飞。"],"source":"宋诗"},{"title":"大","author":"吴文英","dynasty":"宋","form":"词","lines":["峭石帆収，归期差，林沼年销红碧。","渔蓑樵笠畔，买佳邻翻盖，浣花新宅。","地凿桃阴，天澄藻镜，聊与渔郎分席。","沧波耕不砕，似蓝田初种，翠烟生璧。","料情属新莲，梦惊春草，断桥相识。","平生江海客。","秀怀抱、云锦当秋织。","任岁晩、陶篱菊暗，逋冢梅荒，总输玉井尝甘液。","忍弃红香叶。","集楚裳、西风催着。","正明月、秋无极。","归隐何处，门外垂杨天窄。","放船五湖夜色。"],"source":"宋词"},{"title":"荼コ香・记得初相守，偶尔间因循成就，美满効绸缪。花朝月夜同宴赏，","author":"关汉卿","dynasty":"元","form":"曲","lines":["佳节须酬，到今一旦休。","常言道好事天悭，美姻缘他娘间阻，生拆散鸾交凤友。"],"source":"元曲"},{"title":"女曰鸡鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["女曰鸡鸣，士曰昧旦。子兴视夜，明星有烂。将翱将翔，弋凫与雁。","弋言加之，与子宜之。宜言饮酒，与子偕老。琴瑟在御，莫不静好。","知子之来之，杂佩以赠之。知子之顺之，杂佩以问之。知子之好之，杂佩以报之。"],"source":"《诗经》"},{"title":"寄人 一","author":"张泌","dynasty":"唐","form":"诗","lines":["别梦依依到谢家，小廊回合曲阑斜。","多情只有春庭月，犹为离人照落花。"],"source":"《唐诗三百首》"},{"title":"春晩三首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["夕阳槐影上帘钩，一枕清风梦昔游。","梦见銭塘春尽処，碧桃花谢水西流。"],"source":"宋诗"},{"title":"解蹀躞","author":"吴文英","dynasty":"宋","form":"词","lines":["酔云又兼醒雨，楚梦时来往。","倦蜂刚着梨花、惹游荡。","还作一段相思，冷波叶舞愁红，送人双桨。","暗凝想。","情共天涯秋黯，朱桥锁深巷。","会稀投得轻分、顿惆怅。","此去幽曲谁来，可怜残照西风，半妆楼上。"],"source":"宋词"},{"title":"幺・坐想行思，伤怀感旧，各辜负了星前月下深深呪。愿不损，愁不煞，","author":"关汉卿","dynasty":"元","form":"曲","lines":["神天还佑。","他有日不测相逢，话别离情取一场消痩。"],"source":"元曲"},{"title":"有女同车","author":"佚名","dynasty":"先秦","form":"诗","lines":["有女同车，颜如舜华。将翱将翔，佩玉琼琚。彼美孟姜，洵美且都。","有女同行，颜如舜英。将翱将翔，佩玉将将。彼美孟姜，徳音不忘。"],"source":"《诗经》"},{"title":"陇西行四首 二","author":"陈陶","dynasty":"唐","form":"诗","lines":["誓扫匈奴不顾身，五千貂锦丧胡尘。","可怜无定河辺骨，犹是春闺梦里人。"],"source":"《唐诗三百首》"},{"title":"楽先生辟新堂以待芍薬酴醿作诗奉赠","author":"范成大","dynasty":"宋","form":"诗","lines":["芍薬有国色，酴醿乃天香。","二妙绝世立，百草为不芳。","先生绝俗姿，风味本无双。","年来悟结习，欲试安心方。","天魔巧伺便，作计回刚肠。","多情开此花，艳绝温柔郷。","道人为一笑，正尔未易忘。","呼童葺荷芷，択胜开轩窗。","啼鶑不愁思，游蜂亦猖狂。","百年颦呻顷，共此过隙光。","朝为春条绿，暮为秋叶黄。","把玩尚无几，况以忧愁妨。","愿言秉烛游，迨此春宵长。"],"source":"宋诗"},{"title":"江神子・江城子","author":"吴文英","dynasty":"宋","form":"词","lines":["天街如水翠尘空。","建章宫。","月明中。","人未归来，玉树起秋风。","宝栗万钉花露重，催赐带，过垂虹。","夜凉沈水绣帘栊。","酒香浓。","雾蒙蒙。","钗列吴娃，騕袅带金虫。","三十六宫蟾观冷，留不住，佩丁东。"],"source":"宋词"},{"title":"好观音煞・与怪友狂朋寻花柳，时复间和哄消愁。对着浪蕊浮花懒回首，","author":"关汉卿","dynasty":"元","form":"曲","lines":["怏怏归来，原不饮杯中酒。"],"source":"元曲"},{"title":"山有扶苏","author":"佚名","dynasty":"先秦","form":"诗","lines":["山有扶苏，隰有荷华。不见子都，乃见狂且。","山有乔松，隰有游龙，不见子充，乃见狡童。"],"source":"《诗经》"},{"title":"颂古三十二首  其二三","author":"釈明弁","dynasty":"唐","form":"诗","lines":["打起黄莺児，莫教枝上啼。","几回惊妾梦，不得到辽西。"],"source":"《唐诗三百首》"},{"title":"题城山晩対轩壁","author":"范成大","dynasty":"宋","form":"诗","lines":["一枕清风梦绿萝，人间随処是南柯。","也知睡足当帰去，不奈渓山留客何。"],"source":"宋诗"},{"title":"江神子・江城子","author":"吴文英","dynasty":"宋","form":"词","lines":["西风来晩桂开迟。","月宫移。","到东篱。","簌簌惊尘，吹下半冰规。","拟唤阿娇来小隐，金屋低，乱香飞。","重阳还是隔年期。","蝶相思。","客情知。","吴水吴烟，愁里更多诗。","一夜看承应未别，秋好处，雁来时。"],"source":"宋词"},{"title":"大石调・青杏子骋怀","author":"关汉卿","dynasty":"元","form":"曲","lines":["花月酒家楼，可追欢亦可悲秋。","悲欢聚散为常事，明眸皓齿，歌莺舞燕，各逞温柔。"],"source":"元曲"},{"title":"萚兮","author":"佚名","dynasty":"先秦","form":"诗","lines":["萚兮萚兮，风其吹女。叔兮伯兮，倡予和女。","萚兮萚兮，风其漂女。叔兮伯兮，倡予要女。"],"source":"《诗经》"},{"title":"后宫词","author":"白居易","dynasty":"唐","form":"诗","lines":["涙湿罗巾梦不成，夜深前殿按歌声。","红颜未老恩先断，斜倚薫笼坐到明。"],"source":"《唐诗三百首》"},{"title":"题城山挂月堂壁","author":"范成大","dynasty":"宋","form":"诗","lines":["百畳烟鬟得眼明，坐来心迹喜双清。","秋阳満地西风起，犹有啼鶑四五声。"],"source":"宋诗"},{"title":"江神子・江城子","author":"吴文英","dynasty":"宋","form":"词","lines":["西风一叶送行舟。","浅迟留。","舣汀洲。","新浴红衣，绿水带香流。","应是离宫城外晩，人伫立，小帘钩。","新归重省别来愁。","黛眉头。","半痕秋。","天上人间，斜月绣针楼。","湘浪莫迷花蝶梦，江上约，负轻鸥。"],"source":"宋词"},{"title":"幺・人俊惜风流，欠前生酒病花愁。尚还不彻相思债，携云挈雨，批风切","author":"关汉卿","dynasty":"元","form":"曲","lines":["月，到处绸缪。"],"source":"元曲"},{"title":"狡童","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼狡童兮，不与我言兮。维子之故，使我不能餐兮。","彼狡童兮，不与我食兮。维子之故，使我不能息兮。"],"source":"《诗经》"},{"title":"喜见外弟又言别","author":"李益","dynasty":"唐","form":"诗","lines":["十年离乱后，长大一相逢。","问姓惊初见，称名忆旧容。","别来沧海事，语罢暮天钟。","明日巴陵道，秋山又几重。"],"source":"《唐诗三百首》"},{"title":"姑悪","author":"范成大","dynasty":"宋","form":"诗","lines":["姑悪妇所云，恐是妇偏辞。","姑言妇悪定有之，妇言姑悪未可知。","姑不悪，妇不死。","与人作妇亦大难，已死人言尚如此。"],"source":"宋诗"},{"title":"沁园春","author":"吴文英","dynasty":"宋","form":"词","lines":["澄碧西湖，软红南陌，银河地穿。","见华星影里，仙棋局静，清风行处，瑞玉圭寒。","斜谷山深，望春楼远，无此峥嵘小渭川。","一泓地，解新波不涸，独障狂澜。","老苏而后坡仙。","继菊井嘉名相与传。","试摩挲劲石，无令角折，丁宁明月，莫涴规圆。","漫结鸥盟，那知鱼乐，心止中流别有天。","无尘夜，听吾伊正在，秋水阑干。"],"source":"宋词"},{"title":"催拍子・爱共寝花间锦鸠，恨孤眠水上白鸥。月宵花昼，大筵排回雪韦娘，","author":"关汉卿","dynasty":"元","form":"曲","lines":["小酌会窃香韩寿。","举觞红袖，玉纤横管，银甲调筝，酒令诗筹。","曲成诗就，韵协声律，情动魂消，腹稿冥捜，美恩当受。","水仙山鬼，月妹花妖，如还得遇，不许干休，会埋伏未尝泄漏。"],"source":"元曲"},{"title":"褰裳","author":"佚名","dynasty":"先秦","form":"诗","lines":["子恵思我，褰裳渉溱。子不我思，岂无他人？狂童之狂也且！","子恵思我，褰裳渉洧。子不我思，岂无他士？狂童之狂也且！"],"source":"《诗经》"},{"title":"江南词","author":"李益","dynasty":"唐","form":"诗","lines":["嫁得瞿塘贾，朝朝悮妾期。","早知潮有信，嫁与弄潮児。"],"source":"《唐诗三百首》"},{"title":"大暑舟行含山道中雨骤至霆奔竜挂可骇","author":"范成大","dynasty":"宋","form":"诗","lines":["𬯎云暧前駆，连鼓讧后殿。","骎骎失高丘，扰扰暗古県。","白竜起幽蛰，黒雾佐神変。","盆倾耳双聩，斗暗目四眩。","帆重腹逾饱，橹润鸣更健。","円漪晕雨点，溅滴走波面。","伶俜愁孤鸳，飐闪乱饥燕。","麦老枕水卧，秧穉与风戦。","牛蹊岌城沉，蚁隧汹瓴建。","水车竞施行，歳事敢休宴。","咿唖啸簧鸣，𫐆辘连锁転。","骈头立妇子，列舎望宗伴。","东枯骇西溃，寸涸惊尺淀。","嗟余岂能贤，与彼亦何弁。","扁舟风露熟，半世江湖徧。","不知忧稼穑，但解加餐饭。","遥怜老农苦，敢厌游子倦。"],"source":"宋诗"},{"title":"江神子・江城子","author":"吴文英","dynasty":"宋","form":"词","lines":["情如之何，暮涂为客，忍堪送君。","便江湖天远，中宵同月，关河秋近，何日清尘。","玉尘生风，貂裘明雪，幕府英雄今几人。","行须早，料刚肠肯𣨼，泪眼离颦。","平生秀句清尊。","到帐东风开自有神。","听夜鸣黄鹤，楼高百尺，朝驰白马，笔扫千军。","贾傅才高，岳家军在，好勒燕然石上文。","松江上，念故人老矣，甘卧闲云。"],"source":"宋词"},{"title":"幺・群芳会首，繁英故友，梦回时绿肥红痩。荣华过可见蔬薄，财物广始","author":"关汉卿","dynasty":"元","form":"曲","lines":["知亲厚。","慕新思旧，簪遗佩解，镜破钗分，蜂妒蝶羞。","恶缘难救，痼疾常发，业贯将盈，努力呈头。","冷餐重馏，口刀舌剑，吻槊唇枪，独攻决胜，混战无忧，不到得落人奸彀。"],"source":"元曲"},{"title":"丰","author":"佚名","dynasty":"先秦","form":"诗","lines":["子之丰兮，俟我乎巷兮，悔予不送兮。","子之昌兮，俟我乎堂兮，悔予不将兮。","衣锦褧衣，裳锦褧裳。叔兮伯兮，驾予与行。","裳锦褧裳，衣锦褧衣。叔兮伯兮，驾予与归。"],"source":"《诗经》"},{"title":"夜上受降城闻笛","author":"李益","dynasty":"唐","form":"诗","lines":["回楽峰前沙似雪，受降城下月如霜。","不知何処吹芦管，一夜征人尽望郷。"],"source":"《唐诗三百首》"},{"title":"题画巻五首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["凿落秋江水石明，高枫老柳両滩横。","君看畳𪩘云容変，又有中宵雨意生。"],"source":"宋诗"},{"title":"珍珠帘・真珠帘","author":"吴文英","dynasty":"宋","form":"词","lines":["蜜沈烬暖萸烟袅。","层帘巻、伫立行人官道。","麟带压愁香，听舞箫云渺。","恨缕情丝春絮远，怅梦隔、银屏难到。","寒峭。","有东风嫩柳，学得腰小。","还近绿水清明，叹孤身如燕，将花平绕。","细雨湿黄昏，半酔归怀抱。","蠹损歌纨人去久，漫泪沾、香兰如笑。","书杳。","念客枕幽单，看看春老。"],"source":"宋词"},{"title":"天净沙・平生肥马轻裘，何须锦带吴钩？百岁光阴转首，休闲生受，叹功","author":"关汉卿","dynasty":"元","form":"曲","lines":["名似水上浮沤。"],"source":"元曲"},{"title":"东门之𫮃","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之𫮃，茹藘在阪。其室则迩，其人甚远。","东门之栗，有践家室。岂不尔思？子不我即！"],"source":"《诗经》"},{"title":"聴筝","author":"李端","dynasty":"唐","form":"诗","lines":["鸣筝金粟柱，素手玉房前。","欲得周郎顾，时时误払弦。"],"source":"《唐诗三百首》"},{"title":"题画巻五首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["欹倾桟路绕山明，隔陇人家犬吠声。","无限白云堆去路，不知谁识许宣平。"],"source":"宋诗"},{"title":"风入松","author":"吴文英","dynasty":"宋","form":"词","lines":["春风吴柳几番黄。","欢事小蛮窗。","梅花正结双头梦，被玉龙、吹散幽香。","昨夜灯前歌黛，今朝陌上啼妆。","最怜无侣伴雏莺。","桃叶已春江。","曲屏先暖鸳衾惯，夜寒深、都是思量。","莫道蓝桥路远，行云只隔幽坊。"],"source":"宋词"},{"title":"寨儿冷・得自由，莫刚求。茶余饭饱邀故友，谢馆秦楼，散闷消愁，惟蹴","author":"关汉卿","dynasty":"元","form":"曲","lines":["リ最风流。","演习得踢打温柔，施逞得解数滑熟。","引脚蹑龙斩眼，担枪拐凤摇头。","一左一右，折叠鹘胜游。"],"source":"元曲"},{"title":"风雨","author":"佚名","dynasty":"先秦","form":"诗","lines":["风雨凄凄，鸡鸣喈喈，既见君子。云胡不夷？","风雨潇潇，鸡鸣胶胶。既见君子，云胡不瘳？","风雨如晦，鸡鸣不已。既见君子，云胡不喜？"],"source":"《诗经》"},{"title":"贼平后送人北帰","author":"司空曙","dynasty":"唐","form":"诗","lines":["世乱同南去，时清独北还。","他郷生白髪，旧国见青山。","暁月过残塁，繁星宿故関。","寒禽与衰草，処処伴愁颜。"],"source":"《唐诗三百首》"},{"title":"题画巻五首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["春阴十日渓头暗，夜半西风雨脚収。","但覚奔霆吼空谷，遥知万壑正争流。"],"source":"宋诗"},{"title":"风入松","author":"吴文英","dynasty":"宋","form":"词","lines":["听风听雨过清明。","愁草瘗花铭。","楼前绿暗分携路，一丝柳、一寸柔情。","料峭春寒中酒，交加晓梦啼莺。","西园日日扫林亭。","依旧赏新晴。","黄蜂频扑秋千索，有当时、纤手香凝。","惆怅双鸳不到，幽阶一夜苔生。"],"source":"宋词"},{"title":"尾・锦缠腕、叶底桃、鸳鸯叩，入脚面带黄河逆流。斗白打赛官场，三场","author":"关汉卿","dynasty":"元","form":"曲","lines":["儿尽皆有。"],"source":"元曲"},{"title":"子衿","author":"佚名","dynasty":"先秦","form":"诗","lines":["青青子衿，悠悠我心。纵我不往，子宁不嗣音？","青青子佩，悠悠我思。纵我不往，子宁不来？","挑兮达兮，在城阙兮。一日不见，如三月兮。"],"source":"《诗经》"},{"title":"云阳馆与韩绅宿别","author":"司空曙","dynasty":"唐","form":"诗","lines":["故人江海别，几度隔山川。","乍见翻疑梦，相悲各问年。","孤灯寒照雨，湿竹暗浮烟。","更有明朝恨，离杯惜共伝。"],"source":"《唐诗三百首》"},{"title":"题画巻五首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["暑云溌墨送惊雷，坐见前山骤雨来。","今夜一凉千万里，更无焦巻与尘埃。"],"source":"宋诗"},{"title":"风入松","author":"吴文英","dynasty":"宋","form":"词","lines":["兰舟高荡涨波凉。","愁被矮桥妨。","暮烟疏雨西园路，误秋娘、浅约宫黄。","还泊邮亭唤酒，旧曽送客斜阳。","蝉声空曳别枝长。","似曲不成商。","御罗屏底翻歌扇，忆西湖、临水开窗。","和酔重寻幽梦，残衾已断熏香。"],"source":"宋词"},{"title":"越调・斗鹌鹑又","author":"关汉卿","dynasty":"元","form":"曲","lines":["蹴リ场中，鸣珂巷里，南北驰名，寰中可意。","夹缝堪夸，抛声尽喜。","那换活，煞整齐。","款侧金莲，微那玉体。","唐裙轻荡，绣带斜飘，舞袖低垂。"],"source":"元曲"},{"title":"扬之水","author":"佚名","dynasty":"先秦","form":"诗","lines":["扬之水，不流束楚。终鲜兄弟，维予与女。无信人之言，人实诳女。","扬之水，不流束薪。终鲜兄弟，维予二人。无信人之言，人实不信。"],"source":"《诗经》"},{"title":"喜外弟卢纶见宿","author":"司空曙","dynasty":"唐","form":"诗","lines":["静夜四无邻，荒居旧业贫。","雨中黄叶树，灯下白头人。","以我独沈久，愧君相见频。","平生自有分，况是蔡家亲。"],"source":"《唐诗三百首》"},{"title":"题画巻五首  其五","author":"范成大","dynasty":"宋","form":"诗","lines":["秋晩黄芦断岸，江南野水连天。","日色微明鱼网，鴈行飞入苍烟。"],"source":"宋诗"},{"title":"风入松","author":"吴文英","dynasty":"宋","form":"词","lines":["一番疏雨洗芙蓉。","玉冷佩丁东。","辘轳听带秋声转，早凉生、傍井梧桐。","欢宴良宵好月，佳人修竹清风。","临池飞阁乍青红。","移酒小垂虹。","贞元供奉梨园曲，称十香、深蘸琼锺。","酔梦孤云晓色，笙歌一派秋空。"],"source":"宋词"},{"title":"小桃红・装跷委实用心机，不枉了夸强会，女辈丛中最为贵。煞曽习，沾","author":"关汉卿","dynasty":"元","form":"曲","lines":["身那取着田地。","赶起了白踢，诸余里快収拾。"],"source":"元曲"},{"title":"出其东门","author":"佚名","dynasty":"先秦","form":"诗","lines":["出其东门，有女如云。虽则如云。匪我思存。缟衣綦巾，聊乐我员。","出其𬮱阇，有女如荼。虽则如荼，匪我思且。缟衣茹藘，聊可与娱。"],"source":"《诗经》"},{"title":"聴弾琴","author":"刘长卿","dynasty":"唐","form":"诗","lines":["泠泠七糸上，静聴松风寒。","古调虽自爱，今人多不弾。"],"source":"《唐诗三百首》"},{"title":"六月七日夜起坐殿庑取凉","author":"范成大","dynasty":"宋","form":"诗","lines":["畏暑中夜起，出门月露清。","晶荧卧银汉，错落低玉縄。","网戸闭妙香，石楼栖古灯。","风従何処来，殿阁微凉生。","桂旗俨不动，藻井森上征。","榱楣共突兀，鬼物相枝撑。","彭觥鉄拄杖，磔磔栖燕惊。","俗人岂解事，鼻息春雷鸣。","大星送暁来，四窗炯微明。","颢気澡肌骨，栩栩両腋軽。","乗风欲帰去，骖鸾羾青冥。","却恐方平知，浪得狡狯名。"],"source":"宋诗"},{"title":"风入松","author":"吴文英","dynasty":"宋","form":"词","lines":["画船帘密不蔵香。","飞作楚云狂。","傍怀半巻金炉烬，怕暖销、春日朝阳。","清馥晴熏残酔，断烟无限思量。","凭阑心事隔垂杨。","楼燕锁幽妆。","梅花偏恼多情月，慰渓桥、流水昏黄。","哀曲霜鸿凄断，梦魂寒蝶幽扬。"],"source":"宋词"},{"title":"秃厮儿・粉汗湿珍珠乱滴，宝髻偏鸦玉斜堆。虚蹬落实拾蹑起，侧身动，","author":"关汉卿","dynasty":"元","form":"曲","lines":["柳腰脆，丸惜。"],"source":"元曲"},{"title":"野有蔓草","author":"佚名","dynasty":"先秦","form":"诗","lines":["野有蔓草，零露漙兮。有美一人，清扬婉兮。邂逅相遇，适我愿兮。","野有蔓草，零露瀼瀼。有美一人，婉如清扬。邂逅相遇，与子偕臧。"],"source":"《诗经》"},{"title":"送方外上人","author":"刘长卿","dynasty":"唐","form":"诗","lines":["孤云将野鹤，岂向人间住。","莫买沃洲山，时人已知処。"],"source":"《唐诗三百首》"},{"title":"中秋卧病呈同社","author":"范成大","dynasty":"宋","form":"诗","lines":["人间佳风月，浩浩満大千。","俗子不解爱，我乃知其天。","以此有尽姿，玩彼无穷妍。","受用能几何，北溟一杯然。","天公尚龃龉，不肯畀其全。","卧病窘诗料，坐贫羞酒銭。","琼楼与金阙，想像屋角辺。","如闻真率社，胜游若登仙。","四者自难并，造物岂我偏。"],"source":"宋诗"},{"title":"莺啼序","author":"吴文英","dynasty":"宋","form":"词","lines":["天吴驾云阆海，凝春空灿绮。","倒银海、蘸影西城，四碧天镜无际。","彩翼曳、扶摇宛转，雩龙降尾交新霁。","近玉虚高处，天风笑语吹坠。","清濯缁尘，快展旷眼，傍危阑酔倚。","面屏障、一一莺花，薛萝浮动金翠。","惯朝昏、晴光雨色，燕泥动、红香流水。","歩新梯，藐视年华，顿非尘世。","麟翁衮舄，领客登临，座有诵鱼美。","翁笑起、离席而语，敢诧京兆，以役为功，落成奇事。","明良庆会，赓歌熙载，隆都观国多闲暇，遣丹青、雅饰繁华地。","平瞻太极，天街润纳璇题，露床夜沈秋纬。","清风观阙，丽日罘罳，正午长漏迟。","为洗尽、脂痕茸唾，净巻曲尘，永昼低垂，绣帘十二。","高轩驷马，峨冠鸣佩，班回花底修禊饮，御炉香、分惹朝衣袂。","碧桃数点飞花，涌出宫沟，溯春万里。"],"source":"宋词"},{"title":"圣药王・甚旖旎，解数儿希，左盘右折煞曽习。甚整齐，省气力，旁行侧","author":"关汉卿","dynasty":"元","form":"曲","lines":["脚歩频移，来往似粉蝶儿飞。"],"source":"元曲"},{"title":"溱洧","author":"佚名","dynasty":"先秦","form":"诗","lines":["溱与洧，方涣涣兮。士与女，方秉𫈉兮。女曰观乎？士曰既且。且往观乎？","洧之外，洵𬣙且乐。维士与女，伊其相谑，赠之以勺药。","溱与洧，浏其清矣。士与女，殷其盈矣。女曰观乎？士曰既且。且往观乎？","洧之外，洵𬣙且乐。维士与女，伊其将谑，赠之以勺药。"],"source":"《诗经》"},{"title":"送霊澈上人","author":"刘长卿","dynasty":"唐","form":"诗","lines":["苍苍竹林寺，杳杳钟声晩。","荷笠帯夕阳，青山独帰远。"],"source":"《唐诗三百首》"},{"title":"秋日雑兴六首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["我友蓬蒿士，却扫谢四邻。","内无三尺童，外无双蒲轮。","岂非骐骥姿，执辔难其人。","无衣可御冬，忍寒待阳春。","仰云発永叹，夜作寒螀呻。","奓戸勧之起，懐宝善自珍。","秋月耿清夜，秋风卷曽云。","佳哉为谁欤，定为我与君。","莫嫌酒味薄，聊复相歓欣。"],"source":"宋诗"},{"title":"莺啼序","author":"吴文英","dynasty":"宋","form":"词","lines":["残寒正欺病酒，掩沈香绣户。","燕来晩、飞入西城，似说春事迟暮。","画船载、清明过却，晴烟冉冉吴宫树。","念羁情游荡，随风化为轻絮。","十载西湖，傍柳系马，趁娇尘软雾。","溯红渐、招入仙渓，锦儿偷寄幽素。","倚银屏、春宽梦窄，断红湿、歌纨金缕。","暝堤空，轻把斜阳，总还鸥鹭。","幽兰旋老，杜若还生，水乡尚寄旅。","别后访、六桥无信，事往花委，瘗玉埋香，几番风雨。","长波妒盼，遥山羞黛，渔灯分影春江宿，记当时、短楫桃根渡。","青楼彷仏，临分败壁题诗，泪墨惨澹尘土。","危亭望极，草色天涯，吹鬓侵半苎。","暗点检、离痕欢唾，尚染鲛绡，亸凤迷归，破鸾慵舞。","殷勤待写，书中长恨，蓝霞辽海沈过雁，漫相思、弹入哀筝柱。","伤心千里江南，怨曲重招，断魂在否。"],"source":"宋词"},{"title":"尾・不离了花前柳影闲田地，斗白打官场小踢。竿网下世无双，全场儿占","author":"关汉卿","dynasty":"元","form":"曲","lines":["了第一。"],"source":"元曲"},{"title":"鸡鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸡既鸣矣，朝既盈矣。匪鸡则鸣，苍蝇之声。","东方明矣，朝既昌矣。匪东方则明，月出之光。","虫飞薨薨，甘与子同梦。会且归矣，无庶予子憎。"],"source":"《诗经》"},{"title":"新年作","author":"刘长卿","dynasty":"唐","form":"诗","lines":["郷心新歳切，天畔独潸然。","老至居人下，春帰在客先。","岭猨同旦暮，江柳共风烟。","已是长沙傅，従今又几年。"],"source":"《唐诗三百首》"},{"title":"秋日雑兴六首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["夕阳下桑柘，余晖挂西山。","西山在何许，冉冉紫翠间。","彩云无朝昏，绿萝竟暄寒。","昔与霞上人，同跨双飞翰。","上凌紫霄峰，下弄白石湍。","风吹堕渺莽，及此行路难。","佳人応望予，我岂真忘还。"],"source":"宋诗"},{"title":"莺啼序","author":"吴文英","dynasty":"宋","form":"词","lines":["横塘棹穿艳锦，引鸳鸯弄水。","断霞晩、笑折花归，绀纱低护灯蕊。","润玉痩、冰轻倦浴，斜拖凤股盘云坠。","听银床声细。","梧桐渐搅凉思。","窗隙流光，冉冉迅羽，诉空粱燕子。","误惊起、风竹敲门，故人还又不至。","记琅玕、新诗细掐，早陈迹、香痕纤指。","怕因循，罗扇恩疏，又生秋意。","西湖旧日，画舸频移，叹几萦梦寐。","霞佩冷，叠澜不定，麝霭飞雨，乍湿鲛绡，暗盛红泪。","𦈌单夜共，波心宿处，琼箫吹月霓裳舞，向明朝、未觉花容悴。","嫣香易落，回头澹碧销烟，镜空画罗屏裹。","残蝉度曲，唱彻西园，也感红怨翠。","念省惯、吴宫幽憩。","暗柳追凉，晓岸参斜，露零沤起。","丝索寸藕，留连欢事。","桃笙平展湘浪影，有昭华、秾李冰相倚。","如今鬓点凄霜，半箧秋词，恨盈蠹纸。"],"source":"宋词"},{"title":"双调・新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["楚台云雨会巫峡，赴昨宵约来的期话。","楼头栖燕子，庭院已闻鸦，料想他家，収针指晩妆罢。"],"source":"元曲"},{"title":"还","author":"佚名","dynasty":"先秦","form":"诗","lines":["子之还兮，遭我乎狃之间兮。并驱从两肩兮，揖我谓我儇兮。","子之茂兮，遭我乎狃之道兮。并驱从两牡兮，揖我谓我好兮。","子之昌兮，遭我乎狃之阳兮。并驱从两狼兮，揖我谓我臧兮。"],"source":"《诗经》"},{"title":"秋日登呉公台上寺远眺寺即陈将呉明彻戦场","author":"刘长卿","dynasty":"唐","form":"诗","lines":["古台揺落后，秋日望郷心。","野寺人来少，云峰水隔深。","夕阳依旧塁，寒磬満空林。","惆怅南朝事，长江独至今。"],"source":"《唐诗三百首》"},{"title":"秋日雑兴六首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["秋高気弥清，歳晏天雨霜。","繁枝各病绿，况乃枝上香。","向来不胜春，渺在无何郷。","楽极定自悲，谁欤此更张。","春秋无终穷，栄落殊未央。"],"source":"宋诗"},{"title":"天香","author":"吴文英","dynasty":"宋","form":"词","lines":["珠络玲珑，罗囊闲斗，酥怀暖麝相倚。","百和花须，十分风韵，半袭凤箱重绮。","茜垂四角，慵未掲、流苏春睡。","熏度红薇院落，烟销画屏沈水。","温泉降绡乍试。","露华侵、透肌兰泚。","漫省浅渓月夜，暗浮花气。","荀令如今老矣。","但未减、韩郎旧风味。","远寄相思，馀熏梦里。"],"source":"宋词"},{"title":"乔牌儿・款将花径踏，独立在纱窗下，颤钦钦把不定心头怕。不敢将小名","author":"关汉卿","dynasty":"元","form":"曲","lines":["呼，咱则索等候他。"],"source":"元曲"},{"title":"着","author":"佚名","dynasty":"先秦","form":"诗","lines":["俟我于着乎而，充耳以素乎而，尚之以琼华乎而。","俟我于庭乎而，充耳以青乎而，尚之以琼莹乎而。","俟我于堂乎而，充耳以黄乎而，尚之以琼英乎而。"],"source":"《诗经》"},{"title":"寻南渓常山道人隠居","author":"刘长卿","dynasty":"唐","form":"诗","lines":["一路経行処，莓苔见履痕。","白云依静渚，春草闭闲门。","过雨看松色，随山到水源。","渓花与禅意，相対亦忘言。"],"source":"《唐诗三百首》"},{"title":"秋日雑兴六首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["嫣嫣芙蓉花，秀出清霜晨。","众卉已昨梦，孤芳若为新。","寒蜂无儇飞，一笑静自珍。","谁令婵娟姿，堕此寂寞浜。","绝世贵独立，后时莫酸辛。","回风佐小舞，薄日生微醺。","即事亦足楽，何必桃李尘。"],"source":"宋诗"},{"title":"天香","author":"吴文英","dynasty":"宋","form":"词","lines":["蟫叶黏霜，蝇苞缀冻，生香远带风峭。","岭上寒多，渓头月冷，北枝痩、南枝小。","玉奴有姊，先占立、墙阴春早。","初试宫黄澹薄，偷分寿阳纤巧。","银烛泪深未晓。","酒锺悭、贮愁多少。","记得短亭归马，暮衙蜂闹。","豆蔻钗梁恨袅。","但怅望、天涯岁华老。","远信难，吴云雁杳。"],"source":"宋词"},{"title":"挂搭钩・等候多时不见他，这的是约下佳期话，莫不是贪睡人儿忘了那？","author":"关汉卿","dynasty":"元","form":"曲","lines":["伏冢在蓝桥下。","意懊恼却待将他骂，听得呀的门开，蓦见如花。"],"source":"元曲"},{"title":"东方之日","author":"佚名","dynasty":"先秦","form":"诗","lines":["东方之日兮，彼姝者子，在我室兮。在我室兮，履我即兮。","东方之月兮，彼姝者子，在我闼兮。在我闼兮，履我发兮。"],"source":"《诗经》"},{"title":"饯别王十一南游","author":"刘长卿","dynasty":"唐","form":"诗","lines":["望君烟水阔，挥手涙沾巾。","飞鸟没何処，青山空向人。","长江一帆远，落日五湖春。","谁见汀洲上，相思愁白苹。"],"source":"《唐诗三百首》"},{"title":"秋日雑兴六首  其五","author":"范成大","dynasty":"宋","form":"诗","lines":["苍筠如苍玉，郷是磵壑姿。","朅来西窗下，死生付污泥。","虫縁有病叶，土痩无新枝。","太阳岂我偏，檐影为蔽亏。","昔如松柏独，今作蒲柳衰。","暮夜风雨急，歳晏谁与帰。"],"source":"宋诗"},{"title":"玉漏迟","author":"吴文英","dynasty":"宋","form":"词","lines":["雁边风讯小，飞琼望杳，碧云先晩。","露冷阑干，定怯藕丝冰腕。","净洗浮空片玉，胜花影、春灯相乱。","秦镜满。","素娥未肯，分秋一半。","毎圆处既良宵，甚此夕偏饶，对歌临怨。","万里蝉娟，几许雾屏云幔。","孤免凄凉照水，晓风起、银河西转。","摩泪眼。","瑶台梦回人远。"],"source":"宋词"},{"title":"豆叶黄・髻挽乌云，蝉鬓堆鸦，粉腻酥胸，脸衬红霞；袅娜腰肢更喜恰，","author":"关汉卿","dynasty":"元","form":"曲","lines":["堪讲堪夸。","比月里嫦娥，媚媚孜孜，那更撑达。"],"source":"元曲"},{"title":"东方未明","author":"佚名","dynasty":"先秦","form":"诗","lines":["东方未明，颠倒衣裳。颠之倒之，自公召之。","东方未晞，颠倒裳衣。倒之颠之，自公令之。","折柳樊圃，狂夫瞿瞿。不能辰夜，不夙则莫。"],"source":"《诗经》"},{"title":"江州重别薛六柳八二员外","author":"刘长卿","dynasty":"唐","form":"诗","lines":["生涯岂料承优诏，世事空知学酔歌。","江上月明胡鴈过，淮南木落楚山多。","寄身且喜沧洲近，顾影无如白髪何。","今日竜钟人共弃，媿君犹遣慎风波。"],"source":"《唐诗三百首》"},{"title":"秋日雑兴六首  其六","author":"范成大","dynasty":"宋","form":"诗","lines":["屋东双梧桐，婉娩无真姿。","朝为春风条，暮为秋霜枝。","夜久风叶鸣，惊鹊一再飞。","梧桐不足愁，会有明年期。","人老真可叹，宁复游冶时。"],"source":"宋诗"},{"title":"金盏子","author":"吴文英","dynasty":"宋","form":"词","lines":["卜筑西湖，种翠萝犹傍，软红尘裹。","来往载清吟，为偏爱吾庐，画船频繁。","笑携雨色晴光，入春明朝市。","石桥锁，烟霞五百名仙，第一人是。","临酒论深意。","流光转、莺花任乱委。","冷然九秋肺腑，应多梦、岩扃冷云空翠。","漱流枕石幽情，写猗兰绿绮。","专城处，他山小队登临，待西风起。"],"source":"宋词"},{"title":"梅花酒・两情浓，兴转佳。地权为床榻，月高烧银蜡。夜深沉，人静悄，","author":"关汉卿","dynasty":"元","form":"曲","lines":["低低的问如花终是个女儿家。"],"source":"元曲"},{"title":"南山","author":"佚名","dynasty":"先秦","form":"诗","lines":["南山崔崔，雄狐绥绥。鲁道有荡，齐子由归。既曰归止，曷又怀止？","葛屦五两，冠緌双止。鲁道有荡，齐子庸止。既曰庸止，曷又从止？","蓺麻如之何？衡从其亩。取妻如之何？必告父母。既曰告止，曷又鞠止？","析薪如之何？匪斧不克。取妻如之何？匪媒不得。既曰得止，曷又极止？"],"source":"《诗经》"},{"title":"长沙过贾谊宅","author":"刘长卿","dynasty":"唐","form":"诗","lines":["三年谪宦此栖遅，万古惟留楚客悲。","秋草独寻人去后，寒林空见日斜时。","汉文有道恩犹薄，湘水无情吊岂知。","寂寂江山揺落処，怜君何事到天涯。"],"source":"《唐诗三百首》"},{"title":"拟古","author":"范成大","dynasty":"宋","form":"诗","lines":["弯环楼前月，掩抑楼上人。","人月不得语，相看両凝颦。","西窗回纹机，织徧锦字春。","聊可自持玩，何由将寄君。"],"source":"宋诗"},{"title":"金盏子","author":"吴文英","dynasty":"宋","form":"词","lines":["赏月梧园，恨广寒宫树，晓风摇落。","莓砌扫珠尘，空肠断、熏炉烬销残萼。","殿秋尚有馀花，锁烟窗云幄。","新雁又、无端送人江上，短亭初泊。","篱角。","梦依约。","人一笑、惺忪翠袖薄。","悠然酔魂唤醒，幽丛畔、凄香雾雨漠漠。","晩吹乍颤秋声，早屏空金雀。","明朝想，犹有数点蜂黄，伴我斟酌。"],"source":"宋词"},{"title":"収江南・好风吹绽牡丹花，半合儿揉损绛裙纱。冷丁丁舌尖上送香茶，都","author":"关汉卿","dynasty":"元","form":"曲","lines":["不到半霎，森森一向遍身麻。"],"source":"元曲"},{"title":"甫田","author":"佚名","dynasty":"先秦","form":"诗","lines":["无田甫田，维莠骄骄。无思远人，劳心忉忉。","无田甫田，维莠桀桀。无思远人，劳心怛怛。","婉兮娈兮。总角丱兮。未几见兮，突而弁兮！"],"source":"《诗经》"},{"title":"自夏口至鹦鹉洲夕望岳阳寄源中丞","author":"刘长卿","dynasty":"唐","form":"诗","lines":["[汀]洲无浪复无烟，楚客相思益渺然。","汉口夕阳斜渡鸟，洞庭秋水远连天。","孤城背岭寒吹角，独戍临江夜泊船。","贾谊上书忧汉室，长沙谪去古今怜。"],"source":"《唐诗三百首》"},{"title":"立春日郊行","author":"范成大","dynasty":"宋","form":"诗","lines":["竹拥渓桥麦盖坡，土牛行処亦笙歌。","麹尘欲暗垂垂柳，醅面初明浅浅波。","日満県前春市合，潮平浦口暮帆多。","春来不饮兼无句，奈此金旛彩胜何。"],"source":"宋诗"},{"title":"永遇乐","author":"吴文英","dynasty":"宋","form":"词","lines":["春酌沈沈，晩妆的的，仙梦游惯。","锦溆维舟，青门倚盖，还被笼莺唤。","裴郎归后，崔娘沈恨，漫客请传芳巻。","联题在，频经翠袖，胜隔绀纱尘幔。","桃根杏叶，胶黏缃缥，几回凭阑人换。","峨髻愁云，兰香腻粉，都为多情褪。","离巾拭泪，征袍染酔，强作酒朋花伴。","留连怕，风姨浪妒，又吹雨断。"],"source":"宋词"},{"title":"尾・整乌云欲把金莲さ，纽回身再说些儿话：“你明夜个早些儿来，我专","author":"关汉卿","dynasty":"元","form":"曲","lines":["听着纱窗外芭蕉叶儿上打。"],"source":"元曲"},{"title":"卢令","author":"佚名","dynasty":"先秦","form":"诗","lines":["卢令令，其人美且仁。","卢重环，其人美且鬈。","卢重镅，其人美且偲。"],"source":"《诗经》"},{"title":"赋得","author":"刘长卿","dynasty":"唐","form":"诗","lines":["莺啼燕语报新年，马邑竜堆路几千。","家住层城临汉苑，[心]随明月到胡天。","机中锦字论长恨，楼上花枝笑独眠。","为问元戎窦车骑，何时返斾勒燕然。"],"source":"《唐诗三百首》"},{"title":"次韵汉卿舅即事二绝  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["风卷南枝一夜休，孤芳宁肯为人留。","淡妆素服真成梦，落月横参各自愁。"],"source":"宋诗"},{"title":"永遇乐","author":"吴文英","dynasty":"宋","form":"词","lines":["风払尘徽，雨侵凉榻，才动秋思。","缓酒销更，移灯傍影，净洗芭蕉耳。","铜华沧海，愁霾重嶂，燕北雁南天外。","算阴晴，浑似几番，渭城故人离会。","青楼旧日，高歌取酔，唤出玉人梳洗。","红叶流光，苹花两鬓，心事成秋水。","白凝虚晓，香吹轻烬，倚窗小瓶疏桂。","问深宫，姮娥正在，妒云第几。"],"source":"宋词"},{"title":"双调・新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["闲争夺鼎沸了丽春园，欠排场不堪久恋。","时间相敬爱，端的怎团圆？白没事教人笑，惹人怨。"],"source":"元曲"},{"title":"敝笱","author":"佚名","dynasty":"先秦","form":"诗","lines":["敝笱在梁，其鱼鲂鳏。齐子归止，其从如云。","敝笱在梁，其鱼鲂𫚈。齐子归止，其从如雨。","敝笱在梁，其鱼唯唯。齐子归止，其从如水。"],"source":"《诗经》"},{"title":"九日登望仙台呈刘明府容","author":"崔曙","dynasty":"唐","form":"诗","lines":["汉文皇帝有高台，此日登临曙色开。","三晋云山皆北向，二陵风雨自东来。","関门令尹谁能识，河上仙翁去不回。","且欲近寻彭沢宰，陶然共酔菊花杯。"],"source":"《唐诗三百首》"},{"title":"次韵汉卿舅即事二绝  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["万木垂垂欲改柯，根萌焦渇奈春何。","晩来础汗南风壮，会有渓云载雨过。"],"source":"宋诗"},{"title":"永遇乐","author":"吴文英","dynasty":"宋","form":"词","lines":["阁雪云低，巻沙风急，惊雁失序。","户掩寒宵，屏闲冷梦，灯飐唇似语。","堪怜窗景，都闲刺绣，但续旧愁一缕。","邻歌散，罗襟印粉，袖湿茜桃红露。","西湖旧日，留连清夜，爱酒几将花误。","遣袜尘销，题裙墨黯，天远吹笙路。","吴台直下，缃梅无限，未放野桥香度。","重谋酔，揉香弄影，水清浅处。"],"source":"宋词"},{"title":"驻马听・锦阵里争先，紧巻旗幡不再展；花营中挑战，劳拴意马与心猿。","author":"关汉卿","dynasty":"元","form":"曲","lines":["降书执写纳君前，唇枪舌剑难施展。","参破脱空禅，早抽头索甚他人劝。"],"source":"元曲"},{"title":"载驱","author":"佚名","dynasty":"先秦","form":"诗","lines":["载驱薄薄，簟茀朱鞹。鲁道有荡，齐子发夕。","四骊济济，垂辔沵沵。鲁道有荡，齐子岂弟。","汶水汤汤，行人彭彭。鲁道有荡，齐子翱翔。","汶水滔滔，行人儦儦。鲁道有荡，齐了游敖。"],"source":"《诗经》"},{"title":"凉州词二首 一","author":"王翰","dynasty":"唐","form":"诗","lines":["葡萄美酒夜光杯，欲饮琵琶马上催。","酔卧沙场君莫笑，古来征戦几人回。"],"source":"《唐诗三百首》"},{"title":"晩潮","author":"范成大","dynasty":"宋","form":"诗","lines":["东风吹雨晩潮生，畳鼓催船镜里行。","底事今年春涨小，去年曽与画桥平。"],"source":"宋诗"},{"title":"玉胡蝶・玉蝴蝶","author":"吴文英","dynasty":"宋","form":"词","lines":["角断竿鸣疏点，倦萤透隙，低弄书光。","一寸悲秋，生动万种凄凉。","旧衫染、唾凝花碧，别泪想、妆洗蜂黄。","楚魂伤。","雁汀沙冷，来信微茫。","都忘。","孤山旧赏，水沈熨露，岸锦宜霜。","败叶题诗，御沟应不到流湘。","数客路、又随淮月，羡故人、还买吴航。","两凝望。","满城风雨，催送重阳。"],"source":"宋词"},{"title":"天仙子・从今后，识破野狐涎。红粉无情，灾星不现。村酒酽野花浓，再","author":"关汉卿","dynasty":"元","form":"曲","lines":["不粘拈。","当时话儿无应显，好事天悭。"],"source":"元曲"},{"title":"猗嗟","author":"佚名","dynasty":"先秦","form":"诗","lines":["猗嗟昌兮，颀而长兮。抑若扬兮，美目扬兮。巧趋跄兮，射则臧兮。","猗嗟名兮，美目清兮。仪既成兮，终日射侯，不出正兮，展我甥兮。","猗嗟娈兮，清扬婉兮。舞则选兮，射则贯兮，四矢反兮，以御乱兮。"],"source":"《诗经》"},{"title":"秋登兰山寄张五","author":"孟浩然","dynasty":"唐","form":"诗","lines":["北山白云里，隠者自怡悦。","相望试登高，心飞逐鸟灭。","愁因薄暮起，兴是清秋発。","时见帰村人，沙行渡头歇。","天辺树若荠，江畔舟如月。","何当载酒来，共酔重阳节。"],"source":"《唐诗三百首》"},{"title":"一篙","author":"范成大","dynasty":"宋","form":"诗","lines":["一篙新绿浦东西，雪絮漫江鴈不飞。","宿雨才晴风又転，片帆那得及时帰。"],"source":"宋诗"},{"title":"绛都春","author":"吴文英","dynasty":"宋","form":"词","lines":["香深雾暖。","正人在、锦瑟华年深院。","旧日汉宫，分得红兰滋吴苑。","临池羞落梅花片。","弄水月、初匀妆面。","紫烟笼处，双鸾共跨，洞箫低按。","歌管。","红围翠袖，冻云外，似觉东风先转。","绣畔昼迟，花底天宽春无限。","仙郎骄马琼林宴。","待巻上、珠帘教看。","更传莺入新年，宝钗梦燕。"],"source":"宋词"},{"title":"双调・新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["搅闲风吹散楚台云，天对付满怀愁闷。","您那里欢娱嫌夜短，俺寂寞恨长更。","恰似线断风筝，绝鱼雁杳音信。"],"source":"元曲"},{"title":"葛屦","author":"佚名","dynasty":"先秦","form":"诗","lines":["纠纠葛屦，可以履霜？掺掺女手，可以缝裳？要之襋之，好人服之。","好人提提，宛然左辟，佩其象揥。维是褊心，是以为刺。"],"source":"《诗经》"},{"title":"夏日南亭懐辛大","author":"孟浩然","dynasty":"唐","form":"诗","lines":["山光忽西落，池月渐东上。","散髪乗夕凉，开轩卧闲敞。","荷风送香気，竹露滴清响。","欲取鸣琴弾，恨无知音赏。","感此懐故人，中宵労梦想。"],"source":"《唐诗三百首》"},{"title":"碧瓦","author":"范成大","dynasty":"宋","form":"诗","lines":["碧瓦楼头繍幙遮，赤栏桥外绿渓斜。","无风杨柳漫天絮，不雨棠梨満地花。"],"source":"宋诗"},{"title":"绛都春","author":"吴文英","dynasty":"宋","form":"词","lines":["羁云旅雁。","敛倦羽、寄楼墙阴年晩。","问字翠尊，刻烛红笺悭曽展。","冰滩鸣佩舟如箭。","笑乌帻、临风重岸。","傍邻垂柳，清霜万缕，送将人远。","吴苑。","千金未惜，买新赋、共赏文园词翰。","流水翠微，明月清风平分半。","梅深驿路香不断。","万玉舞、罘罳东畔。","料应花底春多，软红雾暖。"],"source":"宋词"},{"title":"驻马听・多绪多情，病身躯憔悴损；闲愁闲闷，将柳带结同心。痩岩岩宽","author":"关汉卿","dynasty":"元","form":"曲","lines":["褪了绛绡裙，羞答答恐怕他邻姬问。","若道伤春，今年更比年时甚。"],"source":"元曲"},{"title":"汾沮洳","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼汾沮洳，言采其莫。彼其之子，美无度。美无度，殊异乎公路。","彼汾一方，言采其桑。彼其之子，美如英。美如英，殊异乎公行。","彼汾一曲，言采其藚。彼其之子，美如玉。美如玉，殊异乎公族。"],"source":"《诗经》"},{"title":"宿业师山房期丁大不至","author":"孟浩然","dynasty":"唐","form":"诗","lines":["夕阳度西岭，群壑倏已暝。","松月生夜凉，风泉満清聴。","樵人帰欲尽，烟鸟栖初定。","之子期宿来，孤琴候萝迳。"],"source":"《唐诗三百首》"},{"title":"题记事册","author":"范成大","dynasty":"宋","form":"诗","lines":["划破虚空一剣间，六根同転上头関。","如今宴坐庵中事，政在凡夫道法间。"],"source":"宋诗"},{"title":"绛都春","author":"吴文英","dynasty":"宋","form":"词","lines":["螺屏暖翠。","正雾巻暮色，星河浮霁。","路幕递香，街马冲尘东风细。","梅槎凌海横鳌背。","倩稳载、蓬莱云气。","宝阶斜转，冰峨素影，夜清如水。","应记。","千秋化鹤，旧华表、认得山川犹是。","暗解绣囊，争掷金钱游人酔。","笙歌晓度晴霞外。","又上苑、春生一苇。","便教接宴莺花，万红镜裹。"],"source":"宋词"},{"title":"幺・早是我愁怀闷哽，更那堪四扇帏屏。遣人愁，添人恨，无端怨煞丹青。","author":"关汉卿","dynasty":"元","form":"曲","lines":["画得来双双厮配定，做得伤情对景。"],"source":"元曲"},{"title":"园有桃","author":"佚名","dynasty":"先秦","form":"诗","lines":["园有桃，其实之肴。心之忧矣，我歌且谣。不知我者，谓我士也骄。","彼人是哉，子曰何其？心之忧矣，其谁知之？其谁知之，盖亦勿思！","园有棘，其实之食。心之忧矣，聊以行国。不知我者，谓我士也罔极。","彼人是哉，子曰何其？心之忧矣，其谁知之？其谁知之，盖亦勿思！"],"source":"《诗经》"},{"title":"夜帰鹿门山歌","author":"孟浩然","dynasty":"唐","form":"诗","lines":["山寺钟鸣昼已昏，渔梁渡头争渡喧。","人随沙路向江村，余亦乗舟帰鹿门。","鹿门月照开烟树，忽到庞公栖隠処。","巌扉松径长寂寥，惟有幽人夜来去。"],"source":"《唐诗三百首》"},{"title":"暮春上塘道中","author":"范成大","dynasty":"宋","form":"诗","lines":["店舎无烟野水寒，竞船人酔鼓阑珊。","石门柳绿清明市，洞口桃红上巳山。","飞絮着人春共老，片云将梦晩俱还。","明朝遮日长安道，惭愧江湖钓手闲。"],"source":"宋诗"},{"title":"绛都春","author":"吴文英","dynasty":"宋","form":"词","lines":["情黏舞线。","怅驻马灞桥，天寒人远。","旋翦露痕，移得春娇栽琼苑。","流莺常语烟中怨。","恨三月、飞花零乱。","艳阳归后，红蔵翠掩，小坊幽院。","谁见。","新腔按彻，背灯暗、共倚筼屏葱茜。","绣被梦轻，金屋妆深沈香换。","梅花重洗春风面。","正渓上、参横月转。","并禽飞上金沙，瑞香雾暖。"],"source":"宋词"},{"title":"天仙子・一扇儿画着双通叔，和苏氏到予章城；一扇儿是司马文君；一扇","author":"关汉卿","dynasty":"元","form":"曲","lines":["儿是王魁桂英。","画的来厮顾盼厮温存，比各青春。","这一扇儿比他毎情更深，是君瑞莺莺。"],"source":"元曲"},{"title":"陟岵","author":"佚名","dynasty":"先秦","form":"诗","lines":["陟彼岵兮，瞻望父兮。父曰：嗟！予子行役，夙夜无已。上慎旃哉，犹来！无止！","陟彼屺兮，瞻望母兮。母曰：嗟！予季行役，夙夜无寐。上慎旃哉，犹来！无弃！","陟彼冈兮，瞻望兄兮。兄曰：嗟！予弟行役，夙夜必偕。上慎旃哉，犹来！无死！"],"source":"《诗经》"},{"title":"望洞庭湖赠张丞相","author":"孟浩然","dynasty":"唐","form":"诗","lines":["八月湖水平，涵虚混太清。","気蒸云梦沢，波撼岳阳城。","欲済无舟楫，端居耻圣明。","坐観垂钓者，空有羡鱼情。"],"source":"《唐诗三百首》"},{"title":"江上","author":"范成大","dynasty":"宋","form":"诗","lines":["天色无情淡，江声不断流。","古人愁不尽，留与后人愁。"],"source":"宋诗"},{"title":"绛都春","author":"吴文英","dynasty":"宋","form":"词","lines":["南楼坠燕。","又灯晕夜凉，疏帘空巻。","叶吹暮喧，花露晨晞秋光短。","当时明月娉婷伴。","怅客路、幽扃俱远。","雾鬟依约，除非照影，镜空不见。","别馆。","秋娘乍识，似人处、最在双波凝盼。","旧色旧香，闲雨闲云情终浅。","丹青谁画真真面。","便只作、梅花频看。","更愁花变梨霙，又随梦散。"],"source":"宋词"},{"title":"随煞・您团圆偏俺孤另，拥被和衣坐等。听鼓打四更过，搭伏定鸳鸯枕头","author":"关汉卿","dynasty":"元","form":"曲","lines":["儿等。"],"source":"元曲"},{"title":"十亩之间","author":"佚名","dynasty":"先秦","form":"诗","lines":["十亩之间兮，桑者闲闲兮，行与子还兮。","十亩之外兮，桑者泄泄兮，行与子逝兮。"],"source":"《诗经》"},{"title":"秦中感秋寄远上人","author":"孟浩然","dynasty":"唐","form":"诗","lines":["一丘常欲卧，三径苦无资。","北土非吾愿，东林懐我师。","黄金然桂尽，壮志逐年衰。","日夕凉风至，闻蝉但益悲。"],"source":"《唐诗三百首》"},{"title":"余杭道中","author":"范成大","dynasty":"宋","form":"诗","lines":["落花流水浅深红，尽日帆飞繍浪中。","桑眼迷离応欠雨，麦须騒杀已禁风。","牛羊路杳千山合，鶏犬村深一径通。","五柳能消多许地，客程何苦镇匆匆。"],"source":"宋诗"},{"title":"绛都春","author":"吴文英","dynasty":"宋","form":"词","lines":["春来雁渚。","弄艳冶、又入垂杨如许。","困舞痩腰，啼湿宫黄池塘雨。","碧沿苍藓云根路。","尚追想、凌波微歩。","小楼重上，凭谁为唱，旧时金缕。","凝伫。","烟萝翠竹，欠罗袖、为倚天寒日暮。","强酔梅边，招得花奴来尊俎。","东风须惹春云住。","□莫把、飞琼吹去。","便教移取熏笼，夜温绣户。"],"source":"宋词"},{"title":"双调・新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["寨儿中风月煞经谙，収心也合搠淹。","再不缠头戴蜀锦，沽酒典春衫。","心如柳絮粘泥，狂风过怎摇撼。"],"source":"元曲"},{"title":"伐檀","author":"佚名","dynasty":"先秦","form":"诗","lines":["坎坎伐檀兮，置之河之干兮。河水清且涟猗。不稼不穑，胡取禾三百廛兮？","不狩不猎，胡瞻尔庭有县貆兮？彼君子兮，不素餐兮！","坎坎伐辐兮，置之河之侧兮。河水清且直猗。不稼不穑，胡取禾三百亿兮？","不狩不猎，胡瞻尔庭有县特兮？彼君子兮，不素食兮！","坎坎伐轮兮，置之河之漘兮。河水清且沦猗。不稼不穑，胡取禾三百囷兮？","不狩不猎，胡瞻尔庭有县鹑兮？彼君子兮，不素飧兮！"],"source":"《诗经》"},{"title":"宿桐庐江寄広陵旧游","author":"孟浩然","dynasty":"唐","form":"诗","lines":["山暝闻猿愁，沧江急夜流。","风鸣両岸叶，月照一孤舟。","建徳非吾土，维扬忆旧游。","还将両行涙，遥寄海西头。"],"source":"《唐诗三百首》"},{"title":"陈侍御园坐上","author":"范成大","dynasty":"宋","form":"诗","lines":["愁眼逢歓春水明，诗情得酒春云生。","花梢蝴蝶作団去，竹里鹁鸠相対鸣。","邂逅浮生此日好，缠绵俗累何时軽。","擘牋沫墨乏奇句，𢬍笛当筵惭妙声。"],"source":"宋诗"},{"title":"惜秋华","author":"吴文英","dynasty":"宋","form":"词","lines":["细响残蛩，傍灯前、似说深秋怀抱。","怕上翠微，伤心乱烟残照。","西湖镜掩尘沙，翳晓影、秦鬟云扰。","新鸿，唤凄凉、渐入红萸乌帽。","江上故人老。","视东篱秀色，依然娟好。","晩梦趁、邻杵断，乍将愁到。","秋娘泪湿黄昏，又满城、雨轻风小。","闲了。","看芙蓉、画船多少。"],"source":"宋词"},{"title":"夜行船・又引起往前风月胆，今番做得尴。且休说久远当来，奈何时暂，","author":"关汉卿","dynasty":"元","form":"曲","lines":["这些时陡羞惨。"],"source":"元曲"},{"title":"硕鼠","author":"佚名","dynasty":"先秦","form":"诗","lines":["硕鼠硕鼠，无食我黍！三岁贯女，莫我肯顾。逝将去女，适彼乐土。乐土乐土，爰得我所。","硕鼠硕鼠，无食我麦！三岁贯女，莫我肯徳。逝将去女，适彼乐国。乐国乐国，爰得我直。","硕鼠硕鼠，无食我苗！三岁贯女，莫我肯劳。逝将去女，适彼乐郊。乐郊乐郊，谁之永号？"],"source":"《诗经》"},{"title":"早寒江上有懐","author":"孟浩然","dynasty":"唐","form":"诗","lines":["木落雁南度，北风江上寒。","我家襄水上，遥隔楚云端。","郷涙客中尽，孤帆天际看。","迷津欲有问，平海夕漫漫。"],"source":"《唐诗三百首》"},{"title":"独游虎跑泉小庵","author":"范成大","dynasty":"宋","form":"诗","lines":["苔径弯环入，茅斎取次成。","蔓花縁壁起，闲草上阶生。","宿雨松篁色，新晴燕雀声。","筒泉烹御米，聊共老僧倾。"],"source":"宋诗"},{"title":"惜秋华","author":"吴文英","dynasty":"宋","form":"词","lines":["思渺西风，怅行踪、浪逐南飞高雁。","怯上翠微，危楼更堪凭晩。","蓬莱对起幽云，澹野色山容愁巻。","清浅。","瞰沧波、静衔秋痕一线。","十载寄吴苑。","惯东篱深把，露黄偷翦。","移暮影、照越镜，意销香断。","秋娥赋得闲情，倚翠尊、小眉初展。","深劝。","待明朝、酔巾重岸。"],"source":"宋词"},{"title":"天仙子・咱非参，坏怪斗来搀。怎肯袄庙火绝，蓝桥水淹。难掩盖泼风声，","author":"关汉卿","dynasty":"元","form":"曲","lines":["被各俱耽。","怎只恁两下里阻隔情分减，面北眉南。"],"source":"元曲"},{"title":"蟋蟀","author":"佚名","dynasty":"先秦","form":"诗","lines":["蟋蟀在堂，岁聿其莫。今我不乐，日月其除。无已大康，职思其居。好乐无荒，良士瞿瞿。","蟋蟀在堂，岁聿其逝。今我不乐，日月其迈。无已大康，职思其外。好乐无荒，良士蹶蹶。","蟋蟀在堂，役车其休。今我不乐，日月其慆。无以大康。职思其忧。好乐无荒，良士休休。"],"source":"《诗经》"},{"title":"留别王侍御维","author":"孟浩然","dynasty":"唐","form":"诗","lines":["寂寂竟何待，朝朝空自帰。","欲寻芳草去，惜与故人违。","当路谁相仮，知音世所稀。","秪応守索寞，还掩故园扉。"],"source":"《唐诗三百首》"},{"title":"王希武通判挽词二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["当代名臣后，惟公奕世贤。","及亲三釜养，遗子一経伝。","薬石探奇字，芸香缉断编。","堂堂今不见，尘迹自依然。"],"source":"宋诗"},{"title":"惜秋华","author":"吴文英","dynasty":"宋","form":"词","lines":["露罥蛛丝，小楼阴堕月，秋惊华鬓。","宫漏未央，当时钿钗遗恨。","人间梦隔西风，算天上、年华一瞬。","相逢，纵相疏、胜却巫阳无准。","和处动凉讯。","听露井梧桐，楚骚成韵。","彩云断、翠羽散，此情难问。","银河万古秋声，但望中、婺星清润。","轻俊。","度金针、漫牵方寸。"],"source":"宋词"},{"title":"离亭宴煞・你休起风波剁断渔舟缆，得团圆摔破青铜鉴。冤家行再三，再","author":"关汉卿","dynasty":"元","form":"曲","lines":["三嘱付勤相探。","常将好事贪，却休教花星暗。","万一问休将人倒赚，眼挫了可憎才，心疼煞志诚俺。"],"source":"元曲"},{"title":"山有枢","author":"佚名","dynasty":"先秦","form":"诗","lines":["山有枢，隰有楡。子有衣裳，弗曳弗娄。子有车马，弗驰弗驱。宛其死矣，他人是愉。","山有栲，隰有杻。子有廷内，弗洒弗扫。子有钟鼓，弗鼓弗考。宛其死矣，他人是保。","山有漆，隰有栗。子有酒食，何不日鼓瑟？且以喜乐，且以永日。宛其死矣，他人入室。"],"source":"《诗经》"},{"title":"清明日宴梅道士房","author":"孟浩然","dynasty":"唐","form":"诗","lines":["林卧愁春尽，开轩覧物华。","忽逢青鸟使，邀入赤松家。","丹竃初开火，仙桃正落花。","童颜若可驻，何惜酔流霞。"],"source":"《唐诗三百首》"},{"title":"王希武通判挽词二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["事契従先世，姻连亦近亲。","遽为重壌去，凄断十年邻。","物理真飘忽，家声正隠辚。","门阑可三戟，何止驷车云。"],"source":"宋诗"},{"title":"惜秋华","author":"吴文英","dynasty":"宋","form":"词","lines":["数日西风，打秋林枣熟，还催人去。","瓜果夜深，斜河拟看星度。","葱葱便倒离尊，怅遇合、云销萍聚。","留连，有残蝉韵晩，时歌金缕。","绿水暂如许。","奈南墙冷落，竹烟槐雨。","此去杜曲，已近紫霄尺五。","扁舟夜宿吴江，正水佩霓裳无数。","眉妩。","问别来、解相思否。"],"source":"宋词"},{"title":"双调・新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["凤凰台上忆吹箫，似钱塘梦魂初觉。","花月约，凤鸾交，半世疏狂，总做了一场懊。"],"source":"元曲"},{"title":"扬之水","author":"佚名","dynasty":"先秦","form":"诗","lines":["扬之水，白石凿凿。素衣朱襮，从子于沃。既见君子，云何不乐？","扬之水，白石皓皓。素衣朱绣，从子于鹄。既见君子，云何其忧？","扬之水，白石粼粼。我闻有命，不敢以告人。"],"source":"《诗经》"},{"title":"与诸子登岘山","author":"孟浩然","dynasty":"唐","form":"诗","lines":["人事有代谢，往来成古今。","江山留胜迹，我辈复登临。","水落鱼梁浅，天寒梦沢深。","羊公碑字在，読罢涙沾襟。"],"source":"《唐诗三百首》"},{"title":"剧暑","author":"范成大","dynasty":"宋","form":"诗","lines":["赫赫炎官张伞，啾啾赤帝骑竜。","安得雷轰九地，会令雨起千峰。"],"source":"宋诗"},{"title":"惜秋华","author":"吴文英","dynasty":"宋","form":"词","lines":["路远仙城，自王郎去后，芳卿憔悴。","锦段镜空，重铺歩障新绮。","凡花痩不禁秋，幻腻玉、腴红鲜丽。","相携。","试新妆乍毕，交扶轻酔。","长记断桥外。","骤玉骢过处，千娇凝睇。","昨梦顿醒，依约旧时眉翠。","愁边暮合碧云，倩唱入、六幺声里。","风起。","舞斜阳、阑干十二。"],"source":"宋词"},{"title":"驻马听・黄诏奢豪，桑木剑熬乏古定刀；双郎穷薄，纸糊锹撅了点刚锹。","author":"关汉卿","dynasty":"元","form":"曲","lines":["怕不待争锋取债恋多娇，又索书名画字寻人保。","枉徒劳，供钱买笑教人笑。"],"source":"元曲"},{"title":"椒聊","author":"佚名","dynasty":"先秦","form":"诗","lines":["椒聊之实，蕃衍盈升。彼其之子，硕大无朋。椒聊且，远条且。","椒聊之实，蕃衍盈匊。彼其之子，硕大且笃。椒聊且，远条且。"],"source":"《诗经》"},{"title":"过故人荘","author":"孟浩然","dynasty":"唐","form":"诗","lines":["故人具鶏黍，邀我至田家。","绿树村辺合，青山郭外斜。","开筵面场圃，把酒话桑麻。","待到重阳日，还来就菊花。"],"source":"《唐诗三百首》"},{"title":"次韵时叙","author":"范成大","dynasty":"宋","form":"诗","lines":["新春残春一梦间，梦中兀兀长闭関。","今朝出门春已去，但见新笋斉屋山。","作诗惜春聊复尔，春亦何能与人事。","闲心如絮久沾泥，但爱日长添午睡。"],"source":"宋诗"},{"title":"惜黄花慢","author":"吴文英","dynasty":"宋","form":"词","lines":["粉靥金裳。","映绣屏认得，旧日萧娘。","翠微高处，故人帽底，一年最好，偏是重阳。","避春祗怕春不远，望幽径、偷理秋妆。","𣨼酔乡。","寸心似翦，飘荡愁觞。","潮腮笑入清霜。","斗万花样巧，深染蜂黄。","露痕千点，自怜旧色，寒泉半掬，百感幽香。","雁声不到东篱畔，满城但、风雨凄凉。","最断肠。","夜深怨蝶飞狂。"],"source":"宋词"},{"title":"落梅风・姨夫闹，咱便晓，君子不夺人之好。他揽定磨杆儿夸俏，推不动","author":"关汉卿","dynasty":"元","form":"曲","lines":["磨杆上自吊。"],"source":"元曲"},{"title":"绸缪","author":"佚名","dynasty":"先秦","form":"诗","lines":["绸缪束薪，三星在天。今夕何夕，见此良人？子兮子兮，如此良人何？","绸缪束刍，三星在隅。今夕何夕，见此邂逅？子兮子兮，如此邂逅何？","绸缪束楚，三星在户。今夕何夕，见此粲者？子兮子兮，如此粲者何？"],"source":"《诗经》"},{"title":"歳暮帰南山","author":"孟浩然","dynasty":"唐","form":"诗","lines":["北阙休上书，南山帰敝庐。","不才明主弃，多病故人疏。","白髪催年老，青阳逼歳除。","永懐愁不寐，松月夜窗虚。"],"source":"《唐诗三百首》"},{"title":"夜宴曲","author":"范成大","dynasty":"宋","form":"诗","lines":["金麟喷香烟竜蟠，玉灯九枝青阑干。","明琼翠带湘帘斑，风帏繍浪千飞鸾。","舞娥紫袖如弓弯，云中一笑天解颜。","衔杯快巻玻璃干，花楼促箭春宵寒，二十五声宫点阑。"],"source":"宋诗"},{"title":"惜黄花慢","author":"吴文英","dynasty":"宋","form":"词","lines":["送客吴皐。","正试霜夜冷，枫落长桥。","望天不尽，背城渐杳，离亭黯黯，恨水迢迢。","翠香零落红衣老，暮愁锁、残柳眉梢。","念痩腰。","沈郎旧日，曽系兰桡。","仙人凤咽琼箫。","怅断魂送远，九弁难招。","酔鬟留盼，小窗翦烛，歌云载恨，飞上银霄。","素秋不解随船去，败红趁、一叶寒涛。","梦翠翘。","怨鸿料过南谯。"],"source":"宋词"},{"title":"歩歩娇・积趱下三十两通行鸦青钞，买取个大笠子粗麻罩。妆甚腰，眼落","author":"关汉卿","dynasty":"元","form":"曲","lines":["处和他契丹交。","虽是不风骚，不到得着圏套。"],"source":"元曲"},{"title":"杕杜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有杕之杜，其叶湑湑。独行踽踽。岂无他人？不如我同父。嗟行之人，胡不比焉？人无兄弟，胡不佽焉？","有杕之杜，其叶箐箐。独行睘睘。岂无他人？不如我同姓。嗟行之人，胡不比焉？人无兄弟，胡不佽焉？"],"source":"《诗经》"},{"title":"歳除夜有懐","author":"孟浩然","dynasty":"唐","form":"诗","lines":["迢逓三巴路，羁危万里身。","乱山残雪夜，孤灯异郷人。","渐与骨肉远，転于奴仆亲。","那堪正飘泊，来日歳华新。"],"source":"《唐诗三百首》"},{"title":"神弦","author":"范成大","dynasty":"宋","form":"诗","lines":["双娥一去三千秋，粉篁春涙凝古愁。","神鼍悲鸣老竜怨，水为翻澜云为留。","素空逗露晩花泣，神官行水鳞僮湿。","潮声不平江风急，苍梧冥茫九山立。"],"source":"宋诗"},{"title":"十二郎・二郎神","author":"吴文英","dynasty":"宋","form":"词","lines":["素天际水，浪拍砕、冻云不凝。","记晓叶题霜，秋灯吟雨，曽系长桥过艇。","又是宾鸿重来后，猛赋得、归期才定。","嗟绣鸭解言，香鲈堪钓，尚庐人境。","幽兴。","争如共载，越娥妆镜。","念倦客依前，貂裘茸帽，重向淞江照影。","酹酒苍茫，倚歌平远，亭上玉虹腰冷。","迎酔面，暮雪飞花，几点黛愁山暝。"],"source":"宋词"},{"title":"甜水令・佳人有意郎君俏，郎君没钞莺花恼。如今等惜花人弄巧，指不过","author":"关汉卿","dynasty":"元","form":"曲","lines":["美话儿排，虚科儿套，实心儿少。","想着月下情，星前约，是则是花木瓜儿看好。","李亚仙负心疾，郑元和下番早。"],"source":"元曲"},{"title":"羔裘","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔裘豹祛，自我人居居。岂无他人？维子之故。","羔裘豹褎，自我人究究。岂无他人？维子之好。"],"source":"《诗经》"},{"title":"春暁","author":"孟浩然","dynasty":"唐","form":"诗","lines":["春眠不覚暁，処処闻啼鸟。","夜来风雨声，花落知多少。"],"source":"《唐诗三百首》"},{"title":"楽神曲","author":"范成大","dynasty":"宋","form":"诗","lines":["豚蹄満盘酒満杯，清风萧萧神欲来。","愿神好来复好去，男児拝迎女児舞。","老翁翻香笑且言，今年田家胜去年。","去年解衣折租価，今年有衣着祭社。"],"source":"宋诗"},{"title":"酔蓬莱","author":"吴文英","dynasty":"宋","form":"词","lines":["望碧天书断，宝枕香留，泪痕盈袖。","谁识秋娘，比行云纤痩。","象尺熏炉，翠针金缕，记倚床同绣。","月亸琼梳，冰销粉汗，南花熏透。","尽是当时，少年清梦，臂约痕深，帕绡红皱。","凭鹊传音，恨语多轻漏。","润玉留情，沈郎无奈，向柳阴期候。","数曲催阑，双铺深掩，风环鸣兽。"],"source":"宋词"},{"title":"庆东原・或向幽窗下，或向曲槛前，春纤相对摇纨扇。闲凭着玉肩，双歌","author":"关汉卿","dynasty":"元","form":"曲","lines":["《采莲》，斗抚冰弦。","遂却少年心，称了于飞愿。"],"source":"元曲"},{"title":"鸨羽","author":"佚名","dynasty":"先秦","form":"诗","lines":["肃肃鸨羽，集于苞栩。王事靡盬，不能蓺稷黍。父母何怙？悠悠苍天，曷其有所？","肃肃鸨翼，集于苞棘。王事靡盬，不能蓺黍稷。父母何食？悠悠苍天，曷其有极？","肃肃鸨行，集于苞桑，王事靡盬，不能蓺稲梁。父母何尝？悠悠苍天，曷其有常？"],"source":"《诗经》"},{"title":"宿建徳江","author":"孟浩然","dynasty":"唐","form":"诗","lines":["移舟泊烟渚，日暮客愁新。","野旷天低树，江清月近人。"],"source":"《唐诗三百首》"},{"title":"缲糸行","author":"范成大","dynasty":"宋","form":"诗","lines":["小麦青青大麦黄，原头日出天色凉。","姑妇相呼有忙事，舎后煮茧门前香。","缲车嘈嘈似风雨，茧厚糸长无断缕。","今年那暇织绢着，明日西门売糸去。"],"source":"宋诗"},{"title":"烛影摇红","author":"吴文英","dynasty":"宋","form":"词","lines":["西子西湖，赋情合载鸱夷棹。","断桥直去是孤山，应为梅花到。","几度吟昏酔晓。","背东风、偷闲斗草。","乱鸦啼后，解佩归来，春怀多少。","千里蝉娟，茂园今夜同清照。","樱脂茸唾听吟诗，争似还家好。","昵昵西窗语笑。","凤云深、琼箫缥缈。","顾春如旧，柳带同心，花枝压帽。"],"source":"宋词"},{"title":"早乡词・九秋天，三径边，绽黄花遍撒金钱。露春纤把花笑捻，捧金杯酒","author":"关汉卿","dynasty":"元","form":"曲","lines":["频劝，畅好是风流如五柳庄前。"],"source":"元曲"},{"title":"无衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["岂曰无衣七兮？不如子之衣，安且吉兮！","岂曰无衣六兮？不如子之衣，安且燠兮！"],"source":"《诗经》"},{"title":"蜀道难","author":"李白","dynasty":"唐","form":"诗","lines":["噫吁戯！危乎高哉！蜀道之难难于上青天！蚕丛及鱼凫，开国何茫然。","尔来四万八千歳，不与秦塞通人烟。","西当太白有鸟道，可以横绝峨眉巅。","地崩山摧壮士死，然后天梯石桟相钩连。","上有六竜回日之高标，下有冲波逆折之回川。","黄鹤之飞尚不得过，猨猱欲度愁攀援。","青泥何盘盘，百歩九折萦巌峦。","扪参歴井仰胁息，以手抚膺坐长叹。","问君西游何时还？畏途巉巌不可攀。","但见悲鸟号古木，雄飞雌従绕林间。","又闻子规啼夜月，愁空山，蜀道之难难于上青天，使人聴此凋朱颜。","连峰去天不盈尺，枯松倒挂倚绝壁。","飞湍瀑流争喧豗，砅厓転石万壑雷。","其険也如此，嗟尔远道之人胡为乎来哉！劒阁峥嵘而崔嵬，一夫当関，万夫莫开。","所守或匪亲，化为狼与豺。","朝避猛虎，夕避长蛇。","磨牙吮血，杀人如麻。","锦城虽云楽，不如早还家。","蜀道之难难于上青天，侧身西望长咨嗟。"],"source":"《唐诗三百首》"},{"title":"田家留客行","author":"范成大","dynasty":"宋","form":"诗","lines":["行人莫笑田家小，门戸虽低堪洒扫。","大児繋馿桑树辺，小児払席软胜毡。","木臼新舂雪花白，急炊香饭来看客。","好人入门百事宜，今年不忧蚕麦遅。"],"source":"宋诗"},{"title":"烛影摇红","author":"吴文英","dynasty":"宋","form":"词","lines":["新月侵阶，彩云林外笙箫透。","银台双引绕花行，红坠香沾袖。","不管签声转漏。","更明朝、棋消永昼。","静中闲看，倦羽飞还，游云出岫。","随处春光，翠阴那只西湖柳。","去年渓上牡丹时，还试长安酒。","都把愁怀抖擞。","笑流莺、啼春漫漫痩。","晓风恶尽，妒雪寒销，青梅如豆。"],"source":"宋词"},{"title":"挂打沽・浅浅江梅驿使传，乱剪砕鹅毛片。旋剖温橙列着玳筵，玉液着金","author":"关汉卿","dynasty":"元","form":"曲","lines":["瓶旋。","酒晕红，新妆面，人道是穷冬，我道是虚言。"],"source":"元曲"},{"title":"有杕之杜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有杕之杜，生于道左。彼君子兮，噬肯适我？中心好之，曷饮食之？","有杕之杜，生于道周。彼君子兮，噬肯来游？中心好之，曷饮食之？"],"source":"《诗经》"},{"title":"将进酒","author":"李白","dynasty":"唐","form":"诗","lines":["君不见黄河之水天上来，奔流到海不复回。","君不见高堂明镜悲白髪，朝如青糸暮成雪。","人生得意须尽歓，莫使金樽空対月。","天生我材必有用，千金散尽还复来。","烹羊宰牛且为楽，会须一饮三百杯。","岑夫子，丹丘生，将进酒，君莫停。","与君歌一曲，请君为我侧耳聴。","钟鼓馔玉不足贵，但愿长酔不愿醒。","古来圣贤皆寂寞，惟有饮者留其名。","陈王昔时宴平楽，斗酒十千恣讙谑。","主人何为言少銭，径须沽取対君酌。","五花马，千金裘，呼児将出换美酒，与尔同销万古愁。"],"source":"《唐诗三百首》"},{"title":"催租行","author":"范成大","dynasty":"宋","form":"诗","lines":["输租得钞官更催，踉蹡里正敲门来。","手持文书雑嗔喜，我亦来営酔帰耳。","床头悭囊大如拳，扑破正有三百銭。","不堪与君成一酔，聊复偿君草鞋费。"],"source":"宋诗"},{"title":"烛影摇红","author":"吴文英","dynasty":"宋","form":"词","lines":["飞尽西园，晩秋却胜春天气。","霜花开尽锦屏空，红叶新装缀。","时放清杯泛水。","暗凄凉、东风旧事。","夜吟不绝，松影阑干，月笼寒翠。","莫唱阳关，但凭彩袖歌千岁。","秋星入梦隔明朝，十载吴宫会。","一棹回潮度苇。","正西窗、灯花报喜。","柳蛮樱素，试酒争怜，不教不酔。"],"source":"宋词"},{"title":"石竹子・夜夜嬉游赛上元，朝朝宴乐赏禁烟。密爱幽欢不能恋，无奈被名","author":"关汉卿","dynasty":"元","form":"曲","lines":["缰利锁牵。"],"source":"元曲"},{"title":"葛生","author":"佚名","dynasty":"先秦","form":"诗","lines":["葛生蒙楚，蔹蔓于野。予美亡此，谁与？独处？","葛生蒙棘，蔹蔓于域。予美亡此，谁与？独息？","角枕粲兮，锦衾烂兮。予美亡此，谁与？独旦？","夏之日，冬之夜。百岁之后，归于其居。","冬之夜，夏之日。百岁之后，归于其室。"],"source":"《诗经》"},{"title":"客夜与故人偶集","author":"戴叔伦","dynasty":"唐","form":"诗","lines":["天秋月又満，城阙夜千重。","还作江南会，翻疑梦里逢。","风枝惊暗鹊，露草覆寒蛩。","羁旅长堪酔，相留畏暁钟。"],"source":"《唐诗三百首》"},{"title":"缄口翁","author":"范成大","dynasty":"宋","form":"诗","lines":["君子取中道，常在语黙间。","多言固自费，不语良独难。","此翁身如郑文渊，弁如悬河思如泉。","迩来缄口欲挂壁，嗫嚅畏客翻可怜。","君不见东家玉壶本弟兄，叩之犹解语分明。","愿闻胚浑甚深义，定自能令一座倾。"],"source":"宋诗"},{"title":"赤壁词・念奴娇","author":"陆游","dynasty":"宋","form":"词","lines":["禁门锺晓，忆君来朝路，初翔鸾鹄。","西府中台推独歩，行对金莲宫烛。","蹙绣华鞯，仙葩宝带，看即飞腾速。","人生难料，一尊此地相属。","回首紫陌青门，西湖闲院，锁千梢修竹。","素壁栖鸦应好在，残梦不堪重续。","岁月惊心，功名看镜，短鬓无多绿。","一欢休惜，与君同酔浮玉。"],"source":"宋词"},{"title":"酔也摩挲・真个索去也幺天，真个索去也幺天！再要团圆，动是经年，思","author":"关汉卿","dynasty":"元","form":"曲","lines":["量杀俺也幺天！。"],"source":"元曲"},{"title":"采苓","author":"佚名","dynasty":"先秦","form":"诗","lines":["采苓采苓，首阳之巅。人之为言，苟亦无信。舎旃舎旃，苟亦无然。人之为言，胡得焉？","采苦采苦，首阳之下。人之为言，苟亦无与。舎旃舎旃，苟亦无然。人之为言，胡得焉？","采葑采葑，首阳之东。人之为言，苟亦无从。舎旃舎旃，苟亦无然。人之为言，胡得焉？"],"source":"《诗经》"},{"title":"和张仆射塞下曲 一","author":"卢纶","dynasty":"唐","form":"诗","lines":["鹫翎金仆姑，燕尾繍蝥弧。","独立扬新令，千営共一呼。"],"source":"《唐诗三百首》"},{"title":"春思","author":"范成大","dynasty":"宋","form":"诗","lines":["沙际绿苹満，楼头芳树多。","光风入网戸，罗幕生繍波。","前年花开忆湘水，今年花开涙如洗。","园树伤心三见花，依旧银屏梦千里。"],"source":"宋诗"},{"title":"浣渓沙","author":"陆游","dynasty":"宋","form":"词","lines":["懒向沙头酔玉瓶。","唤君同赏小窗明。","夕阳吹角最关情。","忙日苦多闲日少，新愁常续旧愁生。","客中无伴怕君行。"],"source":"宋词"},{"title":"相公爱・晩宿在孤村闷怎生眠，伴人离愁月当轩。月圆，人几时圆？不似","author":"关汉卿","dynasty":"元","form":"曲","lines":["他南楼上斗婵娟。"],"source":"元曲"},{"title":"车邻","author":"佚名","dynasty":"先秦","form":"诗","lines":["有车邻邻，有马白颠。未见君子，寺人之令。","阪有漆，隰有栗。既见君子，并坐鼓瑟。今者不乐，逝者其耋。","阪有桑，隰有杨。既见君子，并坐鼓簧。今者不乐，逝者其亡。"],"source":"《诗经》"},{"title":"和张仆射塞下曲 二","author":"卢纶","dynasty":"唐","form":"诗","lines":["林暗草惊风，将军夜引弓。","平明寻白羽，没在石棱中。"],"source":"《唐诗三百首》"},{"title":"次韵汉卿舅腊梅二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["垂垂痩萼泫微霜，剪剪繊英锁暗香。","金雀钗头金蛱蝶，春风伝得旧宫妆。"],"source":"宋诗"},{"title":"浣渓沙","author":"陆游","dynasty":"宋","form":"词","lines":["浴罢华清第二汤。","红绵扑粉玉肌凉。","娉婷初试藕丝裳。","凤尺裁成猩血色，螭奁熏透麝脐香。","水亭幽处捧霞觞。"],"source":"宋词"},{"title":"胡十八・天配合俏姻眷，分拆开并头莲。思量席上与樽前，天生的自然，","author":"关汉卿","dynasty":"元","form":"曲","lines":["那些儿体面。","也是俺心上有，常常的梦中见。"],"source":"元曲"},{"title":"驷驖","author":"佚名","dynasty":"先秦","form":"诗","lines":["驷驖孔阜，六辔在手。公之媚子，从公于狩。","奉时辰牡，辰牡孔硕。公曰左之，舎抜则获。","游于北园，四马既闲。𬨎车鸾镳，载猃歇骄。"],"source":"《诗经》"},{"title":"和张仆射塞下曲 三","author":"卢纶","dynasty":"唐","form":"诗","lines":["月黒鴈飞高，単于夜遁逃。","欲将軽骑逐，大雪満弓刀。"],"source":"《唐诗三百首》"},{"title":"次韵汉卿舅腊梅二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["湘袂朝天紫锦裳，光风微度绛霄香。","寿阳信美无仙骨，空把心情学澹妆。"],"source":"宋诗"},{"title":"青玉案","author":"陆游","dynasty":"宋","form":"词","lines":["西风挟雨声翻浪。","恰洗尽、黄茅瘴。","老惯人间齐得丧。","千岩高卧，五湖归棹，替却凌烟像。","故人小驻平戎帐。","白羽腰间气何壮。","我老渔樵君将相。","小槽红酒，晩香丹茘，记取蛮江上。"],"source":"宋词"},{"title":"一锭银・心友毎相邀列着管弦，却子待欢解动凄然。十分酒十分悲怨，却","author":"关汉卿","dynasty":"元","form":"曲","lines":["不道怎生般消遣。"],"source":"元曲"},{"title":"小戎","author":"佚名","dynasty":"先秦","form":"诗","lines":["小戎俴収，五楘梁辀。游环胁驱，阴靷鋈续。文茵畅毂，驾我骐馵。","言念君子，温其如玉。在其板屋，乱我心曲。","四牡孔阜，六辔在手。骐骝是中，䯄骊是骖。龙盾之合，鋈以觼𫐇。","言念君子，温其在邑。方何为期？胡然我念之！","俴驷孔群，厹矛鋈𬭚。蒙伐有苑，虎韔镂膺。交韔二弓，竹闭绲縢。","言念君子，载寝载兴。厌厌良人，秩秩徳音。"],"source":"《诗经》"},{"title":"和张仆射塞下曲 四","author":"卢纶","dynasty":"唐","form":"诗","lines":["野幕敞琼筵，羌戎贺労旋。","酔和金甲舞，雷鼓动山川。"],"source":"《唐诗三百首》"},{"title":"宿东寺二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["淡天如水雾如尘，残雪和霜冻瓦鳞。","织女无言千古恨，素娥有意十分春。"],"source":"宋诗"},{"title":"水调歌头","author":"陆游","dynasty":"宋","form":"词","lines":["江左占形胜，最数古徐州。","连山如画，佳处缥渺着危楼。","鼓角临风悲壮，烽火连空明灭，往事忆孙刘。","千里曜戈甲，万灶宿貔貅。","露沾草，风落木，岁方秋。","使君宏放，谈笑洗尽古今愁。","不见襄阳登览，磨灭游人无数，遗恨黯难収。","叔子独千载，名与汉江流。"],"source":"宋词"},{"title":"不拝门・酒入愁肠闷怎生言，疏竹萧萧西风战。如年，如年似长夜天，正","author":"关汉卿","dynasty":"元","form":"曲","lines":["是恰黄昏庭院。"],"source":"元曲"},{"title":"蒹葭","author":"佚名","dynasty":"先秦","form":"诗","lines":["蒹葭苍苍，白露为霜。所谓伊人，在水一方。溯洄从之，道阻且长。溯游从之，宛在水中央。","蒹葭萋萋，白露未晞。所谓伊人，在水之湄。溯洄从之，道阻且跻。溯游从之，宛在水中坻。","蒹葭采采，白露未已。所谓伊人，在水之涘。溯洄从之，道阻且右。溯游从之，宛在水中沚。"],"source":"《诗经》"},{"title":"晩次鄂州","author":"卢纶","dynasty":"唐","form":"诗","lines":["云开远见汉阳城，犹是孤帆一日程。","估客昼眠知浪静，舟人夜语覚潮生。","三湘衰鬓逢秋色，万里帰心対月明。","旧业已随征戦尽，更堪江上鼓鼙声。"],"source":"《唐诗三百首》"},{"title":"宿东寺二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["一声黄鹄夜深帰，栖雀惊鸣触殿扉。","北斗半垂楼阁外，风旛浑欲上云飞。"],"source":"宋诗"},{"title":"浪淘沙","author":"陆游","dynasty":"宋","form":"词","lines":["绿树暗长亭。","几把离尊。","阳关常恨不堪闻。","何况今朝秋色里，身是行人。","清泪浥罗巾。","各自消魂。","一江离恨恰平分。","安得千寻横铁锁，截断烟津。"],"source":"宋词"},{"title":"金盏子・咱无缘，风流十全。尽可怜，芙蓉面。腕松着金钏，鬓贴着翠钿，","author":"关汉卿","dynasty":"元","form":"曲","lines":["脸朵着秋莲。","眼去眉来相思恋，春山摇，秋波转。"],"source":"元曲"},{"title":"终南","author":"佚名","dynasty":"先秦","form":"诗","lines":["终南何有？有条有梅。君子至止，锦衣狐裘。颜如渥丹，其君也哉！","终南何有？有纪有堂。君子至止，黻衣绣裳。佩玉将将，寿考不忘！"],"source":"《诗经》"},{"title":"李端公","author":"卢纶","dynasty":"唐","form":"诗","lines":["故関衰草遍，离别自堪悲。","路出寒云外，人帰暮雪时。","少孤为客早，多难识君遅。","掩涙空相向，风尘何処期。"],"source":"《唐诗三百首》"},{"title":"范老前歳相别约帰括苍便游四明今不知何地暇日有懐","author":"范成大","dynasty":"宋","form":"诗","lines":["春色重来意未阑，故人一去肯复还。","括苍洞天扫旧隠，补陀海岸寻神山。","杖屦云烟远游楽，衣裳风雪行路难。","鸿飞冥冥鴎浩荡，安得置之鶏鹜间。"],"source":"宋诗"},{"title":"定风波","author":"陆游","dynasty":"宋","form":"词","lines":["敧帽垂鞭送客回。","小桥流水一枝梅。","衰病逢春都不记。","谁谓。","幽香却解逐人来。","安得身闲频置酒。","携手。","与君看到十分开。","少壮相从今雪鬓。","因甚。","流年羁恨两相催。"],"source":"宋词"},{"title":"也不罗・只听得乐声喧，列着华筵，聚集诸亲眷。首先一盏拦门劝，走马","author":"关汉卿","dynasty":"元","form":"曲","lines":["身劳倦。"],"source":"元曲"},{"title":"黄鸟","author":"佚名","dynasty":"先秦","form":"诗","lines":["交交黄鸟，止于棘。谁从穆公？子车奄息。维此奄息，百夫之特。","临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！","交交黄鸟，止于桑。谁从穆公？子车仲行。维此仲行，百夫之防。","临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！","交交黄鸟，止于楚。谁从穆公？子车针虎。维此针虎，百夫之御。","临其穴，惴惴其栗。彼苍者天，歼我良人！如可赎兮，人百其身！"],"source":"《诗经》"},{"title":"过香积寺","author":"王维","dynasty":"唐","form":"诗","lines":["不知香积寺，数里入云峰。","古木无人迳，深山何処钟。","泉声咽危石，日色冷青松。","薄暮空潭曲，安禅制毒竜。"],"source":"《唐诗三百首》"},{"title":"癸亥日泊舟呉会亭","author":"范成大","dynasty":"宋","form":"诗","lines":["去年春盘浙江駅，湛湛清波动浮石。","今年春盘呉会亭，冥冥细雨湿高城。","天辺作客风沙里，今年去年成老矣。","客心古井冷无波，过眼人情亦如水。","忆昔三生住翠微，偶来平地着征衣。","山中故人応大笑，扁舟坐穏何当帰。"],"source":"宋诗"},{"title":"南乡子","author":"陆游","dynasty":"宋","form":"词","lines":["归梦寄吴樯。","水驿江程去路长。","想见芳洲初系缆，斜阳。","烟树参差认武昌。","愁鬓点新霜。","曽是朝衣染御香。","重到故乡交旧少，凄凉。","却恐它乡胜故乡。"],"source":"宋词"},{"title":"喜人心・人丛里遥见，半遮着罗扇，可喜的风流业冤，两叶眉儿未展。百","author":"关汉卿","dynasty":"元","form":"曲","lines":["般的陪告，一创的求和，只管里熬煎。","他越将个庞儿变，咱百般的难分弁。"],"source":"元曲"},{"title":"晨风","author":"佚名","dynasty":"先秦","form":"诗","lines":["𫛣彼晨风，郁彼北林。未见君子，忧心钦钦。如何如何，忘我实多！","山有苞栎，隰有六駮。未见君子，忧心靡乐。如何如何，忘我实多！","山有苞棣，隰有树檖。未见君子，忧心如酔。如何如何，忘我实多！"],"source":"《诗经》"},{"title":"山居秋暝","author":"王维","dynasty":"唐","form":"诗","lines":["空山新雨后，天気晩来秋。","明月松间照，清泉石上流。","竹喧帰浣女，莲动下渔舟。","随意春芳歇，王孙自可留。"],"source":"《唐诗三百首》"},{"title":"时叙火后意不釈然作诗解之","author":"范成大","dynasty":"宋","form":"诗","lines":["潘郎暁衾梦蘧蘧，舞马竟与融风俱。","前駆炎官后热属，席卷不贷渊明庐。","君家十年四立壁，震风凌雨啼妻孥。","平生白眼盖九州，闭戸不纳结驷车。","清贫往往被鬼笑，付与一炬相揶揄。","井垔木刊乌鼠赭，汝则暂戯吾何辜。","天阙悠悠虎豹怒，叱阍上诉非良図。","作诗聊复相料理，甑堕已破空踟蹰。","浮生适来且适去，况此茅屋三间余。","扫除劫灰得空阔，新月恰上东墙隅。","幕天席地正可楽，为君鼓旗助歌呼。"],"source":"宋诗"},{"title":"南乡子","author":"陆游","dynasty":"宋","form":"词","lines":["早岁入皇州。","尊酒相逢尽胜流。","三十年来真一梦，堪愁。","客路萧萧两鬓秋。","蓬峤偶重游。","不待人嘲我自羞。","看镜倚楼俱已矣，扁舟。","月笛烟蓑万事休。"],"source":"宋词"},{"title":"风流体・胡猜咱，胡猜咱居帝辇，和别人、和别人相留恋。上放着、上放","author":"关汉卿","dynasty":"元","form":"曲","lines":["着赐福天，你不知、你不知神明见。"],"source":"元曲"},{"title":"无衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["岂曰无衣？与子同袍。王于兴师，修我戈矛。与子同仇！","岂曰无衣？与子同泽。王于兴师，修我矛戟。与子偕作！","岂曰无衣？与子同裳。王于兴师，修我甲兵。与子偕行！"],"source":"《诗经》"},{"title":"终南别业","author":"王维","dynasty":"唐","form":"诗","lines":["中歳颇好道，晩家南山陲。","兴来毎独往，胜事空自知。","行到水穷処，坐看云起时。","偶然值林叟，谈笑无还期。"],"source":"《唐诗三百首》"},{"title":"题汤致远运使所蔵隆师四図 欠伸","author":"范成大","dynasty":"宋","form":"诗","lines":["春风吹梦蓦江飞，行尽江南只片时。","深院无人自惊覚，夕阳芳树乳鸦啼。","背立妆台髻鬟懒，镜鸾応见茸茸眼。","不须回首更嫣然，刘郎已自无肠断。"],"source":"宋诗"},{"title":"满江红","author":"陆游","dynasty":"宋","form":"词","lines":["危堞朱栏，登览处、一江秋色。","人正似、征鸿社燕，几番轻别。","缱绻难忘当日语，凄凉又作它乡客。","问鬓边、都有几多丝，真堪织。","杨柳院，秋千陌。","无限事，成虚掷。","如今何处也，梦魂难觅。","金鸭微温香缥渺，锦茵初展情萧瑟。","料也应、红泪伴秋霖，灯前滴。"],"source":"宋词"},{"title":"忽都白・我半载来孤眠，信口胡言，枉了把我冤也幺冤。打听的真实，有","author":"关汉卿","dynasty":"元","form":"曲","lines":["人曽见，母亲跟前，恁儿情愿，一任当刑宪，死而心无怨。"],"source":"元曲"},{"title":"渭阳","author":"佚名","dynasty":"先秦","form":"诗","lines":["我送舅氏，曰至渭阳。何以赠之？路车乗黄。","我送舅氏，悠悠我思。何以赠之？琼瑰玉佩。"],"source":"《诗经》"},{"title":"帰嵩山作","author":"王维","dynasty":"唐","form":"诗","lines":["清川帯长薄，车马去闲闲。","流水如有意，暮禽相与还。","荒城临古渡，落日満秋山。","迢逓嵩高下，帰来且闭関。"],"source":"《唐诗三百首》"},{"title":"题汤致远运使所蔵隆师四図 倦繍","author":"范成大","dynasty":"宋","form":"诗","lines":["猧児弄煖縁阶走，花気薫人浓似酒。","困来如酔复如愁，不管低鬟钗燕溜。","无端心绪向天涯，想见樯竿旛脚斜。","槐阴忽到帘旌上，遅却寻常一线花。"],"source":"宋诗"},{"title":"满江红","author":"陆游","dynasty":"宋","form":"词","lines":["疏蕊幽香，禁不过、晩寒愁绝。","那更是、巴东江上，楚山千叠。","敧帽闲寻西瀼路，亸鞭笑向南枝说。","恐使君、归去上銮坡，孤风月。","清镜里，悲华发。","山驿外，渓桥侧。","凄然回首处，凤凰城阙。","憔悴如今谁领略，飘零已是无颜色。","问行厨、何日唤宾僚，犹堪折。"],"source":"宋词"},{"title":"唐兀歹・不付能告求的绣帏里头眠，痛惜轻怜。斩眼不觉得绿窗儿外月明","author":"关汉卿","dynasty":"元","form":"曲","lines":["却又早转，畅好是疾明也幺天！。"],"source":"元曲"},{"title":"权舆","author":"佚名","dynasty":"先秦","form":"诗","lines":["于我乎，夏屋渠渠，今也毎食无余。于嗟乎，不承权舆！","于我乎，毎食四簋，今也毎食不饱。于嗟乎，不承权舆！"],"source":"《诗经》"},{"title":"终南山","author":"王维","dynasty":"唐","form":"诗","lines":["太乙近天都，连山接海隅。","白云回望合，青霭入看无。","分野中峰変，阴晴众壑殊。","欲投人処宿，隔水问樵夫。"],"source":"《唐诗三百首》"},{"title":"题汤致远运使所蔵隆师四図 倚竹","author":"范成大","dynasty":"宋","form":"诗","lines":["軽薄人情翻覆手，冰容却耐幽居久。","関中旧事逐春休，付与新人莫回首。","目送斜阳忘却帰，竹风揺曳翠罗衣。","君看脉脉无言処，中有杜陵饥客诗。"],"source":"宋诗"},{"title":"感皇恩","author":"陆游","dynasty":"宋","form":"词","lines":["春色到人间，彩旛初戴。","正好春盘细生菜。","一般日月，只有仙家偏耐。","雪霜从点鬓，朱颜在。","温诏鼎来，延英催对。","凤阁鸾台看除拝。","对衣裁稳，恰称球纹新带。","个时方旋了、功名债。"],"source":"宋词"},{"title":"尾・腰肢困摆垂杨软，舌尖笑吐丁香喘。绣帐里无人，并枕低言。畅道美","author":"关汉卿","dynasty":"元","form":"曲","lines":["满姻缘，风流缱绻，天若肯为人，为人是今生愿。","尽老同眠也者，也强如雁底关河路儿远。"],"source":"元曲"},{"title":"宛丘","author":"佚名","dynasty":"先秦","form":"诗","lines":["子之汤兮，宛丘之上兮。洵有情兮，而无望兮。","坎其击鼓，宛丘之下。无冬无夏，值其鹭羽。","坎其击缶，宛丘之道。无冬无夏，值其鹭翿。"],"source":"《诗经》"},{"title":"汉江临泛","author":"王维","dynasty":"唐","form":"诗","lines":["楚塞三湘接，荆门九派通。","江流天地外，山色有无中。","郡邑浮前浦，波澜动远空。","襄阳好风日，留酔与山翁。"],"source":"《唐诗三百首》"},{"title":"题汤致远运使所蔵隆师四図 嗅梅","author":"范成大","dynasty":"宋","form":"诗","lines":["雪意勒花愁未解，背阴一朶寒先退。","东风还是去年香，不比人心容易改。","宿酒瞢腾正耐春，花枝人面両时新。","相看好作风流伴，只恐花枝却妒人。"],"source":"宋诗"},{"title":"感皇恩","author":"陆游","dynasty":"宋","form":"词","lines":["小阁倚秋空，下临江渚。","漠漠孤云未成雨。","数声新雁，回首杜陵何处。","壮心空万里，人谁许。","黄阁紫枢，筑坛开府。","莫怕功名欠人做。","如今熟计，只有故乡归路。","石帆山脚下，菱三亩。"],"source":"宋词"},{"title":"双调・乔牌儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["世情推物理，人生贵适意。","想人间造物搬兴废，吉蔵凶，凶暗吉。"],"source":"元曲"},{"title":"东门之枌","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之枌，宛丘之栩。子仲之子，婆娑其下。","谷旦于差，南方之原。不绩其麻，市也婆娑。","谷旦于逝，越以鬷迈。视尔如荍，贻我握椒。"],"source":"《诗经》"},{"title":"奉和圣制従蓬莱向兴庆阁道中留春雨中春望之作応制","author":"王维","dynasty":"唐","form":"诗","lines":["渭水自萦秦塞曲，黄山旧遶汉宫斜。","銮舆迥出千门柳，阁道廻看上苑花。","云里帝城双凤阙，雨中春树万人家。","为乗阳気行时令，不是宸游玩物华。"],"source":"《唐诗三百首》"},{"title":"晩歩","author":"范成大","dynasty":"宋","form":"诗","lines":["排门帘幕夜香飘，灯火人声小市桥。","満県月明春意好，旗亭吹笛近元宵。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["羁雁未成归，肠断宝筝零落。","那更冻醪无力，似故人情薄。","瘴云蛮雨暗孤城，身在楚山角。","烦问剑南消息，怕还成疏索。"],"source":"宋词"},{"title":"夜行船・富贵那能长富贵，日盈昃月满亏蚀。地下东南，天高西北，天地","author":"关汉卿","dynasty":"元","form":"曲","lines":["尚无完体。"],"source":"元曲"},{"title":"衡门","author":"佚名","dynasty":"先秦","form":"诗","lines":["衡门之下，可以栖迟。泌之洋洋，可以乐饥。","岂其食鱼，必河之鲂？岂其取妻，必齐之姜？","岂其食鱼，必河之鲤？岂其取妻，必宋之子？"],"source":"《诗经》"},{"title":"和贾舎人早朝大明宫之作","author":"王维","dynasty":"唐","form":"诗","lines":["绛帻鶏人送暁筹，尚衣方进翠云裘。","九天阊阖开宫殿，万国衣冠拝冕旒。","日色才临仙掌动，香烟欲傍衮竜浮。","朝罢须裁五色诏，佩声帰向凤池头。"],"source":"《唐诗三百首》"},{"title":"题开元天宝遗事四首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["御前羯鼓透春空，笑覚花奴手未工。","一曲打开红杏蕊，须知天子是天公。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["风露九霄寒，侍宴玉华宫阙。","亲向紫皇香案，见金芝千叶。","碧壶仙露酝初成，香味两奇绝。","酔后却骑丹凤，看蓬莱春色。"],"source":"宋词"},{"title":"庆宣和・算到天明走到黒，赤紧的是衣食。凫短鹤长不能齐，且休题，谁","author":"关汉卿","dynasty":"元","form":"曲","lines":["是非。"],"source":"元曲"},{"title":"东门之池","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之池，可以沤麻。彼美淑姬，可与晤歌。","东门之池，可以沤纻。彼美淑姬，可与晤语。","东门之池，可以沤菅。彼美淑姬，可与晤言。"],"source":"《诗经》"},{"title":"酬郭给事","author":"王维","dynasty":"唐","form":"诗","lines":["洞门高阁霭余辉，桃李阴阴柳絮飞。","禁里疏钟官舎晩，省中啼鸟吏人稀。","晨揺玉佩趋金殿，夕奉天书拝琐闱。","强欲従君无那老，将因卧病解朝衣。"],"source":"《唐诗三百首》"},{"title":"题开元天宝遗事四首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["谢蛮舞袖贵妃弦，秦国如花虢国妍。","不赏缠头三百万，阿姨何処费金銭。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["客路苦思归，愁似茧丝千绪。","梦里镜湖烟雨，看山无重数。","尊前消尽少年狂，慵着送春语。","花落燕飞庭户，叹年光如许。"],"source":"宋词"},{"title":"锦上花・展放愁眉，休争闲气。今日容颜，老如昨日。古往今来，恁须尽","author":"关汉卿","dynasty":"元","form":"曲","lines":["知，贤的愚的，贫的和富的。"],"source":"元曲"},{"title":"东门之杨","author":"佚名","dynasty":"先秦","form":"诗","lines":["东门之杨，其叶牂牂。昏以为期，明星煌煌。","东门之杨，其叶肺肺。昏以为期，明星晢晢。"],"source":"《诗经》"},{"title":"积雨辋川荘作","author":"王维","dynasty":"唐","form":"诗","lines":["积雨空林烟火遅，蒸藜炊黍饷东菑。","漠漠水田飞白鹭，阴阴夏木啭黄鹂。","山中习静観朝槿，松下清斎折露葵。","野老与人争席罢，海鴎何事更相疑。"],"source":"《唐诗三百首》"},{"title":"题开元天宝遗事四首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["朝天车马诏频催，𣃁得新汤未敢开。","忽报猪竜掀宇宙，阿瞒虚読相书来。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["岁晩喜东归，扫尽市朝陈迹。","拣得乱山环处，钓一潭澄碧。","卖鱼沽酒酔还醒，心事付横笛。","家在万重云外，有沙鸥相识。"],"source":"宋词"},{"title":"幺・到头这一身，难逃那一日。受用了一朝，一朝便宜。百岁光阴，七十","author":"关汉卿","dynasty":"元","form":"曲","lines":["者稀。","急急流年，滔滔逝水。"],"source":"元曲"},{"title":"墓门","author":"佚名","dynasty":"先秦","form":"诗","lines":["墓门有棘，斧以斯之。夫也不良，国人知之。知而不已，谁昔然矣。","墓门有梅，有鸮萃止。夫也不良，歌以讯之。讯予不顾，颠倒思予。"],"source":"《诗经》"},{"title":"辋川集 鹿柴","author":"王维","dynasty":"唐","form":"诗","lines":["空山不见人，但闻人语响。","返景入深林，复照青苔上。"],"source":"《唐诗三百首》"},{"title":"题开元天宝遗事四首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["剥啄延秋屋上乌，明朝箭道入东都。","宫中亦有风流阵，不及渔阳突骑粗。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["华表又千年，谁记驾云孤鹤。","回首旧曽游处，但山川城郭。","纷纷车马满人间，尘土汚芒𪨗。","且访葛仙丹井，看岩花开落。"],"source":"宋词"},{"title":"清江引・落花满院春又归，晩景成何济！车尘马足中，蚁穴蜂衙内，寻取","author":"关汉卿","dynasty":"元","form":"曲","lines":["个稳便处闲坐地。"],"source":"元曲"},{"title":"防有鹊巣","author":"佚名","dynasty":"先秦","form":"诗","lines":["防有鹊巣，邛有旨苕。谁侜予美？心焉忉忉。","中唐有甓，邛有旨鹝。谁侜予美？心焉惕惕。"],"source":"《诗经》"},{"title":"辋川集 竹里馆","author":"王维","dynasty":"唐","form":"诗","lines":["独坐幽篁里，弾琴复长啸。","深林人不知，明月来相照。"],"source":"《唐诗三百首》"},{"title":"読甘露遗事二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["神理人情本不同，绝怜鼠辈幸元功。","天公盍仮毛牦助，成败都悬反掌中。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["挥袖别人间，飞蹑峭崖苍壁。","寻见古仙丹灶，有白云成积。","心如潭水静无风，一坐数千息。","夜半忽惊奇事，看鲸波暾日。"],"source":"宋词"},{"title":"碧玉箫・乌兔相催，日月走东西。人生别离，白发故人稀。不停闲岁月疾，","author":"关汉卿","dynasty":"元","form":"曲","lines":["光阴似驹过隙。","君莫痴，休争名利。","幸有几杯，且不如花前酔。"],"source":"元曲"},{"title":"月出","author":"佚名","dynasty":"先秦","form":"诗","lines":["月出皎兮。佼人僚兮。舒窈纠兮。劳心悄兮。","月出皓兮。佼人懰兮。舒忧受兮。劳心慅兮。","月出照兮。佼人燎兮。舒夭绍兮。劳心惨兮。"],"source":"《诗经》"},{"title":"送别","author":"王维","dynasty":"唐","form":"诗","lines":["山中相送罢，日暮掩柴扉。","春草明年绿，王孙帰不帰。"],"source":"《唐诗三百首》"},{"title":"読甘露遗事二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["上林辇路草青青，谁向凭高识圣情。","谩展东封図画看，不如𬪩酒乱平生。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["湓口放船归，薄暮散花洲宿。","两岸白苹红蓼，映一蓑新绿。","有沽酒处便为家，菱芡四时足。","明日又乗风去，任江南江北。"],"source":"宋词"},{"title":"歇拍煞・恁则待闲熬煎、闲烦恼、闲萦系、闲追欢、闲落魄、闲游戏。金","author":"关汉卿","dynasty":"元","form":"曲","lines":["鸡触祸机，得时间早弃迷途。","繁华重念箫韶歇，急流勇退寻归计。","采蕨薇，洗是非；夷齐等，巣由辈。","这两个谁人似得？松菊晋陶潜，江湖越范蠡。"],"source":"元曲"},{"title":"株林","author":"佚名","dynasty":"先秦","form":"诗","lines":["胡为乎株林？从夏南！匪适株林，从夏南！","驾我乗马，说于株野。乗我乗驹，朝食于株！"],"source":"《诗经》"},{"title":"雑诗三首 二","author":"王维","dynasty":"唐","form":"诗","lines":["君自故郷来，応知故郷事。","来日绮窗前，寒梅着花未。"],"source":"《唐诗三百首》"},{"title":"半塘","author":"范成大","dynasty":"宋","form":"诗","lines":["柳暗阊门逗暁开，半塘塘下越渓回。","炊烟拥柂船船过，芳草縁堤歩歩来。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["挥袖上西峰，孤绝去天无尺。","拄杖下临鲸海，数烟帆历历。","贪看云气舞青鸾，归路已将夕。","多谢半山松吹，解殷勤留客。"],"source":"宋词"},{"title":"仙吕・桂枝香","author":"关汉卿","dynasty":"元","form":"曲","lines":["因他别后，恹恹消痩。","粉褪了雨后桃花，带宽了风前杨柳。","这相思怎休？这相思怎休？害得我天长地久，难禁难受！泪痕流，滴破芙蓉面，却似珍珠断线头。"],"source":"元曲"},{"title":"泽陂","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼泽之陂，有蒲与荷。有美一人，伤如之何？寤寐无为，涕泗滂沱。","彼泽之陂，有蒲与𫈉。有美一人，硕大且巻。寤寐无为，中心悁悁。","彼泽之陂，有蒲菡萏。有美一人，硕大且俨。寤寐无为，辗转伏枕。"],"source":"《诗经》"},{"title":"相思","author":"王维","dynasty":"唐","form":"诗","lines":["红豆生南国，秋来発故枝。","愿君多采撷，此物最相思。"],"source":"《唐诗三百首》"},{"title":"枫桥","author":"范成大","dynasty":"宋","form":"诗","lines":["朱门白壁枕弯流，桃李无言満屋头。","墙上浮図路傍堠，送人南北管离愁。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["小倦带馀酲，澹澹数櫺斜日。","驱退睡魔十万，有双龙苍璧。","少年莫笑老人衰，风味似平昔。","扶杖冻云深处，探渓梅消息。"],"source":"宋词"},{"title":"不是路・万种风流，今日番成一段愁。泪盈眸，云山满目恨悠悠。谩追求，","author":"关汉卿","dynasty":"元","form":"曲","lines":["情如柳絮风前斗，性似桃花逐水流。","沉吟久，因他数尽残更漏，恁般亻孱亻愁！恁般亻孱亻愁！。"],"source":"元曲"},{"title":"羔裘","author":"佚名","dynasty":"先秦","form":"诗","lines":["羔裘逍遥，狐裘以朝。岂不尔思？劳心忉忉。","羔裘翱翔，狐裘在堂。岂不尔思？我心忧伤。","羔裘如膏，日出有曜。岂不尔思？中心是悼。"],"source":"《诗经》"},{"title":"九月九日忆山东兄弟","author":"王维","dynasty":"唐","form":"诗","lines":["独在异郷为异客，毎逢佳节倍思亲。","遥知兄弟登高処，遍挿茱萸少一人。"],"source":"《唐诗三百首》"},{"title":"横塘","author":"范成大","dynasty":"宋","form":"诗","lines":["南浦春来绿一川，石桥朱塔両依然。","年年送客横塘路，细雨垂杨繋画船。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["觅个有缘人，分付玉壶灵药。","谁向市尘深处，识辽天孤鹤。","月中吹笛下巴陵，条华赴前约。","今古废兴何限，叹山川如昨。"],"source":"宋词"},{"title":"木丫叉・雾锁秦楼，雾锁秦楼。云迷楚岫，御沟红叶空流。偷香韩寿，锦","author":"关汉卿","dynasty":"元","form":"曲","lines":["帐中枉自绸缪，蹙破两眉头。","小蛮腰痩如杨柳，浅淡樱桃樊素口。","空教人目断去时舟，又不知风流浪子，何处温柔。"],"source":"元曲"},{"title":"素冠","author":"佚名","dynasty":"先秦","form":"诗","lines":["庶见素冠兮，棘人栾栾兮。劳心慱慱兮。","庶见素衣兮，我心伤悲兮。聊与子同归兮。","庶见素𫖒兮，我心蕴结兮。聊与子如一兮。"],"source":"《诗经》"},{"title":"渭城曲","author":"王维","dynasty":"唐","form":"诗","lines":["渭城朝雨浥軽尘，客舎青青杨柳春。","勧君更尽一杯酒，西出阳関无故人。"],"source":"《唐诗三百首》"},{"title":"胥口","author":"范成大","dynasty":"宋","form":"诗","lines":["扁舟拍浪信西东，何処孤帆万里风。","一雨快晴云放树，両山中断水粘空。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["平旦出秦关，雪色驾车双鹿。","借问此行安往，赏清伊修竹。","汉家宫殿劫灰中，春草几回绿。","君看变迁如许，况纷纷荣辱。"],"source":"宋词"},{"title":"幺篇・月下砧声幽，月下砧声幽，风前笛秦。断肠声无了无休，捣砕我心","author":"关汉卿","dynasty":"元","form":"曲","lines":["又加上一场症候，顿使我愁不寐，襄王梦雨散云収。"],"source":"元曲"},{"title":"隰有苌楚","author":"佚名","dynasty":"先秦","form":"诗","lines":["隰有苌楚，猗傩其枝，夭之沃沃，乐子之无知。","隰有苌楚，猗傩其华，夭之沃沃。乐子之无家。","隰有苌楚，猗傩其实，夭之沃沃。乐子之无室。"],"source":"《诗经》"},{"title":"崔九欲往南山马上口号与别","author":"裴迪","dynasty":"唐","form":"诗","lines":["帰山深浅去，须尽丘壑美。","莫学武陵人，暂游桃源里。"],"source":"《唐诗三百首》"},{"title":"香山","author":"范成大","dynasty":"宋","form":"诗","lines":["采香径里木兰舟，嚼蕊吹芳烂熳游。","落日青山都好在，桑间荞麦満芳洲。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["秋晓上莲峰，高蹑倚天青壁。","谁与放翁为伴，有天坛轻策。","铿然忽变赤龙飞，雷雨四山黒。","谈笑做成丰岁，笑禅龛楖栗。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・仙吕/赏花时","author":"关汉卿","dynasty":"元","form":"曲","lines":["则这一曲翻成和泪篇，最苦偏高离恨天，双泪落尊前。","山长水远，愁见理行轩。"],"source":"元曲"},{"title":"匪风","author":"佚名","dynasty":"先秦","form":"诗","lines":["匪风发兮，匪车偈兮。顾瞻周道，中心怛兮。","匪风飘兮，匪车嘌兮。顾瞻周道，中心吊兮。","谁能亨鱼？溉之釜鬵。谁将西归？怀之好音。"],"source":"《诗经》"},{"title":"寻西山隠者不遇","author":"丘为","dynasty":"唐","form":"诗","lines":["绝顶一茅茨，直[上]三十里。","扣関无僮仆，窥室唯案几。","若非巾柴车，応是钓秋水。","差池不相见，黾勉空仰止。","草色新雨中，松声晩牕里。","及兹契幽绝，自足荡心耳。","虽无宾主意，颇得清浄理。","兴尽方下山，何必待之子。"],"source":"《唐诗三百首》"},{"title":"上沙","author":"范成大","dynasty":"宋","form":"诗","lines":["水辺犬吠隔疏林，篱落萧森日半阴。","繁杏锁红春意浅，晩梅飘粉暮寒深。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["家住东吴近帝乡。","平生豪举少年场。","十千沽酒青楼上，百万呼卢锦瑟傍。","身易老，恨难忘。","尊前赢得是凄凉。","君归为报京华旧，一事无成两鬓霜。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・玄篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["待得鸾胶续断弦，欲盼雕鞍难顾恋。","谢他新理任这官员，常好是与民方便，咱又得个一夜并头莲。","（同下）。"],"source":"元曲"},{"title":"蜉蝣","author":"佚名","dynasty":"先秦","form":"诗","lines":["蜉蝣之羽，衣裳楚楚。心之忧矣，于我归处。","蜉蝣之翼，采采衣服。心之忧矣，于我归息。","蜉蝣掘阅，麻衣如雪。心之忧矣，于我归说。"],"source":"《诗经》"},{"title":"黄鹤楼","author":"崔颢","dynasty":"唐","form":"诗","lines":["昔人已乗白云去，此地空余黄鹤楼。","黄鹤一去不复返，白云千载空悠悠。","晴川歴歴汉阳树，春草萋萋鹦鹉洲。","日暮郷関何処是，烟波江上使人愁。"],"source":"《唐诗三百首》"},{"title":"天平寺","author":"范成大","dynasty":"宋","form":"诗","lines":["旧游仿佛记三年，轰饮题诗夜満山。","山上白云応解笑，又将尘土涴朱颜。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["看尽巴山看蜀山。","子规江上过春残。","惯眠古驿常安枕，熟听《阳关》不惨颜。","慵服气，懒烧丹。","不妨青鬓戏人间。","秘传一字神仙诀，说与君知只是顽。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・仙吕/点绛唇","author":"关汉卿","dynasty":"元","form":"曲","lines":["讲论诗词，笑谈街市，学难似风里扬丝，一世常如此。"],"source":"元曲"},{"title":"候人","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼候人兮，何戈与祋。彼其之子，三百赤芾。","维鹈在梁，不濡其翼。彼其之子，不称其服。","维鹈在梁，不濡其咮。彼其之子，不遂其媾。","荟兮蔚兮，南山朝𬯀。婉兮娈兮，季女斯饥。"],"source":"《诗经》"},{"title":"行経华阴","author":"崔颢","dynasty":"唐","form":"诗","lines":["岧嶤太华俯咸京，天外三峰削不成。","武帝祠前云欲散，仙人掌上雨初晴。","河山北枕秦関険，駅树西连汉畤平。","借问路傍名利客，无如此処学长生。"],"source":"《唐诗三百首》"},{"title":"白云泉","author":"范成大","dynasty":"宋","form":"诗","lines":["竜头高啄嗽飞流，玉醴甘浑乳気浮。","扪腹煮泉烹鬭胯，真成骑鹤上扬州。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["梳发金盘剰一窝。","画眉鸾镜晕双蛾。","人间何处无春到，只有伊家独占多。","微歩处，奈娇何。","春衫初换曲尘罗。","东邻斗草归来晩，忘却新传子夜歌。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・混江龙","author":"关汉卿","dynasty":"元","form":"曲","lines":["我逐日家把您相试，乞求的教您做人时，但能勾终朝为父，也想着一日为师。","但有个敢接我这上厅行首案，情愿分会与你这搬演戏台儿。","则为四般儿误了前程事，都只为聪明智能，因此上辛苦无辞。"],"source":"元曲"},{"title":"鸤鸠","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸤鸠在桑，其子七兮。淑人君子，其仪一兮。其仪一兮，心如结兮。","鸤鸠在桑，其子在梅。淑人君子，其带伊丝。其带伊丝，其弁伊骐。","鸤鸠在桑，其子在棘。淑人君子，其仪不忒。其仪不忒，正是四国。","鸤鸠在桑，其子在榛。淑人君子，正是国人，正是国人。胡不万年？"],"source":"《诗经》"},{"title":"长干曲四首 一","author":"崔颢","dynasty":"唐","form":"诗","lines":["君家何処住？妾住在横塘。","停船暂借问，或恐是同郷。"],"source":"《唐诗三百首》"},{"title":"山顶","author":"范成大","dynasty":"宋","form":"诗","lines":["翠屏无路强攀縁，我与枯藤各半仙。","不敢高声天阙近，人间漠漠但寒烟。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["家住苍烟落照间。","丝毫尘事不相关。","斟残玉瀣行穿竹，巻罢《黄庭》卧看山。","贪啸傲，任衰残。","不妨随处一开颜。","元知造物心肠别，老却英雄似等闲。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・油葫芦","author":"关汉卿","dynasty":"元","form":"曲","lines":["你道是金笼内鹦哥能念诗，这便是咱家的好比似。","原来越聪明越得不出笼时！能吹弹好比人毎日常看伺，惯歌讴好比人毎日常差使。","（云）我不怨别人。","（众旦云）姐姐，你怨谁？（旦云）咱会弹唱的，日日官身；不会弹唱的，倒得些自在！（唱）我怨那礼案里几个令史，他毎都是我掌命司，先将那等不会弹不会唱的除了名字，早知道则做个哑猱儿。"],"source":"元曲"},{"title":"下泉","author":"佚名","dynasty":"先秦","form":"诗","lines":["冽彼下泉，浸彼苞稂。忾我寤叹，念彼周京。","冽彼下泉，浸彼苞萧。忾我寤叹，念彼京周。","冽彼下泉，浸彼苞蓍。忾我寤叹，念彼京师。","芃芃黍苗，阴雨膏之。四国有王，郇伯劳之。"],"source":"《诗经》"},{"title":"长干曲四首 二","author":"崔颢","dynasty":"唐","form":"诗","lines":["家临九江水，来去九江侧。","同是长干人，自小不相识。"],"source":"《唐诗三百首》"},{"title":"山径","author":"范成大","dynasty":"宋","form":"诗","lines":["云根新径络山腰，暗绿交阴宿露飘。","行到竹深啼鸟閙，鹁鸠老怨画眉娇。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["挿脚红尘已是颠。","更求平地上青天。","新来有个生涯别，买断烟波不用钱。","沽酒市，采菱船。","酔听风雨拥蓑眠。","三山老子真堪笑，见事迟来四十年。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・天下乐","author":"关汉卿","dynasty":"元","form":"曲","lines":["俺可也图甚幺香名贯人耳！想当也波时，不三思：越聪明，不能勾无外事。","卖弄的有伎俩，卖弄的有艳姿，则落的临老来呼\"弟子\"！（张千云）谢大姐，你怎生这早晩才来？你只在这里，我报复去。","（做报科，云）报的老爷得知：有乐人毎来参见。","（钱大尹云）别的休进来，则着那为头的一人来见。","（张千云）别的都回去，则着谢大姐过去哩！（众旦下）（正旦见、拝科，云）上厅行首谢天香谨参。","（钱大尹云）休要误了官身。","（旦云）理会的。","（做出门科，云）爷爷，那官人好个冷脸子也！（唱）。"],"source":"元曲"},{"title":"七月","author":"佚名","dynasty":"先秦","form":"诗","lines":["七月流火，九月授衣。一之日觱发，二之日栗烈。无衣无褐，何以卒岁？","三之日于耜，四之日举趾。同我妇子，馌彼南亩。田畯至喜。","七月流火，九月授衣。春日载阳，有鸣仓庚。女执懿筐，遵彼微行，爰求柔桑。","春日迟迟，采蘩祁祁。女心伤悲，殆及公子同归。","七月流火，八月萑苇。蚕月条桑，取彼斧斨。以伐远扬，猗彼女桑。","七月鸣鵙，八月载绩。载玄载黄，我朱孔阳，为公子裳。","四月秀葽，五月鸣蜩。八月其获，十月陨萚。一之日于貉，取彼狐狸，为公子裘。","二之日其同，载缵武功。言私其𫎆，献豜于公。","五月斯螽动股，六月莎鸡振羽。七月在野，八月在宇，九月在户，十月蟋蟀，入我床下。","穹窒熏鼠，塞向墐户。嗟我妇子，曰为改岁，入此室处。","六月食郁及薁，七月亨葵及菽。八月剥枣，十月获稲。为此春酒，以介眉寿。","七月食瓜，八月断壶，九月叔苴，采荼薪樗。食我农夫。","九月筑场圃，十月纳禾稼。黍稷重穋，禾麻菽麦。嗟我农夫，我稼既同，上入执宫功。","昼尔于茅，宵尔索绹，亟其乗屋，其始播百谷。","二之日凿冰冲冲，三之日纳于凌阴。四之日其蚤，献羔祭韭。九月肃霜，十月涤场。","朋酒斯飨，曰杀羔羊，跻彼公堂。称彼兕觥：万寿无疆！"],"source":"《诗经》"},{"title":"望蓟门","author":"祖咏","dynasty":"唐","form":"诗","lines":["燕台一望客心惊，箫鼓喧喧汉将営。","万里寒光生积雪，三辺曙色动危旌。","沙场烽火连胡月，海畔云山拥蓟城。","少小虽非投笔吏，论功还欲请长缨。"],"source":"《唐诗三百首》"},{"title":"泉亭","author":"范成大","dynasty":"宋","form":"诗","lines":["収拾风烟锁翠微，乱山穷処结巌扉。","青天不尽鸟飞尽，呉楚川原似衲衣。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["懒向青门学种瓜。","只将渔钓送年华。","双双新燕飞春岸，片片轻鸥落晩沙。","歌缥渺，舻呕哑。","酒如清露鲊如花。","逢人问道归何处，笑指船儿此是家。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・金盏儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["猛觑了那容姿，不觉的下阶址，下场头少不的跟官长厅前死；往常觑品官宣使似小孩儿。","他则道官身休失误，启口更无词。","立地刚一饭间，心战勾两炊时。"],"source":"元曲"},{"title":"鸱鸮","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸱鸮鸱鸮，既取我子，无毁我室。恩斯勤斯，鬻子之闵斯。","迨天之未阴雨，彻彼桑土，绸缪牖户。今女下民，或敢侮予？","予手拮据，予所捋荼。予所蓄租，予口卒瘏，曰予未有室家。","予羽谯谯，予尾翛翛，予室翘翘。风雨所漂摇，予维音哓哓！"],"source":"《诗经》"},{"title":"终南望余雪","author":"祖咏","dynasty":"唐","form":"诗","lines":["终南阴岭秀，积雪浮云端。","林表明霁色，城中増暮寒。"],"source":"《唐诗三百首》"},{"title":"金氏庵","author":"范成大","dynasty":"宋","form":"诗","lines":["酔墨题窗侧暮鸦，蔓藤縁壁走青蛇。","春深有燕捎飞蝶，日暮无人扫落花。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["南浦舟中两玉人。","谁知重见楚江滨。","凭教后苑红牙版，引上西川绿锦茵。","才浅笑，却轻嚬。","淡黄杨柳又催春。","情知言语难传恨，不思琵琶道得真。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・酔中天","author":"关汉卿","dynasty":"元","form":"曲","lines":["初相见呼你为学士，谨厚不因而；今遍回身嘱付尔，相公也冷眼儿频偷视。","你觑他交椅上擡颏样儿，待的你不同前次，他则是微分间将表字呼之。"],"source":"元曲"},{"title":"东山","author":"佚名","dynasty":"先秦","form":"诗","lines":["我徂东山，慆慆不归。我来自东，零雨其蒙。我东曰归，我心西悲。","制彼裳衣，勿士行枚。蜎蜎者蠋，烝在桑野。敦彼独宿，亦在车下。","我徂东山，慆慆不归。我来自东，零雨其蒙。果臝之实，亦施于宇。","伊威在室，蟏蛸在户。町畽鹿场，熠耀宵行。不可畏也，伊可怀也。","我徂东山，慆慆不归。我来自东，零雨其蒙。鹳鸣于垤，妇叹于室。","洒扫穹窒，我征聿至。有敦瓜苦，烝在栗薪。自我不见，于今三年。","我徂东山，慆慆不归。我来自东，零雨其蒙。仓庚于飞，熠耀其羽。","之子于归，皇驳其马。亲结其缡，九十其仪。其新孔嘉，其旧如之何？"],"source":"《诗经》"},{"title":"古従军行","author":"李颀","dynasty":"唐","form":"诗","lines":["白日登山望烽火，黄昏饮马傍交河。","行人刁斗风沙暗，公主琵琶幽怨多。","野云万里无城郭，雨雪纷纷连大漠。","胡鴈哀鸣夜夜飞，胡児眼涙双双落。","闻道玉门犹被遮，応将性命逐軽车。","年年戦骨埋荒外，空见蒲桃入汉家。"],"source":"《唐诗三百首》"},{"title":"平云阁","author":"范成大","dynasty":"宋","form":"诗","lines":["背倚天峰涌化宫，横空阁道拖双虹。","火云六月応奇绝，青琐玲珑八面风。"],"source":"宋诗"},{"title":"蓦山渓","author":"陆游","dynasty":"宋","form":"词","lines":["元戎十乗，出次高唐馆。","归去旧鹓行，更何人、齐飞霄汉。","瞿唐水落，惟是泪波深，催叠鼓，起牙樯，难锁长江断。","春深鳌禁，红日宫瓦暖。","何处望音尘，黯消魂、层城飞观。","人情见惯，不敢恨相忘，梅驿外，蓼滩边，只待除书看。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・酔扶归","author":"关汉卿","dynasty":"元","form":"曲","lines":["你陡恁的无才思，有甚省不的两桩儿？我道这相公不是漫词，你怎幺不解其中意？他道是种桃花砍折竹枝，则说你重色轻君子！。"],"source":"元曲"},{"title":"破斧","author":"佚名","dynasty":"先秦","form":"诗","lines":["既破我斧，又欠我斨。周公东征，四国是皇。哀我人斯，亦孔之将。","既破我斧，又欠我锜。周公东征，四国是遒。哀我人斯，亦孔之嘉。","既破我斧，又欠我𨱇。周公东征，四国是遒。哀我人斯，亦孔之休。"],"source":"《诗经》"},{"title":"琴歌","author":"李颀","dynasty":"唐","form":"诗","lines":["主人有酒歓今夕，请奏鸣琴広陵客。","月照城头乌半飞，霜凄万树风入衣。","铜𬬻华烛烛増辉，初弾渌水后楚妃。","一声已动物皆静，四座无言星欲稀。","清淮奉使千余里，敢告云山従此始。"],"source":"《唐诗三百首》"},{"title":"鉄锡","author":"范成大","dynasty":"宋","form":"诗","lines":["八环流韵宝枝鸣，古鉄无花紫翠明。","莫遣闲人容易振，泉飞石落鬼寰惊。"],"source":"宋诗"},{"title":"蓦山渓","author":"陆游","dynasty":"宋","form":"词","lines":["穷山孤垒，腊尽春初破。","寂寞掩空斋，好一个、无聊底我。","啸台龙岫，随分有云山，临浅濑，荫长松，闲据胡床坐。","三杯径酔，不觉纱巾堕。","画角唤人归，落梅村、篮舆夜过。","城门渐近，几点妓衣红，官驿外，酒垆前，也有闲灯火。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・赚煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["我这府里祗候几曽闲，差拨无铨次，从今后无倒断嗟呀怨咨。","我去这触热也似官人行将礼数使，若是轻咳嗽便有官司。","我直到掲席时、来到家时，我又索趱下些工夫忆念尔。","是我那清歌皓齿，是我那言谈情思，是我那湿浸浸舞困袖梢儿。","（下）。"],"source":"元曲"},{"title":"伐柯","author":"佚名","dynasty":"先秦","form":"诗","lines":["伐柯如何？匪斧不克。取妻如何？匪媒不得。","伐柯伐柯，其则不远。我觏之子，笾豆有践。"],"source":"《诗经》"},{"title":"送陈章甫","author":"李颀","dynasty":"唐","form":"诗","lines":["四月南风大麦黄，枣花未落桐阴长。","青山朝别暮还见，嘶马出门思旧郷。","陈侯立身何坦荡，虬须虎眉仍大颡。","腹中贮书一万巻，不肯低头在草莽。","东门酤酒饮我曹，心軽万事皆鸿毛。","酔卧不知白日暮，有时空望孤云高。","长河浪头连天黒，津口停舟渡不得。","郑国游人未及家，洛阳行子空叹息。","闻道故林相识多，罢官昨日今如何。"],"source":"《唐诗三百首》"},{"title":"放鹤亭","author":"范成大","dynasty":"宋","form":"诗","lines":["石门関外古亭基，树老藤枯野径微。","放鹤道人今不见，故応人与鹤俱飞。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"陆游","dynasty":"宋","form":"词","lines":["三年流落巴山道。","破尽青衫尘满帽。","身如西瀼渡头云，愁抵瞿塘关上草。","春盘春酒年年好。","试戴银旛判酔倒。","今朝一岁大家添，不是人间偏我老。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・南吕/一枝花","author":"关汉卿","dynasty":"元","form":"曲","lines":["往常时唤官身可早眉黛舒，今日个叫祗候喉咙响。","原来是你这狠首领，我则道是那个面前桑？恰才陪着笑脸儿应昂，怎觑我这查梨相，只因他忒过当。","据妾身貌陋残妆，谁教他大尹行将咱过奖？。"],"source":"元曲"},{"title":"九罭","author":"佚名","dynasty":"先秦","form":"诗","lines":["九罭之鱼，鳟鲂。我觏之子，衮衣绣裳。","鸿飞遵渚，公归无所，于女信处。鸿飞遵六，公归不复，于女信宿。","是以有衮衣兮，无以我公归兮，无使我心悲兮。"],"source":"《诗经》"},{"title":"聴安万善吹觱篥歌","author":"李颀","dynasty":"唐","form":"诗","lines":["南山截竹为觱篥，此楽本自亀兹出。","流伝汉地曲転奇，凉州胡人为我吹。","傍邻闻者多叹息，远客思郷皆涙垂。","世人解聴不解赏，长飙风中自来往。","枯桑老柏寒飕飗，九雏鸣凤乱啾啾。","竜吟虎啸一时発，万籁百泉相与秋。","忽然更作渔阳掺，黄云萧条白日暗。","変调如闻杨柳春，上林繁花照眼新。","歳夜高堂列明烛，美酒一杯声一曲。"],"source":"《唐诗三百首》"},{"title":"马迹石","author":"范成大","dynasty":"宋","form":"诗","lines":["跨马凌空亦快哉，竜腰鹤背谩徘徊。","游人欲识仙踪処，但觅苍崖白塔来。"],"source":"宋诗"},{"title":"朝中措","author":"陆游","dynasty":"宋","form":"词","lines":["幽姿不入少年场。","无语只凄凉。","一个飘零身世，十分冷淡心肠。","江头月底，新诗旧梦，孤恨清香。","任是春风不管，也曽先识东皇。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・隔尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["我见他严容端坐挨着罗幌，可甚幺和气春风满画堂！我最愁是劈先里递一声唱，这里但有个女娘、坐场，可敢烘散我家私做的赏。"],"source":"元曲"},{"title":"狼跋","author":"佚名","dynasty":"先秦","form":"诗","lines":["狼跋其胡，载疐其尾。公孙硕肤，赤舄几几。","狼疐其尾，载跋其胡。公孙硕肤，徳音不瑕？"],"source":"《诗经》"},{"title":"古意","author":"李颀","dynasty":"唐","form":"诗","lines":["男児事长征，少小幽燕客。","赌胜马蹄下，由来軽七尺。","杀人莫敢前，须如猬毛磔。","黄云陇底白雪飞，未得报恩不能帰。","辽东小妇年十五，惯弾琵琶解歌舞。","今为羗笛出塞声，使我三军涙如雨。"],"source":"《唐诗三百首》"},{"title":"金沙","author":"范成大","dynasty":"宋","form":"诗","lines":["荘厳福地守霊仙，不为人闲计子銭。","一掬斓斒光照眼，路傍馋隶枉流涎。"],"source":"宋诗"},{"title":"朝中措","author":"陆游","dynasty":"宋","form":"词","lines":["怕歌愁舞懒逢迎。","妆晩托春酲。","总是向人深处，当时枉道无情。","关心近日，啼红密诉，剪绿深盟。","杏馆花阴恨浅，画堂银烛嫌明。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・贺新郎","author":"关汉卿","dynasty":"元","form":"曲","lines":["呀，想东坡一曲〔满庭芳〕则道一个\"香霭雕盘\"，可又早祸从天降！当时嘲拨无拦当，乞相公宽洪海量，怎不的仔细参详？（钱大尹云）怎幺在我行打关节那？（正旦唱）小人便关节煞，怎生勾除籍不做娼，弃贱得为良。","他则是一时间带酒闲支谎，量妾身本开封府阶下承应辈，怎做的柳耆卿心上谢天香？。"],"source":"元曲"},{"title":"鹿鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["呦呦鹿鸣，食野之苹。我有嘉宾，鼓瑟吹笙。吹笙鼓簧，承筐是将。人之好我，示我周行。","呦呦鹿鸣，食野之蒿。我有嘉宾，徳音孔昭。视民不恌，君子是则是効。我有旨酒，嘉宾式燕以敖。","呦呦鹿鸣，食野之芩。我有嘉宾，鼓瑟鼓琴。鼓瑟鼓琴，和乐且湛。我有旨酒，以燕乐嘉宾之心。"],"source":"《诗经》"},{"title":"聴董大弾胡笳声兼寄语弄房给事","author":"李颀","dynasty":"唐","form":"诗","lines":["蔡女昔造胡笳声，一弾一十有八拍。","胡人落涙沾辺草，汉使断肠対帰客。","古戍苍苍烽火寒，大荒沈沈飞雪白。","先払商弦后角羽，四郊秋叶惊摵摵。","董夫子，通神明，深山窃聴来妖精。","言遅更速皆応手，将往复旋如有情。","空山百鸟散还合，万里浮云阴且晴。","嘶酸雏鴈失群夜，断绝胡児恋母声。","川为浄其波，鸟亦罢其鸣。","乌孙部落家郷远，逻娑沙尘哀怨生。","幽音変调忽飘洒，长风吹林雨堕瓦。","迸泉飒飒飞木末，野鹿呦呦走堂下。","长安城连东掖垣，凤凰池対青琐门。","高才脱略名与利，日夕望君抱琴至。"],"source":"《唐诗三百首》"},{"title":"竜母庙","author":"范成大","dynasty":"宋","form":"诗","lines":["孝竜分职隶湘西，天许宁亲歳一帰。","风雹春春损桃李，山中寒食尚冬衣。"],"source":"宋诗"},{"title":"朝中措","author":"陆游","dynasty":"宋","form":"词","lines":["咚咚傩鼓饯流年。","烛焔动金船。","彩燕难寻前梦，酥花空点春妍。","文园谢病，兰成久旅，回首凄然。","明月梅山笛夜，和风禹庙莺天。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・牧羊关","author":"关汉卿","dynasty":"元","form":"曲","lines":["相公名誉传天下，妾身乐籍在教坊；量妾身则是个妓女排场，相公是当代名儒。","妾身则好去待宾客，供些优唱。","妾身是临路金丝柳，相公是架海紫金梁；想你便意错见、心错爱，怎做的门厮敌、户厮当？。"],"source":"元曲"},{"title":"四牡","author":"佚名","dynasty":"先秦","form":"诗","lines":["四牡𬴂𬴂，周道倭迟。岂不怀归？王事靡盬，我心伤悲。","四牡𬴂𬴂，啴啴骆马。岂不怀归？王事靡盬，不遑启处。","翩翩者鵻，载飞载下，集于苞栩。王事靡盬，不遑将父。","翩翩者鵻，载飞载止，集于苞杞。王事靡盬，不遑将母。","驾彼四骆，载骤骎骎。岂不怀归？是用作歌，将母来谂。"],"source":"《诗经》"},{"title":"送魏万之京","author":"李颀","dynasty":"唐","form":"诗","lines":["朝闻游子唱离歌，昨夜微霜初渡河。","鸿鴈不堪愁里聴，云山况是客中过。","関城树色催寒近，御苑砧声向晩多。","莫见长安行楽処，空令歳月易蹉跎。"],"source":"《唐诗三百首》"},{"title":"白莲堂","author":"范成大","dynasty":"宋","form":"诗","lines":["古木参天护碧池，青銭弱叶戦涟漪。","匆匆游子匆匆去，不见风清月冷时。"],"source":"宋诗"},{"title":"临江仙","author":"陆游","dynasty":"宋","form":"词","lines":["鸠雨催成新绿，燕泥収尽残红。","春光还与美人同。","论心空眷眷，分袂却匆匆。","只道真情易写，那知怨句难工。","水流云散各西东。","半廊花院月，一帽柳桥风。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・二煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["则恁这秀才毎活计似鱼翻浪，大人家前程似狗探汤。","则俺这侍妾毎近帏房，止不过供手巾到他行，能勾见些模样？着护衣须是相亲傍，止不过梳头处俺胸前靠着脊梁，几时得儿女成双？（云）指望嫁杭州柳耆卿，做个自在人，如今怎了也？（唱）。"],"source":"元曲"},{"title":"皇皇者华","author":"佚名","dynasty":"先秦","form":"诗","lines":["皇皇者华，于彼原隰。𬳽𬳽征夫，毎怀靡及。","我马维驹，六辔如濡。载驰载驱，周爰咨诹。","我马维骐，六辔如丝。载驰载驱，周爰咨谋。","我马维骆，六辔沃若。载驰载驱，周爰咨度。","我马维骃，六辔既均。载驰载驱，周爰咨询。"],"source":"《诗经》"},{"title":"春泛若耶渓","author":"綦毋潜","dynasty":"唐","form":"诗","lines":["幽意无断绝，此去随所偶。","晩风吹行舟，花路入渓口。","际夜転西壑，隔山望南斗。","潭烟飞溶溶，林月低向后。","生事且弥漫，愿为持竿叟。"],"source":"《唐诗三百首》"},{"title":"白善坑","author":"范成大","dynasty":"宋","form":"诗","lines":["银须玉璞紫金精，犯难穷探亦有名。","白垩区区土同価，呉侬无事亦軽生。"],"source":"宋诗"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["陌上箫声寒食近。","雨过园林，花气浮芳润。","千里斜阳锺欲瞑。","凭高望断南楼信。","海角天涯行略尽。","三十年间，无处无遗恨。","天若有情终欲问。","忍教霜点相思鬓。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・正宫/端正好","author":"关汉卿","dynasty":"元","form":"曲","lines":["往常我在风尘为歌妓，止不过见了那几个筵席，到家来须做个自由鬼；今日个打我在无底磨牢笼内！。"],"source":"元曲"},{"title":"棠棣","author":"佚名","dynasty":"先秦","form":"诗","lines":["棠棣之华，鄂不韡韡。凡今之人，莫如兄弟。","死丧之威，兄弟孔怀。原隰裒矣，兄弟求矣。","脊令在原，兄弟急难。毎有良朋，况也永叹。","兄弟阋于墙，外御其务。毎有良朋，烝也无戎。","丧乱既平，既安且宁。虽有兄弟，不如友生？","傧尔笾豆，饮酒之饫。兄弟既具，和乐且孺。","妻子好合，如鼓瑟琴。兄弟既翕，和乐且湛。","宜尔室家，乐尔妻帑。是究是图，亶其然乎？"],"source":"《诗经》"},{"title":"塞下曲四首 一","author":"王昌齢","dynasty":"唐","form":"诗","lines":["蝉鸣空桑林，八月萧関道。","出塞入塞寒，処処黄芦草。","従来幽幷客，皆共尘沙老。","莫学游侠児，矜夸紫骝好。"],"source":"《唐诗三百首》"},{"title":"贺楽丈先生南郭新居","author":"范成大","dynasty":"宋","form":"诗","lines":["新堂燕雀喜，竹篱挂藤萝。","崩奔风涛里，得此巣亀荷。","西山効爽気，南浦供清波。","会心不在远，容膝何须多。","先生淮海俊，踏地尝兵戈。","飘飘万里道，芒鞵厌関河。","风吹落下邑，楚语成呉歌。","岂不有故国，荒垣鞠秋莎。","无庸说当帰，到処皆南柯。","卜迁不我遐，一水明青罗。","闭戸长独佳，奈客剥啄何。","会令苍苔石，屐歯如蜂窠。"],"source":"宋诗"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["桐叶晨飘蛩夜语。","旅思秋光，黯黯长安路。","忽记横戈盘马处。","散关清渭应如故。","江海轻舟今已具。","一巻兵书，叹息无人付。","早信此生终不遇。","当年悔草《长杨赋》。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・滚绣球","author":"关汉卿","dynasty":"元","form":"曲","lines":["到早起过洗面水，到晩来又索铺床叠被，我服侍的都入罗帏，我恰才舒铺盖似孤鬼，少不的足恋蜷寝睡，整三年有名无实。","本是个见交风月耆卿伴，教我做遥受恩情大尹妻，端的谁知？（二旦扮姬妾上，云）俺二人是钱大尹家侍妾。","今日无甚事，去望姓谢的姐姐走一遭去。","（见旦科，云）姐姐，俺二人竟来望姐姐。","（正旦云）二位姐姐请坐。","（二旦云）姐姐，你在宅中三年，相公曽亲近你幺？（正旦唱）。"],"source":"元曲"},{"title":"伐木","author":"佚名","dynasty":"先秦","form":"诗","lines":["伐木丁丁，鸟鸣嘤嘤。出自幽谷，迁于乔木。嘤其鸣矣，求其友声。","相彼鸟矣，犹求友声。矧伊人矣，不求友生？神之听之，终和且平。","伐木许许，酾酒有藇！既有肥羜，以速诸父。宁适不来，微我弗顾。","于粲洒扫，陈馈八簋。既有肥牡，以速诸舅。宁适不来，微我有咎。","伐木于阪，酾酒有衍。笾豆有践，兄弟无远。民之失徳，干糇以愆。","有酒湑我，无酒酤我。坎坎鼓我，蹲蹲舞我。迨我暇矣，饮此湑矣。"],"source":"《诗经》"},{"title":"塞下曲四首 二","author":"王昌齢","dynasty":"唐","form":"诗","lines":["饮马渡秋水，水寒风似刀。","平沙日未没，黯黯见临洮。","昔日长城戦，咸言意気高。","黄尘足今古，白骨乱蓬蒿。"],"source":"《唐诗三百首》"},{"title":"歳旱邑人祷第五罗汉得雨楽先生有诗次韵","author":"范成大","dynasty":"宋","form":"诗","lines":["海山之湫竜所宫，溅瀑下赴声琤琮。","碧𪾦大士何许主，爱此匹练飞冥蒙。","偶然宴坐百千劫，神力悲愿俱无穷。","向来火云挟日走，沙煎日烂千山童。","陆浑风高煽热属，泾川草肥闲雨工。","万口嗷嗷叫此士，炉燎未吐诚先通。","暮尘卷地羊角暗，朝霞横天鱼尾红。","商羊摩霄鸢起舞，居然一澍歌年豊。","人言仏陀入三昧，断取世界如旋蓬。","指麾釈梵骏奔走，况尔风伯并雷公。","风騒老将亦賛喜，笔阵独扫诗坛空。","嗟余啸咏不釈手，一曲何啻歌三终。"],"source":"宋诗"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["水漾萍根风巻絮。","倩笑娇颦，忍记逢迎处。","只有梦魂能再遇。","堪嗟梦不由人做。","梦若由人何处去。","短帽轻衫，夜夜眉州路。","不怕银缸深绣户。","只愁风断青衣渡。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・倘秀才","author":"关汉卿","dynasty":"元","form":"曲","lines":["俺若是曽宿睡呵，则除是天知地知；相公那铺盖儿，知他是横的竖的！比我那初使唤，如今越更稀。","想是我出身处本低微，则怕展汚了相公贵体。"],"source":"元曲"},{"title":"天保","author":"佚名","dynasty":"先秦","form":"诗","lines":["天保定尔，亦孔之固。俾尔单厚，何福不除？俾尔多益，以莫不庶。","天保定尔，俾尔戬谷。罄无不宜，受天百禄。降尔遐福，维日不足。","天保定尔，以莫不兴。如山如阜，如冈如陵，如川之方至，以莫不増。","吉蠲为饎，是用孝享。禴祠烝尝，于公先王。君曰：卜尔，万寿无疆。","神之吊矣，诒尔多福。民之质矣，日用饮食。群黎百姓，遍为尔徳。","如月之恒，如日之升。如南山之寿，不骞不崩。如松柏之茂，无不尔或承。"],"source":"《诗经》"},{"title":"同従弟销南斎玩月忆山阴崔少府","author":"王昌齢","dynasty":"唐","form":"诗","lines":["高卧南斎时，开帷月初吐。","清辉淡水木，演漾在窗戸。","苒苒几盈虚，澄澄変今古。","美人清江畔，是夜越吟苦。","千里其如何，微风吹兰杜。"],"source":"《唐诗三百首》"},{"title":"次韵时叙赋楽先生新居","author":"范成大","dynasty":"宋","form":"诗","lines":["愚士繁俗如囚奴，至人遗形与化俱。","纷纭覚梦不可弁，蘧蘧栩栩知谁欤。","百年如泡亦如电，刚欲鋳鉄充门枢。","列仙之臞堕山沢，一席三椽良有余。","平生嵚巇百戦勇，顿挫久已帰夷途。","光芒无用入诗句，青天白日轰雷车。","松煤茧纸妙挥扫，芸香锦囊深贮储。","紫露双瓶春夜酔，黄云一棱秋田租。","谁能抟扶北溟海，政尔帰卧南阳庐。","鸿飞冥冥隔云雨，弋人可慕不可呼。"],"source":"宋诗"},{"title":"钗头凤・撷芳词","author":"陆游","dynasty":"宋","form":"词","lines":["红酥手。","黄縢酒。","满城春色宫墙柳。","东风恶。","欢情薄。","一怀愁绪，几年离索。","错错错。","春如旧。","人空痩。","泪痕红浥鲛绡透。","桃花落。","闲池阁。","山盟虽在，锦书难托。","莫莫莫。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・滚绣球","author":"关汉卿","dynasty":"元","form":"曲","lines":["姐姐毎肯教诲，怕不是好意？争奈我官人行，怎敢便话不投机？（二旦云）姐姐，你又无甚幺过失。","（正旦唱）你道是无过失，学恁的，姐姐毎会也那不会？我则是斟量着紧慢迟疾，强何郎旖旎煞难搽粉，狠张敞央及煞怎画眉？要识个高低。","（二旦云）敢问姐姐，当日柳七官人《乐章集》，姐姐収的好幺？（正旦唱）。"],"source":"元曲"},{"title":"采薇","author":"佚名","dynasty":"先秦","form":"诗","lines":["采薇采薇，薇亦作止。曰归曰归，岁亦莫止。靡室靡家，𤞤狁之故。不遑启居，𤞤狁之故。","采薇采薇，薇亦柔止。曰归曰归，心亦忧止。忧心烈烈，载饥载渇。我戍未定，靡使归聘。","采薇采薇，薇亦刚止。曰归曰归，岁亦阳止。王事靡盬，不遑启处。忧心孔疚，我行不来！","彼尔维何？维常之华。彼路斯何？君子之车。戎车既驾，四牡业业。岂敢定居？一月三捷。","驾彼四牡，四牡骙骙。君子所依，小人所腓。四牡翼翼，象弭鱼服。岂不日戒？𤞤狁孔棘！","昔我往矣，杨柳依依。今我来思，雨雪霏霏。行道迟迟，载渇载饥。我心伤悲，莫知我哀！"],"source":"《诗经》"},{"title":"出塞二首 一","author":"王昌齢","dynasty":"唐","form":"诗","lines":["秦时明月汉时関，万里长征人未还。","但使竜城飞将在，不教胡马度阴山。"],"source":"《唐诗三百首》"},{"title":"病中夜坐呈致远","author":"范成大","dynasty":"宋","form":"诗","lines":["似雾如烟夜気浮，鹤鸣惊睡起掻头。","含风竹影淡留月，着雨蛩声深怨秋。","万事心空痴已惯，百骸歳晩病相投。","便当采薬西山去，脚力蹒跚怕远游。"],"source":"宋诗"},{"title":"清商怨","author":"陆游","dynasty":"宋","form":"词","lines":["江头日暮痛饮。","乍雪晴犹凛。","山驿凄凉，灯昏人独寝。","鸳机新寄断锦。","叹往事、不堪重省。","梦破南楼，绿云堆一枕。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・倘秀才","author":"关汉卿","dynasty":"元","form":"曲","lines":["便休题花七、柳七，若听得这里是那里，相公的耳朵里风闻那旧是非。","休只管这几句，滥黄齑，我也记得。"],"source":"元曲"},{"title":"出车","author":"佚名","dynasty":"先秦","form":"诗","lines":["我出我车，于彼牧矣。自天子所，谓我来矣。召彼仆夫，谓之载矣。王事多难，维其棘矣。","我出我车，于彼郊矣。设此旐矣，建彼旄矣。彼旟旐斯，胡不旆旆？忧心悄悄，仆夫况瘁。","王命南仲，往城于方。出车彭彭，旗旐央央。天子命我，城彼朔方。赫赫南仲，𤞤狁于襄。","昔我往矣，黍稷方华。今我来思，雨雪载途。王事多难，不遑启居。岂不怀归？畏此简书。","喓喓草虫，趯趯阜螽。未见君子，忧心忡忡。既见君子，我心则降。赫赫南仲，薄伐西戎。","春日迟迟，卉木萋萋。仓庚喈喈，采蘩祁祁。执讯获丑，薄言还归。赫赫南仲，𤞤狁于夷。"],"source":"《诗经》"},{"title":"春宫曲","author":"王昌齢","dynasty":"唐","form":"诗","lines":["昨夜风开露井桃，未央前殿月轮高。","平阳歌舞新承宠，帘外春寒赐锦袍。"],"source":"《唐诗三百首》"},{"title":"戯题薬裹","author":"范成大","dynasty":"宋","form":"诗","lines":["卷却糸纶飏却竿，莫随鱼鼈弄腥涎。","须知别有垂钩処，枯海无风浪拍天。"],"source":"宋诗"},{"title":"水龙吟","author":"陆游","dynasty":"宋","form":"词","lines":["樽前花底寻春处，堪叹心情全减。","一身萍寄，酒徒云散，佳人天远。","那更今年，瘴烟蛮雨，夜郎江畔。","漫倚楼横笛，临窗看镜，时挥涕、惊流转。","花落月明庭院。","悄无言、魂消肠断。","凭肩携手，当时曽効，画梁栖燕。","见说新来，网萦尘暗，舞衫歌扇。","料也羞憔悴，慵行芳径，怕啼莺见。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・穷河西","author":"关汉卿","dynasty":"元","form":"曲","lines":["姐姐毎谁敢道袖褪《乐章集》，都则是断送的我一身亏。","怕待学大曲子我从头儿唱与你，本记的人前会，挂口儿从今后再休提。","（二旦云）咱和你同去竹云亭上赌戏咱。","（正旦云）姐姐毎，咱去波。","（唱）。"],"source":"元曲"},{"title":"杕杜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有杕之杜，有睆其实。王事靡盬，继嗣我日。日月阳止，女心伤止，征夫遑止。","有杕之杜，其叶萋萋。王事靡盬，我心伤悲。卉木萋止，女心悲止，征夫归止！","陟彼北山，言采其杞。王事靡盬，忧我父母。檀车𪩷𪩷，四牡痯痯，征夫不远！","匪载匪来，忧心孔疚。斯逝不至，而多为恤。卜筮偕止，会言近止，征夫迩止！"],"source":"《诗经》"},{"title":"闺怨","author":"王昌齢","dynasty":"唐","form":"诗","lines":["闺中少妇不曽愁，春日凝妆上翠楼。","忽见陌头杨柳色，悔教夫壻觅封侯。"],"source":"《唐诗三百首》"},{"title":"夜帰","author":"范成大","dynasty":"宋","form":"诗","lines":["竹舆伊轧走长街，掠面风清酔梦回。","曲巷无声门戸闭，一灯犹照酒垆开。"],"source":"宋诗"},{"title":"秋波媚・眼儿媚","author":"陆游","dynasty":"宋","form":"词","lines":["秋到边城角声哀。","烽火照高台。","悲歌击筑，凭高酹酒，此兴悠哉。","多情谁似南山月，特地暮云开。","灞桥烟柳，曲江池馆，应待人来。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・滚绣球","author":"关汉卿","dynasty":"元","form":"曲","lines":["想前日使象棋，说下的则是个手帕儿赌戏，你将我那玉束纳藤箱子，便不放空回。","近新来，下雨的那一日，你输与我绣鞋儿一对，挂口儿再不曽提。","那里为些些赌赛绝了交契，小小输赢丑了面皮，道我不精细。"],"source":"元曲"},{"title":"鱼丽","author":"佚名","dynasty":"先秦","form":"诗","lines":["鱼丽于罶，鲿鲨。君子有酒，旨且多。","鱼丽于罶，鲂鳢。君子有酒，多且旨。","鱼丽于罶，𫚢鲤。君子有酒，旨且有。物其多矣，","维其嘉矣！物其旨矣，维其偕矣！物其有矣，维其时矣！"],"source":"《诗经》"},{"title":"芙蓉楼送辛渐二首 一","author":"王昌齢","dynasty":"唐","form":"诗","lines":["寒雨连天夜入湖，平明送客楚山孤。","洛阳亲友如相问，一片冰心在玉壶。"],"source":"《唐诗三百首》"},{"title":"田舎","author":"范成大","dynasty":"宋","form":"诗","lines":["呼唤携锄至，安排筑圃忙。","児童眠落叶，鸟雀噪斜阳。","烟火村声远，林菁野気香。","楽哉今歳事，天末稲云黄。"],"source":"宋诗"},{"title":"秋波媚・眼儿媚","author":"陆游","dynasty":"宋","form":"词","lines":["曽散天花蕊珠宫。","一念堕尘中。","铅华洗尽，珠玑不御，道骨仙风。","东游我酔骑鲸去，君驾素鸾从。","垂虹看月，天台采药，更与谁同。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・倘秀才","author":"关汉卿","dynasty":"元","form":"曲","lines":["幺四五骰着个撮十，二三二趁着个夹七；一面打个色儿，也当得幺二三是鼠尾。","赌钱的、不伶俐，姐姐你可便再掷。"],"source":"元曲"},{"title":"南有嘉鱼","author":"佚名","dynasty":"先秦","form":"诗","lines":["南有嘉鱼，烝然罩罩。君子有酒，嘉宾式燕以乐。","南有嘉鱼，烝然汕汕。君子有酒，嘉宾式燕以衎。","南有樛木，甘瓠累之。君子有酒，嘉宾式燕绥之。","翩翩者鵻，烝然来思。君子有酒，嘉宾式燕又思。"],"source":"《诗经》"},{"title":"宿王昌齢隠居","author":"常建","dynasty":"唐","form":"诗","lines":["清渓深不测，隠処唯孤云。","松际露微月，清光犹为君。","茅亭宿花影，薬院滋苔纹。","余亦谢时去，西山鸾鹤群。"],"source":"《唐诗三百首》"},{"title":"戯题致远书房","author":"范成大","dynasty":"宋","form":"诗","lines":["照丛菊靥万黄金，欹架薇条半绿阴。","逋客已随丹凤诏，但余花草怨秋深。"],"source":"宋诗"},{"title":"采桑子","author":"陆游","dynasty":"宋","form":"词","lines":["宝钗楼上妆梳晩，懒上秋千。","闲拨沈烟。","金缕衣宽睡髻偏。","鳞鸿不寄辽东信，又是经年。","弹泪花前。","愁入春风十四弦。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・呆骨朵","author":"关汉卿","dynasty":"元","form":"曲","lines":["我将这色数儿轻放在骰盆内，二三五又掷个乌十；不下钱打赛，我可便赢了你两回。","这上面分明见，色数儿且休提。","姐姐，我可便做桩儿三个五，你今日这般输说甚的？。"],"source":"元曲"},{"title":"南山有台","author":"佚名","dynasty":"先秦","form":"诗","lines":["南山有台，北山有莱。乐只君子，邦家之基。乐只君子，万寿无期。","南山有桑，北山有杨。乐只君子，邦家之光。乐只君子，万寿无疆。","南山有杞，北山有李。乐只君子，民之父母。乐只君子，徳音不已。","南山有栲，北山有杻。乐只君子，遐不眉寿。乐只君子，徳音是茂。","南山有枸，北山有楰。乐只君子，遐不黄耇。乐只君子，保艾尔后。"],"source":"《诗经》"},{"title":"清平调 一","author":"李白","dynasty":"唐","form":"诗","lines":["云想衣裳花想容，春风払槛露华浓。","若非群玉山头见，会向瑶台月下逢。"],"source":"《唐诗三百首》"},{"title":"乌戍密印寺","author":"范成大","dynasty":"宋","form":"诗","lines":["青堆渓上水平堤，绛瓦参差半掩扉。","我与圣公俱客寓，人伝帝子尚霊威。","胜縁龃龉三重障，志士辛勤十载帰。","花木禅房都不见，但余蝙蝠昼群飞。"],"source":"宋诗"},{"title":"卜算子","author":"陆游","dynasty":"宋","form":"词","lines":["驿外断桥边，寂寞开无主。","已是黄昏独自愁，更着风和雨。","无意苦争春，一任群芳妒。","零落成泥碾作尘，只有香如故。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・倘秀才","author":"关汉卿","dynasty":"元","form":"曲","lines":["你休要不君子便将闹起，我永世儿不和你厮极，塌着那臭尸骸一壁稳坐的。","（钱将拄仗放在旦右肩上）（正旦拨科，唱）兀的不闲着您！（钱将拄杖放在旦左肩上）（正旦抜科，唱）臭驴蹄！（钱又将拄杖放在旦右肩上）（正旦拿住回头科，唱）兀的是谁？。"],"source":"元曲"},{"title":"蓼萧","author":"佚名","dynasty":"先秦","form":"诗","lines":["蓼彼萧斯，零露湑兮。既见君子，我心写兮。燕笑语兮，是以有誉处兮。","蓼彼萧斯，零露瀼瀼。既见君子，为龙为光。其徳不爽，寿考不忘。","蓼彼萧斯，零露泥泥。既见君子，孔燕岂弟。宜兄宜弟，令徳寿岂。","蓼彼萧斯，零露浓浓。既见君子，鞗革忡忡。和鸾雍雍，万福攸同。"],"source":"《诗经》"},{"title":"清平调 二","author":"李白","dynasty":"唐","form":"诗","lines":["一枝红艳露凝香，云雨巫山枉断肠。","借问汉宫谁得似，可怜飞燕倚新妆。"],"source":"《唐诗三百首》"},{"title":"月夜泛舟新塘","author":"范成大","dynasty":"宋","form":"诗","lines":["渓上清风柳万重，绿烟无路月朦胧。","船头忽逐回塘転，一水迢迢却向东。"],"source":"宋诗"},{"title":"沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["粉破梅梢，绿动萱丛，春意已深。","渐珠帘低巻，筇枝微歩，冰开跃鲤，林暖鸣禽。","茘子扶疏，竹枝哀怨，浊酒一尊和泪斟。","凭栏久，叹山川冉冉，岁月骎骎。","当时岂料如今。","漫一事无成霜鬓侵。","看故人强半，沙堤黄阁，鱼悬带玉，貂映蝉金。","许国虽坚，朝天无路，万里凄凉谁寄音。","东风里，有灞桥烟柳，知我归心。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・酔太平","author":"关汉卿","dynasty":"元","form":"曲","lines":["唬的我连忙的跪膝，不由我泪雨似扒推；可又早七留七力来到我跟底，不言语立地；我见他出留出律两个都回避。","相公将必留不剌拄杖相调戏，我不该必丢不搭口内失尊卑，这的是天香犯罪。","（钱大尹云）天香，你怕幺？（正旦云）可知怕哩。","（钱大尹云）你要饶幺？（正旦云）可知要饶哩。","（钱大尹云）既然要饶，或诗或词，作一首来我看，我便饶了你。","（正旦云）请。"],"source":"元曲"},{"title":"湛露","author":"佚名","dynasty":"先秦","form":"诗","lines":["湛湛露斯，匪阳不晞。厌厌夜饮，不酔无归。","湛湛露斯，在彼丰草。厌厌夜饮，在宗载考。","湛湛露斯，在彼杞棘。显允君子，莫不令徳。","其桐其椅，其实离离。岂弟君子，莫不令仪。"],"source":"《诗经》"},{"title":"清平调 三","author":"李白","dynasty":"唐","form":"诗","lines":["名花倾国両相歓，常得君王帯笑看。","解得春风无限恨，沈香亭北倚阑干。"],"source":"《唐诗三百首》"},{"title":"客舎","author":"范成大","dynasty":"宋","form":"诗","lines":["毂撃肩摩锦繍堆，朝声汹汹暮声催。","忽然忆起长桥路，天镜无辺白鸟回。"],"source":"宋诗"},{"title":"沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["一别秦楼，转眼新春，又近放灯。","忆盈盈倩笑，纤纤柔握，玉香花语，雪暖酥凝。","念远愁肠，伤春病思，自怪平生殊未曽。","君知否，渐香消蜀锦，泪渍吴绫。","难求系日长绳。","况倦客飘零少旧朋。","但江郊雁起，渔村笛怨，寒釭委烬，孤砚生冰。","水绕山围，烟昏云惨，纵有高台常怯登。","消魂处，是鱼笺不到，兰梦无凭。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・二煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["往常时不曽挂眼都无意，今日回心有甚迟？相公的言语更怕不中，委付妾身教我转转猜疑。","相公又不是戏笑，又不是沉酔，又不是昏迷；待道是颠狂睡呓，兀的不青天这白日？。"],"source":"元曲"},{"title":"彤弓","author":"佚名","dynasty":"先秦","form":"诗","lines":["彤弓弨兮，受言蔵之。我有嘉宾，中心贶之。钟鼓既设，一朝飨之。","彤弓弨兮，受言载之。我有嘉宾，中心喜之。钟鼓既设，一朝右之。","彤弓弨兮，受言櫜之。我有嘉宾，中心好之。钟鼓既设，一朝酬之。"],"source":"《诗经》"},{"title":"还郷偶书  其二","author":"黄拱","dynasty":"唐","form":"诗","lines":["少小离家老大回，郷音难改鬓毛衰。","児童相见不相识，借问客従何処来。"],"source":"《唐诗三百首》"},{"title":"病中夜坐","author":"范成大","dynasty":"宋","form":"诗","lines":["村巷秋舂远，禅房夕磬深。","饥蚊常绕鬓，暗鼠忽鸣琴。","薄薄寒相中，棱棱痩不禁。","时成洛下咏，却似越人吟。"],"source":"宋诗"},{"title":"沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["孤鹤归飞，再过辽天，换尽旧人。","念累累枯冢，茫茫梦境，王侯蝼蚁，毕竟成尘。","载酒园林，寻花巷陌，当日何曽轻负春。","流年改，叹围腰带剰，点鬓霜新。","交亲。","散落如云。","又岂料如今馀此身。","幸眼明身健，茶甘饭软，非惟我老，更有人贫。","躲尽危机，消残壮志，短艇湖中闲采莼。","吾何恨，有渔翁共酔，渓友为邻。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・一煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["相公，你一言既出如何悔，驷马奔驰不可追。","妾身出入兰堂，身居画阁，行有香车，宿有罗帏。","相公，整过了三年，可便调理，无个消息；不想道今朝错爱我这匪妓，也则是可怜见哭啼啼。","（钱大尹云）天香，后堂中换衣服去。","（下）（正旦唱）。"],"source":"元曲"},{"title":"菁菁者莪","author":"佚名","dynasty":"先秦","form":"诗","lines":["菁菁者莪，在彼中阿。既见君子，乐且有仪。","菁菁者莪，在彼中沚。既见君子，我心则喜。","菁菁者莪，在彼中陵。既见君子，锡我百朋。","泛泛杨舟，载沉载浮。既见君子，我心则休。"],"source":"《诗经》"},{"title":"长恨歌","author":"白居易","dynasty":"唐","form":"诗","lines":["汉皇重色思倾国，御宇多年求不得。","杨家有女初长成，养在深闺人未识。","天生丽质难自弃，一朝选在君王侧。","回眸一笑百媚生，六宫粉黛无颜色。","春寒赐浴华清池，温泉水滑洗凝脂。","侍児扶起娇无力，始是新承恩沢时。","云鬓花颜金歩揺，芙蓉帐暖度春宵。","春宵苦短日高起，従此君王不早朝。","承歓侍宴无闲暇，春従春游夜専夜。","后宫佳丽三千人，三千宠爱在一身。","金屋妆成娇侍夜，玉楼宴罢酔和春。","姊妹弟兄皆列土，可怜光彩生门戸。","遂令天下父母心，不重生男重生女。","骊宫高処入青云，仙楽风飘処処闻。","缓歌慢舞凝糸竹，尽日君王看不足。","渔阳鞞鼓动地来，惊破霓裳羽衣曲。","九重城阙烟尘生，千乗万骑西南行。","翠华揺揺行复止，西出都门百余里。","六军不発无奈何，宛転蛾眉马前死。","花钿委地无人収，翠翘金雀玉掻头。","君王掩面救不得，回看血涙相和流。","黄埃散漫风萧索，云桟萦纡登劒阁。","峨嵋山下少人行，旌旗无光日色薄。","蜀江水碧蜀山青，圣主朝朝暮暮情。","行宫见月伤心色，夜雨闻铃肠断声。","天旋日転回竜驭，到此踌躇不能去。","马嵬坡下泥土中，不见玉颜空死処。","君臣相顾尽沾衣，东望都门信马帰。","帰来池苑皆依旧，太液芙蓉未央柳。","芙蓉如面柳如眉，対此如何不涙垂？","春风桃李花开夜，秋雨梧桐叶落时。","西宫南苑多秋草，宫叶満阶红不埽。","棃园弟子白髪新，椒房阿监青娥老。","夕殿蛍飞思悄然，孤灯挑尽未成眠。","遅遅钟鼓初长夜，耿耿星河欲曙天。","鸳鸯瓦冷霜华重，翡翠衾寒谁与共。","悠悠生死别経年，魂魄不曽来入梦。","临邛道士鸿都客，能以精诚致魂魄。","为感君王展転思，遂教方士殷勤觅。","排空驭気奔如电，升天入地求之徧。","上穷碧落下黄泉，両処茫茫皆不见。","忽闻海上有仙山，山在虚无缥缈间。","楼阁玲珑五云起，其中绰约多仙子。","中有一人字太真，雪肤花貌参差是。","金阙西厢叩玉扃，転教小玉报双成。","闻道汉家天子使，九华帐里梦魂惊。","揽衣推枕起裴回，珠箔银屏逦迤开。","云鬓半偏新睡覚，花冠不整下堂来。","风吹仙袂飘飖挙，犹似霓裳羽衣舞。","玉容寂莫涙阑干，棃花一枝春帯雨。","含情凝睇谢君王，一别音容両渺茫。","昭阳殿里恩爱绝，蓬莱宫中日月长。","回头下望人寰処，不见长安见尘雾。","唯将旧物表深情，钿合金钗寄将去。","钗留一股合一扇，钗擘黄金合分钿。","但教心似金钿坚，天上人间会相见。","临别殷勤重寄词，词中有誓両心知。","七月七日长生殿，夜半无人私语时。","在天愿作比翼鸟，在地愿为连理枝。","天长地久有时尽，此恨緜緜无绝期。"],"source":"《唐诗三百首》"},{"title":"秋芸有春绿","author":"范成大","dynasty":"宋","form":"诗","lines":["秋芸有春绿，疏篱照孤芳。","清霜早晩至，何草能不黄。","宁当念衰落，政尔事容光。","及时且自好，来日殊未量。"],"source":"宋诗"},{"title":"忆秦娥","author":"陆游","dynasty":"宋","form":"词","lines":["玉花骢。","晩街金辔声璁珑。","声璁珑。","闲敧乌帽，又过城东。","富春巷陌花重重。","千金沽酒酬春风。","酬春风。","笙歌围里，锦绣丛中。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・煞尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["则今番文诌诌的施才艺，从来个扑籁籁没气力。","相公这一句言语可立碑，我也不敢十分相信的。","许来大官员，恁来大职位，发出言词忒口疾。","你不委心为自家没见识，又不是花街中、柳陌里，那一个彻梢虚、雾塌桥，浑身我可也认的你！（下）。"],"source":"元曲"},{"title":"六月","author":"佚名","dynasty":"先秦","form":"诗","lines":["六月栖栖，戎车既饬。四牡骙骙，载是常服。𤞤狁孔炽，我是用急。王于出征，以匡王国。","比物四骊，闲之维则。维此六月，既成我服。我服既成，于三十里。王于出征，以佐天子。","四牡修广，其大有颙。薄伐𤞤狁，以奏肤公。有严有翼，共武之服。共武之服，以定王国。","𤞤狁匪茹，整居焦获。侵镐及方，至于泾阳。织文鸟章，白旆央央。元戎十乗，以先启行。","戎车既安，如轾如轩。四牡既佶，既佶且闲。薄伐𤞤狁，至于大原。文武吉甫，万邦为宪。","吉甫燕喜，既多受祉。来归自镐，我行永久。饮御诸友，炰鳖脍鲤。侯谁在矣？张仲孝友。"],"source":"《诗经》"},{"title":"琵琶引","author":"白居易","dynasty":"唐","form":"诗","lines":["浔阳江头夜送客，枫叶荻花秋索索。","主人下马客在船，挙酒欲饮无管弦。","酔不成歓惨将别，别时茫茫江浸月。","忽闻水上琵琶声，主人忘帰客不発。","寻声暗问弾者谁，琵琶声停欲语遅。","移船相近邀相见，添酒回灯重开宴。","千呼万唤始出来，犹抱琵琶半遮面。","転轴拨弦三両声，未成曲调先有情。","弦弦掩抑声声思，似诉平生不得意。","低眉信手続続弾，说尽心中无限事。","軽拢慢撚抹复挑，初为霓裳后六幺。","大弦嘈嘈如急雨，小弦切切如私语。","嘈嘈切切错雑弾，大珠小珠落玉盘。","间関莺语花底滑，幽咽泉流水下滩。","水泉冷渋弦疑绝，疑绝不通声暂歇。","别有幽愁暗恨生，此时无声胜有声。","银缾乍破水浆迸，鉄骑突出刀枪鸣。","曲终収拨当心画，四弦一声如裂帛。","东舟西舫悄无言，唯见江心秋月白。","沈吟放拨挿弦中，整顿衣裳起敛容。","自言本是京城女，家在虾蟇陵下住。","十三学得琵琶成，名蜀教坊第一部。","曲罢曽教善才伏，妆成毎被秋娘妬。","五陵年少争缠头，一曲红绡不知数。","钿头云箆撃节砕，血色罗帬飜酒污。","今年歓笑复明年，秋月春风等闲度。","弟走従军阿姨死，暮去朝来颜色故。","门前冷落鞍马稀，老大嫁作商人妇。","商人重利軽别离，前月浮梁买茶去。","去来江口守空船，绕船月明江水寒。","夜深忽梦少年事，梦啼妆涙红阑干。","我闻琵琶已叹息，又闻此语重唧唧。","同是天涯沦落人，相逢何必曽相识。","我従去年辞帝京，谪居卧病浔阳城。","浔阳小処无音楽，终歳不闻糸竹声。","住近湓江地低湿，黄芦苦竹绕宅生。","其间旦暮闻何物，杜鹃啼血猨哀鸣。","春江花朝秋月夜，往往取酒还独倾。","岂无山歌与村笛，呕唖嘲哳难为聴。","今夜闻君琵琶语，如聴仙楽耳暂明。","莫辞更坐弾一曲，为君飜作琵琶行。","感我此言良久立，却坐促弦弦転急。","凄凄不似向前声，満座重闻皆掩泣。","座中泣下谁最多，江州司马青衫湿。"],"source":"《唐诗三百首》"},{"title":"三湘怨","author":"范成大","dynasty":"宋","form":"诗","lines":["牙樯罨画橹，揺漾三湘浦。","佳人翔绿裾，含颦为谁舞。","拳拳新荷叶，愁绝烟水暮。","风云忽飘荡，隠约闻箫鼓。"],"source":"宋诗"},{"title":"汉宫春","author":"陆游","dynasty":"宋","form":"词","lines":["浪迹人间。","喜闻猿楚峡，学剑秦川。","虚舟泛然不系，万里江天。","朱颜绿鬓，作红尘、无事神仙。","何妨在，莺花海里，行歌闲送流年。","休笑放慵狂眼，看闲坊深院，多少婵娟。","燕宫海棠夜宴，花覆金船。","如椽画烛，酒阑时、百炬吹烟。","凭寄语，京华旧侣，幅巾莫换貂蝉。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・中吕/粉蝶儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["送的那水护衣为头，先使了熬麸浆细香澡豆，暖的那温泔清手面轻揉；打底干南定粉，把蔷擞露和就；破开那苏合香油，我嫌棘针梢燎的来油臭。"],"source":"元曲"},{"title":"采芑","author":"佚名","dynasty":"先秦","form":"诗","lines":["薄言采芑，于彼新田，呈此菑亩。方叔涖止，其车三千。师干之试，方叔率止。","乗其四骐，四骐翼翼。路车有奭，簟茀鱼服，钩膺鞗革。","薄言采芑，于彼新田，于此中乡。方叔涖止，其车三千。旗旐央央，方叔率止。","约軧错衡，八鸾玱玱。服其命服，朱芾斯皇，有玱葱珩。","𫛣彼飞隼，其飞戻天，亦集爰止。方叔涖止，其车三千。师干之试，方叔率止。","钲人伐鼓，陈师鞠旅。显允方叔，伐鼓渊渊，振旅阗阗。","蠢尔蛮荆，大邦为仇。方叔元老，克壮其犹。方叔率止，执讯获丑。戎车啴啴，","啴啴焞焞，如霆如雷。显允方叔，征伐𤞤狁，蛮荆来威。"],"source":"《诗经》"},{"title":"赋得古原草送别","author":"白居易","dynasty":"唐","form":"诗","lines":["离离原上草，一歳一枯栄。","野火焼不尽，春风吹又生。","远芳侵古道，晴翠接荒城。","又送王孙去，萋萋満别情。"],"source":"《唐诗三百首》"},{"title":"夜発昆山","author":"范成大","dynasty":"宋","form":"诗","lines":["歳寒人墐戸，霜重独登舟。","弱橹揺孤梦，疏篷盖百忧。","但吟今不楽，岂计几宜休。","惭愧沙湖月，年年照薄游。"],"source":"宋诗"},{"title":"汉宫春","author":"陆游","dynasty":"宋","form":"词","lines":["羽箭雕弓，忆呼鹰古垒，截虎平川。","吹笳暮归，野帐雪压青毡。","淋漓酔墨，看龙蛇、飞落蛮笺。","人误许，诗情将略，一时才气超然。","何事又作南来，看重阳药市，元夕灯山。","花时万人乐处，敧帽垂鞭。","闻歌感旧，尚时时、流涕尊前。","君记取，封侯事在，功名不信由天。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・酔春风","author":"关汉卿","dynasty":"元","form":"曲","lines":["那里敢深蘸着指头搽，我则索轻将绵絮纽。","比俺那门前乐探等着官身，我今日个不丑、丑。","虽不是宅院里夫人，也是那大人家姬妾，强似那上厅的祗候。"],"source":"元曲"},{"title":"车攻","author":"佚名","dynasty":"先秦","form":"诗","lines":["我车既攻，我马既同。四牡庞庞，驾言徂东。","田车既好，田牡孔阜。东有甫草，驾言行狩。","之子于苗，选徒嚣嚣。建旐设旄，搏兽于敖。","驾彼四牡，四牡奕奕。赤芾金舄，会同有绎。","决拾既佽，弓矢既调。射夫既同，助我举柴。","四黄既驾，两骖不猗。不失其驰，舎矢如破。","萧萧马鸣，悠悠旆旌。徒御不惊，大庖不盈。","之子于征，有闻无声。允矣君子，展也大成。"],"source":"《诗经》"},{"title":"自河南経乱関内阻饥兄弟离散各在一処因望月有感聊书所懐寄上浮梁大兄于潜七兄乌江十五兄兼示符离及下邽弟妹","author":"白居易","dynasty":"唐","form":"诗","lines":["时难年饥世业空，弟兄羇旅各西东。","田园寥落干戈后，骨肉流离道路中。","吊影分为千里鴈，辞根散作九秋蓬。","共看明月応垂涙，一夜郷心五処同。"],"source":"《唐诗三百首》"},{"title":"十一月十二日枕上暁作","author":"范成大","dynasty":"宋","form":"诗","lines":["竹响风成阵，窗明雪已花。","柴扉吟冻犬，纸瓦啄饥鸦。","宿酒欺寒力，新诗管歳华。","日高犹拥被，蓐食愧邻家。"],"source":"宋诗"},{"title":"月上海棠","author":"陆游","dynasty":"宋","form":"词","lines":["斜阳废苑朱门闭。","吊兴亡、遗恨泪痕里。","淡淡宫梅，也依然、点酥剪水。","凝愁处，似忆宣华旧事。","行人别有凄凉意。","折幽香、谁与寄千里。","伫立江皐，杳难逢、陇头归骑。","音尘远，楚天危楼独倚。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・石榴花","author":"关汉卿","dynasty":"元","form":"曲","lines":["我则道坐着的是那个俊儒流，我这里猛窥视细凝眸，原来是三年不肯往杭州，闪的我落后，有国难投！莫不是将咱故意相迤逗，特教的露丑呈羞？你觑那衣服毎各自施忠厚，百般儿省不的甚缘由。"],"source":"元曲"},{"title":"吉日","author":"佚名","dynasty":"先秦","form":"诗","lines":["吉日维戊，既伯既祷。田车既好，四牡孔阜。升彼大阜，从其群丑。","吉日庚午，既差我马。兽之所同，麀鹿麌麌。漆沮之从，天子之所。","瞻彼中原，其祁孔有。儦儦俟俟，或群或友。悉率左右，以燕天子。","既张我弓，既挟我矢。发彼小豝，殪此大兕。以御宾客，且以酌醴。"],"source":"《诗经》"},{"title":"问刘十九","author":"白居易","dynasty":"唐","form":"诗","lines":["绿螘新醅酒，红泥小火垆。","晩来天欲雪，能饮一杯无。"],"source":"《唐诗三百首》"},{"title":"南楼望雪","author":"范成大","dynasty":"宋","form":"诗","lines":["夜月流瑶圃，春风満玉都。","篱疏先剥落，树密正模糊。","乱点横烟鴈，惊啼失木乌。","酔魂方浩荡，风袖不支梧。"],"source":"宋诗"},{"title":"月上海棠","author":"陆游","dynasty":"宋","form":"词","lines":["兰房绣户厌厌病。","叹春酲、和闷甚时醒。","燕子空归，几曽传、玉关边信。","伤心处，独展团窠瑞锦。","熏笼消歇沈烟冷。","泪痕深、展转看花影。","漫拥馀香，怎禁他、峭寒孤枕。","西窗晓，几声银瓶玉井。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・斗鹌鹑","author":"关汉卿","dynasty":"元","form":"曲","lines":["并无那私事公仇，倒与俺张筵置酒。","（带云）我这一过去，说些甚幺的是？（唱）我则是佯不相瞅，怎敢道特来问候。","（见科）（钱大尹云）天香，与耆卿施礼咱。","（正旦唱）我这里施罢礼，官人行紧低首。","（钱大尹云）天香、近前来些。","（正旦唱）谁敢道是离了左右，我则索侍立旁边，我则索趋前褪后。"],"source":"元曲"},{"title":"鸿雁","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸿雁于飞，肃肃其羽。之子于征，劬劳于野。爰及矜人，哀此鳏寡。","鸿雁于飞，集于中泽。之子于垣，百堵皆作。虽则劬劳，其究安宅？","鸿雁于飞，哀鸣嗷嗷。维此哲人，谓我劬劳。维彼愚人，谓我宣骄。"],"source":"《诗经》"},{"title":"寻隠者不遇","author":"贾岛","dynasty":"唐","form":"诗","lines":["松下问童子，言师采薬去。","只在此山中，云深不知処。"],"source":"《唐诗三百首》"},{"title":"除夜书懐","author":"范成大","dynasty":"宋","form":"诗","lines":["运斗寅杓転，周天日御回。","夜従冬后短，春逐雨中来。","鬓绿看看雪，心丹念念灰。","有懐怜断鴈，无思惜疏梅。","絮厚眼生缬，蔬寒肠転雷。","烛花红琐砕，香雾碧徘徊。","昨梦书三箧，平生酒一杯。","床头新暦日，衣上旧尘埃。","揺落何堪柳，纷纭各梦槐。","隙光能几许，世事剧悠哉。","岐路东西変，羲娥日夜催。","头颅元自覚，懐抱故応开。","踊跃金何意，青黄木自灾。","身谋同斥鷃，政尔愿蒿莱。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["金鸭馀香尚暖，绿窗斜日偏明。","兰膏香染云鬟腻，钗坠滑无声。","冷落秋千伴侣，阑珊打马心情。","绣屏惊断潇湘梦，花外一声莺。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・哨遍","author":"关汉卿","dynasty":"元","form":"曲","lines":["一自才郎别后，相公那帘幕里香风透。","又无个交错觥筹，又无个宾客闲游饮杯酒，坐衙紧唤，乐探忙勾，唬的我难収救，只得向公厅祗候。","不问我舞旋，只着我歌讴。","将凤凰杯注酒尊前递，把商角调填词韵脚捜，唱到\"惨绿愁红\"。","\"事事可可\"，一时禁口。"],"source":"元曲"},{"title":"庭燎","author":"佚名","dynasty":"先秦","form":"诗","lines":["夜如何其？夜未央，庭燎之光。君子至止，鸾声将将。","夜如何其？夜未艾，庭燎晣晣。君子至止，鸾声哕哕。","夜如何其？夜乡晨，庭燎有辉。君子至止，言观其旗。"],"source":"《诗经》"},{"title":"利州南渡","author":"温庭筠","dynasty":"唐","form":"诗","lines":["澹然空水対斜晖，曲岛苍茫接翠微。","波上马嘶看櫂去，柳辺人歇待船帰。","数丛沙草群鴎散，万顷江田一鹭飞。","谁解乗舟寻范蠡，五湖烟水独忘机。"],"source":"《唐诗三百首》"},{"title":"戯答澹庵小偈","author":"范成大","dynasty":"宋","form":"诗","lines":["莫问前程事，漂然海上舟。","命乖逢鬼国，縁合遇蓬丘。","毕竟非身计，俱成错路头。","故郷随脚是，流浪不知休。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["檐角楠阴转日，楼前茘子吹花。","鹧鸪声里霜天晩，叠鼓已催衙。","乡梦时来枕上，京书不到天涯。","邦人讼少文移省，闲院自煎茶。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・耍孩儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["相公讳字都全有，我将别韵儿轻轻换偷；即时间乐案里便除名，扬言说要结绸缪。","三年甚事曽占着铺盖，千日何曽靠着枕头？相公意，难参透。","我本是沾泥飞絮，倒做了不缆孤舟！。"],"source":"元曲"},{"title":"沔水","author":"佚名","dynasty":"先秦","form":"诗","lines":["沔彼流水，朝宗于海。𫛣彼飞隼，载飞载止。嗟我兄弟，邦人诸友。莫肯念乱，谁无父母？","沔彼流水，其流汤汤。𫛣彼飞隼，载飞载扬。念彼不迹，载起载行。心之忧矣，不可弭忘。","𫛣彼飞隼，率彼中陵。民之讹言，宁莫之惩？我友敬矣，谗言其兴。"],"source":"《诗经》"},{"title":"瑶瑟怨","author":"温庭筠","dynasty":"唐","form":"诗","lines":["冰簟银床梦不成，碧天如水夜云軽。","雁声远过潇湘去，十二楼中月自明。"],"source":"《唐诗三百首》"},{"title":"偶书","author":"范成大","dynasty":"宋","form":"诗","lines":["出処由人不繋天，痴児富贵更求仙。","东家就食西家宿，世事何縁得両全。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["我校丹台玉字，君书蕊殿云篇。","锦官城里重相遇，心事两依然。","携酒何妨处处，寻梅共约年年。","细思上界多官府，且作地行仙。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・二煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["见妾身精神比杏桃，相公如何共卯酉？见天香颜色当春昼。","观花不比观娇态，饮酒合当饮巨瓯。","谁把清香嗅？则是深围在阑底，又何曽挿个花头！（钱大尹云）张千，快収拾车马，送谢夫人到状元宅上去！（柳同旦拝谢科，云）深感相公大恩！（正旦唱）。"],"source":"元曲"},{"title":"鹤鸣","author":"佚名","dynasty":"先秦","form":"诗","lines":["鹤鸣于九皐，声闻于野。鱼潜在渊，或在于渚。乐彼之园，爰有树檀，其下维萚。他山之石，可以为错。","鹤鸣于九皐，声闻于天。鱼在于渚，或潜在渊。乐彼之园，爰有树檀，其下维谷。他山之石，可以攻玉。"],"source":"《诗经》"},{"title":"送人东游","author":"温庭筠","dynasty":"唐","form":"诗","lines":["荒戍落黄叶，浩然离故関。","高风汉阳渡，初日郢门山。","江上几人在，天涯孤櫂还。","何当重相见，尊酒慰离颜。"],"source":"《唐诗三百首》"},{"title":"题立雪図","author":"范成大","dynasty":"宋","form":"诗","lines":["堂下心如鉄，庵中语似雷。","有人参此语，三个一坑埋。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["世事从来惯见，吾生更欲何之。","镜湖西畔秋千顷，鸥鹭共忘机。","一枕苹风午酔，二升菰米晨炊。","故人莫讶音书绝，钓侣是新知。"],"source":"宋词"},{"title":"钱大尹智宠谢天香・煞尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["这天香不想艳阳天气开，我则道无情干罢休！谁想这牡丹花折入东君手，今日个分与章台路傍柳。"],"source":"元曲"},{"title":"祈父","author":"佚名","dynasty":"先秦","form":"诗","lines":["祈父，予王之爪牙。胡转予于恤，靡所止居？","祈父，予王之爪士。胡转予于恤，靡所厎止？","祈父，亶不聪。胡转予于恤？有母之尸饔。"],"source":"《诗经》"},{"title":"苏武庙","author":"温庭筠","dynasty":"唐","form":"诗","lines":["苏武魂销汉使前，古祠高树両茫然。","云辺雁断胡天月，陇上羊帰塞草烟。","廻日楼台非甲帐，去时冠劒是丁年。","茂陵不见封侯印，空向秋波哭逝川。"],"source":"《唐诗三百首》"},{"title":"题日记","author":"范成大","dynasty":"宋","form":"诗","lines":["谁言万事転头空，未転头时亦梦中。","若向梦中寻梦覚，覚来还入大槐宫。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["素意幽栖物外，尘缘浪走天涯。","归来犹幸身强健，随分作山家。","已趁馀寒泥酒，还乗小雨移花。","柴门尽日无人到，一径傍渓斜。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・仙吕/端正好","author":"王实甫","dynasty":"元","form":"曲","lines":["因姐姐玉精神，花模样，无倒断晓夜思量。","着一片志诚心盖抹了漫天谎。","出画阁，向书房；离楚岫，赴高唐；学窃玉，试偷香；巫娥女，楚襄王；楚襄王敢先在阳台上。","(下)。"],"source":"元曲"},{"title":"白驹","author":"佚名","dynasty":"先秦","form":"诗","lines":["皎皎白驹，食我场苗。絷之维之，以永今朝。所谓伊人，于焉逍遥？","皎皎白驹，食我场藿。絷之维之，以永今夕。所谓伊人，于焉嘉客？","皎皎白驹，贲然来思。尔公尔侯，逸予无期？慎尔优游，勉尔遁思。","皎皎白驹，在彼空谷。生刍一束，其人如玉。毋金玉尔音，而有遐心。"],"source":"《诗经》"},{"title":"渡汉江","author":"李频","dynasty":"唐","form":"诗","lines":["岭外音书绝，経年复歴春。","近郷情更怯，不敢问来人。"],"source":"《唐诗三百首》"},{"title":"题张氏新亭","author":"范成大","dynasty":"宋","form":"诗","lines":["水杨成幄翠相遮，犹有东风管歳华。","叶底青梅无数子，梢头红杏不多花。","烦将錬火炊香饭，更引长泉煮鬭茶。","约我诗成须疥壁，莫嗔欹侧似帰鸦。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["园馆青林翠樾，衣巾细葛轻纨。","好风吹散霏微雨，沙路喜新干。","小燕双飞水际，流莺百啭林端。","投壶声断弹棋罢，闲展道书看。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・仙吕/点绛唇","author":"王实甫","dynasty":"元","form":"曲","lines":["伫立闲阶。","夜深香霭、横金界。","萧洒书斋，闷杀读书客。"],"source":"元曲"},{"title":"黄鸟","author":"佚名","dynasty":"先秦","form":"诗","lines":["黄鸟黄鸟，无集于谷，无啄我粟。此邦之人，不我肯谷。言旋言归，复我邦族。","黄鸟黄鸟，无集于桑，无啄我粱。此邦之人，不可与明。言旋言归，复我诸兄。","黄鸟黄鸟，无集于栩，无啄我黍。此邦之人，不可与处。言旋言归，复我诸父。"],"source":"《诗经》"},{"title":"贫女","author":"秦韬玉","dynasty":"唐","form":"诗","lines":["蓬门未识绮罗香，拟托良媒益自伤。","谁爱风流高格调，共怜时世倹梳妆。","敢将十指夸偏巧，不把双眉鬬画长。","苦恨年年圧金线，为他人作嫁衣裳。"],"source":"《唐诗三百首》"},{"title":"玉台体","author":"范成大","dynasty":"宋","form":"诗","lines":["卷幔灯千朶，钩帘月半弓。","繍鸳翔沥水，金雀跂屏风。","细意翩长袖，多情结短封。","铜壶従婉娩，玉珮正丁东。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["从宦元知漫浪，还家更觉清真。","兰亭道上多修竹，随处岸纶巾。","泉冽偏宜雪茗，粳香雅称丝莼。","け然一饱西窗下，天地有闲人。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・油葫芦","author":"王实甫","dynasty":"元","form":"曲","lines":["情思昏昏眼倦开，单枕侧，梦魂飞入梦阳台。","早知道无明无夜因他害，想当初\"不如不遇倾城色\"。","人有过，必自责，勿惮改。","我却待\"贤贤易色\"将心戒，怎禁他兜的上心来。"],"source":"元曲"},{"title":"我行其野","author":"佚名","dynasty":"先秦","form":"诗","lines":["我行其野，蔽芾其樗。婚姻之故，言就尔居。尔不我畜，复我邦家。","我行其野，言采其蓫。婚姻之故，言就尔宿。尔不我畜，言归斯复。","我行其野，言采其葍。不思旧姻，求尔新特。成不以富，亦祗以异。"],"source":"《诗经》"},{"title":"春宫怨","author":"周朴","dynasty":"唐","form":"诗","lines":["早被婵娟误，欲妆临镜慵。","承恩不在貌，教妾若为容。","风暖鸟声砕，日高花影重。","年年越渓女，相忆采芙蓉。"],"source":"《唐诗三百首》"},{"title":"枕上","author":"范成大","dynasty":"宋","form":"诗","lines":["明月无声満屋梁，梦余分影上人床。","素娥脉脉翻愁寂，付与风铃语夜长。"],"source":"宋诗"},{"title":"乌夜啼","author":"陆游","dynasty":"宋","form":"词","lines":["纨扇婵娟素月，纱巾缥渺轻烟。","高槐叶长阴初合，清润雨馀天。","弄笔斜行小草，钩帘浅酔闲眠。","更无一点尘埃到，枕上听新蝉。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・天下乐","author":"王实甫","dynasty":"元","form":"曲","lines":["我则索倚定门儿手托腮，好着我难猜：来也那不来？夫人行料应难离侧。","望得人眼欲穿，想得人心越窄，多管是冤家不自在。"],"source":"元曲"},{"title":"斯干","author":"佚名","dynasty":"先秦","form":"诗","lines":["秩秩斯干，幽幽南山。如竹苞矣，如松茂矣。兄及弟矣，式相好矣，无相犹矣。","似续妣祖，筑室百堵，西南其户。爰居爰处，爰笑爰语。","约之阁阁，椓之橐橐。风雨攸除，鸟鼠攸去，君子攸芋。","如跂斯翼，如矢斯棘，如鸟斯革，如翚斯飞，君子攸跻。","殖殖其庭，有觉其楹。哙哙其正，哕哕其冥。君子攸宁。","下莞上簟，乃安斯寝。乃寝乃兴，乃占我梦。吉梦维何？维熊维罴，维虺维蛇。","大人占之：维熊维罴，男子之祥；维虺维蛇，女子之祥。","乃生男子，载寝之床。载衣之裳，载弄之璋。其泣喤喤，朱芾斯皇，室家君王。","乃生女子，载寝之地。载衣之裼，载弄之瓦。无非无仪，唯酒食是议，无父母诒罹。"],"source":"《诗经》"},{"title":"孤鴈 二","author":"崔涂","dynasty":"唐","form":"诗","lines":["几行帰去尽，片影独何之。","暮雨相呼失，寒塘独下遅。","渚云低暗度，関月冷遥随。","未必逢矰缴，孤飞自可疑。"],"source":"《唐诗三百首》"},{"title":"斑骓","author":"范成大","dynasty":"宋","form":"诗","lines":["斑骓别后月繊繊，门外疏桐影画帘。","留下可怜将不去，西风吹上両眉尖。"],"source":"宋诗"},{"title":"真珠帘","author":"陆游","dynasty":"宋","form":"词","lines":["山村水馆参差路。","感羁游、正似残春风絮。","掠地穿帘，知是竟归何处。","镜里新霜空自悯，问几时、鸾台鳌署。","迟暮。","谩凭高怀远，书空独语。","自古。","儒冠多误。","悔当年、早不扁舟归去。","酔下白苹洲，看夕阳鸥鹭。","菰菜鲈鱼都弃了，只换得、青衫尘土。","休顾。","早収身江上，一蓑烟雨。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・那咤令","author":"王实甫","dynasty":"元","form":"曲","lines":["他若是肯来，早身离贵宅；他若是到来，便春生敝斋；他若是不来，似石沉大海。","数着他脚歩儿行，倚定窗棂儿待。","寄语多才：。"],"source":"元曲"},{"title":"无羊","author":"佚名","dynasty":"先秦","form":"诗","lines":["谁谓尔无羊？三百维群。谁谓尔无牛？九十其犉。尔羊来思，其角濈濈。尔牛来思，其耳湿湿。","或降于阿，或饮于池，或寝或讹。尔牧来思，何蓑何笠，或负其糇。三十维物，尔牲则具。","尔牧来思，以薪以蒸，以雌以雄。尔羊来思，矜矜兢兢，不骞不崩。麾之以肱，毕来既升。","牧人乃梦，众维鱼矣，旐维旟矣，大人占之；众维鱼矣，实维丰年；旐维旟矣，室家溱溱。"],"source":"《诗经》"},{"title":"巴山道中除夜书懐","author":"崔涂","dynasty":"唐","form":"诗","lines":["迢遰三巴路，羇危万里身。","乱山残雪夜，孤烛异郷春。","渐与骨肉远，転于僮仆亲。","那堪正漂泊，明日歳华新。"],"source":"《唐诗三百首》"},{"title":"题伝记二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["莫将彩笔寄朝云，红涙罗巾隔路尘。","说与东风无限恨，倩风吹断去年春。"],"source":"宋诗"},{"title":"好事近","author":"陆游","dynasty":"宋","form":"词","lines":["混迹寄人间，夜夜画楼银烛。","谁见五云丹灶，养黄芽初熟。","春风归从紫皇游，东海宴晹谷。","进罢碧桃花赋，赐玉尘千斛。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・鹊踏枝","author":"王实甫","dynasty":"元","form":"曲","lines":["恁的般恶抢白，并不曽记心怀；抜得个意转心回，夜去明来。","空调眼色经今半载，这其间委实难挨。"],"source":"元曲"},{"title":"节南山","author":"佚名","dynasty":"先秦","form":"诗","lines":["节彼南山，维石岩岩。赫赫师尹，民具尔瞻。忧心如惔，不敢戏谈。国既卒斩，何用不监！","节彼南山，有实其猗。赫赫师尹，不平谓何。天方荐瘥，丧乱弘多。民言无嘉，惨莫惩嗟。","尹氏大师，维周之氐；秉国之钧，四方是维。天子是毗，俾民不迷。不吊昊天，不宜空我师。","弗躬弗亲，庶民弗信。弗问弗仕，勿罔君子。式夷式已，无小人殆。琐琐姻亚，则无膴仕。","昊天不佣，降此鞠讻。昊天不恵，降此大戻。君子如届，俾民心阕。君子如夷，恶怒是违。","不吊昊天，乱靡有定。式月斯生，俾民不宁。忧心如酲，谁秉国成？不自为政，卒劳百姓。","驾彼四牡，四牡项领。我瞻四方，蹙蹙靡所骋。","方茂尔恶，相尔矛矣。既夷既怿，如相酬矣。","昊天不平，我王不宁。不惩其心，覆怨其正。","家父作诵，以究王讻。式讹尔心，以畜万邦。"],"source":"《诗经》"},{"title":"宫词二首 一","author":"张祜","dynasty":"唐","form":"诗","lines":["故国三千里，深宫二十年。","一声河満子，双涙落君前。"],"source":"《唐诗三百首》"},{"title":"题伝记二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["彩舟帰去海山青，寂莫瑶台月自明。","啼雨落花春已尽，梦魂何必更多情。"],"source":"宋诗"},{"title":"柳梢青","author":"陆游","dynasty":"宋","form":"词","lines":["锦里繁华。","环宫故邸，叠萼奇花。","俊客妖姬，争飞金勒，齐驻香车。","何须幕障帏遮。","宝杯浸、红云瑞霞。","银烛光中，清歌声里，休恨天涯。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・寄生草","author":"王实甫","dynasty":"元","form":"曲","lines":["安排着害，准备着擡。","想着这异乡身强把茶汤挨，则为这可憎才熬得心肠耐，办一片志诚心留得形骸在。","试着那司天台打算半年愁，端的是太平车约有十余载。"],"source":"元曲"},{"title":"正月","author":"佚名","dynasty":"先秦","form":"诗","lines":["正月繁霜，我心忧伤。民之讹言，亦孔之将。念我独兮，忧心京京。哀我小心，癙忧以痒。","父母生我，胡俾我瘉？不自我先，不自我后。好言自口，莠言自口。忧心愈愈，是以有侮。","忧心惸惸，念我无禄。民之无辜，并其臣仆。哀我人斯，于何从禄？瞻乌爰止？于谁之屋？","瞻彼中林，侯薪侯蒸。民今方殆，视天梦梦。既克有定，靡人弗胜。有皇上帝，伊谁云憎？","谓山盖卑，为冈为陵。民之讹言，宁莫之惩。召彼故老，讯之占梦。具曰予圣，谁知乌之雌雄！","谓天盖高，不敢不局。谓地盖厚，不敢不蹐。维号斯言，有伦有脊。哀今之人，胡为虺蜴？","瞻彼阪田，有菀其特。天之杌我，如不我克。彼求我则，如不我得。执我仇仇，亦不我力。","心之忧矣，如或结之。今兹之正，胡然厉矣？燎之方扬，宁或灭之？赫赫宗周，褒姒灭之！","终其永怀，又窘阴雨。其车既载，乃弃尔辅。载输尔载，将伯助予！","无弃尔辅，员于尔辐。屡顾尔仆，不输尔载。终逾绝险，曽是不意。","鱼在于沼，亦匪克乐。潜虽伏矣，亦孔之炤。忧心惨惨，念国之为虐！","彼有旨酒，又有嘉肴。洽比其邻，婚姻孔云。念我独兮，忧心殷殷。","佌佌彼有屋，蔌蔌方有谷。民今之无禄，天夭是椓。哿矣富人，哀此惸独。"],"source":"《诗经》"},{"title":"赠内人","author":"张祜","dynasty":"唐","form":"诗","lines":["禁门宫树月痕过，媚眼唯看宿燕窠。","斜抜玉钗灯影畔，剔开红焔救飞蛾。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["空里情知不着花，逢场将病当生涯。","蒲団软暖无时节，夜聴蚊雷暁聴鸦。"],"source":"宋诗"},{"title":"柳梢青","author":"陆游","dynasty":"宋","form":"词","lines":["十载江湖，行歌沽酒，不到京华。","底事翩然，长亭烟草，衰鬓风沙。","凭高目断天涯。","细雨外、楼台万家。","只恐明朝，一时不见，人共梅花。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・村里迓鼓","author":"王实甫","dynasty":"元","form":"曲","lines":["猛见他可憎模样，--小生那里得病来--早医可九分不快。","先前见责，谁承望今宵欢爱！着小姐这般用心，不才张珙，合当跪拝。","小生无宋玉般容，潘安般貌，子建般才；姐姐，你则是可怜见为人在客！。"],"source":"元曲"},{"title":"十月之交","author":"佚名","dynasty":"先秦","form":"诗","lines":["十月之交，朔月辛卯。日有食之，亦孔之丑。彼月而微，此日而微；今此下民，亦孔之哀。","日月告凶，不用其行。四国无政，不用其良。彼月而食，则维其常；此日而食，于何不臧。","烨烨震电，不宁不令。百川沸腾，山冢崒崩。高岸为谷，深谷为陵。哀今之人，胡惨莫惩？","皇父卿士，番维司徒，家伯维宰，仲允膳夫，棸子内史，蹶维趣马，楀维师氏。醘妻煽方处。","抑此皇父，岂曰不时？胡为我作，不即我谋？彻我墙屋，田卒汚莱。曰予不戕，礼则然矣。","皇父孔圣，作都于向。择三有事，亶侯多蔵。不慭遗一老，俾守我王。择有车马，以居徂向。","黾勉从事，不敢告劳。无罪无辜，谗口嚣嚣。下民之孽，匪降自天。噂沓背憎，职竞由人。","悠悠我里，亦孔之痗。四方有羡，我独居忧。民莫不逸，我独不敢休。天命不彻，我不敢効我友自逸。"],"source":"《诗经》"},{"title":"集霊台二首 一","author":"张祜","dynasty":"唐","form":"诗","lines":["日光斜照集霊台，红树花迎暁露开。","昨夜上皇新授箓，太真含笑入帘来。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["溽暑薫天地涌泉，弯跧避湿挂行缠。","出门斟酌无忙事，睡过黄梅细雨天。"],"source":"宋诗"},{"title":"夜游宫","author":"陆游","dynasty":"宋","form":"词","lines":["雪晓清笳乱起。","梦游处、不知何地。","铁骑无声望似水。","想关河，雁门西，青海际。","睡觉寒灯里。","漏声断、月斜窗纸。","自许封侯在万里。","有谁知，鬓虽残，心未死。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・元和令","author":"王实甫","dynasty":"元","form":"曲","lines":["绣鞋儿刚半拆，柳腰儿勾一搦，羞答答不肯把头擡，只将鸳枕挨。","云鬟仿仏坠金钗，偏宜髟狄髻儿歪。"],"source":"元曲"},{"title":"雨无正","author":"佚名","dynasty":"先秦","form":"诗","lines":["浩浩昊天，不骏其徳。降丧饥馑，斩伐四国。旻天疾威，弗虑弗图。舎彼有罪，既伏其辜。若此无罪，沦胥以铺。","周宗既灭，靡所止戻。正大夫离居，莫知我勚。三事大夫，莫肯夙夜。邦君诸侯，莫肯朝夕。庶曰式臧，覆出为恶。","如何昊天，辟言不信。如彼行迈，则靡所臻。凡百君子，各敬尔身。胡不相畏，不畏于天？","戎成不退，饥成不遂。曽我暬御，惨惨日瘁。凡百君子，莫肯用讯。听言则答，谮言则退。","哀哉不能言，匪舌是出，维躬是瘁。哿矣能言，巧言如流，俾躬处休！","维曰予仕，孔棘且殆。云不何使，得罪于天子；亦云可使，怨及朋友。","谓尔迁于王都。曰予未有室家。鼠思泣血，无言不疾。昔尔出居，谁从作尔室？"],"source":"《诗经》"},{"title":"集霊台二首 二","author":"张祜","dynasty":"唐","form":"诗","lines":["虢国夫人承主恩，平明骑马入宫门。","却嫌脂粉汚颜色，淡扫蛾眉朝至尊。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["石鼎飕飕夜煮汤，乱拖芝术鬭温凉。","化児幻我知何用，祗与人间试薬方。"],"source":"宋诗"},{"title":"夜游宫","author":"陆游","dynasty":"宋","form":"词","lines":["独夜寒侵翠被。","奈幽梦、不成还起。","欲写新愁泪溅纸。","忆承恩，叹馀生，今至此。","蔌蔌灯花坠。","问此际、报人何事。","咫尺长门过万里。","恨君心，似危栏，难久倚。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・胜葫芦","author":"王实甫","dynasty":"元","form":"曲","lines":["我这里软玉温香抱满怀。","呀，阮肇到天台，春至人间花弄色。","将柳腰款摆，花心轻拆，露滴牡丹开。"],"source":"元曲"},{"title":"小旻","author":"佚名","dynasty":"先秦","form":"诗","lines":["旻天疾威，敷于下土。谋犹回遹，何日斯沮？谋臧不从，不臧覆用。我视谋犹，亦孔之邛。","潝潝訿訿，亦孔之哀。谋之其臧，则具是违。谋之不臧，则具是依。我视谋犹，伊于胡厎。","我龟既厌，不我告犹。谋夫孔多，是用不集。发言盈庭，谁敢执其咎？如匪行迈谋，是用不得于道。","哀哉为犹，匪先民是程，匪大犹是经。维迩言是听，维迩言是争。如彼筑室于道谋，是用不溃于成。","国虽靡止，或圣或否。民虽靡膴，或哲或谋，或肃或艾。如彼泉流，无沦胥以败。","不敢暴虎，不敢冯河。人知其一，莫知其他。战战兢兢，如临深渊，如履薄冰。"],"source":"《诗经》"},{"title":"题金陵渡","author":"张祜","dynasty":"唐","form":"诗","lines":["金陵津渡小山楼，一宿行人自可愁。","潮落夜江斜月里，両三星火是瓜州。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["病中心境両俱降，犹忆江湖白鸟双。","一夜雨声鸣纸瓦，聴成飞雪打船窗。"],"source":"宋诗"},{"title":"安公子","author":"陆游","dynasty":"宋","form":"词","lines":["风雨初经社。","子规声里春光谢。","最是无情，零落尽、蔷薇一架。","况我今年，憔悴幽窗下。","人尽怪、诗酒消声价。","向药炉经巻，忘却莺窗柳榭。","万事収心也。","粉痕犹在香罗帕。","恨月愁花，争信道、如今都罢。","空忆前身，便面章台马。","因自来、禁得心肠怕。","纵遇歌逢酒，但说京都旧话。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・后庭花","author":"王实甫","dynasty":"元","form":"曲","lines":["春罗原莹白，早见红香点嫩色。","(旦云)羞人答答的，看甚幺？(末)灯下偷晴觑，胸前着肉揣。","畅奇战，浑身通泰，不知春从何处来？无能的张秀才，孤身西洛客，自从逢稔色，思量的不下怀；忧愁因间隔，相思无摆划，谢芳卿不见责。"],"source":"元曲"},{"title":"小宛","author":"佚名","dynasty":"先秦","form":"诗","lines":["宛彼鸣鸠，翰飞戻天。我心忧伤，念昔先人。明发不寐，有怀二人。","人之齐圣，饮酒温克。彼昏不知，一酔日富。各敬尔仪，天命不又。","中原有菽，庶民采之。螟蛉有子，蜾蠃负之。教诲尔子，式谷似之。","题彼脊令，载飞载鸣。我日斯迈，而月斯征。夙兴夜寐，毋忝尔所生。","交交桑扈，率场啄粟。哀我填寡，宜岸宜狱。握粟出卜，自何能谷？","温温恭人，如集于木。惴惴小心，如临于谷。战战兢兢，如履薄冰。"],"source":"《诗经》"},{"title":"宫词","author":"朱庆余","dynasty":"唐","form":"诗","lines":["寂寂花时闭院门，美人相并立琼轩。","含情欲说宫中事，鹦鹉前头不敢言。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其五","author":"范成大","dynasty":"宋","form":"诗","lines":["檐头排溜密如帘，渓上层阴定解厳。","最是看山奇绝処，白云堆絮拥青尖。"],"source":"宋诗"},{"title":"玉胡蝶・玉蝴蝶","author":"陆游","dynasty":"宋","form":"词","lines":["倦客平生行处，坠鞭京洛，解佩潇湘。","此夕何年，来赋宋玉高唐。","绣帘开、香尘乍起，莲歩稳、银烛分行。","暗端相。","燕羞莺妒，蝶绕蜂忙。","难忘。","芳樽频劝，峭寒新退，玉漏犹长。","几许幽情，只愁歌罢月侵廊。","欲归时、司空笑问，微近处，丞相嗔狂。","断人肠。","仮饶相送，上马何妨。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・柳叶儿","author":"王实甫","dynasty":"元","form":"曲","lines":["我将你做心肝儿般看待，点汚了小姐清白。","忘餐废寝舒心害，若不是真心耐，志诚挨，怎能够这相思苦尽甘来？。"],"source":"元曲"},{"title":"小弁","author":"佚名","dynasty":"先秦","form":"诗","lines":["弁彼鸴斯，归飞提提。民莫不谷，我独于罹。何辜于天？我罪伊何？心之忧矣，云如之何？","踧踧周道，鞫为茂草。我心忧伤，惄焉如捣。仮寐永叹，维忧用老。心之忧矣，疢如疾首。","维桑与梓，必恭敬止。靡瞻匪父，靡依匪母。不属于毛？不罹于里？天之生我，我辰安在？","菀彼柳斯，鸣蜩嘒嘒，有漼者渊，萑苇淠淠。譬彼舟流，不知所届，心之忧矣，不遑仮寐。","鹿斯之奔，维足伎伎。雉之朝雊，尚求其雌。譬彼坏木，疾用无枝。心之忧矣，宁莫之知？","相彼投兔，尚或先之。行有死人，尚或墐之。君子秉心，维其忍之。心之忧矣，涕既陨之。","君子信谗，如或酬之。君子不恵，不舒究之。伐木掎矣，析薪扡矣。舎彼有罪，予之佗矣。","莫高匪山，莫浚匪泉。君子无易由言，耳属于垣。无逝我梁，无发我笱。我躬不阅，遑恤我后。"],"source":"《诗经》"},{"title":"石鼓歌","author":"韩愈","dynasty":"唐","form":"诗","lines":["张生手持石鼓文，勧我试作石鼓歌。","少陵无人谪仙死，才薄将奈石鼓何。","周纲陵遅四海沸，宣王愤起挥天戈。","大开明堂受朝贺，诸侯劒佩鸣相磨。","搜于岐阳骋雄俊，万里禽獣皆遮罗。","镌功勒成告万世，凿石作鼓隳嵯峨。","従臣才芸咸第一，拣选撰刻留山阿。","雨淋日炙野火燎，鬼物守护烦㧑呵。","公従何処得纸本，毫髪尽备无差讹。","辞厳义密読难暁，字体不类隶与科。","年深岂免有欠画，快劒斫断生蛟鼍。","鸾翔凤翥众僊下，珊瑚碧树交枝柯。","金縄鉄索锁纽壮，古鼎跃水竜腾梭。","陋儒编诗不収入，二雅褊迫无委蛇。","孔子西行不到秦，掎摭星宿遗羲娥。","嗟予好古生苦晩，対此涕涙双滂沱。","忆昔初蒙博士徴，其年始改称元和。","故人従军在右辅，为我度量掘臼科。","濯冠沐浴告祭酒，如此至宝存岂多。","氊包席裹可立致，十鼓祗载数骆驼。","荐诸太庙比郜鼎，光価岂止百倍过。","圣恩若许留太学，诸生讲解得切磋。","観経鸿都尚填咽，坐见挙国来奔波。","剜苔剔藓露节角，安置妥帖平不颇。","大厦深檐与盖覆，経歴久远期无佗。","中朝大官老于事，讵肯感激徒媕婀。","牧童敲火牛砺角，谁复着手为摩挲。","日销月铄就埋没，六年西顾空吟哦。","羲之俗书趁姿媚，数纸尚可博白鹅。","継周八代争戦罢，无人収拾理则那。","方今太平日无事，柄任儒术崇丘轲。","安能以此上论列，愿借弁口如悬河。","石鼓之歌止于此，呜呼吾意其蹉跎。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其六","author":"范成大","dynasty":"宋","form":"诗","lines":["夜合梢头蘸紫茸，菉葱顶上拆黄封。","去年団扇题诗処，依旧疏帘细雨中。"],"source":"宋诗"},{"title":"木兰花慢","author":"陆游","dynasty":"宋","form":"词","lines":["阅邯郸梦境，叹绿鬓、早霜侵。","奈华岳烧丹，青渓看鹤，尚负初心。","年来向浊世里，悟真诠秘诀绝幽深。","养就金芝九畹，种成琪树千林。","星坛夜学歩虚吟。","露冷透瑶簪。","对翠凤披云，青鸾溯月，宫阙萧森。","琅函一封奏罢，自钧天帝所有知音。","却过蓬壶啸傲，世间岁月骎骎。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・青哥儿","author":"王实甫","dynasty":"元","form":"曲","lines":["成就了今宵欢爱，魂正在九霄云外。","投至得见你多情小奶奶，憔悴形骸，痩似麻秸。","今夜和谐，犹自疑猜。","露滴香埃，风静闲阶，月射书斋，云锁阳台；审问明白，只疑是昨夜梦中来，愁无奈。"],"source":"元曲"},{"title":"巧言","author":"佚名","dynasty":"先秦","form":"诗","lines":["悠悠昊天，曰父母且。无罪无辜，乱如此幠。昊天已威，予慎无罪。昊天大幠，予慎无辜。","乱之初生，僭始既涵。乱之又生，君子信谗。君子如怒，乱庶遄沮。君子如祉，乱庶遄已。","君子屡盟，乱是用长。君子信盗，乱是用暴。盗言孔甘，乱是用餤。匪其止共，维王之邛。","奕奕寝庙，君子作之。秩秩大猷，圣人莫之。他人有心，予忖度之。跃跃毚兔，遇犬获之。","荏染柔木，君子树之。往来行言，心焉数之。蛇蛇硕言，出自口矣。巧言如簧，颜之厚矣。","彼何人斯？居河之麋。无拳无勇，职为乱阶。既微且尰，尔勇伊何？为犹将多，尔居徒几何？"],"source":"《诗经》"},{"title":"秋夜曲","author":"王涯","dynasty":"唐","form":"诗","lines":["桂魄初生秋露微，軽罗已薄未更衣。","银筝夜久殷勤弄，心怯空房不忍帰。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其七","author":"范成大","dynasty":"宋","form":"诗","lines":["盆倾瓴建夜翻渠，绕屋蛙声一倍粗。","想见西堂浑不睡，明朝踏湿看菖蒲。"],"source":"宋诗"},{"title":"苏武慢","author":"陆游","dynasty":"宋","form":"词","lines":["澹霭空蒙，轻阴清润，绮陌细尘初静。","平桥系马，画阁移舟，湖水倒空如镜。","掠岸飞花，傍檐新燕，都似学人无定。","叹连年戎帐，经春边垒，暗凋颜鬓。","空记忆、杜曲池台，新丰歌管，怎得故人音信。","羁怀易感，老伴无多，谈麈久闲犀柄。","惟有修然，笔床茶灶，自适笋舆烟艇。","待绿荷遮岸，红蕖浮水，更乗幽兴。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・寄生草","author":"王实甫","dynasty":"元","form":"曲","lines":["多丰韵，忒稔色。","乍时相见教人害，霎时不见教人怪，些儿得见教人爱。","今宵同会碧纱厨，何时重解香罗带。"],"source":"元曲"},{"title":"何人斯","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼何人斯？其心孔艰。胡逝我梁，不入我门？伊谁云从？维暴之云。","二人从行，谁为此祸？胡逝我梁，不入唁我？始者不如今，云不我可","彼何人斯？胡逝我陈？我闻其声，不见其身。不愧于人？不畏于天？","彼何人斯？其为飘风。胡不自北？胡不自南？胡逝我梁？𫄨搅我心。","尔之安行，亦不遑舎。尔之亟行，遑脂尔车。一者之来，云何其盱。","尔还而入，我心易也。还而不入，否难知也。一者之来，俾我𫄨也。","伯氏吹埙，仲氏吹篪。及尔如贯，谅不我郑出此三物，以诅尔斯。","为鬼为蜮，则不可得。有腼面目，视人罔极。作此好歌，以极反侧。"],"source":"《诗经》"},{"title":"晨诣超师院読禅経","author":"柳宗元","dynasty":"唐","form":"诗","lines":["汲井漱寒歯，清心払尘服。","闲持贝叶书，歩出东斎読。","真源了无取，妄迹世所逐。","遗言冀可冥，缮性何由熟。","道人庭宇静，苔色连深竹。","日出雾露余，青松如膏沐。","澹然离言说，悟悦心自足。"],"source":"《唐诗三百首》"},{"title":"病中绝句八首  其八","author":"范成大","dynasty":"宋","form":"诗","lines":["晴色先従喜鹊知，斜阳一抹照天西。","竹鶏何物能无頼，如许泥深更苦啼。"],"source":"宋诗"},{"title":"齐天乐","author":"陆游","dynasty":"宋","form":"词","lines":["角残锺晩关山路，行人乍依孤店。","塞月征尘，鞭丝帽影，常把流年虚占。","蔵鸦柳暗。","叹轻负莺花，谩劳书剑。","事往关情，悄然频动壮游念。","孤怀谁与强遣。","市垆沽酒，酒薄怎当愁酽。","倚瑟妍词，调铅妙笔，那写柔情芳艳。","征途自厌。","况烟敛芜痕，雨稀萍点。","最是眠时，枕寒门半掩。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・煞尾","author":"王实甫","dynasty":"元","form":"曲","lines":["春意透酥胸，春色横眉黛，贱却人间玉帛。","杏脸桃腮，乗着月色，娇滴滴越显得红白。","下香阶，懒歩苍苔，动人处弓鞋凤头窄。","叹鲰生不才，谢多娇错爱。","若小姐不弃小生，此情一心者，你是必破工夫明夜早些来。","(下)。"],"source":"元曲"},{"title":"巷伯","author":"佚名","dynasty":"先秦","form":"诗","lines":["萋兮斐兮，成是贝锦。彼谮人者，亦已大甚！","哆兮侈兮，成是南箕。彼谮人者，谁适与谋。","缉缉翩翩，谋欲谮人。慎尔言也，谓尔不信。","捷捷幡幡，谋欲谮言。岂不尔受？既其女迁。","骄人好好，劳人草草。苍天苍天，视彼骄人，矜此劳人。","彼谮人者，谁适与谋？取彼谮人，投畀豺虎。豺虎不食，投畀有北。有北不受，投畀有昊！","杨园之道，猗于亩丘。寺人孟子，作为此诗。凡百君子，敬而听之。"],"source":"《诗经》"},{"title":"登柳州城楼寄漳汀封连四州","author":"柳宗元","dynasty":"唐","form":"诗","lines":["城上高楼接大荒，海天愁思正茫茫。","惊风乱飐芙蓉水，密雨斜侵薜茘墙。","岭树重遮千里目，江流曲似九廻肠。","共来百越文身地，犹自音书滞一郷。"],"source":"《唐诗三百首》"},{"title":"病中三偈  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["扰扰随流无定期，波停浪息始応知。","一尘不偶同帰処，四海无亲独歩时。","苦相打通俱入妙，病縁才入更何疑。","霜清木落千山露，笑杀东风叶満枝。"],"source":"宋诗"},{"title":"齐天乐","author":"陆游","dynasty":"宋","form":"词","lines":["客中随处闲消闷，来寻啸台龙岫。","路敛春泥，山开翠雾，行乐年年依旧。","天工妙手。","放轻绿萱牙，淡黄杨柳。","笑问东君，为人能染鬓丝否。","西州催去近也，帽檐风软，且看市楼沽酒。","宛转巴歌，凄凉塞管，携客何妨频奏。","征尘暗袖。","漫禁得梅花，伴人疏痩。","几日东归，画船平放溜。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・越调/斗鹌鹑","author":"王实甫","dynasty":"元","form":"曲","lines":["则着你夜去明来，倒有个天长地久，不争你握雨携云，常使我提心在口。","你则合带月披星，谁着你停眠整宿？老夫人心数多，情性亻刍；使不着我巧语花言，将没做有。"],"source":"元曲"},{"title":"谷风","author":"佚名","dynasty":"先秦","form":"诗","lines":["习习谷风，维风及雨。将恐将惧，维予与女。将安将乐，女转弃予。","习习谷风，维风及颓。将恐将惧，置予于怀。将安将乐，弃予如遗。","习习谷风，维山崔嵬。无草不死，无木不萎。忘我大徳，思我小怨。"],"source":"《诗经》"},{"title":"渓居","author":"柳宗元","dynasty":"唐","form":"诗","lines":["久为簪组累，幸此南夷谪。","闲依农圃邻，偶似山林客。","暁耕翻露草，夜榜响渓石。","来往不逢人，长歌楚天碧。"],"source":"《唐诗三百首》"},{"title":"病中三偈  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["一交销取万黄金，将病求医在用心。","化尽此身成薬树，不妨栽得病根深。"],"source":"宋诗"},{"title":"望梅","author":"陆游","dynasty":"宋","form":"词","lines":["寿非金石。","恨天教老向，水程山驿。","似梦里、来到南柯，这些子光阴，更勘轻掷。","戍火边尘，又过了、一年春色。","叹名姬骏马，尽付杜陵，苑路豪客。","长绳漫劳系日。","看人间俯仰，俱是陈迹。","纵自倚、英气凌云，奈回尽鹏程，铩残鸾翮。","终日凭高，诮不见、江东消息。","算沙边、也有断鸿，倩谁问得。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・紫花儿序","author":"王实甫","dynasty":"元","form":"曲","lines":["老夫人猜那穷酸做了新婿，小姐做了娇妻，这小贱人做了牵头。","俺小姐这些时春山低翠，秋水凝眸。","别样的都休，试把你裙带儿拴，纽门儿扣，比着你旧时肥痩，出落得精神，别样的风流。","(旦云)红娘，你到那里小心回话者！(红云)我到夫人处，必问：\"这小贱人，。"],"source":"元曲"},{"title":"蓼莪","author":"佚名","dynasty":"先秦","form":"诗","lines":["蓼蓼者莪，匪莪伊蒿。哀哀父母，生我劬劳。","蓼蓼者莪，匪莪伊蔚。哀哀父母，生我劳瘁。","瓶之罄矣，维罍之耻。鲜民之生，不如死之久矣。无父何怙？无母何恃？出则衔恤，入则靡至。","父兮生我，母兮鞠我。抚我畜我，长我育我，顾我复我，出入腹我。欲报之徳。昊天罔极！","南山烈烈，飘风发发。民莫不谷，我独何害！南山律律，飘风弗弗。民莫不谷，我独不卒！"],"source":"《诗经》"},{"title":"江雪","author":"柳宗元","dynasty":"唐","form":"诗","lines":["千山鸟飞绝，万迳人踪灭。","孤舟蓑笠翁，独钓寒江雪。"],"source":"《唐诗三百首》"},{"title":"病中三偈  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["莫把无言绝病根，病根深処是无言。","丈夫解却维摩缚，八字轰开不二门。"],"source":"宋诗"},{"title":"洞庭春色・沁园春","author":"陆游","dynasty":"宋","form":"词","lines":["壮岁文章，暮年勋业，自昔误人。","算英雄成败，轩裳得失，难如人意，空丧天真。","请看邯郸当日梦，待炊罢黄粱徐欠伸。","方知道，许多时富贵，何处关身。","人间定无可意，怎换得、玉鲙丝莼。","且钓竿渔艇，笔床茶灶，闲听荷雨，一洗衣尘。","洛水秦关千古后，尚棘暗铜驼空怆神。","何须更，慕封侯定远，图像麒麟。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・金蕉叶","author":"王实甫","dynasty":"元","form":"曲","lines":["\"我着你但去处行监坐守，谁着你拖逗的胡行乱走？\"若问着此一节呵如何诉休？你便索与他个\"知情\"的犯由。"],"source":"元曲"},{"title":"大东","author":"佚名","dynasty":"先秦","form":"诗","lines":["有饛簋飧，有捄棘匕。周道如砥，其直如矢。君子所履，小人所视。眷言顾之，潸焉出涕。","小东大东，杼柚其空。纠纠葛屦，可以履霜。佻佻公子，行彼周行。既往既来，使我心疚。","有冽氿泉，无浸获薪。契契寤叹，哀我惮人。薪是获薪，尚可载也。哀我惮人，亦可息也。","东人之子，职劳不来。西人之子，粲粲衣服。舟人之子，熊罴是裘。私人之子，百僚是试。","或以其酒，不以其浆。鞙鞙佩璲，不以其长。维天有汉，监亦有光。跂彼织女，终日七襄。","虽则七襄，不成报章。睆彼牵牛，不以服箱。东有启明，西有长庚。有捄天毕，载施之行。","维南有箕，不可以簸扬。维北有斗，不可以挹酒浆。维南有箕，载翕其舌。维北有斗，西柄之掲。"],"source":"《诗经》"},{"title":"渔翁","author":"柳宗元","dynasty":"唐","form":"诗","lines":["渔翁夜傍西巌宿，暁汲清湘燃楚竹。","烟销日出不见人，[欸]乃一声山水绿。","回看天际下中流，巌上无心云相逐。"],"source":"《唐诗三百首》"},{"title":"云间湖光亭","author":"范成大","dynasty":"宋","form":"诗","lines":["微风不动敛涛湍，组练晶晶色界寒。","斜照発挥犹未尽，月明残夜更来看。"],"source":"宋诗"},{"title":"渔家傲","author":"陆游","dynasty":"宋","form":"词","lines":["东望山阴何处是。","往来一万三千里。","写得家书空满纸。","流清泪。","书回已是明年事。","寄语红桥桥下水。","扁舟何日寻兄弟。","行遍天涯真老矣。","愁无寐。","鬓丝几缕茶烟里。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・调笑令","author":"王实甫","dynasty":"元","form":"曲","lines":["你绣帏里効绸缪，倒凤颠鸾百事有。","我在窗儿外几曽轻咳嗽，立苍苔将绣鞋儿冰透。","今日个嫩皮肤到将粗棍抽，姐姐呵，俺这通殷勤的着甚来由？。"],"source":"元曲"},{"title":"四月","author":"佚名","dynasty":"先秦","form":"诗","lines":["四月维夏，六月徂署。先祖匪人，胡宁忍予？","秋日凄凄，百卉具腓。乱离瘼矣，爰其适归？","冬日烈烈，飘风发发。民莫不谷，我独何害？","山有嘉卉，侯栗侯梅。废为残贼，莫知其尤！","相彼泉水，载清载浊。我日构祸，曷云能谷？","滔滔江汉，南国之纪。尽瘁以仕，宁莫我有？","匪鹑匪鸢，翰飞戻天。匪鳣匪鲔，潜逃于渊。","山有蕨薇，隰有杞桋。君子作歌，维以告哀。"],"source":"《诗经》"},{"title":"蜀先主庙","author":"刘禹锡","dynasty":"唐","form":"诗","lines":["天地英雄気，千秋尚凛然。","势分三足鼎，业复五铢銭。","得相能开国，生児不象贤。","凄凉蜀故妓，来舞魏宫前。"],"source":"《唐诗三百首》"},{"title":"高景庵泉亭","author":"范成大","dynasty":"宋","form":"诗","lines":["峰头挥手笑红尘，天入双眸洗翳昏。","万里西风熟秔稲，白云堆里着黄云。"],"source":"宋诗"},{"title":"绣停针","author":"陆游","dynasty":"宋","form":"词","lines":["叹半纪，跨万里秦吴，顿觉衰谢。","回首鹓行，英俊并游，咫尺玉堂金马。","气凌嵩华。","负壮略、纵横王覇。","梦经洛浦梁园，觉来泪流如泻。","山林定去也。","却自恐说着，少年时话。","静院焚香，闲倚素屏，今古总成虚仮。","趁时婚嫁。","幸自有、湖边茅舎。","燕归应笑，客中又还过社。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・鬼三台","author":"王实甫","dynasty":"元","form":"曲","lines":["夜坐时停了针绣，共姐姐闲穷究，说张生哥哥病久。","咱两个背着夫人，向书房问候。","(夫人云)问候呵，他说甚幺？(红云)他说来，道\"老夫人事已休，将恩变为仇，着小生半途喜变做忧\"。","他道：\"红娘你且先行，教小姐权时落后。"],"source":"元曲"},{"title":"北山","author":"佚名","dynasty":"先秦","form":"诗","lines":["陟彼北山，言采其杞。偕偕士子，朝夕从事。王事靡盬，忧我父母。","溥天之下，莫非王土；率土之滨，莫非王臣。大夫不均，我从事独贤。","四牡彭彭，王事傍傍。嘉我未老，鲜我方将。旅力方刚，经营四方。","或燕燕居息，或尽瘁事国；或息偃在床，或不已于行。","或不知叫号，或惨惨劬劳；或栖迟偃仰，或王事鞅掌。","或湛乐饮酒，或惨惨畏咎；或出入风议，或靡事不为。"],"source":"《诗经》"},{"title":"月夜","author":"杜甫","dynasty":"唐","form":"诗","lines":["今夜鄜州月，闺中只独看。","遥怜小児女，未解忆长安。","香雾云鬟湿，清辉玉臂寒。","何时倚虚幌，双照涙痕干。"],"source":"《唐诗三百首》"},{"title":"晩入盘门","author":"范成大","dynasty":"宋","form":"诗","lines":["人语嘲喧晩吹凉，万窗灯火転河塘。","両行碧柳笼官渡，一簇红楼圧女墙。","何処采菱闻度曲，谁家拝月认飘香。","軽裘骏马慵穿市，困倚蒲団入睡郷。"],"source":"宋诗"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["斜阳寂历柴门闭。","一点炊烟时起。","鸡犬往来林外。","俱有萧然意。","衰翁老去疏荣利。","绝爱山城无事。","临去画楼频倚。","何日重来此。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・秃厮儿","author":"王实甫","dynasty":"元","form":"曲","lines":["我则道神针法灸，谁承望燕侣莺俦。","他两个经今月余则是一处宿，何须你一一问缘由？。"],"source":"元曲"},{"title":"无将大车","author":"佚名","dynasty":"先秦","form":"诗","lines":["无将大车，祇自尘兮。无思百忧，祇自疧兮。","无将大车，维尘冥冥。无思百忧，不出于颎。","无将大车，维尘雍兮。无思百忧，祇自重兮。"],"source":"《诗经》"},{"title":"春望","author":"杜甫","dynasty":"唐","form":"诗","lines":["国破山河在，城春草木深。","感时花溅涙，恨别鸟惊心。","烽火连三月，家书抵万金。","白头掻更短，浑欲不胜簪。"],"source":"《唐诗三百首》"},{"title":"九月三十日夜出関候致远不至","author":"范成大","dynasty":"宋","form":"诗","lines":["风劲便軽棹，霜厳怯弊裘。","青山蟠巨浸，红树立沧洲。","月黒鴈犹去，灯寒人更愁。","烟松漫小岘，何処问鸣驺。"],"source":"宋诗"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["栏干几曲高斋路。","正在重云深处。","丹碧未干人去。","高栋空留句。","离离芳草长亭暮。","无奈征车不住。","惟有断鸿烟渚。","知我频回顾。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・圣药王","author":"王实甫","dynasty":"元","form":"曲","lines":["他毎不识忧，不识愁，一双心意两相投。","夫人得好休，便好休，这其间何必苦追求？常言道\"女大不中留\"。"],"source":"元曲"},{"title":"小明","author":"佚名","dynasty":"先秦","form":"诗","lines":["明明上天，照临下土。我征徂西，至于艽野。二月初吉，载离寒暑。","心之忧矣，其毒大苦。念彼共人，涕零如雨。岂不怀归？畏此罪罟！","昔我往矣，日月方除。曷云其还？岁聿云莫。念我独兮，我事孔庶。","心之忧矣，惮我不暇。念彼共人，眷眷怀顾！岂不怀归？畏此谴怒。","昔我往矣，日月方奥。曷云其还？政事愈蹙。岁聿云莫，采萧获菽。","心之忧矣，自诒伊戚。念彼共人，兴言出宿。岂不怀归？畏此反复。","嗟尔君子，无恒安处。靖共尔位，正直是与。神之听之，式谷以女。","嗟尔君子，无恒安息。靖共尔位，好是正直。神之听之，介尔景福。"],"source":"《诗经》"},{"title":"春宿左省","author":"杜甫","dynasty":"唐","form":"诗","lines":["花隠掖垣暮，啾啾栖鸟过。","星临万戸动，月傍九霄多。","不寝聴密钥，因风想玉珂。","明朝有封事，数问夜如何。"],"source":"《唐诗三百首》"},{"title":"次韵致远自毘陵见寄二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["黄鹄高飞碧落寒，向来山水梦惊残。","故情若问玄真子，依旧江头把钓竿。"],"source":"宋诗"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["一弹指顷浮生过。","堕甑元知当破。","去去酔吟高卧。","独唱何须和。","残年还我从来我。","万里江湖烟舸。","脱尽利名缰锁。","世界元来大。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・麻郎儿","author":"王实甫","dynasty":"元","form":"曲","lines":["秀才是文章魁首，姐姐是仕女班头；一个通彻三教九流，一个晓尽描鸾刺绣。"],"source":"元曲"},{"title":"鼓钟","author":"佚名","dynasty":"先秦","form":"诗","lines":["鼓钟将将，淮水汤汤，忧心且伤。淑人君子，怀允不忘。","鼓钟喈喈，淮水湝湝，忧心且悲。淑人君子，其徳不回。","鼓钟伐鼛，淮有三洲，忧心且妯。淑人君子，其徳不犹。","鼓钟钦钦，鼓瑟鼓琴，笙磬同音。以雅以南，以龠不僭。"],"source":"《诗经》"},{"title":"至徳二载甫自京金光门出问道帰凤翔乾元初従左拾遗移华州掾与亲故别因出此门有悲往事","author":"杜甫","dynasty":"唐","form":"诗","lines":["此道昔帰顺，西郊胡正繁。","至今残破胆，応有未招魂。","近得帰京邑，移官岂至尊。","无才日衰老，驻马望千门。"],"source":"《唐诗三百首》"},{"title":"次韵致远自毘陵见寄二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["新词一阕话羁愁，清似寒泉咽陇头。","官下有谁同此景，仲宣応是独登楼。"],"source":"宋诗"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["城南载酒行歌路。","冶叶倡条无数。","一朵鞓红凝露。","最是关心处。","莺声无赖催春去。","那更兼旬风雨。","试问岁华何许。","芳草连天暮。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・幺篇","author":"王实甫","dynasty":"元","form":"曲","lines":["世有、便休、罢手，大恩人怎做敌头？起白马将军故友，斩飞虎叛贼草寇。"],"source":"元曲"},{"title":"楚茨","author":"佚名","dynasty":"先秦","form":"诗","lines":["楚楚者茨，言抽其棘，自昔何为？我蓺黍稷。我黍与与，我稷翼翼。","我仓既盈，我庾维亿。以为酒食，以享以祀，以妥以侑，以介景福。","济济跄跄，絜尔牛羊，以往烝尝。或剥或亨，或四或将。祝祭于祊，","祀事孔明。先祖是皇，神保是飨。孝孙有庆，报以介福，万寿无疆！","执爨踖踖，为俎孔硕，或燔或炙。君妇莫莫，为豆孔庶。为宾为客，","献酬交错。礼仪卒度，笑语卒获。神保是格，报以介福，万寿攸醋！","我孔戁矣，式礼莫愆。工祝致告，徂赉孝孙。苾芬孝祀，神嗜饮食。","卜尔百福，如几如式。既齐既稷，既匡既勅。永锡尔极，时万时亿！","礼仪既备，钟鼓既戒，孝孙徂位，工祝致告，神具酔止，皇尸载起。","鼓钟送尸，神保聿归。诸宰君妇，废彻不迟。诸父兄弟，备言燕私。","乐具入奏，以绥后禄。尔肴既将，莫怨具庆。既酔既饱，小大稽首。","神嗜饮食，使君寿考。孔恵孔时，维其尽之。子子孙孙，勿替引之！"],"source":"《诗经》"},{"title":"月夜忆舎弟","author":"杜甫","dynasty":"唐","form":"诗","lines":["戍鼓断人行，秋辺一雁声。","露従今夜白，月是故郷明。","有弟皆分散，无家问死生。","寄书长不避，况乃未休兵。"],"source":"《唐诗三百首》"},{"title":"元日山寺","author":"范成大","dynasty":"宋","form":"诗","lines":["聴熟朝鱼又暮钟，全将慵懒度三冬。","贪眠豹褥窗间日，怕拥𫘞裘陌上风。","登版自怜行蹭蹬，読碑仍怪视蒙笼。","少年豪壮今如此，略与残僧気味同。"],"source":"宋诗"},{"title":"桃源忆故人","author":"陆游","dynasty":"宋","form":"词","lines":["中原当日三川震。","关辅回头煨烬。","泪尽两河征镇。","日望中兴运。","秋风霜满青青鬓。","老却新丰英俊。","云外华山千仞。","依旧无人问。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・络丝娘","author":"王实甫","dynasty":"元","form":"曲","lines":["不争和张解元参辰卯酉，便是与崔相国出乖弄丑。","到底干连着自己骨肉，夫人索穷究。","(夫人云)这小贱人也道得是。","我不合养了这个不肖之女。","待经官呵，玷辱家门。","罢罢！俺家无犯法之男，再婚之女，与了这厮罢。","红娘唤那贱人来！(红见旦云)且喜姐姐，那棍子则是滴溜溜在我身上，吃我直说过了。","我也怕不得许多，夫人如今唤你来，待成合亲事。","(旦去)羞人答答的，怎幺见夫人？(红云)娘跟前有甚幺羞？。"],"source":"元曲"},{"title":"信南山","author":"佚名","dynasty":"先秦","form":"诗","lines":["信彼南山，维禹甸之。畇畇原隰，曽孙田之。我疆我理，南东其亩。","上天同云。雨雪雰雰，益之以霡霂。既优既渥，既沾既足。生我百谷。","疆埸翼翼，黍稷彧彧。曽孙之穑，以为酒食。畀我尸宾，寿考万年。","中田有庐，疆埸有瓜。是剥是菹，献之皇祖。曽孙寿考，受天之祜。","祭以清酒，从以骍牡，享于祖考。执其鸾刀，以启其毛，取其血膋。","是烝是享，苾苾芬芬。祀事孔明，先祖是皇。报以介福。万寿无疆。"],"source":"《诗经》"},{"title":"天末忆李白","author":"杜甫","dynasty":"唐","form":"诗","lines":["凉风起天末，君子意如何。","鸿雁几时到，江湖秋水多。","文章憎命达，魑魅喜人过。","応共冤魂语，投诗赠汩罗。"],"source":"《唐诗三百首》"},{"title":"题记事册","author":"范成大","dynasty":"宋","form":"诗","lines":["北山山下小庵居，仏劫仙尘只故吾。","八万四千空色界，不离一法认毘卢。"],"source":"宋诗"},{"title":"极相思","author":"陆游","dynasty":"宋","form":"词","lines":["江头疏雨轻烟。","寒食落花天。","翻红坠素，残霞暗锦，一段凄然。","惆怅东君堪恨处，也不念、冷落尊前。","那堪更看，漫空相趁，柳絮楡钱。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・小桃红","author":"王实甫","dynasty":"元","form":"曲","lines":["当日个月明才上柳梢头，却早人约黄昏后。","羞得我脑背后将牙儿衬着衫儿袖。","猛凝眸，则见鞋底尖儿痩。","一个恣情的不休，一个哑声儿厮耨。","呸！那其间可怎生不害半星儿羞？。"],"source":"元曲"},{"title":"甫田","author":"佚名","dynasty":"先秦","form":"诗","lines":["倬彼甫田，岁取十千。我取其陈，食我农人。自古有年。","今适南亩，或耘或耔。黍稷薿薿，攸介攸止，烝我髦士。","以我齐明，与我牺羊，以社以方。我田既臧，农夫之庆。","琴瑟击鼓，以御田祖。以祈甘雨，以介我稷黍，以谷我士女。","曽孙来止，以其妇子。馌彼南亩，田畯至喜。攘其左右，","尝其旨否。禾易长亩，终善且有。曽孙不怒，农夫克敏。","曽孙之稼，如茨如梁。曽孙之庾，如坻如京。乃求千斯仓，","乃求万斯箱。黍稷稲粱，农夫之庆。报以介福，万寿无疆。"],"source":"《诗经》"},{"title":"蜀相","author":"杜甫","dynasty":"唐","form":"诗","lines":["丞相祠堂何処寻，锦官城外柏森森。","映堦碧草自春色，隔叶黄鹂空好音。","三顾频烦天下计，両朝开済老臣心。","出师未捷身先死，长使英雄涙満襟。"],"source":"《唐诗三百首》"},{"title":"寄赠致远并呈现老","author":"范成大","dynasty":"宋","form":"诗","lines":["草草家风节物新，従来忧病不忧贫。","琴书稍覚浮生误，香火惟知此事真。","室里谈空思二士，花间対影谩三人。","袛愁卢李分携后，别有箜篌一曲春。"],"source":"宋诗"},{"title":"一丛花","author":"陆游","dynasty":"宋","form":"词","lines":["尊前凝伫漫魂迷。","犹恨负幽期。","从来不惯伤春泪，为伊后、滴满罗衣。","那堪更是，吹箫池馆，青子绿阴时。","回廊帘影昼参差。","偏共睡相宜。","朝云梦断知何处，倩双燕、说与相思。","从今判了，十分憔悴，图要个人知。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・东原乐","author":"王实甫","dynasty":"元","form":"曲","lines":["想思事，一笔勾，早则展放从前眉儿皱，美爱幽欢恰动头。","既能够，张生，你觑兀的般可喜娘庞儿也要人消受。"],"source":"元曲"},{"title":"大田","author":"佚名","dynasty":"先秦","form":"诗","lines":["大田多稼，既种既戒，既备乃事。以我覃耜，俶载南亩。","播厥百谷，既庭且硕，曽孙是若。","既方既皂，既坚既好，不稂不莠。去其螟螣，及其蟊贼，","无害我田稚。田祖有神，秉畀炎火。","有渰萋萋，兴雨祈祈。雨我公田，遂及我私。彼有不获稚，","此有不敛穧，彼有遗秉，此有滞穂，伊寡妇之利。","曽孙来止，以其妇子。馌彼南亩，田畯至喜。来方禋祀，","以其骍黒，与其黍稷。以享以祀，以介景福。"],"source":"《诗经》"},{"title":"客至","author":"杜甫","dynasty":"唐","form":"诗","lines":["舎南舎北皆春水，但见群鴎日日来。","花径不曽縁客扫，蓬门今始为君开。","盘餐市远无兼味，樽酒家贫只旧醅。","肯与邻翁相対饮，隔篱呼取尽余桮。"],"source":"《唐诗三百首》"},{"title":"春后微雪一宿而晴","author":"范成大","dynasty":"宋","form":"诗","lines":["彩胜金旛换物华，垂垂天意晩平沙。","东君未破含春蕊，青女先飞剪水花。","夜逐回风鸣瓦垅，暁成疏雨滴檐牙。","朝暾不与同云便，烘作晴空万缕霞。"],"source":"宋诗"},{"title":"一丛花","author":"陆游","dynasty":"宋","form":"词","lines":["仙姝天上自无双。","玉面翠蛾长。","黄庭读罢心如水，闭朱户、愁近丝簧。","窗明几净，闲临唐帖，深炷宝奁香。","人间无药驻流光。","风雨又催凉。","相逢共话清都旧，叹尘劫、生死茫茫。","何如伴我，绿蓑青箬，秋晩钓潇湘。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・収尾","author":"王实甫","dynasty":"元","form":"曲","lines":["来时节画堂箫鼓鸣春昼，列着一对儿鸾交凤友。","那其间才受你说媒红，方吃你谢亲酒。","(并下)。"],"source":"元曲"},{"title":"瞻彼洛矣","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻彼洛矣，维水泱泱。君子至止，福禄如茨。韎韐有奭，以作六师。","瞻彼洛矣，维水泱泱。君子至止，鞸琫有珌。君子万年，保其家室。","瞻彼洛矣，维水泱泱。君子至止，福禄既同。君子万年，保其家邦。"],"source":"《诗经》"},{"title":"野望","author":"杜甫","dynasty":"唐","form":"诗","lines":["西山白雪三奇戍，南浦清江万里桥。","海内风尘诸弟隔，天涯涕涙一身遥。","唯将遅暮供多病，未有涓埃荅圣朝。","跨马出郊时极目，不堪人事日萧条。"],"source":"《唐诗三百首》"},{"title":"雪霁独登南楼","author":"范成大","dynasty":"宋","form":"诗","lines":["雪晴风劲晩来冰，楼上奇寒病骨惊。","雀啄空檐银笋堕，鸦翻高树玉尘倾。","青帘闪闪千家静，黄帽亭亭一水横。","坐久天容却温丽，一弯新月対长庚。"],"source":"宋诗"},{"title":"隔浦莲近拍","author":"陆游","dynasty":"宋","form":"词","lines":["飞花如趁燕子。","直度帘栊里。","帐掩香云暖，金笼鹦鹉惊起。","凝恨慵梳洗。","妆台畔，蘸粉纤纤指。","宝钗坠。","才醒又困，厌厌中酒滋味。","墙头柳暗，过尽一年春事。","罨画高楼怕独倚。","千里。","孤舟何处烟水。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・正宫/端正好","author":"王实甫","dynasty":"元","form":"曲","lines":["碧云天，黄花地，西风紧，北雁南飞。","晓来谁染霜林酔？总是离人泪。"],"source":"元曲"},{"title":"裳裳者华","author":"佚名","dynasty":"先秦","form":"诗","lines":["裳裳者华，其叶湑兮。我觏之子，我心写兮。我心写兮，是以有誉处兮。","裳裳者华，芸其黄矣。我觏之子，维其有章矣。维其有章矣，是以有庆矣。","裳裳者华，或黄或白。我觏之子，乗其四骆。乗其四骆，六辔沃若。","左之左之，君子宜之。右之右之，君子有之。维其有之，是以似之。"],"source":"《诗经》"},{"title":"奉済駅重送厳公四韵","author":"杜甫","dynasty":"唐","form":"诗","lines":["远送従此别，青山空复情。","几时桮重把，昨夜月同行。","列郡讴歌惜，三朝出入栄。","江村独帰処，寂寞养残生。"],"source":"《唐诗三百首》"},{"title":"次时叙韵送至先兄赴调","author":"范成大","dynasty":"宋","form":"诗","lines":["梅柳欲动风作难，行人意在飞鸿间。","一官远游门戸弱，百歳上策身心闲。","胸次饶渠有廊庙，梦魂叵使无江山。","栽桃种杏须付我，已办鉄锁遅公攀。"],"source":"宋诗"},{"title":"隔浦莲近拍","author":"陆游","dynasty":"宋","form":"词","lines":["骑鲸云路倒景。","酔面风吹醒。","笑把浮丘袂，寥然非复尘境。","震泽秋万顷。","烟霏散，水面飞金镜。","露华冷。","湘妃睡起，鬟倾钗坠慵整。","临江舞处，零乱塞鸿清影。","河汉横斜夜漏永。","人静。","吹箫同过缑岭。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・脱布衫","author":"王实甫","dynasty":"元","form":"曲","lines":["下西风黄叶纷飞，染寒烟衰草萋迷。","酒席上斜签着坐的，蹙愁眉死临侵地。"],"source":"元曲"},{"title":"桑扈","author":"佚名","dynasty":"先秦","form":"诗","lines":["交交桑扈，有莺其羽。君子乐胥，受天之祜。","交交桑扈，有莺其领。君子乐胥，万邦之屏。","之屏之翰，百辟为宪。不戢不难，受福不那。","兕觥其觩，旨酒思柔。彼交匪敖，万福来求。"],"source":"《诗经》"},{"title":"闻官军収河南河北","author":"杜甫","dynasty":"唐","form":"诗","lines":["劒外忽伝収蓟北，初闻涕涙満衣裳。","却看妻子愁何在，漫巻诗书喜欲狂。","白日放歌须縦酒，青春作伴好还郷。","即従巴峡穿巫峡，便下襄阳向洛阳。"],"source":"《唐诗三百首》"},{"title":"上沙遇雨快凉","author":"范成大","dynasty":"宋","form":"诗","lines":["刮地风来健葛衣，一凉便覚暑光低。","云头竜挂如垂筯，雨在中峰白塔西。"],"source":"宋诗"},{"title":"昭君怨","author":"陆游","dynasty":"宋","form":"词","lines":["昼永蝉声庭院。","人倦懒摇团扇。","小景写潇湘。","自生凉。","帘外蹴花双燕。","帘下有人同见。","宝篆拆官黄。","炷熏香。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・小梁州","author":"王实甫","dynasty":"元","form":"曲","lines":["我见他阁泪汪汪不敢垂，恐怕人知；猛然见了把头低，长吁气，推整素罗衣。"],"source":"元曲"},{"title":"鸳鸯","author":"佚名","dynasty":"先秦","form":"诗","lines":["鸳鸯于飞，毕之罗之。君子万年，福禄宜之。","鸳鸯在梁，戢其左翼。君子万年，","宜其遐福。乗马在厩，摧之秣之。君子万年，福禄艾之。","乗马在厩，秣之摧之。君子万年，福禄绥之。"],"source":"《诗经》"},{"title":"登高","author":"杜甫","dynasty":"唐","form":"诗","lines":["风急天高猨啸哀，渚清沙白鸟飞回。","无辺落木萧萧下，不尽长江衮衮来。","万里悲秋常作客，百年多病独登台。","艰难苦恨繁霜鬓，潦倒新停浊酒桮。"],"source":"《唐诗三百首》"},{"title":"自天平岭过高景庵","author":"范成大","dynasty":"宋","form":"诗","lines":["卓笔峰前树作団，天平岭上石成関。","绿阴匝地无人过，落日秋蝉満四山。"],"source":"宋诗"},{"title":"双头莲","author":"陆游","dynasty":"宋","form":"词","lines":["华鬓星星，惊壮志成虚，此身如寄。","萧条病骥。","向暗里。","消尽当年豪气。","梦断故国山川，隔重重烟水。","身万里。","旧社凋零，青门俊游谁记。","尽道锦里繁华，叹官闲昼永，柴荆添睡。","清愁自酔。","念此际。","付与何人心事。","纵有楚柂吴樯，知何时东逝。","空怅望，鲙美菰香，秋风又起。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・幺篇","author":"王实甫","dynasty":"元","form":"曲","lines":["虽然久后成佳配，奈时间怎不悲啼。","意似痴，心如酔，昨宵今日，清减了小腰围。","(夫人云)小姐把盏者！(红递酒，旦把盏长吁科，云)请吃酒！。"],"source":"元曲"},{"title":"𫠆弁","author":"佚名","dynasty":"先秦","form":"诗","lines":["有𫠆者弁，实维伊何？尔酒既旨，尔肴既嘉。岂伊异人？兄弟匪他。","茑与女萝，施于松柏。未见君子，忧心奕奕；既见君子，庶几说怿。","有𫠆者弁，实维何期？尔酒既旨，尔肴既时。岂伊异人？兄弟具来。","茑与女萝，施于松上。未见君子，忧心怲怲；既见君子，庶几有臧。","有𫠆者弁，实维在首。尔酒既旨，尔肴既阜。岂伊异人？兄弟甥舅。","如彼雨雪，先集维霰。死丧无日，无几相见。乐酒今夕，君子维宴。"],"source":"《诗经》"},{"title":"别房太尉墓","author":"杜甫","dynasty":"唐","form":"诗","lines":["他郷复行役，驻马别孤坟。","近涙无干土，低空有断云。","対碁陪谢傅，把劒觅徐君。","唯见林花落，鸎啼送客闻。"],"source":"《唐诗三百首》"},{"title":"高景山夜帰","author":"范成大","dynasty":"宋","form":"诗","lines":["伊轧篮舆草露间，夜凉月暗走孱颜。","忽逢陂水明如镜，照见沉沉倒景山。"],"source":"宋诗"},{"title":"南歌子","author":"陆游","dynasty":"宋","form":"词","lines":["异县相逢晩，中年作别难。","暮秋风雨客衣寒。","又向朝天门外、话悲欢。","痩马行霜栈，轻舟下雪滩。","乌奴山下一林丹。","为说三年常寄、梦魂间。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・上小楼","author":"王实甫","dynasty":"元","form":"曲","lines":["合欢未已，离愁相继。","想着俺前暮私情，昨夜成亲，今日别离。","我谂知这几日相思滋味，却原来比别离情更増十倍。"],"source":"元曲"},{"title":"车舝","author":"佚名","dynasty":"先秦","form":"诗","lines":["间关车之舝兮，思娈季女逝兮。匪饥匪渇，徳音来括。虽无好友？式燕且喜。","依彼平林，有集维鷮。辰彼硕女，令徳来教。式燕且誉，好尔无射。","虽无旨酒？式饮庶几。虽无嘉肴？式食庶几。虽无徳与女？式歌且舞？","陟彼高冈，析其柞薪。析其柞薪，其叶湑兮。鲜我觏尔，我心写兮。","高山仰止，景行行止。四牡𬴂𬴂，六辔如琴。觏尔新婚，以慰我心。"],"source":"《诗经》"},{"title":"登楼","author":"杜甫","dynasty":"唐","form":"诗","lines":["花近高楼伤客心，万方多难此登临。","锦江春色来天地，玉塁浮云変古今。","北极朝廷终不改，西山寇盗莫相侵。","可怜后主还祠庙，日暮聊为梁甫吟。"],"source":"《唐诗三百首》"},{"title":"白云岭","author":"范成大","dynasty":"宋","form":"诗","lines":["路入千峰一线通，陆离长剣立天风。","五年领客题诗処，正在孤云乱石中。"],"source":"宋诗"},{"title":"豆叶黄・忆王孙","author":"陆游","dynasty":"宋","form":"词","lines":["春风楼上柳腰肢。","初试花前金缕衣。","袅袅娉娉不自持。","晓妆迟。","画得蛾眉胜旧时。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・幺篇","author":"王实甫","dynasty":"元","form":"曲","lines":["年少呵轻远别，情薄呵易弃掷。","全不想腿儿相挨，脸儿相偎，手儿相携。","你与俺崔相国做女婿，妻荣夫贵，但得一个并头莲，煞强如状元及第。","(夫人云)红娘把盏者！(红把酒科)(旦唱)。"],"source":"元曲"},{"title":"青蝇","author":"佚名","dynasty":"先秦","form":"诗","lines":["营营青蝇，止于樊。岂弟君子，无信谗言。","营营青蝇，止于棘。谗人罔极，交乱四国。","营营青蝇，止于榛。谗人罔极，构我二人。"],"source":"《诗经》"},{"title":"宿府","author":"杜甫","dynasty":"唐","form":"诗","lines":["清秋幕府井梧寒，独宿江城蝋炬残。","永夜角声悲自语，中天月色好谁看。","风尘荏苒音书绝，関塞萧条行路难。","已忍伶俜十年事，强移栖息一枝安。"],"source":"《唐诗三百首》"},{"title":"偃月泉","author":"范成大","dynasty":"宋","form":"诗","lines":["松风竹露午犹寒，知有竜蟠一掬悭。","我欲今年来结夏，莫扃岫幌掩云関。"],"source":"宋诗"},{"title":"豆叶黄・忆王孙","author":"陆游","dynasty":"宋","form":"词","lines":["一春常是雨和风。","风雨晴时春已空。","谁惜泥沙万点红。","恨难穷。","恰似衰翁一世中。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・满庭芳","author":"王实甫","dynasty":"元","form":"曲","lines":["供食太急，须臾对面，顷刻别离。","若不是酒席间子母毎当回避，有心待与他举案齐眉。","虽然是厮守得一时半刻，也合着俺夫妻毎共桌而食。","眼底空留意，寻思起就里，险化做望夫石。","(红云)姐姐不曽吃早饭，饮一口儿汤水。","(旦云)红娘，甚幺汤水咽得下！。"],"source":"元曲"},{"title":"宾之初筵","author":"佚名","dynasty":"先秦","form":"诗","lines":["宾之初筵，左右秩秩。笾豆有楚，殽核维旅。酒既和旨，饮酒孔偕。","钟鼓既设，举酬逸逸。大侯既抗，弓矢斯张。射夫既同，献尔发功。","发彼有的，以祈尔爵。","籥舞笙鼓，乐既和奏。烝衎烈祖，以洽百礼。百礼既至，有壬有林。","锡尔纯嘏，子孙其湛。其湛曰乐，各奏尔能。宾载手仇，室人入又。","酌彼康爵，以奏尔时。","宾之初筵，温温其恭。其未酔止，威仪反反。曰既酔止，威仪幡幡。","舎其坐迁，屡舞仙仙。其未酔止，威仪抑抑。曰既酔止，威仪抑抑。","是曰既酔，不知其秩。","宾既酔止，载号载呶。乱我笾豆，屡舞僛僛。是曰既酔，不知其邮。","侧弁之俄，屡舞傞傞。既酔而出，并受其福。酔而不出，是谓伐徳。","饮酒孔嘉，维其令仪。","凡此饮酒，或酔或否。既立之监，或佐之史。彼酔不臧，不酔反耻。","式勿从谓，无俾大怠。匪言勿言，匪由勿语。由酔之言，俾出童羖。","三爵不识，矧敢多又。"],"source":"《诗经》"},{"title":"旅夜书懐","author":"杜甫","dynasty":"唐","form":"诗","lines":["细草微风岸，危樯独夜舟。","星垂平野阔，月涌大江流。","名岂文章着，官因老病休。","飘飘何所似，天地一沙鴎。"],"source":"《唐诗三百首》"},{"title":"代人七月十四日生朝","author":"范成大","dynasty":"宋","form":"诗","lines":["秋入壶中玉宇鲜，芝兰桃李共熙然。","已饶瑞荚明朝満，先借清蟾一夜円。","北阙紫泥応道路，东山红袖莫云烟。","如今且酔江湖酒，来歳城南尺五天。"],"source":"宋诗"},{"title":"酔落魄・一斛珠","author":"陆游","dynasty":"宋","form":"词","lines":["江湖酔客。","投杯起舞遗乌帻。","三更冷翠沾衣湿。","袅袅菱歌，催落半川月。","空花昨梦休寻觅。","云台麟阁俱陈迹。","元来只有闲难得。","青史功名，天却无心惜。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・快活三","author":"王实甫","dynasty":"元","form":"曲","lines":["将来的酒共食，尝着似土和泥。","仮若便是上和泥，也有些土气息，泥滋味。"],"source":"元曲"},{"title":"鱼藻","author":"佚名","dynasty":"先秦","form":"诗","lines":["鱼在在藻，有颁其首。王在在镐，岂乐饮酒。","鱼在在藻，有莘其尾。王在在镐，饮酒乐岂。","鱼在在藻，依于其蒲。王在在镐，有那其居。"],"source":"《诗经》"},{"title":"阁夜","author":"杜甫","dynasty":"唐","form":"诗","lines":["歳暮阴阳催短景，天涯霜雪霁寒宵。","五更鼓角声悲壮，三峡星河影动揺。","野哭几家闻戦伐，夷歌数処起渔樵。","卧竜跃马终黄土，人事依依漫寂寥。"],"source":"《唐诗三百首》"},{"title":"题金牛洞","author":"范成大","dynasty":"宋","form":"诗","lines":["故郷江呉多好山，笋舆篾舫相穷年。","春风吹入江南陌，畳障双峰如旧识。","闻道金牛更孱颜，古来鉄锁高难攀。","自従仙伯弭芝盖，凤舞鸾歌开洞天。","新诗賸说山中妙，我不曽游先梦到。","従渠弱水隔蓬莱，云山何処无瑶草。"],"source":"宋诗"},{"title":"鹊桥仙","author":"陆游","dynasty":"宋","form":"词","lines":["华灯纵博，雕鞍驰射，谁记当年豪举。","酒徒一一取封侯，独去作、江边渔父。","轻舟八尺，低篷三扇，占断苹洲烟雨。","镜湖元自属闲人，又何必、君恩赐与。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・朝天子","author":"王实甫","dynasty":"元","form":"曲","lines":["暖溶溶玉醅，白泠泠似水，多半是相思泪。","眼面前茶饭怕不待要吃，恨塞满愁肠胃。","\"蜗角虚名，蝇头微利\"，拆鸳鸯在两下里。","一个这壁，一个那壁，一递一声长吁气。"],"source":"元曲"},{"title":"采菽","author":"佚名","dynasty":"先秦","form":"诗","lines":["采菽采菽，筐之莒之。君子来朝，何锡予之？虽无予之？路车乗马。又何予之？玄衮及黼。","觱沸槛泉，言采其芹。君子来朝，言观其旗。其旗淠淠，鸾声嘒嘒。载骖载驷，君子所届。","赤芾在股，邪幅在下。彼交匪纾，天子所予。乐只君子，天子命之。乐只君子，福禄申之。","维柞之枝，其叶蓬蓬。乐只君子，殿天子之邦。乐只君子，万福攸同。平平左右，亦是率从。","泛泛杨舟，绋𫄥维之。乐只君子，天子葵之。乐只君子，福禄膍之。优哉游哉，亦是戻矣。"],"source":"《诗经》"},{"title":"八阵図","author":"杜甫","dynasty":"唐","form":"诗","lines":["功盖三分国，名高八阵図。","江流石不転，遗恨失吞呉。"],"source":"《唐诗三百首》"},{"title":"暁自银林至东灞登舟寄宣城亲戚","author":"范成大","dynasty":"宋","form":"诗","lines":["暁山障望眼，脉脉紫翠横。","澄江已不见，况乃江上城。","结束治野装，木末浮三星。","羸马陇头嘶，小车谷中鸣。","亭亭东灞树，练练绿浦明。","篙师笑迎我，新涨没苹汀。","径投一叶去，云水相与平。","聊将尘土面，照此玻瓈清。","懐我二三友，高堂晨欲兴。","风细桐叶堕，露浓荷盖倾。","凝香绕燕几，安知路傍情。"],"source":"宋诗"},{"title":"鹊桥仙","author":"陆游","dynasty":"宋","form":"词","lines":["一竿风月，一蓑烟雨，家在钓台西住。","卖鱼生怕近城门，况肯到、红尘深处。","潮生理棹，潮平系缆，潮落浩歌归去。","时人错把比严光，我自是、无名渔父。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・四边静","author":"王实甫","dynasty":"元","form":"曲","lines":["霎时间杯盘狼籍，车儿投东，马儿向西，两意徘徊，落日山横翠。","知他今宵宿在那里？有梦也难寻觅。"],"source":"元曲"},{"title":"角弓","author":"佚名","dynasty":"先秦","form":"诗","lines":["骍骍角弓，翩其反矣。兄弟婚姻，无胥远矣。","尔之远矣，民胥然矣。尔之教矣，民胥効矣。","此令兄弟，绰绰有裕。不令兄弟，交相为愈。","民之无良，相怨一方。受爵不让，至于已斯亡。","老马反为驹，不顾其后。如食宜饇，如酌孔取。","毋教猱升木，如涂涂附。君子有徽猷，小人与属。","雨雪瀌瀌，见𬀪曰消。莫肯下遗，式居娄骄。","雨雪浮浮，见𬀪曰流。如蛮如髦，我是用忧。"],"source":"《诗经》"},{"title":"咏懐古迹五首 一","author":"杜甫","dynasty":"唐","form":"诗","lines":["支离东北风尘际，漂泊西南天地间。","三峡楼台淹日月，五渓衣服共云山。","羯胡事主终无頼，词客衰时且未还。","庾信平生最萧瑟，暮年诗赋动江関。"],"source":"《唐诗三百首》"},{"title":"読唐太宗纪  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["宫府相図势不収，国家何有各身谋。","縦无管蔡当时例，业已弯弓肯罢休。"],"source":"宋诗"},{"title":"鹊桥仙","author":"陆游","dynasty":"宋","form":"词","lines":["茅檐人静，蓬窗灯暗，春晩连江风雨。","林莺巣燕总无声，但月夜、常啼杜宇。","催成清泪，惊残孤梦，又拣深枝飞去。","故山犹自不堪听，况半世、飘然羁旅。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・耍孩儿","author":"王实甫","dynasty":"元","form":"曲","lines":["淋漓襟袖啼红泪，比司马青衫更湿。","伯劳东去燕西飞，未释程九问归期。","虽然眼底人千里，且尽生前洒一杯。","未饮心先酔，眼中流血，心水成灰。"],"source":"元曲"},{"title":"菀柳","author":"佚名","dynasty":"先秦","form":"诗","lines":["有菀者柳，不尚息焉。上帝甚蹈，无自暱焉。俾予靖之，后予极焉。","有菀者柳，不尚愒焉。上帝甚蹈，无自瘵焉。俾予靖之，后予迈焉。","有鸟高飞，亦傅于天。彼人之心，于何其臻。曷予靖之，居以凶矜。"],"source":"《诗经》"},{"title":"咏懐古迹五首 二","author":"杜甫","dynasty":"唐","form":"诗","lines":["揺落深知宋玉悲，风流儒雅亦吾师。","怅望千秋一洒涙，萧条异代不同时。","江山故宅空文藻，云雨荒台岂梦思。","最是楚宫俱泯灭，舟人指点到今疑。"],"source":"《唐诗三百首》"},{"title":"読唐太宗纪  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["弟兄相贼斁天伦，自古无如舜苦辛。","掩井捐阶危万死，不闻亲杀鼻亭神。"],"source":"宋诗"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["云千重。","水千重。","身在千重云水中。","月明収钓筒。","头未童。","耳未聋。","得酒犹能双脸红。","一尊谁与同。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・五煞","author":"王实甫","dynasty":"元","form":"曲","lines":["到京师服水土，趁程途节饮食，顺时自保揣身体。","荒村雨露宜眠早，野店风霜要起迟！鞍马秋风里，最难调护，最要扶持。"],"source":"元曲"},{"title":"都人士","author":"佚名","dynasty":"先秦","form":"诗","lines":["彼都人士，狐裘黄黄。其容不改，出言有章。行归于周，万民所望。","彼都人士，台笠缁撮。彼君子女，绸直如发。我不见兮，我心不说。","彼都人士，充耳琇实。彼君子女，谓之尹吉。我不见兮，我心苑结。","彼都人士，垂带而厉。彼君子女，巻发如虿。我不见兮，言从之迈。","匪伊垂之，带则有余。匪伊巻之，发则有旟。我不见兮，云何盱矣。"],"source":"《诗经》"},{"title":"咏懐古迹五首 三","author":"杜甫","dynasty":"唐","form":"诗","lines":["群山万壑赴荆门，生长明妃尚有村。","一去紫台连朔漠，独留青冢向黄昏。","画図省识春风面，环佩空帰月夜魂。","千载琵琶作胡语，分明怨恨曲中论。"],"source":"《唐诗三百首》"},{"title":"読唐太宗纪  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["佐命诸公趣夜装，争言社稷要霊长。","就令昆季尸神器，未必唐家便破亡。"],"source":"宋诗"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["桥如虹。","水如空。","一叶飘然烟雨中。","天教称放翁。","侧船篷。","使江风。","蟹舎参差渔市东。","到时闻暮锺。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・四煞","author":"王实甫","dynasty":"元","form":"曲","lines":["这忧愁诉与谁？相思只自知，老天不管人憔悴。","泪添九曲黄河溢，恨压三峰华岳低。","到晩来闷把西楼倚，见了些夕阳古道，衰柳长堤。"],"source":"元曲"},{"title":"采绿","author":"佚名","dynasty":"先秦","form":"诗","lines":["终朝采绿，不盈一匊。予发曲局，薄言归沐。","终朝采蓝，不盈一襜。五日为期，六日不詹。","之子于狩，言韔其弓。之子于钓，言纶之绳。","其钓维何？维鲂及𫚈。维鲂及𫚈，薄言观者。"],"source":"《诗经》"},{"title":"咏懐古迹五首 四","author":"杜甫","dynasty":"唐","form":"诗","lines":["蜀主窥呉幸三峡，崩年亦在永安宫。","翠华想像空山里，玉殿虚无野寺中。","古庙杉松巣水鹤，歳时伏腊走村翁。","武侯祠屋常邻近，一体君臣祭祀同。"],"source":"《唐诗三百首》"},{"title":"読唐太宗纪  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["建成回马欲驰帰，元吉行趋武徳闱。","若使両人俱得去，却于何処极兵威。"],"source":"宋诗"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["面苍然。","鬓皤然。","满腹诗书不直钱。","官闲常昼眠。","画凌烟。","上甘泉。","自古功名属少年。","知心惟杜鹃。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・三煞","author":"王实甫","dynasty":"元","form":"曲","lines":["笑吟吟一处来。","哭啼啼独自归。","归家若到罗帏里，昨宵个绣衾香暖留春住，今夜个翠被生寒有梦知。","留恋你别无意，见据鞍上马，。"],"source":"元曲"},{"title":"黍苗","author":"佚名","dynasty":"先秦","form":"诗","lines":["芃芃黍苗，阴雨膏之。悠悠南行，召伯劳之。","我任我辇，我车我牛。我行既集，盖云归哉。","我徒我御，我师我旅。我行既集，盖云归处。","肃肃谢功，召伯营之。烈烈征师，召伯成之。","原隰既平，泉流既清。召伯有成，王心则宁。"],"source":"《诗经》"},{"title":"咏懐古迹五首 五","author":"杜甫","dynasty":"唐","form":"诗","lines":["诸葛大名垂宇宙，宗臣遗像粛清高。","三分割拠纡筹策，万古云霄一羽毛。","伯仲之间见伊吕，指挥若定失萧曹。","福移汉祚难恢复，志决身歼军务労。"],"source":"《唐诗三百首》"},{"title":"読唐太宗纪  其五","author":"范成大","dynasty":"宋","form":"诗","lines":["嫡长承祧有大伦，老公爱子本平均。","只知世上寻常理，争信英雄解灭亲。"],"source":"宋诗"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["暮山青。","暮霞明。","梦笔桥头艇子横。","苹风吹酒醒。","看潮生。","看潮平。","小住西陵莫较程。","莼丝初可烹。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・二煞","author":"王实甫","dynasty":"元","form":"曲","lines":["你休忧\"文齐福不齐\"，我则怕你\"停妻再娶妻\"。","休要\"一春鱼雁无消息\"！我这里青鸾有信频须寄，你却休\"金榜无名誓不归\"。","此一节君须记，若见了那异乡花草，再休似此处栖迟。","(末云)再谁似小妇？小生又生此念。","(旦唱)。"],"source":"元曲"},{"title":"隰桑","author":"佚名","dynasty":"先秦","form":"诗","lines":["隰桑有阿，其叶有难。既见君子，其乐如何。","隰桑有阿，其叶有沃。既见君子，云何不乐。","隰桑有阿，其叶有幽。既见君子，徳音孔胶。","心乎爱矣，遐不谓矣？中心蔵之，何日忘之！"],"source":"《诗经》"},{"title":"江南逢李亀年","author":"杜甫","dynasty":"唐","form":"诗","lines":["歧王宅里寻常见，崔九堂前几度闻。","正是江南好风景，落花时节又逢君。"],"source":"《唐诗三百首》"},{"title":"重読唐太宗纪  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["父子情深苦亦深，盖天神武一沾襟。","想当抜刃投床际，也忆海池舟里心。"],"source":"宋诗"},{"title":"长相思","author":"陆游","dynasty":"宋","form":"词","lines":["悟浮生。","厌浮名。","回视千锺一发轻。","从今心太平。","爱松声。","爱泉声。","写向孤桐谁解听。","空江秋月明。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・一煞","author":"王实甫","dynasty":"元","form":"曲","lines":["青山隔送行，疏林不做美，淡烟暮蔼相屏蔽。","夕阳古道无人语，禾黍秋风听马嘶。","我为甚幺懒上车儿内，来时甚急，去后何迟？。"],"source":"元曲"},{"title":"白华","author":"佚名","dynasty":"先秦","form":"诗","lines":["白华菅兮，白茅束兮。之子之远，俾我独兮。","英英白云，露彼菅茅。天歩艰难，之子不犹。","滮池北流，浸彼稲田。啸歌伤怀，念彼硕人。","樵彼桑薪，卬烘于煁。维彼硕人，实劳我心。","鼓钟于宫，声闻于外。念子懆懆，视我迈迈。","有鹙在梁，有鹤在林。维彼硕人，实劳我心。","鸳鸯在梁，戢其左翼。之子无良，二三其徳。","有扁斯石，履之卑兮。之子之远，俾我疧兮。"],"source":"《诗经》"},{"title":"登岳阳楼","author":"杜甫","dynasty":"唐","form":"诗","lines":["昔闻洞庭水，今上岳阳楼。","呉楚东南坼，乾坤日夜浮。","亲朋无一字，老病有孤舟。","戎马関山北，凭轩涕泗流。"],"source":"《唐诗三百首》"},{"title":"重読唐太宗纪  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["承干谋父保天年，青雀図兄亦両全。","隠刺诸児却孥戮，一私知隔几山渊。"],"source":"宋诗"},{"title":"菩萨蛮","author":"陆游","dynasty":"宋","form":"词","lines":["江天淡碧云如扫。","苹花零落莼丝老。","细细晩波平。","月从波面生。","渔家真个好。","悔不归来早。","经岁洛阳城。","鬓丝添几茎。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・収尾","author":"王实甫","dynasty":"元","form":"曲","lines":["四围山色中，一鞭残照里。","遍人间烦恼填胸臆，量这些大小车儿如何载得起？。"],"source":"元曲"},{"title":"绵蛮","author":"佚名","dynasty":"先秦","form":"诗","lines":["绵蛮黄鸟，止于丘阿。道之云远，我劳如何。饮之食之，教之诲之。命彼后车，谓之载之。","绵蛮黄鸟，止于丘隅。岂敢惮行，畏不能趋。饮之食之。教之诲之。命彼后车，谓之载之。","绵蛮黄鸟，止于丘侧。岂敢惮行，畏不能极。饮之食之，教之诲之。命彼后车，谓之载之。"],"source":"《诗经》"},{"title":"虢国夫人","author":"杜甫","dynasty":"唐","form":"诗","lines":["虢国夫人承主恩，平明上马入宫门。","却嫌脂粉涴颜色，澹埽蛾眉朝至尊。"],"source":"《唐诗三百首》"},{"title":"重読唐太宗纪  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["更张聊欲亢吾宗，仁孝承家合至公。","天発杀机那可料，正投阿武祸胎中。"],"source":"宋诗"},{"title":"菩萨蛮","author":"陆游","dynasty":"宋","form":"词","lines":["小院蚕眠春欲老。","新巣燕乳花如扫。","幽梦锦城西。","海棠如旧时。","当年真草草。","一棹还吴早。","题罢惜春诗。","镜中添鬓丝。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・双调/新水令","author":"王实甫","dynasty":"元","form":"曲","lines":["望薄东萧寺暮云遮，惨离情半林黄叶。","马迟人意懒，风急雁行斜。","离恨重叠，破题儿第一夜。"],"source":"元曲"},{"title":"瓠叶","author":"佚名","dynasty":"先秦","form":"诗","lines":["幡幡瓠叶，采之亨之。君子有酒，酌言尝之。","有兔斯首，炮之燔之。君子有酒，酌言献之。","有兔斯首，燔之炙之。君子有酒，酌言醋之。","有兔斯首，燔之炮之。君子有酒，酌言酬之。"],"source":"《诗经》"},{"title":"望月懐远","author":"张九齢","dynasty":"唐","form":"诗","lines":["海上生明月，天涯共此时。","情人怨遥夜，竟夕起相思。","灭烛怜光満，披衣覚露滋。","不堪盈手赠，还寝梦佳期。"],"source":"《唐诗三百首》"},{"title":"复自姑苏过宛陵至邓歩出陆","author":"范成大","dynasty":"宋","form":"诗","lines":["浆家馈食槿为藩，酒市停骖竹庑门。","红树亭亭栖晩照，黄茅杳杳被高原。","饮渓有迹於菟过，掠草如飞朴渥翻。","车轨如沟平地少，饱帆天镜忆江村。"],"source":"宋诗"},{"title":"诉衷情","author":"陆游","dynasty":"宋","form":"词","lines":["当年万里觅封侯。","匹马戍梁州。","关河梦断何处，尘暗旧貂裘。","胡未灭，鬓先秋。","泪空流。","此生谁料，心在天山，身老沧洲。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・落梅风","author":"王实甫","dynasty":"元","form":"曲","lines":["旅馆欹单枕，秋蛩鸣四野，助人愁的是纸窗儿风裂。","乍孤眠被儿薄又怯，冷清清几时温热！。"],"source":"元曲"},{"title":"渐渐之石","author":"佚名","dynasty":"先秦","form":"诗","lines":["渐渐之石，维其高矣。山川悠远，维其劳矣。武人东征，不遑朝矣。","渐渐之石，维其卒矣。山川悠远，曷其没矣？武人东征，不遑出矣。","有豕白蹢，烝渉波矣。月离于毕，俾滂沱矣。武人东征，不皇他矣。"],"source":"《诗经》"},{"title":"题大庾岭北駅","author":"宋之问","dynasty":"唐","form":"诗","lines":["阳月南飞雁，伝闻至此回。","我行殊未已，何日复帰来？江静潮初落，林昏瘴不开。","明朝望郷処，応见陇头梅。"],"source":"《唐诗三百首》"},{"title":"题南塘客舎","author":"范成大","dynasty":"宋","form":"诗","lines":["闲里方知得此生，痴人身外更経営。","君看坐贾行商辈，谁复従容唱渭城。"],"source":"宋诗"},{"title":"诉衷情","author":"陆游","dynasty":"宋","form":"词","lines":["青衫初入九重城。","结友尽豪英。","蜡封夜半传檄，驰骑谕幽并。","时易失，志难成。","鬓丝生。","平章风月，弹压江山，别是功名。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・乔木查","author":"王实甫","dynasty":"元","form":"曲","lines":["走荒郊旷野，把不住心娇怯，喘吁吁难将两气接。","疾忙赶上者，打草惊蛇。"],"source":"元曲"},{"title":"苕之华","author":"佚名","dynasty":"先秦","form":"诗","lines":["苕之华，芸其黄矣。心之忧矣，维其伤矣！","苕之华，其叶青青。知我如此，不如无生！","牂羊坟首，三星在罶。人可以食，鲜可以饱！"],"source":"《诗经》"},{"title":"渡汉江","author":"宋之问","dynasty":"唐","form":"诗","lines":["岭外音书断，経冬复歴春。","近郷情更怯，不敢问来人。"],"source":"《唐诗三百首》"},{"title":"南塘冬夜倡和","author":"范成大","dynasty":"宋","form":"诗","lines":["燃萁烘煖夜窗幽，时有新诗趣倡酬。","为问灞桥风雪里，何如田舎火炉头。","寒釭欲暗吟方苦，冻笔难駆字更遒。","绝笑児痴生活淡，略无歳晩稲粱谋。"],"source":"宋诗"},{"title":"生查子","author":"陆游","dynasty":"宋","form":"词","lines":["还山荷主恩，聊试扶犁手。","新结小茅茨，恰占清江口。","风尘不化衣，邻曲常持酒。","那似宦游时，折尽长亭柳。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・锦上花","author":"王实甫","dynasty":"元","form":"曲","lines":["有限姻缘，方才宁贴；无奈功名，使人离欠。","害不了的愁怀，却才觉些；撇不下的相思，如今又也。"],"source":"元曲"},{"title":"何草不黄","author":"佚名","dynasty":"先秦","form":"诗","lines":["何草不黄？何日不行？何人不将？经营四方。","何草不玄？何人不矜？哀我征夫，独为匪民。","匪兕匪虎，率彼旷野。哀我征夫，朝夕不暇。","有芃者狐，率彼幽草。有栈之车，行彼周道。"],"source":"《诗经》"},{"title":"新年作","author":"宋之问","dynasty":"唐","form":"诗","lines":["郷心新歳切，天畔独澘然。","老至居人下，春帰在客先。","岭猨同旦暮，江柳共风烟。","已似长沙傅，従今又几年。"],"source":"《唐诗三百首》"},{"title":"游金牛洞题石壁上","author":"范成大","dynasty":"宋","form":"诗","lines":["仙翁旧游処，琅璈韵霊曲。","至今有余音，玄鹤舞幽谷。","众真期我住，歳晩芝田熟。","腰镵従翁来，𥬞云跨飞鹿。"],"source":"宋诗"},{"title":"生查子","author":"陆游","dynasty":"宋","form":"词","lines":["梁空燕委巣，院静鸠催雨。","香润上朝衣，客少闲谈麈。","鬓边千缕丝，不是吴蚕吐。","孤梦泛潇湘，月落闻柔橹。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・幺篇","author":"王实甫","dynasty":"元","form":"曲","lines":["清霜净碧波，白露下黄叶。","下下高高，道路曲折；四野风来，左右乱踅。","我这里奔驰，他何处困歇？。"],"source":"元曲"},{"title":"文王","author":"佚名","dynasty":"先秦","form":"诗","lines":["文王在上，于昭于天。周虽旧邦，其命维新。有周不显，帝命不时。文王陟降，在帝左右。","亹亹文王，令闻不已。陈锡哉周，侯文王孙子。文王孙子，本支百世，凡周之士，不显亦世。","世之不显，厥犹翼翼。思皇多士，生此王国。王国克生，维周之桢；济济多士，文王以宁。","穆穆文王，于缉熙敬止。仮哉天命。有商孙子。商之孙子，其丽不亿。上帝既命，侯于周服。","侯服于周，天命靡常。殷士肤敏。裸将于京。厥作裸将，常服黼冔。王之荩臣。无念尔祖。","无念尔祖，聿修厥徳。永言配命，自求多福。殷之未丧师，克配上帝。宜鉴于殷，骏命不易！","命之不易，无遏尔躬。宣昭义问，有虞殷自天。上天之载，无声无臭。仪刑文王，万邦作孚。"],"source":"《诗经》"},{"title":"杜少府之任蜀州","author":"王勃","dynasty":"唐","form":"诗","lines":["城阙辅三秦，风烟望五津。","与君离别意，同是宦游人。","海内存知己，天涯若比隣。","无为在岐路，児女共沾巾。"],"source":"《唐诗三百首》"},{"title":"浄行寺傍皆圩田毎为潦涨所决民歳歳兴筑患粮绝功辄不成","author":"范成大","dynasty":"宋","form":"诗","lines":["崩涛裂岸四三年，落日寒烟正渺然。","空腹荷锄那办此，人功未至不関天。"],"source":"宋诗"},{"title":"破阵子","author":"陆游","dynasty":"宋","form":"词","lines":["仕至千锺良易，年过七十常稀。","眼底荣华元是梦，身后声名不自知。","营营端为谁。","幸有旗亭沽酒，何妨茧纸题诗。","幽谷云萝朝采药，静院轩窗夕对棋。","不归真个痴。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・清江引","author":"王实甫","dynasty":"元","form":"曲","lines":["呆答孩店房儿里没话说，闷对如年夜。","暮雨催寒蛩，晓风吹残月，今宵酒醒何处也？(旦云)在这个店儿里，不免敲门。","(末云)谁敲门哩？是一个女人的声音。","我且开门看咱，这早晩是谁？。"],"source":"元曲"},{"title":"大明","author":"佚名","dynasty":"先秦","form":"诗","lines":["明明在下，赫赫在上。天难忱斯，不易维王。天位殷适，使不挟四方。","挚仲氏任，自彼殷商，来嫁于周，曰嫔于京。乃及王季，维徳之行。","大任有身，生此文王。维此文王，小心翼翼。昭事上帝，聿怀多福。厥徳不回，以受方国。","天监在下，有命既集。文王初载，天作之合。在洽之阳，在渭之涘。","文王嘉止，大邦有子。大邦有子，伣天之妹。文定厥祥，亲迎于渭。造舟为梁，不显其光。","有命自天，命此文王。于周于京，缵女维莘。长子维行，笃生武王。保右命尔，燮伐大商。","殷商之旅，其会如林。矢于牧野，维予侯兴。上帝临女，无二尔心。","牧野洋洋，檀车煌煌，驷𫘪彭彭。维师尚父，时维鹰扬。凉彼武王，四伐大商，会朝清明。"],"source":"《诗经》"},{"title":"和晋陵陆丞早春游望","author":"杜审言","dynasty":"唐","form":"诗","lines":["独有宦游人，偏惊物候新。","云霞出海曙，梅柳渡江春。","淑気催黄鸟，晴光転绿苹。","忽闻歌古调，帰思欲沾巾。"],"source":"《唐诗三百首》"},{"title":"衮山道中","author":"范成大","dynasty":"宋","form":"诗","lines":["虎啸狐鸣苦竹丛，魂惊终日走蒙茸。","松林断処前山欠，又见南湖数十峰。"],"source":"宋诗"},{"title":"破阵子","author":"陆游","dynasty":"宋","form":"词","lines":["看破空花尘世，放轻昨梦浮名。","蜡屐登山真率饮，筇杖穿林自在行。","身闲心太平。","料峭馀寒犹力，廉纤细雨初晴。","苔纸闲题渓上句，菱唱遥闻烟外声。","与君同酔醒。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・庆宣和","author":"王实甫","dynasty":"元","form":"曲","lines":["是人呵疾忙快分说，是鬼呵合速灭。","(旦云)是我。","老夫人睡了。","想你去了，几时再得见，特来和你同去。","(末唱)听说罢将香罗袖儿拽，却原来是姐姐、姐姐。"],"source":"元曲"},{"title":"绵","author":"佚名","dynasty":"先秦","form":"诗","lines":["绵绵瓜瓞。民之初生，自土沮漆。古公亶父，陶复陶冗，未有家室。","古公亶父，来朝走马。率西水浒，至于岐下。爰及姜女，聿来胥宇。","周原膴膴，堇荼如饴。爰始爰谋，爰契我龟，曰止曰时，筑室于兹。","乃慰乃止，乃左乃右，乃疆乃理，乃宣乃亩。自西徂东，周爰执事。","乃召司空，乃召司徒，俾立室家。其绳则直，缩版以载，作庙翼翼。","捄之陾陾，度之薨薨，筑之登登，削屡冯冯。百堵皆兴，鼛鼓弗胜。","乃立皐门，皐门有伉。乃立应门，应门将将。乃立冢土，戎丑攸行。","四不殄厥愠，亦不陨厥问。柞棫抜矣，行道兑矣。混夷駾矣，维其喙矣！","虞芮质厥成，文王蹶厥生。予曰有疏附，予曰有先后。予曰有奔奏，予曰有御侮！"],"source":"《诗经》"},{"title":"登楼","author":"朱斌","dynasty":"唐","form":"诗","lines":["白日依山尽，黄河入海流。","欲穷千里目，更上一层楼。"],"source":"《唐诗三百首》"},{"title":"花山村舎","author":"范成大","dynasty":"宋","form":"诗","lines":["潦退滩滩露，沙虚岸岸颓。","涧声穿竹去，云影过山来。","柳菌粘枝住，桑花共叶开。","庵庐少来往，门巷湿苍苔。"],"source":"宋诗"},{"title":"上西楼・相见欢","author":"陆游","dynasty":"宋","form":"词","lines":["江头绿暗红稀。","燕交飞。","忽到当年行处、恨依依。","洒清泪。","叹人事。","与心违。","满酌玉壶花露、送春归。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・乔牌儿","author":"王实甫","dynasty":"元","form":"曲","lines":["你是为人须为彻，将衣袂不藉。","绣鞋儿被露水泥沾惹，脚心儿管踏破也。"],"source":"元曲"},{"title":"棫朴","author":"佚名","dynasty":"先秦","form":"诗","lines":["芃芃棫朴，薪之槱之。济济辟王，左右趣之。","济济辟王，左右奉璋。奉璋峨峨，髦士攸宜。","淠彼泾舟，烝徒楫之。周王于迈，六师及之。","倬彼云汉，为章于天。周王寿考，遐不作人？","追琢其章，金玉其相。勉勉我王，纲纪四方。"],"source":"《诗经》"},{"title":"送李少府贬峡中王少府贬长沙","author":"高适","dynasty":"唐","form":"诗","lines":["嗟君此别意何如，驻马衔桮问谪居。","巫峡啼猿数行涙，衡阳帰雁几封书。","青枫江上秋天远，白帝城辺古木疏。","圣代即今多雨露，暂时分手莫踌躇。"],"source":"《唐诗三百首》"},{"title":"清明日狸渡道中","author":"范成大","dynasty":"宋","form":"诗","lines":["洒洒沾巾雨，披披侧帽风。","花燃山色里，柳卧水声中。","石马立当道，纸鸢鸣半空。","墦间人散后，乌鸟正西东。"],"source":"宋诗"},{"title":"点绛唇","author":"陆游","dynasty":"宋","form":"词","lines":["采药归来，独寻茅店沽新酿。","暮烟千嶂。","处处闻渔唱。","酔弄扁舟，不怕粘天浪。","江湖上。","遮回疏放。","作个闲人样。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・甜水令","author":"王实甫","dynasty":"元","form":"曲","lines":["想着你废寝忘餐，香消玉减，花开花谢，犹自觉争些；便枕冷衾寒，凤只鸾孤，月圆云遮，寻思来有甚伤嗟。"],"source":"元曲"},{"title":"旱麓","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻彼旱麓，榛楛济济。岂弟君子，干禄岂弟。","瑟彼玉瓒，黄流在中。岂弟君子，福禄攸降。","鸢飞戻天，鱼跃于渊。岂弟君子，遐不作人？","清酒既载，骍牡既备。以享以祀，以介景福。","瑟彼柞棫，民所燎矣。岂弟君子，神所劳矣。","莫莫葛藟，施于条枚。岂弟君子，求福不回。"],"source":"《诗经》"},{"title":"望岳","author":"杜甫","dynasty":"唐","form":"诗","lines":["岱宗夫如何，斉鲁青未了。","造化钟神秀，阴阳割昏暁。","荡胷生曽云，决眦入帰鸟。","会当凌绝顶，一覧众山小。"],"source":"《唐诗三百首》"},{"title":"寒食客中有懐","author":"范成大","dynasty":"宋","form":"诗","lines":["江郭花开也寂寥，不须绿暗与红凋。","疾风甚雨过寒食，白日青春吟大招。","芳景尚随流水去，故人応作彩云飘。","烟波千里家何在，惟有渓声似晩潮。"],"source":"宋诗"},{"title":"谢池春","author":"陆游","dynasty":"宋","form":"词","lines":["壮岁从戎，曽是气吞残虏。","阵云高、狼烽夜举。","朱颜青鬓，拥雕戈西戍。","笑儒冠、自来多误。","功名梦断，却泛扁舟吴楚。","漫悲歌、伤怀吊古。","烟波无际，望秦关何处。","叹流年、又成虚度。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・折桂令","author":"王实甫","dynasty":"元","form":"曲","lines":["想人生最苦离别，可怜见千里关山，独自跋渉。","似这般割肚牵肠，倒不如义断恩绝。","虽然是一时间花残月欠，休猜做瓶坠簪折。","不恋豪杰，不羡骄奢；自愿的生则同衾，死则同穴。"],"source":"元曲"},{"title":"思齐","author":"佚名","dynasty":"先秦","form":"诗","lines":["思齐大任，文王之母，思媚周姜，京室之妇。大姒嗣徽音，则百斯男。","恵于宗公，神罔时怨，神罔时恫。刑于寡妻，至于兄弟，以御于家邦。","雍雍在宫，肃肃在庙。不显亦临，无射亦保。","四戎疾不殄，烈仮不瑕。不闻亦式，不谏亦入。四成人有徳，小子有造。古之人无斁，誉髦斯士。"],"source":"《诗经》"},{"title":"兵车行","author":"杜甫","dynasty":"唐","form":"诗","lines":["车辚辚，马萧萧，行人弓箭各在腰。","耶嬢妻子走相送，尘埃不见咸阳桥。","牵衣顿足阑道哭，哭声直上干云霄。","道傍过者问行人，行人但云点行频。","或従十五北防河，便至四十西営田。","去时里正与裹头，帰来头白还戍辺。","辺亭流血成海水，武皇开辺意未已。","君不闻汉家山东二百州，千村万落生荆杞。","縦有健妇把锄犂，禾生陇亩无东西。","况复秦兵耐苦戦，被駆不异犬与鶏。","长者虽有问，役夫敢申恨。","且如今年冬，未休関西卒。","県官急索租，租税従何出？信知生男悪，反是生女好。","生女犹是嫁比邻，生男埋没随百草。","君不见青海头，古来白骨无人収。","新鬼烦冤旧鬼哭，天阴雨湿声啾啾。"],"source":"《唐诗三百首》"},{"title":"南塘寒食书事","author":"范成大","dynasty":"宋","form":"诗","lines":["埂外新陂绿，冈头宿焼红。","裹鱼蒸菜把，馈鸭锁筠笼。","酒侣晨相命，歌场夜不空。","土风并节物，不与故郷同。"],"source":"宋诗"},{"title":"谢池春","author":"陆游","dynasty":"宋","form":"词","lines":["贺监湖边，初系放翁归棹。","小园林、时时酔倒。","春眠惊起，听啼莺催晓。","叹功名、误人勘笑。","朱桥翠径，不许京尘飞到。","挂朝衣、东归欠早。","连宵风雨，巻残红如扫。","恨樽前、送春人老。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・雁儿落","author":"王实甫","dynasty":"元","form":"曲","lines":["绿依依墙高柳半遮，静悄悄门掩清秋夜，疏剌剌林梢落叶风，昏惨惨云际穿窗月。"],"source":"元曲"},{"title":"皇矣","author":"佚名","dynasty":"先秦","form":"诗","lines":["皇矣上帝，临下有赫。监观四方，求民之莫。维此二国，其政不获。","维彼四国，爰究爰度。上帝耆之，憎其式廓。乃眷西顾，此维与宅。","作之屏之，其菑其翳。修之平之，其灌其栵。启之辟之，其柽其椐。","攘之剔之，其檿其柘。帝迁明徳，串夷载路。天立厥配，受命既固。","帝省其山，柞棫斯抜，松柏斯兑。帝作邦作对，自大伯王季。维此王季，","因心则友。则友其兄，则笃其庆，载锡之光。受禄无丧，奄有四方。","维此王季，帝度其心。貊其徳音，其徳克明。克明克类，克长克君。","王此大邦，克顺克比。比于文王，其徳靡悔。既受帝祉，施于孙子。","帝谓文王：无然畔援，无然歆羡，诞先登于岸。密人不恭，敢距大邦，","侵阮徂共。王赫斯怒，爰整其旅，以按徂旅。以笃于周祜，以对于天下。","依其在京，侵自阮疆。陟我高冈，无矢我陵。我陵我阿，无饮我泉，","我泉我池。度其鲜原，居岐之阳，在渭之将。万邦之方，下民之王。","帝谓文王：予怀明徳，不大声以色，不长夏以革。不识不知，顺帝之则。","帝谓文王：訽尔仇方，同尔弟兄。以尔钩援，与尔临冲，以伐崇墉。","临冲闲闲，崇墉言言。执讯连连，攸馘安安。是类是祃，是致是附，","四方以无侮。临冲茀茀，崇墉仡仡。是伐是四，是绝是忽。四方以无払。"],"source":"《诗经》"},{"title":"赠卫八処士","author":"杜甫","dynasty":"唐","form":"诗","lines":["人生不相见，动如参与商。","今夕复何夕，共此灯烛光。","少壮能几时，鬓髪各已苍。","访旧半为鬼，惊呼热中肠。","焉知二十载，重上君子堂。","昔别君未婚，児女忽成行。","怡然敬父执，问我来何方。","问荅乃未已，児女罗酒浆。","夜雨剪春韭，新炊间黄粱。","主称会面难，一挙累十觞。","十觞亦不酔，感子故意长。","明日隔山岳，世事両茫茫。"],"source":"《唐诗三百首》"},{"title":"周徳万携孥赴竜舒法曹道过水阳相见留别女弟","author":"范成大","dynasty":"宋","form":"诗","lines":["草草相逢小驻船，一杯和涙饮江天。","妹孤忍使行千里，兄老那堪别数年。","马転不容吾怅望，橹鸣肯为汝留连。","神如相此俱强健，绿髪帰来慰眼前。"],"source":"宋诗"},{"title":"谢池春","author":"陆游","dynasty":"宋","form":"词","lines":["七十衰翁，不减少年豪气。","似天山、凄凉病骥。","铜驼荆棘，洒临风清泪。","甚情怀、伴人儿戏。","如今何幸，作个故渓归计。","鹤飞来、晴岚暖翠。","玉壶春酒，约群仙同酔。","洞天寒、露桃开未。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・得胜令","author":"王实甫","dynasty":"元","form":"曲","lines":["惊觉我的是颤巍巍竹影走龙蛇，虚飘飘庄周梦蝴蝶，絮叨叨促织儿无休歇，韵悠悠砧声儿不断绝。","痛煞煞伤别，急煎煎好梦儿应难舎；冷清清的咨嗟，娇滴滴玉人儿何处也！。"],"source":"元曲"},{"title":"灵台","author":"佚名","dynasty":"先秦","form":"诗","lines":["经始灵台，经之营之。庶民攻之，不日成之。经始勿亟，庶民子来。","王在灵囿，麀鹿攸伏。麀鹿濯濯，白鸟翯翯。王在灵沼，于牣鱼跃。","虡业维枞，贲鼓维镛。于论鼓钟，于乐辟雍。","于论鼓钟，于乐辟雍。鼍鼓逢逢。蒙瞍奏公。"],"source":"《诗经》"},{"title":"丽人行","author":"杜甫","dynasty":"唐","form":"诗","lines":["三月三日天気新，长安水辺多丽人。","态浓意远淑且真，肌理细腻骨肉匀。","繍罗衣裳照暮春，蹙金孔雀银麒麟。","头上何所有，翠微㔩叶垂鬓唇。","背后何所见，珠圧腰衱穏称身。","就中云幕椒房亲，赐名大国虢与秦。","紫驼之峰出翠釜，水精之盘行素鳞。","犀箸厌饫久未下，銮刀缕切空纷纶。","黄门飞鞚不动尘，御厨络绎送八珍。","箫鼓哀吟感鬼神，宾従雑遝実要津。","后来鞍马何逡巡，当轩下马入锦茵。","杨花雪落覆白苹，青鸟飞去衔红巾。","炙手可热势绝伦，慎莫近前丞相嗔。"],"source":"《唐诗三百首》"},{"title":"高淳道中","author":"范成大","dynasty":"宋","form":"诗","lines":["路入高淳麦更深，草泥沾润马骎骎。","雨帰陇首云凝黛，日漏山腰石渗金。","老柳不春花自蔓，古祠无壁树空阴。","一箪定属前村店，衮衮炊烟起竹林。"],"source":"宋诗"},{"title":"一落索","author":"陆游","dynasty":"宋","form":"词","lines":["满路游丝飞絮。","韶光将暮。","此时谁与说新愁，有百啭、流莺语。","俯仰人间今古。","神仙何处。","花前须判酔扶归，酒不到、刘伶墓。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・鸳鸯煞","author":"王实甫","dynasty":"元","form":"曲","lines":["柳丝长咫尺情牵惹，水声幽仿仏人呜咽。","斜月残灯，半明不灭。","畅道是旧恨连绵，新愁郁结；别恨离愁，满肺腑难淘泻。","除纸笔代喉舌，千种相思对谁说。","(并下)。"],"source":"元曲"},{"title":"下武","author":"佚名","dynasty":"先秦","form":"诗","lines":["下武维周，世有哲王。三后在天，王配于京。","王配于京，世徳作求。永言配命，成王之孚。","成王之孚，下土之式。永言孝思，孝思维则。","媚兹一人，应侯顺徳。永言孝思，昭哉嗣服。","昭兹来许，绳其祖武。于万斯年，受天之祜。","受天之祜，四方来贺。于万斯年，不遐有佐。"],"source":"《诗经》"},{"title":"哀江头","author":"杜甫","dynasty":"唐","form":"诗","lines":["少陵野老吞声哭，春日潜行曲江曲。","江头宫殿锁千门，细柳新蒲为谁绿。","忆昔霓旌下南苑，苑中万物生颜色。","昭阳殿里第一人，同辇随君侍君侧。","辇前才人帯弓箭，白马嚼啮黄金勒。","翻身向天仰射云，一箭正坠双飞翼。","明眸皓歯今何在，血汚游魂帰不得。","清渭东流劒阁深，去住彼此无消息。","人生有情涙沾臆，江水江花岂终极。","黄昏胡骑尘満城，欲往城南忘南北。"],"source":"《唐诗三百首》"},{"title":"夜至宁庵见壁间端礼昆仲倡和明日将去次其韵","author":"范成大","dynasty":"宋","form":"诗","lines":["杉松庑门森老苍，仏屋深夜幡花香。","借床睡倒恍何処，梦随潜鱼聴惊榔。","咿唖禽语暁光浄，窸窣草鸣朝雨凉。","哦诗出门懐二妙，春涨绕山湖水黄。"],"source":"宋诗"},{"title":"一落索","author":"陆游","dynasty":"宋","form":"词","lines":["识破浮生虚妄。","从人讥谤。","此身恰似弄潮儿，曽过了、千重浪。","且喜归来无恙。","一壶春酿。","雨蓑烟笠傍渔矶，应不是、封侯相。"],"source":"宋词"},{"title":"草桥店梦莺莺(第四本)・络丝娘煞尾","author":"王实甫","dynasty":"元","form":"曲","lines":["都则为一官半职，阻隔得千山万水。"],"source":"元曲"},{"title":"文王有声","author":"佚名","dynasty":"先秦","form":"诗","lines":["文王有声，遹骏有声。遹求厥宁，遹观厥成。文王烝哉！","文王受命，有此武功。既伐于崇，作邑于丰。文王烝哉！","筑城伊淢，作丰伊匹。匪棘其欲，遹追来孝。王后烝哉！","王公伊濯，维丰之垣。四方攸同，王后维翰。王后烝哉！","丰水东注，维禹之绩。四方攸同，皇王维辟。皇王烝哉！","镐京辟雍，自西自东，自南自北，无思不服。皇王烝哉！","考卜维王，宅是镐京。维龟正之，武王成之。武王烝哉！","丰水有芑，武王岂不仕？诒厥孙谋，以燕翼子。武王烝哉！"],"source":"《诗经》"},{"title":"哀王孙","author":"杜甫","dynasty":"唐","form":"诗","lines":["长安城头头白乌，夜飞延秋门上呼。","又向人家啄大屋，屋底达官走避胡。","金鞭断折九马死，骨肉不待同驰駆。","腰下実玦青珊瑚，可怜王孙泣路隅。","问之不肯道姓名，但道困苦乞为奴。","已経百日窜荆棘，身上无有完肌肤。","高帝子孙尽隆准，竜种自与常人殊。","豺狼在邑竜在野，王孙善保千金躯。","不敢长语临交衢，且为王孙立斯须。","昨夜东风吹血腥，东来橐驼満旧都。","朔方健児好身手，昔何勇锐今何愚。","窃闻天子已伝位，贤徳北服南単于。","花门剺面请雪耻，慎勿出口他人狙。","哀哉王孙慎勿疏，五陵佳気无时无。"],"source":"《唐诗三百首》"},{"title":"行唐村平野晴色妍甚","author":"范成大","dynasty":"宋","form":"诗","lines":["暖日烘繁梅，秾香扑征鞅。","云烟醸春色，心目両骀荡。","柳眉翠已扫，桑眼青未放。","兹游定不俗，前路入千嶂。"],"source":"宋诗"},{"title":"杏花天","author":"陆游","dynasty":"宋","form":"词","lines":["老来驹隙骎骎度。","筭只合、狂歌酔舞。","金杯到手君休诉。","看着春光又暮。","谁为倩、柳条系住。","且莫遣、城笳催去。","残红转眼无寻处。","尽属蜂房燕户。"],"source":"宋词"},{"title":"董秀英花月东墙记・仙吕/赏花时","author":"白朴","dynasty":"元","form":"曲","lines":["文质彬彬一丈夫，千里寻师为学谋。","今日个践路途，单身独歩，云外雁声孤。"],"source":"元曲"},{"title":"生民","author":"佚名","dynasty":"先秦","form":"诗","lines":["厥初生民，时维姜嫄。生民如何？克禋克祀，以弗无子。","履帝武敏歆，攸介攸止，载震载夙。载生载育，时维后稷。","诞弥厥月，先生如达。不拆不副，无菑无害。以赫厥灵。","上帝不宁，不康禋祀，居然生子。","诞寘之隘巷，牛羊腓字之。诞寘之平林，会伐平林。","诞寘之寒冰，鸟覆翼之。鸟乃去矣，后稷呱矣。","实覃实𬣙，厥声载路。诞实匍匐，克岐克嶷。以就口食。","蓺之荏菽，荏菽旆旆。禾役穟穟，麻麦幪幪，瓜瓞唪唪。","诞后稷之穑，有相之道。茀厥丰草，种之黄茂。实方实苞，实种实褎。","实发实秀，实坚实好。实颖实栗，即有邰家室。","诞降嘉种，维秬维秠，维穈维芑。恒之秬秠，是获是亩。","恒之穈芑，是任是负。以归肇祀。","诞我祀如何？或舂或揄，或簸或蹂。释之叟叟，烝之浮浮。","载谋载惟。取萧祭脂，取羝以𫐈，载燔载烈，以兴嗣岁。","卬盛于豆，于豆于登。其香始升，上帝居歆。胡臭亶时。","后稷肇祀。庶无罪悔，以迄于今。"],"source":"《诗经》"},{"title":"佳人","author":"杜甫","dynasty":"唐","form":"诗","lines":["绝代有佳人，幽居在空谷。","自云良家子，零落依草木。","関中昔丧败，兄弟遭杀戮。","官高何足论，不得収骨肉。","世情悪衰歇，万事随転烛。","夫壻軽薄児，新人已如玉。","合昏尚知时，鸳鸯不独宿。","但见新人笑，那闻旧人哭。","在山泉水清，出山泉水浊。","侍婢売珠回，牵萝补茅屋。","摘花不挿髪，采柏动盈匊。","天寒翠袖薄，日暮倚修竹。"],"source":"《唐诗三百首》"},{"title":"岭上红梅","author":"范成大","dynasty":"宋","form":"诗","lines":["雾雨臙脂照松竹，江南春风一枝足。","満城桃李各嫣然，寂莫倾城在空谷。","城中谁解惜娉婷，游子路傍空复情。","花不能言客无语，日暮清愁相対生。"],"source":"宋诗"},{"title":"太平时・添声杨柳枝","author":"陆游","dynasty":"宋","form":"词","lines":["竹里房栊一径深。","静愔愔。","乱红飞尽绿成阴。","有鸣禽。","临罢兰亭无一事，自修琴。","铜炉袅袅海南沉。","洗尘襟。"],"source":"宋词"},{"title":"董秀英花月东墙记・幺篇","author":"白朴","dynasty":"元","form":"曲","lines":["我如今赤手空拳百事无，父丧家贫不似初，囊箧尽消疏。","鹏程有路，何日赴皇都？(云)行了个月期程，到得松江府。","家童，你寻个客店安下。","(童云)理会的。","兀那就是一所店房。","店主在家幺？(净上，云)谁叫，谁叫？(童云)老者，俺家长来此投宿。","(做见科，云)小生动问老公公，此处董府尹在否？(净云)府尹下世去了。","(生云)他宅子在何处？(净云)隔壁就是。","足下与府尹甚亲？(生云)先父与府尹相交契厚。","自先父下世，一向间阔，不曽问候。","(净云)足下如今那里去？(生云)小生儒业进身，游学至此，将赴诏选。","敢问公公，有房舎借一间小生借居，待来春赴试。","(净云)足下既要安住，老夫有一小顽，名曰山寿，就托足下教训攻书。","老夫东墙下有一花木堂，先生就在其中设馆，如何？(生云)如此多谢！(净云)院公，疾忙収拾洁净者。","(院公云)已停当了。","(净云)先生，请往花木堂安歇。","(同下)。"],"source":"元曲"},{"title":"行苇","author":"佚名","dynasty":"先秦","form":"诗","lines":["敦彼行苇，牛羊勿践履。方苞方体，维叶泥泥。","戚戚兄弟，莫远具尔。或四之筵，或授之几。","四筵设席，授几有缉御。或献或醋，洗爵奠斝。","醓醢以荐，或燔或炙。嘉肴脾臄，或歌或咢。","敦弓既坚，四𬭤既均，舎矢既均，序宾以贤。","敦弓既句，既挟四𬭤。四𬭤如树，序宾以不侮。","曽孙维主，酒醴维醽，酌以大斗，以祈黄耇。","黄耇台背，以引以翼。寿考维祺，以介景福。"],"source":"《诗经》"},{"title":"梦李白二首 一","author":"杜甫","dynasty":"唐","form":"诗","lines":["死别已吞声，生别常恻恻。","江南瘴疠地，逐客无消息。","故人入我梦，明我长相忆。","恐非平生魂，路远不可测。","魂来枫叶青，魂返関塞黒。","君今在罗网，何以有羽翼。","落月満屋梁，犹疑照颜色。","水深波浪阔，无使蛟竜得。"],"source":"《唐诗三百首》"},{"title":"浙东参政寄示会稽蓬莱阁诗轴次韵寄题二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["仙翁来佩玉符麟，绿髪无霜照碧筠。","永夜阑干千嶂月，清风挥麈七州春。","尘埃不隔壶中境，功业犹関物外身。","鸾鹤莫惊兵卫峻，主人元是白云人。"],"source":"宋诗"},{"title":"恋绣衾","author":"陆游","dynasty":"宋","form":"词","lines":["不惜貂裘换钓篷。","嗟时人、谁识放翁。","归棹借、樵风稳，数声闻、林外暮锺。","幽栖莫笑蜗庐小，有云山、烟水万重。","半世向、丹青看，喜如今、身在画中。"],"source":"宋词"},{"title":"董秀英花月东墙记・吕仙/点绛唇","author":"白朴","dynasty":"元","form":"曲","lines":["万物乗春，落花成阵，莺声嫩。","垂柳黄匀，越引起心间闷。"],"source":"元曲"},{"title":"既酔","author":"佚名","dynasty":"先秦","form":"诗","lines":["既酔以酒，既饱以徳。君子万年，介尔景福。","既酔以酒，尔肴既将。君子万年，介尔昭明。","昭明有融，高朗令终，令终有俶。公尸嘉告。","其告维何？笾豆静嘉。朋友攸摄，摄以威仪。","威仪孔时，君子有孝子。孝子不匮，永锡尔类。","其类维何？室家之壶。君子万年，永锡祚胤。","其胤维何？天被尔禄。君子万年，景命有仆。","其仆维何？厘尔女士。厘尔女士，从以孙子。"],"source":"《诗经》"},{"title":"梦李白二首 二","author":"杜甫","dynasty":"唐","form":"诗","lines":["浮云终日行，游子久不至。","三夜频梦君，情亲见君意。","告帰常局促，苦道来不易。","江湖多风波，舟楫恐失坠。","出门掻白首，若负平生志。","冠盖満京华，斯人独顦顇。","孰云网恢恢，将老身反累。","千秋万歳名，寂莫身后事。"],"source":"《唐诗三百首》"},{"title":"浙东参政寄示会稽蓬莱阁诗轴次韵寄题二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["鳌背飞来绀碧浮，人间还有小蓬丘。","不须撃水三千里，已圧中天十二楼。","羽驾旧曽将梦到，芝田今合为公秋。","玉霄有客方东望，竟欲乗风驭気游。"],"source":"宋诗"},{"title":"恋绣衾","author":"陆游","dynasty":"宋","form":"词","lines":["无方能驻脸上红。","笑浮生、扰扰梦中。","平地是、冲霄路，又何劳、千日用功。","飘然再过莲峰下，乱云深、吹下暮锺。","访旧隐、依然在，但鹤巣、时有堕松。"],"source":"宋词"},{"title":"董秀英花月东墙记・混江龙","author":"白朴","dynasty":"元","form":"曲","lines":["三春时分，南园草木一时新。","清和天气，淑景良辰。","紫陌游人嫌日短，青闺素女怕黄昏。","寻芳俊士，拾翠佳人。","千红万紫，花柳分春。","对韶光半晌不开言，一天愁都结做心间恨。","憔悴了玉肌金粉，痩损了窈窕精神。"],"source":"元曲"},{"title":"凫鹥","author":"佚名","dynasty":"先秦","form":"诗","lines":["凫鹥在泾，公尸在燕来宁。尔酒既清，尔肴既馨。公尸燕饮，福禄来成。","凫鹥在沙，公尸来燕来宜。尔酒既多，尔肴既嘉。公尸燕饮，福禄来为。","凫鹥在渚，公尸来燕来处。尔酒既湑，尔肴伊脯。公尸燕饮，福禄来下。","凫鹥在潨，公尸来燕来宗，既燕于宗，福禄攸降。公尸燕饮，福禄来崇。","凫鹥在亹，公尸来止熏熏。旨酒欣欣，燔炙芬芬。公尸燕饮，无有后艰。"],"source":"《诗经》"},{"title":"韦讽录事宅観曹将军画马図","author":"杜甫","dynasty":"唐","form":"诗","lines":["国初已来画鞍马，神妙独数江都王。","将军得名三十载，人间又见真乗黄。","曽貌先帝照夜白，竜池十日飞霹雳。","内府殷红马脳盌，倢伃伝诏才人索。","盌赐将军拝舞帰，軽纨细绮相追飞。","贵戚権门得笔迹，始覚屏障生光辉。","昔日太宗拳毛䯄，近时郭家师子花。","今之新図有二马，复令识者久叹嗟。","此皆骑戦一敌万，缟素漠漠开风沙。","其余七匹亦殊绝，迥若寒空动烟雪。","霜蹄蹴踏长楸间，马官厮养森成列。","可怜九马争神骏，顾视清高気深穏。","借问苦心爱者谁，后有韦讽前支遁。","忆昔巡幸新豊宫，翠华払天来向东。","腾骧磊落三万匹，皆与此図筋骨同。","自従献宝朝河宗，无复射蛟江水中。","君不见金粟堆前松柏里，竜媒去尽鸟呼风。"],"source":"《唐诗三百首》"},{"title":"外舅挽词二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["植徳千章茂，硎材百錬刚。","事功才止此，物理故难量。","鴈序云天远，兰阶雨露芳。","公无憾身后，人自惜堂堂。"],"source":"宋诗"},{"title":"风入松","author":"陆游","dynasty":"宋","form":"词","lines":["十年裘马锦江滨。","酒隐红尘。","万金选胜莺花海，倚疏狂、驱使青春。","吹笛鱼龙尽出，题诗风月俱新。","自怜华发满纱巾。","犹是官身。","凤楼常记当年语，问浮名、何似身亲。","欲寄吴笺说与，这回真个闲人。"],"source":"宋词"},{"title":"董秀英花月东墙记・油葫芦","author":"白朴","dynasty":"元","form":"曲","lines":["杏朵桃枝似绛唇，柳絮纷，春光偏闪断肠人。","微风细雨催花信，闲愁万种心间印。","罗帏绣被，孤寒欲断魂。","掩重门尽日无人问，情不遂越伤神。"],"source":"元曲"},{"title":"仮乐","author":"佚名","dynasty":"先秦","form":"诗","lines":["仮乐君子，显显令徳，宜民宜人。受禄于天，保右命之，自天申之。","千禄百福，子孙千亿。穆穆皇皇，宜君宜王。不愆不忘，率由旧章。","威仪抑抑，徳音秩秩。无怨无恶，率由群匹。受福无疆，四方之纲。","之纲之纪，燕及朋友。百辟卿士，媚于天子。不解于位，民之攸塈。"],"source":"《诗经》"},{"title":"丹青引赠曹将军覇","author":"杜甫","dynasty":"唐","form":"诗","lines":["将军魏武之子孙，于今为庶为清门。","英雄割拠虽已矣，文彩风流犹尚存。","学书初学卫夫人，但恨无过王右军。","丹青不知老将至，富贵于我如浮云。","开元之中常引见，承恩数上南熏殿。","凌烟功臣少颜色，将军下笔开生面。","良相头上进贤冠，猛将腰间大羽箭。","褒公鄂公毛髪动英姿飒爽来酣戦。","先帝天马玉花骢，画工如山貌不同。","是日牵来赤墀下，迥立阊阖生长风。","诏谓将军払绢素，意匠惨澹経営中。","斯须九重真竜出，一洗万古凡马空。","玉花却在御榻上，榻上庭前屹相向。","至尊含笑催赐金，圉人太仆皆惆怅。","弟子韩干早入室，亦能画马穷殊相。","干惟画肉不画骨，忍使骅骝気凋丧。","将军画善盖有神，必逢佳士亦写真。","即今飘泊干戈际，屡貌寻常行路人。","途穷反遭俗眼白，世上未有如公贫。","但看古来盛名下，终日坎𡒄缠其身。"],"source":"《唐诗三百首》"},{"title":"外舅挽词二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["幽介连昏援，门阑阅歳更。","方欣承燕几，何意写铭旌。","笑语犹寻梦，恩勤已隔生。","情伤到深処，有涙不胜倾。"],"source":"宋诗"},{"title":"真珠帘","author":"陆游","dynasty":"宋","form":"词","lines":["灯前月下嬉游处。","向笙歌、锦绣丛中相遇。","彼此知名，才见便论心素。","浅黛娇蝉风调别，最动人、时时偷顾。","归去。","想闲窗深院，调弦促柱。","乐府初翻新谱。","漫裁红点翠，闲题金缕。","燕子入帘时，又一番春暮。","侧帽燕脂坡下过，料也记、前年崔护。","休诉。","待从今须与，好花为主。"],"source":"宋词"},{"title":"董秀英花月东墙记・天下乐","author":"白朴","dynasty":"元","form":"曲","lines":["我只见杨柳横墙易得春，欢欣，可意人，一见了心下如何忍。","送秋波眼角情，近东墙住左邻，觑了可憎才有就因。"],"source":"元曲"},{"title":"公刘","author":"佚名","dynasty":"先秦","form":"诗","lines":["笃公刘，匪居匪康。乃埸乃疆，乃积乃仓；乃裹糇粮，于橐于囊。","思辑用光，弓矢斯张；干戈戚扬，爰方启行。","笃公刘，于胥斯原。既庶既繁，既顺乃宣，而无永叹。陟则在𪩘，","复降在原。何以舟之？维玉及瑶，鞞琫容刀。","笃公刘，逝彼百泉。瞻彼溥原，乃陟南冈。乃觏于京，京师之野。","于时处处，于时庐旅，于时言言，于时语语。","笃公刘，于京斯依。跄跄济济，俾筵俾几。既登乃依，乃造其曹。","执豕于牢，酌之用匏。食之饮之，君之宗之。","笃公刘，既溥既长。既景乃冈，相其阴阳，观其流泉。其军三单，","度其隰原。彻田为粮，度其夕阳。豳居允荒。","笃公刘，于豳斯馆。渉渭为乱，取厉取锻，止基乃理。爰众爰有，","夹其皇涧。溯其过涧。止旅乃密，芮鞫之即。"],"source":"《诗经》"},{"title":"寄韩谏议","author":"杜甫","dynasty":"唐","form":"诗","lines":["今我不楽思岳阳，身欲奋飞病在床。","美人娟娟隔秋水，濯足洞庭望八荒。","鸿飞冥冥日月白，青枫叶赤天雨霜。","玉京群帝集北斗，或骑骐𬴊翳凤皇。","芙蓉旌旗烟雾楽，影动倒景揺潇湘。","星宫之君酔琼浆，羽人稀少不在旁。","似闻昨者赤松子，恐是汉代韩张良。","昔随刘氏定长安，帷幄未改神惨伤。","国家成败吾岂敢，色难腥腐餐风香。","周南留滞古所惜，南极老人応寿昌。","美人胡为隔秋水，焉得置之贡玉堂。"],"source":"《唐诗三百首》"},{"title":"天平先陇道中时将赴新安掾","author":"范成大","dynasty":"宋","form":"诗","lines":["霜桥冰涧浄无尘，竹坞梅渓未放春。","百畳海山郷梦熟，三年江路旅愁生。","松楸永寄孤穷涙，泉石终収漫浪身。","好住邻翁各安健，帰来相访说情真。"],"source":"宋诗"},{"title":"风流子","author":"陆游","dynasty":"宋","form":"词","lines":["佳人多命薄，初心慕、徳耀嫁梁鸿。","记绿窗睡起，静吟闲咏，句翻离合，格变玲珑。","更乗兴，素纨留戏墨，纤玉抚孤桐。","蟾滴夜寒，水浮微冻，凤笺春丽，花砑轻红。","人生谁能料，堪悲处、身落柳陌花丛。","空羡画堂鹦鹉，深闭金笼。","向宝镜鸾钗，临妆常晩，绣茵牙版，催舞还慵。","肠断市桥月笛，灯院霜锺。"],"source":"宋词"},{"title":"董秀英花月东墙记・那咤令","author":"白朴","dynasty":"元","form":"曲","lines":["一见了那人，不由我断魂；思量起这人，有韩文柳文；他是个俏人，读齐论鲁论。","想的咱不下怀，几时得成秦晋，甚何年一处温存？。"],"source":"元曲"},{"title":"泂酌","author":"佚名","dynasty":"先秦","form":"诗","lines":["泂酌彼行潦，挹彼注兹，可以餴饎。岂弟君子，民之父母。","泂酌彼行潦，挹彼注兹，可以濯罍。岂弟君子，民之攸归。","泂酌彼行潦，挹彼注兹，可以濯溉。岂弟君子，民之攸墍。"],"source":"《诗经》"},{"title":"古柏行","author":"杜甫","dynasty":"唐","form":"诗","lines":["孔明庙前有老柏，柯如青铜根如石。","霜皮溜雨四十囲，黛色参天二千尺。","君臣已与时际会，树木犹为人爱惜。","云来気接巫峡长，月出寒通雪山白。","忆昨路绕锦亭东，先主武侯同閟宫。","崔嵬枝干郊原古，窈窕丹青戸牖空。","落落盘踞虽得地，冥冥孤高多烈风。","扶持自是神明力，正直原因造化功。","大厦如倾要梁栋，万牛回首丘山重。","不露文章世已惊，未辞剪伐谁能送。","苦心岂免容蝼蚁，香叶终経宿鸾凤。","志士幽人莫怨嗟，古来材大难为用。"],"source":"《唐诗三百首》"},{"title":"元夕泊舟霅川","author":"范成大","dynasty":"宋","form":"诗","lines":["莲炬光中月自円，人情草草竞华年。","最怜一夜旗亭鼓，能共钟声到客船。"],"source":"宋诗"},{"title":"双头莲","author":"陆游","dynasty":"宋","form":"词","lines":["风巻征尘，堪叹处、青骢正摇金辔。","客襟贮泪。","漫万点如血，凭谁持寄。","伫想艳态幽情，压江南佳丽。","春正媚。","怎忍长亭，匆匆顿分连理。","目断淡日平芜，望烟浓树远，微茫如荠。","悲欢梦里。","奈倦客、又是关河千里。","最苦唱彻骊歌，重迟留无计。","何限事。","待与丁宁，行时已酔。"],"source":"宋词"},{"title":"董秀英花月东墙记・鹊踏枝","author":"白朴","dynasty":"元","form":"曲","lines":["好教我闷昏昏，泪纷纷，都只为美貌潘安，仁者能仁。","一会家心中自忖，谁与俺通个殷勤。"],"source":"元曲"},{"title":"巻阿","author":"佚名","dynasty":"先秦","form":"诗","lines":["有巻者阿，飘风自南。岂弟君子，来游来歌，以矢其音。","伴奂尔游矣，优游尔休矣。岂弟君子，俾尔弥尔性，似先公酋矣。","尔土宇昄章，亦孔之厚矣。岂弟君子，俾尔弥尔性，百神尔主矣。","尔受命长矣，茀禄尔康矣。岂弟君子，俾尔弥尔性，纯嘏尔常矣。","有冯有翼，有孝有徳，以引以翼。岂弟君子，四方为则。","颙颙卬卬，如圭如璋，令闻令望。岂弟君子，四方为纲。","凤凰于飞，翙翙其羽，亦集爰止。蔼蔼王多吉士，维君子使，媚于天子。","凤凰于飞，翙翙其羽，亦傅于天。蔼蔼王多吉人，维君子命，媚于庶人。","凤凰鸣矣，于彼高冈。梧桐生矣，于彼朝阳。菶菶萋萋，雍雍喈喈。","君子之车，既庶且多。君子之马，既闲且驰。矢诗不多，维以遂歌。"],"source":"《诗经》"},{"title":"観公孙大娘弟子舞劒器行","author":"杜甫","dynasty":"唐","form":"诗","lines":["昔有佳人公孙氏，一舞劒気动四方。","観者如山色沮丧，天地为之久低昂。","㸌如羿射九日落，矫如群帝骖竜翔。","来如雷霆収震怒，罢如江海凝清光。","绛唇珠袖両寂莫，况有弟子伝芬芳。","临颍美人在白帝，妙舞此曲神扬扬。","与余问答既有以，感时抚事増惋伤。","先帝侍女八千人，公孙劒器初第一。","五十年间似反掌，风尘倾动昏王室。","棃园子弟散如烟，女楽余姿映寒日。","金粟堆南木已拱，瞿唐石城草萧瑟。","玳筵急管曲复终，楽极哀来月东出。","老夫不知其所往，足茧荒山転愁疾。"],"source":"《唐诗三百首》"},{"title":"桐川郡圃梅极盛皆囲抱高木浙中无有","author":"范成大","dynasty":"宋","form":"诗","lines":["家住丹枫白苇林，横枝一笑万黄金。","玉渓园里逢千树，还尽春风未足心。"],"source":"宋诗"},{"title":"鹧鸪天","author":"陆游","dynasty":"宋","form":"词","lines":["杖屦寻春苦未迟。","洛城樱笋正当时。","三千界外归初到，五百年前事总知。","吹玉笛，渡清伊。","相逢休问姓名谁。","小车处士深衣叟，曽是天津共赋诗。"],"source":"宋词"},{"title":"董秀英花月东墙记・寄生草","author":"白朴","dynasty":"元","form":"曲","lines":["怕的是黄昏后，入罗帏愁越狠。","孤眠独枕教人闷，愁潘病沈教人恨，行迟力顿教人困。","似这等含情掩卧象牙床，几时得阳台上遇着多才俊。","(梅云)姐姐，我猜着你，敢待和昨日那秀才说话。","他在那壁，你在这壁，如何得会？(旦云)想当初卓文君怎生私奔相如来？(梅云)他两个缘何便得成就来？(旦唱)。"],"source":"元曲"},{"title":"民劳","author":"佚名","dynasty":"先秦","form":"诗","lines":["民亦劳止，汔可小康。恵此中国，以绥四方。无纵诡随，以谨无良。","式遏寇虐，憯不畏明。柔远能迩，以定我王。","民亦劳止，汔可小休。恵此中国，以为民逑。无纵诡随，以谨惛怓。","式遏寇虐，无俾民忧。无弃尔劳，以为王休。","民亦劳止，汔可小息。恵此京师，以绥四国。无纵诡随，以谨罔极。","式遏寇虐，无俾作慝。敬慎威仪，以近有徳。","民亦劳止，汔可小愒。恵此中国，俾民忧泄。无纵诡随，以谨丑厉。","式遏寇虐，无俾正败。戎虽小子，而式弘大。","民亦劳止，汔可小安。恵此中国，国无有残。无纵诡随，以谨缱绻。","式遏寇虐，无俾正反。王欲玉女，是用大谏。"],"source":"《诗经》"},{"title":"寄人二首  其一","author":"张佖","dynasty":"唐","form":"诗","lines":["别梦依依到谢家，小廊回合曲阑斜。","多情只有春庭月，犹为离人照落花。"],"source":"《唐诗三百首》"},{"title":"牧马山道中","author":"范成大","dynasty":"宋","form":"诗","lines":["土桥茅屋両三家，竹里鸣泉漱白沙。","春色悩人无畔岸，乱飘风袖払梅花。"],"source":"宋诗"},{"title":"蝶恋花","author":"陆游","dynasty":"宋","form":"词","lines":["禹庙兰亭今古路。","一夜清霜，染尽湖边树。","鹦鹉杯深君莫诉。","他时相遇知何处。","冉冉年华留不住。","镜里朱颜，毕竟消磨去。","一句丁宁君记取。","神仙须是闲人做。"],"source":"宋词"},{"title":"董秀英花月东墙记・幺篇","author":"白朴","dynasty":"元","form":"曲","lines":["汉相如在寒窗下，卓氏女配做婚。","都只为我情你意相投顺，姻缘自把佳期问，郎才女貌皆相趁。","你道是阻东墙难会碧纱厨，似俺这干荷叶那讨灵犀润。"],"source":"元曲"},{"title":"板","author":"佚名","dynasty":"先秦","form":"诗","lines":["上帝板板，下民卒瘅。出话不然，为犹不远。","靡圣管管。不实于亶。犹之未远，是用大谏。","天之方难，无然宪宪。天之方蹶，无然泄泄。","辞之辑矣，民之洽矣。辞之怿矣，民之莫矣。","我虽异事，及尔同僚。我即尔谋，听我嚣嚣。","我言维服，勿以为笑。先民有言，询于刍荛。","天之方虐，无然谑谑。老夫灌灌，小子𫏋𫏋。","匪我言耄，尔用忧谑。多将熇熇，不可救药。","天之方懠。无为夸毗。威仪卒迷，善人载尸。","民之方殿屎，则莫我敢葵？丧乱蔑资，曽莫恵我师？","天之牖民，如埙如篪，如璋如圭，如取如携。","携无曰益，牖民孔易。民之多辟，无自立辟。","价人维藩，大师维垣，大邦维屏，大宗维翰，","怀徳维宁，宗子维城。无俾城坏，无独斯畏。","敬天之怒，无敢戏予。敬天之渝，无敢驰驱。","昊天曰明，及尔出王。昊天曰旦，及尔游衍。"],"source":"《诗经》"},{"title":"雑曲歌辞 盖罗缝 一","author":"不详","dynasty":"唐","form":"诗","lines":["秦时明月汉时関，万里征人尚未还。","但愿竜庭神将在，不教胡马渡阴山。"],"source":"《唐诗三百首》"},{"title":"宿牧马山胜果寺","author":"范成大","dynasty":"宋","form":"诗","lines":["仏灯已暗还吐，旅枕才安却惊。","月色看成暁色，渓声聴作松声。"],"source":"宋诗"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["石帆山下雨空蒙。","三扇香新翠箬篷。","苹叶绿，蓼花红。","回首功名一梦中。"],"source":"宋词"},{"title":"董秀英花月东墙记・后庭花","author":"白朴","dynasty":"元","form":"曲","lines":["似这等害相思怎地忍？不由人上心来雨泪频。","避不的老母将将怪，好教我留连心上人。","枉劳魂，不觉的罗衣宽褪。","被生寒怎地温？看看的憔悴了身，厌厌的害杀人。","唤梅香掩上门，把沉檀炉内焚，志诚心祷告神。"],"source":"元曲"},{"title":"荡","author":"佚名","dynasty":"先秦","form":"诗","lines":["荡荡上帝，下民之辟。疾威上帝，其命多辟。","天生烝民，其命匪谌。靡不有初，鲜克有终。","文王曰咨，咨汝殷商。曽是彊御？曽是掊克？","曽是在位？曽是在服？天降滔徳，女兴是力。","文王曰咨，咨女殷商。而秉义类，彊御多怼。","流言以对。寇攘式内。侯作侯祝，靡届靡究。","文王曰咨，咨女殷商。女炰烋于中国。敛怨以为徳。","不明尔徳，时无背无侧。尔徳不明，以无陪无卿。","文王曰咨，咨女殷商。天不湎尔以酒，不义从式。","既衍尔止。靡明靡晦。式号式呼。俾昼作夜。","文王曰咨，咨女殷商。如蜩如螗，如沸如羹。","小大近丧，人尚乎由行。内奰于中国，覃及鬼方。","文王曰咨，咨女殷商。匪上帝不时，殷不用旧。","虽无老成人，尚有典刑。曽是莫听，大命以倾。","文王曰咨，咨女殷商。人亦有言：颠沛之掲，","枝叶未有害，本实先拨。殷鉴不远，在夏后之世。"],"source":"《诗经》"},{"title":"雑曲歌辞 婆罗门","author":"杨敬述进","dynasty":"唐","form":"诗","lines":["回楽峰前沙似雪，受降城外月如霜。","不知何処吹芦管？一夜征人尽望郷。"],"source":"《唐诗三百首》"},{"title":"游宁国奉圣寺","author":"范成大","dynasty":"宋","form":"诗","lines":["松梢台殿鬰高标，山転渓回一水朝。","不惜褰裳呼小渡，夜来春涨失浮桥。"],"source":"宋诗"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["晴山滴翠水挼蓝。","聚散渔舟两复三。","横埭北，断桥南。","侧起船篷便作帆。"],"source":"宋词"},{"title":"董秀英花月东墙记・柳叶儿","author":"白朴","dynasty":"元","form":"曲","lines":["呀，愁锁定眉尖春恨，怎不教心怀忧闷？见如今人远天涯近，难勾引，怎相交？越加上鬼病三分。"],"source":"元曲"},{"title":"抑","author":"佚名","dynasty":"先秦","form":"诗","lines":["抑抑威仪，维徳之隅。人亦有言：靡哲不愚，庶人之愚，亦职维疾。","哲人之愚，亦维斯戻。无竞维人，四方其训之。有觉徳行，四国顺之。","𬣙谟定命，远犹辰告。敬慎威仪，维民之则。其在于今，兴迷乱于政。","颠覆厥徳，荒湛于酒。女虽湛乐从，弗念厥绍。罔敷求先王，克共明刑。","四皇天弗尚，如彼泉流，无沦胥以亡。夙兴夜寐，洒扫庭内，维民之章。","修尔车马，弓矢戎兵，用戒戎作，用逷蛮方。质尔人民，谨尔侯度，用戒不虞。","慎尔出话，敬尔威仪，无不柔嘉。白圭之玷，尚可磨也；斯言之玷，不可为也！","无易由言，无曰苟矣，莫扪朕舌，言不可逝矣。无言不仇，无徳不报。","恵于朋友，庶民小子。子孙绳绳，万民靡不承。视尔友君子，辑柔尔颜，不遐有愆。","相在尔室，尚不愧于屋漏。无曰不显，莫予云觏。神之格思，不可度思，矧可射思！","辟尔为徳，俾臧俾嘉。淑慎尔止，不愆于仪。不僭不贼，鲜不为则。投我以桃，报之以李。","彼童而角，实虹小子。荏染柔木，言缗之丝。温温恭人，维徳之基。","其维哲人，告之话言，顺徳之行。其维愚人，覆谓我僭。民各有心。","于乎小子，未知臧否。匪手携之，言示之事。匪面命之，言提其耳。","借曰未知，亦既抱子。民之靡盈，谁夙知而莫成？昊天孔昭，我生靡乐。","视尔梦梦，我心惨惨。诲尔谆谆，听我藐藐。匪用为教，覆用为虐。","借曰未知，亦聿既耄。于乎，小子，告尔旧止。听用我谋，庶无大悔。","天方艰难，曰丧厥国。取譬不远，昊天不忒。回遹其徳，俾民大棘。"],"source":"《诗经》"},{"title":"雑曲歌辞 清平调 一","author":"李白","dynasty":"唐","form":"诗","lines":["云想衣裳花想容，春风払槛露华浓。","若非群玉山头见，会向瑶台月下逢。"],"source":"《唐诗三百首》"},{"title":"自宁国渓行至宣城舟人云凡百八十滩","author":"范成大","dynasty":"宋","form":"诗","lines":["波惊石険夜喧雷，暁泊旗亭笑眼开。","休问行人縁底痩，适従百八十滩来。"],"source":"宋诗"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["镜湖俯仰两青天。","万顷玻璃一叶船。","拈棹舞，拥蓑眠。","不作天仙作水仙。"],"source":"宋词"},{"title":"董秀英花月东墙记・青哥儿","author":"白朴","dynasty":"元","form":"曲","lines":["对人前一言难尽，老夫人治家严训，怨俺那火性如雷老母亲。","谨慎闺门，昼夜追巡，坐守行跟，恐失人伦。","但若离了半时辰，来相问。","(梅云)姐姐，似你今春多病，可以自己调理，莫费神思。","不争你这等念想，倘若其身有失，如何是了？休休，莫要护病成疾，自损其身。","姐姐自当思之。","(旦云)梅香，你可知我心间的事？(梅云)妾虽不知，见姐姐身体不快，以此谏劝，自可调理。","(旦云)似这等病，如何治度？我一会家不想起来便罢，一会家想将起，好是凄凉人也！(唱)。"],"source":"元曲"},{"title":"桑柔","author":"佚名","dynasty":"先秦","form":"诗","lines":["菀彼桑柔，其下侯旬，捋采其刘，瘼此下民。不殄心忧，仓兄填兮。倬彼昊天，宁不我矜？","四牡骙骙，旟旐有翩。乱生不夷，靡国不泯。民靡有黎，具祸以烬。于乎有哀，国歩斯频。","国歩灭资，天不我将。靡所止疑，云徂何往？君子实维，秉心无竞。谁生厉阶，至今为梗？","忧心殷殷，念我土宇。我生不辰，逢天𫢸怒。自西徂东，靡所定处。多我觏痻，孔棘我圉。","为谋为毖，乱况斯削。告尔忧恤，诲尔序爵。谁能执热，逝不以濯？其何能淑，载胥及溺。","如彼溯风，亦孔之僾。民有肃心，荓云不逮。好是稼穑，力民代食。稼穑维宝，代食维好？","天降丧乱，灭我立王。降此蟊贼，稼穑卒痒。哀恫中国，具赘卒荒。靡有旅力，以念穹苍。","维此恵君，民人所瞻。秉心宣犹，考慎其相。维彼不顺，自独俾臧。自有肺肠，俾民卒狂。","瞻彼中林，甡甡其鹿。朋友已谮，不胥以谷。人亦有言：进退维谷。","维此圣人，瞻言百里。维彼愚人，覆狂以喜。匪言不能，胡斯畏忌？","维此良人，弗求弗迪。维彼忍心，是顾是复。民之贪乱，宁为荼毒。","大风有隧，有空大谷。维此良人，作为式谷。维彼不顺，征以中垢。","大风有隧，贪人败类。听言则对，诵言如酔。匪用其良，复俾我悖。","嗟尔朋友，予岂不知而作。如彼飞虫，时亦弋获。既之阴女，反予来赫。","民之罔极，职凉善背。为民不利，如云不克。民之回遹，职竞用力。","民之未戻，职盗为寇。凉曰不可，覆背善詈。虽曰匪予，既作尔歌！"],"source":"《诗经》"},{"title":"雑曲歌辞 清平调 二","author":"李白","dynasty":"唐","form":"诗","lines":["一枝红艳露凝香，云雨巫山枉断肠。","借问汉宫谁得似，可怜飞燕倚新妆。"],"source":"《唐诗三百首》"},{"title":"次韵宣州西园二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["苔茵无地着红尘，花草含芳一笑新。","不待东君能剪刻，相公笔力挽回春。"],"source":"宋诗"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["湘湖烟雨长莼丝。","菰米新炊滑上匙。","云散后，月斜时。","潮落舟横酔不知。"],"source":"宋词"},{"title":"董秀英花月东墙记・赚煞","author":"白朴","dynasty":"元","form":"曲","lines":["合晩至黄昏，独宿心间闷。","苦厌厌忧愁自忖。","便有铁石心肠也断魂。","串香焚被冷谁温，引入多情梦里人。","窗儿外月华正新，玉人儿在方寸，我将这海棠花分付与东君。"],"source":"元曲"},{"title":"云汉","author":"佚名","dynasty":"先秦","form":"诗","lines":["倬彼云汉，昭回于天。王曰：于乎！何辜今之人？天降丧乱，饥馑荐臻。","靡神不举，靡爱斯牲。圭壁既卒，宁莫我听？","旱既大甚，蕴隆虫虫。不殄禋祀，自郊徂宫。上下奠瘗，靡神不宗。","后稷不克，上帝不临。耗斁下土，宁丁我梗","旱既大甚，则不可推。兢兢业业，如霆如雷。周余黎民，靡有孑遗。","昊天上帝，则不我遗。胡不相畏？先祖于摧。","旱既大甚，则不可沮。赫赫炎炎，云我无所。大命近止，靡瞻靡顾。","群公先正，则不我助。父母先祖，胡宁忍予？","旱既大甚，涤涤山川。旱魃为虐，如惔如焚。我心惮暑，忧心如熏。","群公先正，则不我闻。昊天上帝，宁俾我遁？","旱既大甚，黾勉畏去。胡宁瘨我以旱？憯不知其故。祈年孔夙，方社不莫。","昊天上帝，则不我虞。","敬恭明神，宜无悔怒。旱既大甚，散无友纪。鞫哉庶正，疚哉冢宰。","趣马师氏，膳夫左右。靡人不周。无不能止，瞻卬昊天，云如何里！","瞻卬昊天，有嘒其星。大夫君子，昭仮无赢。大命近止，无弃尔成。","何求为我。以戻庶正。瞻卬昊天，曷恵其宁？"],"source":"《诗经》"},{"title":"雑曲歌辞 清平调 三","author":"李白","dynasty":"唐","form":"诗","lines":["名花倾国両相歓，长得君王帯笑看。","解釈春风无限恨，沈香亭北倚阑干。"],"source":"《唐诗三百首》"},{"title":"次韵宣州西园二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["星芒垂耀笔床寒，河汉波流砚滴干。","棐几松跗入三昧，一篇诗就一杯残。"],"source":"宋诗"},{"title":"渔父・渔歌子","author":"陆游","dynasty":"宋","form":"词","lines":["长安拝免几公卿。","渔父横眠酔未醒。","烟艇小，钓车腥。","遥指梅山一点青。"],"source":"宋词"},{"title":"董秀英花月东墙记・正宫/端正好","author":"白朴","dynasty":"元","form":"曲","lines":["下香阶，踏芳径，歩苍苔月影当庭。","过回廊一弄凄凉景，好教我添悲兴。"],"source":"元曲"},{"title":"崧高","author":"佚名","dynasty":"先秦","form":"诗","lines":["崧高维岳，骏极于天。维岳降神，生甫及申。维申及甫，维周之翰。四国于蕃。四方于宣。","亹亹申伯，王缵之事。于邑于谢，南国是式。王命召伯，定申伯之宅。登是南邦，世执其功。","王命申伯，式是南邦。因是谢人，以作尔庸。王命召伯，彻申伯土田。王命傅御，迁其私人。","申伯之功，召伯是营。有俶其城，寝庙既成。既成藐藐，王锡申伯。四牡𫏋𫏋，钩膺濯濯。","王遣申伯，路车乗马。我图尔居，莫如南土。锡尔介圭，以作尔宝。往近王舅，南土是保。","申伯信迈，王饯于郿。申伯还南，谢于诚归。王命召伯，彻申伯土疆。以峙其粻，式遄其行。","申伯番番，既入于谢。徒御啴啴。周邦咸喜，戎有良翰。不显申伯，王之元舅，文武是宪。","申伯之徳，柔恵且直。揉此万邦，闻于四国。吉甫作诵，其诗孔硕。其风四好，以赠申伯。"],"source":"《诗经》"},{"title":"雑曲歌辞 渭城曲","author":"王维","dynasty":"唐","form":"诗","lines":["谓城朝雨浥軽尘，客舎青青柳色春。","勧君更尽一杯酒，西出阳関无故人。"],"source":"《唐诗三百首》"},{"title":"晩歩西园","author":"范成大","dynasty":"宋","form":"诗","lines":["料峭軽寒结晩阴，飞花院落怨春深。","吹开红紫还吹落，一种东风両様心。"],"source":"宋诗"},{"title":"恋绣衾","author":"陆游","dynasty":"宋","form":"词","lines":["雨断西山晩照明。","悄无人、幽梦自惊。","说道去、多时也，到如今、真个是行。","远山已是无心画，小楼空、斜掩绣屏。","你嚎早、収心呵，趁刘郎、双鬓未星。"],"source":"宋词"},{"title":"董秀英花月东墙记・滚绣球","author":"白朴","dynasty":"元","form":"曲","lines":["垂杨宿鸟惊，绣鞋不待行。","降明香问天求聘，志诚心祷告神灵。","相思病渐成，看看痩损形，受寂寞事关前定，盼佳期井底银瓶。","似这等栖迟误了奴家命，强打精神拝斗星，何日安宁？(梅云)姐姐，你听那里冰弦之声。","(旦唱)。"],"source":"元曲"},{"title":"烝民","author":"佚名","dynasty":"先秦","form":"诗","lines":["天生烝民，有物有则。民之秉彝，好是懿徳。天监有周，昭仮于下。保兹天子，生仲山甫。","仲山甫之徳，柔嘉维则。令仪令色。小心翼翼。古训是式。威仪是力。天子是若，明命使赋。","王命仲山甫，式是百辟，缵戎祖考，王躬是保。出纳王命，王之喉舌。赋政于外，四方爰发。","肃肃王命，仲山甫将之。邦国若否，仲山甫明之。既明且哲，以保其身。夙夜匪解，以事一人。","人亦有言，柔则茹之，刚则吐之。维仲山甫，柔亦不茹，刚亦不吐。不侮矜寡，不畏强御。","人亦有言，徳𬨎如毛，民鲜克举之。我仪图之，维仲山甫举之。爱莫助之。衮职有阙，维仲山甫补之。","仲山甫出祖。四牡业业。征夫捷捷，毎怀靡及。四牡彭彭，八鸾锵锵。王命仲山甫，城彼东方。","四牡骙骙，八鸾喈喈。仲山甫徂齐，式遄其归。吉甫作诵，穆如清风。仲山甫永怀，以慰其心。"],"source":"《诗经》"},{"title":"雑曲歌辞 金缕衣","author":"不详","dynasty":"唐","form":"诗","lines":["勧君莫惜金缕衣，勧君惜取少年时。","花开堪折直须折，莫待无花空折枝。"],"source":"《唐诗三百首》"},{"title":"送端言","author":"范成大","dynasty":"宋","form":"诗","lines":["东君留恋一分春，蜂蝶阑珊燕子新。","桃李无情空绿径，市桥杨柳送行人。"],"source":"宋诗"},{"title":"采桑子","author":"陆游","dynasty":"宋","form":"词","lines":["三山山下闲居士，巾履萧然。","小酔闲眠。","风引飞花落钓船。"],"source":"宋词"},{"title":"董秀英花月东墙记・倘秀才","author":"白朴","dynasty":"元","form":"曲","lines":["则道是半空中神仙胜境，却元来东墙下把丝桐慢整，你听他款抚冰弦音韵清。","夜阑人静，情悲戚，话丁宁，怎不教人动情？。"],"source":"元曲"},{"title":"韩奕","author":"佚名","dynasty":"先秦","form":"诗","lines":["奕奕梁山，维禹甸之，有倬其道。","韩侯受命，王亲命之：缵戎祖考，无废朕命。","夙夜匪解，虔共尔位，朕命不易。","粲不庭方，以佐戎辟。四牡奕奕，孔修且张。","韩侯入觐，以其介圭，入觐于王。","王锡韩侯，淑旗绥章，簟茀错衡。","玄衮赤舄，钩膺镂锡，鞹鞃浅幭，鞗革金厄。","韩侯出祖，出宿于屠。显父饯之，清酒百壶。","其殽维何？炰鳖鲜鱼。其蔌维何？维笋及蒲。","其赠维何？乗马路车。笾豆有且。侯氏燕胥。","韩侯取妻，汾王之甥，蹶父之子。","韩侯迎止，于蹶之里。","百两彭彭，八鸾锵锵，不显其光。","诸娣从之，祁祁如云。韩侯顾之，烂其盈门。","蹶父孔武，靡国不到。为韩姞相攸，莫如韩乐。","孔乐韩土，川泽𬣙𬣙，鲂𫚈甫甫，麀鹿噳噳。","有熊有罴，有猫有虎。庆既令居，韩姞燕誉。","溥彼韩城，燕师所完。以先祖受命，因时百蛮。","王锡韩侯，其追其貊。奄受北国，因以其伯。","实墉实壑，实亩实藉。献其貔皮，赤豹黄罴。"],"source":"《诗经》"},{"title":"感遇十二首 一","author":"张九齢","dynasty":"唐","form":"诗","lines":["兰叶春葳蕤，桂华秋皎洁。","欣欣此生意，自尔为佳节。","谁知林栖者，闻风坐相悦。","草木有本心，何求美人折。"],"source":"《唐诗三百首》"},{"title":"早発竹下","author":"范成大","dynasty":"宋","form":"诗","lines":["结束晨装破小寒，跨鞍聊得散疲顽。","行冲薄薄軽軽雾，看放重重畳畳山。","碧穂炊烟当树直，绿纹渓水趁桥弯。","清禽百啭似迎客，正在有情无思间。"],"source":"宋诗"},{"title":"水龙吟","author":"陆游","dynasty":"宋","form":"词","lines":["摩诃池上追游路，红绿参差春晩。","韶光妍媚，海棠如酔，桃花欲暖。","挑菜初闲，禁烟将近，一城丝管。","看金鞍争道，香车飞盖，争先占、新亭馆。","惆怅年华暗换。","黯销魂、雨収云散。","镜奁掩月，钗梁拆凤，秦筝斜雁。","身在天涯，乱山孤垒，危楼飞观。","叹春来只有，杨花和恨、向东风满。"],"source":"宋词"},{"title":"董秀英花月东墙记・滚绣球","author":"白朴","dynasty":"元","form":"曲","lines":["我向这东墙仔细听。","凤求鸾曲未成，怎不教想的人成病，今日个聪明的遇着聪明。","这琴陶潜膝上横，蔡邕爨下生。","断肠人这答儿孤另，一句句诉你飘零。","几时得同衾共枕销金帐，满斗焚香说誓盟，愿足平生。"],"source":"元曲"},{"title":"江汉","author":"佚名","dynasty":"先秦","form":"诗","lines":["江汉浮浮，武夫滔滔。匪安匪游，淮夷来求。既出我车，既设我旟。匪安匪舒，淮夷来铺。","江汉汤汤，武夫洸洸。经营四方，告成于王。四方既平，王国庶定。时靡有争，王心载宁。","江汉之浒，王命召虎：式辟四方，彻我疆土。匪疚匪棘，王国来极。于疆于理，至于南海。","王命召虎：来旬来宣。文武受命，召公维翰。无曰予小子，召公是似。肇敏戎公，用锡尔祉。","厘尔圭瓒，秬鬯一卣。告于文人，锡山土田。于周受命，自召祖命，虎拝稽首：天子万年！","虎拝稽首，对扬王休。作召公考：天子万寿！明明天子，令闻不已，矢其文徳，洽此四国。"],"source":"《诗经》"},{"title":"感遇十二首 二","author":"张九齢","dynasty":"唐","form":"诗","lines":["幽林帰独卧，滞虑洗孤清。","持此谢高鸟，因之伝远情。","日夕懐空意，人谁感至精。","飞沈理自隔，何所慰吾诚。"],"source":"《唐诗三百首》"},{"title":"小涧","author":"范成大","dynasty":"宋","form":"诗","lines":["石碍珠旒溅，滩平雾縠舗。","小童能好事，繋马𣃁菖蒲。"],"source":"宋诗"},{"title":"月照梨花・河传","author":"陆游","dynasty":"宋","form":"词","lines":["霁景风软，烟江春涨。","小阁无人，绣帘半上。","花外姊妹相呼。","约樗蒲。","修蛾忘了章台样。","细思一饷。","感事添惆怅。","胸酥臂玉消减，拟觅双鱼。","倩传书。"],"source":"宋词"},{"title":"董秀英花月东墙记・倘秀才","author":"白朴","dynasty":"元","form":"曲","lines":["他在那东墙下诗和了一声，我这里近亭轩把绣鞋立定，好教我兜上心来意不宁。","愁攒眉角上，忽的动伤情，知他是怎生？。"],"source":"元曲"},{"title":"常武","author":"佚名","dynasty":"先秦","form":"诗","lines":["赫赫明明。王命卿士，南仲大祖，大师皇父。整我六师，以修我戎。既敬既戒，恵此南国。","王谓尹氏，命程伯休父，左右陈行。戒我师旅，率彼淮浦，省此徐土。不留不处，三事就绪。","赫赫业业，有严天子。王舒保作，匪绍匪游。徐方绎骚，震惊徐方。如雷如霆，徐方震惊。","王奋厥武，如震如怒。进厥虎臣，阚如虓虎。铺敦淮𣸣，仍执丑虏。截彼淮浦，王师之所。","王旅啴啴，如飞如翰。如江如汉，如山之苞。如川之流，绵绵翼翼。不测不克，濯征徐国。","王犹允塞，徐方既来。徐方既同，天子之功。四方既平，徐方来庭。徐方不回，王曰还归。"],"source":"《诗经》"},{"title":"感遇十二首 四","author":"张九齢","dynasty":"唐","form":"诗","lines":["孤鸿海上来，池潢不敢顾。","侧见双翠鸟，巣在三珠树。","矫矫珍木巅，得无金丸惧。","美服患人指，高明逼神悪。","今我游冥冥，弋者何所慕。"],"source":"《唐诗三百首》"},{"title":"次韵子文探梅水西春已深犹未开水西谓歙渓而黄君谟州学记云濒江地卑盖此水为浙之源正可谓之江也","author":"范成大","dynasty":"宋","form":"诗","lines":["孤山山下小斜桥，客魂曽共暗香飘。","五年不踏西湖路，想见黄昏清浅処。","如今憔悴古江干，岂有幽芳伴倚栏。","腊尽雪残春不至，坐令愁里眼长寒。","霜棱未贷千林槁，门外风饕人欲倒。","斟酌芳心正怯寒，有情真被无情悩。"],"source":"宋诗"},{"title":"月照梨花・河传","author":"陆游","dynasty":"宋","form":"词","lines":["闷已萦损。","那堪多病。","几曲屏山，伴人昼静。","梁燕催起犹慵。","换熏龙。","新愁旧恨何时尽。","渐凋绿鬓。","小雨知花信。","芳笺寄与何处，绣阁珠栊。","柳阴中。"],"source":"宋词"},{"title":"董秀英花月东墙记・呆骨朵","author":"白朴","dynasty":"元","form":"曲","lines":["我这里闷厌厌锁不住疏狂性，怎禁的独自伤情？孤帏里翠减香消，花稍上蜂喧蝶并。","少年人辜负了三春景，身体也无康盛。","自思量怎奈何，渐染出风流病。"],"source":"元曲"},{"title":"瞻卬","author":"佚名","dynasty":"先秦","form":"诗","lines":["瞻卬昊天，则不我恵。孔填不宁，降此大厉。邦靡有定，士民其瘵。","蟊贼蟊疾，靡有夷届。罪罟不収，靡有夷瘳。","人有土田，女反有之。人有民人，女覆夺之。此宜无罪，女反収之。","彼宜有罪，女覆说之。","哲夫成城，哲妇倾城。懿厥哲妇，为枭为鸱。妇有长舌，维厉之阶。","乱匪降自天，生自妇人。匪教匪诲，时维妇寺。","鞫人忮忒。谮始竞背。岂曰不极？伊胡为慝？如贾三倍，君子是识。","妇无公事，休其蚕织。","天何以剌？何神不富？舎尔介狄，维予胥忌。不吊不祥，威仪不类。","人之云亡，邦国殄瘁。","天之降罔，维其优矣。人之云亡，心之忧矣。天之降罔，维其几矣。","人之云亡，心之悲矣。","觱沸槛泉，维其深矣。心之忧矣，宁自今矣？不自我先，不自我后。","藐藐昊天，无不克巩。无忝皇祖，式救尔后。"],"source":"《诗经》"},{"title":"感遇十二首 七","author":"张九齢","dynasty":"唐","form":"诗","lines":["江南有丹橘，経冬犹绿林。","岂伊地気暖，自有歳寒心。","可以荐嘉客，奈何阻重深。","运命唯所遇，循环不可寻。","徒言树桃李，此木岂无阴。"],"source":"《唐诗三百首》"},{"title":"后催租行","author":"范成大","dynasty":"宋","form":"诗","lines":["老父田荒秋雨里，旧时高岸今江水。","佣耕犹自抱长饥，的知无力输租米。","自従郷官新上来，黄纸放尽白纸催。","売衣得銭都纳却，病骨虽寒聊免缚。","去年衣尽到家口，大女临岐両分首。","今年次女已行媒，亦复駆将换升斗。","室中更有第三女，明年不怕催租苦。"],"source":"宋诗"},{"title":"夜游宫","author":"陆游","dynasty":"宋","form":"词","lines":["宴罢珠帘半巻。","画檐外、蜡香人散。","翠雾霏霏漏声断。","倚香肩，看中庭，花影乱。","宛是高唐馆。","宝奁炷、麝烟初暖。","璧月何妨夜夜满。","拥芳柔，恨今年，寒尚浅。"],"source":"宋词"},{"title":"董秀英花月东墙记・脱布衫","author":"白朴","dynasty":"元","form":"曲","lines":["思量起俊俏书生，今日个显姓通名。","海棠花权为信行，姻缘事该前定。"],"source":"元曲"},{"title":"召旻","author":"佚名","dynasty":"先秦","form":"诗","lines":["旻天疾威，天笃降丧。瘨我饥馑，民卒流亡。我居圉卒荒。","天降罪罟，蟊贼内讧。昏椓靡共，溃溃回遹，实靖夷我邦。","皐皐訿訿，曽不知其玷。兢兢业业，孔填不宁，我位孔贬。","如彼岁旱，草不溃茂，如彼栖苴。我相此邦，无不溃止。","维昔之富不如时，维今之疚不如兹。彼疏斯粺，胡不自替？职兄斯引。","池之竭矣，不云自频。泉之竭矣，不云自中。溥斯害矣，职兄斯弘，不灾我躬。","昔先王受命，有如召公，日辟国百里，今也日蹙国百里。于乎哀哉！维今之人，不尚有旧！"],"source":"《诗经》"},{"title":"寻陆鸿渐不遇","author":"皎然","dynasty":"唐","form":"诗","lines":["移家虽帯郭，野径入桑麻。","近种篱辺菊，秋来未着花。","扣门无犬吠，欲去问西家。","报道山中去，帰时毎日斜。"],"source":"《唐诗三百首》"},{"title":"次韵子文冲雨迓使者道闻子规","author":"范成大","dynasty":"宋","form":"诗","lines":["梦魂翾蜨翅，鼻息吼鼍鼓。","唤起治暁装，马嘶童仆语。","汩泥溷凫鹜，惭愧黄鹄挙。","猥吟陬隅池，浪廃桔槹圃。","啼鹃撩客心，钩引着何许。","请歌苏仙词，帰耕一犁雨。"],"source":"宋诗"},{"title":"如梦令","author":"陆游","dynasty":"宋","form":"词","lines":["独倚博山峰小。","翠雾满身飞绕。","只恐学行云，去作阳台春晓。","春晓。","春晓。","满院绿阳芳草。"],"source":"宋词"},{"title":"董秀英花月东墙记・小梁州","author":"白朴","dynasty":"元","form":"曲","lines":["谁想是旧日刘郎到武陵，听说罢怎不伤情。","孤鸾寡凤几时成？人孤另，长叹两三声。"],"source":"元曲"},{"title":"清庙","author":"佚名","dynasty":"先秦","form":"诗","lines":["于穆清庙，肃雍显相。济济多士，秉文之徳。对越在天，骏奔走在庙。不显不承，无射于人斯。"],"source":"《诗经》"},{"title":"西塞山懐古","author":"刘禹锡","dynasty":"唐","form":"诗","lines":["西晋楼船下益州，金陵王気黯然収。","千寻鉄锁沈江底，一片降旛出石头。","人世几回伤往事，山形依旧枕江流。","今逢四海为家日，故塁萧萧芦荻秋。"],"source":"《唐诗三百首》"},{"title":"奉题胡宗伟推官揽秀堂","author":"范成大","dynasty":"宋","form":"诗","lines":["城外屏峰云百畳，城里看云笏拄颊。","山霊自与人争秀，明灭烟霏难応接。","南邻范叔骨相寒，不如骑曹知爱山。","晨霞傥可救枵腹，丐君分我入朝餐。"],"source":"宋诗"},{"title":"失调名","author":"陆游","dynasty":"宋","form":"词","lines":["飞上锦裀红皱。"],"source":"宋词"},{"title":"董秀英花月东墙记・幺篇","author":"白朴","dynasty":"元","form":"曲","lines":["黄昏一盏孤灯映，困腾腾闷倚帏屏。","鼓二更，人初静，更添愁兴，照不到天明。","(旦云)我常记得，俺父亲在日，曽与俺母亲说，在朝之日，曽与三原县令马昂为交，次后，半我许与他儿子马文辅为妻。","我那时年幼，也不曽成得；后来音信不通，因此上不曽成合这亲事。","我那日在后花园中，只见山寿家东墙上，有一秀才，往这壁望着。","我一见那生，发黒眉青，唇红齿白，教我放心不下。","我前日在海棠亭下烧夜香，又遇着他弹琴，专诉失其佳配。","昨日使山寿来问我讨花，我因问他，你师父是谁；山寿说，姓马名彬字文辅。","我就想起俺父亲的言语，莫不就是这生？我两日前写下了一个简帖儿，今日着梅香送与他去。","梅香，你送这简帖儿与那秀才去。","(梅云)将来，我送去。","(旦与简科)(梅云)我送简帖儿去来。","(同下)(生上，云)自从见了秀英小姐，着我神魂飘荡，茶饭懒尝。","昨日着山寿讨花去，小姐与了一朵海棠花，不知主何意？似这等音信不通，如何是了？(梅云)先生万福。","(生云)小娘子，来有何事？(梅云)你不知，听我说咱。","(唱)。"],"source":"元曲"},{"title":"维天之命","author":"佚名","dynasty":"先秦","form":"诗","lines":["维天之命，于穆不已。于乎不显，文王之徳之纯。仮以溢我，我其収之。骏恵我文王，曽孙笃之。"],"source":"《诗经》"},{"title":"金陵五题 乌衣巷","author":"刘禹锡","dynasty":"唐","form":"诗","lines":["朱雀桥辺野草花，乌衣巷口夕阳斜。","旧时王谢堂前燕，飞入寻常百姓家。"],"source":"《唐诗三百首》"},{"title":"次韵太守出郊","author":"范成大","dynasty":"宋","form":"诗","lines":["暁装缇骑踏芳辰，江为安澜露浥尘。","棨戟前駆留住月，笙箫后备带行春。","鱼竜水面金杯満，鸾鹤山头彩笔新。","闻道将军寛礼数，不辞酩酊吐车茵。"],"source":"宋诗"},{"title":"解连环","author":"陆游","dynasty":"宋","form":"词","lines":["泪淹妆薄。","背东风伫立，柳绵池阁。","漫细字、书满芳笺，恨钗燕筝鸿，总难凭托。","风雨无情，又颠倒、绿苔红萼。","仗香醪破闷，怎禁夜阑，酒酲萧索。","刘郎已望故约。","奈重门静院，光景如昨。","尽做它、别有留心，便不念当时，雨意初着。","京兆眉残，怎忍为、新人梳掠。","尽今生、拼了为伊，任人道错。"],"source":"宋词"},{"title":"董秀英花月东墙记・上小楼","author":"白朴","dynasty":"元","form":"曲","lines":["只因你青春后生，俺小姐心肠不硬。","想前夜月下鸣琴，韵和新诗，福至心灵。","音韵轻，声律清，精通理性，多管是暗中传两情相应。","(云)俺姐姐与了这个简帖儿，教送与先生，不知是甚幺言语？(生云)将来我看。","(生看科，云)小娘子，这一首诗是谁写的？(梅云)俺姐姐亲笔写的，你试念与我听。","(生云)\"潇洒月明中，潜身墙角东。","鸣琴离恨积，入夜绣帏空。","梦绕三千界，云迷十二峰。","仙郎休负我，我意若春浓。","\"好高才也！既小姐有顾恋小生之心，我如今备办礼物，使媒人说去，如何？(梅唱)。"],"source":"元曲"},{"title":"维清","author":"佚名","dynasty":"先秦","form":"诗","lines":["维清缉熙，文王之典。肇禋，迄用有成，维周之祯。"],"source":"《诗经》"},{"title":"和楽天春词","author":"刘禹锡","dynasty":"唐","form":"诗","lines":["新妆面面下朱楼，深锁春光一院愁。","行到中庭数花朵，蜻蜓飞上玉掻头。"],"source":"《唐诗三百首》"},{"title":"暁出古巌呈宗伟子文","author":"范成大","dynasty":"宋","form":"诗","lines":["暁风生小寒，岚润裛巾屦。","宿云埋树黒，奔渓転山怒。","东方动光彩，晃晃金钲吐。","千峰森隠现，一気澹回互。","平生癖幽讨，邂逅饱新遇。","那知尘満甑，晨炊午未具。","不愧忍饥面，来寻古巌路。","稲粱亦易谋，烟霞乃难痼。","持此慰亀肠，捜枯尚能句。"],"source":"宋诗"},{"title":"大圣乐","author":"陆游","dynasty":"宋","form":"词","lines":["电转雷惊，自叹浮生，四十二年。","试思量往事，虚无似梦，悲欢万状，合散如烟。","苦海无边，爱河无底，流浪看成百漏船。","何人解，问无常火里，铁打身坚。","须臾便是华颠。","好収拾形体归自然。","又何通，是非荣辱，此事由来都在天。","从今去，任东西南北，作个飞仙。"],"source":"宋词"},{"title":"董秀英花月东墙记・幺篇","author":"白朴","dynasty":"元","form":"曲","lines":["你待教媒人偶成，老夫人天生劣性。","不争你走透消息，泄漏风声，误了前程。","俺姐姐念旧盟，想旧情，何须媒证，不用你半星儿绛罗为定。","(生云)既蒙小姐垂念，小生也写一简，烦小娘子捎去。","(梅云)你写来。","(生写科，云)小娘子，你道我多多上复小姐来。","(梅下)(生云)小姐若见了这简帖儿，好事必成也。","(下)。"],"source":"元曲"},{"title":"烈文","author":"佚名","dynasty":"先秦","form":"诗","lines":["烈文辟公，锡兹祉福。恵我无疆，子孙保之。无封靡于尔邦，维王其崇之。","念兹戎功，继序其皇之。无竞维人，四方其训之。不显维徳，百辟其刑之。于乎，前王不忘！"],"source":"《诗经》"},{"title":"列女操","author":"孟郊","dynasty":"唐","form":"诗","lines":["梧桐相待老，鸳鸯会双死。","贞女贵狥夫，舍生亦如此。","波澜誓不起，妾心井中水。"],"source":"《唐诗三百首》"},{"title":"积雨蒸润体中不佳颇思故居之楽戯书呈子文","author":"范成大","dynasty":"宋","form":"诗","lines":["门外泥深蘸马鞍，墨云未放四维寛。","前山忽接后山暗，暑雨全如秋雨寒。","梦里江湖三叹息，酔中天地一凭阑。","斗升留滞休惆怅，枳棘従来着凤鸾。"],"source":"宋诗"},{"title":"桂枝香","author":"王安石","dynasty":"宋","form":"词","lines":["登临送目。","正故国晩秋，天气初肃。","千里澄江似练，翠峰如簇。","归帆去棹残阳里，背西风、酒旗斜矗。","彩舟云淡，星河鹭起，画图难足。","念往昔、繁华竞逐。","叹门外楼头，悲恨相续。","千古凭高，对此漫嗟荣辱。","六朝旧事随流水，但寒烟、芳草凝绿。","至今商女，时时犹唱，后庭遗曲。"],"source":"宋词"},{"title":"董秀英花月东墙记・满庭芳","author":"白朴","dynasty":"元","form":"曲","lines":["恰便似龙蛇弄影，才过子建，笔扫千兵。","温柔软款多才性，忒煞聪明。","据相貌容颜齐整，论文学海宇传名，堪人敬。","都只为更长漏永，伤感泪盈盈。"],"source":"元曲"},{"title":"天作","author":"佚名","dynasty":"先秦","form":"诗","lines":["天作高山，大王荒之。彼作矣，文王康之。彼徂矣，岐有夷之行。子孙保之。"],"source":"《诗经》"},{"title":"游子吟","author":"孟郊","dynasty":"唐","form":"诗","lines":["慈母手中线，游子身上衣。","临行密密缝，意恐遅遅帰。","谁言寸草心，报得三春晖。"],"source":"《唐诗三百首》"},{"title":"签庁夜帰用前韵呈子文","author":"范成大","dynasty":"宋","form":"诗","lines":["簿书堆里解帰鞍，我亦萧然辔勒寛。","炉篆无风香雾直，庭柯有月露光寒。","闲思喜鹊填河鼓，静数流蛍绕井栏。","明日又駆官里去，従教白鹭侣红鸾。"],"source":"宋诗"},{"title":"甘露歌","author":"王安石","dynasty":"宋","form":"词","lines":["折得一枝香在手。","人间应未有。","疑是经春雪未消。","今日是何朝。"],"source":"宋词"},{"title":"董秀英花月东墙记・耍孩儿","author":"白朴","dynasty":"元","form":"曲","lines":["似这等空房静悄人孤另，却又早香消金鼎。","何时害彻相思病，卜金钱祷告神灵。","生前禽演分明判，八卦详推莫顺情。","四柱安排定，都来増下，祸福分明。"],"source":"元曲"},{"title":"昊天有成命","author":"佚名","dynasty":"先秦","form":"诗","lines":["昊天有成命，二后受之。成王不敢康，夙夜基命宥密。于缉熙！单厥心，四其靖之。"],"source":"《诗经》"},{"title":"度南涧","author":"蔡襄","dynasty":"唐","form":"诗","lines":["隠隠飞桥隔野烟，石矶西畔问渔船。","桃花尽日随流水，洞在清渓何処辺。"],"source":"《唐诗三百首》"},{"title":"圣集夸说少年俊游用韵记其语戯之","author":"范成大","dynasty":"宋","form":"诗","lines":["京尘红软扑雕鞍，年少王孙酒量寛。","倚袖竹风怜翠薄，捧杯花露怯金寒。","黄云城上栖乌曲，绿水桥辺鬭鸭栏。","别后相思惟故物，壁煤侵损扇中鸾。"],"source":"宋诗"},{"title":"甘露歌","author":"王安石","dynasty":"宋","form":"词","lines":["尽日含毫难比兴。","都无色可并。","万里晴天何处来。","真是屑琼瑰。"],"source":"宋词"},{"title":"董秀英花月东墙记・四煞","author":"白朴","dynasty":"元","form":"曲","lines":["画檐铁马喧，纱窗梦不成，佳人才子何时娉？他是个异乡背井飘零客，我便是孤枕独眠董秀英。","都薄幸，一个在东墙下烦恼，一个在锦帐里伤情。"],"source":"元曲"},{"title":"我将","author":"佚名","dynasty":"先秦","form":"诗","lines":["我将我享，维羊维牛，维天其右之。仪式刑文王之典，日靖四方。","伊嘏文王，既右飨之。我其夙夜，畏天之威，于时保之。"],"source":"《诗经》"},{"title":"谷口书斎寄杨补阙","author":"銭起","dynasty":"唐","form":"诗","lines":["泉壑帯茅茨，云霞生薜帷。","竹怜新雨后，山爱夕阳时。","闲鹭栖常早，秋花落更遅。","家童扫萝迳，昨与故人期。"],"source":"《唐诗三百首》"},{"title":"次温伯用林公正刘庆充倡和韵","author":"范成大","dynasty":"宋","form":"诗","lines":["前山后山梅子雨，屯云日夜相吞吐。","长林绝壑望不到，时有樵帰说逢虎。","奔渓朝来忽怒涨，夹岸柳梢余尺许。","屋头未放浓岚散，苦忆清风泛琼宇。","客行落此乱山中，但欲寻人诉羁旅。","比邻邂逅得清士，眉宇津津佳笑语。","杯行起舞出新句，我気已衰聊复鼓。","明年与君杭太湖，扁舟踏浪不踏土。","沉沉玉柱閟仙扃，矫矫虹梁浮水府。","目力无穷天不尽，却笑向来谁缚汝。"],"source":"宋诗"},{"title":"甘露歌","author":"王安石","dynasty":"宋","form":"词","lines":["天寒日暮山谷里。","的砾愁成水。","池上渐多枝上稀。","唯有故人知。"],"source":"宋词"},{"title":"董秀英花月东墙记・三煞","author":"白朴","dynasty":"元","form":"曲","lines":["叹鸳鸯绣被空，满怀愁为那生，只因他新诗和的声相应。","更把那瑶琴拨出艰难调，彩凤求凰指下鸣。","都是相思令，听了他凄凉惨切，好教我寸歩难行。"],"source":"元曲"},{"title":"时迈","author":"佚名","dynasty":"先秦","form":"诗","lines":["时迈其邦，昊天其子之，实右序有周。薄言震之，莫不震叠。怀柔百神，及河乔岳，允王维后。","明昭有周，式序在位。载戢干戈，载橐弓矢。我求懿徳，四于时夏，允王保之。"],"source":"《诗经》"},{"title":"送僧帰日本","author":"銭起","dynasty":"唐","form":"诗","lines":["上国随縁住，来途若梦行。","浮天沧海远，去世法舟軽。","水月通禅観，鱼竜聴梵声。","惟怜一灯影，万里眼中明。"],"source":"《唐诗三百首》"},{"title":"次韵温伯夜坐今日忽得舎弟到杭消息喜见于词","author":"范成大","dynasty":"宋","form":"诗","lines":["长风吹月来，影砕竹间牖。","良宵坐窘束，媿我尘外友。","平生烟霞兴，硉兀上南斗。","颇亦契三三，未省计九九。","迷涂入簿领，郷心几回首。","嗟予季行役，舟払涨渓柳。","凌晨双鹊鸣，玩占得无咎。","何当従汝去，履綦寻蕙亩。"],"source":"宋诗"},{"title":"菩萨蛮","author":"王安石","dynasty":"宋","form":"词","lines":["数家茅屋闲临水。","单衫短帽垂杨里。","今日是何朝。","看予度石桥。","梢梢新月偃。","午酔醒来晩。","何物最关情。","黄鹂三两声。"],"source":"宋词"},{"title":"董秀英花月东墙记・二煞","author":"白朴","dynasty":"元","form":"曲","lines":["婚姻配偶迟，难挨更漏永，画蛾眉懒去临妆镜。","老天不管人憔翠，一派黄河九遍清。","贞烈性，也只是粉墙一堵，似隔着百座连城。"],"source":"元曲"},{"title":"执竞","author":"佚名","dynasty":"先秦","form":"诗","lines":["执竞武王，无竞维烈。不显成康，上帝是皇。自彼成康，奄有四方，斤斤其明。","钟鼓喤喤，磬莞将将，降福穣穣。降福简简，威仪反反。既酔既饱，福禄来反。"],"source":"《诗经》"},{"title":"赠阙下裴舎人","author":"銭起","dynasty":"唐","form":"诗","lines":["二月黄莺飞上林，春城紫禁暁阴阴。","长楽钟声花外尽，竜池柳色雨中深。","阳和不散穷途恨，霄汉长懐捧日新。","献赋十年犹未遇，羞将白髪対华簪。"],"source":"《唐诗三百首》"},{"title":"再次韵呈宗伟温伯","author":"范成大","dynasty":"宋","form":"诗","lines":["官居数椽间，局促如瓮牖。","幸邻诗酒社，金薤対玉友。","真清廊庙器，伟望配山斗。","行当侍紫极，槐棘位三九。","馆舎有奇士，高文粲参首。","倡酬猥及我，双松圧孤柳。","生活従冷淡，幸免誉与咎。","相従结此夏，何异帰陇亩。"],"source":"宋诗"},{"title":"渔家傲","author":"王安石","dynasty":"宋","form":"词","lines":["灯火已収正月半。","山南山北花撩乱。","闻说洊亭新水漫。","骑款段。","穿云入坞寻游伴。","却払僧床褰素幔。","千岩万壑春风暖。","一弄松声悲急管。","吹梦断。","西看窗日犹嫌短。"],"source":"宋词"},{"title":"董秀英花月东墙记・尾煞","author":"白朴","dynasty":"元","form":"曲","lines":["相思愁越添，凄凉恶梦境。","便做道铁石般只恁心肠硬，都写入愁怀唤不省。","(下)。"],"source":"元曲"},{"title":"思文","author":"佚名","dynasty":"先秦","form":"诗","lines":["思文后稷，克配彼天。立我烝民，莫菲尔极。贻我来牟，帝命率育，无此疆尔界。陈常于时夏。"],"source":"《诗经》"},{"title":"和张仆射塞下曲","author":"銭起","dynasty":"唐","form":"诗","lines":["月黒雁飞高，単于夜遁逃。","欲将軽骑逐，大雪満弓刀。"],"source":"《唐诗三百首》"},{"title":"次韵温伯纳凉","author":"范成大","dynasty":"宋","form":"诗","lines":["日斜犹畏暑，吏退合偷闲。","霞散红绡薄，渓回碧玉弯。","伴人惟羽扇，娱客欠风鬟。","且复哦新句，相嘲饭颗山。"],"source":"宋诗"},{"title":"渔家傲","author":"王安石","dynasty":"宋","form":"词","lines":["平岸小桥千嶂抱。","柔蓝一水萦花草。","茅屋数间窗窈窕。","尘不到。","时时自有春风扫。","午枕觉来闻语鸟。","敧眠似听朝鸡早。","忽忆故人今总老。","贪梦好。","茫然忘了邯郸道。"],"source":"宋词"},{"title":"董秀英花月东墙记・中吕/粉蝶儿","author":"白朴","dynasty":"元","form":"曲","lines":["睡眼难开，锁愁眉如何担待？恨相思昼夜难挨。","则俺这异乡人，如风絮，飘零在外。","愁满心怀，何时得否极生泰？。"],"source":"元曲"},{"title":"臣工","author":"佚名","dynasty":"先秦","form":"诗","lines":["嗟嗟臣工，敬尔在公。王厘尔成，来咨来茹。嗟嗟保介，维莫之春，亦又何求？如何新畲？","于皇来牟，将受厥明。明昭上帝，迄用康年。命我众人：庤乃钱镈，奄观铚艾。"],"source":"《诗经》"},{"title":"贼退示官吏","author":"元结","dynasty":"唐","form":"诗","lines":["昔歳逢太平，山林二十年。","泉源在庭戸，洞壑当门前。","井税有常期，日[晏]犹得眠。","忽然遭世変，数歳亲戎旃。","今来典斯郡，山夷又纷然。","城小贼不屠，人贫伤可怜。","是以陥隣境，此州独见全。","使臣将王命，岂不如贼焉。","今彼徴敛者，迫之如火煎。","谁能绝人命，以作时世贤。","思欲委符节，引竿自刺船。","将家就鱼麦，帰老江湖辺。"],"source":"《唐诗三百首》"},{"title":"雨凉二首呈宗伟  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["谁扶病客起竜钟，恩在盆倾一雨中。","问讯九関何路到，拟牋歓喜谢天公。"],"source":"宋诗"},{"title":"雨霖铃","author":"王安石","dynasty":"宋","form":"词","lines":["孜孜矻矻。","向无明里、强作窠窟。","浮名浮利何济，堪留恋处，轮回仓猝。","幸有明空妙觉，可弹指超出。","缘底事、抛了全潮，认一浮沤作瀛渤。","本源自性天真仏。","祗些些、妄想中埋没。","贪他眼花阳艳，谁信道、本来无物。","一旦茫然，终被阎罗老子相屈。","便纵有、千种机筹，怎免伊唐突。"],"source":"宋词"},{"title":"董秀英花月东墙记・酔春风","author":"白朴","dynasty":"元","form":"曲","lines":["只因遇着可憎才，引的我熬煎深似海。","害的我须臾咫尺难移挨，你好是歹，歹！一会家倒枕捶床，长吁短叹，教咱无奈。"],"source":"元曲"},{"title":"噫嘻","author":"佚名","dynasty":"先秦","form":"诗","lines":["噫嘻成王，既昭仮尔。率时农夫，播厥百谷。骏发尔私，终三十里。亦服尔耕，十千维耦。"],"source":"《诗经》"},{"title":"石鱼湖上酔歌","author":"元结","dynasty":"唐","form":"诗","lines":["石鱼湖，似洞庭，夏水欲満君山青。","山为樽，水为沼，酒徒歴歴坐洲岛。","长风连日作大浪，不能廃人运酒舫。","我持长瓢坐巴丘，酌饮四坐以散愁。"],"source":"《唐诗三百首》"},{"title":"雨凉二首呈宗伟  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["惊雷隠地送凉飔，起舞看山不自持。","说与騒人须早计，片云催雨雨催诗。"],"source":"宋诗"},{"title":"清平乐","author":"王安石","dynasty":"宋","form":"词","lines":["云垂平野。","掩映竹篱茅舎。","阒寂幽居实潇洒。","是处绿娇红冶。","丈夫运用堂堂。","且莫五角六张。","若有一卮芳酒，逍遥自在无妨。"],"source":"宋词"},{"title":"董秀英花月东墙记・脱布衫","author":"白朴","dynasty":"元","form":"曲","lines":["病潘安痩损形骸，杜韦娘憔悴香腮。","你两个恩情似海，没来由把咱禁害。"],"source":"元曲"},{"title":"振鹭","author":"佚名","dynasty":"先秦","form":"诗","lines":["振鹭于飞，于彼西雍。我客戻止，亦有斯容。在彼无恶，在此无斁。庶几夙夜，以永终誉。"],"source":"《诗经》"},{"title":"枫桥夜泊","author":"张継","dynasty":"唐","form":"诗","lines":["月落乌啼霜満天，江枫渔父対愁眠。","姑苏城外寒山寺，夜半钟声到客船。"],"source":"《唐诗三百首》"},{"title":"明日复雨凉再用韵二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["东山朝日澹冥蒙，一片云生万畳中。","宿雨未苏焦巻尽，又烦箕井唤雷公。"],"source":"宋诗"},{"title":"浣渓沙","author":"王安石","dynasty":"宋","form":"词","lines":["百亩中庭半是苔。","门前白道水萦回。","爱闲能有几人来。","小院回廊春寂寂，山桃渓杏两三栽。","为谁零落为谁开。"],"source":"宋词"},{"title":"董秀英花月东墙记・小梁州","author":"白朴","dynasty":"元","form":"曲","lines":["你只要搂带同心结不开，都只待鱼水和谐。","旷夫怨女命安排，心无奈，盼杀楚阳台。"],"source":"元曲"},{"title":"丰年","author":"佚名","dynasty":"先秦","form":"诗","lines":["丰年多黍多稌，亦有高廪，万亿及秭。为酒为醴，烝畀祖妣。以洽百礼，降福孔皆。"],"source":"《诗经》"},{"title":"酬程延秋夜即事见赠","author":"韩翃","dynasty":"唐","form":"诗","lines":["长簟迎风早，空城澹月华。","星河秋一雁，砧杵夜千家。","节候看応晩，心期卧亦赊。","向来吟秀句，不覚已鸣鸦。"],"source":"《唐诗三百首》"},{"title":"明日复雨凉再用韵二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["溅瓦排檐散万糸，颠狂风筿要扶持。","恩深到骨吾能报，急赋新凉第一诗。"],"source":"宋诗"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["常时黄色见眉间。","松桂我同攀。","毎言天上辛苦，不肯饵金丹。","怜水静，爱云闲。","便忘还。","高歌一曲，岩谷迤逦，宛似商山。"],"source":"宋词"},{"title":"董秀英花月东墙记・幺篇","author":"白朴","dynasty":"元","form":"曲","lines":["这便是才郎有意佳人爱，两下里怎不伤怀？好意挨，舒心害，粉墙为界，镜破两分钗。","(云)早来到也，我隔这窗儿试瞧咱。","(唱)。"],"source":"元曲"},{"title":"有瞽","author":"佚名","dynasty":"先秦","form":"诗","lines":["有瞽有瞽，在周之庭。设业设虡，崇牙树羽。应田县鼓，鞉磬柷圉。既备","乃奏，箫管备举。喤喤厥声，肃雍和鸣，先祖是听。我客戻止，永观厥成。"],"source":"《诗经》"},{"title":"同题仙游観","author":"韩翃","dynasty":"唐","form":"诗","lines":["仙台下见五城楼，风物凄凄宿雨収。","山色遥连秦树晩，砧声近报汉宫秋。","疏松影落空坛静，细草香闲小洞幽。","何用别寻方外去，人间亦自有丹丘。"],"source":"《唐诗三百首》"},{"title":"次韵庆充避暑水西寺","author":"范成大","dynasty":"宋","form":"诗","lines":["佳晨出西郭，仰视天宇清。","楽哉旷士懐，浩浩吞四溟。","新涨忽勇退，篱落粘枯萍。","风幡招客游，旷望隔苹汀。","仆夫厉清深，竹舆竦亭亭。","波翻石凿落，尚带蛟竜腥。","华堂入松竹，徳人占聚星。","脱帽飞羽觞，颓放解天刑。","时当行火令，草腐亦化蛍。","炎官纷陆梁，空飞赤云𫐌。","遥知陇上耘，暴背愁白丁。","兹游岂易得，未用叹沉冥。"],"source":"宋诗"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["练巾藜杖白云间。","有兴即跻攀。","追思往昔如梦，华毂也曽丹。","尘自扰，性长闲。","更无还。","达如周召，穷似丘轲，祗个山山。"],"source":"宋词"},{"title":"董秀英花月东墙记・上小楼","author":"白朴","dynasty":"元","form":"曲","lines":["我把这窗儿润开，觑一觑何妨何碍。","只见他东倒西歪，倚床靠枕，身体斜挨。","叫一声马秀才，头不擡，相思苦害，问你个病襄王在也不在。","(梅见科，云)先生万福。","(生起，跪科，云)呀、呀、呀！小娘子，怎生就不来了？(梅云)夫人严谨，仆妾岂敢轻出？(生云)小娘子，今日小姐有何话说？(梅云)俺姐姐写了一简，教我送来，不知上面写着甚幺。","(生云)将来我看。","(做接科)(梅唱)。"],"source":"元曲"},{"title":"潜","author":"佚名","dynasty":"先秦","form":"诗","lines":["猗与漆沮，潜有多鱼。有鳣有鲔，鲦鲿𫚢鲤。以享以祀，以介景福。"],"source":"《诗经》"},{"title":"寒食","author":"韩翃","dynasty":"唐","form":"诗","lines":["春城无処不飞花，寒食东风御柳斜。","日暮汉宫伝蝋烛，軽烟散入五侯家。"],"source":"《唐诗三百首》"},{"title":"送滕子昭绩渓罢帰","author":"范成大","dynasty":"宋","form":"诗","lines":["天马西极来，目力尽九寰。","执辔者谁欤，堕此空谷间。","草深石啮足，一跃度孱颜。","长风送逸驾，荡荡登虎関。","五云清都上，白日开帝闲。","钩陈动光彩，球琳锵辔环。","亦复念旧群，依然叹驽顽。","红尘起天末，可望不可攀。"],"source":"宋诗"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["茫然不肯住林间。","有处即追攀。","将他死语图度，怎得离真丹。","浆水价，匹如闲。","也须还。","何如直截，踢倒军持，赢取沩山。"],"source":"宋词"},{"title":"董秀英花月东墙记・幺篇","author":"白朴","dynasty":"元","form":"曲","lines":["俺小姐亲封一策，向你这东君叩拝。","不知他有甚衷肠，道甚言词，诉甚情杯。","试取开，看内才，中间梗概，比那吓蛮书赛也不赛。"],"source":"元曲"},{"title":"雝","author":"佚名","dynasty":"先秦","form":"诗","lines":["有来雝雝，至止肃肃。相维辟公，天子穆穆。于荐广牡，相予四祀。仮哉皇考！绥予孝子。","宣哲维人，文武维后。燕及皇天，克昌厥后。绥我眉寿，介以繁祉，既右烈考，亦右文母。"],"source":"《诗经》"},{"title":"寄李儋元锡","author":"韦応物","dynasty":"唐","form":"诗","lines":["去年花里逢君别，今日花开已一年。","世事茫茫难自料，春愁黯黯独成眠。","身多疾病思田里，邑有流亡愧俸銭。","闻道欲来相问讯，西楼望月几廻円。"],"source":"《唐诗三百首》"},{"title":"次韵温伯谋帰","author":"范成大","dynasty":"宋","form":"诗","lines":["官路駆驰易折肱，官曹随処是愁城。","随风片叶郷心动，过雨千峰病眼明。","一脔何须尝世味，寸田久已廃吾耕。","羡君早作帰欤计，屈指従今几合并。"],"source":"宋诗"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["营巣燕子逞翱翔。","微志在雕梁。","碧云举翮千里，其奈有鸾皇。","临济处，徳山行。","果承当。","自时降住，一切天魔，扫地焚香。"],"source":"宋词"},{"title":"董秀英花月东墙记・贺圣朝","author":"白朴","dynasty":"元","form":"曲","lines":["似这般子建才学，埋没书斋，愁肠一似东洋海。","生的相貌堂堂，见了开怀。","心中自猜，怎生教他昼去昏来？。"],"source":"元曲"},{"title":"载见","author":"佚名","dynasty":"先秦","form":"诗","lines":["载见辟王，曰求厥章。龙旗阳阳，和铃央央。鞗革有鸧，休有烈光。率见昭考，以孝以享。","以介眉寿，永言保之，思皇多祜。烈文辟公，绥以多福，俾缉熙于纯嘏。"],"source":"《诗经》"},{"title":"寄全椒山中道士","author":"韦応物","dynasty":"唐","form":"诗","lines":["今朝郡斎冷，忽念山中客。","涧底束荆薪，帰来煮白石。","欲持一瓢酒，远慰风雨夕。","落叶満空山，何処寻行迹。"],"source":"《唐诗三百首》"},{"title":"次韵温伯雨凉感懐","author":"范成大","dynasty":"宋","form":"诗","lines":["穷士病且饥，古今同一流。","身安腹果然，此外吾何求。","判司诚卑官，未免尘甑忧。","穷山更瘅暑，惫卧不挙头。","二物交寇我，生世真如浮。","晨朝墨云作，疾雷破山丘。","排檐忽飞溜，蛙蝈鸣相酬。","朱冠领热属，横溃输一筹。","新凉苏肺気，踏湿登城楼。","好邀云雨仙，长袖按梁州。","吹水添瓶罍，浄洗千斛愁。","何従有此段，冰庁冷如秋。","但覚诗思生，爽気入银钩。","章成竟何用，知能救穷不。","汤子亦旅食，回望家还羞。","倡予敢不和，共作商声讴。"],"source":"宋诗"},{"title":"诉衷情","author":"王安石","dynasty":"宋","form":"词","lines":["莫言普化祗颠狂。","真解作津梁。","蓦然打个筋斗，直跳过羲皇。","临济处，徳山行。","果承当。","将他创建，认作心诚，也是寻香。"],"source":"宋词"},{"title":"董秀英花月东墙记・满庭芳","author":"白朴","dynasty":"元","form":"曲","lines":["姻缘合该，今朝相待，鱼水和谐。","似这等不枉了教人害，苦尽甘来。","古人言知过必改，不由人兜在心怀。","一见了相亲爱，便休道贤贤易色，非是我放在狂乖。","(下)。"],"source":"元曲"},{"title":"有客","author":"佚名","dynasty":"先秦","form":"诗","lines":["有客有客，亦白其马。有萋有且，敦琢其旅。有客宿宿，有客信信。","言授之絷，以絷其马。薄言追之，左右绥之。既有淫威，降福孔夷。"],"source":"《诗经》"},{"title":"秋夜寄丘二十二员外","author":"韦応物","dynasty":"唐","form":"诗","lines":["懐君属秋夜，散歩咏凉天。","山空松子落，幽人応未眠。"],"source":"《唐诗三百首》"},{"title":"次韵子文雨后思帰","author":"范成大","dynasty":"宋","form":"诗","lines":["断云将雨洗松篁，昨夜痴竜起蛰蔵。","人自无情孤楽事，天犹有意作新凉。","尊前不见凌波袜，楼下空闻拝月香。","万事安能尽如愿，且来相伴圧糟床。"],"source":"宋诗"},{"title":"南乡子","author":"王安石","dynasty":"宋","form":"词","lines":["嗟见世间人。","但有纤毫即是尘。","不住旧时无相貌，沈沦。","祗为从来认识神。","作么有疏亲。","我自降魔转法轮。","不是摄心除妄想，求真。","幻化空身即法身。"],"source":"宋词"},{"title":"董秀英花月东墙记・耍孩儿","author":"白朴","dynasty":"元","form":"曲","lines":["看了你桃腮杏脸花无寒，星眼朦胧不开。","魂灵儿飞在五云端，只将这玉体相挨。","安排定共宿鸳鸯枕，准备下双飞鸾凤台。","今日得同欢爱，把湘裙皱损，宝髻斜歪。"],"source":"元曲"},{"title":"武","author":"佚名","dynasty":"先秦","form":"诗","lines":["于皇武王！无竞维烈。允文文王，克开厥后。嗣武受之，胜殷遏刘，耆定尔功。"],"source":"《诗经》"},{"title":"赋得暮雨送李胄","author":"韦応物","dynasty":"唐","form":"诗","lines":["楚江微雨里，建业暮钟时。","漠漠帆来重，冥冥鸟去遅。","海门深不见，浦树远含滋。","相送情无限，沾襟比散糸。"],"source":"《唐诗三百首》"},{"title":"次韵温伯苦蚊","author":"范成大","dynasty":"宋","form":"诗","lines":["白鸟営営夜苦饥，不堪薫燎出窗扉。","小虫与我同忧患，口腹駆来敢倦飞。"],"source":"宋诗"},{"title":"南乡子","author":"王安石","dynasty":"宋","form":"词","lines":["自古帝王州。","郁郁葱葱佳气浮。","四百年来成一梦，堪愁。","晋代衣冠成古丘。","绕水恣行游。","上尽层城更上楼。","往事悠悠君莫问，回头。","槛外长江空自流。"],"source":"宋词"},{"title":"董秀英花月东墙记・五煞","author":"白朴","dynasty":"元","form":"曲","lines":["衫儿扭扣松，裙儿搂带解，酥胸粉腕天然态。","楚腰似柳娇尤软，未吐桃花露润开。","完成了恩和爱，今日个良姻匹配，便死呵一穴同埋。"],"source":"元曲"},{"title":"闵予小子","author":"佚名","dynasty":"先秦","form":"诗","lines":["闵予小子，遭家不造，嬛嬛在疚。于乎皇考，永世克孝。","念兹皇祖，陟降庭止。维予小子，夙夜敬止。于乎皇王，继序思不忘。"],"source":"《诗经》"},{"title":"送杨氏女","author":"韦応物","dynasty":"唐","form":"诗","lines":["永日方戚戚，出门复悠悠。","女子今有行，大江溯軽舟。","尔辈况无恃，抚念益慈柔。","幼为长所育，両别泣不休。","対此结中肠，义往难复留。","自小阙内训，事姑贻我忧。","頼兹托令门，仁恤庶无尤。","贫倹诚所尚，资従岂待周。","孝恭遵妇道，容止顺其猷。","别离在今晨，见尔当何秋。","居闲始自遣，临感忽难収。","帰来视幼女，零涙縁缨流。"],"source":"《唐诗三百首》"},{"title":"庆充自黄山帰索其道中诗书一绝问之","author":"范成大","dynasty":"宋","form":"诗","lines":["鸣驺如电马如雷，知是婆娑酔尉回。","常日锦囊犹有句，况従三十六峰来。"],"source":"宋诗"},{"title":"浪淘沙令","author":"王安石","dynasty":"宋","form":"词","lines":["伊吕两衰翁。","历遍穷通。","一为钓叟一耕佣。","若使当时身不遇，老了英雄。","汤武偶相逢。","风虎云龙。","兴王祗在笑谈中。","直至如今千载后，谁与争功。"],"source":"宋词"},{"title":"董秀英花月东墙记・三煞","author":"白朴","dynasty":"元","form":"曲","lines":["娇羞力不加，低垂颈怕擡，风流彻骨遗香在。","相偎玉体轻轻按，粉汗溶溶湿杏腮。","似这等偷香窃玉，几时得一发明白。"],"source":"元曲"},{"title":"访落","author":"佚名","dynasty":"先秦","form":"诗","lines":["访予落止，率时昭考。于乎悠哉，朕未有艾。将予就之，继犹判涣。","维予小子，未堪家多难。绍庭上下，陟降厥家。休矣皇考，以保明其身。"],"source":"《诗经》"},{"title":"长安遇冯着","author":"韦応物","dynasty":"唐","form":"诗","lines":["客従东方来，衣上灞陵雨。","问客何为来，采山因买斧。","冥冥花正开，飏飏燕新乳。","昨别今已春，鬓糸生几缕。"],"source":"《唐诗三百首》"},{"title":"暁出古城山","author":"范成大","dynasty":"宋","form":"诗","lines":["落月堕眇莽，残星澹微茫。","竹舆乱清渓，飞盖入岚光。","松桧雾霭湿，桑麻风露香。","空翠滴尘缨，何必濯沧浪。","山家亦早作，迨此朝気凉。","林深无人声，木末炊烟苍。","离离瓜芋区，粛粛枣栗场。","田园古云楽，令我思故郷。","墟市稍来集，筠笼転山忙。","吏事亦挽我，帰路盘朝阳。"],"source":"宋诗"},{"title":"望江南・忆江南","author":"王安石","dynasty":"宋","form":"词","lines":["归依众，梵行四威仪。","愿我遍游诸仏土。","十方贤圣不相离。","永灭世间痴。"],"source":"宋词"},{"title":"董秀英花月东墙记・二煞","author":"白朴","dynasty":"元","form":"曲","lines":["澄澄夜气清，低低月转阶，枝枝花影横窗外。","灯前试把香罗看，点点猩红映莹白。","则见他羞无奈，困腾腾倚墙靠壁，急忙忙重整金钗。"],"source":"元曲"},{"title":"敬之","author":"佚名","dynasty":"先秦","form":"诗","lines":["敬之敬之，天维显思，命不易哉。无曰高高在上，陟降厥士，日监在兹。","维予小子，不聪敬止。日就月将，学有缉熙于光明。仏时仔肩，示我显徳行。"],"source":"《诗经》"},{"title":"夕次盱眙県","author":"韦応物","dynasty":"唐","form":"诗","lines":["落帆逗淮镇，停舫临孤駅。","浩浩风起波，冥冥日沈夕。","人帰山郭暗，雁下芦洲白。","独夜忆秦関，聴钟未眠客。"],"source":"《唐诗三百首》"},{"title":"李深之西尉同年谈呉兴风物再用古城韵","author":"范成大","dynasty":"宋","form":"诗","lines":["李侯昔游呉，莲舟镜苍茫。","风鬟与雾鬓，共濯玻瓈光。","采花不盈舫，日暮云水香。","还登缥缈楼，罗襟酒淋浪。","巻箔纳星月，踏筵按伊梁。","安知有恨事，但恐蒹葭苍。","风吹落穷谷，草深麋鹿场。","高冈苦炎热，游子悲异郷。","尚喜简书省，期会无匆忙。","犹余作诗苦，消痩如东阳。"],"source":"宋诗"},{"title":"望江南・忆江南","author":"王安石","dynasty":"宋","form":"词","lines":["归依法，法法不思议。","愿我六根常寂静，心如宝月映琉璃。","了法更无疑。"],"source":"宋词"},{"title":"董秀英花月东墙记・尾煞","author":"白朴","dynasty":"元","form":"曲","lines":["相思一笔勾，姻缘前世该。","好教人撇不下恩和爱，几时得再把同心带儿解。"],"source":"元曲"},{"title":"小毖","author":"佚名","dynasty":"先秦","form":"诗","lines":["予其惩，而毖后患。莫予荓蜂，自求辛螫。肇允彼桃虫，拚飞维鸟。未堪家多难，予又集于蓼。"],"source":"《诗经》"},{"title":"东郊","author":"韦応物","dynasty":"唐","form":"诗","lines":["吏舎跼终年，出郊旷清曙。","杨柳散和风，青山澹吾虑。","依丛适自憩，縁涧还复去。","微雨霭芳原，春鸠鸣何処？楽幽心屡止，遵事迹犹遽。","终罢斯结庐，慕陶真可庶。"],"source":"《唐诗三百首》"},{"title":"七月五日夜雨快晴","author":"范成大","dynasty":"宋","form":"诗","lines":["豊隆坎坎夜伐鼓，霊湫老竜撇波舞。","褰云掣电上清空，倒卷天潢作飞雨。","向来炎官作夏旱，万里彤霞烘玉宇。","岂惟牛马困蚊蝱，垅上行人口生土。","我従雪浪叶舟来，不谓山城热如许。","天公知我愁欲病，施与一凉苏逆旅。","稍闻水绕屋除鸣，不覚星従云罅吐。","千山濯濯浄鬟髻，欠月娟娟炯眉妩。","浮生此景万事足，但欠清歌対芳醑。","天上秋期正多事，趣驾星桥跨银渚。","人间四者自难并，莫妒黄姑迎织女。"],"source":"宋诗"},{"title":"望江南・忆江南","author":"王安石","dynasty":"宋","form":"词","lines":["归依仏，弹指越三祗。","愿我速登无上觉，还如仏坐道场时。","能智又能悲。"],"source":"宋词"},{"title":"董秀英花月东墙记・越调/斗鹌鹑","author":"白朴","dynasty":"元","form":"曲","lines":["眼见的枕剰衾空，怎挨这更长漏永？桃蕊飘霞，杨花弄风。","翠袖生寒，乌云不拢。","恰成了鸾凤交，眼见的各西东。","离恨千般，闲愁万种。"],"source":"元曲"},{"title":"载芟","author":"佚名","dynasty":"先秦","form":"诗","lines":["载芟载柞，其耕泽泽。千耦其耘，徂隰徂畛。侯主侯伯，侯亚侯旅，侯彊侯以。","有嗿其馌，思媚其妇，有依其士。有略其耜，俶载南亩，播厥百谷。实函斯活，驿驿其达。","有厌其杰，厌厌其苗，绵绵其麃。载获济济，有实其积，万亿及秭。为酒为醴，烝畀祖妣，不洽百礼。","有𫗣其香。邦家之光。有椒其馨，胡考之宁。匪且有且，匪今斯今，振古如兹。"],"source":"《诗经》"},{"title":"滁州西涧","author":"韦応物","dynasty":"唐","form":"诗","lines":["独怜幽草涧辺生，上有黄鹂深树鸣。","春潮帯雨晩来急，野渡无人舟自横。"],"source":"《唐诗三百首》"},{"title":"次韵宗伟温伯","author":"范成大","dynasty":"宋","form":"诗","lines":["冉冉流光迫歳余，青林日夜向人疏。","雨滋巌桂重堆粟，风折庭蕉又献书。","逋客解兰思婉娩，先生弾铗厌清虚。","一尘不立浑输我，即境心安是故庐。"],"source":"宋诗"},{"title":"望江南・忆江南","author":"王安石","dynasty":"宋","form":"词","lines":["三界里，有取总灾危。","普愿众生同我愿，能于空有善思惟。","三宝共住持。"],"source":"宋词"},{"title":"董秀英花月东墙记・紫花儿序","author":"白朴","dynasty":"元","form":"曲","lines":["见如今亭前分袂，目下离别，多应是梦里相逢。","忍不住长吁短叹，难割舎意重情浓。","枉教我埋怨天公，莫不是美满姻缘不得终！好教人伤悲切痛，霎时间去马回车，都做了往雁归鸿。","(云)自从文辅去后，今经半载有余，杳无音信，教我身心不安。","好是烦恼人也！(唱)。"],"source":"元曲"},{"title":"良耜","author":"佚名","dynasty":"先秦","form":"诗","lines":["畟畟良耜，俶载南亩。播厥百谷，实函斯活。或来瞻女，载筐及莒，其𫗵伊黍。","其笠伊纠，其镈斯赵，以薅荼蓼。荼蓼朽止，黍稷茂止。获之挃挃，积之栗栗。","其崇如墉，其比如栉。以开百室，百室盈止，妇子宁止。杀时犉牡，有捄其角。以似以续，续古之人。"],"source":"《诗经》"},{"title":"和晋陵陆丞早春游望","author":"韦応物","dynasty":"唐","form":"诗","lines":["独有宦游人，偏惊物候新。","云霞出海曙，梅柳渡江春。","淑気催黄鸟，晴光照绿苹。","忽闻歌苦调，帰思欲沾巾。"],"source":"《唐诗三百首》"},{"title":"再韵答子文","author":"范成大","dynasty":"宋","form":"诗","lines":["浮生饱外莫求余，羁旅东来计已疏。","肩耸已高犹索句，眼明无用且繙书。","百年子莫占元绪，万法吾今付子虚。","惟有登临心未厌，黄山闻道胜衡庐。"],"source":"宋诗"},{"title":"西江月","author":"王安石","dynasty":"宋","form":"词","lines":["梅好惟嫌淡伫，天教薄与胭脂。","真妃初出华清池。","酒入琼姬半酔。","东阁诗情易动，高楼玉管休吹。","北人浑作杏花疑。","惟有青枝不似。"],"source":"宋词"},{"title":"董秀英花月东墙记・小桃红","author":"白朴","dynasty":"元","form":"曲","lines":["腰肢纤细减芳容，似带雨梨花重。","翠被香消谁共，思无穷，音书写下无人送。","鱼沉雁杳，枕剰衾空，因此上泪滴满酥胸。"],"source":"元曲"},{"title":"丝衣","author":"佚名","dynasty":"先秦","form":"诗","lines":["丝衣其紑，载弁俅俅。自堂徂基，自羊徂牛，鼐鼎及鼒，兕觥其觩。旨酒思柔。不吴不敖，胡考之休。"],"source":"《诗经》"},{"title":"与高适薛拠慈恩寺浮図","author":"岑参","dynasty":"唐","form":"诗","lines":["塔势如涌出，孤高耸天宫。","登临出世界，磴道盘虚空。","突兀圧神州，峥嵘如鬼工。","四角碍白日，七层摩苍穹。","下窥指高鸟，俯聴闻惊风。","连山若波涛，奔凑似朝东。","青槐夹驰道，宫馆何玲珑。","秋色従西来，苍然満関中。","五陵北原上，万古青蒙蒙。","浄理了可悟，胜因夙所宗。","誓将挂冠去，覚道资无穷。"],"source":"《唐诗三百首》"},{"title":"道见蓼花","author":"范成大","dynasty":"宋","form":"诗","lines":["秋风袅袅露华鲜，去歳如今刺钓船。","歙県门西见红蓼，此身曽在白鴎前。"],"source":"宋诗"},{"title":"渔家傲","author":"王安石","dynasty":"宋","form":"词","lines":["隔岸桃花红未半。","枝头已有蜂儿乱。","惆怅武陵人不管。","清梦断。","亭亭伫立春宵短。"],"source":"宋词"},{"title":"董秀英花月东墙记・天净纱","author":"白朴","dynasty":"元","form":"曲","lines":["害的人病厌厌痩了形容，宽绰绰带慢衣松，俏身儿往日难同。","越添悲痛，倚帏屏星眼朦胧。"],"source":"元曲"},{"title":"酌","author":"佚名","dynasty":"先秦","form":"诗","lines":["于铄王师，遵养时晦。时纯熙矣，是用大介。我龙受之，𫏋𫏋王之造。载用有嗣，实维尔公允师。"],"source":"《诗经》"},{"title":"白雪歌送武判官帰京","author":"岑参","dynasty":"唐","form":"诗","lines":["北风卷地白草折，胡天八月即飞雪。","忽然一夜春风来，千树万树梨花开。","散入珠帘湿罗幕，狐裘不煖锦衾薄。","将军角弓不得控，都护鉄衣冷难着。","瀚海阑干百丈冰，愁云黪淡万里凝。","中军置酒饮帰客，胡琴琵琶与羌笛。","纷纷暮雪下辕门，风掣红旗冻不翻。","轮台东门送君去，去时雪満天山路。","山回路転不见君，雪上空留马行処。"],"source":"《唐诗三百首》"},{"title":"次韵温伯种兰","author":"范成大","dynasty":"宋","form":"诗","lines":["霊均堕荒寒，采采纫兰手。","九畹不留客，高丘一回首。","峥嵘路孔棘，凄怆肘生柳。","遂令此粲者，永与穷愁友。","不如汤子远，情事只诗酒。","但知爱国香，此外付乌有。","栽培带苔藓，披払护尘垢。","孤芳亦有遇，洒濯居座右。","君看深林下，埋没随藜莠。"],"source":"宋诗"},{"title":"清平乐","author":"王安石","dynasty":"宋","form":"词","lines":["留春不住。","费尽莺儿语。","满地残红宫锦汚。","昨夜南园风雨。","小怜初上琵琶。","晓来思绕天涯。","不肯画堂朱户，春风自在杨花。"],"source":"宋词"},{"title":"董秀英花月东墙记・调笑令","author":"白朴","dynasty":"元","form":"曲","lines":["好教我气冲，怨天公，闪的我独宿孤眠锦帐中。","珠帘不巻金钩控，怕的是南楼上画鼓冬冬。","我这里好梦初成，又成墙东，怎生般梦中鱼水也难同。"],"source":"元曲"},{"title":"桓","author":"佚名","dynasty":"先秦","form":"诗","lines":["绥万邦，屡丰年。天命匪解，桓桓武王。保有厥士，于以四方，克定厥家。于昭于天，皇以间之。"],"source":"《诗经》"},{"title":"轮台歌奉送封大夫出师西征","author":"岑参","dynasty":"唐","form":"诗","lines":["轮台城头夜吹角，轮台城北旄头落。","羽书昨夜过渠黎，単于已在金山西。","戍楼西望烟尘黒，汉兵屯在轮台北。","上将拥旄西出征，平明吹笛大军行。","四辺伐鼓雪海涌，三军大呼阴山动。","虏塞兵気连云屯，戦场白骨缠草根。","劒河风急雪片阔，沙口石冻马蹄脱。","亜相勤王甘苦辛，誓将报主静辺尘。","古来青史谁不见，今见功名胜古人。"],"source":"《唐诗三百首》"},{"title":"次韵子文","author":"范成大","dynasty":"宋","form":"诗","lines":["幻尘久已破狐涎，身世谁能料鼠肝。","暮夜雨収千嶂出，晨朝风巻四维寛。","我今无事不如梦，君岂有心犹觅安。","但促小槽添圧石，竜头珠滴夜珊珊。"],"source":"宋诗"},{"title":"生查子","author":"王安石","dynasty":"宋","form":"词","lines":["雨打江南树。","一夜花开无数。","绿叶渐成阴，下有游人归路。","与君相逢处。","不道春将暮。","把酒祝东风，且莫恁、匆匆去。"],"source":"宋词"},{"title":"董秀英花月东墙记・秃厮儿","author":"白朴","dynasty":"元","form":"曲","lines":["恨人，画檐间铁马丁东；恨人，寒山野寺鸣钟。","恨人，把美爱幽欢好梦惊；恨人，又见花梢儿窗影下重重。"],"source":"元曲"},{"title":"赉","author":"佚名","dynasty":"先秦","form":"诗","lines":["文王既勤止，我应受之。敷时绎思，我徂维求定。时周之命，于绎思。"],"source":"《诗经》"},{"title":"走马川行奉送出师西征","author":"岑参","dynasty":"唐","form":"诗","lines":["君不见走马川行雪海辺，平沙莽莽黄入天。","轮台九月风夜吼，一川砕石大如斗，随风満地石乱走。","匈奴草黄马正肥，金山西见烟尘飞。","汉家大将西出师，将军金甲夜不脱。","半夜军行戈相拨，风头如刀面如割。","马毛帯雪汗気蒸，五花连銭旋作冰。","幕中草檄砚水凝，虏骑闻之応胆慑。","料知短兵不敢接，车师西门伫献捷。"],"source":"《唐诗三百首》"},{"title":"次韵知郡安抚九日南楼宴集三首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["双旌暮卷小舂容，画栋云生笑语中。","但覚山光侵酒绿，不知日脚染渓红。","控临缥缈疑无地，指点虚无欲驭风。","谁遣玉蟾催骑吹，帰来人影在朦胧。"],"source":"宋诗"},{"title":"谒金门","author":"王安石","dynasty":"宋","form":"词","lines":["春又老。","南陌酒香梅小。","遍地落花浑不扫。","梦回情意悄。","红笺寄与添烦恼。","细写相思多少。","酔后几行书字小。","泪痕都揾了。"],"source":"宋词"},{"title":"董秀英花月东墙记・圣药王","author":"白朴","dynasty":"元","form":"曲","lines":["想旧境，一梦中，海棠亭下正欢浓。","宝髻松，绣被重，觉来犹在画屏东，无语泪溶溶。"],"source":"元曲"},{"title":"般","author":"佚名","dynasty":"先秦","form":"诗","lines":["于皇时周！陟其高山，嶞山乔岳，允犹翕河。敷天之下，裒时之对。时周之命。"],"source":"《诗经》"},{"title":"寄左省杜拾遗","author":"岑参","dynasty":"唐","form":"诗","lines":["连歩趋丹陛，分曹限紫微。","暁随天仗入，暮惹御香帰。","白髪悲花落，青云羡鸟飞。","圣朝无阙事，自覚谏书稀。"],"source":"《唐诗三百首》"},{"title":"次韵知郡安抚九日南楼宴集三首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["珠履参陪北海觞，仍邀拥节旧中郎。","碧城香雾连天暝，黄叶霜风卷地凉。","佳节転头论聚散，清波従古阅兴亡。","明年重把茱萸酔，公在丛霄贡玉堂。"],"source":"宋诗"},{"title":"菩萨蛮","author":"王安石","dynasty":"宋","form":"词","lines":["海棠乱发皆临水。","君知此处花何似。","凉月白纷纷。","香风隔岸闻。","啭枝黄鸟近。","隔岸声相应。","随意坐莓苔。","飘零酒一杯。"],"source":"宋词"},{"title":"董秀英花月东墙记・麻郎儿","author":"白朴","dynasty":"元","form":"曲","lines":["恨相思病浓，转思量泪重。","眉蹙损春山闷萦，显的凄凉一弄。"],"source":"元曲"},{"title":"𬳶","author":"佚名","dynasty":"先秦","form":"诗","lines":["𬳶𬳶牡马，在坰之野。薄言𬳶者，有驈有皇，有骊有黄，以车彭彭。思无疆思，马斯臧。","𬳶𬳶牡马，在坰之野。薄言𬳶者，有骓有𬳵，有骍有骐，以车伾伾。思无期思，马斯才。","𬳶𬳶牡马，在坰之野。溥言𬳶者，有驒有骆，有骝有雒，以车绎绎。思无斁思，马斯作。","𬳶𬳶牡马，在坰之野。薄言𬳶者，有骃有騢，有驔有鱼，以车祛祛。思无邪思，马斯徂。"],"source":"《诗经》"},{"title":"奉和中书舎人贾至早朝大明宫","author":"岑参","dynasty":"唐","form":"诗","lines":["鶏鸣紫陌曙光寒，莺啭皇州春色阑。","金阙暁钟开万戸，玉阶仙仗拥千官。","花迎劒珮星初落，柳払旌旗露未干。","独有凤皇池上客，阳春一曲和皆难。"],"source":"《唐诗三百首》"},{"title":"次韵知郡安抚九日南楼宴集三首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["斯民邹鲁更豊年，雅道凄凉见此贤。","万陇登禾新霁色，千村鸣柝旧寒烟。","锵金绝世诗情妙，倚剣凌空隶墨鲜。","珍重北窗山六六，使君名与汝俱伝。"],"source":"宋诗"},{"title":"千秋岁引","author":"王安石","dynasty":"宋","form":"词","lines":["别馆寒砧，孤城画角。","一派秋声入寥廓。","东归燕从海上去，南来雁向沙头落。","楚台风，庾楼月，宛如昨。","无奈被些名利缚。","无奈被他情担阁。","可惜风流总闲却。","当初漫留华表语，而今误我秦楼约。","梦阑时，酒醒后，思量着。"],"source":"宋词"},{"title":"董秀英花月东墙记・幺篇","author":"白朴","dynasty":"元","form":"曲","lines":["这病攻、泪浓、闷重，都只为满腹愁衷，都只为鱼水难同，都只为孤鸾寡凤。"],"source":"元曲"},{"title":"有駜","author":"佚名","dynasty":"先秦","form":"诗","lines":["有駜有駜，駜彼乗黄。夙夜在公，在公明明。振振鹭，鹭于下。鼓咽咽，酔言舞。于胥乐兮！","有駜有駜，駜彼乗牡。夙夜在公，在公饮酒。振振鹭，鹭于飞。鼓咽咽，酔言归。于胥乐兮！","有駜有駜，駜彼乗駽。夙夜在公，在公载燕。自今以始，岁其有。君子有谷，诒孙子。于胥乐兮！"],"source":"《诗经》"},{"title":"逢入京使","author":"岑参","dynasty":"唐","form":"诗","lines":["故园东望路漫漫，双袖竜钟涙不干。","马上相逢无纸笔，凭君伝语报平安。"],"source":"《唐诗三百首》"},{"title":"晩集南楼","author":"范成大","dynasty":"宋","form":"诗","lines":["浪随児女怨萍蓬，笑拍阑干万事空。","宇宙勲名无骨相，江山得句有神功。","掉头莫觑秋高鹗，留眼来宾日暮鸿。","懒拙已成三昧解，此生还证一円通。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["斗草阶前初见，穿针楼上曽逢。","罗裙香露玉钗风。","靓妆眉沁绿，羞脸粉生红。","流水便随春远，行云终与谁同。","酒醒长恨锦屏空。","相寻梦里路，飞雨落花中。"],"source":"宋词"},{"title":"董秀英花月东墙记・络丝娘","author":"白朴","dynasty":"元","form":"曲","lines":["粉花笺写下更长漏永，专诉着痩减香肌玉容。","写罢了眉尖一纵，更教人悲痛。","(云)自马生去后，教我朝思暮想，疾病转加，如之奈何！梅香，你来。","(梅云)姐姐，怎幺说？(旦云)我这几天身子不快，我待请医调理，你请母亲来商量。","(梅云)老夫人，有请。","(卜上，云)有甚事？(旦云)平亲，你孩儿身体不快，如何治之？(卜云)孩儿，快请个良医来，服些药饵就好了。","梅香，你快请去。","(梅背云)除是马秀才来，我就好了。","(做请科，云)李郎中，在家不在家？(净上，云)小子李郎中是也。","别无买卖营生，专靠我这药上盘费。","我这妙用，有神仙之法，手到病除。","家传一样妙药，专治男女伤春之病。","恰才董府尹家来请，须索走一遭去。","(行科，见梅科，云)小娘子，报复去。","(梅报云)奶奶，请将医士来了。","(卜云)请进来。","(见科，卜云)小女有些不快，特请先生调治。","(净云)请出来诊脉。","(旦出见科)(诊脉科，净云)此脉沉细。","(卜云)如何调治？(净云)小人专治伤春之病，岂可无药？不瞒老夫人说，我这药费本钱。","(卜云)老身怎肯少了药资。","(净云)我便攒药。","(旦云)此药何名？(净云)不当受，小人回去也。","(下)(卜云)梅香，你教孩儿睡一会儿，我回去。","(下)(梅云)姐姐，服了此药就好。","(旦唱)。"],"source":"元曲"},{"title":"泮水","author":"佚名","dynasty":"先秦","form":"诗","lines":["思乐泮水，薄采其芹。鲁侯戻止，言观其旗。其旗茷茷，鸾声哕哕。无小无大，从公于迈。","思乐泮水，薄采其藻。鲁侯戻止，其马𫏋𫏋。其马𫏋𫏋，其音昭昭。载色载笑，匪怒伊教。","思乐泮水，薄采其茆。鲁侯戻止，在泮饮酒。既饮旨酒，永锡难老。顺彼长道，屈此群丑。","穆穆鲁侯，敬明其徳。敬慎威仪，维民之则。允文允武，昭仮烈祖。靡有不孝，自求伊祜。","明明鲁侯，克明其徳。既作泮宫，淮夷攸服。矫矫虎臣，在泮献馘。淑问如皐陶，在泮献囚。","济济多士，克广徳心。桓桓于征，狄彼东南。烝烝皇皇，不吴不扬。不告于讻，在泮献功。","角弓其觩。束矢其捜。戎车孔博。徒御无斁。既克淮夷，孔淑不逆。式固尔犹，淮夷卒获。","翩彼飞鸮，集于泮林。食我桑黮，怀我好音。憬彼淮夷，来献其琛。元龟象齿，大赂南金。"],"source":"《诗经》"},{"title":"访羊尊师","author":"孙革","dynasty":"唐","form":"诗","lines":["松下问童子，言师采薬去。","只在此山中，云深不知処。"],"source":"《唐诗三百首》"},{"title":"赏雪骑鲸轩子文夜帰酒渇侍児荐茗饮蜜浆明日以诧同游戯为书事邀宗伟同作","author":"范成大","dynasty":"宋","form":"诗","lines":["渓山四时佳，今日更奇绝。","天公妙荘厳，施此一川雪。","飞花浩如海，眩転塞空阔。","水西万珠树，玉塔照银阙。","碧渓不受冻，长滩泻清咽。","渔舟晩犹泛，樵檐寒未歇。","悬知画不到，未省诗能说。","帰来强捜句，冰砚冷于鉄。","不知厳夫子，迎门生暖热。","梅香不可耐，但覚酒肠㷎。","密融花気动，茶泛乳膏発。","宁辞春笋寒，为暖花瓷滑。","瞢腾画屏暖，唤起眼余缬。","笑我独何事，作此淡生活。","想像高唐赋，何如径排闼。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["身外闲愁空满，眼中欢事常稀。","明年应赋送君诗。","细从今夜数，相会几多时。","浅酒欲邀谁劝，深情惟有君知。","东渓春近好同归。","柳垂江上影，梅谢雪中枝。"],"source":"宋词"},{"title":"董秀英花月东墙记・东原乐","author":"白朴","dynasty":"元","form":"曲","lines":["这厮是哄人机见，他说来的不通，越教人添沉重。","他一片胡言都是空，无些儿効功，他正是说真方把咱做弄。"],"source":"元曲"},{"title":"閟宫","author":"佚名","dynasty":"先秦","form":"诗","lines":["閟宫有侐，实实枚枚。赫赫姜嫄，其徳不回。上帝是依，无灾无害。","弥月不迟，是生后稷。降之百福。黍稷重穋，稙稚菽麦。奄有下国，俾民稼穑。","有稷有黍，有稲有秬。奄有下土，缵禹之绪。后稷之孙，实维大王。","居岐之阳，实始剪商。至于文武，缵大王之绪，致天之届，于牧之野。","无二无虞，上帝临女。敦商之旅，克咸厥功。王曰叔父，建尔元子，俾侯于鲁。","大启尔宇，为周室辅。乃命鲁公，俾侯于东。锡之山川，土田附庸。","周公之孙，庄公之子。龙旗承祀。六辔耳耳。春秋匪解，享祀不忒。","皇皇后帝！皇祖后稷！享以骍牺，是飨是宜。降福既多，周公皇祖，亦其福女。","秋而载尝，夏而楅衡，白牡骍刚。牺尊将将，毛炰胾羹。笾豆大房，万舞洋洋。","孝孙有庆。俾尔炽而昌，俾尔寿而臧。保彼东方，鲁邦是尝。不亏不崩，不震不腾。","三寿作朋，如冈如陵。公车千乗，朱英绿縢。二矛重弓。公徒三万，贝胄朱綅。","烝徒増増，戎狄是膺，荆舒是惩，则莫我敢承！俾尔昌而炽，俾尔寿而富。","黄发台背，寿胥与试。俾尔昌而大，俾尔耆而艾。万有千岁，眉寿无有害。","泰山岩岩，鲁邦所詹。奄有龟蒙，遂荒大东。至于海邦，淮夷来同。","莫不率从，鲁侯之功。保有凫绎，遂荒徐宅。至于海邦，淮夷蛮貊。","及彼南夷，莫不率从。莫敢不诺，鲁侯是若。天锡公纯嘏，眉寿保鲁。","居常与许，复周公之宇。鲁侯燕喜，令妻寿母。宜大夫庶士，邦国是有。","既多受祉，黄发儿齿。徂徕之松，新甫之柏。是断是度，是寻是尺。","松桷有舄，路寝孔硕，新庙奕奕。奚斯所作，孔曼且硕，万民是若。"],"source":"《诗经》"},{"title":"书辺事","author":"张乔","dynasty":"唐","form":"诗","lines":["调角断清秋，征人倚戍楼。","春风対青冢，白日落梁州。","大汉无兵阻，穷辺有客游。","蕃情似此水，长愿向南流。"],"source":"《唐诗三百首》"},{"title":"従圣集乞黄巌鱼鲊","author":"范成大","dynasty":"宋","form":"诗","lines":["截玉凝膏腻白，点酥粘粟軽红。","千里来従何処，想看舶浪帆风。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["淡水三年欢意，危弦几夜离情。","晓霜红叶舞归程。","客情今古道，秋梦短长亭。","渌酒尊前清泪，阳关叠里离声。","少陵诗思旧才名。","云鸿相约处，烟雾九重城。"],"source":"宋词"},{"title":"董秀英花月东墙记・绵打絮","author":"白朴","dynasty":"元","form":"曲","lines":["深闱静悄，幽僻庭空。","月轮展纸，几扇屏风。","似海棠半酔春睡重，鲛绡上绿鬓拥。","有情人何日相逢，几时得赴高唐梦中？。"],"source":"元曲"},{"title":"那","author":"佚名","dynasty":"先秦","form":"诗","lines":["猗与那与！置我鞉鼓。奏鼓简简，衎我烈祖。汤孙奏仮，绥我思成。","鞉鼓渊渊，嘒嘒管声。既和且平，依我磬声。于赫汤孙！穆穆厥声。","庸鼓有斁，万舞有奕。我有嘉客，亦不夷怿。自古在昔，先民有作。","温恭朝夕，执事有恪，顾予烝尝，汤孙之将。"],"source":"《诗经》"},{"title":"行路难三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["金樽清酒斗十千，玉盘珍羞直万銭。","停杯投筯不能食，抜劒四顾心茫然。","欲渡黄河冰塞川，将登太行雪満山。","闲来垂钓碧渓上，忽复乗舟梦日辺。","行路难，行路难，多岐路，今安在。","长风破浪会有时，直挂云帆済沧海。"],"source":"《唐诗三百首》"},{"title":"従宗伟乞冬笋山薬","author":"范成大","dynasty":"宋","form":"诗","lines":["竹坞拨沙犀顶锐，薬畦粘土玉肌豊。","裹芽束缊能分似，政及莱芜甑釜空。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["浅浅馀寒春半，雪消蕙草初长。","烟迷柳岸旧池塘。","风吹梅蕊闹，雨细杏花香。","月堕枝头欢意，从前虚梦高唐，觉来何处放思量。","如今不是梦，真个到伊行。"],"source":"宋词"},{"title":"董秀英花月东墙记・拙鲁速","author":"白朴","dynasty":"元","form":"曲","lines":["花落去绿丛丛，怎不教人泪盈盈？愁锁眉尖万种，清夜悠悠谁共？画檐下摇曳帘栊，不想把离人断送，鹧鸪啼惊觉巫山梦。"],"source":"元曲"},{"title":"烈祖","author":"佚名","dynasty":"先秦","form":"诗","lines":["嗟嗟烈祖！有秩斯祜。申锡无疆，及尔斯所。既载清酤，赉我思成。","亦有和羹，既戒既平。鬷仮无言，时靡有争。绥我眉寿，黄耇无疆。","约軧错衡，八鸾鸧鸧。以仮以享，我受命溥将。自天降康，丰年穣穣。","来仮来飨，降福无疆。顾予烝尝，汤孙之将。"],"source":"《诗经》"},{"title":"行路难三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["大道如青天，我独不得出。","羞逐长安社中児，赤鶏白狗赌梨栗。","弾劒作歌奏苦声，曳裾王门不称情。","淮阴市井笑韩信，汉朝公卿忌贾生。","君不见昔时燕家重郭隗，拥篲折节无嫌猜。","剧辛楽毅感恩分，输肝剖胆効英才。","昭王白骨萦烂草，谁人更扫黄金台。","行路难，帰去来。"],"source":"《唐诗三百首》"},{"title":"雪后守之家梅未开呈宗伟","author":"范成大","dynasty":"宋","form":"诗","lines":["瓦沟冻残雪，檐溜粘軽冰。","破寒一竿日，春随人意生。","瑞叶再三白，南枝尚含情。","定知司花女，未肯嫁娉婷。","官居苦无頼，一笑如河清。","落木露荒山，寒渓绕孤城。","朝暮何所见，云黄叫饥鹰。","东风不早计，愁眼何当明。","北邻小横斜，藓地可班荆。","凭君趣花信，把酒撼琼英。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["长爱碧阑干影，芙蓉秋水开时。","脸红凝露学娇啼。","霞觞熏冷艳，云髻袅纤枝。","烟雨依前时候，霜丛如旧芳菲。","与谁同酔采香归。","去年花下客，今似蝶分飞。"],"source":"宋词"},{"title":"董秀英花月东墙记・尾声","author":"白朴","dynasty":"元","form":"曲","lines":["鱼沉雁杳音难送，阻隔着千里关山万重。","埋怨俺狠毒娘，走将来分开了鸾凤种。","(下)。"],"source":"元曲"},{"title":"玄鸟","author":"佚名","dynasty":"先秦","form":"诗","lines":["天命玄鸟，降而生商，宅殷土芒芒。古帝命武汤，正域彼四方。","方命厥后，奄有九有。商之先后，受命不殆，在武丁孙子。武丁孙子，武王靡不胜。","龙旗十乗，大糦是承。邦畿千里，维民所止，肇域彼四海。","四海来仮，来仮祁祁。景员维河。殷受命咸宜，百禄是何。"],"source":"《诗经》"},{"title":"行路难三首 三","author":"李白","dynasty":"唐","form":"诗","lines":["有耳莫洗颍川水，有口莫食首阳蕨。","含光混世贵无名，何用孤高比云月。","吾観自古贤达人，功成不退皆殒身。","子胥既弃呉江上，屈原终投湘水浜。","陆机雄才岂自保，李斯税驾苦不早。","华亭鹤唳讵可闻，上蔡苍鹰何足道。","君不见呉中张翰称达生，秋风忽忆江东行。","且楽生前一杯酒，何须身后千载名。"],"source":"《唐诗三百首》"},{"title":"次韵温伯城上","author":"范成大","dynasty":"宋","form":"诗","lines":["闭戸成痴坐，扶藜得意行。","楼台浮霁色，市井砕春声。","雪尽小桥出，烟消千嶂生。","病多无脚力，遥羡落鸿軽。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["旖旎仙花解语，轻盈春柳能眠。","玉楼深处绮窗前。","梦回芳草夜，歌罢落梅天。","沈水浓熏绣被，流霞浅酌金船。","绿娇红小正堪怜。","莫如云易散，须似月频圆。"],"source":"宋词"},{"title":"董秀英花月东墙记・双调/新水令","author":"白朴","dynasty":"元","form":"曲","lines":["春雷掲地震青天，平歩上广寒宫殿。","风吹乌帽整，日照锦袍鲜。","拝宴开筵，这其间方称了丈夫愿。"],"source":"元曲"},{"title":"长发","author":"佚名","dynasty":"先秦","form":"诗","lines":["浚哲维商，长发其祥。洪水芒芒，禹敷下土方。外大国是疆，幅陨既长。有娀方将，帝立子生商。","玄王桓拨，受小国是达，受大国是达。率履不越，遂视既发。相士烈烈。海外有截。","帝命不违，至于汤齐。汤降不迟，圣敬日跻。昭仮迟迟，上帝是祗，帝命式于九围。","受小球大球，为下国缀旒，何天之休。不竞不絿，不刚不柔。敷政优优。百禄是遒。","受小共大共，为下国骏厖。何天之龙，敷奏其勇。不震不动，不戁不竦，百禄是总。","武王载旆，有虔秉钺。如火烈烈，则莫我敢曷。苞有三蘖，莫遂莫达。九有有截，韦顾既伐，昆吾夏桀。","昔在中叶，有震且业。允也天子，降予卿士。实维阿衡，实左右商王。"],"source":"《诗经》"},{"title":"长相思","author":"李白","dynasty":"唐","form":"诗","lines":["长相思，在长安，络纬秋啼金井阑。","微霜凄凄簟色寒，孤灯不明思欲绝。","巻帷望月空长叹，美人如花隔云端。","上有青冥之长天，下有渌水之波澜。","天长路远魂飞苦，梦魂不到関山难。","长相思，摧心肝。"],"source":"《唐诗三百首》"},{"title":"知郡安抚以立春日掲所书新安郡榜南楼之上暁雪纷集邦人以为善祥遂开宴以落之辄赋长句一篇以附风谣之末","author":"范成大","dynasty":"宋","form":"诗","lines":["碧瓦朱甍上牛斗，妙墨新题森锁钮。","使君笔力挽春来，一夜飞花暗梅柳。","南山与楼相対高，向来千载争雄豪。","八分三字一弾圧，众峰戢戢如児曹。","人间盛事天不隔，急催此雪成三白。","未论千古福邦人，先卜明年満冈麦。","东风酒面吹凝酥，不辞酔倒帰相扶。","短歌万一伝楽府，湛辈亦与公名俱。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["梦后楼台高锁，酒醒帘幕低垂。","去年春恨却来时。","落花人独立，微雨燕双飞。","记得小苹初见，两重心字罗衣。","琵琶弦上说相思。","当时明月在，曽照彩云归。"],"source":"宋词"},{"title":"董秀英花月东墙记・驻马听","author":"白朴","dynasty":"元","form":"曲","lines":["十载心坚，酬志了金屋银屏紫府仙。","当时贫贱，怎忘了箪瓢陋巷在穷檐。","官高犹记武陵源，身荣怎忘前亲眷。","才中选，今朝又把程途践。","(云)行了数日，早到松江府了。","趱动马，径奔宅上去者。","(做到科，云)左右，报的老夫人知道。","(做报科)(夫人上，云)马文辅得了头名状元，今日回来，我须迎他进来者。","(生做见科)(卜云)儿鞍马劳困。","梅香，叫你姐姐来见学士者。","(梅走上，云)姐姐在那里？(旦上，云)小贱人，你管我怎幺？(梅云)俺姐夫做了官回来，在堂上，老夫人着我请你相见哩。","(旦云)是真个？(梅云)你待不见哩。","(旦云)不想有今日也！(做相见叙礼科)(旦云)才郎及第，官拝何职？(生云)托祖宗福荫，叨中状元，小生喜不自胜。","(旦唱)。"],"source":"元曲"},{"title":"殷武","author":"佚名","dynasty":"先秦","form":"诗","lines":["挞彼殷武，奋伐荆楚。深入其阻，裒荆之旅。有截其所，汤孙之绪。","维女荆楚，居国南乡。昔有成汤，自彼氐羌，莫敢不来享，莫敢不来王。曰商是常。","天命多辟，设都于禹之绩。岁事来辟，勿予祸适，稼穑匪解。","天命降监，下民有严。不僭不滥，不敢怠遑。命于下国，封建厥福。","商邑翼翼，四方之极。赫赫厥声，濯濯厥灵。寿考且宁，以保我后生。","陟彼景山，松伯丸丸。是断是迁，方斫是虔。松桷有梴，旅楹有闲，寝成孔安。"],"source":"《诗经》"},{"title":"関山月","author":"李白","dynasty":"唐","form":"诗","lines":["明月出天山，苍茫云海间。","长风几万里，吹度玉门関。","汉下白登道，胡窥青海湾。","由来征戦地，不见有人还。","[戍]客望辺色，思帰多苦颜。","高楼当此夜，叹息未応闲。"],"source":"《唐诗三百首》"},{"title":"次韵知郡安抚元夕赏倅庁红梅三首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["春入林梢一再风，破寒匀染费天工。","虽然媚荡新妆别，只与横斜旧格同。","午枕乍醒铅粉退，暁奁初罢蝋脂融。","后来颜色休论似，夹路漫山取次红。"],"source":"宋诗"},{"title":"临江仙","author":"晏几道","dynasty":"宋","form":"词","lines":["东野亡来无丽句，于君去后少交亲。","追思往事好沾巾。","白头王建在，犹见咏诗人。","学道深山空自老，留名千载不干身。","酒筵歌席莫辞频。","争如南陌上，占取一年春。"],"source":"宋词"},{"title":"董秀英花月东墙记・雁儿落","author":"白朴","dynasty":"元","form":"曲","lines":["谁想你入科场艺在先，金榜上名堪羡。","脱却了旧布衣，直走上金銮殿。"],"source":"元曲"},{"title":"玉阶怨","author":"李白","dynasty":"唐","form":"诗","lines":["玉阶生白露，夜久侵罗袜。","却下水晶帘，玲珑望秋月。"],"source":"《唐诗三百首》"},{"title":"次韵知郡安抚元夕赏倅庁红梅三首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["真色生香绝世逢，烟光池面両溶溶。","楚邻不待施朱好，虢国翻嫌傅粉浓。","晴日暧云春照耀，温风霁月夜舂容。","酒阑且驻纱笼看，慢破団団一壁竜。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["巻絮风头寒欲尽。","坠粉飘红，日日香成阵。","新酒又添残酒困。","今春不减前春恨。","蝶去莺飞无处问。","隔水高楼，望断双鱼信。","恼乱层波横一寸。","斜阳只与黄昏近。"],"source":"宋词"},{"title":"董秀英花月东墙记・得胜令","author":"白朴","dynasty":"元","form":"曲","lines":["你如今束带立朝前，得志受皇宣。","列翰苑为学士，挿金花饮玉筵。","标写在凌烟，宝匣内方显出龙泉剑。","享富贵绵绵，立芳名见大贤。","(生云)小生别后一载有余，多亏小姐持家养徳。","(旦唱)。"],"source":"元曲"},{"title":"清平调词三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["云想衣裳花想容，春风払槛露华浓。","若非群玉山头见，会向瑶台月下逢。"],"source":"《唐诗三百首》"},{"title":"次韵知郡安抚元夕赏倅庁红梅三首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["司花一笑为谁开，知道朱幡得得来。","疏影有情当洞戸，蔫香无语堕空杯。","风生翰墨留连看，月入笙歌次第催。","来歳如今翻旧唱，五云丛里望三台。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["初拈霜纨生怅望。","隔叶莺声，似学秦娥唱。","午睡醒来慵一饷。","双纹翠簟铺寒浪。","雨罢苹风吹碧涨。","脉脉荷花，泪脸红相向。","斜贴绿云新月上。","弯环正是愁眉样。"],"source":"宋词"},{"title":"董秀英花月东墙记・水仙子","author":"白朴","dynasty":"元","form":"曲","lines":["今朝一日笑声喧，又得才郎叙旧缘，相逢诉不尽心中怨。","那时节意惨然，自别来动是经年。","我只怕恩情断，盼归期天样远，谁知道今日团圆。"],"source":"元曲"},{"title":"清平调词三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["一枝秾艳露凝香，云雨巫山枉断肠。","借问汉宫谁得似，可怜飞燕倚新妆。"],"source":"《唐诗三百首》"},{"title":"新安绝少红梅惟倅庁特盛通判朝议召幕僚赏之坐皆有诗亦赋古风一首","author":"范成大","dynasty":"宋","form":"诗","lines":["华灯収尽江梅落，别有横枝照林薄。","天教阆苑染芳根，小住山城慰萧索。","腾腾酔后酒红醺，淡淡妆成笑靥新。","斟酌东君已倾倒，为渠都费十分春。","别乗胸懐有风月，催唤清尊洗愁绝。","花知主客得不凡，一夜光风融绛雪。","楼头烟暝吹単于，花梢挂星光有无。","帰来境熟落春梦，梦入锁香红绮疏。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["庭院碧苔红叶遍。","金菊开时，已近重阳宴。","日日露荷凋绿扇。","粉塘烟水澄如练。","试倚凉风醒酒面。","雁字来时，恰向层楼见。","几点护霜云影转。","谁家芦管吹秋怨。"],"source":"宋词"},{"title":"董秀英花月东墙记・折桂令","author":"白朴","dynasty":"元","form":"曲","lines":["喜今朝又得团圆，夫妇相逢，前世姻缘。","携手相将，花前月下，笑语甜言。","旧日的恩情不浅，还记得海棠亭誓对婵娟。","你如今黄榜名悬，翰苑超迁，愿足平生，尽在神天。"],"source":"元曲"},{"title":"静夜思","author":"李白","dynasty":"唐","form":"诗","lines":["床前看月光，疑是地上霜。","挙头望山月，低头思故郷。"],"source":"《唐诗三百首》"},{"title":"胡宗伟罢官改秩挙将不及格往谒金陵丹阳诸使者遂朝行在颇有倦游之叹作诗送之","author":"范成大","dynasty":"宋","form":"诗","lines":["冻云埋山天冥蒙，北风无情雪塞空。","道傍人稀鸟飞绝，问君东游何怱怱。","君言薄官淡无味，免俗未能聊复尔。","我评兹事一鸿毛，因行且看佳山水。","陵阳楼阁圧高城，烟屏百畳双流横。","姑孰江亭更奇绝，浓黛両抹长眉青。","山形成竜复成虎，六代遗踪供吊古。","大荒莽苍江水黄，両涘风烟眇呉楚。","却浮一苇下长川，浮玉低昂波聒天。","梁渓南岸小停橹，一酌人间第二泉。","阊门峨峨过吾国，姑苏临波照金碧。","太湖三万六千顷，上有垂虹跨南极。","我家越相尚神游，试従烟浪访扁舟。","问讯白鴎相记否，谓言久客不胜愁。","软红三尺长安道，九重城阙乾坤绕。","西湖山寺浙江楼，君昔曽游今更好。","故人客馆中天开，非君谁上黄金台。","挽着天衢五云上，却望江湖如梦回。","万境何如一丘壑，几时定解冠裳缚。","幔亭山下桂丛深，清社向来都寂莫。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["喜鹊桥成催凤驾。","天为欢迟，乞与初凉夜。","乞巧双蛾加意画。","玉钩斜傍西南挂。","分钿擘钗凉叶下。","香袖凭肩，谁记当时话。","路隔银河犹可借。","世间离恨何年罢。"],"source":"宋词"},{"title":"董秀英花月东墙记・沽美酒","author":"白朴","dynasty":"元","form":"曲","lines":["降明香，接诏宣，拝天使，喜开颜。","圣主恩波遍九天，坐金銮宝殿，四海内都朝见。"],"source":"元曲"},{"title":"春思","author":"李白","dynasty":"唐","form":"诗","lines":["燕草如碧糸，秦桑低绿枝。","当君懐帰日，是妾断肠时。","春风不相识，何事入罗帏。"],"source":"《唐诗三百首》"},{"title":"黄伯益官舎赏梅","author":"范成大","dynasty":"宋","form":"诗","lines":["一杯何処洗愁颜，黄法曹家玉树寒。","翠袖撚香留客看，春风都在小阑干。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["碧草池塘春又晩。","小叶风娇，尚学娥妆浅。","双燕来时还念远。","珠帘绣户杨花满。","绿柱频移弦易断。","细看秦筝，正似人情短。","一曲啼乌心绪乱。","红颜暗与流年换。"],"source":"宋词"},{"title":"董秀英花月东墙记・太平令","author":"白朴","dynasty":"元","form":"曲","lines":["托皇朝文能武羡，养徳性道重名传。","姓列在金章宝篆，普天下黎民方便。","只愿的万千，永远，保天恩圣贤，端的是威镇了四方八面。","(生云)使臣，请筵宴。","(使臣云)不必了，就此告回。","(下)(生上，云)贤妻，如今有圣旨，教即便赴京上任，你心下如何？(旦云)妾身岂敢抗拒？(生云)既如此，弓兵快収拾车马，赴任去来。","(唱)。"],"source":"元曲"},{"title":"子夜呉歌 春歌","author":"李白","dynasty":"唐","form":"诗","lines":["秦地罗敷女，采桑绿水辺。","素手青条上，红妆白日鲜。","蚕饥妾欲去，五马莫留连。"],"source":"《唐诗三百首》"},{"title":"次韵朱厳州従李徽州乞牡丹三首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["佳人绝世堕空谷，破恨解颜春亦来。","莫対渓山话京洛，碧云西北涨黄埃。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["碾玉钗头双凤小。","倒晕工夫，画得宫眉巧。","嫩曲罗裙胜碧草。","鸳鸯绣字春衫好。","三月露桃芳意早。","细看花枝，人面争多少。","水调声长歌未了。","掌中杯尽东池晓。"],"source":"宋词"},{"title":"董秀英花月东墙记・川拨棹","author":"白朴","dynasty":"元","form":"曲","lines":["列头搭在马前，把香车帘半巻。","只见官诰新鲜，翠袖花钿，宝髻云偏，疑是天仙。","只见他喜孜孜俏脸儿笑拈，敢见我紫罗袍体间穿。"],"source":"元曲"},{"title":"子夜呉歌 夏歌","author":"李白","dynasty":"唐","form":"诗","lines":["镜湖三百里，菡萏発荷花。","五月西施采，人看隘若耶。","回舟不待月，帰去越王家。"],"source":"《唐诗三百首》"},{"title":"次韵朱厳州従李徽州乞牡丹三首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["歙浦烟山蟠万畳，钓台云日拥千章。","両侯好事洗寒劣，宝槛移春入燕香。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["酔别西楼醒不记。","春梦秋云，聚散真容易。","斜月半窗还少睡。","画屏闲展吴山翠。","衣上酒痕诗里字。","点点行行，总是凄凉意。","红烛自怜无好计。","夜寒空替人垂泪。"],"source":"宋词"},{"title":"董秀英花月东墙记・七弟兄","author":"白朴","dynasty":"元","form":"曲","lines":["我这里向前，谢得完全，今日个夫妻称了平生愿。","身荣休忘了海棠轩，东墙下私约成姻眷。"],"source":"元曲"},{"title":"子夜呉歌 秋歌","author":"李白","dynasty":"唐","form":"诗","lines":["长安一片月，万戸捣衣声。","秋风吹不尽，総是玉関情。","何日平胡虏，良人罢远征。"],"source":"《唐诗三百首》"},{"title":"次韵朱厳州従李徽州乞牡丹三首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["阆风苑里司花女，肯作山腰水尾来。","十二玉栏天一笑，只今帰路五云开。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["欲减罗衣寒未去。","不巻珠帘，人在深深处。","残杏枝头花几许。","啼红正恨清明雨。","尽日沈香烟一缕。","宿酒醒迟，恼破春情绪。","远信还因归燕误。","小屏风上西江路。"],"source":"宋词"},{"title":"董秀英花月东墙记・梅花酒","author":"白朴","dynasty":"元","form":"曲","lines":["俺如今践登程，路途沿，几时到八水三川，西洛中原。","莫得俄延，摔砕丝鞭。","马蹄儿践香尘，钿车儿古道穿。","今日个，来赴选；来赴选，到金銮；到金銮，日月边；日月边，受皇宣；受皇宣，古今传。"],"source":"元曲"},{"title":"子夜呉歌 冬歌","author":"李白","dynasty":"唐","form":"诗","lines":["明朝駅使発，一夜絮征袍。","素手抽针冷，那堪把剪刀。","裁缝寄远道，几日到临洮。"],"source":"《唐诗三百首》"},{"title":"送琴客许扬帰永嘉","author":"范成大","dynasty":"宋","form":"诗","lines":["乌帽休冲九陌埃，痩藤定约到秋回。","竜湫鴈荡経行処，断取松风万壑来。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["千叶早梅夸百媚。","笑面凌寒，内样妆先试。","月脸冰肌香细腻。","风流新称东君意。","一捻年光春有味。","江北江南，更有谁相比。","横玉声中吹满地。","好枝长恨无人寄。"],"source":"宋词"},{"title":"董秀英花月东墙记・収江南","author":"白朴","dynasty":"元","form":"曲","lines":["想当初五言诗和得句儿联，七条弦弹就旧姻缘，想着那海棠亭下设盟言。","今日个两全，夫妻勅赐再团圆。"],"source":"元曲"},{"title":"赠孟浩然","author":"李白","dynasty":"唐","form":"诗","lines":["吾爱孟夫子，风流天下闻。","红颜弃轩冕，白首卧松云。","酔月频中圣，迷花不事君。","高山安可仰，徒此揖清芬。"],"source":"《唐诗三百首》"},{"title":"送李徽州赴湖北漕","author":"范成大","dynasty":"宋","form":"诗","lines":["徂徕千丈松，阅世耸绝壁。","高标上霄汉，峻节贯金石。","惟有孤生竹，亭亭附微植。","月夜借清景，春朝分秀色。","托根未渠央，万牛挽山沢。","昂蔵転江湖，夷路入王国。","明堂五云上，一柱屹天极。","可望不可攀，清都与尘隔。","依然此清士，空山淡愁閴。","悲吟発清籁，揺荡风雨夕。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["金翦刀头芳意动。","彩蕊开时，不怕朝寒重。","晴雪半消花䰒䰄。","晓妆呵尽香酥冻。","十二楼中双翠凤。","缥缈歌声，记得江南弄。","酔舞春风谁可共。","秦云已有鸳屏梦。"],"source":"宋词"},{"title":"董秀英花月东墙记・鸳鸯煞","author":"白朴","dynasty":"元","form":"曲","lines":["佳人才子心留恋，东墙花下成姻眷，标写青编，唱道一举登科将名姓显。","男儿得志共赏在琼林宴，玉堂中千古名贤。","似这等金榜题名万代显。"],"source":"元曲"},{"title":"庐山谣寄卢侍御虚舟","author":"李白","dynasty":"唐","form":"诗","lines":["我本楚狂人，凤歌笑孔丘。","手持绿玉杖，朝别黄鹤楼。","五岳寻仙不辞远，一生好入名山游。","庐山秀出南斗傍，屏风九畳云锦张，影落明湖青黛光。","金阙前开二峰长，银河倒挂三石梁。","香炉瀑布遥相望，回厓沓嶂凌苍苍。","翠影红霞映朝日，鸟飞不到呉天长。","登高壮観天地间，大江茫茫去不还。","黄云万里动风色，白波九道流雪山。","好为庐山谣，兴因庐山発。","闲窥石镜清我心，谢公行処苍苔没。","早服还丹无世情，琴心三畳道初成。","遥见仙人彩云里，手把芙蓉朝玉京。","先期汗漫九垓上，愿接卢敖游太清。"],"source":"《唐诗三百首》"},{"title":"送通守林彦强寺丞还朝","author":"范成大","dynasty":"宋","form":"诗","lines":["鴈荡之山天下无，奔岸绝壑不可図。","地霊境秀有人物，新安府丞今第一。","纷纶草木変暄寒，竹节松心故凛然。","穷山薄宦我无恨，识公大胜荆州韩。","梅风涨渓绿如酒，暁挿樯乌上南斗。","只今広厦论唐虞，斟酌正须医国手。","秀眉津津双颊丹，想看鸣佩翔九関。","诸公倘欲持公议，莫遣此贤思故山。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["笑艳秋莲生绿浦。","红脸青腰，旧识凌波女。","照影弄妆娇欲语。","西风岂是繁华主。","可恨良辰天不与。","才过斜阳，又是黄昏雨。","朝落暮开空自许。","竟无人解知心苦。"],"source":"宋词"},{"title":"山神庙裴度还带・仙吕/点绛唇","author":"关汉卿","dynasty":"元","form":"曲","lines":["我如今匣剑尘埋，壁琴土盖，三十载。","忧愁的髭鬓斑白，尚兀自还不彻他这穷途债。"],"source":"元曲"},{"title":"梦游天姥吟留别","author":"李白","dynasty":"唐","form":"诗","lines":["海客谈瀛洲，烟涛微茫信难求。","越人语天姥，云霓明灭或可覩。","天姥连天向天横，势抜五岳掩赤城。","天台四万八千丈，対此欲倒东南倾。","我欲因之梦呉越，一夜飞度镜湖月。","湖月照我影，送我至剡渓。","谢公宿処今尚在，渌水荡漾清猨啼。","脚着谢公屐，身登青云梯。","半壁见海日，空中闻天鶏。","千巌万転路不定，迷花倚石忽已暝。","熊咆竜吟殷巌泉，栗深林兮惊层巅。","云青青兮欲雨，水澹澹兮生烟。","列欠霹雳，丘峦崩摧。","洞天石扇，訇然中开。","青冥浩荡不见底，日月照耀金银台。","霓为衣兮风为马，云之君兮纷纷而来下。","虎鼓瑟兮鸾回车，仙之人兮列如麻。","忽魂悸以魄动，怳惊起而长嗟。","惟覚时之枕席，失向来之烟霞。","世间行楽亦如此，古来万事东流水。","别君去时何时还，且放白鹿青崖间，须行即骑访名山。","安能摧眉折腰事権贵？使我不得开心颜。"],"source":"《唐诗三百首》"},{"title":"送温伯帰福唐纳妇且约复游霅川","author":"范成大","dynasty":"宋","form":"诗","lines":["揽秀堂前一笑倾，都忘身世両浮萍。","扶藜処処従君赏，落笔时时得我惊。","茘熟闽山労梦想，苹香苕水约逢迎。","袛愁误入桃源后，従此车轮四角生。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["碧落秋风吹玉树。","翠节红旌，晩过银河路。","休笑星机停弄杼。","凤帏已在云深处。","楼上金针穿绣缕。","谁管天边，隔岁分飞苦。","试等夜阑寻别绪。","泪痕千点罗衣露。"],"source":"宋词"},{"title":"山神庙裴度还带・混江龙","author":"关汉卿","dynasty":"元","form":"曲","lines":["几时得否极生泰？看别人青云独歩立瑶阶，摆三千珠履，列十二金钗。","我不能勾丹凤楼前春中选，伴着这蒺藜沙上野花开。","则我这运不至，我也则索宁心儿耐。","久淹在桑枢瓮牖，几时能勾画阁楼台？。"],"source":"元曲"},{"title":"金陵酒肆留别","author":"李白","dynasty":"唐","form":"诗","lines":["风吹柳花満店香，呉姬圧酒唤客尝。","金陵子弟来相送，欲行不行各尽觞。","请君试问东流水，别意与之谁短长。"],"source":"《唐诗三百首》"},{"title":"次韵宗伟阅番楽","author":"范成大","dynasty":"宋","form":"诗","lines":["十日闲愁昼掩関，起寻一笑共清歓。","罢休诗社工夫淡，洗浄书生気味酸。","尽遣余銭付桑落，莫随短梦到槐安。","繍𫖇画鼓留花住，賸舞春风小契丹。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["碧玉高楼临水住。","红杏开时，花底曽相遇。","一曲阳春春已暮。","晓莺声断朝云去。","远水来从楼下路。","过尽流波，未得鱼中素。","月细风尖垂柳渡。","梦魂长在分襟处。"],"source":"宋词"},{"title":"山神庙裴度还带・油葫芦","author":"关汉卿","dynasty":"元","form":"曲","lines":["我则待安乐窝中且避乖，争奈我便时未来！想着这红尘万丈困贤才，那个似那鲁大夫亲赠他这千斛麦？那个似那庞居士可便肯放做来生债？自无了田孟尝，有谁人养剑客？待着我折腰屈脊的将诗卖，怕不待要寻故友、访吾侪。"],"source":"元曲"},{"title":"黄鹤楼送孟浩然之広陵","author":"李白","dynasty":"唐","form":"诗","lines":["故人西辞黄鹤楼，烟花三月下扬州。","孤帆远影碧山尽，唯见长江天际流。"],"source":"《唐诗三百首》"},{"title":"题漫斎壁","author":"范成大","dynasty":"宋","form":"诗","lines":["汉阴无械可容机，歳晩功名一衲衣。","槁木闲身随念懒，浮云幻事転头非。","三彭已罢庚申守，五鬼従教乙丑帰。","富贵神仙両俱累，此心安処是真依。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["梦入江南烟水路。","行尽江南，不与离人遇。","睡里消魂无说处。","觉来惆怅消魂误。","欲尽此情书尺素。","浮雁沈鱼，终了无凭据。","却倚缓弦歌别绪。","断肠移破秦筝柱。"],"source":"宋词"},{"title":"山神庙裴度还带・天下乐","author":"关汉卿","dynasty":"元","form":"曲","lines":["好教我\"十谒朱门九不开\"，我可便难也波禁，难禁那等朽木材：一个个铺眉苫眼妆些像态，他肚肠细，胸次狭，眼皮薄，局量窄。","（云）此等人本性难移，（唱）可不道他山河容易改？（正末云）可早来到也。","报复去，道有裴中立在门首。","（家童云）你则在这里，我报复去。","员外，有裴中立在门首。","（员外云）着他过来。","（家童云）理会的。","员外着你过去。","（正末见科，云）姨夫、姨娘请坐，受您侄儿几拝。","（旦儿云）裴度，想你父母身亡之后，你不成半器，不肯寻些买卖营生做，你毎日则是读书。","我想来：你那读书的穷酸饿醋有甚幺好处，几时能勾发迹也！（正末云）姨娘不知，圣人云：\"富家不用买良田，书中自有千钟粟。","\"小生我虽居贫贱，我身贫志不贫。","（员外云）大嫂，人说他胸次高傲，果然如此！我虽不通古今，你是读书人，你说那为人的道理，我试听咱。","（旦儿云）谁听你那\"之乎者也\"的！（正末唱）。"],"source":"元曲"},{"title":"渡荆门送别","author":"李白","dynasty":"唐","form":"诗","lines":["渡远荆门外，来従楚国游。","山随平野尽，江入大荒流。","月下飞天镜，云生结海楼。","仍连故郷水，万里送行舟。"],"source":"《唐诗三百首》"},{"title":"四月十六日拄笏亭偶题","author":"范成大","dynasty":"宋","form":"诗","lines":["転午闻鶏日正长，小亭方丈纳空光。","绿阴一雨浓如黛，何処风来百种香。"],"source":"宋诗"},{"title":"蝶恋花","author":"晏几道","dynasty":"宋","form":"词","lines":["黄菊开时伤聚散。","曽记花前，共说深深愿。","重见金英人未见。","相思一夜天涯远。","罗带同心闲结遍。","带易成双，人恨成双晩。","欲写彩笺书别怨。","泪痕早已先书满。"],"source":"宋词"},{"title":"山神庙裴度还带・那咤令","author":"关汉卿","dynasty":"元","form":"曲","lines":["正人伦，传道统，有尧之君大哉；理纲常，训典谟，是孔之贤圣哉；邦反坫，树塞门，敢管之器小哉。","整风俗遗后人，立洪范承先代，养情性抱徳怀才。"],"source":"元曲"},{"title":"送友人","author":"李白","dynasty":"唐","form":"诗","lines":["青山横北郭，白水遶东城。","此地一为别，孤蓬万里征。","浮云游子意，落日故人情。","挥手自兹去，萧萧班马鸣。"],"source":"《唐诗三百首》"},{"title":"次韵即席","author":"范成大","dynasty":"宋","form":"诗","lines":["留连银烛照金荷，肠断华年一掷梭。","月姊有情难独夜，天孙无頼早斜河。","晶晶霜瓦寒生粟，衮衮风帏细涌波。","鸹鹖暁啼鸣鹊散，许多佳景奈愁何。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["彩袖殷勤捧玉锺。","当年拼却酔颜红。","舞低杨柳楼心月，歌尽桃花扇影风。","从别后，忆相逢。","几回魂梦与君同。","今宵剰把银釭照，犹恐相逢是梦中。"],"source":"宋词"},{"title":"山神庙裴度还带・后庭花","author":"关汉卿","dynasty":"元","form":"曲","lines":["你教我休读书，做买卖；你着我去酸寒，可便有些气概。","你正是那得道夸经纪，我正是成人不自在。","（旦儿云）你穷则穷，则是胸次高傲。","(正末唱）我胸次巻江淮，志已在青霄云外。","叹穷途年少客，一时间命运乖！有一日显威风出浅埃，起云雷变气色。"],"source":"元曲"},{"title":"宣州谢朓楼饯别校书叔云","author":"李白","dynasty":"唐","form":"诗","lines":["弃我去者昨日之日不可留，乱我心者今日之日多烦忧。","长风万里送秋雁，対此可以酣高楼。","蓬莱文章建安骨，中间小谢又清発。","俱懐逸兴壮思飞，欲上青天覧日月。","抽刀断水水更流，挙杯销愁愁更愁。","人生在世不称意，明朝散髪弄扁舟。"],"source":"《唐诗三百首》"},{"title":"五月闻鶑二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["桑阴浄尽麦头斉，江上闻鶑毎歳遅。","不及暁风鹎𫛥子，迎春啼到送春时。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["一酔醒来春又残。","野棠梨雨泪阑干。","玉笙声里鸾空怨。","罗幕香中燕未还。","终易散，且长闲。","莫教离恨损朱颜。","谁堪共展鸳鸯锦，同过西楼此夜寒。"],"source":"宋词"},{"title":"山神庙裴度还带・青哥儿","author":"关汉卿","dynasty":"元","form":"曲","lines":["我稳情取登坛、登坛为帅，我扫妖氛息平蛮貊，你看我立国安邦为相宰。","那其间日转千阶，喜笑盈腮，挂印悬牌，坐金鼎莲花碧油幢，骨刺刺的绣旗开。","恁时节您看我敢青史内标名载！（旦儿云）我本待与你顿饭吃；你这等说大言，我也无那饭也无那钱钞与你，你出去！（正末云）小生但得片云遮顶，不在他人之下。","（旦儿云）看了你这般嘴脸，一世不能勾发迹，出去！（正末云）好无礼也！你数番教人来请我，来到这里，将这等言语轻慢小生！罢、罢、罢！我冻死饿死，再也不上你家门来！（唱）。"],"source":"元曲"},{"title":"下终南山过斛斯山人宿置酒","author":"李白","dynasty":"唐","form":"诗","lines":["暮従碧山下，山月随人帰。","却顾所来径，苍苍横翠微。","相携及田家，童稚开荆扉。","绿竹入幽径，青萝払行衣。","歓言得所憩，美酒聊共挥。","长歌吟松风，曲尽河星稀。","我酔君复楽，陶然共忘机。"],"source":"《唐诗三百首》"},{"title":"五月闻鶑二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["一声初上最高枝，忙杀呕唖百舌児。","老尽西园千树绿，却怜槐眼正迷离。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["梅蕊新妆桂叶眉。","小莲风韵出瑶池。","云随绿水歌声转，雪绕红绡舞袖垂。","伤别易，恨欢迟。","惜无红锦为裁诗。","行人莫便消魂去，汉渚星桥尚有期。"],"source":"宋词"},{"title":"山神庙裴度还带・南吕/一枝花","author":"关汉卿","dynasty":"元","form":"曲","lines":["恰便似梅花遍地开，柳絮因风起。","有山皆痩岭，无处不花飞。","凛冽风吹，风缠雪银鹅戏，雪缠风玉马垂。","采樵人荷担空回，更和那钓鱼叟披蓑倦起。"],"source":"元曲"},{"title":"登金陵凤凰台","author":"李白","dynasty":"唐","form":"诗","lines":["凤凰台上凤凰游，凤去台空江自流。","呉宫花草埋幽径，晋代衣冠成古丘。","三山半落青天外，二水中分白鹭洲。","総为浮云能蔽日，长安不见使人愁。"],"source":"《唐诗三百首》"},{"title":"知郡検计斎醮祷雨登时感通辄赋古风以附舆颂","author":"范成大","dynasty":"宋","form":"诗","lines":["六月火云高偃蹇，使君有意怜焦巻。","一封红篆駅金竜，雨気倏随炉燎満。","风师避路雷车鸣，石破天惊檐溜倾。","不知稲本颇苏否，但覚渓声如百霆。","税驾朱旛未云久，造化功成屈伸肘。","我评兹事与天通，知公小试调元手。","清坛深夜宾众真，前駆霓旌后飚轮。","定有霊官识仙伯，报道紫皇思侍臣。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["守得莲开结伴游。","约开萍叶上兰舟。","来时浦口云随棹，采罢江边月满楼。","花不语，水空流。","年年拼得为花愁。","明朝万一西风动，争向朱颜不耐秋。"],"source":"宋词"},{"title":"山神庙裴度还带・梁州","author":"关汉卿","dynasty":"元","form":"曲","lines":["看路径行人绝迹，我可便听园林冻鸟时啼。","这其间袁安高卧将门闭。","这其间寻梅的意懒，访戴的心灰，烹茶的得趣，映雪的伤悲。","冰雪堂冻苏秦懒谒张仪，蓝关下孝韩湘喜遇昌黎。","我、我、我，飘的这眼眩耀，认不的个来往回归；是、是、是，我可便心恍惚，弁不的个东西南北；呀、呀、呀，屯的这路弥漫，分不的个远近高低。","琼姬素衣，纷纷巧剪鹅毛细；战八百万玉龙退败，鳞甲纵横上下飞。","可端的羡杀冯夷！。"],"source":"元曲"},{"title":"早発白帝城","author":"李白","dynasty":"唐","form":"诗","lines":["朝辞白帝彩云间，千里江陵一日还。","両岸猨声啼不尽，軽舟已过万重山。"],"source":"《唐诗三百首》"},{"title":"送子文雑言","author":"范成大","dynasty":"宋","form":"诗","lines":["阴谷云低梅雨多，黄山涤源渓涌波。","南风匝地送帰客，双桨下瀬如投梭。","厳夫子，君挙酒，我其为君歌。","万山丛丛石凿凿，官居破屋巣烟萝。","杜鹃暁啼猿暮叫，客行到此真蹉跎。","穷愁无复理，一饮三叹息。","城东黉舎有佳人，邂逅使我加餐食。","同郷更同调，目撃心已伝。","蛰虫欲作雷奋地，万籁方寂风行山。","吹竽唤我醒，连鼓相追攀。","飚车电毂不可辇，但覚両腋生飞翰。","狂歌不必终曲，戯奕不必満局。","有时不揖上马去，出门大笑惊僮仆。","穷郷眼冷见未曽，道上嗫嚅相指目。","云此陿隘何以有二士，直恐翩翩跨黄鹄。","広文组解登王畿，诸公贵人争勧帰。","常日心期有定论，赠行不惜重费词。","腰金佩璐众目好，汗简沉碑千载痴。","一尊有意重山岳，五鼎无心軽网糸。","厳夫子，応领略，别后频书相発薬。","我既为万顷之狎鴎，君勿作九臯之鸣鹤。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["斗鸭池南夜不归。","酒阑纨扇有新诗。","云随碧玉歌声转，雪绕红琼舞袖回。","今感旧，欲沾衣。","可怜人似水东西。","回头满眼凄凉事，秋月春风岂得知。"],"source":"宋词"},{"title":"山神庙裴度还带・隔尾","author":"关汉卿","dynasty":"元","form":"曲","lines":["这其间正乱飘僧舎茶烟湿，密洒歌楼酒力微，青山也白头老了尘世。","都不到一时半刻，可又早周围四壁，添我在冰壶画图里。"],"source":"元曲"},{"title":"夜泊牛渚懐古","author":"李白","dynasty":"唐","form":"诗","lines":["牛渚西江夜，青天无片云。","登舟望秋月，空忆谢将军。","余亦能高咏，斯人不可闻。","明朝挂帆席，枫叶落纷纷。"],"source":"《唐诗三百首》"},{"title":"新馆","author":"范成大","dynasty":"宋","form":"诗","lines":["露稲粘明珰，风茅衮高浪。","荒烟暗白道，行行乱蛩响。","日脚午未吐，云头晩犹涨。","欣此半日凉，篮舆走清旷。","病客不堪暑，兹行天肯相。","蚊蝱扫无迹，秋意満千嶂。","稍寻泉石盟，略褫簿书障。","鸰原定相念，因风报无恙。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["当日佳期鹊误传。","至今犹作断肠仙。","桥成汉渚星波外，人在鸾歌凤舞前。","欢尽夜，别经年。","别多欢少奈何天。","情知此会无长计。","咫尺凉蟾亦未圆。"],"source":"宋词"},{"title":"山神庙裴度还带・牧羊关","author":"关汉卿","dynasty":"元","form":"曲","lines":["念小生居在白屋，处于布衣，多感谢长老慈悲！为小生缘薄，承吾师厚礼；见一日无空过，整三顿饱斋食。","你今日患难哀怜我，久以后得峥嵘答报你。"],"source":"元曲"},{"title":"月下独酌四首 一","author":"李白","dynasty":"唐","form":"诗","lines":["花间一壶酒，独酌无相亲。","挙杯邀明月，対影成三人。","月既不解饮，影徒随我身。","暂伴月将影，行楽须及春。","我歌月裴回，我舞影零乱。","醒时同交歓，酔后各分散。","永结无情游，相期邈云汉。"],"source":"《唐诗三百首》"},{"title":"临渓寺","author":"范成大","dynasty":"宋","form":"诗","lines":["万山绕竮竛，二水奔澒洞。","亭亭林中寺，金碧灿檐栋。","解鞍得蒲団，卧受瓦炉供。","少捐一炊顷，暂作百年梦。","无人自惊覚，幽禽正清哢。","倦客如残僧，无力供世用。","此行端为山，紫翠迭迎送。","漱井出门去，惊尘扑飞鞚。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["题破香笺小砑红。","诗篇多寄旧相逢。","西楼酒面垂垂雪，南苑春衫细细风。","花不尽，柳无穷。","别来欢事少人同。","凭谁问取归云信，今在巫山第几峰。"],"source":"宋词"},{"title":"山神庙裴度还带・骂玉郎","author":"关汉卿","dynasty":"元","form":"曲","lines":["有那等嫌贫爱富的儿曹辈，将俺这贫傲慢，把他那富追陪，那个肯恤孤念寡存仁义？有那一等靠着富贵，有干万乔所为，有那等夸强会。","（长老云）秀才真乃英才之辈，比他人不同也。","（正末唱）。"],"source":"元曲"},{"title":"聴蜀僧濬弾琴","author":"李白","dynasty":"唐","form":"诗","lines":["蜀僧抱绿绮，西下峨眉峰。","为我一挥手，如聴万壑松。","客心洗流水，余响入霜钟。","不覚碧山暮，秋云暗几重。"],"source":"《唐诗三百首》"},{"title":"盘竜駅","author":"范成大","dynasty":"宋","form":"诗","lines":["闻鶏一唱罢，占斗三星没。","天高月徘徊，野旷山突兀。","暗蛩泣草露，怨乱语还咽。","凉蛍不复挙，点缀稲花末。","惟余络纬豪，悲壮殷林樾。","小虫亦何情，孤客心断绝。","魂惊板桥穿，足侧石子滑。","行路如许难，谁能不华髪。","高城谩回首，畳嶂屹天阙。","遥知秋衾梦，千里一飘忽。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["清颍尊前酒满衣。","十年风月旧相知。","凭谁细话当时事，肠断山长水远诗。","金凤阙，玉龙墀。","看君来换锦袍时。","姮娥已有殷勤约，留着蟾宫第一枝。"],"source":"宋词"},{"title":"山神庙裴度还带・感皇恩","author":"关汉卿","dynasty":"元","form":"曲","lines":["他显耀些饱暖衣食，卖弄些精细伶俐。","怎听他仮文谈，胡答应，强支持！出身于市井，便显耀雄威；则待要邀些名誉，施些小恵，要些便宜。","（长老云）真乃君子、小人不同也！（正末唱）。"],"source":"元曲"},{"title":"怨情","author":"李白","dynasty":"唐","form":"诗","lines":["美人卷珠帘，深坐颦蛾眉。","但见涙痕湿，不知心恨谁。"],"source":"《唐诗三百首》"},{"title":"竹下","author":"范成大","dynasty":"宋","form":"诗","lines":["松杉晨気清，桑柘暑阴薄。","稲穂黄欲卧，槿花红未落。","秋鶑尚娇姹，晩蝶成飘泊。","犬𫘤逐车马，鶏惊扑篱落。","道逢行商问，平生几芒𪨗。","頳肩走四方，为口不计脚。","劣能濡箪瓢，何敢议囊橐。","我亦縻斗升，三年去丘壑。","二俱亡羊耳，未用苦商略。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["酔拍春衫惜旧香。","天将离恨恼疏狂。","年年陌上生秋草，日日楼中到夕阳。","云渺渺，水茫茫。","征人归路许多长。","相思本是无凭语，莫向花笺费泪行。"],"source":"宋词"},{"title":"山神庙裴度还带・采茶歌","author":"关汉卿","dynasty":"元","form":"曲","lines":["无才学有权势，有文章受驱驰，长老，这的是鹤长凫短不能齐！比小生剰趱浮财润自己，比吾师身穿几件虼虫两皮。"],"source":"元曲"},{"title":"淮上喜会梁川故人","author":"韦応物","dynasty":"唐","form":"诗","lines":["江汉曽为客，相逢毎酔还。","浮云一别后，流水十年间。","歓笑情如旧，萧疏鬓已斑。","何因北帰去，淮上対秋山。"],"source":"《唐诗三百首》"},{"title":"寒亭","author":"范成大","dynasty":"宋","form":"诗","lines":["沟塍与涧合，陇亩抱山転。","向来六月旱，此地免焦巻。","早穂已垂垂，晩苗犹剪剪。","一川豊年意，比屋閙鶏犬。","老农霜须鬓，矍铄黄犊健。","自云足踏地，常赋何能免。","刈熟倩人输，不识长官面。","康年无复事，但恐社酒浅。","我亦有二顷，収拾尚可茧。","懐哉笠沢路，帰铲犁头藓。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["小令尊前见玉箫。","银灯一曲太妖娆。","歌中酔倒谁能恨，唱罢归来酒未消。","春悄悄，夜迢迢。","碧云天共楚宫遥。","梦魂惯得无拘检，又踏杨花过谢桥。"],"source":"宋词"},{"title":"山神庙裴度还带・贺新郎","author":"关汉卿","dynasty":"元","form":"曲","lines":["通神的许负细详推，地阁天仓，兰台廷尉测他那山根印堂人中贵，五露三停六极，龙角鱼尾伏犀；肉眼蔵天地理，风鉴隐鬼神机。","断祸福、观气色、占凶吉，这厮好世情看冷暖，人面逐高低！（野鹤云）秀才，你休怪小子。","我敢断人生死无差，生则便生，死则便死，相法中无有不准．江湖上谁不知道肉眼通神相！人皆称呼我做无虚道人。","（正末唱）。"],"source":"元曲"},{"title":"郡斎雨中与诸文士燕集","author":"韦応物","dynasty":"唐","form":"诗","lines":["兵卫森画戟，宴寝凝清香。","海上风雨至，逍遥池阁凉。","烦疴近消散，嘉宾复満堂。","自慙居処崇，未覩斯民康。","理会是非遣，性达形迹忘。","鲜肥属时禁，蔬果幸见尝。","俯饮一杯酒，仰聆金玉章。","神歓体自軽，意欲凌风翔。","呉中盛文史，群彦今汪洋。","方知大藩地，岂曰财赋疆。"],"source":"《唐诗三百首》"},{"title":"清弋江","author":"范成大","dynasty":"宋","form":"诗","lines":["微生本渔樵，长日渺江海。","扣舷濯沧浪，尚说天宇隘。","朅来车马路，悒悒佳思败。","黄尘扑眉须，駆逐似偿债。","羸骖繋偪仄，狂犬吠荒怪。","郷心入旅梦，一叶舞澎湃。","晨兴过墟市，喜有鱼虾売。","眼明见清江，积雨助横溃。","褰裳唤扁舟，臲卼不胜载。","不辞野渡険，弄水聊一快。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["楚女腰肢越女腮。","粉圆双蕊髻中开。","朱弦曲怨愁春尽，渌酒杯寒记夜来。","新掷果，旧分钗。","冶游音信隔章台。","花间锦字空频寄，月底金鞍竟未回。"],"source":"宋词"},{"title":"山神庙裴度还带・乌夜啼","author":"关汉卿","dynasty":"元","form":"曲","lines":["稳情取禹门三级登鳌背，振天关平地一声雷。","看堂堂图相麒麟内，有一日列鼎而食，衣锦而回。","那其间青霄独歩上天梯，看姓名亚等呼先辈；攀龙鳞，附凤翼，显五陵豪气，吐万丈虹霓。","（野鹤云）相法所断，何故大怒？（长老云）裴中立，虽然相法中如此断，也看人心上所积，可不道：人有可延之寿也。","（野鹤云）小子无虚言也。","（正未唱）。"],"source":"元曲"},{"title":"初発扬子寄元大校书","author":"韦応物","dynasty":"唐","form":"诗","lines":["凄凄去亲爱，泛泛入烟雾。","帰棹洛阳人，残钟広陵树。","今朝此为别，何処还相遇。","世事波上舟，沿洄安得住。"],"source":"《唐诗三百首》"},{"title":"隠静山","author":"范成大","dynasty":"宋","form":"诗","lines":["五峰抱巌扉，千柱奠云壑。","荒原蕞尔県，有此宝楼阁。","维昔経営初，衣锡化双鹤。","杖头具只眼，矫矫云中落。","尊者一笑许，璇题照林薄。","庭柏有祖意，石泉韵天楽。","清簧転碧鶏，飞梭掷苍鹊。","号风饥虎怒，失木啼猿愕。","英游偶然同，吏檄乃不悪。","题名记吾曽，酔墨疥丹垩。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["十里楼台倚翠微。","百花深处杜娟啼。","殷勤自与行人语，不似流莺取次飞。","惊梦觉，弄晴时。","声声只道不如归。","天涯岂是无归意，争奈归期未可期。"],"source":"宋词"},{"title":"山神庙裴度还带・煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["噤声！我则理会的\"先生之道斯为美\"；正是\"不患人之不己知\"。","则是你个巧言令色打家贼，不弁个贵贱高低！按不住浩然之气，你看我登科甲便及第。","若是我金榜无名誓不回，有一日我独歩丹墀。","（长老云）秀才，再答话一回去波。","（正末不辞出门科，云）罢、罢、罢！（唱）。"],"source":"元曲"},{"title":"相和歌辞 江南曲","author":"李益","dynasty":"唐","form":"诗","lines":["嫁得瞿塘贾，朝朝误妾期。","早知潮有信，嫁与弄潮児。"],"source":"《唐诗三百首》"},{"title":"新岭","author":"范成大","dynasty":"宋","form":"诗","lines":["痩马兀瞢腾，荒鶏号莽苍。","糸窠罥朝露，篱落万珠网。","宿云払树过，飞泉擘山响。","老桑跼潜虬，怪蔓挂腾蟒。","山行何许深，空翠滴羁鞅。","醸愁积雨寒，破闷朝日放。","曈曈赤帜张，昱昱金钲上。","浮动草花馥，清和野禽唱。","仆夫有好语，沙平路如掌。","惟忧三渓阻，桥断山水涨。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["陌上蒙蒙残絮飞。","杜娟花里杜娟啼。","年年底事不归去，怨月愁烟长为谁。","梅雨细，晓风微。","倚楼人听欲沾衣。","故园三度群花谢，曼倩天涯犹未归。"],"source":"宋词"},{"title":"山神庙裴度还带・正宫/端正好","author":"关汉卿","dynasty":"元","form":"曲","lines":["我愁见古松林，我这里便怕到兀那崩摧庙。","我可便叹吾生久困蓬蒿，看别人\"青霄有路终须到\"，知他我何日\"朝闻道\"？。"],"source":"元曲"},{"title":"相和歌辞 燕歌行","author":"高适","dynasty":"唐","form":"诗","lines":["汉家烟尘在东北，汉将辞家破残贼。","男児本自重横行，天子非常赐颜色。","𪭢金伐鼓下楡関，旌旗逶迤碣石间。","校尉羽书飞瀚海，単于猟火照狼山。","山川萧条极辺土，胡骑凭凌雑风雨。","戦士军前半死生，美人帐下犹歌舞。","大漠穷秋塞草衰，孤城落日鬬兵稀。","身当恩遇常軽敌，力尽関山未解囲。","鉄衣远戍辛勤久，玉箸応啼别离后。","少妇城南欲断肠，征人蓟北空回首。","辺风飘飘那可度，绝域苍茫更何有。","杀気三日作阵云，寒声一夜伝刁斗。","相看白刃血纷纷，死节従来岂顾勲。","君不见沙场征戦苦，至今犹忆李将军。"],"source":"《唐诗三百首》"},{"title":"送通守赵积中朝议请祠帰天台","author":"范成大","dynasty":"宋","form":"诗","lines":["城头千峰青绕屋，城下滩流三百曲。","谁云偪仄复偪仄，尚有高轩肯来辱。","红梅花下両芳春，春风恵和如主人。","抢攘尘土簿书里，见此缫籍天球温。","厚禄故人车结辙，掉头独泛清渓月。","不従世外得超然，世间谁肯如公决。","生平我亦一沙鴎，苇白芦黄今正秋。","送公使我帰思动，破烟冲雨忆扁舟。","明年想见东山起，我亦煎茶石桥水。","道逢蓑笠把渔竿，即是马曹狂掾史。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["晓日迎长岁岁同。","太平箫鼓间歌钟。","云高未有前村雪，梅小初开昨夜风。","罗幕翠，锦筵红。","钗头罗胜写宜冬。","从今屈指春期近，莫使金尊对月空。"],"source":"宋词"},{"title":"山神庙裴度还带・滚绣球","author":"关汉卿","dynasty":"元","form":"曲","lines":["今日见那赵野鹤，他观了我相貌；他道冻饿纹耳连着口角，横死纹鬓接着眉梢；他道我主福禄薄，更寿夭。","则他那相法中无他那半星儿差错，他道：\"我断的准也不差分毫。","\"我平生正直无私曲，一任天公饶不饶！这的是\"善与人交\"。","（正末云）来到这山神庙也。","我与你払了这头上雪，入的这庙来。","这庙如此疏漏，又待倒也，如之奈何？（唱）。"],"source":"元曲"},{"title":"相和歌辞 従军行","author":"李颀","dynasty":"唐","form":"诗","lines":["白日登山望烽火，昏黄饮马傍交河。","行人刁斗风砂暗，公主琵琶幽怨多。","野営万里无城郭，雨雪纷纷连大漠。","胡雁哀鸣夜夜飞，胡児眼涙双双落。","闻道玉门犹被遮，応将性命逐軽车。","年年戦骨埋荒外，空见蒲萄入汉家。"],"source":"《唐诗三百首》"},{"title":"送詹道子教授奉祠养亲","author":"范成大","dynasty":"宋","form":"诗","lines":["新安学宫天下稀，先生孝友真吾师。","斑衣悮作长裾曳，二年思帰今得帰。","牋词上诉人叵挽，玺书赐可群公叹。","青山百匝不留人，空与诸生遮望眼。","白云孤起越南天，向来恨身无羽翰。","下马入门懐橘拝，身今却在白云辺。","鹤髪𩭹𩭹堂上坐，児孙称觞妇供果。","世间此楽几人同，看我风前孤涙堕。","一杯送舟下水西，我欲赠言无好词。","径须唤起束広微，为君重补南陔诗。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["小玉楼中月上时。","夜来惟许月华知。","重帘有意蔵私语，双烛无端恼暗期。","伤别易，恨欢迟。","归来何处验相思。","沈郎春雪愁消臂，谢女香膏懒画眉。"],"source":"宋词"},{"title":"山神庙裴度还带・酔太平","author":"关汉卿","dynasty":"元","form":"曲","lines":["我则见泥脱下些仰托。","更和这水浸过这笆箔。","我则见梁漕椽烂柱根糟，这的是欠九分来待倒。","这一座十疏九漏山神庙，如十花九裂寒冰窖，似十摧九塌草团瓢，比着那漏星堂较少。"],"source":"元曲"},{"title":"相和歌辞 蜀道难","author":"李白","dynasty":"唐","form":"诗","lines":["噫吁嚱！危乎高哉！蜀道之难难于上青天！蚕丛及鱼凫，开国何茫然。","尔来四万八千歳，乃与秦塞通人烟。","西当太白有鸟道，可以横绝峨眉巅。","地崩山摧壮士死，然后天梯石桟方钩连。","上有六竜回日之高标，下有冲波逆折之回川。","黄鹤之飞尚不得，猨猱欲度愁攀縁。","青泥何盘盘，百歩九折萦巌峦。","扪参歴井仰胁息，以手抚膺坐长叹。","问君西游何时还？畏途巉巌不可攀。","但见悲鸟号枯木，雄飞呼雌绕林间。","又闻子规啼夜月，愁空山，蜀道之难难于上青天！使人聴此雕朱颜。","连峰去天不盈尺，枯松倒挂倚绝壁。","飞湍瀑流相喧豗，砅崖転石万壑雷。","其崄也若此，嗟尔远道之人胡为乎来哉？劒阁峥嵘而崔嵬，一夫当関，万夫莫开。","所守或匪亲，化为狼与豺。","朝避猛虎，夕避长蛇。","磨牙吮血，杀人如麻。","锦城虽云楽，不如早还家。","蜀道之难难于上青天，侧身西望长咨嗟。"],"source":"《唐诗三百首》"},{"title":"道子教授奉祠诸生率余祖席如意院","author":"范成大","dynasty":"宋","form":"诗","lines":["暂移三席款云関，木末阑干暮紫间。","绛帐莫贪江上路，青鞵先试水西山。","伯阳有道来重趼，御寇他年忆解颜。","怪我抗尘駆俗驾，诸公何事许追攀。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["手拈香笺忆小莲。","欲将遗恨倩谁传。","归来独卧逍遥夜，梦里相逢酩酊天。","花易落，月难圆。","只应花月似欢缘。","秦筝算有心情在，试写离声入旧弦。"],"source":"宋词"},{"title":"山神庙裴度还带・倘秀才","author":"关汉卿","dynasty":"元","form":"曲","lines":["水头巾供桌上控着，泥脚靴土墙边晾着。","（正末云）裴中立也！（唱）我可甚\"买卖归来汗未消\"！凄凉愁今夜，犹自想来朝，藁荐上和衣儿睡倒。"],"source":"元曲"},{"title":"相和歌辞 长信怨 二","author":"王昌齢","dynasty":"唐","form":"诗","lines":["奉帚平明金殿开，暂将団扇共裴回。","玉颜不及寒鵶色，犹帯昭阳日影来。"],"source":"《唐诗三百首》"},{"title":"淳安","author":"范成大","dynasty":"宋","form":"诗","lines":["篙师叫怒破涛滝，水石如钟自撃撞。","欲识人间奇険処，但従歙浦过桐江。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["九日悲秋不到心。","凤城歌管有新音。","风凋碧柳愁眉淡，露染黄花笑靥深。","初见雁，已闻砧。","绮罗丛里胜登临。","须教月户纤纤玉，细捧霞觞滟滟金。"],"source":"宋词"},{"title":"山神庙裴度还带・呆骨朵","author":"关汉卿","dynasty":"元","form":"曲","lines":["我恰才待盘膝裹脚向亭柱上靠。","这藁荐下垫的来偌高！我这里悄悄量度，好着我暗暗的暗约。","（正末云）我试抹藁荐下咱。","（做拿起带科，云）是一条带！（唱）不由我小胆儿心中怕，唬的我小鹿儿心头跳；那一个富豪家失忘了？天呵！天呵！把我这穷魂灵儿险唬了！。"],"source":"元曲"},{"title":"相和歌辞 玉阶怨","author":"李白","dynasty":"唐","form":"诗","lines":["玉阶生白露，夜久侵罗袜。","却下水精帘，玲珑望秋月。"],"source":"《唐诗三百首》"},{"title":"厳州","author":"范成大","dynasty":"宋","form":"诗","lines":["城府黄尘扑马鞍，一篙重探水云寒。","耳辺眼底无公事，睡过厳州二百滩。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["碧藕花开水殿凉。","万年枝外转红阳。","升平歌管随天仗，祥瑞封章满御床。","金掌露，玉炉香。","岁华方共圣恩长。","皇州又奏圜扉静，十样宫眉捧寿觞。"],"source":"宋词"},{"title":"山神庙裴度还带・倘秀才","author":"关汉卿","dynasty":"元","form":"曲","lines":["我弁认的分分晓晓，我可便惹一场烦烦恼恼，我今夜索思量计万条。","若有人来寻觅，我权与他且収着，我两只手捧托。"],"source":"元曲"},{"title":"相和歌辞 子夜四时歌四首 春歌","author":"李白","dynasty":"唐","form":"诗","lines":["秦地罗敷女，采桑绿水辺。","素手青条上，红妆白日鲜。","蚕饥妾欲去，五马莫留连。"],"source":"《唐诗三百首》"},{"title":"钓台","author":"范成大","dynasty":"宋","form":"诗","lines":["山林朝市両尘埃，邂逅人生有往来。","各向此心安処住，钓台无意圧云台。"],"source":"宋诗"},{"title":"鹧鸪天","author":"晏几道","dynasty":"宋","form":"词","lines":["绿橘梢头几点春。","似留香蕊送行人。","明朝紫凤朝天路，十二重城五碧云。","歌渐咽，酒初醺。","尽将红泪湿湘裙。","赣江西畔从今日，明月清风忆使君。"],"source":"宋词"},{"title":"山神庙裴度还带・小梁州","author":"关汉卿","dynasty":"元","form":"曲","lines":["借问你个老妪缘由，女艳娇，你因甚事细说根苗。","（云）你有甚幺冤枉，在此觅死？你从头至尾说一遍咱。","（旦儿云）我看来这个人必是个儒人秀士。","哥哥不嫌絮烦，听妾从头至尾说一遍咱。","妾身乃洛阳韩太守的女孩儿，这个是我母亲，嫡亲的三口儿家属。","父亲在此为理，与人秋毫无犯。","为因上司差傅彬来河南点检钱粮，傅彬到此洛阳。","问我父要上马钱下马钱，我父不肯与他；后来傅彬为侵使过官钱，追赃赔纳，不想傅彬贼子怀挟前仇，指下家父三千贯赃。","奏闻行移至本府，提下家父，下于缧绁，赔赃三千贯。","事以不明，难为伸诉；下情不能上达，何须分辩！不能越朝廷法例，舒心赔纳。","家中収拾止勾送饭日用而已。","父母面上亲戚处助一千贯。","父母止生妾身一个，因父祖名家，老母家训，教妾读书吟诗写字。","在城里外，妾身怀羞搠笔题诗救父难，得市户乡民恻隐，一则为父清廉，二则因妾孝道，半年中抄化了一千贯。","陆续纳入官，前后二千贯。","尚有一千贯未完，父亲未能脱禁。","则见一日城市中有人对妾言说：\"小姐，这城中关厢里外，人事上也絮繁了。","近日朝廷差一公子，来此歇马，今日说往城东去，有人见在邮亭赏雪饮酒哩，若到那里，一则提笔卖诗，二则诉父冤枉，但得些滋润，勾你赔赃也。","\"听的说罢急走出城，来至邮亭，正见公子赏雪饮酒。","见妾，问其缘故；妾将前事尽诉其情，公子甚是怜念。","又命妾题诗，妾随做诗数首。","公子甚喜，就赐腰间玉带一条，价值千金，与妾身救父脱禁。","妾欲要回城中，到此半路风紧雪大，妾在此庙中歇脚避雪，不觉身体困倦，在此歇息，我将玉带放在藁荐下。","猛然省来，诚恐天晩母亲在家悬望，妾身慌走出庙来。","又怕关了城门，紧走到家中。","老母问其缘故，忽然想起玉带来，急要来取，城门已闭。","俺娘女二人一夜不曽睡，今日早挨门出来，入的庙门来寻，谁想不见了玉带！则觑着这条玉带救父脱禁；我既不能救父，又不能尽孝，我因此寻自尽。","（夫人云）哥哥，我则觑着这个孩儿，他寻自尽，夫主又不能出禁，要我身何用？我也寻个自尽，也是俺出于无奈也！（正末云）好可怜人也！（唱）为尊君冤枉坐囚牢，卖诗呵把父母恩临报。","小姐也，你可甚幺家富小儿娇！。"],"source":"元曲"},{"title":"相和歌辞 子夜四时歌四首 夏歌","author":"李白","dynasty":"唐","form":"诗","lines":["镜湖三百里，菡萏発荷花。","五月西施采，人看隘若邪。","回舟不待月，帰去越王家。"],"source":"《唐诗三百首》"},{"title":"桐庐","author":"范成大","dynasty":"宋","form":"诗","lines":["湿云垂野淡疏林，十日山行九日阴。","梅子弄黄応要雨，不知客路已泥深。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["金鞭美少年，去跃青骢马。","牵系玉楼人，绣被春寒夜。","消息未归来，寒食梨花谢。","无处说相思，背面秋千下。"],"source":"宋词"},{"title":"山神庙裴度还带・幺篇","author":"关汉卿","dynasty":"元","form":"曲","lines":["你道是从来养小防备老，都一般哀哀父母劬劳。","（带云）先圣有言：\"身体发肤，受之父母，不敢毁伤，孝之始也。","\"（唱）你便怎生舎性命寻自吊？（带云）\"扬名于后世，以显父母，孝之终也。","\"（唱）这的可也方为全孝。","（云）\"父母全而生之，子全而归之，可为孝也。","\"（唱）则这的是为人子立的根苗。","（夫人云）据先生说呵，也说的是；争夺我夫主无辜受禁，眼睁睁不得脱难，则觑着这条玉带救夫主；不见了，似此这般，一千贯赃几时纳的了也！（正末云）夫人、小娘子，仮若有这玉带呵呢？（夫人云）若是有这玉带呵，便是救了俺一家性命也。","（正末云）仮若无了这玉带呵呢？（夫人云）俺一家儿便是死的，都不得活也。","（正末云）老夫人、小娘子放心，玉带我替你収着哩！（旦儿云）先生勿戏言！（正未云）孔子门徒，岂有戏言！（正末做取带科，云）娘子，兀的不是带，还你！（旦儿接科，云）兀的不正是此带！索是谢了先生。","（夫人云）孩儿也，俺娘儿两个一齐的拝谢先生咱。","（正末云）不敢！不敢！（夫人云）先生救活我一家之恩，此义非轻也！世间似先生者世之罕有。","处于布衣窘暴之中，千金不改其志，端的是仁人君子也！（正末云）不敢！不敢！世间似小娘子贞孝之女--自古孝子多，孝女少--女子中只有两三个人也。","（夫人云）是那两三个？先生试说，老身洗耳愿闻咱。","（正末唱）。"],"source":"元曲"},{"title":"相和歌辞 子夜四时歌四首 秋歌","author":"李白","dynasty":"唐","form":"诗","lines":["长安一片月，万戸捣衣声。","秋风吹不尽，総是玉関情。","何日平胡虏？良人罢远征。"],"source":"《唐诗三百首》"},{"title":"富阳","author":"范成大","dynasty":"宋","form":"诗","lines":["不到江湖恰五年，歙山青绕屋头辺。","富春渡口明人眼，落日孤舟浪拍天。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["轻匀两脸花，淡扫双眉柳。","会写锦笺时，学弄朱弦后。","今春玉钏宽，昨夜罗裙皱。","无计奈情何，且酔金杯酒。"],"source":"宋词"},{"title":"山神庙裴度还带・叨叨令","author":"关汉卿","dynasty":"元","form":"曲","lines":["当日个贾氏为父屠龙孝，杨香为父跨虎曽行孝，曹蛾为父嚎江孝；今日个琼英为父题诗孝。","端的可便感天地也波哥，端的可便感天地也波哥！为父母呵，男女皆可尽人之孝。"],"source":"元曲"},{"title":"相和歌辞 子夜四时歌四首 冬歌","author":"李白","dynasty":"唐","form":"诗","lines":["明朝駅使発，一夜絮征袍。","素手抽针冷，那堪把剪刀。","裁缝寄远道，几日到临洮。"],"source":"《唐诗三百首》"},{"title":"余杭","author":"范成大","dynasty":"宋","form":"诗","lines":["春晩山花各静芳，従教红紫送韶光。","忍冬清馥蔷薇酽，薫満千村万落香。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["关山魂梦长，鱼雁音尘少。","两鬓可怜青，只为相思老。","归梦碧纱窗，说与人人道。","真个别离难，不似相逢好。"],"source":"宋词"},{"title":"山神庙裴度还带・塞鸿秋","author":"关汉卿","dynasty":"元","form":"曲","lines":["我则待粗衣淡饭从吾乐，我一心待要固穷守分天之道，我则待存心谨守先王教。","（旦儿云）先生恰才不与此带，无计所奈也！（正末唱）可不道\"君子不夺人之好\"？（夫人云）老身一家处于患难，先生也在窘迫，故使先生救我一家性命。","（正末唱）夫人处患难，小生甘穷暴，咱正是摇鞭举棹休相笑。"],"source":"元曲"},{"title":"琴曲歌辞 列女操","author":"孟郊","dynasty":"唐","form":"诗","lines":["梧桐相待老，鸳鸯会双死。","贞妇贵徇夫，舎生亦如此。","波澜誓不起，妾心井中水。"],"source":"《唐诗三百首》"},{"title":"于潜","author":"范成大","dynasty":"宋","form":"诗","lines":["邑居官寺両凄清，晩市都无菜可羹。","何処直能令鬼怕，祗今犹自有人行。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["坠雨已辞云，流水难归浦。","遗恨几时休，心抵秋莲苦。","忍泪不能歌，试托哀弦语。","弦语愿相逢，知有相逢否。"],"source":"宋词"},{"title":"山神庙裴度还带・倘秀才","author":"关汉卿","dynasty":"元","form":"曲","lines":["出庙门送下涩道，近行径转过墙角，这的是贫不忧愁富不骄。","（旦儿云）妾身看了秀才，若非古之君子，岂有如此局量！此还带之意．异日必当重报于足下。","《毛诗》云：\"投之以木桃，报之以琼瑶。","\"焉敢忘恩人之大徳也！（正末唱）你道是\"投之以木桃，报之以琼瑶\"，小人怎敢比古人量作！（旦儿云）此时世俗，惟先生之一人；礼义廉耻道徳之风--余者俗子，受不明之物，取不义之财--有几人也？（正末云）\"皇天无私，惟徳是辅\"。","（唱）。"],"source":"元曲"},{"title":"雑曲歌辞 游子吟","author":"孟郊","dynasty":"唐","form":"诗","lines":["慈母手中线，游子身上衣。","临行密密缝，意恐遅遅帰。","谁言寸草心，报得三春晖。"],"source":"《唐诗三百首》"},{"title":"昌化","author":"范成大","dynasty":"宋","form":"诗","lines":["翠染南山拥県门，一洲横截両渓分。","长官日永无公事，卧聴滩声看白云。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["一分残酒霞，两点愁蛾晕。","罗幕夜犹寒，玉枕春先困。","心情翦彩慵，时节烧灯近。","见少别离多，还有人堪恨。"],"source":"宋词"},{"title":"山神庙裴度还带・滚绣球","author":"关汉卿","dynasty":"元","form":"曲","lines":["咱人命里有呵福禄増，（云）暗室亏心，神目如电。","（唱）命里无时灾祸招。","（云）近之不逊，远之又怨。","（唱）受不明物呵不合神道，（云）\"不义而富且贵，于我如浮云\"！（唱）取不义财呵枉物难消。","（见儿云）据先生如此大量，当来发达于世，岂不壮哉！（正未唱）有一日蛰龙奋头角，风云酔碧桃；酬志也五陵年少，轩昂也当发英豪；伴旌旗日暖龙蛇动，看宫殿风微燕雀高，雁塔名标。"],"source":"元曲"},{"title":"雑曲歌辞 丽人行","author":"杜甫","dynasty":"唐","form":"诗","lines":["三月三日天気新，长安水辺多丽人。","态浓意远淑且真，肌理细腻骨肉匀。","繍罗衣裳照暮春，蹙金孔雀银麒麟。","头上何所有？翠微㔩叶垂鬓唇。","背后何所见？珠圧腰衱穏称身。","就中云幕椒房亲，赐名大国虢与秦。","紫𫘞之峰出翠釜，水晶之盘行素鳞。","犀筯厌饫久未下，鸾刀缕切空纷纶。","黄门飞鞚不动尘，御厨糸络送八珍。","箫鼓哀吟感鬼神，宾従雑遝実要津。","后来鞍马何逡巡，当轩下马入锦茵。","杨花雪落覆白苹，青鸟飞去衔红巾。","炙手可热势绝伦，慎莫近前丞相嗔。"],"source":"《唐诗三百首》"},{"title":"百丈山","author":"范成大","dynasty":"宋","form":"诗","lines":["沐雨梳风有底忙，解鞍来宿賛公房。","伝闻三岭连天峻，未到王千已断肠。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["轻轻制舞衣，小小裁歌扇。","三月柳浓时，又向津亭见。","垂泪送行人，湿破红妆面。","玉指袖中弹，一曲清商怨。"],"source":"宋词"},{"title":"山神庙裴度还带・煞","author":"关汉卿","dynasty":"元","form":"曲","lines":["阴阳有准无虚道，好一个肉眼通神赵野鹤！咱人这祸福难逃，吉凶怎避，莫得执迷，枉了徒劳！判断在昨日，分已定前生，果应于今朝。","若是砕砖瓦里命终得这身夭，险些儿白骨卧荒郊！（夫人云）先生为何如此惊叹？必有其情，乞请知之。","（正末云）老夫人不知。","小生昨日在白马寺中遇一相士，说小生今日不过午，一命掩泉土，今日午前死于砕砖瓦之下。","今日果应其言！小生若不为还此带，送出老夫人、小姐来呵，小生正遭此一死也！（夫人云）皆是先生阴徳大重，救我一家之命，因此遇大难不死；必有后程，准定发迹也！（正末唱）。"],"source":"元曲"},{"title":"雑曲歌辞 长相思三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["长相思，在长安，络纬秋啼金井栏。","微霜凄凄簟色寒，孤灯不明思欲绝。","巻帷望月空长叹，美人如花隔云端。","上有青冥之长天，下有绿水之波澜。","天长路远魂飞苦，梦魂不到関山难。","长相思，摧心肝。"],"source":"《唐诗三百首》"},{"title":"昱岭","author":"范成大","dynasty":"宋","form":"诗","lines":["竹舆揺兀走婆娑，石滑泥融侧足过。","昱岭不高人已困，晩登新岭奈君何。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["红尘陌上游，碧柳堤边住。","才趁彩云来，又逐飞花去。","深深美酒家，曲曲幽香路。","风月有情时，总是相思处。"],"source":"宋词"},{"title":"山神庙裴度还带・尾声","author":"关汉卿","dynasty":"元","form":"曲","lines":["我但得一朝冠盖向长安道，趁着这万里风头鹤背高。","有一日享荣华、受官爵，早则不居无安，食无饱。","（旦儿云）此恩此徳，时刻未忘。","（夫人云）我记着先生这个模样，请个良工写像传真，侍奉终日，烧香供养先生也。","（正末唱）你道是这恩临决然报，常记着休忘了，命良工写像传真，点烛烧香，你将我来供养。","到老。","（下）。"],"source":"元曲"},{"title":"雑曲歌辞 长相思三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["日色已尽花含烟，月明欲素愁不眠。","赵瑟初停凤凰柱，蜀琴欲奏鸳鸯弦。","此曲有意无人伝，愿随春风寄燕然，忆君迢迢隔青天。","昔日横波目，今成流涙泉。","不信妾肠断，帰来看取明镜前。"],"source":"《唐诗三百首》"},{"title":"王千岭","author":"范成大","dynasty":"宋","form":"诗","lines":["山霊设険合峥嵘，行客何须向此行。","羸马不前人雨汗，此身安得讳労生。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["长恨渉江遥，移近渓头住。","闲荡木兰舟，误入双鸳浦。","无端轻薄云，暗作廉纤雨。","翠袖不胜寒，欲向荷花语。"],"source":"宋词"},{"title":"山神庙裴度还带・双调/新水令","author":"关汉卿","dynasty":"元","form":"曲","lines":["想着我二十年埋没洛阳尘，今日个起蛰龙一声雷震；一来文章好立身，二来是天子重贤臣。","好徳亲仁，束带冠巾，演武修文，温故知新，咱人要修天爵正方寸。"],"source":"元曲"},{"title":"雑曲歌辞 行路难三首 一","author":"李白","dynasty":"唐","form":"诗","lines":["金尊清酒斗十千，玉盘珍羞直万銭。","停杯投筯不能食，抜劒四顾心茫然。","欲渡黄河冰塞川，将登太行雪暗天。","闲来垂钓坐渓上，忽复乗舟梦日辺。","行路难，行路难，多岐路，今安在？长风破浪会有时，直挂云帆済沧海。"],"source":"《唐诗三百首》"},{"title":"刈麦","author":"范成大","dynasty":"宋","form":"诗","lines":["麦头熟颗已如珠，小阨惟忧积雨余。","丐我一晴天易耳，十分终恵莫乗除。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["远山眉黛长，细柳腰肢袅。","妆罢立春风，一笑千金少。","归去凤城时，说与青楼道。","遍看颍川花，不似师师好。"],"source":"宋词"},{"title":"山神庙裴度还带・庆东原","author":"关汉卿","dynasty":"元","form":"曲","lines":["居廊庙，当缙绅，习《诗》《书》，学《礼》《易》，从先进君子务本。","忘身发愤，能正其身。","酬志了白玉带紫朝服，茶褐伞黄金印。","（媒人云）瑶池降谪三天仙，今夜高门招状元。","琼酿金杯长寿酒，新郎舒手接丝鞭。","请状元接丝鞭！（正末唱）。"],"source":"元曲"},{"title":"雑曲歌辞 行路难三首 二","author":"李白","dynasty":"唐","form":"诗","lines":["大道如青天，我独不得出。","羞逐长安社中児，赤鶏白狗赌梨栗。","弾劒作歌奏苦声，曳裾王门不称情。","淮阴市井笑韩信，汉朝公卿忌贾生。","君不见昔时燕家重郭隗，拥篲折腰无嫌猜。","剧辛楽毅感恩分，输肝剖胆効英才。","昭王白骨萦蔓草，谁人更扫黄金台。","行路难，帰去来。"],"source":"《唐诗三百首》"},{"title":"挿秧","author":"范成大","dynasty":"宋","form":"诗","lines":["种密移疏绿毯平，行间清浅縠纹生。","谁知细细青青草，中有豊年撃壌声。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["落梅庭榭香，芳草池塘绿。","春恨最关情，日过阑干曲。","几时花里闲，看得花枝足。","酔后莫思家，借取师师宿。"],"source":"宋词"},{"title":"山神庙裴度还带・川拨棹","author":"关汉卿","dynasty":"元","form":"曲","lines":["展图像挂高门，彩楼新接着绛云。","我自见皓齿朱唇，翠袖红裙，簇捧个雾鬓云鬟的美人。","见官媒将导引，他道招状元为婿君，不邀媒不问肯，惊丝鞭捧玉樽。"],"source":"元曲"},{"title":"雑曲歌辞 行路难三首 三","author":"李白","dynasty":"唐","form":"诗","lines":["有耳莫洗颍川水，有口莫食首阳蕨。","含光混世贵无名，何用孤高比云月。","吾観自古贤达人，功成不退皆殒身。","子胥既弃呉江上，屈原终投湘水浜。","陆机才多岂自保，李斯税驾苦不早。","华亭鹤唳讵可闻，上蔡苍鹰何足道？君不见呉中张翰称达士，秋风忽忆江东行。","且楽生前一杯酒，何须身后千载名。"],"source":"《唐诗三百首》"},{"title":"晒茧","author":"范成大","dynasty":"宋","form":"诗","lines":["隔篱処処雪成窝，牢闭柴荆断客过。","叶贵蚕饥危欲死，尚能包裹一糸窠。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["狂花顷刻香，晩蝶缠绵意。","天与短因缘，聚散常容易。","传唱入离声，恼乱双蛾翠。","游子不堪闻，正是衷肠事。"],"source":"宋词"},{"title":"雑曲歌辞 长干曲四首 一","author":"崔颢","dynasty":"唐","form":"诗","lines":["君家定何処？妾住在横塘。","停舟暂借问，或恐是同郷。"],"source":"《唐诗三百首》"},{"title":"科桑","author":"范成大","dynasty":"宋","form":"诗","lines":["斧斤留得万枯株，独速槎牙立暝途。","饱尽春蚕収罢茧，更殚余力付樵苏。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["官身几日闲，世事何时足。","君貌不长红，我鬓无重绿。","榴花满盏香，金缕多情曲。","且尽眼中欢，莫叹时光促。"],"source":"宋词"},{"title":"雑曲歌辞 长干曲四首 二","author":"崔颢","dynasty":"唐","form":"诗","lines":["家临九江水，去来九江侧。","同是长干人，生小不相识。"],"source":"《唐诗三百首》"},{"title":"竜学尚书新安侯罗公挽词二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["今代丹台籍，频年绿野居。","鉄冠真御史，革履旧尚书。","短世浮云尽，平生半稿余。","人言公不朽，兰玉照前除。"],"source":"宋诗"},{"title":"生查子","author":"晏几道","dynasty":"宋","form":"词","lines":["春从何处归，试向渓边问。","岸柳弄娇黄，陇麦回青润。","多情美少年，屈指芳菲近。","谁寄岭头梅，来报江南信。"],"source":"宋词"},{"title":"雑曲歌辞 长干行二首 一","author":"李白","dynasty":"唐","form":"诗","lines":["妾髪初覆额，折花门前剧。","郎骑竹马来，遶床弄青梅。","同居长干里，両小无嫌猜。","十四为君妇，羞颜尚不开。","低头向暗壁，千唤不一回。","十五始展眉，愿同尘与灰。","常存抱柱信，岂上望夫台。","十六君远行，瞿塘滟预堆。","五月不可触，猨鸣天上哀。","门前遅行迹，一一生绿苔。","苔深不能扫，落叶秋风早。","八月蝴蝶来，双飞西园草。","感此伤妾心，坐愁红颜老。","早晩下三巴，预将书报家。","相迎不道远，直至长风沙。"],"source":"《唐诗三百首》"},{"title":"竜学尚书新安侯罗公挽词二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["一昨更调瑟，如闻欲赐环。","途殚泣西狩，望绝起东山。","华屋林霏惨，新阡草露班。","春风埋玉涙，重为庾公潸。"],"source":"宋诗"},{"title":"南乡子","author":"晏几道","dynasty":"宋","form":"词","lines":["渌水带青潮。","水上朱阑小渡桥。","桥上女儿双笑靥，妖娆。","倚着阑干弄柳条。","月夜落花朝。","减字偷声按玉箫。","柳外行人回首处，迢迢。","若比银河路更遥。"],"source":"宋词"},{"title":"雑曲歌辞 独不见","author":"沈佺期","dynasty":"唐","form":"诗","lines":["卢家小妇郁金堂，海燕双栖玳瑁梁。","九月寒砧催下叶，十年征戍忆辽阳。","白狼河北音书断，丹凤城南秋夜长。","谁知含愁独不见，使妾明月照流黄。"],"source":"《唐诗三百首》"},{"title":"竜学侍郎清河侯张公挽词二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["白水名多士，清河最有声。","人危孔北海，帝识柳宜城。","蜀険谈间固，蛮讧檄到平。","凌烟何処在，风雨上铭旌。"],"source":"宋诗"},{"title":"南乡子","author":"晏几道","dynasty":"宋","form":"词","lines":["小蕊受春风。","日日宫花花树中。","恰向柳绵撩乱处，相逢。","笑靥旁边心字浓。","归路草茸茸。","家在秦楼更近东。","醒去酔来无限事，谁同。","说着西池满面红。"],"source":"宋词"},{"title":"雑曲歌辞 秋夜曲","author":"王涯","dynasty":"唐","form":"诗","lines":["桂魄初生秋露微，軽罗已薄未更衣。","银筝夜久殷勤弄，心怯空房不忍帰。"],"source":"《唐诗三百首》"},{"title":"竜学侍郎清河侯张公挽词二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["太息逢萋锦，平生付薄冰。","沧溟淙赤舌，白日照青蝇。","岳麓身犹健，星维驭已升。","天如遗一老，人亦望三登。"],"source":"宋诗"},{"title":"南乡子","author":"晏几道","dynasty":"宋","form":"词","lines":["花落未须悲。","红蕊明年又满枝。","惟有花间人别后，无期。","水阔山长雁字迟。","今日最相思。","记得攀条话别离。","共说春来春去事，多时。","一点愁心入翠眉。"],"source":"宋词"},{"title":"春思","author":"皇甫冉","dynasty":"唐","form":"诗","lines":["莺啼燕语报新年，马邑竜堆路几千。","家住秦城邻汉苑，心随明月到胡天。","机中锦字论长恨，楼上花枝笑独眠。","为问元戎窦车骑，何时反斾勒燕然。"],"source":"《唐诗三百首》"},{"title":"新安侯夫人俞氏挽词","author":"范成大","dynasty":"宋","form":"诗","lines":["蚤兆于凰卜，来嫔驷马车。","夫君宜竹帛，子舎各诗书。","露薤丹旌挙，风杨组帐虚。","空余彤管训，他日照郷闾。"],"source":"宋诗"},{"title":"南乡子","author":"晏几道","dynasty":"宋","form":"词","lines":["何处别时难。","玉指偷将粉泪弹。","记得来时楼上烛，初残。","待得清霜满画阑。","不惯独眠寒。","自解罗衣衬枕檀。","百媚也应愁不睡，更阑。","恼乱心情半被闲。"],"source":"宋词"},{"title":"夜月","author":"刘方平","dynasty":"唐","form":"诗","lines":["更深月色半人家，北斗阑干南斗斜。","今夜偏知春気暖，虫声新透绿窗纱。"],"source":"《唐诗三百首》"},{"title":"次韵甄云卿晩登浮丘亭","author":"范成大","dynasty":"宋","form":"诗","lines":["宾筵旧圧三千客，燕榭新高十二城。","溌墨云头连树暗，垂糸雨脚过渓生。","葛巾羽扇吾身健，雪椀冰瓯子句清。","従此相従须痛饮，故応此事胜公栄。"],"source":"宋诗"},{"title":"南乡子","author":"晏几道","dynasty":"宋","form":"词","lines":["画鸭懒熏香。","绣茵犹展旧鸳鸯。","不似同衾愁易晓，空床。","细剔银灯怨漏长。","几夜月波凉。","梦魂随月到兰房。","残睡觉来人又远，难忘。","便是无情也断肠。"],"source":"宋词"},{"title":"春怨","author":"刘方平","dynasty":"唐","form":"诗","lines":["纱窗日落渐黄昏，金屋无人见涙痕。","寂寞空庭春欲晩，梨花満地不开门。"],"source":"《唐诗三百首》"},{"title":"古风上知府秘书二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["神仙绝世立，功行闻清都。","玉符赐长生，𥬞云游紫虚。","鶏犬尔何知，偶舐薬鼎余。","身軽亦仙去，罡风与之俱。","俯视旧篱落，眇莽如积苏。","非无凤与麟，终然侣虫鱼。","微物岂有命，政尔谢泥涂。","时哉适丁是，邂逅真良図。"],"source":"宋诗"},{"title":"南乡子","author":"晏几道","dynasty":"宋","form":"词","lines":["眼约也应虚。","昨夜归来凤枕孤。","且据如今情分里，相于。","只恐多时不似初。","深意托双鱼。","小翦蛮笺细字书。","更把此情重问得，何如。","共结因缘久远无。"],"source":"宋词"},{"title":"登鹳雀楼","author":"王之涣","dynasty":"唐","form":"诗","lines":["白日依山尽，黄河入海流。","欲穷千里目，更上一层楼。"],"source":"《唐诗三百首》"},{"title":"古风上知府秘书二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["大鹏上扶揺，南溟聒天沸。","斥鷃有羽翼，意満蓬蒿里。","不如附骥蝇，掣电抹荆蓟。","谁云极幺么，俛仰且万里。","向来庭戸间，决起不逾咫。","飘飖托方便，意気乃如此。","物生未可料，旦暮倘逢世。","君看功名场，得失一交臂。"],"source":"宋诗"},{"title":"南乡子","author":"晏几道","dynasty":"宋","form":"词","lines":["新月又如眉。","长笛谁教月下吹。","楼倚暮云初见雁，南飞。","漫道行人雁后归。","意欲梦佳期。","梦里关山路不知。","却待短书来破恨，应迟。","还是凉生玉枕时。"],"source":"宋词"},{"title":"凉州词二首 一","author":"王之涣","dynasty":"唐","form":"诗","lines":["黄河远上白云间，一片孤城万仞山。","羌笛何须怨杨柳，春光不度玉门関。"],"source":"《唐诗三百首》"},{"title":"拄笏亭晩望","author":"范成大","dynasty":"宋","form":"诗","lines":["林泉随処有清凉，山绕阑干客自忙。","渓雨不飞虹尚饮，乱蝉高柳満斜阳。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["留人不住。","酔解兰舟去。","一棹碧涛春水路。","过尽晓莺啼处。","渡头杨柳青青。","枝枝叶叶离情。","此后锦书休寄，画楼云雨无凭。"],"source":"宋词"},{"title":"阙题","author":"刘眘虚","dynasty":"唐","form":"诗","lines":["道由白云尽，春与青渓长。","时有落花至，远随流水香。","闲门向山路，深柳読书堂。","幽映毎白日，清辉照衣裳。"],"source":"《唐诗三百首》"},{"title":"乳滩","author":"范成大","dynasty":"宋","form":"诗","lines":["清渓可怖亦可喜，造化于人真虐戯。","轰雷卷雪鬓成糸，一掷平生来此试。","険绝无双是乳滩，舟如滚石下高山。","画楼正倚黄昏雨，岂识江间行路难。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["千花百草。","送得春归了。","拾蕊人稀红渐少。","叶底杏青梅小。","小琼闲抱琵琶。","雪香微透轻纱。","正好一枝娇艳，当筵独占韶华。"],"source":"宋词"},{"title":"征怨","author":"柳中庸","dynasty":"唐","form":"诗","lines":["歳歳金河复玉関，朝朝马策与刀环。","三春白雪帰青冢，万里黄河遶黒山。"],"source":"《唐诗三百首》"},{"title":"浮丘亭","author":"范成大","dynasty":"宋","form":"诗","lines":["黟山鬰律神仙宅，三十六峰雷雨隔。","碧城栏槛偃双旌，笑挹浮丘为坐客。","巌扉无锁昼长开，紫云明灭多楼台。","云中仙驭参差是，肯为使君乗兴来。","西昆巉绝不可至，东望蓬莱愁弱水。","谁知芳草徧天涯，玉京只在珠帘底。","他年麟阁上清空，却访旧游寻赤松。","我亦従公负丹鼎，来𣃁砂床汲汤井。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["烟轻雨小。","紫陌香尘少。","谢客池塘生绿草。","一夜红梅先老。","旋题罗带新诗。","重寻杨柳佳期。","强半春寒去后，几番花信来时。"],"source":"宋词"},{"title":"送李端","author":"厳维","dynasty":"唐","form":"诗","lines":["故関衰草遍，离别正堪悲。","路出寒云外，人帰暮雪时。","少孤为客早，多难识君遅。","揜泣空相向，风尘何所期。"],"source":"《唐诗三百首》"},{"title":"风月堂","author":"范成大","dynasty":"宋","form":"诗","lines":["天风无辺吹海月，景入渓山更奇绝。","太守文章别乗贤，平生付与金杯滑。","门阑我亦似彭宣，想闻横玉叫苍烟。","読碑索句仍投辖，谁是扬州控鹤仙。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["可怜娇小。","掌上承恩早。","把镜不知人易老。","欲占朱颜长好。","画堂秋月佳期。","蔵钩赌酒归迟。","红烛泪前低语，绿笺花里新词。"],"source":"宋词"},{"title":"宫词五首 二","author":"顾况","dynasty":"唐","form":"诗","lines":["玉楼天半起笙歌，风送宫嫔笑语和。","月殿影开闻夜漏，水精帘巻近银河。"],"source":"《唐诗三百首》"},{"title":"寄赠泉石使李元直入觐","author":"范成大","dynasty":"宋","form":"诗","lines":["汉図昔中天，百六启真主。","当时邓高密，徒歩赴光武。","诸公上云台，一叶渺湘浦。","声名三十年，玉気贯晴宇。","向来宣室问，天语道旧故。","不図太平日，复见起兵簿。","双旌奠侯服，三节临江浒。","垂欲大用公，少驻议圜府。","人言山沢官，底用庙廊具。","果闻一乗伝，已踵追锋去。","翔凤覧辉来，风采照鸳鹭。","平生経済心，十不一二吐。","兹行公勿逊，安国如鼎吕。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["红英落尽。","未有相逢信。","可恨流年凋绿鬓。","睡得春酲欲醒。","钿筝曽酔西楼。","朱弦玉指梁州。","曲罢翠帘高巻，几回新月如钩。"],"source":"宋词"},{"title":"休宁","author":"范成大","dynasty":"宋","form":"诗","lines":["南街豪郡城，东圃圧州宅。","谁云沸镬地，気象不偪仄。","林园富瓜笋，堂密美杉柏。","山醪极可人，渓女能酔客。","呉子邑中彦，毫端万人敌。","伝杯相労苦，不覚东方白。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["春云绿处。","又见归鸿去。","侧帽风前花满路。","冶叶倡条情绪。","红楼桂酒新开。","曽携翠袖同来。","酔弄影娥池水，短箫吹落残梅。"],"source":"宋词"},{"title":"祁门","author":"范成大","dynasty":"宋","form":"诗","lines":["石梁平波心，金刹驾巌腹。","渓藤巻霜缯，山骨琢紫玉。","东堂有嘉名，窈窕窗纱绿。","落花扫无迹，蕉叶森似束。","主人甚爱客，挽袖语陆続。","冲雨出门去，役役媿童仆。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["波纹碧皱。","曲水清明后。","折得疏梅香满袖。","暗喜春红依旧。","归来紫陌东头。","金钗换酒消愁。","柳影深深细路，花梢小小层楼。"],"source":"宋词"},{"title":"霊山口","author":"范成大","dynasty":"宋","form":"诗","lines":["陵高类登天，斗下剧窥井。","衡従十里近，底用许多岭。","秋雨醸春泥，掀淖力扛鼎。","仆夫负隅哭，邂逅忧性命。","旧嗤子猷狂，夜半桨帰艇。","方知兴尽処，顷歩令人瘿。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["西池烟草。","恨不寻芳早。","满路落花红不扫。","春色渐随人老。","远山眉黛娇长。","清歌细逐霞觞。","正在十洲残梦，水心宫殿斜阳。"],"source":"宋词"},{"title":"浮梁","author":"范成大","dynasty":"宋","form":"诗","lines":["大滩石如林，小滩石如枿。","微生抛掷过，両桨砉将割。","一滩复一滩，食顷経七八。","崎岖幸脱免，已足凋鬓髪。","我家五湖船，镜面贴天阔。","行迷勿浪远，帰欤泛花月。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["蕙心堪怨。","也逐春风转。","丹杏墙东当日见。","幽会绿窗题遍。","眼中前事分明。","可怜如梦难凭。","都把旧时薄幸，只消今日无情。"],"source":"宋词"},{"title":"鄱阳湖","author":"范成大","dynasty":"宋","form":"诗","lines":["凄悲鸿雁来，泱漭鱼竜蛰。","雷霆一鼓罢，星斗万里湿。","波翻渔火砕，月落村舂急。","折苇已纷披，衰杨尚僵立。","长年畏简书，今夕念蓑笠。","江湖有佳思，逆旅百忧集。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["幺弦写意。","意密弦声砕。","书得凤笺无限事。","犹恨春心难寄。","卧听疏雨梧桐。","雨馀淡月朦胧。","一夜梦魂何处，那回杨叶楼中。"],"source":"宋词"},{"title":"回黄坦","author":"范成大","dynasty":"宋","form":"诗","lines":["渥丹枫凋零，浓黛柏幽独。","畦稲晩已黄，陂草秋重绿。","平远一横看，浩荡供酔目。","落帆金碧渓，嘶马锦繍谷。","世界真荘厳，造物极不俗。","向非来远游，那有此奇瞩。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["笙歌宛转。","台上吴王宴。","宫女如花倚春殿。","舞绽缕金衣线。","酒阑画烛低迷。","彩鸳惊起双栖。","月底三千绣户，云间十二琼梯。"],"source":"宋词"},{"title":"桑岭","author":"范成大","dynasty":"宋","form":"诗","lines":["回肠山百盘，挥手天一握。","俯惊危桟穿，仰诧飞石落。","挽舆如挽舟，绝叫断双筰。","怪蔓缠枯槎，瘠草被幽壑。","此岂车马路，谁云强刊凿。","人言远游好，呼来试着脚。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["暂来还去。","轻似风头絮。","纵得相逢留不住。","何况相逢无处。","去时约略黄昏。","月华却到朱门。","别后几番明月，素娥应是消魂。"],"source":"宋词"},{"title":"天都峰","author":"范成大","dynasty":"宋","form":"诗","lines":["维帝有下都，作镇此南国。","孤撑紫玉楼，横绝太霄碧。","晶荧砂窦红，夭矫泉绅白。","晴云无尽蔵，竟日袅幽石。","诸峰三十五，离立侍傍侧。","会稽眇小哉，请议职方籍。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["双纹彩袖。","笑捧金船酒。","娇妙如花轻似柳。","劝客千春长寿。","艳歌更倚疏弦。","有情须酔尊前。","恰是可怜时候，玉娇今夜初圆。"],"source":"宋词"},{"title":"温泉","author":"范成大","dynasty":"宋","form":"诗","lines":["砂床毓霊源，石液漱和気。","鬰攸甑常蒸，觱沸鼎百沸。","人生本无垢，安用涤肠胃。","一瓢滟清肥，回首谢罗罻。","山深人迹罕，政以远为贵。","君看华清池，谈者至今讳。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["寒催酒醒。","晓陌飞霜定。","背照画帘残烛影。","斜月光中人静。","锦衣才子西征。","万重云水初程。","翠黛倚门相送，鸾肠断处离声。"],"source":"宋词"},{"title":"伏闻知府秘书欲取小杜桐庐诗语以见花名堂成大记东坡送郑戸曹诗云荡荡清河壖黄楼我所开遅君为坐客新诗出琼瑰楼成君已去人事固多乖此段大类今日成大行且受代计梅开堂成帰舟已下南浦欲为坐客不可得懐不能已请先为公赋之","author":"范成大","dynasty":"宋","form":"诗","lines":["使君来暖东堂席，又见堂前花信息。","小白犹封竹外枝，微黄已点眉间色。","山城十月如春台，闻有细书天上来。","说与横斜応早计，不须更待雪花催。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["莲开欲遍。","一夜秋声转。","残绿断红香片片。","长是西风堪怨。","莫愁家住渓边。","采莲心事年年。","谁管水流花谢，月明昨夜兰船。"],"source":"宋词"},{"title":"知府秘书遣帐下持新诗追路赠行辄次韵寄上","author":"范成大","dynasty":"宋","form":"诗","lines":["冷云去仍来，冻雨落还歇。","平明一篙涨，珍重送船発。","端成南渓泛，宁复东堂谒。","何时公三日，请沢看山笏。","恩勤一未报，终古铭肌骨。","幡幡迹虽远，耿耿心不没。","门阑如水波，永印此孤月。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["沈思暗记。","几许无凭事。","菊靥开残秋少味。","闲却画阑风意。","梦云归处难寻。","微凉暗入香襟。","犹恨那回庭院，依前月浅灯深。"],"source":"宋词"},{"title":"寄上鄙句之明日舟次梅口南枝已有春意复次知府秘书赠行高韵","author":"范成大","dynasty":"宋","form":"诗","lines":["晏温解船去，暮夜檥船歇。","横斜隘梅村，玉蓓粲将発。","城中三辅豪，指日承明谒。","高懐妙康済，未试君前笏。","周南又小春，微温入花骨。","我瞻浮丘亭，山高璇柄没。","飞鸟正飘荡，空绕南枝月。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["莺来燕去。","宋玉墙东路。","草草幽欢能几度。","便有系人心处。","碧天秋月无端。","别来长照关山。","一点恹恹谁会，依前凭暖阑干。"],"source":"宋词"},{"title":"晞真阁留别方道士宾実","author":"范成大","dynasty":"宋","form":"诗","lines":["东山西山双袖舞，中有清宫蟠万础。","云横朱阁碧梧寒，风扫石坛苍桧古。","道人宾実其姓方，来従何许今几霜。","诛蒿仆蓬殿突兀，玉华紫気腾真香。","胸奇腹愤无人识，我独相従似畴昔。","时时苦语见针砭，邂逅天涯得三益。","明朝帰客上帰艎，重到晞真计渺茫。","只有双鱼相问讯，歙江之水通呉江。"],"source":"宋诗"},{"title":"清平乐","author":"晏几道","dynasty":"宋","form":"词","lines":["心期休问。","只有尊前分。","勾引行人添别恨。","因是语低香近。","劝人满酌金锺。","清歌唱彻还重。","莫道后期无定，梦魂犹有相逢。"],"source":"宋词"},{"title":"程助教远饯求诗","author":"范成大","dynasty":"宋","form":"诗","lines":["残山剰水带离亭，送客烦君远作程。","直欲明年撃呉榜，白沙翠竹是柴荆。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["秋千院落重帘暮。","彩笔闲来题绣户。","墙头丹杏雨馀花，门外绿杨风后絮。","朝云信断知何处。","应作襄王春梦去。","紫骝认得旧游踪，嘶过画桥东畔路。"],"source":"宋词"},{"title":"次伯安推官赠别韵","author":"范成大","dynasty":"宋","form":"诗","lines":["交情弥歳竟匆匆，短棹帰寻一亩宫。","塞责文书容我懒，及时杯酒頼君同。","披云峰顶城头月，揽秀堂前扇里风。","千里音书慰离索，莫言天远费鳞鸿。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["小颦若解愁春暮。","一笑留春春也住。","晩红初减谢池花，新翠已遮琼苑路。","湔裙曲水曽相遇。","挽断罗巾容易去。","啼珠弹尽又成行，毕竟心情无会处。"],"source":"宋词"},{"title":"次景琳录事赠别韵","author":"范成大","dynasty":"宋","form":"诗","lines":["放船鸣橹便秦呉，送别空烦长者车。","宿雾锁山常羃羃，断云将雨忽疏疏。","高城五岭花深処，短棹三江木落初。","頼得渓流通尺素，蒲根仍有一双鱼。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["小莲未解论心素。","狂似钿筝弦底柱。","脸边霞散酒初醒，眉上月残人欲去。","旧时家近章台住。","尽日东风吹柳絮。","生憎繁杏绿阴时，正碍粉墙偷眼觑。"],"source":"宋词"},{"title":"次黄必先主簿同年赠别韵二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["当年仗外揖高标，繍䪌芦鞭宝马骄。","琼苑天香飘合坐，碧城山色照同僚。","思帰意决吾张翰，赠别情深子绕朝。","蟹簖鱼梁従此去，他年书札堕烟霄。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["风帘向晓寒成阵。","来报东风消息近。","试从梅蒂紫边寻，更绕柳枝柔处问。","来迟不是春无信。","开晩却疑花有恨。","又应添得几分愁，二十五弦弹未尽。"],"source":"宋词"},{"title":"次黄必先主簿同年赠别韵二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["山郭官闲得烂游，弥年还往话绸缪。","西园剥栗催奴课，东院寻梅勧客留。","笔下修锋千首富，谈间和気両眉浮。","别来怅望何时见，谩上重城谩上楼。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["念奴初唱离亭宴。","会作离声勾别怨。","当时垂泪忆西楼，湿尽罗衣歌未遍。","难逢最是身强健。","无定莫如人聚散。","已拼归袖酔相扶，更恼香檀珍重劝。"],"source":"宋词"},{"title":"次胡経仲知丞赠别韵","author":"范成大","dynasty":"宋","form":"诗","lines":["先生有道抗浮云，拄颊看山意最真。","霜鬓不堪痟首疾，翠蛾常作捧心颦。","官如斯立蓝田小，家似渊明栗里贫。","俯仰别来蓂荚换，只今谁与话情亲。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["玉真能唱朱帘静。","忆在双莲池上听。","百分蕉叶酔如泥，却向断肠声里醒。","夜凉水月铺明镜。","更看娇花闲弄影。","曲终人意似流波，休问心期何处定。"],"source":"宋词"},{"title":"次诸葛伯山赡军赠别韵","author":"范成大","dynasty":"宋","form":"诗","lines":["歙维群山囿，漫仕富英杰。","清标照人寒，玉笋森积雪。","嗟余独委琐，无用等木屑。","又如道傍李，味苦不堪折。","帰舟坐成泛，去马亦已刷。","三年风波険，尽付一笑阅。","惟君同懐抱，各坐天机拙。","我家鸱夷子，竹帛照呉越。","云仍无肖似，𫖯首媿前哲。","若家卧竜公，事业管萧埒。","期君踵祖武，勿惜児女别。","言狂挙白浮，酔倒霜松折。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["阿茸十五腰肢好。","天与怀春风味早。","画眉匀脸不知愁，𣨼酒熏香偏称小。","东城杨柳西城草。","月会花期如意少。","思量心事薄轻云，绿镜台前还自笑。"],"source":"宋词"},{"title":"次韵楽先生除夜三绝  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["団蒲曲几坐成痴，北看南観恍是非。","道眼已空诗眼在，梅花欲动雪花稀。"],"source":"宋诗"},{"title":"木兰花・玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["初心已恨花期晩。","别后相思长在眼。","兰衾犹有旧时香，毎到梦回珠泪满。","多应不信人肠断。","几夜夜寒谁共暖。","欲将恩爱结来生，只恐来生缘又短。"],"source":"宋词"},{"title":"次韵楽先生除夜三绝  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["天辺客里五迎冬，争信还郷似寓公。","人事都非城郭是，独怜鶏犬识新豊。"],"source":"宋诗"},{"title":"减字木兰花","author":"晏几道","dynasty":"宋","form":"词","lines":["长亭晩送。","都似绿窗前日梦。","小字还家。","恰应红灯昨夜花。","良时易过。","半镜流年春欲破。","往事难忘。","一枕高楼到夕阳。"],"source":"宋词"},{"title":"次韵楽先生除夜三绝  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["床头暦日鬓糸糸，懒倦慵吟守歳诗。","宜入新年须吉利，明朝把笔写门楣。"],"source":"宋诗"},{"title":"减字木兰花","author":"晏几道","dynasty":"宋","form":"词","lines":["留春不住。","恰似年光无味处。","满眼飞英。","弹指东风太浅情。","筝弦未稳。","学得新声难破恨。","转枕花前。","且占香红一夜眠。"],"source":"宋词"},{"title":"次韵唐幼度客中幼度相别数年复会于銭塘湖上","author":"范成大","dynasty":"宋","form":"诗","lines":["西湖冰泮绿生鳞，料峭东风欲中人。","花片不禁寒食雨，鬓糸犹那涌金春。","江山契阔诗情在，京洛追随客梦新。","唤取歌声不愁思，为君吹水引杯频。"],"source":"宋诗"},{"title":"减字木兰花","author":"晏几道","dynasty":"宋","form":"词","lines":["长杨辇路。","绿满当年携手处。","试逐春风。","重到宫花花树中。","芳菲绕遍。","今日不如前日健。","酒罢凄凉。","新恨犹添旧恨长。"],"source":"宋词"},{"title":"客中呈幼度","author":"范成大","dynasty":"宋","form":"诗","lines":["手板头衔意已慵，墨池书枕兴无穷。","醸泥深巷五更雨，吹酒小楼三面风。","草色有无春最好，客心去住水长东。","今朝合有家书到，昨夜灯花缀玉虫。"],"source":"宋诗"},{"title":"泛清波摘遍","author":"晏几道","dynasty":"宋","form":"词","lines":["催花雨小，着柳风柔，都似去年时候好。","露红烟绿，尽有狂情斗春早。","长安道。","秋千影里，丝管声中，谁放艳阳轻过了。","倦客登临，暗惜光阴恨多少。","楚天渺。","归思正如乱云，短梦未成芳草。","空把吴霜鬓华，自悲清晓。","帝城杳。","双凤旧约渐虚，孤鸿后期难到。","且趁朝花夜月，翠尊频倒。"],"source":"宋词"},{"title":"奠唐少梁晋仲兄弟墓下","author":"范成大","dynasty":"宋","form":"诗","lines":["当年连璧気如蜺，人许跻攀九列斉。","黄壌一时埋玉树，青云何処用丹梯。","生平书札频双鲤，歳晩交情但只鶏。","眼底伤心难制涙，宁论宿草已萋萋。"],"source":"宋诗"},{"title":"洞仙歌","author":"晏几道","dynasty":"宋","form":"词","lines":["春残雨过，绿暗东池道。","玉艳蔵羞媚赪笑。","记当时、已恨飞镜欢疏，那至此，仍苦题花信少。","连环情未己，物是人非，月下疏梅似伊好。","澹秀色，黯寒香，粲若春容，何心顾、闲花凡草。","但莫使、情随岁华迁，便杳隔秦源，也须能到。"],"source":"宋词"},{"title":"镇东行送汤丞相帅绍兴","author":"范成大","dynasty":"宋","form":"诗","lines":["呉波鳞鳞越山紫，镇东旌旆东风里。","前駆伝道相君来，一夜鉴湖春涨起。","鉴湖如鉴涵空明，相君出処如湖清。","十年勲业泰山重，五鼎富贵浮云軽。","人言公如裴相国，绿野堂高贮风月。","我独愿公如子牟，身在江湖心魏阙。","浯渓有石高嵯峨，公方东征如此何。","丁宁湖水莫断渡，早晩帰来绝江去。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["来时杨柳东桥路。","曲中暗有相期处。","明月好因缘。","欲圆还未圆。","欲寻芳草去。","画扇遮微雨。","飞絮莫无情。","闲花应笑人。"],"source":"宋词"},{"title":"水月庵谒现老不值","author":"范成大","dynasty":"宋","form":"诗","lines":["有客叩巌扃，无人管送迎。","片云闲出岫，水月自空明。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["个人轻似低飞燕。","春来绮陌时相见。","堪恨两横波。","恼人情绪多。","长留青鬓住。","莫放红颜去。","占取艳阳天。","且教伊少年。"],"source":"宋词"},{"title":"次韵辺公弁","author":"范成大","dynasty":"宋","form":"诗","lines":["错落参旗罥竹梢，柴荆临水闭蓬蒿。","春风吹暁玉蟾堕，秾露洗空银汉高。","双鹊绕枝応也倦，一蛩吟壁已能豪。","新秋只合添诗兴，莫学潘郎叹二毛。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["鸾啼似作留春语。","花飞斗学回风舞。","红日又平西。","画帘遮燕泥。","烟光还自老。","绿镜人空好。","香在去年衣。","鱼笺音信稀。"],"source":"宋词"},{"title":"中秋无月复次韵","author":"范成大","dynasty":"宋","form":"诗","lines":["屋山従卷杜陵茅，门径慵芟仲蔚蒿。","澹澹白虹风晕壮，纷纷苍狗雨云高。","凌空累筯仙无术，半夜撞钟句谩豪。","枵腹题诗将底用，真成兔角与亀毛。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["春风未放花心吐。","尊前不拟分明语。","酒色上来迟。","绿须红杏枝。","今朝眉黛浅。","暗恨归时远。","前夜月当楼。","相逢南陌头。"],"source":"宋词"},{"title":"公弁用前韵见赠复次韵","author":"范成大","dynasty":"宋","form":"诗","lines":["先生笔力玉山鼇，気圧明堂一柱蒿。","雪椀涤毫词绝妙，朱弦缩瑟调弥高。","心兵不起无三粲，坐客常多似四豪。","喜有过従南北巷，苏兰薪桂瀹渓毛。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["娇香淡染胭脂雪。","愁春细画弯弯月。","花月镜边情。","浅妆匀未成。","佳期应有在。","试倚秋千待。","满地落英红。","万条杨柳风。"],"source":"宋词"},{"title":"公弁再赠复次韵","author":"范成大","dynasty":"宋","form":"诗","lines":["书生活计极萧騒，爝火微明似束蒿。","犬子地寒徒壁立，元竜身懒谩楼高。","笔端未办夸三绝，酒里犹能扫二豪。","又向诗坛蕲借一，强磨铅钝歯吹毛。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["香莲烛下匀丹雪。","妆成笑弄金阶月。","娇面胜芙蓉。","脸边天与红。","玳筵双掲鼓。","唤上华茵舞。","春浅未禁寒。","暗嫌罗袖宽。"],"source":"宋词"},{"title":"送施元光赴江西幕府","author":"范成大","dynasty":"宋","form":"诗","lines":["镇南旌旆照江臯，入幕如今客最高。","月暗秋城稀撃柝，云飞朝栋賸挥毫。","长亭酒尽歌三畳，半夜渓深雨一篙。","莫恋阳関更西路，九関帰路踏金鼇。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["哀筝一弄湘江曲。","声声写尽湘波绿。","纤指十三弦。","细将幽恨传。","当筵秋水慢。","玉柱斜飞雁。","弹到断肠时。","春山眉黛低。"],"source":"宋词"},{"title":"次韵林子章阻浅留滞","author":"范成大","dynasty":"宋","form":"诗","lines":["客行端似未帰云，指点璇杓几易辰。","喜有风花黄作晕，似闻渓涨绿生鳞。","我従走俗言无味，君已鸣文笔有神。","繍段炳然空辱赠，急繙缇袭扫蛛尘。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["江南未雪梅花白。","忆梅人是江南客。","犹记旧相逢。","淡烟微月中。","玉容长有信。","一笑归来近。","怀远上楼时。","晩云和雁低。"],"source":"宋词"},{"title":"次韵马少伊木犀  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["月窟飞来露已凉，断无尘格惹蜂黄。","繊繊绿裹排金粟，何処能容九里香。"],"source":"宋诗"},{"title":"菩萨蛮","author":"晏几道","dynasty":"宋","form":"词","lines":["相逢欲话相思苦。","浅情肯信相思否。","还恐漫相思。","浅情人不知。","忆曽携手处。","月满窗前路。","长到月来时。","不眠犹待伊。"],"source":"宋词"},{"title":"次韵马少伊木犀  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["水尾山腰树影苍，一天风露不供香。","谁家镜里能消得，付与诗人古锦囊。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["雕鞍好为莺花住。","占取东城南陌路。","尽教春思乱如云，莫管世情轻似絮。","古来多被虚名误。","宁负虚名身莫负。","劝君频入酔乡来，此是无愁无恨处。"],"source":"宋词"},{"title":"次韵马少伊木犀  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["密密娇黄侍翠舆，避风遮日小扶疏。","画阑想见悬秋晩，无限宫香総不如。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["一尊相遇春风里。","诗好似君人有几。","吴姬十五语如弦，能唱当时楼下水。","良辰易去如弹指。","金盏十分须尽意。","明朝三丈日高时，共拼酔头扶不起。"],"source":"宋词"},{"title":"林夫人挽词","author":"范成大","dynasty":"宋","form":"诗","lines":["翰墨门阑正岿然，故応婉娩亦儒先。","与闻古学三千礼，能诵家书四百篇。","卜协妫姜占永世，梦呼辰巳谶凋年。","班姬合有遗文在，后日従容访孟坚。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["琼酥酒面风吹醒。","一缕斜红临晩镜。","小颦微笑尽妖娆，浅注轻匀长淡净。","手挪梅蕊寻香径。","正是佳期期未定。","春来还为个般愁，痩损宫腰罗带剰。"],"source":"宋词"},{"title":"李仲镇懒窝","author":"范成大","dynasty":"宋","form":"诗","lines":["求名当着鞭，访道亦重趼。","二辺俱不住，三昧不如懒。","向来南岳师，自谓极萧散。","収涕且无绪，客至那可款。","争如懒窝高，门外辙常満。","殊不妨啸歌，秉烛苦夜短。","天寒雪欲花，屋角黄云晩。","径须烦二妙，対洗玻瓈盏。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["清歌学得秦娥似。","金屋瑶台知姓字。","可怜春恨一生心，长带粉痕双袖泪。","从来懒话低眉事。","今日新声谁会意。","坐中应有赏音人，试问回肠曽断未。"],"source":"宋词"},{"title":"次韵陈季陵寺丞求歙石眉子砚","author":"范成大","dynasty":"宋","form":"诗","lines":["金星荧荧眉子绿，婺源琢石如琢玉。","宝玩何曽捄枵腹，但爱文君远山蹙。","文人笔阵森五兵，书品入妙仍诗名。","我有陂陀天海様，与公文本俱金声。","枭卢一掷不须呼，况敢定価论车渠。","只烦将到妆台下，试比何如京兆画。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["旗亭西畔朝云住。","沈水香烟长满路。","柳阴分到画眉边，花片飞来垂手处。","妆成尽任秋娘妒。","袅袅盈盈当绣户。","临风一曲酔朦腾，陌上行人凝恨去。"],"source":"宋词"},{"title":"次韵季陵贡院新晴","author":"范成大","dynasty":"宋","form":"诗","lines":["锁闱令厳深复深，五星帘幕晴若阴。","澹云微月谩清夜，短檠政自関人心。","看灯作晕生睡色，江南行処梦不隔。","覚来快読新晴篇，怳然寘我鶑花前。","径欲觞公后堂酒，倘烦春衫小垂手。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["离鸾照罢尘生镜。","几点吴霜侵绿鬓。","琵琶弦上语无凭，豆蔻梢头春有信。","相思拼损朱颜尽。","天若多情终欲问。","雪窗休记夜来寒，桂酒已消人去恨。"],"source":"宋词"},{"title":"次韵周子充正字馆中绯碧両桃花","author":"范成大","dynasty":"宋","form":"诗","lines":["碧城香雾赤城霞，深出刘郎未见花。","凭仗天风扶绛节，为招萼绿过羊家。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["东风又作无情计。","艳粉娇红吹满地。","碧楼帘影不遮愁，还似去年今日意。","谁知错管春残事。","到处登临曽费泪。","此时金盏直须深，看尽落花能几酔。"],"source":"宋词"},{"title":"明日子充折赠次韵谢之","author":"范成大","dynasty":"宋","form":"诗","lines":["海上三山冠彩霞，六时高会雨天花。","歩虚声里随风下，吹落寻常百姓家。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["斑骓路与阳台近。","前度无题初借问。","暖风鞭袖尽闲垂，微月帘栊曽暗认。","梅花未足凭芳信。","弦语岂堪传素恨。","翠眉饶似远山长，寄与此愁颦不尽。"],"source":"宋词"},{"title":"明日大雨复折赠再次韵","author":"范成大","dynasty":"宋","form":"诗","lines":["一天云叶翳朝霞，风巻泥沾不惜花。","群玉山高春好在，人间烟雨暗千家。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["红绡学舞腰肢软。","旋织舞衣宫样染。","织成云外雁行斜，染作江南春水浅。","露桃宫里随歌管。","一曲霓裳红日晩。","归来双袖酒成痕，小字香笺无意展。"],"source":"宋词"},{"title":"张恭甫正字折赠馆中碧桃因次子充韵","author":"范成大","dynasty":"宋","form":"诗","lines":["満枝晴雪照青霞，旧识桃源晕碧花。","俯仰京尘隔年梦，东风犹认故人家。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["当年信道情无价。","桃叶尊前论别夜。","脸红心绪学梅妆，眉翠工夫如月画。","来时酔倒旗亭下。","知是阿谁扶上马。","忆曽挑尽五更灯，不记临分多少话。"],"source":"宋词"},{"title":"雨中报谒呈刘韶美侍郎","author":"范成大","dynasty":"宋","form":"诗","lines":["花落満城雨，雨余云重阴。","駆车有底急，巷泥三尺深。","平生黄篾舫，渔榔有清音。","斗升得苦相，懐刺冲愁霖。","帰来掩関卧，一枕直兼金。","作诗诧比邻，幸勿讥褊心。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["采莲时候慵歌舞。","永日闲从花里度。","暗随苹末晓风来，直待柳梢斜月去。","停桡共说江头路。","临水楼台苏小住。","细思巫峡梦回时，不减秦源肠断处。"],"source":"宋词"},{"title":"雨中集水月","author":"范成大","dynasty":"宋","form":"诗","lines":["献之今年不堪暑，天亦相怜病良苦。","明便中秋法合凉，夜半行云暁行雨。","蕲州竹簟清如冰，饥蚊倔强犹鸣声。","下床蚤喜衣裳健，出门更覚山川明。","曳屐扶藜寻水月，不惜垂垂巾角折。","竹间松下已凄然，却要芳樽生暖热。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["芳年正是香英嫩。","天与娇波长入鬓。","蕊珠宫里旧承恩，夜払银屏朝把镜。","云情去住终难信。","花意有无休更问。","酔中同尽一杯欢，归后各成孤枕恨。"],"source":"宋词"},{"title":"送洪景卢内翰使虏二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["金章玉色照离亭，戦伐和亲决此行。","国有威霊双节重，家伝忠义一身軽。","平生海内文场伯，今日胸中武库兵。","万里往来公有相，淮𣸣阴徳贯神明。"],"source":"宋诗"},{"title":"玉楼春","author":"晏几道","dynasty":"宋","form":"词","lines":["轻风払柳冰初绽。","细雨消尘云未散。","红窗青镜待妆梅，绿陌高楼催送雁。","华罗歌扇金蕉盏。","记得寻芳心绪惯。","凤城寒尽又飞花，岁岁春光常有限。"],"source":"宋词"},{"title":"送洪景卢内翰使虏二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["檄到中原杀気销，穹庐那敢说天骄。","今年蕃始来和汉，即日燕当远徙辽。","北土未干遗老涙，西陵応望孝孙朝。","着鞭往矣功名会，麟阁丹青上九霄。"],"source":"宋诗"},{"title":"阮郎归","author":"晏几道","dynasty":"宋","form":"词","lines":["粉痕闲印玉尖纤。","啼红傍晩奁。","旧寒新暖尚相兼。","梅疏待雪添。","春冉冉，恨恹恹。","章台对巻帘。","个人鞭影弄凉蟾。","楼前侧帽檐。"],"source":"宋词"},{"title":"次韵厳子文旅中见赠","author":"范成大","dynasty":"宋","form":"诗","lines":["杯中畴昔共江天，倾座新诗报警连。","海浦寸心空共月，京华双鬓各凋年。","交情敢说同方友，句法甘従弟子员。","有意数従文本饮，何须争着祖生鞭。"],"source":"宋诗"},{"title":"阮郎归","author":"晏几道","dynasty":"宋","form":"词","lines":["来时红日弄窗纱。","春红入睡霞。","去时庭树欲栖鸦。","香屏掩月斜。","収翠羽，整妆华。","青骊信又差。","玉笙犹恋碧桃花。","今宵未忆家。"],"source":"宋词"},{"title":"次韵子文客舎小楼","author":"范成大","dynasty":"宋","form":"诗","lines":["客里仍携一束书，闭门虹気自凌虚。","未闻光范延珠履，谁向甘泉従玉车。","散尽生涯千答布，収将文価百车渠。","淹留且结西湖夏，同到秋风赋遂初。"],"source":"宋诗"},{"title":"阮郎归","author":"晏几道","dynasty":"宋","form":"词","lines":["旧香残粉似当初。","人情恨不如。","一春犹有数行书。","秋来书更疏。","衾凤冷，枕鸳孤。","愁肠待酒舒。","梦魂纵有也成虚。","那堪和梦无。"],"source":"宋词"},{"title":"次韵刘韶美大风雨壊门屋","author":"范成大","dynasty":"宋","form":"诗","lines":["云烟挥翰墨池翻，缃缥如山昼掩関。","已许六丁収散落，只愁雷电费墙藩。"],"source":"宋诗"},{"title":"阮郎归","author":"晏几道","dynasty":"宋","form":"词","lines":["天边金掌露成霜。","云随雁字长。","绿杯红袖称重阳。","人情似故乡。","兰佩紫，菊簪黄。","殷勤理旧狂。","欲将沈酔换悲凉。","清歌莫断肠。"],"source":"宋词"},{"title":"洪景卢内翰使还入境以诗迓之","author":"范成大","dynasty":"宋","form":"诗","lines":["玉帛干戈汹并驰，孤臣叱驭触危机。","関山无极申舟去，天地有情苏武帰。","汉月凌秋随使节，胡尘卷暑避征衣。","国人渇望公颜色，为报褰帷入帝畿。"],"source":"宋诗"},{"title":"阮郎归","author":"晏几道","dynasty":"宋","form":"词","lines":["晩妆长趁景阳钟。","双蛾着意浓。","舞腰浮动绿云浓。","樱桃半点红。","怜美景，惜芳容。","沈思暗记中。","春寒帘幕几重重。","杨花尽日风。"],"source":"宋词"},{"title":"寄题向抚州采菊亭","author":"范成大","dynasty":"宋","form":"诗","lines":["一叶起秋色，众绿凋歳华。","耿耿霜露侧，余此黄金葩。","西风満天地，孤芳照尘沙。","殷勤开小筑，花気日夕嘉。","落英楚累手，东篱陶令家。","両穷偶寓意，岂必真爱花。","不如亭中人，一笑了天涯。","采采勿虚度，门前欲高牙。"],"source":"宋诗"},{"title":"归田乐","author":"晏几道","dynasty":"宋","form":"词","lines":["试把花期数。","便早有、感春情绪。","看即梅花吐。","愿花更不谢，春且长住。","只恐花飞又春去。","花开还不语。","问此意、年年春还会否。","绛唇青鬓，渐少花前语。","对花又记得、旧曽游处。","门外垂杨未飘絮。"],"source":"宋词"},{"title":"古风二首上汤丞相  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["抱瑟游孔门，岂识宫与商。","古曲一再行，乃雑巴人倡。","知音顾之笑，解弦为更张。","帰来掩関卧，冰炭交愁肠。","平生桑濮手，未省歌虞唐。","明発理朱糸，复登君子堂。","遗音入三叹，山高水汤汤。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["二月春花厌落梅。","仙源归路碧桃催。","渭城丝雨劝离杯。","欢意似云真薄幸，客鞭摇柳正多才。","凤楼人待锦书来。"],"source":"宋词"},{"title":"古风二首上汤丞相  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["空山学仙子，穷年卧巌扃。","煮石不得饱，秋鬓苍已星。","道逢紫霄翁，示我餐霞経。","采采晨之华，涤濯腐与腥。","向来役薪水，终然槁柴荆。","跪谢起再拝，飘飖蜕蝉軽。","飞升那敢学，倘许学长生。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["卧鸭池头小苑开。","暄风吹尽北枝梅。","柳长莎软路萦回。","静避绿阴莺有意，漫随游骑絮多才。","去年今日忆同来。"],"source":"宋词"},{"title":"冷泉亭放水","author":"范成大","dynasty":"宋","form":"诗","lines":["古苔危磴着枯藜，脚底翻涛汹欲飞。","九陌倦游那有此，従教惊雪溅尘衣。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["二月和风到碧城。","万条千缕绿相迎。","舞烟眠雨过清明。","妆镜巧眉偷叶样，歌楼妍曲借枝名。","晩秋霜霰莫无情。"],"source":"宋词"},{"title":"九月十日南山见梅","author":"范成大","dynasty":"宋","form":"诗","lines":["五斗留连首屡回，来寻南涧濯尘埃。","春风直恐渊明去，借与横斜対菊开。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["白纻春衫杨柳鞭。","碧蹄骄马杏花鞯。","落英飞絮冶游天。","南陌暖风吹舞榭，东城凉月照歌筵。","赏心多是酒中仙。"],"source":"宋词"},{"title":"送汪圣锡侍郎帅福唐","author":"范成大","dynasty":"宋","form":"诗","lines":["承明才入又南州，重见旌旗照柁楼。","道义平生无捷径，风波随処有虚舟。","如公未可违文石，稽古何妨欠碧油。","我亦登门烦着录，此行无力为王留。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["床上银屏几点山。","鸭炉香过琐窗寒。","小云双枕恨春闲。","惜别漫成良夜酔，解愁时有翠笺还。","那回分袂月初残。"],"source":"宋词"},{"title":"送王纯白郎中赴闽漕","author":"范成大","dynasty":"宋","form":"诗","lines":["声利场中百戦鏖，今谁勇退似公豪。","缓寻南粤千山路，先破西兴百尺涛。","平日曼容嫌禄厚，他年文本叹官高。","才名政尔帰安往，富贵追踪未可逃。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["绿柳蔵乌静掩关。","鸭炉香细琐窗闲。","那回分袂月初残。","惜别漫成良夜酔，解愁时有翠笺还。","欲寻双叶寄情难。"],"source":"宋词"},{"title":"长至日与同舎游北山","author":"范成大","dynasty":"宋","form":"诗","lines":["歳晩山同色，湖平雾不収。","寒云低阁雪，佳节静供愁。","竹柏森厳立，蒲荷索莫休。","痩笻知脚力，政尔耐清游。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["家近旗亭酒易酤。","花时长得酔工夫。","伴人歌笑懒妆梳。","户外绿杨春系马，床前红烛夜呼卢。","相逢还解有情无。"],"source":"宋词"},{"title":"次韵尹少稷察院九宫坛斎宿","author":"范成大","dynasty":"宋","form":"诗","lines":["草草驰三里，萧萧共一餐。","吏方绵礼𫈵，公自将诗坛。","隙月窥床近，窗风刮坐寒。","鸦鸣未忍散，端为四并难。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["日日双眉斗画长。","行云飞絮共轻狂。","不将心嫁冶游郎。","溅酒滴残歌扇字，弄花熏得舞衣香。","一春弹泪说凄凉。"],"source":"宋词"},{"title":"冬祠太乙六言四首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["三一旧伝神呪，十神今済时艰。","愿挽霊旗北指，为君直捣阴山。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["飞鹊台前晕翠蛾。","千金新换绛仙螺。","最难加意为颦多。","几处睡痕留酔袖，一春愁思近横波。","远山低尽不成歌。"],"source":"宋词"},{"title":"冬祠太乙六言四首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["月色胧明碧瓦，蝋烟浮动黄帘。","罡骑飚轮欲下，一天飞霰繊繊。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["午酔西桥夕未醒。","雨花凄断不堪听。","归时应减鬓边青。","衣化客尘今古道，柳含春意短长亭。","凤楼争见路旁情。"],"source":"宋词"},{"title":"冬祠太乙六言四首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["云木栖乌未动，风庭警鹤先鸣。","残夜百霊夙驾，人间鼻息雷惊。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["一样宫妆簇彩舟。","碧罗团扇自障羞。","水仙人在镜中游。","腰自细来多态度，脸因红处转风流。","年年相遇绿江头。"],"source":"宋词"},{"title":"冬祠太乙六言四首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["行道羽衣缥缈，卷班玉珮冬珑。","回首金舗獣面，歩虚声在天风。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["已拆秋千不奈闲。","却随胡蝶到花间。","旋寻双叶挿云鬟。","几折湘裙烟缕细，一钩罗袜素蟾弯。","绿窗红豆忆前欢。"],"source":"宋词"},{"title":"次韵李子永雪中长句","author":"范成大","dynasty":"宋","form":"诗","lines":["黄昏苦寒乌鸟稀，吹沙走石交横飞。","布衾如鉄复似水，梦想东风来解囲。","岂知天地有奇事，夜半窗纸生光辉。","兜罗宝界仏所现，冥凌不敢専璇玑。","开门倚杖眩一色，迥立此世空无依。","少年行楽怳尚记，瑶林珠树中成蹊。","犬骄鹰俊马蹄快，狡穴未尽须穷追。","湖海粗豪今岂在，但忆鸣哮如饿鸱。","北邻亦复淡生活，要我忍寒吟此诗。","手亀笔退不可捉，墨泓龃龉冰生衣。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["闲弄筝弦懒系裙。","铅华消尽见天真。","眼波低处事还新。","怅恨不逢如意酒，寻思难值有情人。","可怜虚度琐窗春。"],"source":"宋词"},{"title":"次韵子永见赠建除体","author":"范成大","dynasty":"宋","form":"诗","lines":["建子玉杓直，黄昏月如霜。","除道启柴扃，客来巾履忙。","満炷寒缸油，共此书檠光。","平生卜邻愿，何意登我堂。","定交吾岂敢，南栄惭伯阳。","执手道古作，遗篇记河梁。","破窗风鸣悲，孤客多慨伤。","危肠不捄饥，我诗安得昌。","成章类村歌，但可侣牛羊。","収功翰墨薮，微子谁能良。","开巻得雅音，玉銮导旗常。","闭戸坐相念，雪深梅暗香。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["团扇初随碧簟収。","画檐归燕尚迟留。","靥朱眉翠喜清秋。","风意未应迷狭路，灯痕犹自记高楼。","露花烟叶与人愁。"],"source":"宋词"},{"title":"与胡経仲陈朋元游照山堂梅数百株盛开","author":"范成大","dynasty":"宋","form":"诗","lines":["九陌缁尘満客襟，銭塘门外有园林。","胡床住処梅无限，酒旆垂辺柳未深。","晴日暖风千里目，残山剰水一人心。","元方伯始皆吾党，解后清游直万金。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["翠阁朱阑倚处危。","夜凉闲捻彩箫吹。","曲中双凤已分飞。","绿酒细倾消别恨，红笺小写问归期。","月华风意似当时。"],"source":"宋词"},{"title":"次韵胡邦衡秘监","author":"范成大","dynasty":"宋","form":"诗","lines":["斯言向来立，千古敢疵瑕。","有命孤蓬転，何心劲箭加。","人穷名満世，天定客还家。","回首冥恩怨，虚空不着花。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["唱得红梅字字香。","柳枝桃叶尽深蔵。","遏云声里送雕觞。","才听便拼衣袖湿，欲歌先倚黛眉长。","曲终敲损燕钗梁。"],"source":"宋词"},{"title":"三月四日骤煖","author":"范成大","dynasty":"宋","form":"诗","lines":["日脚融晴晩気暄，睡余初覚薄罗便。","如何柳絮沾泥処，煖似槐阴転午天。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["小杏春声学浪仙。","疏梅清唱替哀弦。","似花如雪绕琼筵。","腮粉月痕妆罢后，脸红莲艳酒醒前。","今年水调得人怜。"],"source":"宋词"},{"title":"久雨地湿","author":"范成大","dynasty":"宋","form":"诗","lines":["汗础経旬未肯干，破窗随処有蜗涎。","只今不耐春阴得，想见黄梅细雨天。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["铜虎分符领外台。","五云深处彩旌来。","春随红旆过长淮。","千里裤襦添旧暖，万家桃李间新栽。","使星回首是三台。"],"source":"宋词"},{"title":"昼锦行送陈福公判信州","author":"范成大","dynasty":"宋","form":"诗","lines":["汉家麟阁多王侯，冠佩相望経几秋。","昼锦声名両栄耀，惟有信州如相州。","国南门头折杨柳，借问江津垂白叟。","住在行都四十年，曽见帰舟似公否。","人言公与赤松期，飚车羽轮来何时。","云出云帰俱是道，苦学赤松还未妙。","君不见补陀大士海复山，随喜却来観世间。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["浦口莲香夜不収。","水边风里欲生秋。","棹歌声细不惊鸥。","凉月送归思往事，落英飘去起新愁。","可堪题叶寄东楼。"],"source":"宋词"},{"title":"送张真甫中书奉祠帰蜀","author":"范成大","dynasty":"宋","form":"诗","lines":["种成桃李恰新阴，忽忆家山丛桂林。","客路莫嫌帰计拙，春江争似骇机深。","一封朝奏钧天梦，万里江行魏阙心。","后日还朝饱风露，黒头応有雪糸侵。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["莫问逢春能几回。","能歌能笑是多才。","露花犹有好枝开。","绿鬓旧人皆老大，红梁新燕又归来。","尽须珍重掌中杯。"],"source":"宋词"},{"title":"送周子充左史奉祠帰庐陵","author":"范成大","dynasty":"宋","form":"诗","lines":["黄鹄飘然下九関，江船载月客俱还。","名高岂是孤臣愿，身退聊开壮士颜。","倾盖当年真旦暮，沾巾明日有河山。","后期淹速都难料，相対犹怜鬓未斑。"],"source":"宋诗"},{"title":"浣渓沙","author":"晏几道","dynasty":"宋","form":"词","lines":["楼上灯深欲闭门。","梦云归去不留痕。","几年芳草忆王孙。","向日阑干依旧绿，试将前事倚黄昏。","记曽来处易消魂。"],"source":"宋词"},{"title":"送陈天予大监同年使闽","author":"范成大","dynasty":"宋","form":"诗","lines":["春関十载记英游，蚤喜时才近采旒。","夷路着鞭方逸驾，急流回首忽扁舟。","云霄正穏君犹去，尘土无辺我合休。","问讯后车容客否，茶山茘浦看南州。"],"source":"宋诗"},{"title":"六幺令","author":"晏几道","dynasty":"宋","form":"词","lines":["绿阴春尽，飞絮绕香阁。","晩来翠眉宫样，巧把远山学。","一寸狂心未说，已向横波觉。","画帘遮币。","新翻曲妙，暗许闲人带偷掏。","前度书多隐语，意浅愁难答。","昨夜诗有回纹，韵险还慵押。","都待笙歌散了，记取留时霎。","不消红蜡。","闲云归后，月在庭花旧阑角。"],"source":"宋词"},{"title":"送陆务観编修监镇江郡帰会稽待阙  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["宝马天街路，烟篷海浦心。","非関爱京口，自是忆山阴。","高兴余飞动，孤忠有照临。","浮云付舒巻，知子道根深。"],"source":"宋诗"},{"title":"六幺令","author":"晏几道","dynasty":"宋","form":"词","lines":["雪残风信，悠扬春消息。","天涯倚楼新恨，杨柳几丝碧。","还是南云雁少，锦字无端的。","宝钗瑶席。","彩弦声里，拼作尊前未归客。","遥想疏梅此际，月底香英白。","别后谁绕前渓，手拣繁枝摘。","莫道伤高恨远，付与临风笛。","尽堪愁寂。","花时往事，更有多情个人忆。"],"source":"宋词"},{"title":"送陆务観编修监镇江郡帰会稽待阙  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["见说云门好，全家住翠微。","京尘成歳晩，江雨送人帰。","辺锁风雷动，军书日夜飞。","功名袖中手，世事巧相违。"],"source":"宋诗"},{"title":"六幺令","author":"晏几道","dynasty":"宋","form":"词","lines":["日高春睡，唤起懒装束。","年年落花时候，惯得娇眠足。","学唱宫梅便好，更暖银笙逐。","黛蛾低绿。","堪教人恨，却似江南旧时曲。","常记东楼夜雪，翠幕遮红烛。","还是芳酒杯中，一酔光阴促。","曽笑阳台梦短，无计怜香玉。","此欢难续。","乞求歌罢，借取归云画堂宿。"],"source":"宋词"},{"title":"送李仲镇宰溧阳","author":"范成大","dynasty":"宋","form":"诗","lines":["相逢已叹十年遅，冷淡贫交又语离。","玉笋换班通籍后，黄梅催雨送帆时。","月巌家世犹为県，金瀬渓山好赋诗。","唤起酸寒孟东野，倒流三峡洗余悲。"],"source":"宋诗"},{"title":"更漏子","author":"晏几道","dynasty":"宋","form":"词","lines":["槛花稀，池草遍。","冷落吹笙庭院。","人去日，燕西飞。","燕归人未归。","数书期，寻梦意。","弹指一年春事。","新怅望，旧悲凉。","不堪红日长。"],"source":"宋词"},{"title":"送呉元茂丞浦江","author":"范成大","dynasty":"宋","form":"诗","lines":["玉笋翻乗県佐车，飘然不肯待新除。","才名已被人争说，官薄何妨计小疏。","忆昨西湖同我载，従今南浦望君书。","遥知敛板趋风后，始覚丞哉果负予。"],"source":"宋诗"},{"title":"更漏子","author":"晏几道","dynasty":"宋","form":"词","lines":["柳间眠，花里酔。","不惜绣裙铺地。","钗燕重，鬓蝉轻。","一双梅子青。","粉笺书，罗袖泪。","还有可怜新意。","遮闷绿，掩羞红。","晩来团扇风。"],"source":"宋词"},{"title":"雪晴呈子永","author":"范成大","dynasty":"宋","form":"诗","lines":["碧空无処泊同云，晴入荒园鸟雀驯。","冰面小风池欲动，雪辺浓日瓦如薫。","尘容俗状长为客，冷蕊疏枝又作春。","诗巻岂能生暖热，犯寒聊复悩比邻。"],"source":"宋诗"},{"title":"更漏子","author":"晏几道","dynasty":"宋","form":"词","lines":["柳丝长，桃叶小。","深院断无人到。","红日淡，绿烟晴。","流莺三两声。","雪香浓，檀晕少。","枕上卧枝花好。","春思重，晓妆迟。","寻思残梦时。"],"source":"宋词"},{"title":"次韵子永雪后见赠","author":"范成大","dynasty":"宋","form":"诗","lines":["雪瓴待伴半阴晴，竟日檐冰溜雨声。","九陌泥干尘未动，南山石露塔犹明。","稍闻吉语占农事，便覚帰心胜宦情。","想得秫田来歳好，瓦盆加醸灌愁城。"],"source":"宋诗"},{"title":"更漏子","author":"晏几道","dynasty":"宋","form":"词","lines":["露华高，风信远。","宿酔画帘低巻。","梳洗倦，冶游慵。","绿窗春睡浓。","彩条轻，金缕重。","昨日小桥相送。","芳草恨，落花愁。","去年同倚楼。"],"source":"宋词"},{"title":"次韵郊祀庆成","author":"范成大","dynasty":"宋","form":"诗","lines":["帝徳重尧绪，天心与舜禋。","庆期符后甲，元日际初辛。","土纬扶南极，旄胡拱北辰。","律谐风自艮，衡正斗垂寅。","桂燎霊宫暁，萧脂太室晨。","百神森壁塁，万卫密钩陈。","日月青旗色，雷霆玉辂尘。","洗兵银汉水，収雪紫坛春。","天歩临黄道，仙班像玉宸。","陶匏宗素朴，琮璧慕精纯。","秘祝裒时対，高斿欻下宾。","金钟鸣杰簴，朱火熭芳薪。","日丽鶏竿矗，天旋凤律新。","端门敷锡后，六合共𬘡缊。"],"source":"宋诗"},{"title":"更漏子","author":"晏几道","dynasty":"宋","form":"词","lines":["出墙花，当路柳。","借问芳心谁有。","红解笑，绿能颦。","千般恼乱春。","北来人，南去客。","朝暮等闲攀折。","怜晩秀，惜残阳。","情知枉断肠。"],"source":"宋词"},{"title":"従巨済乞蝋梅","author":"范成大","dynasty":"宋","form":"诗","lines":["寂寥人在暁鶏窗，苦忆花前続断肠。","全树折来応不惜，君家真色自生香。"],"source":"宋诗"},{"title":"更漏子","author":"晏几道","dynasty":"宋","form":"词","lines":["欲论心，先掩泪。","零落去年风味。","闲卧处，不言时。","愁多只自知。","到情深，俱是怨。","惟有梦中相见。","犹似旧，奈人禁。","偎人说寸心。"],"source":"宋词"},{"title":"次韵朋元売花処见梅","author":"范成大","dynasty":"宋","form":"诗","lines":["烟浓日淡不多寒，担上看花雪作団。","想得竹辺春已暗，明朝走马过渓看。"],"source":"宋诗"},{"title":"河满子","author":"晏几道","dynasty":"宋","form":"词","lines":["对镜偷匀玉箸，背人学写银钩。","系谁红豆罗带角，心情正着春游。","那日杨花陌上，多时杏子墙头。","眼底关山无奈，梦中云雨空休。","问看几许怜才意，两蛾蔵尽离愁。","难拼此回肠断，终须锁定红楼。"],"source":"宋词"},{"title":"与正夫朋元游陈侍御园","author":"范成大","dynasty":"宋","form":"诗","lines":["沙际春风卷物华，意行聊复到君家。","年年我是曽来客，処処梅皆旧识花。","官减不妨诗事业，地寒犹办酔生涯。","城中马上那知此，尘満长裾席帽斜。"],"source":"宋诗"},{"title":"河满子","author":"晏几道","dynasty":"宋","form":"词","lines":["绿绮琴中心事，齐纨扇上时光。","五陵年少浑薄幸，轻如曲水飘香。","夜夜魂消梦峡，年年泪尽啼湘。","归雁行边远字，惊鸾舞处离肠。","蕙楼多少铅华在，从来错倚红妆。","可羡邻姬十五，金钗早嫁王昌。"],"source":"宋词"},{"title":"正月十四日雨中与正夫朋元小集夜帰","author":"范成大","dynasty":"宋","form":"诗","lines":["灯市凄清灯火稀，雨巾风帽笑帰遅。","月明想在云堆処，客酔都忘马滑时。","老去樽前花隔雾，春来句里鬓成糸。","浮生不了悲歓事，作剧児童総未知。"],"source":"宋诗"},{"title":"于飞乐","author":"晏几道","dynasty":"宋","form":"词","lines":["晓日当帘，睡痕犹占香腮。","轻盈笑倚鸾台。","晕残红，匀宿翠，满镜花开。","娇蝉鬓畔，挿一枝、淡蕊疏梅。","毎到春深，多愁饶恨，妆成懒下香阶。","意中人，从别后，萦系情怀。","良辰好景，相思字、唤不归来。"],"source":"宋词"},{"title":"次韵子永夜雨","author":"范成大","dynasty":"宋","form":"诗","lines":["办作长愁客，工哦苦雨吟。","挑灯今夕意，欹枕故园心。","漏屋疏疏滴，空檐细细斟。","相过巷南北，屐歯怕泥深。"],"source":"宋诗"},{"title":"愁倚阑令・春光好","author":"晏几道","dynasty":"宋","form":"词","lines":["凭江阁，看烟鸿。","恨春浓。","还有当年闻笛泪，洒东风。","时候草绿花红。","斜阳外、远水溶溶。","浑似阿莲双枕畔，画屏中。"],"source":"宋词"},{"title":"次韵朋元游王氏园","author":"范成大","dynasty":"宋","form":"诗","lines":["连翩歩屧翠微间，回首红尘自鲜歓。","卷地雨添千涧急，拥门云锁両山盘。","绝怜茶笋能留客，仍喜蛙声不在官。","雪白杨梅消息未，重来応至麦秋寒。"],"source":"宋诗"},{"title":"愁倚阑令・春光好","author":"晏几道","dynasty":"宋","form":"词","lines":["花阴月，柳梢莺。","近清明。","长恨去年今夜雨，洒离亭。","枕上怀远诗成。","红笺纸、小砑吴绫。","寄与征人教念远，莫无情。"],"source":"宋词"},{"title":"游霊石山寺","author":"范成大","dynasty":"宋","form":"诗","lines":["西湖富清丽，城府尘事并。","我独数能来，不负双眼明。","騒騒残絮罢，飐飐新荷成。","歳华日夜好，游子能无情。","午阴醸初暑，稍喜巾袂軽。","小风吹鬓毛，将我入松声。","崖寺金碧暗，石泉肝胆清。","寿藟万蛟舞，霊峰双髻撑。","仙人昔来游，笔墨上朱甍。","挙臂寻丈高，聊得児童惊。","老矣谢狡狯，题诗记吾曽。"],"source":"宋诗"},{"title":"愁倚阑令・春光好","author":"晏几道","dynasty":"宋","form":"词","lines":["春罗薄，酒醒寒。","梦初残。","敧枕片时云雨事，已关山。","楼上斜日阑干。","楼前路、曽试雕鞍。","拼却一襟怀远泪，倚阑看。"],"source":"宋词"},{"title":"次韵李器之编修霊石山万歳藤歌","author":"范成大","dynasty":"宋","form":"诗","lines":["君不见东林怪蔓之诗三百年，字如金縄鉄索相纠缠。","不如李侯霊石句，笔阵圧倒长城坚。","藤阴诗律両秀発，此段奇事今无前。","吾闻草木未有不黄落，雨荒霜倒相后先。","绵绵紫藟天所寿，风雨不动常苍然。","坚姿绝邻傲一所，深本无极融三泉。","腾虬舞蛟矫欲去，流苏络带翩如仙。","班荆芘藾得吾党，酌泉共吸杯中天。","诗成一斗属太白，擘牋挥扫如云烟。","北门西掖君自有，坐拥红薬然金莲。","山腰涧底莫濡滞，早晩天风吹蜕蝉。"],"source":"宋诗"},{"title":"御街行","author":"晏几道","dynasty":"宋","form":"词","lines":["年光正似花梢露。","弹指春还暮。","翠眉仙子望归来，倚遍玉城珠树。","岂知别后，好风良月，往事无寻处。","狂情错向红尘住。","忘了瑶台路。","碧桃花蕊已应开，欲伴彩云飞去。","回思十载，朱颜青鬓，枉被浮名误。"],"source":"宋词"},{"title":"次韵正夫游王园会者六人","author":"范成大","dynasty":"宋","form":"诗","lines":["丘园窈窕复崎岖，草木生香景倍殊。","花下百杯斉物我，云辺一眼尽江湖。","不知朱戸趦趄者，能胜青山放浪无。","六逸萧然真可画，为君题作竹渓図。"],"source":"宋诗"},{"title":"御街行","author":"晏几道","dynasty":"宋","form":"词","lines":["街南绿树春饶絮。","雪满游春路。","树头花艳杂娇云，树底人家朱户。","北楼闲上，疏帘高巻，直见街南树。","阑干倚尽犹慵去。","几度黄昏雨。","晩春盘马踏青苔，曽傍绿阴深驻。","落花犹在，香屏空掩，人面知何处。"],"source":"宋词"},{"title":"四月五日集陈园照山堂","author":"范成大","dynasty":"宋","form":"诗","lines":["寻壑経丘到此堂，官闲聊作送春忙。","短篱水面残红満，団扇风前众绿香。","尽卷帘旌延竹色，深斟杯酒纳山光。","洞门无锁城门近，転午鶏啼日正长。"],"source":"宋诗"},{"title":"浪淘沙","author":"晏几道","dynasty":"宋","form":"词","lines":["高阁对横塘。","新燕年光。","柳花残梦隔潇湘。","绿浦归帆看不见，还是斜阳。","一笑解愁肠。","人会娥妆。","藕丝衫袖郁金香。","曳雪牵云留客酔，且伴春狂。"],"source":"宋词"},{"title":"题宝林寺可赋轩","author":"范成大","dynasty":"宋","form":"诗","lines":["十里山行雑市声，道傍无処濯尘缨。","宝林寺里逢修竹，方有诗情约略生。"],"source":"宋诗"},{"title":"浪淘沙","author":"晏几道","dynasty":"宋","form":"词","lines":["小绿间长红。","露蕊烟丛。","花开花落昔年同。","惟恨花前携手处，往事成空。","山远水重重。","一笑难逢。","已拼长在别离中。","霜鬓知他从此去，几度春风。"],"source":"宋词"},{"title":"次韵朋元久雨","author":"范成大","dynasty":"宋","form":"诗","lines":["谁醸愁䨧玉宇间，都縁梅子要斓斑。","腾腾困思午犹梦，扰扰奔云风未还。","休问満城骑马滑，不妨长日闭门闲。","今朝晴色熹微似，干鹊飞来语屋山。"],"source":"宋诗"},{"title":"浪淘沙","author":"晏几道","dynasty":"宋","form":"词","lines":["丽曲酔思仙。","十二哀弦。","秾蛾叠柳脸红莲。","多少雨条烟叶恨，红泪离筵。","行子惜流年。","鹈鴂枝边。","吴堤春水舣兰船。","南去北来今渐老，难负尊前。"],"source":"宋词"},{"title":"韩无咎検详出示所赋陈季陵戸部巫山図诗仰窥高作叹息弥襟余尝考宋玉谈朝云事漫称先王时本无拠依及襄王梦之命玉为赋但云頩颜怒以自持曽不可乎犯干后世弗察一切溷以媟语曹子建赋宓妃亦感此而作此嘲谁当解者辄用此意次韵和呈以资抚掌","author":"范成大","dynasty":"宋","form":"诗","lines":["瑶姬家山高挿天，碧丛奇秀古未伝。","向来题目経楚客，名字径度岷峨前。","是邪非邪莽谁识，乔林古庙常秋色。","暮去行雨朝行云，翠帷瑶席知何人。","峡船一息且千里，五両竿头见旛尾。","仰窥仙馆至今疑，行人问讯居人指。","千年遗恨何当申，阳台愁绝如荒村。","高唐赋里人如画，玉色頩颜元不嫁。","后来饥客眼长寒，浪伝楽府吹复弾。","此事牵连到温洛，更怜尘袜有无间。","君不见天孙住在银涛许，尘间犹作児女语。","公家春风锦瑟傍，莫为此図虚断肠。"],"source":"宋诗"},{"title":"浪淘沙","author":"晏几道","dynasty":"宋","form":"词","lines":["翠幕绮筵张。","淑景难忘。","阳关声巧绕雕梁。","美酒十分谁与共，玉指持觞。","晓枕梦高唐。","略话衷肠。","小山池院竹风凉。","明夜月圆帘四巻，今夜思量。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["金鹤飞来尺素通，新诗字字挟光风。","三年湖海関心処，都在先生句子中。"],"source":"宋诗"},{"title":"丑奴儿・采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["昭华凤管知名久。","长闭帘栊。","日日春慵。","闲倚庭花晕脸红。","应说金谷无人后，此会相逢。","三弄临风。","送得当筵玉盏空。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["官居门巷果园西，桃李成蹊杏圧枝。","如许年芳忙里过，斩新今日试题诗。"],"source":"宋诗"},{"title":"丑奴儿・采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["日高庭院杨花转，闲淡春风。","莺语惺忪。","似笑金屏昨夜空。","娇慵未洗匀妆手，闲印斜红。","新恨重重。","都与年时旧意同。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["暮林栖鸟各深枝，燕子知巣触幔飞。","倘有三椽今已去，不関五斗解忘帰。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["种花人自蕊宫来。","牵衣问小梅。","今年芳意何似，应向旧枝开。","凭寄语，谢瑶台。","客无才。","粉香传信，玉盏开筵，莫待春回。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["懒不看书似姓辺，梦魂飞绕白鴎前。","须知席帽冲尘出，不似篷窗聴雨眠。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["净揩妆脸浅匀眉。","衫子素梅儿。","苦无心绪梳洗，闲淡也相宜。","云态度，柳腰肢。","入相思。","夜来月底，今日尊前，未当佳期。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其五","author":"范成大","dynasty":"宋","form":"诗","lines":["送春蒙雨涨苹滩，荷叶田田柳絮阑。","想见垂虹三万顷，拍天湖水钓糸寒。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["渚莲霜晓坠残红。","依约旧秋同。","玉人团扇恩浅，一意恨西风。","云去住，月朦胧。","夜寒浓。","此时还是，泪墨书成，未有归鸿。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其六","author":"范成大","dynasty":"宋","form":"诗","lines":["知従了义透音闻，古井无波岂更浑。","便好一坑埋众妙，何须六结解诸根。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["凭觞静忆去年秋，桐落故渓头。","诗成自写红叶，和恨寄东流。","人脉脉，水悠悠。","几多愁。","雁书不到，蝶梦无凭，漫倚高楼。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其七","author":"范成大","dynasty":"宋","form":"诗","lines":["几多蝼蚁与王侯，往古来今共一丘。","遮莫功名掀宇宙，百年両角寄蜗牛。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["小梅风韵最妖娆。","开处雪初消。","南枝欲附春信，长恨陇人遥。","闲记忆，旧江皐。","路迢迢。","暗香浮动，疏影横斜，几处渓桥。"],"source":"宋词"},{"title":"次韵楽先生呉中见寄八首  其八","author":"范成大","dynasty":"宋","form":"诗","lines":["粟囊聊复寄三餐，埋没缁尘懒濯冠。","红紫百般纷过眼，郷山歳晩自苍官。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["长因蕙草记罗裙。","绿腰沈水熏。","阑干曲处人静，曽共倚黄昏。","风有韵，月无痕。","暗消魂。","拟将幽恨，试写残花，寄与朝云。"],"source":"宋词"},{"title":"胡长民监元挽词","author":"范成大","dynasty":"宋","form":"诗","lines":["太学虀塩旧，中呉翰墨声。","関山题柱笔，风露読书檠。","夜雨绿荷破，孤坟丹桂生。","空将擅场手，往记玉楼成。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["御纱新制石榴裙。","沈香慢火熏。","越罗双带宫样，飞鹭碧波纹。","随锦字，叠香痕。","寄文君。","系来花下，解向尊前，谁伴朝云。"],"source":"宋词"},{"title":"次韵朋元正夫夜饮","author":"范成大","dynasty":"宋","form":"诗","lines":["歌豪仍作家，弈胜岂徼幸。","莫嗤老非少，乃尚可以逞。","玉瓶引杯长，政尔寒漏永。","二三文章公，共此银烛影。","陈卿得秀句，刘郎一笑领。","羸骖兀残梦，乗坠恍难省。","暁枕讧更潮，俱坠无何境。"],"source":"宋诗"},{"title":"诉衷情","author":"晏几道","dynasty":"宋","form":"词","lines":["都人离恨满歌筵。","清唱倚危弦。","星屏别后千里，更见是何年。","骢骑稳，绣衣鲜。","欲朝天。","北人欢笑，南国悲凉，迎送金鞭。"],"source":"宋词"},{"title":"次韵赵正之同年客中  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["清班合列大明宫，自要牛刀试一同。","踏徧巉巌吾道在，莫将寻尺较穷通。"],"source":"宋诗"},{"title":"破阵子","author":"晏几道","dynasty":"宋","form":"词","lines":["柳下笙歌庭院，花间姊妹秋千。","记得春楼当日事，写向红窗夜月前。","凭谁寄小莲。","绛蜡等闲陪泪，吴蚕到了缠绵。","绿鬓能供多少恨，未肯无情比断弦。","今年老去年。"],"source":"宋词"},{"title":"次韵赵正之同年客中  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["毡车席帽各青春，花下骅骝一哄尘。","离合飘零十霜露，咸阳客舎有诗人。"],"source":"宋诗"},{"title":"好女儿","author":"晏几道","dynasty":"宋","form":"词","lines":["绿遍西池。","梅子青时。","尽无端、尽日东风恶，更霏微细雨，恼人离恨，满路春泥。","应是行云归路，有闲泪、洒相思。","想旗亭、望断黄昏月，又依前误了，红笺香信，翠袖欢期。"],"source":"宋词"},{"title":"次韵赵正之同年客中  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["可怜山県五斤手，不识王孙八斗才。","君自扶揺有霄汉，従渠蜩鷃舞蒿莱。"],"source":"宋诗"},{"title":"好女儿","author":"晏几道","dynasty":"宋","form":"词","lines":["酌酒殷勤。","尽更留春。","忍无情、便赋馀花落，待花前细把、一春心事，问个人人。","莫似花开还谢，愿芳意、且长新。","倚娇红、待得欢期定，向水沈烟底，金莲影下，睡过佳辰。"],"source":"宋词"},{"title":"次韵陈季邻戸部旦过庵","author":"范成大","dynasty":"宋","form":"诗","lines":["宦游触処似悬匏，北岳南山想献嘲。","指手百年休鋳鉄，盖头一把暂诛茅。","玉京歳晩梧桐落，水国霜清橘柚包。","飞锡已随帰梦去，何人顶上鹊成巣。"],"source":"宋诗"},{"title":"点绛唇","author":"晏几道","dynasty":"宋","form":"词","lines":["花信来时，恨无人似花依旧。","又成春痩。","折断门前柳。","天与多情，不与长相守。","分飞后。","泪痕和酒。","占了双罗袖。"],"source":"宋词"},{"title":"朋元不赴湖上観雪之集明日余召试玉堂见寄二绝次其韵  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["雪渓清兴未渠阑，晩上西楼带月看。","公子自贪低唱酒，肯来同対玉峰寒。"],"source":"宋诗"},{"title":"点绛唇","author":"晏几道","dynasty":"宋","form":"词","lines":["明日征鞭，又将南陌垂杨折。","自怜轻别。","拼得音尘绝。","杏子枝边，倚处阑干月。","依前欠。","去年时节。","旧事无人说。"],"source":"宋词"},{"title":"朋元不赴湖上観雪之集明日余召试玉堂见寄二绝次其韵  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["文场宁复鬓霜宜，白玉堂前雪霁时。","不惜狂言枨忌讳，秃毫冰砚竟无奇。"],"source":"宋诗"},{"title":"点绛唇","author":"晏几道","dynasty":"宋","form":"词","lines":["碧水东流，漫题凉叶津头寄。","谢娘春意。","临水颦双翠。","日日骊歌，空费行人泪。","成何计。","未如浓酔。","闲掩红楼睡。"],"source":"宋词"},{"title":"翰林学士何公挽词","author":"范成大","dynasty":"宋","form":"诗","lines":["盛际群多士，诸儒逊一贤。","名场魁淡墨，官簿到花砖。","地近行知政，天高不仮年。","书生稽古力，何必尽台躔。"],"source":"宋诗"},{"title":"点绛唇","author":"晏几道","dynasty":"宋","form":"词","lines":["妆席相逢，旋匀红泪歌金缕。","意中曽许。","欲共吹花去。","长爱荷香，柳色殷桥路。","留人住。","淡烟微雨。","好个双栖处。"],"source":"宋词"},{"title":"送洪内翰使虏二首  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["郊庙熙成霈率浜，罪如猾夏亦维新。","辺烽已却来南虏，使节犹烦第一人。","遥想穹庐占汉月，便呼重訳布唐春。","単于若问公家世，说与麒麟画老臣。"],"source":"宋诗"},{"title":"点绛唇","author":"晏几道","dynasty":"宋","form":"词","lines":["湖上西风，露花啼处秋香老。","谢家春草。","唱得清商好。","笑倚兰舟，转尽新声了。","烟波渺。","暮云稀少。","一点凉蟾小。"],"source":"宋词"},{"title":"送洪内翰使虏二首  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["峨冠方侍玉舆香，双节飘然照大荒。","正倚先生令赵重，宁容骄子诧胡强。","天教忠信行区脱，人许功名上太常。","试卜和羹知未晩，帰来烟雨正梅黄。"],"source":"宋诗"},{"title":"两同心","author":"晏几道","dynasty":"宋","form":"词","lines":["楚乡春晩，似入仙源。","拾翠处、闲随流水，踏青路、暗惹香尘。","心心在，柳外青帘，花下朱门。","对景且酔芳尊。","莫话消魂。","好意思、曽同明月，恶滋味、最是黄昏。","相思处，一纸红笺，无限啼痕。"],"source":"宋词"},{"title":"次韵赵徳荘吏部休沐","author":"范成大","dynasty":"宋","form":"诗","lines":["窈窕新堂好，委蛇夜直还。","遥知欹帽髪，正奈卷帘山。","门外客姑去，窗前人対闲。","谁能乌帽底，尘土涴朱颜。"],"source":"宋诗"},{"title":"少年游","author":"晏几道","dynasty":"宋","form":"词","lines":["绿勾阑畔，黄昏淡月，携手对残红。","纱窗影里，朦腾春睡，繁杏小屏风。","须愁别后，天高海阔，何处更相逢。","幸有花前，一杯芳酒，欢计莫匆匆。"],"source":"宋词"},{"title":"次韵王夷仲正字同游成氏园","author":"范成大","dynasty":"宋","form":"诗","lines":["秀巌堂上玉东西，把酒登临望眼迷。","天宇四垂粘地近，海山一抹带潮低。","绝知客好无尘事，聊记吾曽有酔题。","倚頼群仙连姓字，他年谁敢一杴泥。"],"source":"宋诗"},{"title":"少年游","author":"晏几道","dynasty":"宋","form":"词","lines":["西渓丹杏，波前媚脸，珠露与深匀。","南楼翠柳，烟中愁黛，丝雨恼娇颦。","当年此处，闻歌𣨼酒，曽对可怜人。","今夜相思，水长山远，闲卧送残春。"],"source":"宋词"},{"title":"王季海秘监再赋成园复次韵","author":"范成大","dynasty":"宋","form":"诗","lines":["云荘风榭対东西，清暑光阴近竹迷。","一斗正縁诗兴尽，両眉休为客愁低。","披开豹雾寻陈迹，扫尽蛛尘看旧题。","健往莫愁骑马滑，阑珊梅雨不成泥。"],"source":"宋诗"},{"title":"少年游","author":"晏几道","dynasty":"宋","form":"词","lines":["离多最是，东西流水，终解两相逢。","浅情终似，行云无定，犹到梦魂中。","可怜人意，薄于云水，佳会更难重。","细想从来，断肠多处，不与者番同。"],"source":"宋词"},{"title":"春晩偶题","author":"范成大","dynasty":"宋","form":"诗","lines":["寂寥春事冷于秋，雨打风吹断送休。","点検梨花成一梦，蘸红新绿満枝头。"],"source":"宋诗"},{"title":"少年游","author":"晏几道","dynasty":"宋","form":"词","lines":["西楼别后，风高露冷，无奈月分明。","飞鸿影里，捣衣砧外，总是玉关情。","王孙此际，山重水远，何处赋西征。","金闺魂梦枉丁宁。","寻尽短长亭。"],"source":"宋词"},{"title":"倪文挙奉常将帰东林出示绮川西渓二赋辄赋长句为谢且以赠行","author":"范成大","dynasty":"宋","form":"诗","lines":["绮川亭上凌云赋，人在回仙旧游処。","谁教书剣走长安，荻月霜枫等闲度。","朱门不炙钓竿手，万巻难供折腰具。","偶然把筯忆莼羹，乞得闲官径呼渡。","江涨桥头有渡船，船头歴歴东林路。","云烟如画水如天，笑忆红尘问良苦。","我亦呉松一钓舟，蟹舎漂揺几风雨。","因君赋里说江湖，破帽蹇馿明亦去。","鶏犬相闻望可见，鴎鹭同盟心亦许。","相过得得款渓门，雪夜前村聴鸣橹。"],"source":"宋诗"},{"title":"少年游","author":"晏几道","dynasty":"宋","form":"词","lines":["雕梁燕去，裁诗寄远，庭院旧风流。","黄花酔了，碧梧题罢，闲卧对高秋。","繁云破后，分明素月，凉影挂金钩。","有人凝澹倚西楼。","新样两眉愁。"],"source":"宋词"},{"title":"送呉智叔検详直中秘使闽","author":"范成大","dynasty":"宋","form":"诗","lines":["抗章襆被岂公难，已说高风立懦顽。","客路莫嫌河畔草，直庐须爱道家山。","秋生莲浦船初泛，春満茶渓骑趣还。","却访故人西府旧，定烦书札堕田间。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["闲敲玉镫隋堤路。","一笑开朱户。","素云凝澹月婵娟。","门外鸭头春水、木兰船。","吹花拾蕊嬉游惯。","天与相逢晩。","一声长笛倚楼时。","应恨不题红叶、寄相思。"],"source":"宋词"},{"title":"杨君居士挽词","author":"范成大","dynasty":"宋","form":"诗","lines":["孝至兰陔茂，身修梓里恭。","名场児中鹄，婣党婿乗竜。","驹隙惊年运，蝉嫣有庆钟。","幽光定无憾，豊刻妙形容。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["飞花自有牵情处。","不向枝边坠。","随风飘荡已堪愁。","更伴东流流水、过秦楼。","楼中翠黛含春怨。","闲倚阑干见。","远弹双泪惜香红。","暗恨玉颜光景、与花同。"],"source":"宋词"},{"title":"送周畏知司直帰上饶待次","author":"范成大","dynasty":"宋","form":"诗","lines":["漫郎西笑费三年，故业新闻腹果然。","长麈剧谈抽茧绪，短檠细字缀蚕眠。","频惊陆海风波梦，未了京尘粥饭縁。","后日重来応访旧，五湖烟浪有渔船。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["曲阑干外天如水。","昨夜还曽倚。","初将明月比佳期。","长向月圆时候、望人归。","罗衣着破前香在。","旧意谁教改。","一春离恨懒调弦。","犹有两行闲泪、宝筝前。"],"source":"宋词"},{"title":"次韵魏端仁感懐俳谐体","author":"范成大","dynasty":"宋","form":"诗","lines":["浪学騒人赋远游，大千何事不悠悠。","酒辺点検颜红在，镜里端详鬓雪羞。","过眼浮云翻覆易，曲肱短梦破除休。","孤烟落日冥鸿去，心更冥鸿最上头。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["疏梅月下歌金缕。","忆共文君语。","更谁情浅似春风。","一夜满枝新绿、替残红。","苹香已有莲开信。","两桨佳期近。","采莲时节定来无。","酔后满身花影、倩人扶。"],"source":"宋词"},{"title":"次韵李子永梅村散策図","author":"范成大","dynasty":"宋","form":"诗","lines":["光风先放越渓春，萧散寻诗索笑人。","藜杖前头春浩荡，三生応是主林神。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["玉箫吹遍烟花路。","小谢经年去。","更教谁画远山眉。","又是陌头风细、恼人时。","时光不解年年好。","叶上秋声早。","可怜蝴蝶易分飞。","只有杏梁双燕、毎来归。"],"source":"宋词"},{"title":"太师陈文恭公挽词  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["日者更皇化，公来辅圣能。","无心殊辙混，不作众波澄。","挙国材真相，他年了中兴。","天如遗一老，人亦望三登。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["秋风不似春风好。","一夜金英老。","更谁来凭曲阑干。","惟有雁边斜月、照关山。","双星旧约年年在。","笑尽人情改。","有期无定是无期。","说与小云新恨、也低眉。"],"source":"宋词"},{"title":"太师陈文恭公挽词  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["候火朝连夕，筹帷决縦擒。","一江遮虏障，千古杀胡林。","皦日黄河誓，浮云绿野心。","身名両无憾，天壌独清音。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["小梅枝上东君信。","雪后花期近。","南枝开尽北枝开。","长被陇头游子、寄春来。","年年衣袖年年泪。","总为今朝意。","问谁同是忆花人。","赚得小鸿眉黛、也低颦。"],"source":"宋词"},{"title":"太师陈文恭公挽词  其三","author":"范成大","dynasty":"宋","form":"诗","lines":["圣父咨当璧，元臣预断金。","玉衡宾舜日，黄屋遂尧心。","国定功无迹，身闲病已深。","旌忠有谟训，碑牓照来今。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["湿红笺纸回纹字。","多少柔肠事。","去年双燕欲归时。","还是碧云千里、锦书迟。","南楼风月长依旧。","别恨无端有。","倩谁横笛倚危阑。","今夜落梅声里、怨关山。"],"source":"宋词"},{"title":"太师陈文恭公挽词  其四","author":"范成大","dynasty":"宋","form":"诗","lines":["趣召単车至，惊伝両鬓凋。","倾城迎国老，即日走天骄。","梦已商人奠，身犹汉相朝。","古来贤达意，生灭両消揺。"],"source":"宋诗"},{"title":"虞美人","author":"晏几道","dynasty":"宋","form":"词","lines":["一弦弹尽仙韶乐。","曽破千金学。","玉楼银烛夜深深。","愁见曲中双泪、落香襟。","从来不奈离声怨。","几度朱弦断。","未知谁解赏新音。","长是好风明月、暗知心。"],"source":"宋词"},{"title":"送陈朋元赴溧阳","author":"范成大","dynasty":"宋","form":"诗","lines":["九畹滋兰静自芳，啁啾谁复认孤凰。","风流歳晩嫌杯酒，文本功深得鬓霜。","敛板君犹能俛仰，倚楼吾敢计行蔵。","船开便作江南客，天色无情更鴈行。"],"source":"宋诗"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["秋千散后朦胧月，满院人闲。","几处雕阑。","一夜风吹杏粉残。","昭阳殿里春衣就，金缕初干。","莫信朝寒。","明日花前试舞看。"],"source":"宋词"},{"title":"次韵韩无咎右司上巳泛湖","author":"范成大","dynasty":"宋","form":"诗","lines":["休沐辰良不待晴，径称闲客此闲行。","春衫欺雨任教冷，病眼得山元自明。","抹黛浓岚囲坐晩，揉蓝新渌没篙清。","栖鸦未到催帰去，想被东风笑薄情。"],"source":"宋诗"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["花前独占春风早，长爱江梅。","秀艳清杯。","芳意先愁凤管催。","寻香已落闲人后，此恨难裁。","更晩须来。","却恐初开胜未开。"],"source":"宋词"},{"title":"太保节使赵公挽词","author":"范成大","dynasty":"宋","form":"诗","lines":["结髪険艰会，捐躯跳荡功。","鬓凋犹陛戟，心在惜弢弓。","剣履三槐次，楼台四壁中。","诸郎竞文武，不朽是清风。"],"source":"宋诗"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["芦鞭坠遍杨花陌，晩见珍珍。","疑是朝云。","来作高唐梦里人。","应怜酔落楼中帽，长带歌尘。","试払香茵。","留解金鞍睡过春。"],"source":"宋词"},{"title":"太宜人程氏挽词  其一","author":"范成大","dynasty":"宋","form":"诗","lines":["我昔官黟歙，人伝女训芳。","尊章宜小妇，孙子寿高堂。","风木真无定，冰鱼已不尝。","遥怜霜露感，何必薤歌伤。"],"source":"宋诗"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["日高庭院杨花转，闲淡春风。","昨夜匆匆。","颦入遥山翠黛中。","金盆水冷菱花净，满面残红。","欲洗犹慵。","弦上啼乌此夜同。"],"source":"宋词"},{"title":"太宜人程氏挽词  其二","author":"范成大","dynasty":"宋","form":"诗","lines":["捧檄三牲养，称觞百歳期。","身犹孺子泣，世已隙驹驰。","吉梦青衣卜，豊碑黄绢辞。","佳城有奇事，応足洗余悲。"],"source":"宋诗"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["征人去日殷勤嘱，莫负心期。","寒雁来时。","第一传书慰别离。","轻春织就机中素，泪墨题诗。","欲寄相思。","日日高楼看雁飞。"],"source":"宋词"},{"title":"与王夷仲検讨祀社","author":"范成大","dynasty":"宋","form":"诗","lines":["残夜露如雨，秋気凄以分。","墙西云正黒，跕跕堕金盆。","良耜醋西成，豆笾蓊芳芬。","去年歳大祲，小家甑生尘。","疫鬼投其巇，虐甚溺与焚。","皇慈降清问，下招离散魂。","调糜鬻薬石，黒簿回春温。","徳馨典神天，秋稼如云屯。","社公亦塞责，酔此豊年樽。","神兮率旧职，为国忧元元。","自今歳其有，駆疠苍烟根。"],"source":"宋诗"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["花时恼得琼枝痩，半被残香。","睡损梅妆。","红泪今春第一行。","风流笑伴相逢处，白马游缰。","共折垂杨。","手拈芳条说夜长。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["春风不负年年信，长趁花期。","小锦堂西。","红杏初开第一枝。","碧箫度曲留人酔，昨夜归迟。","短恨凭谁。","莺语殷勤月落时。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["秋来更觉消魂苦，小字还稀。","坐想行思。","怎得相看似旧时。","南楼把手凭肩处，风月应知。","别后除非。","梦里时时得见伊。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["谁将一点凄凉意，送入低眉。","画箔闲垂。","多是今宵得睡迟。","夜痕记尽窗间月，曽误心期。","准拟相思。","还是窗间记月时。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["宜春苑外楼堪倚，雪意方浓。","雁影冥蒙。","正共银屏小景同。","可无人解相思处，昨夜东风。","梅蕊应红。","知在谁家锦字中。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["白莲池上当时月，今夜重圆。","曲水兰船。","忆伴飞琼看月眠。","黄花绿酒分携后，泪湿吟笺。","旧事年年。","时节南湖又采莲。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["高吟烂酔淮西月，诗酒相留。","明日归舟。","碧藕花中酔过秋。","文姬赠别双团扇，自写银钩。","散尽离愁。","携得清风出画楼。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["前欢几处笙歌地，长负登临。","月幌风襟。","犹忆西楼着意深。","莺花见尽当时事，应笑如今。","一寸愁心。","日日寒蝉夜夜砧。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["无端恼破桃源梦，明日青楼。","玉腻花柔。","不学行云易去留。","应嫌衫袖前香冷，重傍金虬。","歌扇风流。","遮尽归时翠黛愁。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["年年此夕东城见，欢意匆匆。","明日还重。","却在楼台缥缈中。","垂螺払黛清歌女，曽唱相逢。","秋月春风。","酔枕香衾一岁同。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["双螺未学同心绾，已占歌名。","月白风清。","长倚昭华笛里声。","知音敲尽朱颜改，寂寞时情。","一曲离亭。","惜与青楼忍泪听。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["西楼月下当时见，泪粉偷匀。","歌罢还颦。","恨隔炉烟看未真。","别来楼外垂杨缕，几换青春。","倦客红尘。","长记楼中粉泪人。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["非花非雾前时见，满眼娇春。","浅笑微颦。","恨隔垂帘看未真。","殷勤借问家何处，不在红尘。","若是朝云。","宜作今宵梦里人。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["当时月下分飞处，依旧凄凉。","也会思量。","不道孤眠夜更长。","泪痕揾遍鸳鸯枕，重绕回廊。","月上东窗。","长到如今欲断肠。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["湘妃浦口莲开尽，昨夜红稀。","懒过前渓。","闲舣扁舟看雁飞。","去年谢女池边酔，晩雨霏微。","记得归时。","旋折新荷盖舞衣。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["别来长记西楼事，结遍兰襟。","遗恨重寻。","弦断相如绿绮琴。","何时一枕逍遥夜，细话初心。","若问如今。","也似当时着意深。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["红窗碧玉新名旧，犹绾双螺。","一寸秋波。","千斛明珠觉未多。","小来竹马同游客，惯听清歌。","今日蹉跎。","恼乱工夫晕翠蛾。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["昭华凤管知名久，长闭帘栊。","闻道春慵。","方倚庭花晕脸红。","可怜金谷无人后，此会相逢。","三弄临风。","送得当筵玉盏空。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["金风玉露初凉夜，秋草窗前。","浅酔闲眠。","一枕江风梦不圆。","长情短恨难凭寄，枉费红笺。","试払幺弦。","却恐琴心可暗传。"],"source":"宋词"},{"title":"采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["心期昨夜寻思遍，犹负殷勤。","齐斗堆金。","难买丹诚一寸真。","须知枕上尊前意，占得长春。","寄语东邻。","似此相看有几人。"],"source":"宋词"},{"title":"踏莎行","author":"晏几道","dynasty":"宋","form":"词","lines":["柳上烟归，池南雪尽。","东风渐有繁华信。","花开花谢蝶应知，春来春去莺能问。","梦意犹疑，心期欲近。","云笺字字萦方寸。","宿妆曽比杏腮红，忆人细把香英认。"],"source":"宋词"},{"title":"踏莎行","author":"晏几道","dynasty":"宋","form":"词","lines":["宿雨収尘，朝霞破暝。","风光暗许花期定。","玉人呵手试妆时，粉香帘幕阴阴静。","斜雁朱弦，孤鸾绿镜。","伤春误了寻芳兴。","去年今日杏墙西，啼莺唤得闲愁醒。"],"source":"宋词"},{"title":"踏莎行","author":"晏几道","dynasty":"宋","form":"词","lines":["绿径穿花，红楼压水。","寻芳误到蓬莱地。","玉颜人是蕊珠仙，相逢展尽双蛾翠。","梦草闲眠，流觞浅酔。","一春总见瀛洲事。","别来双燕又西飞，无端不寄相思字。"],"source":"宋词"},{"title":"踏莎行","author":"晏几道","dynasty":"宋","form":"词","lines":["雪尽寒轻，月斜烟重。","清欢犹记前时共。","迎风朱户背灯开，払檐花影侵帘动。","绣枕双鸳，香苞翠凤。","从来往事都如梦。","伤心最是酔归时，眼前少个人人送。"],"source":"宋词"},{"title":"满庭芳","author":"晏几道","dynasty":"宋","form":"词","lines":["南苑吹花，西楼题叶，故园欢事重重。","凭阑秋思，闲记旧相逢。","几处歌云梦雨，可怜便、流水西东。","别来久，浅情未有，锦字系征鸿。","年光还少味，开残槛菊，落尽渓桐。","漫留得，尊前淡月西风。","此恨谁堪共说，清愁付、绿酒杯中。","佳期在，归时待把，香袖看啼红。"],"source":"宋词"},{"title":"留春令","author":"晏几道","dynasty":"宋","form":"词","lines":["画屏天畔，梦回依约，十洲云水。","手拈红笺寄人书，写无限、伤春事。","别浦高楼曽漫倚。","对江南千里。","楼下分流水声中，有当日、凭高泪。"],"source":"宋词"},{"title":"留春令","author":"晏几道","dynasty":"宋","form":"词","lines":["采莲舟上，夜来陡觉，十分秋意。","懊恼寒花暂时香，与情浅、人相似。","玉蕊歌清招晩酔。","恋小桥风细。","水湿红裙酒初消，又记得、南渓事。"],"source":"宋词"},{"title":"留春令","author":"晏几道","dynasty":"宋","form":"词","lines":["海棠风横，酔中吹落，香红强半。","小粉多情怨花飞，仔细把、残香看。","一抹浓檀秋水畔。","缕金衣新换。","鹦鹉杯深艳歌迟，更莫放、人肠断。"],"source":"宋词"},{"title":"风入松","author":"晏几道","dynasty":"宋","form":"词","lines":["柳阴庭院杏梢墙。","依旧巫阳。","凤箫已远青楼在，水沈谁、复暖前香。","临镜舞鸾离照，倚筝飞雁辞行。","坠鞭人意自凄凉。","泪眼回肠。","断云残雨当年事，到如今、几处难忘。","两袖晓风花陌，一帘夜月兰堂。"],"source":"宋词"},{"title":"风入松","author":"晏几道","dynasty":"宋","form":"词","lines":["心心念念忆相逢。","别恨谁浓。","就中懊恼难拼处，是擘钗、分钿匆匆。","却似桃源路失，落花空记前踪。","彩笺书尽浣渓红。","深意难通。","强欢𣨼酒图消遣，到醒来、愁闷还重。","若是初心未改，多应此意须同。"],"source":"宋词"},{"title":"清商怨","author":"晏几道","dynasty":"宋","form":"词","lines":["庭花香信尚浅。","最玉楼先暖。","梦觉春衾，江南依旧远。","回纹锦字暗翦。","漫寄与、也应归晩。","要问相思，天涯犹自短。"],"source":"宋词"},{"title":"秋蕊香","author":"晏几道","dynasty":"宋","form":"词","lines":["池苑清阴欲就。","还傍送春时候。","眼中人去难欢偶。","谁共一杯芳酒。","朱阑碧砌皆如旧。","记携手。","有情不管别离久。","情在相逢终有。"],"source":"宋词"},{"title":"秋蕊香","author":"晏几道","dynasty":"宋","form":"词","lines":["歌彻郎君秋草。","别恨远山眉小。","无情莫把多情恼。","第一归来须早。","红尘自古长安道。","故人少。","相思不比相逢好。","此别朱颜应老。"],"source":"宋词"},{"title":"思远人","author":"晏几道","dynasty":"宋","form":"词","lines":["红叶黄花秋意晩，千里念行客。","飞云过尽，归鸿无信，何处寄书得。","泪弹不尽临窗滴。","就砚旋研墨。","渐写到别来，此情深处，红笺为无色。"],"source":"宋词"},{"title":"碧牡丹","author":"晏几道","dynasty":"宋","form":"词","lines":["翠袖疏纨扇。","凉叶催归燕。","一夜西风，几处伤高怀远。","细菊枝头，开嫩香还遍。","月痕依旧庭院。","事何限。","怅望秋意晩。","离人鬓华将换。","静忆天涯，路比此情犹短。","试约鸾笺，传素期良愿。","南云应有新雁。"],"source":"宋词"},{"title":"长相思","author":"晏几道","dynasty":"宋","form":"词","lines":["长相思。","长相思。","若问相思甚了期。","除非相见时。","长相思。","长相思。","欲把相思说似谁。","浅情人不知。"],"source":"宋词"},{"title":"酔落魄・一斛珠","author":"晏几道","dynasty":"宋","form":"词","lines":["满街斜月。","垂鞭自唱阳关彻。","断尽柔肠思归切。","都为人人，不许多时别。","南桥昨夜风吹雪。","短长亭下征尘歇。","归时定有梅堪折。","欲把离愁，细拈花枝说。"],"source":"宋词"},{"title":"酔落魄・一斛珠","author":"晏几道","dynasty":"宋","form":"词","lines":["鸾孤月欠。","两春惆怅音尘绝。","如今若负当时节。","信道欢缘，狂向衣襟结。","若问相思何处歇。","相逢便是相思彻。","尽饶别后留心别。","也待相逢，细把相思说。"],"source":"宋词"},{"title":"酔落魄・一斛珠","author":"晏几道","dynasty":"宋","form":"词","lines":["天教命薄。","青楼占得声名恶。","对酒当歌寻思着。","月户星窗，多少旧期约。","相逢细语初心错。","两行红泪尊前落。","霞觞且共深深酌。","恼乱春宵，翠被都闲却。"],"source":"宋词"},{"title":"酔落魄・一斛珠","author":"晏几道","dynasty":"宋","form":"词","lines":["休休莫莫。","离多还是因缘恶。","有情无奈思量着。","月夜佳期，近写青笺约。","心心口口长恨昨。","分飞容易当时错。","后期休似前欢薄。","买断青楼，莫放春闲却。"],"source":"宋词"},{"title":"望仙楼・胡捣练","author":"晏几道","dynasty":"宋","form":"词","lines":["小春花信日边来，未上江楼先坼。","今岁东君消息。","还自南枝得。","素衣染尽天香，玉酒添成国色。","一自故渓疏隔。","肠断长相忆。"],"source":"宋词"},{"title":"凤孤飞","author":"晏几道","dynasty":"宋","form":"词","lines":["一曲画楼钟动，宛转歌声缓。","绮席飞尘满。","更少待、金蕉暖。","细雨轻寒今夜短。","依前是、粉墙别馆。","端的欢期应未晩。","奈归云难管。"],"source":"宋词"},{"title":"西江月","author":"晏几道","dynasty":"宋","form":"词","lines":["愁黛颦成月浅，啼妆印得花残。","只消鸳枕夜来闲。","晓镜心情便懒。","酔帽檐头风细，征衫袖口香寒。","绿江春水寄书难。","携手佳期又晩。"],"source":"宋词"},{"title":"西江月","author":"晏几道","dynasty":"宋","form":"词","lines":["南苑垂鞭路冷，西楼把袂人稀。","庭花犹有鬓边枝。","且挿残红自酔。","画幕凉催燕去，香屏晓放云归。","依前青枕梦回时。","试问闲愁有几。"],"source":"宋词"},{"title":"武陵春","author":"晏几道","dynasty":"宋","form":"词","lines":["绿蕙红兰芳信歇，金蕊正风流。","应为诗人多怨秋。","花意与消愁。","梁王苑路香英密，长记旧嬉游。","曽看飞琼戴满头。","浮动舞梁州。"],"source":"宋词"},{"title":"武陵春","author":"晏几道","dynasty":"宋","form":"词","lines":["九日黄花如有意，依旧满珍丛。","谁似龙山秋兴浓。","吹帽落西风。","年年岁岁登高节，欢事旋成空。","几处佳人此会同。","今在泪痕中。"],"source":"宋词"},{"title":"武陵春","author":"晏几道","dynasty":"宋","form":"词","lines":["烟柳长堤知几曲，一曲一魂消。","秋水无情天共遥。","愁送木兰桡。","熏香绣被心情懒，期信转迢迢。","记得来时倚画桥。","红泪满鲛绡。"],"source":"宋词"},{"title":"解佩令","author":"晏几道","dynasty":"宋","form":"词","lines":["玉阶秋感，年华暗去。","掩深宫、团扇无绪。","记得当时，自翦下、机中轻素。","点丹青、画成秦女。","凉襟犹在，朱弦未改，忍霜纨、飘零何处。","自古悲凉，是情事、轻如云雨。","倚幺弦、恨长难诉。"],"source":"宋词"},{"title":"行香子","author":"晏几道","dynasty":"宋","form":"词","lines":["晩绿寒红。","芳意匆匆。","惜年华、今与谁同。","碧云零落，数字征鸿。","看渚莲凋，宫扇旧，怨秋风。","流波坠叶，佳期何在，想天教、离恨无穷。","试将前事，闲倚梧桐。","有消魂处，明月夜，粉屏空。"],"source":"宋词"},{"title":"庆春时","author":"晏几道","dynasty":"宋","form":"词","lines":["倚天楼殿，升平风月，彩仗春移。","鸾丝凤竹，长生调里，迎得翠舆归。","雕鞍游罢，何处还有心期。","浓熏翠被，深停画烛，人约月西时。"],"source":"宋词"},{"title":"庆春时","author":"晏几道","dynasty":"宋","form":"词","lines":["梅梢已有，春来音信，风意犹寒。","南楼暮雪，无人共赏，闲却玉阑干。","殷勤今夜，凉月还似眉弯。","尊前为把，桃根丽曲，重倚四弦看。"],"source":"宋词"},{"title":"喜团圆","author":"晏几道","dynasty":"宋","form":"词","lines":["危楼静锁，窗中远岫，门外垂杨。","珠帘不禁春风度，解偷送馀香。","眠思梦想，不如双燕，得到兰房。","别来只是，凭高泪眼，感旧离肠。"],"source":"宋词"},{"title":"忆闷令","author":"晏几道","dynasty":"宋","form":"词","lines":["取次临鸾匀画浅。","酒醒迟来晩。","多情爱惹闲愁，长黛眉低敛。","月底相逢花下见。","有深深良愿。","愿期信、似月如花，须更教长远。"],"source":"宋词"},{"title":"梁州令","author":"晏几道","dynasty":"宋","form":"词","lines":["莫唱阳关曲。","泪湿当年金缕。","离歌自古最消魂，闻歌更在魂消处。","南楼杨柳多情绪。","不系行人住。","人情却似飞絮。","悠扬便逐春风去。"],"source":"宋词"},{"title":"燕归梁","author":"晏几道","dynasty":"宋","form":"词","lines":["莲叶雨，蓼花风。","秋恨几枝红。","远烟収尽水溶溶。","飞雁碧云中。","衷肠事。","鱼笺字。","情绪年年相似。","凭高双袖晩寒浓。","人在月桥东。"],"source":"宋词"},{"title":"胡捣练","author":"晏几道","dynasty":"宋","form":"词","lines":["小亭初报一枝梅，惹起江南归兴。","遥想玉渓风景，水漾横斜影。","异香直到酔乡中，酔后还因香醒。","好是玉容相并。","人与花争莹。"],"source":"宋词"},{"title":"扑蝴蝶","author":"晏几道","dynasty":"宋","form":"词","lines":["风梢雨叶，绿遍江南岸。","思归倦客，寻芳来最晩。","酒边红日初长，陌上飞花正满。","凄凉数声弦管。","怨春短。","玉人应在，明月楼中画眉懒。","鱼笺锦字，多时音信断。","恨如去水空长，事与行云渐远。","罗衾旧香馀暖。"],"source":"宋词"},{"title":"丑奴儿・采桑子","author":"晏几道","dynasty":"宋","form":"词","lines":["夜来酒醒清无梦，愁倚阑干。","露滴轻寒。","雨打芙蓉泪不干。","佳人别后音尘悄，痩尽难拼。","明月无端。","已过红楼十二间。"],"source":"宋词"},{"title":"谒金门","author":"晏几道","dynasty":"宋","form":"词","lines":["渓声急。","无数落花漂出。","燕子分泥蜂酿蜜。","迟迟艳风日。","须信芳菲随失。","况复佳期难必。","拟把此情书万一。","愁多翻阁笔。"],"source":"宋词"},{"title":"水龙吟","author":"苏轼","dynasty":"宋","form":"词","lines":["古来云海茫茫，道山绛阙知何处。","人间自有，赤城居士，龙蟠凤举。","清净无为，坐忘遗照，八篇奇语。","向玉霄东望，蓬莱暗霭，有云驾、骖风驭。","行尽九州四海，笑纷纷、落花飞絮。","临江一见，谪仙风采，无言心许。","八表神游，浩然相对，酒酣箕踞。","待垂天赋就，骑鲸路稳，约相将去。"],"source":"宋词"},{"title":"水龙吟","author":"苏轼","dynasty":"宋","form":"词","lines":["楚山修竹如云，异材秀出千林表。","龙须半翦，凤膺微涨，玉肌匀绕。","木落淮南，雨晴云梦，月明风袅。","自中郎不见，桓伊去后，知孤负、秋多少。","闻道岭南太守，后堂深、绿珠娇小。","绮窗学弄，梁州初遍，霓裳未了。","嚼徴含宫，泛商流羽，一声云杪。","为使君洗尽，蛮风瘴雨，作霜天晓。"],"source":"宋词"},{"title":"水龙吟","author":"苏轼","dynasty":"宋","form":"词","lines":["似花还似非花，也无人惜从教坠。","抛家傍路，思量却是，无情有思。","萦损柔肠，困酣娇眼，欲开还闭。","梦随风万里，寻郎去处，又还被、莺呼起。","不恨此花飞尽，恨西园、落红难缀。","晓来雨过，遗踪何在，一池萍砕。","春色三分，二分尘土，一分流水。","细看来，不是杨花点点，是离人泪。"],"source":"宋词"},{"title":"水龙吟","author":"苏轼","dynasty":"宋","form":"词","lines":["小舟横截春江，卧看翠壁红楼起。","云间笑语，使君高会，佳人半酔。","危柱哀弦，艳歌馀响，绕云萦水。","念故人老大，风流未减，独回首、烟波里。","推枕惘然不见，但空江、月明千里。","五湖闻道，扁舟归去，仍携西子。","云梦南州，武昌南岸，昔游应记。","料多情梦里，端来见我，也参差是。"],"source":"宋词"},{"title":"满庭芳","author":"苏轼","dynasty":"宋","form":"词","lines":["归去来兮，吾归何处，万里家在岷峨。","百年强半，来日苦无多。","坐见黄州再闰，儿童尽、楚语吴歌。","山中友，鸡豚社酒，相劝老东坡。","云何。","当此去，人生底事，来往如梭。","待闲看，秋风洛水清波。","好在堂前细柳，应念我、莫翦柔柯。","仍传语，江南父老，时与晒渔蓑。"],"source":"宋词"},{"title":"满庭芳","author":"苏轼","dynasty":"宋","form":"词","lines":["香叆雕盘，寒生冰箸，画堂别是风光。","主人情重，开宴出红妆。","腻玉圆搓素颈，藕丝嫩、新织仙裳。","双歌罢，虚檐转月，馀韵尚悠扬。","人间，何处有，司空见惯，应谓寻常。","坐中有狂客，恼乱愁肠。","报道金钗坠也，十指露、春笋纤长。","亲曽见，全胜宋玉，想像赋高唐。"],"source":"宋词"},{"title":"满庭芳","author":"苏轼","dynasty":"宋","form":"词","lines":["蜗角虚名，蝇头微利，算来着甚干忙。","事皆前定，谁弱又谁强。","且趁闲身未老，尽放我、些子疏狂。","百年里，浑教是酔，三万六千场。","思量。","能几许，忧愁风雨，一半相妨。","又何须，抵死说短论长。","幸对清风皓月，苔茵展、云幕高张。","江南好，千锺美酒，一曲《满庭芳》。"],"source":"宋词"},{"title":"满庭芳","author":"苏轼","dynasty":"宋","form":"词","lines":["三十三年，今谁存者，算只君与长江。","凛然苍桧，霜干苦难双。","闻道司州古县，云渓上、竹坞松窗。","江南岸，不因送子，宁肯过吾邦。","𪭢𪭢。","疏雨过，风林舞破，烟盖云幢。","愿持此邀君，一饮空缸。","居士先生老矣，真梦里、相对残釭。","歌舞断，行人未起，船鼓已逄逄。"],"source":"宋词"},{"title":"满庭芳","author":"苏轼","dynasty":"宋","form":"词","lines":["三十三年，飘流江海，万里烟浪云帆。","故人惊怪，憔悴老青衫。","我自疏狂异趣，君何事、奔走尘凡。","流年尽，穷途坐守，船尾冻相衔。","巉巉。","淮浦外，层楼翠壁，古寺空岩。","歩携手林间，笑挽ホホ。","莫上孤峰尽处，萦望眼、云海相搀。","家何在，因君问我，归梦绕松杉。"],"source":"宋词"},{"title":"水调歌头","author":"苏轼","dynasty":"宋","form":"词","lines":["落日绣帘巻，亭下水连空。","知君为我，新作窗户湿青红。","长记平山堂上，敧枕江南烟雨，渺渺没孤鸿。","认得酔翁语，山色有无中。","一千顷，都镜净，倒碧峰。","忽然浪起，掀舞一叶白头翁。","堪笑兰台公子，未解庄生天籁，刚道有雌雄。","一点浩然气，千里快哉风。"],"source":"宋词"},{"title":"水调歌头","author":"苏轼","dynasty":"宋","form":"词","lines":["安石在东海，从事鬓惊秋。","中年亲友难别，丝竹缓离愁。","一旦功成名遂，准拟东还海道，扶病入西州。","雅志困轩冕，遗恨寄沧洲。","岁云暮，须早计，要褐裘。","故乡归去千里，佳处辄迟留。","我酔歌时君和，酔倒须君扶我，惟酒可忘忧。","一任刘玄徳，相对卧高楼。"],"source":"宋词"},{"title":"水调歌头","author":"苏轼","dynasty":"宋","form":"词","lines":["明月几时有，把酒问青天。","不知天上宫阙，今夕是何年。","我欲乗风归去，又恐琼楼玉宇，高处不胜寒。","起舞弄清影，何似在人间。","转朱阁，低绮户，照无眠。","不应有恨，何事长向别时圆。","人有悲欢离合，月有阴晴圆欠，此事古难全。","但愿人长久，千里共婵娟。"],"source":"宋词"},{"title":"水调歌头","author":"苏轼","dynasty":"宋","form":"词","lines":["昵昵儿女语，灯火夜微明。","恩冤尔汝来去，弹指泪和声。","忽变轩昂勇士，一鼓填然作气，千里不留行。","回首暮云远，飞絮搅青冥。","众禽里，真彩凤，独不鸣。","跻攀寸歩千险，一落百寻轻。","烦子指间风雨，置我肠中冰炭，起坐不能平。","推手从归去，无泪与君倾。"],"source":"宋词"},{"title":"满江红","author":"苏轼","dynasty":"宋","form":"词","lines":["忧喜相寻，风雨过、一江春绿。","巫峡梦、至今空有，乱山屏簇。","何似伯鸾携徳耀，箪瓢未足清欢足。","渐粲然、光彩照阶庭，生兰玉。","幽梦里，传心曲。","肠断处，凭他续。","文君婿知否，笑君卑辱。","君不见周南歌汉广，天教夫子休乔木。","便相将、左手抱琴书，云间宿。"],"source":"宋词"},{"title":"满江红","author":"苏轼","dynasty":"宋","form":"词","lines":["江汉西来，高楼下、蒲萄深碧。","犹自带、岷峨云浪，锦江春色。","君是南山遗爱守，我为剑外思归客。","对此间、风物岂无情，殷勤说。","江表传，君休读。","狂处士，真堪惜。","空洲对鹦鹉，苇花萧瑟。","不独笑书生争底事，曹公黄祖俱飘忽。","愿使君、还赋谪仙诗，追黄鹤。"],"source":"宋词"},{"title":"满江红","author":"苏轼","dynasty":"宋","form":"词","lines":["东武南城，新堤固、涟漪初溢。","隐隐遍、长林高阜，卧红堆碧。","枝上残花吹尽也，与君更向江头觅。","问向前、犹有几多春，三之一。","官里事，何时毕。","风雨外，无多日。","相将泛曲水，满城争出。","君不见兰亭修禊事，当时坐上皆豪逸。","到如今、修竹满山阴，空陈迹。"],"source":"宋词"},{"title":"满江红","author":"苏轼","dynasty":"宋","form":"词","lines":["清颖东流，愁目断、孤帆明灭。","宦游处、青山白浪，万重千叠。","孤负当年林下意，对床夜雨听萧瑟。","恨此生、长向别离中，添华发。","一尊酒，黄河侧。","无限事，从头说。","相看恍如昨，许多年月。","衣上旧痕馀苦泪，眉间喜气添黄色。","便与君、池上觅残春，花如雪。"],"source":"宋词"},{"title":"满江红","author":"苏轼","dynasty":"宋","form":"词","lines":["天岂无情，天也解、多情留客。","春向暖、朝来底事，尚飘轻雪。","君过春来纡组绶，我应归去耽泉石。","恐异时、杯酒忽相思，云山隔。","浮世事，俱难必。","人纵健，头应白。","何辞更一酔，此欢难觅。","欲向佳人诉离恨，泪珠先已凝双睫。","但莫遣、新燕却来时，音书绝。"],"source":"宋词"},{"title":"归朝欢","author":"苏轼","dynasty":"宋","form":"词","lines":["我梦扁舟浮震泽。","雪浪摇空千顷白。","觉来满眼是庐山，倚天无数开青壁。","此生长接淅。","与君同是江南客。","梦中游，觉来清赏，同作飞梭掷。","明日西风还挂席。","唱我新词泪沾臆。","灵均去后楚山空，澧阳兰芷无颜色。","君才如梦得。","武陵更在西南极。","竹枝词，莫摇新唱，谁谓古今隔。"],"source":"宋词"},{"title":"念奴娇","author":"苏轼","dynasty":"宋","form":"词","lines":["大江东去，浪淘尽、千古风流人物。","故垒西边人道是，三国周郎赤壁。","乱石穿空，惊涛拍岸，巻起千堆雪。","江山如画，一时多少豪杰。","遥想公瑾当年，小乔初嫁了，雄姿英发。","羽扇纶巾谈笑间，强虏灰飞烟灭。","故国神游，多情应笑，我早生华发。","人间如梦，一尊还酹江月。"],"source":"宋词"},{"title":"雨中花・夜行船","author":"苏轼","dynasty":"宋","form":"词","lines":["今岁花时深院，尽日东风，荡扬茶烟。","但有绿苔芳草，柳絮楡钱。","闻道城西，长廊古寺，甲第名园。","有国艳带酒，天香染袂，为我留连。","清明过了，残红无处，对此泪洒尊前。","秋向晩，一枝何事，向我依然。","高会聊追短景，清商不暇馀妍。","不如留取，十分春态，付与明年。"],"source":"宋词"},{"title":"沁园春","author":"苏轼","dynasty":"宋","form":"词","lines":["孤馆灯青，野店鸡号，旅枕梦残。","渐月华収练，晨霜耿耿，云山摛锦，朝露清清。","世路无穷，劳生有限，似此区区长鲜欢。","微吟罢，凭征鞍无语，往事千端。","当时共客长安。","似二陆初来俱少年。","有笔头千字，胸中万巻，致君尧舜，此事何难。","用舎由时，行蔵在我，袖手何妨闲处看。","身长健，但优游卒岁，且斗尊前。"],"source":"宋词"},{"title":"劝金船","author":"苏轼","dynasty":"宋","form":"词","lines":["无情流水多情客。","劝我如曽识。","杯行到手休辞却。","这公道难得。","曲水池上，小字更书年月。","还对茂林修竹，似永和节。","纤纤素手如霜雪。","笑把秋花挿。","尊前莫怪歌声咽。","又还是轻别。","此去翱翔，遍赏玉堂金阙。","欲问再来何岁，应有华发。"],"source":"宋词"},{"title":"一丛花","author":"苏轼","dynasty":"宋","form":"词","lines":["今年春浅腊侵年。","冰雪破春妍。","东风有信无人见，露微意、柳际花边。","寒夜纵长，孤衾易暖，钟鼓渐清圆。","朝来初日半含山。","楼阁淡疏烟。","游人便作寻芳计，小桃杏、应已争先。","衰病少情，疏慵自放，惟爱日高眠。"],"source":"宋词"},{"title":"木兰花令","author":"苏轼","dynasty":"宋","form":"词","lines":["霜馀已失长淮阔。","空听潺潺清颍咽。","佳人犹唱酔翁词，四十三年如电抹。","草头秋露流珠滑。","三五盈盈还二八。","与余同是识翁人，惟有西湖波底月。"],"source":"宋词"},{"title":"木兰花令","author":"苏轼","dynasty":"宋","form":"词","lines":["知君仙骨无寒暑。","千载相逢犹旦暮。","故将别语恼佳人，要看梨花枝上雨。","落花已逐回风去。","花本无心莺自诉。","明朝归路下塘西，不见莺啼花落处。"],"source":"宋词"},{"title":"木兰花令","author":"苏轼","dynasty":"宋","form":"词","lines":["梧桐叶上三更雨。","惊破梦魂无觅处。","夜凉枕簟已知秋，更听寒蛩促机杼。","梦中历历来时路。","犹在江亭酔歌舞。","尊前必有问君人，为道别来心与绪。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["公子眼花乱发，老夫鼻观先通。","领巾飘下瑞香风。","惊起谪仙春梦。","后土祠中玉蕊，蓬莱殿后鞓红。","此花清绝更纤秾。","把酒何人心动。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["小院朱阑几曲，重城画鼓三通。","更看微月转光风。","归去香云入梦。","翠袖争浮大白，皂罗半挿斜红。","灯花零落酒花秾。","妙语一时飞动。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["怪此花枝怨泣，托君诗句名通。","凭将草木记吴风。","继取相如云梦。","点笔袖沾酔墨，谤花面有惭红。","知君却是为情秾。","怕见此花撩动。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["闻道双衔凤带，不妨单着鲛绡。","夜香知与阿谁烧。","怅望水沈烟袅。","云鬓风前绿巻，玉颜酔里红潮。","莫教空度可怜宵。","月与佳人共僚。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["点点楼头细雨。","重重江外平湖。","当年戏马会东徐。","今日凄凉南浦。","莫恨黄花未吐。","且教红粉相扶。","酒阑不必看茱萸。","俯仰人间今古。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["龙焙今年绝品，谷帘自古珍泉。","雪芽双井散神仙。","苗裔来从北苑。","汤发云腴酽白，盏浮花乳轻圆。","人间谁敢更争妍。","斗取红窗粉面。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["别梦已随流水，泪巾犹裛香泉。","相如依旧是臞仙。","人在瑶台阆苑。","花雾萦风缥缈，歌珠滴水清圆。","蛾眉新作十分妍。","走马归来便面。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["世事一场大梦，人生几度秋凉。","夜来风叶已鸣廊。","看取眉头鬓上。","酒贱常愁客少，月明多被云妨。","中秋谁与共孤光。","把盏凄然北望。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["莫叹平原落落，且应去鲁迟迟。","与君各记少年时。","须信人生如寄。","白发千茎相送，深杯百罚休辞。","拍浮何用酒为池。","我已为君徳酔。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["玉骨那愁瘴雾，冰姿自有仙风。","海仙时遣探芳丛。","倒挂绿毛幺凤。","素面翻嫌粉涴，洗妆不褪唇红。","高情已逐晓云空。","不与梨花同梦。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["照野弥弥浅浪，横空暧暧微霄。","障泥未解玉骢骄。","我欲酔眠芳草。","可惜一渓明月，莫教踏破琼瑶。","解鞍敧枕绿杨桥。","杜宇一声春晓。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["三过平山堂下，半生弹指声中。","十年不见老仙翁。","壁上龙蛇飞动。","欲吊文章太守，仍歌杨柳春风。","休言万事转头空。","未转头时皆梦。"],"source":"宋词"},{"title":"西江月","author":"苏轼","dynasty":"宋","form":"词","lines":["昨夜扁舟京口，今朝马首长安。","旧官何物与新官。","只有湖山公案。","此景百年几变，个中下语千难。","使君才气巻波澜。","与把新诗判断。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["细马远驮双侍女，青巾玉带红靴。","渓山好处便为家。","谁知巴峡路，却见洛城花。","面旋落英飞玉蕊，人间春日初斜。","十年不见紫云车。","龙丘新洞府，铅鼎养丹砂。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["诗句端来磨我钝，钝锥不解生铓。","欢颜为我解冰霜。","酒阑清梦觉，春草满池塘。","应念雪堂坡下老，昔年共采芸香。","功成名遂早还乡。","回车来过我，乔木拥千章。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["我劝髯张归去好，从来自己忘情。","尘心消尽道心平。","江南与塞北，何处不堪行。","俎豆庚桑真过矣，凭君说与南荣。","愿闻吴越报丰登。","君王如有问，结袜赖王生。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["自古相从休务日，何妨低唱微吟。","天垂云重作春阴。","坐中人半酔，帘外雪将深。","闻道分司狂御史，紫云无路追寻。","凄风寒雨是骎骎。","问囚长损气，见鹤忽惊心。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["忘却成都来十载，因君未免思量。","凭将清泪洒江阳。","故山知好在，孤客自悲凉。","坐上别愁君未见，归来欲断无肠。","殷勤且更尽离觞。","此身如传舎，何处是吾乡。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["尊酒何人怀李白，草堂遥指江东。","珠帘十里巻香风。","花开又花谢，离恨几千重。","轻舸渡江连夜到，一时惊笑衰容。","语音犹自带吴侬。","夜阑对酒处，依旧梦魂中。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["九十日春都过了，贪忙何处追游。","三分春色一分愁。","雨翻楡荚阵，风转柳花球。","阆苑先生须自责，蟠桃动是千秋。","不知人世苦厌求。","东皇不拘束，肯为使君留。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["四大从来都遍满，此间风水何疑。","故应为我发新诗。","幽花香涧谷，寒藻舞沦漪。","借与玉川生两腋，天仙未必相思。","还凭流水送人归。","层巅馀落日，草露已沾衣。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["一别都门三改火，天涯踏尽红尘。","依然一笑作春温。","无波真古井，有节是秋筠。","惆怅孤帆连夜发，送行淡月微云。","尊前不用翠眉颦。","人生如逆旅，我亦是行人。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["多病休文都痩损，不堪金带垂腰。","望湖楼上暗香飘。","和风春弄袖，明月夜闻箫。","酒醒梦回清漏永，隐床无限更潮。","佳人不见董娇饶。","徘徊花上月，空度可怜宵。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["夜饮东坡醒复酔，归来仿仏三更。","家童鼻息已雷鸣。","敲门都不应，倚杖听江声。","长恨此身非我有，何时忘却营营。","夜阑风静縠纹平。","小舟从此逝，江海寄馀生。"],"source":"宋词"},{"title":"临江仙","author":"苏轼","dynasty":"宋","form":"词","lines":["冬夜夜寒冰合井，画堂明月侵帏。","青缸明灭照悲啼。","青缸挑欲尽，粉泪裛还垂。","未尽一尊先掩泪，歌声半带清悲。","情声两尽莫相违。","欲知肠断处，梁上暗尘飞。"],"source":"宋词"},{"title":"渔家傲","author":"苏轼","dynasty":"宋","form":"词","lines":["千古龙蟠并虎踞。","从公一吊兴亡处。","渺渺斜风吹细雨。","芳草渡。","江南父老留公住。","公驾飞车凌彩雾。","红鸾骖乗青鸾驭。","却讶此洲名白鹭。","非吾侣。","翩然欲下还飞去。"],"source":"宋词"},{"title":"渔家傲","author":"苏轼","dynasty":"宋","form":"词","lines":["送客归来灯火尽。","西楼淡月凉生晕。","明日潮来无定准。","潮来稳。","舟横渡口重城近。","江水似知孤客恨。","南风为解佳人愠。","莫学时流轻久困。","频寄问。","钱塘江上须忠信。"],"source":"宋词"},{"title":"渔家傲","author":"苏轼","dynasty":"宋","form":"词","lines":["皎皎牵牛河汉女。","盈盈临水无由语。","望断碧云空日暮。","无寻处。","梦回芳草生春浦。","鸟散馀花纷似雨。","汀洲苹老香风度。","明月多情来照户。","但揽取。","清光长送人归去。"],"source":"宋词"},{"title":"渔家傲","author":"苏轼","dynasty":"宋","form":"词","lines":["一曲《阳关》情几许。","知君欲向秦川去。","白马皂貂留不住。","回首处。","孤城不见天霖雾。","到日长安花似雨。","故关杨柳初飞絮。","渐见靴刀迎夹路。","谁得似。","风流膝上王文度。"],"source":"宋词"},{"title":"鹧鸪天","author":"苏轼","dynasty":"宋","form":"词","lines":["林断山明竹隐墙。","乱蝉衰草小池塘。","翻空白鸟时时见，照水红蕖细细香。","村舎外，古城旁。","杖藜徐歩转斜阳。","殷勤昨夜三更雨，又得浮生一日凉。"],"source":"宋词"},{"title":"鹧鸪天","author":"苏轼","dynasty":"宋","form":"词","lines":["笑拈红梅亸翠翘。","扬州十里最妖饶。","夜来绮席亲曽见，撮得精神滴滴娇。","娇后眼，舞时腰。","刘郎几度欲魂消。","明朝酒醒知何处，肠断云间《紫玉箫》。"],"source":"宋词"},{"title":"少年游","author":"苏轼","dynasty":"宋","form":"词","lines":["银塘朱槛曲尘波。","圆绿巻新荷。","兰条荐浴，菖花酿酒，天气尚清和。","好将沈酔酬佳节，十分酒、一分歌。","狱草烟深，讼庭人悄，无吝宴游过。"],"source":"宋词"},{"title":"少年游","author":"苏轼","dynasty":"宋","form":"词","lines":["去年相送，馀杭门外，飞雪似杨花。","今年春尽，杨花似雪，犹不见还家。","对酒巻帘邀明月，风露透窗纱。","恰似姮娥怜双燕，分明照、画梁斜。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["两两轻红半晕腮。","依依独为使君回。","若道使君无此意。","何为。","双花不向别人开。","但看低昂烟雨里。","不已。","劝君休诉十分杯。","更问尊前狂副使。","来岁。","花开时节与谁来。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["莫听穿林打叶声。","何妨吟啸且徐行。","竹杖芒鞋轻胜马。","谁怕。","一蓑烟雨任平生。","料峭春风吹酒醒。","微冷。","山头斜照却相迎。","回首向来潇洒处。","归去。","也无风雨也无晴。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["与客携壶上翠微。","江涵秋影雁初飞。","尘世难逢开口笑。","年少。","菊花须挿满头归。","酩酊但酬佳节了。","云峤。","登临不用怨斜晖。","古往今来谁不老。","多少。","牛山何必更沾衣。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["莫怪鸳鸯绣带长。","腰轻不胜舞衣裳。","薄幸只贪游冶去。","何处。","垂杨系马恣轻狂。","花谢絮飞春又尽。","堪恨。","断弦尘管伴啼妆。","不信归来但自看。","怕见。","为郎憔悴却羞郎。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["千古风流阮歩兵。","平生游宦爱东平。","千里远来还不住。","归去。","空留风韵照人清。","红粉尊前深懊恼。","休道。","怎生留得许多情。","记得明年花絮乱。","须看。","泛西湖是断肠声。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["雨洗娟娟嫩叶光。","风吹细细绿筠香。","秀色乱侵书帙晩。","帘巻。","清阴微过酒尊凉。","人画竹身肥拥肿。","何用。","先生落笔胜萧郎。","记得小轩岑寂夜。","廊下。","月和疏影上东墙。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["好睡慵开莫厌迟。","自怜冰脸不时宜。","偶作小红桃杏色，闲雅，尚馀孤痩雪霜姿。","休把闲心随物态，何事，酒生微晕沁瑶肌。","诗老不知梅格在，吟咏，更看绿叶与青枝。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["月满苕渓照夜堂。","五星一老斗光芒。","十五年间真梦里。","何事。","长庚对月独凄凉。","绿鬓苍颜同一酔。","还是。","六人吟笑水云乡。","宾主谈锋谁得似。","看取。","曹刘今对两苏张。"],"source":"宋词"},{"title":"定风波","author":"苏轼","dynasty":"宋","form":"词","lines":["常羡人间琢玉郎。","天应乞与点酥娘。","尽道清歌传皓齿。","风起。","雪飞炎海变清凉。","万里归来颜愈少。","微笑。","笑时犹带岭梅香。","试问岭南应不好。","却道。","此心安处是吾乡。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["晩景落琼杯。","照眼云山翠作堆。","认得岷峨春雪浪，初来。","万顷蒲萄涨渌醅。","暮雨暗阳台。","乱洒高楼湿粉腮。","一阵东风来巻地，吹回。","落照江天一半开。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["寒雀满疏篱。","争抱寒柯看玉蕤。","忽见客来花下坐，惊飞。","蹋散芳英落酒卮。","痛饮又能诗。","坐客无毡酔不知。","花尽酒阑春到也，离离。","一点微酸已着枝。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["不到谢公台。","明月清风好在哉。","旧日髯孙何处去，重来。","短李风流更上才。","秋色渐摧颓。","满院黄英映酒杯。","看取桃花春二月，争开。","尽是刘郎去后栽。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["霜降水痕収。","浅碧鳞鳞露远洲。","酒力渐消风力软，飕飕。","破帽多情却恋头。","佳节若为酬。","但把清尊断送秋。","万事到头都是梦，休休。","明日黄花蝶也愁。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["回首乱山横。","不见居人只见城。","谁似临平山上塔，亭亭。","迎客西来送客行。","归路晩风清。","一枕初寒梦不成。","今夜残灯斜照处，荧荧。","秋雨晴时泪不晴。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["冰雪透香肌。","姑射仙人不似伊。","濯锦江头新样锦，非宜。","故着寻常淡薄衣。","暖日下重帏。","春睡香凝索起迟。","曼倩风流缘底事，当时。","爱被西真唤作儿。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["东武望馀杭。","云海天涯两杳茫。","何日功成名遂了，还乡。","酔笑陪公三万场。","不用诉离觞。","痛饮从来别有肠。","今夜送归灯火冷，河塘。","堕泪羊公却姓杨。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["凉簟碧纱厨。","一枕清风昼睡馀。","睡听晩衙无一事，徐徐。","读尽床头几巻书。","掻首赋归欤。","自觉功名懒更疏。","若问使君才与术，何如。","占得人间一味愚。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["裙带石榴红。","却水殷勤解赠侬。","应许逐鸡鸡莫怕，相逢。","一点灵犀必暗通。","何处遇良工。","琢刻天真半欲空。","愿作龙香双凤拨，轻拢。","长在环儿白雪胸。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["旌旆满江湖。","诏发楼船万舳舻。","投笔将军因笑我，迂儒。","帕首腰刀是丈夫。","粉泪怨离居。","喜子垂窗报捷书。","试问伏波三万语，何如。","一斛明珠换绿珠。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["天与化工知。","赐得衣裳总是绯。","毎向华堂深处见，怜伊。","两个心肠一片儿。","自小便相随。","绮席歌筵不暂离。","苦恨人人分拆破，东西。","怎得成双似旧时。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["寒玉细凝肤。","清歌一曲《倒金壶》。","冶叶倡条遍相识，争如。","豆蔻花梢二月初。","年少即须臾。","芳时偷得酔工夫。","罗帐细垂银烛背，欢娱。","豁得平生俊气无。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["怅望送春杯。","渐老逢春能几回。","花满楚城愁远别，伤怀。","何况清丝急管催。","吟断望乡台。","万里归心独上来。","景物登临闲始见，徘徊。","一寸相思一寸灰。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["何处倚阑干。","弦管高楼月正圆。","胡蝶梦中家万里，依然。","老去愁来强自宽。","明镜借红颜。","须着人间比梦间。","蜡烛半笼金翡翠，更阑。","绣被焚香独自眠。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["山与歌眉敛，波同酔眼流。","游人都上十三楼。","不羡竹西歌吹、古扬州。","菰黍连昌歜，琼彝倒玉舟。","谁家《水调》唱歌头。","声绕碧山飞去、晩云留。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["古岸开青葑，新渠走碧流。","会看光满万家楼。","记取他年扶路、入西州。","佳节连梅雨，馀生寄叶舟。","只将菱角与鸡头。","更有月明千顷、一时留。"],"source":"宋词"},{"title":"南乡子","author":"苏轼","dynasty":"宋","form":"词","lines":["雨暗初疑夜，风回忽报晴。","淡云斜照着山明。","细草软沙渓路、马蹄轻。","卯酒醒还困，仙材梦不成。","蓝桥何处觅云英。","只有多情流水、伴人行。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["日出西山雨，无晴又有晴。","乱山深处过清明。","不见彩绳花板、细腰轻。","尽日行桑野，无人与目成。","且将新句琢琼英。","我是世间闲客、此闲行。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["带酒冲山雨，和衣睡晩晴。","不知钟鼓报天明。","梦里栩然蝴蝶、一身轻。","老去才都尽，归来计未成。","求田问舎笑豪英。","自爱湖边沙路、免泥行。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["日薄花房绽，风和麦浪轻。","夜来微雨洗郊坰。","正是一年春好、近清明。","已改煎茶火，犹调入粥饧。","使君高会有馀清。","此乐无声无味、最难名。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["海上乗槎侣，仙人萼绿华。","飞升元不用丹砂。","住在潮头来处、渺天涯。","雷辊夫差国，云翻海若家。","坐中安得弄琴牙。","写取馀声归向、水仙夸。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["苒苒中秋过，萧萧两鬓华。","寓身化世一尘沙。","笑看潮来潮去、了生涯。","方士三山路，渔人一叶家。","早知身世两聱牙。","好伴骑鲸公子、赋雄夸。"],"source":"宋词"},{"title":"南歌子","author":"苏轼","dynasty":"宋","form":"词","lines":["师唱谁家曲，宗风嗣阿谁。","借君拍板与门槌。","我也逢场作戏、莫相疑。","渓女方偷眼，山僧莫眨眉。","却愁弥勒下生迟。","不见老婆三五、少年时。"],"source":"宋词"}];
